window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["fa"]={"ICON-0001":{"nm":"ردپا","de":"یک اثر خاک‌رنگ به‌جا مانده روی کف چوبی. کسی مدت‌ها این‌سو و آن‌سو رفته بود، تا سرانجام یک قدم دیگر هم برداشت. آنچه ردپا ثبت می‌کند، زمان ماندن نیست، بلکه همان لحظه‌ای‌ست که کسی تصمیم به رفتن گرفت."},"ICON-0002":{"nm":"فانوس","de":"وقتی شعله به فتیله می‌رسد، تاریکی آرام‌آرام، وجب‌به‌وجب عقب می‌نشیند. مردمان قدیم با آن گرمای کوچکی که نوک انگشتان را گرم می‌کرد، آرزوهایشان را می‌نوشتند و رها می‌کردند. فانوس را روشن نمی‌کنند تا نور بدهد، بلکه روشن می‌کنند تا همراهت باشد."},"ICON-0003":{"nm":"روبان","de":"با یک گره، دل به‌زیبایی بسته‌بندی می‌شود. برای دستِ دهنده باز کردنش آسان است، برای دستِ گیرنده اما دلش می‌خواهد آهسته باز شود. آنچه روبان می‌بندد جعبه نیست، بلکه همان لرزش شوقی‌ست که درست پیش از تقدیم‌کردن در دل می‌پیچد."},"ICON-0004":{"nm":"صندوق‌پستی","de":"با دهانی سرخ و باز، سرِ کوچه ایستاده است. حتی در روزگاری که نامه‌های دست‌نویس کمیاب شده‌اند، این جعبه‌ی کوچک تا آخرین لحظه منتظر خبری از کسی می‌ماند. ظرفی مهربان که درست همان لحظه‌ی خالی‌شدن، روشن‌ترین حالتش را دارد."},"ICON-0005":{"nm":"نقشه‌ی کوچک جزیره‌ی شخصی","de":"تا‌شده در جیب جا می‌شود، باز‌شده دریا و خط‌الرأس را کنار هم می‌خواباند؛ فقط یک ورق کاغذ. برای کسی که تازه به این‌جا رسیده، هر گوشه‌اش هنوز وعده‌ای‌ست که باز نشده. همین که باز می‌شود، حتی جزیره‌ای کوچک هم به جهانی پهناور بدل می‌شود."},"ICON-0006":{"nm":"میکروفون","de":"درست پیش از خواندن اولین نت، آن نیم‌ضربان نفس‌گرفتن. وقتی بدانی نگاه تماشاگران منتظر یک کلمه‌ی توست، نوک انگشتانت به لرزه می‌افتد. میکروفون صدا را بلند نمی‌کند؛ همان لرزش را تا انتها همراهی می‌کند."},"ICON-0007":{"nm":"ساعت","de":"عقربه‌ی ثانیه‌شمار هرگز نمی‌آرامد، اما هیچ‌کس تو را عجله نمی‌اندازد. چند شب تا دبیوت، چند دقیقه تا صحنه—روی صفحه، انتظار و شور با یک سرعت می‌چرخند. نگاه‌کردن به زمان، یعنی نوازش‌کردن دل."},"ICON-0008":{"nm":"دفترچه","de":"چیزی با بیشترین جای خالی. مسیر رقص، عهدهای سپیده‌دم، حرف‌هایی که هرگز فرستاده نشدند، همه این‌جا انباشته می‌شوند. همین که بازش می‌کنی، من دیروز آرام با من امروز حرف می‌زند."},"ICON-0009":{"nm":"مهر","de":"با جوهر سرخ خیس می‌شود و یک بار محکم فشرده می‌شود، تا پیمانی روشن حک شود. اثری سنگین‌تر از نوشته، صریح‌تر از کلام. در انتهای هر سند، مردم به‌جای نام، دلشان را به این مهر کوچک می‌سپردند."},"ICON-0010":{"nm":"پایه","de":"خودش را تا حد ممکن پایین می‌کشد تا چیز دیگری را نگه دارد. جایی در پایین‌ترین نقطه، بی‌صدا وزن را تحمل می‌کند تا آنچه بالاست نلرزد. هرگز نمی‌درخشد، اما مهربانیِ آن است که نمی‌گذارد چیزی فرو بریزد."},"ICON-0011":{"nm":"تمبر","de":"تصویری کوچک که گوشه‌اش را با آب دهان تر می‌کردی و محکم می‌چسباندی. صادقانه‌ترین بهایی‌ست که برای دلی فرستاده‌شده به دوردست تعیین می‌شود. یک منظره‌ی مربع‌شکل، دست نامه را می‌گیرد و تا آن‌سوی دریا با خود می‌برد."},"ICON-0012":{"nm":"سنجاق‌پرچم","de":"آن را روی نقشه فرومی‌کنی و می‌گوید «من تا این‌جا آمدم». نه فتح، بلکه ثبت است، و تشویقی برای هر که بعدها می‌رسد. نشانه‌ای که بی‌کلام پشتت را هل می‌دهد: با دیدن این پرچم، فقط یک قدم دیگر بردار."},"ICON-0013":{"nm":"شاخه","de":"شاخه‌ای که یک‌بار خم شده، دیگر شکستن را فراموش می‌کند. هر جا که در برابر باد خمیده، گره‌ای سفت و سخت جا می‌گیرد؛ و جنگل کهن با نجوای نسیم می‌گوید که استحکام واقعی از ردِ تحمل‌کردن می‌آید."},"ICON-0014":{"nm":"دکمه","de":"بارها باز می‌شود و دوباره بسته، تا یقه را جمع نگه دارد. یک دایره‌ی کوچک بی‌صدا هم سرمای سپیده‌دم را دور می‌کند، هم خجالت ناگهانی را. تنها وقتی می‌جهد و می‌افتد، آدم می‌فهمد جای کوچکش چقدر بزرگ بوده."},"ICON-0015":{"nm":"پاکت‌نامه","de":"درست همان لحظه که دهانش بسته می‌شود، سرانجام رازی می‌شود. تنها گیرنده می‌داند درونش چیست. یک لایه کاغذ، میان دل و جهان قرار می‌گیرد؛ نازک‌ترین و مهربان‌ترین دری از همه."},"ICON-0016":{"nm":"جعبه","de":"چهار گوشه‌اش صاف است، پس هر چیزی را باگشاده‌دستی در آغوش می‌گیرد. در فصل اسباب‌کشی خاطره، در اعیاد هدیه، در روزهای عادی خرت‌وپرت. درون درِ بسته‌اش همیشه پر است از «بعداً»ی کسی."},"ICON-0017":{"nm":"دستگیره","de":"میان در و آدم، اولین چیزی‌ست که دست دراز می‌کند. تنها با یک کشیدن، درون و بیرون به هم می‌پیوندند. هر تصمیمی برای ورود یا خروج، این دست سرد را یک بار می‌فشارد و می‌گذرد."},"ICON-0018":{"nm":"قاشق","de":"با دهانی گود، آرام آب‌گوشتِ داغ را بالا می‌کشد. ابزاری که گرمای همان اولین قاشقی را به یاد دارد که مادر پیش از دادن، فوت می‌کرد تا خنک شود. مهربان‌ترین دستی‌ست که بیش از هر چیز بر سفره، لب‌ها را لمس می‌کند."},"ICON-0019":{"nm":"دمپایی","de":"درست همان لحظه که از آستانه می‌گذری، پاها اول از همه نفسی تازه می‌کنند. صدای غروب، قدم‌های آرام پس از درآوردن یک روز پرصدا. جفتی که مرتب کنار در چیده شده، می‌گوید «حالا دیگر خانه‌ای»."},"ICON-0020":{"nm":"کلید","de":"پیش از یاد گرفتن قفل‌کردن، باز‌کردن را می‌آموزی. تکه‌فلزی کوچک که در کف دست گرم می‌شود، تا روزی آرام پیش روی دری تازه و ناآشنا بایستد. چیزی که گرمای دستِ رونده را از همه بیشتر نگه می‌دارد."},"ICON-0021":{"nm":"جام","de":"وقتی خالی‌ست منظم است، وقتی پر می‌شود از هر چیزی گرم‌تر. در صدای زلالِ برخورد دو جامی که رو‌به‌روی هم بالا رفته‌اند، پیمانی بی‌کلام نهفته است. ظرفی که برای درخشیدن با دو نفر زاده شده، نه یک نفر."},"ICON-0022":{"nm":"بشقاب","de":"در حاشیه‌ی گردش، دل‌سوزی یک روز کامل جا می‌گیرد. خالی‌شدن و شسته‌شدن و دوباره پرشدن، برای یک عمر—از پرکاربردترین و در عین حال فراموش‌شده‌ترین وسایل خانه. صحنه‌ی سفره همیشه روی همین چیده می‌شود."},"ICON-0023":{"nm":"چراغ","de":"با یک کلید، حالتِ چهره‌ی اتاق عوض می‌شود. روشن که باشد، روزمرگی‌ست؛ کم‌سو که باشد، تسلی. یک نقطه نور که برای کسی که دیر به خانه می‌رسد تا آخر روشن می‌ماند، گرم‌ترین استقبالِ دنیا می‌شود."},"ICON-0024":{"nm":"قاشق‌چای‌خوری","de":"یک دور آرام روی سطح چای می‌چرخد، تا برگ و آب در هم رخنه کنند. حرکتی بی‌عجله، انتظاری کوچک تا رایحه پخش شود. یک دست نقره‌فام، به‌مهربانی سرعت بعدازظهر را کند می‌کند."},"ICON-0025":{"nm":"نشانِ‌کتاب","de":"پیمانی که آرام میان صفحه‌ای می‌ماند که خواندن آن‌جا متوقف شده. عهد «این‌جا ایستادم، حتماً برمی‌گردم» میان صفحات به خواب می‌رود. داستان شاید بسته شود، اما دل روی همان یک خط، واضح نشانه‌گذاری شده."},"ICON-0026":{"nm":"کوسن","de":"بی‌کلام پشت و زانویی را می‌پذیرد که به تکیه‌گاهی نیاز دارند. فرومی‌رود و آرام‌آرام دوباره باد می‌شود، و خستگیِ روز را در خود می‌کشد. چیزی که بخشنده‌ترین اجازه را به تنبل‌ترین حالتِ نشستن می‌دهد."},"ICON-0027":{"nm":"قاب","de":"حاشیه‌ای مربع، یک منظره را به ابدیت گره می‌زند. برای همان لحظه‌ای که در آن گرفتار شده، هرچقدر زمان بگذرد رنگ نمی‌بازد. انتخابی مهربان، نه درباره‌ی این‌که چه چیزی را نگه‌داری، بلکه این‌که چه چیزی را تصمیم گرفتی باقی بماند."},"ICON-0028":{"nm":"نقشه","de":"در هر چین‌وچروکش، ردی از گم‌شدن و دوباره یافتنِ راه نشسته. بازش کن، و حتی جایی که هرگز نرفته‌ای را می‌توانی نخست با نوک انگشت طی کنی. هر ماجراجویی از همان شجاعت کوچکِ بازکردن این یک ورق آغاز می‌شود."},"ICON-0029":{"nm":"کارت‌پستال","de":"نیمی از پشتش عکس است، نیمی خالی. کسی که به دوردست رفته، در پنج کلمه‌ی «حالم خوب است» منظره‌ی آن‌جا را هم همراه می‌فرستد. صادق‌ترین ورق کاغذی که حتی بی‌پاکت هم، خبردادن را شرمگین نمی‌کند."},"ICON-0030":{"nm":"کارت‌ورود","de":"درست همان لحظه که به گردن می‌آویزی‌اش، سرانجام به جهانِ درونی قدم می‌گذاری. نام تو روی کارتی کوچک، آرام اجازه می‌دهد: «این‌جا، جای توست». نه صلاحیتِ عبور، بلکه گواهِ آن‌که به جایی تعلق داری."},"ICON-0031":{"nm":"حرف بی","de":"حرفی که بیش از هر حرفی، از میان یک واژه صدایش می‌زنند. باید لب‌ها را یک‌بار ببندی و بعد ناگهان بازشان کنی تا صدایش بلند شود. نه آغاز است نه پایان، اما جایگاه دومِ استواری‌ست که ضرب‌آهنگ را نگه می‌دارد."},"ICON-0032":{"nm":"کارت‌ویزیت","de":"هنگام دادن با دو دست، هنگام گرفتن با چشم‌در‌چشم. در یک ورق کاغذ، روزِ یک آدم و غرورش آرام فشرده می‌شود. در فاصله‌ی باریک میان نام و عنوان، اولین برداشتِ آن روز آهسته می‌نشیند."},"ICON-0033":{"nm":"جلد","de":"در بیرونی‌ترین لایه‌ی داستان، اول از همه باران و باد را به جان می‌خرد. برای محافظت از حروف درون، خودش از گوشه‌هایش فرسوده می‌شود. آن شور کوتاهِ پیش از باز کردن، همیشه از همین یک صفحه آغاز می‌شود."},"ICON-0034":{"nm":"کتاب‌درسی","de":"تلاش یک نفر با خط‌کشیدن‌ها و ماژیک‌های فسفری، انبوه و متراکم روی صفحاتش نوشته شده. وقتی نو باشد سرگردان‌کننده است، وقتی تمام شود، مطمئن‌ترین دوست می‌شود. رد آنچه ناشناخته بود و شناخته شد، روی هر صفحه به‌آرامی تا خورده است."},"ICON-0035":{"nm":"کارتِ رقص","de":"همین یک ورق، درِ سالن تمرین را چهارطاق باز می‌کند. اتاقی پر از آینه، صدای کوبیدن پا، اولین هشت‌ضربانی که یاد گرفتی. می‌گوید عیب ندارد اگر رقصیدنت هنوز دست‌وپاچلفتی‌ست، و آرام پشتِ لرزانت را جلو می‌راند."},"ICON-0036":{"nm":"پوشه‌ی اسناد","de":"کاغذهایی که تک‌وتنها سرگردان بودند، روی یک ستون فقرات مرتب رج می‌شوند و سرانجام نظمی می‌یابند. با آمدنِ نظم، داستانی شکل می‌گیرد، و هرچه ضخیم‌تر شود، گواهِ مهربان‌تری‌ست بر این‌که کسی همان‌قدر، صفحه‌به‌صفحه، زندگی کرده است."},"ICON-0037":{"nm":"برگه‌ی امتحان","de":"نوک انگشتانی که لحظه‌ای بالای خطوط خالی می‌لرزد. ترسناک‌تر از پاسخ غلط، رو‌به‌رو‌شدنِ مستقیم با چیزی‌ست که نمی‌دانی. وقتی نمره‌گذاری تمام شود، در هر جای اشتباه، حاشیه‌ای برای رشدِ بار بعد، آرام باقی می‌ماند."},"ICON-0038":{"nm":"حرف اِی","de":"اولین صدایی که فقط با باز کردن کامل دهان بیرون می‌آید. اغلب سرِ صف می‌ایستد، درست در آغاز یک نام. چون هر شروعی از این حرف آغاز می‌شود—برای همین همیشه کمی شجاع‌تر است."},"ICON-0039":{"nm":"حرف دی","de":"با پشتی که به‌نرمی خم شده، آرام یک واژه را نگه می‌دارد. سمتِ گردش، منظم به انتهای نام کسی آویزان می‌شود. پرزرق‌وبرق نیست، اما نبودش جای خالی می‌گذارد—همراهی آرام میان حروف الفبا."},"ICON-0040":{"nm":"برگه‌ی تمرین","de":"تنها کاغذ دنیا که اشتباه‌کردن رویش عیب نیست. اجازه می‌دهد همان حرکت را، همان جمله را، ده‌ها بار دوباره بنویسی. به تعداد صفحاتی که مچاله شدند و دور ریخته شدند، مطمئناً کسی داشت بهتر می‌شد."},"ICON-0041":{"nm":"برگه‌ی آهنگ‌سازی","de":"ساعت دو بامداد، یک زمزمه خواب را می‌شکند. مداد روی خطوط پنج‌خطی مکث می‌کند، چون ملودی از دست سریع‌تر است. در هر اثرِ پاک‌شده و دوباره نوشته‌شده، آوازی هنوز بی‌نام، اندک‌اندک بزرگ می‌شود."},"ICON-0042":{"nm":"پاسِ ورود","de":"درست همان لحظه که به گردن می‌آویزی‌اش، راهرویی معمولی به جهانی دیگر بدل می‌شود. کابل‌ها مثل مار در تاریکی می‌خزند، و آن‌سوی صحنه، شمارش‌معکوسی نشنیده آغاز می‌شود. صلاحیتِ ورود به این‌جا را، این یک ورق به‌جای تو بیان می‌کند."},"ICON-0043":{"nm":"برگه‌ی تماس عکاسی","de":"در هر خانه‌ی کوچک، حالتی متفاوت منجمد ایستاده. خندان، رو‌برگردانده، چشم‌بسته. یک‌به‌یک که نشان می‌دهی، شور همان روزِ فشردنِ شاتر به نوک انگشتانت برمی‌گردد. حتی انتخاب یک قاب، خودش پیشاپیش یک ثبت است."},"ICON-0044":{"nm":"برنامه‌ی روزانه","de":"فردا چه ساعتی، کجا، چه کاری. یک ورق کاغذ از پیش، مسیرِ یک روز را ترسیم می‌کند. میان خانه‌های فشرده‌ی دقیقه‌به‌دقیقه، کسی به‌ترتیبِ همین برگه، قدم‌به‌قدم به سمت رؤیا می‌رود."},"ICON-0045":{"nm":"برچسب","de":"پشتِ برچسبِ قیمت، زمانِ آرام سازنده آویزان است. تنها با همان کشیدنِ کوتاه، آن کاغذ کوچک سرانجام مالِ تو می‌شود. آنچه در محلِ بریدگی باقی می‌ماند، بوی نو بودن است و مشتی هیجان."},"ICON-0046":{"nm":"نمونه‌کارها","de":"جلد را که ورق بزنی، راهی که پیموده‌ای یک‌جا باز می‌شود. کنار صفحه‌ای که به آن مغروری، اولین تلاشِ دست‌وپاچلفتی‌ات هم شرمگین کنارش نشسته. وقتی برای اولین بار خودت را به کسی می‌سپاری، معرفی‌ای صادقانه‌تر از این نیست."},"ICON-0047":{"nm":"برنامه‌ریز","de":"امروز را می‌نویسی، هفته‌ی بعد را ترسیم می‌کنی، و گاهی یک خانه را سیاه می‌کنی. حتی اگر هرگز طبق برنامه پیش نرود، دستِ پرکننده‌ی خانه‌ها هرگز نمی‌ایستد. آیینی کوچک برای یک‌بار پیش‌زیستنِ آینده."},"ICON-0048":{"nm":"پلی‌لیست","de":"میان آهنگ‌های آرام و ضرباهنگ‌های تند، آواز‌ها را هم‌راستای آب‌وهوای دلِ آن روز می‌چینی. اگر فکر کنی روز کسی دقیقاً به همین ترتیب می‌گذرد، حتی سکوتِ میان قطعه‌ها هم مهربان می‌شود."},"ICON-0049":{"nm":"کارتِ دانش‌آموزی","de":"یک نام، یک عکس، و چند رقم. یک کارت که روزهای رفت‌وآمد میان کلاس و سالن تمرین را گواهی می‌دهد. در کارتی که از رفت‌وآمد در جیب، گوشه‌هایش فرسوده شده، روزمرگیِ تازه‌ای که دیگر بازنمی‌گردد، حک شده است."},"ICON-0050":{"nm":"دست‌بند","de":"یادت هست آن لحظه‌ای را که رنگِ آن روز را دورِ مچت بستی؟ شعارهایی که با هم فریاد زدید، شبِ کنسرتی که با هم خیس شد. حتی وقتی بند فرسوده و رنگ رفته باشد، بازش نمی‌کنی—چون می‌خواهی آن تابستان همچنان روی مچت زنده بماند."},"ICON-0051":{"nm":"بازوبند","de":"درست همان لحظه که دورِ بازو می‌پیچی‌اش، وزنی به‌نام مسئولیت آرام افزوده می‌شود. نشانِ کسی که سرِ صف می‌ایستد و آخر از همه محل را ترک می‌کند. یک تکه پارچه، کسی را وجبی بلندتر می‌کند."},"ICON-0052":{"nm":"حلقه","de":"خطی یک‌پارچه که بی‌هیچ شکستی دایره شده. چون آغاز و پایانش به هم می‌رسند، مردم در آن شکلِ ابدیت را می‌بینند. دو دست را آرام کنار هم بگذار، و پیش از هر کلامی، پیمانی به شکل درمی‌آید."},"ICON-0053":{"nm":"مدال","de":"روی تکه‌فلزِ کوچکِ نصب‌شده به سینه، روزهای تحمل‌شده حک شده. آنچه می‌درخشد فلز نیست، بلکه شب‌های بی‌شمار تمرینی‌ست که پشتِ آن پنهان است. پیش از افتخار، چیزی که بالا می‌آید، به‌نحوی، سپاسگزاری‌ست."},"ICON-0054":{"nm":"پیش‌بند","de":"بند را دورِ گردن که می‌بندی، دو دست آزاد می‌شوند. نشانه‌ای که آماده‌ای تمام‌وکمال در چیزی غرق شوی—چه آرد باشد چه رنگ. هرچه لکه‌ها یکی‌یکی بیشتر شوند، دلسوزیِ آن روز هم عمیق‌تر می‌شود."},"ICON-0055":{"nm":"کلاه‌گوش","de":"گوش‌ها را که به‌آرامی می‌پوشاند، صداهای بیرون یک قدم دور می‌شوند. در راه مدرسه با بادِ تیزِ سرد، پناهگاهی کوچک برای خزیدن به درونِ نرمی. گاهی گرمای زمستان، درست از همین نوک گوش‌ها آغاز می‌شود."},"ICON-0056":{"nm":"لباس‌صحنه","de":"پیش از بالا رفتنِ پرده، یک دست لباس روی چوب‌لباسی، نفس در سینه حبس کرده آویزان است. در هر درزش، رقصی تا شده. همین که بازو داخلش می‌رود، آدم به نقش بدل می‌شود، و صحنه، پوستِ دومِ همان لباس می‌شود."},"ICON-0057":{"nm":"تاج","de":"درست همان لحظه که روی سر می‌نشیند، پشتِ خمیده خودبه‌خود صاف می‌شود. درخشش طلایی‌اش پیش از قدرت، از مسئولیت زمزمه می‌کند. وزنِ خنکی که پیشانی را لمس می‌کند، خودش می‌گوید: هرچه جایگاه درخشان‌تر باشد، سنگین‌تر است."},"ICON-0058":{"nm":"شنل","de":"روی دوش که می‌اندازی‌اش، باد پشتِ کمرت پرپر می‌زند. حسِ آن یک تکه پارچه که با هر دویدن دنبالت می‌کند. کمتر نشانِ قهرمانی، بیشتر شبیهِ دلِ کودکانه‌ای‌ست که فقط می‌خواست باحال به‌نظر برسد."},"ICON-0059":{"nm":"نقاب","de":"صورت را که بپوشانی، عجیب صادق‌تر می‌شوی. مثل بازی‌های قدیمی حیاط که پشتِ نقاب می‌شد با خیالِ راحت خندید و گریست. آن‌سوی چهره‌ی پنهان، صدای واقعی‌ای که معمولاً فرومی‌خوری، بلندتر بیرون می‌زند."},"ICON-0060":{"nm":"رژلب","de":"درِ آن را که بچرخانی و یک خط بکشی، تصمیمی کوچک بر لب می‌نشیند. آخرین بازبینیِ پیش از آینه، خطی سرخ کشیده‌شده روی تردید. در همان لحظه‌ی کوتاهِ رنگ‌زدن، ترس آرام کنار می‌رود."},"ICON-0061":{"nm":"ژاکت","de":"وقتی خط شانه دقیقاً جفت می‌شود، آدم کمی استوارتر می‌شود. آستین که بالا بزنی، دلِ کار؛ یقه که بالا بزنی، دلِ بیرون‌زدن. یک دست لباس، آرام حالتِ آن روز را تعیین می‌کند."},"ICON-0062":{"nm":"کمربندِ تکواندو","de":"هر بار رنگ یک درجه عوض می‌شود، مقدار عرقِ ریخته‌شده‌ی زیرش هم فرق می‌کند. صبحِ سالنِ تمرینی که گره را محکم می‌بستی و تعظیم می‌کردی. با نوک انگشتانی که کمربند را می‌بندند، ذهنِ پراکنده دوباره جمع می‌شود."},"ICON-0063":{"nm":"عینک‌ایمنی","de":"جلوِ چشم که می‌گذاری‌اش، جهان یک تُن روشن‌تر می‌شود. آن‌سوی سپرِ گردی که باد و گرد‌وغبار را دور نگه می‌دارد، حتی همان مسیرِ معمولیِ همیشگی هم عجیب مثل خطِ شروع می‌درخشد."},"ICON-0064":{"nm":"دستکش","de":"در دست که بکنی‌اش، شجاعتِ محکم‌گرفتنِ هر چیزی بالا می‌زند. انگشتانی که از ترسِ انداختن جمع می‌شدند، سرانجام کاملاً باز می‌شوند. آنچه محافظت می‌شود دست است، اما آنچه واقعاً نگه‌داشته می‌شود، چالشِ بعدی‌ست."},"ICON-0065":{"nm":"ماسک","de":"پایینِ صورت که پوشیده شود، چشم‌ها حرف‌های بیشتری می‌زنند. در خیابانی شلوغ، آزادیِ کوچکِ ناشناس‌ماندن، پشتِ همان پوششِ اندک. برای همین لبخندی که در محلِ برداشتنِ کامل باقی می‌ماند، روشن‌تر پخش می‌شود."},"ICON-0066":{"nm":"کلاه","de":"لبه را کمی که پایین بکشی، هم آفتاب هم نگاه‌ها یک وجب کنار می‌روند. زیرِ سقفِ کوچکِ روی سر، امروز دست‌کم می‌شود با چهره‌ای راحت راه رفت. سبک‌ترین دگرگونی همیشه از همین‌جا آغاز می‌شود."},"ICON-0067":{"nm":"پیراهن","de":"خش‌خش، از یقه‌ی تازه‌اتوکشیده بوی صبح می‌آید. همین‌طور که دکمه‌ها را یکی‌یکی از بالا می‌بندی، دلِ آشفته هم خانه‌به‌خانه مرتب می‌شود. یک ورق سفید، اولین جمله‌ی روز را می‌گشاید."},"ICON-0068":{"nm":"شال‌گردن","de":"یک دور که دورِ گردن بپیچد، مسیرِ باد بسته می‌شود. همان‌طور که سرِ آن روی شانه می‌رقصد، سرما دیگر به درون راه نمی‌یابد. یک تکه پارچه، جایی میان زیبایی و گرما."},"ICON-0069":{"nm":"دستکش","de":"وقتی تا نوک انگشتان پیچیده می‌شوی، از سرما هم دیگر نمی‌ترسی. تجملِ کوچکِ زمستان است، دستی که فوتش می‌کردی، آرام‌آرام گرم می‌شود. یک لنگه که درآورده و به کسی داده می‌شود، دستِ دیگری را هم گرم می‌کند."},"ICON-0070":{"nm":"پلاکِ نظامی","de":"دو ورقِ نازک آرام رو‌به‌روی هم می‌ایستند. سه هجای یک نام و چند رقم—همین کافی‌ست که کسی تا آخر به یاد بماند. فلزی سرد است، اما عجیب شبیهِ گرم‌ترین پیمان است."},"ICON-0071":{"nm":"حلقه‌ی نگه‌دارنده","de":"انگشت را که در آن بیندازی، نگرانیِ افتادن آرام محو می‌شود. اطمینانی کوچک، آن‌قدر که با یک دست هم بتوانی محکم بگیری و تکان بدهی. وقتی برای یک عکس بازو را دراز می‌کنی، بی‌صدا کف دستت را نگه می‌دارد."},"ICON-0072":{"nm":"تاجِ‌گل","de":"روی سر که بگذاری‌اش، آغوشی از بهار همراهت می‌آید. گل‌هایی چیده‌شده از دشت و بافته‌شده به‌شکلِ حلقه، به‌نرمی پیشانی را دور می‌زنند. روی لبخندِ روشنِ عکس، عطرِ کم‌رنگِ علف مدت‌ها می‌ماند."},"ICON-0073":{"nm":"چشم‌بند","de":"چشم را که بپوشاند، هم نور هم صدا یک‌جا دور می‌شوند. چون چیزی دیده نمی‌شود، تنها صدای نفسِ خودت شنیده می‌شود. لحظه‌ای جهان را خاموش کن و به آرامشِ درون قدم بگذار، در پشتِ سرت دری کوچک آرام بسته می‌شود."},"ICON-0074":{"nm":"شال‌گردن‌بافتنی","de":"یک دور، دو دور، هر بار که دورِ گردن می‌پیچد، زمستان اندکی رام‌تر می‌شود. شاید جایی میانِ نخ‌های پشمی، دلِ کسی که آن را بافته، مخلوط شده باشد. تا نوک بینی که در آن فرو بروی، جهان کمی گرم‌تر می‌شود."},"ICON-0075":{"nm":"نقابِ نیم‌ماه","de":"در حالی که تنها نیمی از صورت پوشیده است، شبِ بالماسکه آغاز می‌شود. لب‌های آشکار می‌خندند، چشم‌های پنهان رازی در خود دارند. آن فاصله‌ی باریکِ نیمه‌شناخته، هوای نیمه‌شب را به تپش می‌اندازد."},"ICON-0076":{"nm":"کلاه‌بره","de":"کج که روی سر بگذاری‌اش، روزی معمولی آرام رنگ‌وبویی می‌گیرد. یک تکه پارچه‌ی گرد و صاف، آرام حالتِ هنرمندانه‌ای بر شانه‌ها می‌پوشاند. حتی همان لحظه‌ی کوتاهِ انتخابِ زاویه جلوی آینه هم لذت‌بخش است."},"ICON-0077":{"nm":"چوکر","de":"دقیقاً اندازه‌ی گردن که بسته شود، نگاه‌ها طبیعتاً به بالا کشیده می‌شوند. یک بندِ نازک، کل فضا را عوض می‌کند. کوچک اما واضح، مثل قفلی که اطمینانِ آن روز را پر می‌کند."},"ICON-0078":{"nm":"پارکا","de":"زیپ را تا بالا که بکشی، حتی کولاک هم یک قدم عقب می‌نشیند. دست را عمیق در گرمای درون فرو ببر، تا همهمه‌ی تمامِ جهان آرام بگیرد. خانه‌ای کوچک که حتی میانِ بادِ خشن هم تا آخر گرم می‌ماند."},"ICON-0079":{"nm":"شلوار","de":"پا که تویش برود و کمر که بسته شود، سرانجام آماده‌ی بیرون‌رفتنی. با هر قدم، پارچه به‌نرمی همراهِ رجِ خودش حرکت می‌کند. جایی میان راحتی و آراستگی، روز آغاز می‌شود."},"ICON-0080":{"nm":"پیرسینگ","de":"حتی افزودنِ یک نقطه‌ی کوچک هم اندکی شجاعت می‌خواهد. یک برقِ فلزی، نقطه‌ای واضح بر گوشِ معمولی می‌گذارد. بسیار کوچک، اما نوری‌ست که امروزِ قطعاً متفاوت‌شده را بازمی‌تاباند."},"ICON-0081":{"nm":"موج‌نگاشت","de":"برای مهندسِ صدا، آواز شنیده نمی‌شود—دیده می‌شود. از خط‌الرأسی که روی صفحه بالا و پایین می‌رود، می‌خواند که نفسِ آن روز کجا لرزیده. صدایی که پیش‌تر نامرئی بود، مثلِ رشته‌کوهی دراز می‌کشد و توپوگرافیِ یک قطعه را می‌گشاید."},"ICON-0082":{"nm":"کوک‌کننده","de":"درست پیشِ اجرا، شش سیم را یکی‌یکی نوازش می‌کنی، تا نتِ آشفته سرِ جایش بنشیند. حتی نیم‌درجه هم که کج باشد، تماشاگران مثل روح آن را می‌فهمند. کوک‌کردنِ آن‌قدر دقیق که هیچ‌کس نفهمد—این خودش مهربانی‌ای‌ست رو‌به‌روی صحنه."},"ICON-0083":{"nm":"بندِ نگه‌دارنده","de":"یک بار که دورِ مچ بپیچدش، ترسِ افتادن آرام باز می‌شود. روی صحنه، ترسناک‌ترین چیز از دست دادنِ چیزی‌ست، پس با همین بندِ کوچک، دل سرانجام آرام می‌گیرد."},"ICON-0084":{"nm":"سنج","de":"در همان یک لحظه‌ی برخورد، بر آخرین جمله‌ی قطعه، نقطه‌ای واضح گذاشته می‌شود. صفحه‌ی طلایی می‌داند چگونه کوتاه‌ترین طنین را بدهد و طولانی‌ترین پژواک را برجای بگذارد. پایان باید این‌گونه روشن بسته شود."},"ICON-0085":{"nm":"گیتار","de":"انگشتان که روی شش سیم بلغزند، اتاقی کوچک تمام‌وکمال به صحنه بدل می‌شود. اولین ملودیِ کسی، زمزمه‌های تنهاییِ سپیده‌دمِ بی‌خوابی—همه، اول از همه در همین بدنه‌ی چوبیِ گرد، نفس گرفتند."},"ICON-0086":{"nm":"ابرِ صدا","de":"در یک گوشه‌ی آسمان، نُت‌ها مثل پنبه به هم می‌چسبند و شناور می‌مانند. می‌گویند وقتی بادی یک‌بار می‌گذرد، به‌جای قطره‌های باران، ملودی می‌بارد—و بچه‌های جزیره حتی بی‌چتر به استقبالش می‌روند."},"ICON-0087":{"nm":"قدم‌رقص","de":"مسیرِ روی صحنه حسابی‌ست که با نوکِ پا حل می‌شود. این‌جا یک قدم، آن‌جا نیم‌ضربان—اگر اشتباه شد اشکالی ندارد، آرام برو. خانه‌هایی که صدها بار زیرِ پا خورده و در بدن حک شده، کنار هم جمع می‌شوند تا نقشه‌ی یک قطعه کامل شود."},"ICON-0088":{"nm":"آمپلی‌فایر","de":"جعبه‌ای که زمزمه را به فریاد بدل می‌کند. با این‌همه، پیش از بالا بردنِ یک پله‌ی صدا، دست همیشه مکث می‌کند. این جعبه می‌داند که صدای دقیق‌تر، نه بلندتر، به آخرین ردیفِ تماشاگران می‌رسد."},"ICON-0089":{"nm":"پنبه‌ی نُت","de":"وقتی سرهای گردِ نُت‌ها جمع می‌شوند و توپی پنبه‌ای می‌سازند، مثل بالش نرم می‌شود. آرام سرت را رویش بگذاری، شایعه‌ای می‌گوید لالایی‌ای به‌سختی شنیدنی از آن بیرون می‌آید—مهربان‌ترین شایعه‌ی جزیره."},"ICON-0090":{"nm":"کاست","de":"دکمه‌ی عقب‌گرد را که بفشاری، جیرجیرکنان نوار به‌آرامی به اولین آهنگِ آن تابستان برمی‌گردد. درونِ جعبه‌ای کوچک که یک دوران کامل رویش پیچیده، زمانی که دیگر نمی‌توان لمسش کرد، دست‌نخورده به خواب رفته."},"ICON-0091":{"nm":"چنگک‌کوک","de":"دو شاخه‌ی فلزی که کمی به هم بخورند، یک نتِ مرجع در هوا زاده می‌شود. همه‌ی سازها بی‌صدا سر تعظیم فرود می‌آورند مقابل همین لرزشِ کوچک. آغازِ هر چیزی، از همین‌قدر ارتعاشی ظریف می‌آید."},"ICON-0092":{"nm":"تراشه‌ی موج","de":"تکه‌ای صدا، به‌آرامی درون تراشه‌ای به‌اندازه‌ی ناخن حبس می‌شود. یک هم‌آوازِ بی‌قصدِ ضبط‌شده، خنده‌ی کسی که فکر می‌کردی دیگر نیست—هنوز همین‌جا گرم زنده‌اند و نفس می‌کشند."},"ICON-0093":{"nm":"صفحه‌ی گرام","de":"سوزن که اولین قدمش را در شیار بردارد، اول از همه نفسِ خش‌خشِ کم‌رنگی شنیده می‌شود. حتی همان نویزِ کوچک را هم دوست دارند، تا جایی که برخی هرگز این دیسکِ سیاه را از دست نمی‌گذارند."},"ICON-0094":{"nm":"جیب","de":"آنچه را بیشتر از همه دوست داری، همیشه نزدیک‌ترین جا به قلب نگه می‌داری. یک کیسه‌ی پارچه‌ایِ به‌اندازه‌ی کف دست، روزی گرم‌کن دست می‌شود، روزی طلسم، و روزی دیگر جای نگهداریِ راز."},"ICON-0095":{"nm":"چسب‌زخم","de":"شب‌هایی که تمرین طولانی می‌شود، روی هر پاشنه‌پا یک مدالِ کوچک می‌نشیند. تکه‌ای چسبیده برای فروخوردنِ کلمه‌ی «درد می‌کند»—پیمانی آرام و ناشناخته، برای فردا هم بی‌درنگ رقصیدن."},"ICON-0096":{"nm":"بالش","de":"جایی که آدم تمامِ صحنه‌ی یک روز را زمین می‌گذارد، سرانجام همین یک مربعِ نرم است. سر را آرام که بگذاری، صدای کف‌زدنی که در گوش مانده بود آهسته فرو می‌نشیند، و بر جزیره هم سرانجام شب فرود می‌آید."},"ICON-0097":{"nm":"زنگ","de":"دینگ، با یک صدای کوتاه، کسی در را هل می‌دهد و وارد می‌شود. هم نشانِ آمدن مهمان است، هم سلامی بر باز شدنِ روز. یک تکه فلزِ کوچک، تمام روز فقط خوش‌آمدگویی می‌کند."},"ICON-0098":{"nm":"کیف‌محافظ","de":"هرچه چیزی گران‌بهاتر باشد، خانه‌ای محکم‌تر برایش می‌سازند. دستی که هر بار با احتیاط بازش می‌کند و می‌بندد، چون آنچه درونش هست، صرفاً یک شیء نیست؛ دلی‌ست که دلت نمی‌آید از دستش بدهی."},"ICON-0099":{"nm":"برس","de":"تا آخرین موی برس هم که با رجِ سطح کشیده شود، گردوغباری که در گوشه چسبیده آرام عقب می‌نشیند. لطفِ دستی که حتی از جاهای دیده‌نشده هم دریغ نمی‌کند، هر روز صبحی تازه به اتاق هدیه می‌دهد."},"ICON-0100":{"nm":"طرحِ‌اولیه","de":"خطوطِ پیش از تکمیل، تردید را عمداً پنهان نمی‌کنند. در هر اثرِ پاک‌شده و دوباره کشیده‌شده، آنچه می‌خواسته بشود بی‌دروغ باقی می‌ماند. هرچه آغاز دست‌وپاچلفتی‌تر باشد، صادق‌تر است."},"ICON-0101":{"nm":"عروسک","de":"موجوداتی هستند که فقط با در آغوش‌گرفتن، بی‌هیچ کلامی، تسلی می‌دهند. آن دوست پنبه‌ای که شب‌های لرزیدن دست‌ها پشت صحنه، کنار بالش با تو لرزید—هرکسی یکی از آن‌ها را جایی در قلبش نگه می‌دارد."},"ICON-0102":{"nm":"ناقوس","de":"ناقوس معبد کوهستانی یک بار به صدا درمی‌آید و تمام دره را در می‌نوردد. این طنین خواستِ دلِ فلز است که می‌خواهد دورتر و دورتر برسد و طولانی می‌گرید، چنان‌که صدایش آرام‌آرام در سینه‌ی شنونده فرومی‌نشیند."},"ICON-0103":{"nm":"چتر","de":"وقتی چتر را با هم می‌گیرند، حتماً شانه‌ی یکی‌شان خیس می‌شود. زیر چتری که آرام کج شده، همان شانه‌ی خیس روشن‌ترین گواه مهربانی است. راه کوتاهی که زیر یک سقف طی شده، مدت‌ها در دل باقی می‌ماند."},"ICON-0104":{"nm":"تشک","de":"یک تکه که روی زمین خالی پهن شود، همان‌جا فوراً اتاق تمرین می‌شود. جایی که بی‌کلام غلتیدن و افتادن را می‌پذیرد—بی‌شمار حرکت، نخستین بار روی همین تشک به بدن راه یافت."},"ICON-0105":{"nm":"زنگوله","de":"آرام که تکانش بدهی، صدایی زلال از میان دست بیرون می‌غلتد. همان شادی کوچک و گردی که کودکان قدیم به لبه‌ی جامه‌های رنگارنگشان می‌بستند و در حیاط می‌دویدند، دوباره روی کف دست بیدار می‌شود."},"ICON-0106":{"nm":"مار اسباب‌بازی","de":"شکل کشیده و آویزانش شیطنت‌آمیز آدم را می‌ترساند. ترسیدن، فرار کردن و آخرش قاه‌قاه خندیدن—این‌گونه شوخی‌ها هم در نهایت شاخه‌ای از مهربانی به یکدیگرند."},"ICON-0107":{"nm":"اسباب‌بازی","de":"هرکسی، حتی در بزرگسالی، جعبه‌ای دارد که دلش نمی‌آید دورش بیندازد. درونش خنده‌های درخشان‌ترین روزها هنوز محکم، مثل فنری کوک‌نشده، پیچیده مانده است."},"ICON-0108":{"nm":"سفره","de":"پاهای تاشده را که باز کنی، هر جایی فوراً جای خانواده می‌شود. صدای برخورد قاشق‌ها دور هم، همان همنوازیِ ساده، گرم‌ترین قطعه‌ی تمام روز است."},"ICON-0109":{"nm":"صابون","de":"کم‌کم در دست کوچک می‌شود و بی‌صدا کسی را پاک می‌کند. خودش را فرسودن برای شستن دیگری—تنها مدت‌ها پس از فروکش‌کردن کف‌ها، آن دل آرامش نمایان می‌شود."},"ICON-0110":{"nm":"شانه","de":"همان‌طور که موهای گره‌خورده را تار به تار باز می‌کند، روزی درهم‌ریخته هم کم‌کم مرتب می‌شود. یک دست کوتاه جلوی آینه، پشت مو تا وضع دل را هم آرام‌آرام سامان می‌دهد."},"ICON-0111":{"nm":"قفس پرنده","de":"پرنده‌ای هست که با درِ باز هم نمی‌رود و می‌خواند. دلی که نه از حبس، بلکه از میل به ماندن می‌ماند—این تفاوت ظریف را این قفس زودتر از هرکس درمی‌یابد."},"ICON-0112":{"nm":"کیسه گرمازا","de":"در صف انتظار زمستانی جلوی سالن، گرمای کوچکی در جیب انگشتان یخ‌زده را آرام گرم می‌کند. مهربانی‌ای به اندازه‌ی کف دست که کسی از پیش، با فکر تو که در سرما می‌لرزی، تکانش داده و گرمش کرده است."},"ICON-0113":{"nm":"دستمال","de":"پارچه‌ای که اشک و عرق را بی‌گله می‌پذیرد. گلدوزی کوچک روی گوشه‌اش، مانند آخرین خداحافظی کسی که زودتر رفت، آنجا زیبا مانده تا نگوید فراموشش کن."},"ICON-0114":{"nm":"اسپری","de":"یک بار که فشارش بدهی، بافت هوا در یک لحظه دگرگون می‌شود. مه‌ای که روی صحنه می‌پراکند، گیاهی کنار پنجره‌ی صبح—هر دو در این قطره‌های نازک، لحظه‌ای دنیایی دیگر می‌شوند و می‌درخشند."},"ICON-0115":{"nm":"کاغذ رایحه","de":"انتخاب یک عطر، عجیب شبیه انتخاب یک خاطره است. رشته‌ای نازک از بو که به نوک کاغذی باریک نشسته، آرام فصلی را که فکر می‌کردی فراموش شده، به سوی بینی برمی‌گرداند."},"ICON-0116":{"nm":"میز غذاخوری","de":"در هر رگه‌ی فرسوده‌ی چوب، شمار وعده‌هایی که با هم خورده شده آرام حک شده است. شب‌های پرهیاهو، و شب‌های دیرهنگام تنها—این مربع بی‌کلام همه را در خود گرفت و صیقلی شد."},"ICON-0117":{"nm":"کلاف نخ","de":"یک سرش را آرام بکشی، به‌روانی باز می‌شود؛ یک بخیه بزنی، دوباره وصل می‌شود. وصل‌کردنِ چیزِ گسسته همیشه آرام از همین یک رشته‌ی نازک نخ آغاز می‌شود."},"ICON-0118":{"nm":"بارانی","de":"حتی در روزهای رگبار، همین یک دست لباس است که سرانجام تو را بیرون می‌کشد. تنها کسی که شادیِ خیس‌شدن در باران را می‌شناسد، باران را بهانه‌ی ماندن در خانه نمی‌کند."},"ICON-0119":{"nm":"کیسه","de":"دهانه را که گرد جمع کنی، هرچه درونش هست بالاخره امن می‌شود. در یک کیسه‌ی کوچک و دست‌خورده، سکه و خاطره‌ی روزی و حرف‌های ناگفته با هم می‌لرزند."},"ICON-0120":{"nm":"قفسه کتاب","de":"انگشت را آرام روی پشت کتاب‌های چیده‌شده بکشی، فصل‌های گذشته زیر نوک انگشت لمس می‌شوند. اینکه نمی‌شود کتاب خوانده‌شده را دور انداخت، از این‌روست که همان‌جا هنوز خودِ آن‌روزه‌ات زنده است."},"ICON-0121":{"nm":"برج کتاب","de":"کتاب خوانده‌شده را کنار می‌خوابانند، خوانده‌نشده را روی هم می‌چینند. حتی اگر قولِ روزی همه را خواندن نزدیک سقف کمی بلرزد، همان لرزیدن را هم دوست داری، پس امروز هم یک جلد دیگر می‌گذاری."},"ICON-0122":{"nm":"چرخ دونده","de":"با تمام سرعت هم بدوی انگار سرجایت هستی، اما پاهای کوچک اول ریتم نوک انگشتان را می‌آموزند. دیروزهایی که هرگز نایستادند جمع می‌شوند و روزی روی راهی واقعی، درخشان می‌تابند."},"ICON-0123":{"nm":"روکش","de":"برای اینکه گرد ننشیند، در آفتاب رنگ نبازد—حتی روکش‌کردن هم پرمایه‌ی دقتِ نوک انگشتان است. هرچه چیزی را بیشتر دوست بداری، در جایی نادیدنی مهربانانه‌تر از آن نگهداری می‌شود."},"ICON-0124":{"nm":"کلاف پشم","de":"رشته‌ای که روی زانوی مادربزرگ می‌غلتید و باز می‌شد. گره‌خورده به‌نظر می‌رسد، اما سرش را بیابی و آرام بکشی، بی‌خطا دنبال می‌کند. این‌گونه بود که شب‌های زمستان بخیه به بخیه بلندتر شد."},"ICON-0125":{"nm":"کیف کوچک","de":"بالم لب، کش مو، نامه‌ای تاشده—کوچک به‌نظر می‌رسد، اما درونش دلِ یک روز کامل جای گرفته است. با صدای بسته‌شدنِ زیپ، تمام خرده‌ریزهای عزیز یک‌جا امن می‌شوند."},"ICON-0126":{"nm":"دسته صندلی","de":"بعدازظهری که میان کتاب‌خواندن به خواب رفتی، شبی که در حال مکالمه قدم می‌زدی. جایی که هرچه بیشتر بنشینی رد دست عمیق‌تر می‌شود، همه‌ی آرامش‌هایی که آرنج به یاد دارد، به اندازه‌ی یک وجب، آرام انباشته شده است."},"ICON-0127":{"nm":"بسته","de":"تا پیش از پاره‌شدن، هنوز مالِ هیچ‌کس نیست. یک بسته‌ی مهرشده لبریز از انتظاری ناگشوده است، چنان‌که نوک انگشتانی که گوشه‌اش را می‌گیرند به‌آرامی می‌لرزند. این همان هیجانِ بازکردن است."},"ICON-0128":{"nm":"کاغذ کادو","de":"دلی که یک قدم زودتر از هدیه می‌رسد. تا گوشه‌ها را تا می‌زنی و با روبان می‌بندی، چهره‌ی خندان کسی که آن را دریافت خواهد کرد، از پیش درخشان در دستانت باز می‌شود."},"ICON-0129":{"nm":"دسته بازی","de":"دکمه‌هایی که شست‌ها زودتر از سر به‌خاطر می‌سپارند. باختی، اما فقط یک دور دیگر—و همان یک دور آخر تا صبح بیدارت نگه می‌دارد. وزنی که دقیقاً به دست می‌آید، ماجراجویی امشب را آرام بلند می‌کند."},"ICON-0130":{"nm":"چراغ راهنما","de":"قرمز یعنی لحظه‌ای بایست، سبز یعنی حالا می‌توانی بروی. با یک قول ساده، بی‌شمار راه بی‌آنکه درهم بپیچند جریان می‌یابند. اینکه حتی انتظار هم نوبت دارد را، نور چشمک‌زن مهربانانه می‌گوید."},"ICON-0131":{"nm":"پیکان","de":"مهربان‌ترین شکل برای کسی که راهش را گم کرده. وقتی معلوم نیست کجا باید رفت، همان یک جهت که کسی از پیش کشیده، قدم‌های ایستاده را دوباره استوار می‌کند."},"ICON-0132":{"nm":"مختصات","de":"با فقط دو عدد می‌توان هر نقطه‌ی دنیا را دقیق نشان داد. جایی که قرار ملاقات گذاشتید، ساحلی که در آن گنج پنهان شد. تا قول‌وقرار راهش را گم نکند، همان یک نقطه‌ی کوچک تا آخر نگهش می‌دارد."},"ICON-0133":{"nm":"کاشی","de":"تنها، فقط یک تکه‌ی مربع‌شکل است. لحظه‌ای که شانه‌به‌شانه در کنار هم می‌خوابند، کف و دیوار می‌شوند. چیزهای کوچک دور هم جمع می‌شوند تا جایی بسازند که کسی بتواند با خیال راحت پا بگذارد."},"ICON-0134":{"nm":"ساعت شنی","de":"وقتی محفظه‌ی بالا خالی می‌شود، محفظه‌ی پایین آرام‌آرام پر می‌شود. با دیدن شن‌هایی که نرم فرومی‌ریزند، باور می‌کنیم زمان می‌گذرد. برش گردانی، دوباره از اول—این همان دروغ مهربانِ شن است."},"ICON-0135":{"nm":"توپ","de":"پرتابش کنی برمی‌گردد، لگدش بزنی می‌غلتد. گرد بودن و ندانستنِ اینکه کجا خواهد جهید، بزرگ‌ترین جذابیتش است. وسط زمین بازی، صدای خنده همیشه از همین کره‌ی کوچک، به‌شکلی گرد آغاز شده است."},"ICON-0136":{"nm":"کلید برق","de":"کلیک، با یک فشار روشن، با یک فشار خاموش می‌شود. همان صدای کوچکی که وقتی وارد اتاق تاریک می‌شوی می‌فشاری، آغاز و پایانِ پراکنده‌ی روز را با یک خط روشن از هم جدا می‌کند."},"ICON-0137":{"nm":"علامت سؤال","de":"ندانستنِ پاسخ، چیز شرم‌آوری نیست. گواه خوش‌آیندِ زنده‌بودنِ کنجکاوی است. وقتی این قلاب کوچک آرام به ذهن ضربه می‌زند، یادگیری بالاخره نخستین قدمش را برمی‌دارد."},"ICON-0138":{"nm":"کبریت","de":"چوبی که بدن خودش را می‌خراشد تا آتش را تحویل دهد. کوتاه می‌سوزد و بی‌صدا محو می‌شود، اما در همان لحظه‌ی کوتاه، شمعی روشن می‌شود و اجاقی گرم. یک بخشش کوچک، نخستین دکمه‌ی گرما می‌شود."},"ICON-0139":{"nm":"چهارپایه","de":"یک قدم بالا بروی، دست به قفسه‌ای می‌رسد که دستت نمی‌رسید. کاری که قد کسی را لحظه‌ای بلند می‌کند. جایی مهربان که پایین می‌خزد تا ما را آرام بالاتر ببرد، همین‌جاست."},"ICON-0140":{"nm":"ساعت مچی","de":"نخستین چیزی که روزی که تصمیم به ورزش گرفتی به مچ بستی. مربی کوچکی که ضربان قلب و شمار قدم‌ها را می‌شمارد، آرام ضربه می‌زند و می‌گوید امروز کمی بیشتر از دیروز راه رفته‌ای."},"ICON-0141":{"nm":"زنگ هشدار","de":"وفادارترین دوستی که هر صبح از او دلخوریم. به‌لطف آنکه هر بار به‌جای ما با وسوسه‌ی پنج دقیقه‌ی بیشتر زیر پتو می‌جنگد، نه قرار دیر می‌شود نه رؤیا. همان صدای بی‌رحمانه، در حقیقت تشویق است."},"ICON-0142":{"nm":"هسته","de":"درونی‌ترین بخشی که تا آخر، بعد از کندنِ همه‌ی پوسته می‌ماند. دانه‌ی سیب، صداقتِ دل—هرچه باشد، همان مرکزِ چیز محکم‌تر را در خود دارد. همان یک نقطه که حتی با لرزیدن هم در نهایت باقی می‌ماند."},"ICON-0143":{"nm":"خودکار","de":"لکه‌ای که پیش از خشک‌شدنِ جوهر، آرام روی لبه‌ی دست پخش می‌شد. خوب بنویسد یا نه، نخستین خطی که پیش‌روی کاغذ سفید کشیده می‌شود همیشه اندکی شجاعت می‌خواهد. پُلی است که فکر را به نوک انگشتان می‌رساند."},"ICON-0144":{"nm":"قلم‌مو","de":"وقتی جوهر را می‌مکد و روی کاغذ برنجی می‌گذرد، حتی یک لرزش دودل هم به‌تمامی برجا می‌ماند. اگر با طمعِ سرعت بنویسی، فوراً لو می‌رود. قلم‌مو زودتر از هرکس، صداقتِ نشسته در نوک انگشتان را می‌شناسد."},"ICON-0145":{"nm":"حباب گفتار","de":"جایی که پیش از آنکه کلمات از دهان بیرون بیایند، گرد بالای سر آرام بالا می‌آید. همان یک جمله که می‌خواهی بگویی همین‌جا نگه داشته می‌شود. وقتی خالی است، در حال انتخابِ آن است که چه بگذارد پُرش کند."},"ICON-0146":{"nm":"چک‌باکس","de":"دو خط که روی مربع خالی بکشی، دل کمی سبک‌تر می‌شود. نشانی کوچک که خودت به‌خاطر کاری تمام‌شده به خودت می‌دهی. آخر روز، با نگاه به خانه‌های پرشده، خیالمان راحت می‌شود که امروز هم خوب زندگی کردیم."},"ICON-0147":{"nm":"تبلت","de":"هرجا انگشت لمس کند، نقاشی پخش می‌شود و حروف جاری می‌شوند. آرام روی زانو بگذاری، یک دنیا روشن می‌شود. سبک است، اما امکاناتی که در آن نهفته، هرگز نازک نیست."},"ICON-0148":{"nm":"کنترل از راه دور","de":"استعدادی خدادادی برای پنهان‌شدن در شکاف مبل دارد. قدرت عوض‌کردن کانال همیشه از آنِ کسی است که آن را در دست دارد. کوچک‌ترین و صمیمی‌ترین کشمکش خانواده، روی همین یک وجب رخ می‌دهد."},"ICON-0149":{"nm":"وزنه تعادل","de":"وزنه‌ای که خودش تا پایین‌ترین نقطه پایین رفته تا چیز لرزان را نگه دارد. بالا هرچقدر بلرزد، اگر پایین سنگین باشد، در نهایت نمی‌افتد. تعادل همیشه در جایی نادیدنی تاب می‌آورد."},"ICON-0150":{"nm":"پازل","de":"شبی که دنبال آخرین قطعه‌ی گم‌شده حتی زیر مبل را هم لمس کردی. آن لذتِ بی‌صدای لحظه‌ای که دقیقاً جا می‌افتد. وقتی چیزهای پراکنده جای خود را می‌یابند، سرانجام تصویر کامل می‌شود."},"ICON-0151":{"nm":"خط‌کش","de":"اندازه‌گرفتنِ طول، نوعی وفاداری به یک قول هم هست. تا یک وجب برای همه یکسان باشد، خط‌های آن با صداقت پشت هم می‌ایستند. یک خط صاف حتی می‌تواند دلِ کج را هم صاف کند."},"ICON-0152":{"nm":"بوم نقاشی","de":"سطح سفیدِ خالی، ترسناک‌ترین و در عین حال هیجان‌انگیزترین چیز است. تا پیش از نخستین نقطه، هرچیزی می‌تواند بشود. خالی‌بودن پایان نیست، نام دیگری برای آغاز است."},"ICON-0153":{"nm":"مکعب روبیک","de":"افراد کم‌شماری نیستند که برای مرتب‌کردن هر شش وجه، تمام شب را بیدار مانده‌اند. سماجت نوک انگشتانی که پی‌درپی می‌چرخانند. لحظه‌ای که رنگ‌های درهم جای خود را می‌یابند، جهانی کوچک منظم می‌شود."},"ICON-0154":{"nm":"کنسول دستی","de":"صفحه‌ی کوچکی که در تعطیلات، پسرخاله‌ها و دخترخاله‌ها سرها را کنار هم به آن می‌دوختند. دنیایی از ماجراجویی که درست در کف دست جا می‌گیرد. با شنیدنِ فقط یک نُتِ ملودیِ روشن‌شدن، تمام آن تابستان دوباره برمی‌گردد."},"ICON-0155":{"nm":"دستگیره","de":"همان حسی که وقتی محکم می‌گیری در دست جا می‌افتد، آرام اعتمادبه‌نفس می‌دهد. تا نلغزد، تا از دست نرود. در مهم‌ترین لحظه، همان نقطه‌ی اتصالی است که دست و ابزار را به یک واحد محکم پیوند می‌زند."},"ICON-0156":{"nm":"خودنویس","de":"تا زمانی که با جوهرِ پرشده می‌نویسی، حتی خط دستخط هم کمی مرتب‌تر می‌شود. با صدای خش‌خش نوکش دل را آرام می‌کنی، و بی‌صدا شبیهِ همان دقتی می‌شود که به‌آرامی نخستین سطرِ نامه‌ی دست‌نویس را آغاز می‌کرد."},"ICON-0157":{"nm":"پالت رنگ","de":"کنار قرمز آبی، روی زرد سبز. روی این تخته‌ی کوچک که رنگ‌ها منظم کنار هم خوابیده‌اند، تصویر سرانجام حالت خود را می‌یابد. تمام ماجراجویی مخلوط‌کردن و لایه‌زدن، همین‌جا نخستین قدمش را برمی‌دارد."},"ICON-0158":{"nm":"ست","de":"هریک به‌تنهایی ساده است، اما کنار هم که بچینی‌شان، یک داستان کامل می‌شوند. همان اطمینانِ لحظه‌ای که هیچ قطعه‌ای کم نیست و همه سرجایشان هستند. جمع‌کردنِ چیزهای پراکنده در یک جا، شادیِ کوچکِ تکمیل‌شدن را در خود دارد."},"ICON-0159":{"nm":"توپ بدمینتون","de":"وقتی راکت آن را می‌زند و بالا می‌رود، پرها صدای بادی نرم می‌سازند. سبک به‌نظر می‌رسد و انگار دور نمی‌رود، اما اگر با اراده بزنی، صاف تا انتهای زمین می‌پرد. سبکی هم به‌جای خود، نوعی قدرت است."},"ICON-0160":{"nm":"آنتن","de":"برای گرفتنِ سیگنالی نادیدنی، آرام رو به آسمان می‌ایستد. آن شکیبایی که حتی صدای دوردست را هم سرانجام به سوی خود می‌کشد. در روزهایی که واضح شنیده نمی‌شود، فقط کافی است زاویه را کمی تغییر دهی تا دوباره روشن شود."},"ICON-0161":{"nm":"گوشی پزشکی","de":"نوک گردی که سرد به سینه می‌رسد، و نفسی که لحظه‌ای می‌ایستد. گوش را روی یک صدای طبل کوچک جمع کنی، کهن‌ترین ریتمِ زنده‌بودن به نوک انگشتانت می‌رسد. ابزاری که شنیدن در آن پیش از هرچیز می‌آید."},"ICON-0162":{"nm":"پیاده شطرنج","de":"مهره‌ی کوچکی که آرام و فقط یک خانه در هر نوبت راه می‌رفت. با این‌همه، همین که به آخرین ردیف برسد، می‌تواند هرچیزی شود. صفحه‌ی کهنه‌ی شطرنج بی‌صدا نظاره‌گر همان یک حرکتی است که با قدمی دست‌وپاچلفتی کل بازی را زیرورو می‌کند."},"ICON-0163":{"nm":"دسته کنترل","de":"یادت هست آن شب‌هایی که با دو انگشت شست، جهان را می‌پیمودی؟ همان دستگیره‌ی دست‌خورده که از باخت پرتش کردی و بعد با خجالت دوباره برداشتی. طولانی‌ترین و گرم‌ترین گفت‌وگویی که بی‌کلام با کسی آن‌سوی صفحه در میان گذاشتی."},"ICON-0164":{"nm":"کنسول بازی","de":"کلید را که بزنی، صدای کوچک روشن‌شدن مثل یک سلام طنین می‌اندازد. جعبه‌ی مربعی که تمام تعطیلات زیر پتو روشن و خاموشش می‌کردی، نخستین ماجراجویی روزهای کودکی همیشه در نور همین صفحه آغاز می‌شد."},"ICON-0165":{"nm":"خط زمانی","de":"انتهای چپ، آغاز است؛ انتهای راست، روزی است که هنوز نیامده. هرجای میانه که نقطه‌ای را بکشی و بگذاری، لحظه‌ای که فکر می‌کردی فراموش شده، دوباره باز می‌شود. جایی که زمان روی یک خط دراز کشیده است."},"ICON-0166":{"nm":"منشور","de":"کسی فکرش را می‌کرد که نوری این‌قدر زلال، در واقع هفت رنگ در خود داشته باشد؟ رازی که با گذشتن از یک تکه شیشه به رنگین‌کمان می‌گشاید. هرچه چیزی مرتب‌تر به‌نظر برسد، رنگ‌های بیشتری در درونش پنهان است."},"ICON-0167":{"nm":"تی گلف","de":"پایه‌ی کوچکی برای آرام‌گذاشتن توپ. هرچه بیشتر بخواهی دورش بفرستی، بیشتر به چیزی نیاز داری که اول محکم نگهش دارد. همین میخ کوچک روی چمن، نخستین قدم را استوار می‌کند."},"ICON-0168":{"nm":"میل بافتنی","de":"یک بخیه، بعد یک بخیه‌ی دیگر. یکی را جا بیندازی، باید همه را باز کنی و از اول شروع کنی. شالی که یک فصل زمستان روی زانو آرام‌آرام بلندتر می‌شد، همان جایی که شکیباییِ نوک انگشتان به گرما بافته می‌شد."},"ICON-0169":{"nm":"خط ملودی","de":"یک عبارت که پیش از نشستنِ کلمات، از لب‌ها زمزمه‌وار بیرون می‌زد. در همان آهنگِ مبهم و هنوز بی‌واژه، صادق‌ترین چهره‌ی نخستینِ آواز نهفته است."},"ICON-0170":{"nm":"رادار","de":"به سوی تاریکیِ نادیدنی سیگنالی می‌فرستد و آرام منتظر بازگشتِ یک نقطه می‌ماند. شکیباییِ نور سبزِ گرد، که حتی وقتی هیچ‌چیز دیده نمی‌شود، باور دارد چیزی آنجاست."},"ICON-0171":{"nm":"پد ریتم","de":"تق‌تق، به‌آرامی که بزنی، نور و صدا هم‌زمان می‌جهند. جایی که دست‌ها زودتر از سر ریتم را حفظ می‌کنند. کوچک‌ترین و مهربان‌ترین صحنه، گسترده روی کف دست."},"ICON-0172":{"nm":"رنگ نقاشی","de":"نقاش‌های قدیم سنگ و خاک را می‌ساییدند تا رنگ به‌دست آورند. رنگ نیلی از گیاه، سرخ از خاک. حتی در همین یک قطره که اکنون روی نوک انگشتانت فشرده می‌شود، دقتِ کهنِ انتقالِ آرام طبیعت جاری است."},"ICON-0173":{"nm":"خط","de":"همان چیزی که فقط در لحظه‌ی تصمیم به وصل‌کردنِ نقطه‌ای به نقطه‌ای دیگر زاده می‌شود. کوتاه یا بلند، خمیده یا صاف، ساده‌ترین ردی است که دلِ رفتن به‌جایی برجا می‌گذارد. آغازِ هر نقاشی."},"ICON-0174":{"nm":"شاتر","de":"کلیک، همان یک تاریکیِ کوتاه، صحنه‌ای را برای همیشه نگه می‌دارد. حتی حالتی که در یک چشم‌به‌هم‌زدن نزدیک بود از دست برود، این تیغه‌ی کوچک اندکی نور را می‌بُرد و به خاطره تبدیلش می‌کند."},"ICON-0175":{"nm":"طناب ایمنی","de":"طنابی که یک قدم زودتر از کسی که به بلندی می‌رود، محکم بسته می‌شود. دلی را که از افتادن نگران است به‌جای او نگه می‌دارد، و بی‌آنکه دیده شود کنارت می‌ایستد—بندِ یک قول. همیشه پشتِ سرِ توست."},"ICON-0176":{"nm":"قفل","de":"قفل آهنی سنگینی که بر انبار می‌زدند. نه برای زندانی‌کردنِ چیزی، بلکه دلی بود برای اینکه چیز عزیز را خیالِ‌راحت جای دهند. حتی در دستِ قفل‌زننده هم دقتی نهفته بود، همان استواری خانه‌ی قدیمی."},"ICON-0177":{"nm":"ترازو","de":"یک طرف سنگین شود، طرف دیگر خودبه‌خود سبک می‌شود. در همان لحظه‌ی دودلی که چه چیزی و چقدر باید گذاشت، آدم انصاف را می‌آموزد. دو بازویی که با تاب‌خوردن، تعادل را آموزش می‌دهند."},"ICON-0178":{"nm":"شکافنده","de":"حتی چیز محکم چسبیده، اگر رگه‌اش را دنبال کنی، سرانجام از هم جدا می‌شود. ابزار کوچکی برای دونیم‌کردنِ هرچیز و نگاه‌کردن به درونش. نوک انگشتانِ کنجکاوی که می‌خواهد چیز به‌هم‌پیوسته را دوباره باز و نگاه کند."},"ICON-0179":{"nm":"شمارشگر","de":"یک، دو، سه. دوستی کوچک که به‌جای انگشتان، بی‌صدا اعداد را می‌شمارد. دلی را که از جا‌انداختنِ شمارش نگران است، تیک‌تیک‌کنان به آرامش تبدیل می‌کند—همراهِ مهربانِ شمارش."},"ICON-0180":{"nm":"مکان‌نما","de":"پیکانی کوچک که جایی روی صفحه چشمک می‌زند و منتظر فرمان بعدی می‌ماند. حتی در لحظه‌ی تردید هم آن نقطه را ترک نمی‌کند، نوکِ نوری که بی‌صدا اشاره می‌کند حالا شروع کنیم."},"ICON-0181":{"nm":"گیره صخره‌نوردی","de":"همان یک نقطه که درست پیش از تمام‌شدنِ زورِ نوک انگشتان، آخرین بار می‌گیری. اینکه گاهی با یک اراده‌ی رهانکردن دوام می‌آوری، همان برآمدگیِ کوچکِ روی دیوار آرام یادآوری‌ات می‌کند."},"ICON-0182":{"nm":"سنگریزه","de":"سنگی که مدت‌ها در جویبار غلتیده و تمام گوشه‌هایش را بخشیده است. گرد شدن، نام دیگری برای زمانِ ساییده‌شده است. آرام در کف دست بگیری، شکیباییِ رودخانه‌ی جاری را لمس می‌کنی."},"ICON-0183":{"nm":"نشان خانوادگی","de":"خاندان‌های قدیم روی یک پرچم، جانور و ستاره حک می‌کردند تا خود را بشناسانند. تصویری که پیش از کلام، دل را می‌رساند. نشانی کهن که غرورِ یک انسان را در یک قاب کوچک آرام فشرده است."},"ICON-0184":{"nm":"سپر","de":"ایستادنِ در برابر خطر، همیشه برای کسی بود که پشت سرت ایستاده است. تیرهای پرتاب‌شده را به‌جای او می‌گرفت، و روز عادیِ کسی را حفظ می‌کرد—دیواری سنگین و در عین حال مهربان."},"ICON-0185":{"nm":"احیا","de":"دلی هست که خاموش می‌شود و دوباره روشن. تنها پس از یک بار سقوط است که راهِ برخاستنِ دوباره را می‌آموزی. نفسِ دومی که آرام در همان جایی که پایان می‌پنداشتی، بالا می‌آید."},"ICON-0186":{"nm":"کمان","de":"دستی که می‌خواهد چیزی را دور بفرستد، اول زه را تا انتها می‌کشد. برای رهاکردن، باید به همان اندازه نزدیک در آغوش گرفت—همین را کمانِ خمیده و کشیده، بی‌کلام آرام می‌گوید."},"ICON-0187":{"nm":"قلب","de":"کلمه‌ی دوست‌داشتن پیوسته به شکلی کوچک فروکاسته می‌شود. همین شکلی که نوک لایت‌استیک و میان دو انگشتِ روبه‌روی هم، پنهانی کشیده می‌شود. رایج‌ترین و صادق‌ترین اختصارِ دل."},"ICON-0188":{"nm":"ابر","de":"به سوی باد آرام می‌راند و هر بار چهره‌ای دیگر می‌شود. گاهی خرگوش، گاهی پنبه، چیزی را دیر نگه نمی‌دارد و همه را رها می‌کند—سبک‌ترین دلِ آسمان."},"ICON-0189":{"nm":"هزارتو","de":"جایی که پیش دیوارِ بن‌بست، راهِ بازگشتن را می‌آموزی. حتی در گمراهی، قدم‌ها کم‌کم به سوی خروجی رشد می‌کنند. باید یک‌بار راه را گم کرد تا چشمِ راه‌یابی باز شود."},"ICON-0190":{"nm":"دندان","de":"رسمی بود که دندان افتاده را روی بام می‌انداختند. دعایی کوچک برای اینکه دندان نو صاف دربیاید. قولِ مهربانِ روزهای کودکی که می‌گفت باید یک‌بار در بزرگ‌شدن چیزی را از دست بدهی تا چیزی محکم‌تر به دست آوری."},"ICON-0191":{"nm":"سیاره","de":"بدنی گرد که بی‌آنکه یک‌بار هم از مسیرش خارج شود، دور ستاره می‌چرخد. تنها به‌نظر می‌رسد، اما جاذبه‌اش همیشه چیزی را کنار خود به چرخش وامی‌دارد. بی‌صدا سرجای خود ماندن، خودش یک جهان می‌شود."},"ICON-0192":{"nm":"ستاره","de":"در شب‌های گمشدگی، مردم به روشن‌ترین نقطه نگاه می‌کردند. نوری دست‌نیافتنی و دور، اما در نشان‌دادنِ جهت روشن. قولی که به‌خاطر دوربودن، محکم‌تر می‌شود."},"ICON-0193":{"nm":"سایه‌نما","de":"پشت به نور بایستی، از آدم فقط پیکره‌اش برجا می‌ماند. یک شکل سیاه که نام و حالتش پاک شده است. جایی پرنشده که درست به‌خاطر خالی‌بودن، بیشتر به تخیل وامی‌دارد."},"ICON-0194":{"nm":"گوش","de":"برای خوب‌خواندن، اول باید خوب شنید. ریتم و دل، هر دو در نهایت از شنیدن آغاز می‌شوند. دری کوچک و گرد که همه‌ی صداهای دنیا زودتر از هر جا به آن می‌رسند و در آن می‌مانند."},"ICON-0195":{"nm":"برگ پاییزی","de":"برگ‌هایی هستند که درست در لحظه‌ی افتادن، زیباترین درخشش را دارند. سبکیِ سوزاندنِ کاملِ سبزیِ یک فصل به سرخی و رهاکردنِ آرام آن. پاییز نشان می‌دهد که پایان هم می‌تواند این‌قدر زیبا باشد."},"ICON-0196":{"nm":"ماه","de":"شب‌هایی بود که زیر نور گردِ جشن پاییز، دست‌ها را به‌هم می‌آوردند و آرزو می‌کردند. چهره‌ای که با تکرارِ پرشدن و کاستن، هرگز یک‌بار هم شبیه پیش نبود. چراغی که با تغییرکردن، همیشه همان نقطه را روشن نگه می‌دارد."},"ICON-0197":{"nm":"قلب","de":"حتی روی صحنه هم، صادق‌ترین چیز در نهایت همین ضربان است. با لرزیدن نمی‌ایستد، و با شور بیشتر تندتر می‌تپد. طبل کوچک و سرخی که به‌جای تشویقی که کلمات نتوانستند تمام کنند، خودش می‌تپد."},"ICON-0198":{"nm":"سایه","de":"همراهی که تا نور هست، هرگز جدا نمی‌شود. هرچه روشن‌تر، تیره‌تر؛ هرچه کدر‌تر، کم‌رنگ‌تر—آن یکی دیگرِ من که طولانی‌ترین مدت دنبالم آمده. کسی که حتی در روزهای تنهایی هم کنارم ایستاده."},"ICON-0199":{"nm":"دم","de":"با شادی خودبه‌خود می‌جنبد، با ترس آرام جمع می‌شود. دهان محکم بسته باشد هم، این نوک صادق نمی‌تواند دل را پنهان کند. حال درونی که بدن زودتر از همه فاش می‌کند."},"ICON-0200":{"nm":"بند دم","de":"بندی کوچک که مثل روبان، انتها را می‌بندد و پایان می‌دهد. دلی که یک‌بار دیگر محکم گره زد تا باز نشود. بستنِ مهربانی که چیزهای پراکنده‌شدنی را یک‌جا جمع می‌کند و آرام می‌کند."},"ICON-0201":{"nm":"مردمک چشم","de":"می‌توان کلمات را انتخاب کرد، اما نگاه چشم را نمی‌توان پنهان کرد. جایی که دلِ لورفته نخست از آن بیرون می‌زند، همان درون دایره‌ی سیاه. حتی اگر «دوستت دارم» را فرو ببری، مردمک چشمانت از پیش به‌سوی تو می‌لرزد."},"ICON-0202":{"nm":"نعل اسب","de":"تکه‌آهنی که هرچه نوکش از دویدنِ راه‌های دور فرسوده‌تر می‌شد، سخت‌تر می‌گشت. می‌گفتند اگر وارونه بالای در آویزانش کنی، بختی که می‌آید و می‌رود در آن جمع می‌شود. آرام و بی‌صدا، بازگشتِ سالمِ کسی را بر دوش می‌کشد."},"ICON-0203":{"nm":"سنگ‌نشان خانوادگی","de":"حتی اگر باد و باران حروف را کم‌رنگ و محو کنند، اگر نوک انگشت را بر آن بکشی، خطوطِ کنده‌شده دوباره زنده و روشن می‌شوند. سنگینیِ دلی که نمی‌خواست فراموش شود. سنگ این‌گونه یک نام را سال‌های سال در خود نگاه می‌دارد."},"ICON-0204":{"nm":"پرده‌ی شنا","de":"با یک پرده‌ی نازک که انگشتان پا را به هم می‌پیوندد، هنر راندنِ آب آموخته می‌شود. پارویی کوچک که طبیعت آرام در دستِ شناگرِ ناشی می‌گذارد. طرحی مهربان که هرچند کند، سرانجام تو را به آن‌سوی رودخانه می‌رساند."},"ICON-0205":{"nm":"پولک برق","de":"همه غر می‌زنند که اگر به دست بچسبد، روزها دنبالت می‌آید، اما در روز جشن همه اول از همه سراغ همین ذره‌های نور را می‌گیرند. مشتی گردِ ستاره که بپاشی، حتی کاغذِ ساده هم برق می‌زند و امروز خاص می‌شود."},"ICON-0206":{"nm":"چنگال","de":"جانورانِ جنگل با چنگال خود خاک را می‌خراشند تا ردّ خود را برجا بگذارند. نه تهدید، که نشانه‌ای‌ست؛ امضایی خاموش بر اینکه از اینجا گذشته‌اند. نوکِ تیز، گاه برای کسی نشانه‌راهی مهربان می‌شود."},"ICON-0207":{"nm":"آذرخش","de":"در آن دمی که آسمان لحظه‌ای کف دستش را باز می‌کند، نور پیش از تندر می‌رسد. گویی می‌گوید پیش از آنکه صدای بزرگ برسد، یک نفس تازه کن. ترس و شگفتی همیشه از یک درخشش، با هم زاده می‌شوند."},"ICON-0208":{"nm":"طلسم محافظ","de":"یک سطر آرزو که با جوهر بر کاغذ سرخ فشرده نقش بسته است. باور داشتند اگر زیر بالش بگذاری، خواب‌های بد کنار می‌روند. دلی که برای سلامتِ کسی دعا می‌کند، حتی در یک برگه‌ی نازک کاغذ این‌قدر گرم است."},"ICON-0209":{"nm":"بال قلم‌مو","de":"لحظه‌هایی هست که نوکِ قلم‌مو بال می‌شود. آن سبکیِ لغزیدن بر کاغذ، به‌هنگام کشیدنِ یک خط. دستِ کهنی که جوهر می‌سایید، شاید مبهم می‌دانست که نوشتن خود نوعی پرواز است."},"ICON-0210":{"nm":"استخوان","de":"چیزی که تنها پس از فروریختنِ همه‌ی گوشت باقی می‌ماند. اسکلتِ سفیدی که چون سخت‌ترین بود، تا آخر تاب آورد. مدرکی خاموش که حتی وقتی زمان همه‌چیز را با خود می‌برد، دست‌کم شکل را به یاد می‌سپارد."},"ICON-0211":{"nm":"بینی","de":"بو کوتاه‌ترین راه به‌سوی خاطره است. بوی روغنِ آشپزخانه در روز عید، هوای سردِ صبحِ پس از اولین برف؛ نوکِ بینی زودتر از همه می‌فهمد و دل با یک ضربان تأخیر از پی‌اش می‌آید."},"ICON-0212":{"nm":"نان تست","de":"در صبحِ شلوغ، سریع‌ترین لقمه‌ای که به دست می‌رسد. اگر گازی به سطحِ طلایی‌بریان‌شده بزنی، جرأتِ یک‌روزه با صدایی ترد خرد می‌شود. چیزهایی که پرطمطراق نیستند اما سیرکننده‌اند، آدم را دوباره سرِ پا می‌کنند."},"ICON-0213":{"nm":"کلوچه","de":"کسی که جلوی فر بیشترین انتظار را کشیده، اولین گاز را نصیب می‌برد. گرمایِ لبه‌ی تازه‌پخته، شیرینیِ گذرا. آن‌ها که با یاد کسی پخته شده‌اند، عجیب شیرین‌ترند."},"ICON-0214":{"nm":"میان‌وعده","de":"در بعدازظهری که تمرین طولانی می‌شود، کیسه‌ای کوچک از ته کوله بیرون می‌آید. اگر نصفش کنی، سیریِ آن به‌طرزِ عجیبی دوبرابر می‌شود. مشتی مهربانی که پیش از گرسنگی، دل را پر می‌کند."},"ICON-0215":{"nm":"کپسول اسباب‌بازی","de":"تا وقتی نچرخانی و بازش نکنی، هیچ‌کس نمی‌داند چه در آن است. آنچه درونِ پوسته‌ی گرد نهفته، همیشه همان تپشِ آشناست. صادقانه‌ترین هیجانِ دنیا، جایی که یک تصادفِ کوچک خرید و فروش می‌شود."},"ICON-0216":{"nm":"دستگیره‌ی در","de":"جایی که دست‌های بی‌شمارِ باز و بسته‌کننده‌ی در، نخست به آن می‌رسند. سردی که آغاز می‌شود و در کفِ دست گرم می‌شود، نخستین سلامِ خانه است. هرچه رد دست بیشتر بنشیند، آن اتاق کم‌کم به خانه‌ی کسی بدل می‌شود."},"ICON-0217":{"nm":"قدم‌زدن","de":"حتی راه‌رفتن بی‌مقصد هم دلیلی دارد. زمانی برای بازکردنِ افکارِ درهم، رشته‌به‌رشته، در هر قدم. اگر یک دور بزنی و برگردی، پاسخ همان است که بود، اما تنها دل است که سبک‌تر شده."},"ICON-0218":{"nm":"اسکوتر","de":"دو چرخ که کوچه‌های تنگ را می‌شکافد. تند نیست، اما باد را با تمام بدن می‌گیرد. روزهایی هست که فقط می‌خواهی امروز خنک و آزاد برانی، حتی اگر دور نروی، عیبی ندارد."},"ICON-0219":{"nm":"میله‌ی ایمنی","de":"پیش از سوارشدن، میله‌ای که محکم جلوی سینه پایین می‌آید. وعده‌ای مطمئن که تا پایانِ بخشِ ترسناک همراهت می‌ماند. بی‌کلام و سرد به تو می‌گوید محکم بگیرش، اشکالی ندارد."},"ICON-0220":{"nm":"پله","de":"قدم‌به‌قدم که بالا بروی، ناگهان منظره فرق کرده است. کفِ پا زودتر می‌فهمد که هیچ ارتفاعی با یک جهش به دست نمی‌آید. بالا و پایین رفتن، خودش برای کسی، قدم‌های یک روز بوده است."},"ICON-0221":{"nm":"تراریوم","de":"این حبسِ جنگل در شیشه نیست، بلکه پرورشِ صبورانه‌ی یک جهان است. کیهانی به‌اندازه‌ی کف دست که خزه در آن می‌گسترد و قطره‌های آب می‌نشیند. هرچه بیشتر نگاه کنی، دل آرام‌آرام سبز می‌شود."},"ICON-0222":{"nm":"سکوی سخنرانی","de":"اگر یک وجب بالاتر بایستی، منظره‌ای که می‌بینی فرق می‌کند. جایی که ترس و غرور در یک ارتفاع به هم می‌رسند. بسته به اینکه چه کسی بر آن بایستد، آن یک پله هر بار صحنه‌ای دیگر می‌شود."},"ICON-0223":{"nm":"هواپیما","de":"لحظه‌ای که ابرها زیر پا پهن می‌شوند، بالاخره دلت برای جایی که ترک کرده‌ای تنگ می‌شود. این دورشدن نیست، بلکه گسترده‌ترشدنِ جهان است. حتی رویایی که در جزیره‌ای کوچک بالیده، این‌گونه از آسمان می‌گذرد."},"ICON-0224":{"nm":"اسکیت‌برد","de":"چیزی که فقط پس از یادگرفتنِ افتادن می‌توان سوارش شد. هر بار که زانو زخم می‌شود، تعادل کمی بیشتر در بدن حک می‌شود. چهار چرخِ صادق که به اندازه‌ی هر افتادنِ خوب، دورتر می‌غلتد."},"ICON-0225":{"nm":"گذرنامه","de":"اگر جلدش را باز کنی، صفحه‌های خالیِ بسیاری در آن است. هر مهری که پر شود، خود گواهیِ یک زندگیِ زیسته می‌شود. کتابچه‌ای کوچک که نه اینکه تا کجا رفته‌ای، بلکه امکانِ رفتن به هرکجا را در خود دارد."},"ICON-0226":{"nm":"نقشه‌ی دستی","de":"نه فاصله‌ی دقیقی دارد و نه مقیاسی، اما چون راهی‌ست که با دست کشیده شده، هیچ ترسی از گم‌شدن نیست. کاغذی که نامِ کوچه‌ها و مغازه‌ها در آن گرم‌وصمیمی درهم‌تنیده‌اند. راهنمایی که دل در آن باشد، همیشه پیش از خودِ راه گرم است."},"ICON-0227":{"nm":"نقشه‌ی حرکت صحنه","de":"کاغذی که هر قدم روی صحنه در آن با خط کشیده شده است. کجا بایستد، کجا بچرخد، فلش‌ها از پیش قول داده‌اند. حتی رقصی که آزاد به نظر می‌رسد، در واقع از همین یک برگه آغاز می‌شود."},"ICON-0228":{"nm":"راهنمای صندلی","de":"در فضایی ناآشنا، اولین چیزی که با دست جستجو می‌کنی جای خودت است. ردیف و شماره را دنبال می‌کنی و سرانجام به آن یک خانه می‌رسی. یک برگه کاغذ، هزاران هیجان را مرتب و منظم سرِ جایشان می‌نشاند."},"ICON-0229":{"nm":"کارت راهنمای کوچه","de":"راهنمایی که کسی با دستِ خود، برای کسانی که در کوچه‌های پیچ‌درپیچ گم می‌شوند، نوشته است. خطِ مهربانی که می‌گوید در کدام پیچ باید چرخید. دل‌گرمیِ محله در یک کارتِ کوچک، شمرده‌شمرده جای گرفته است."},"ICON-0230":{"nm":"کارت امنیتی","de":"تنها زمانی که این کارت را به گردن بیاویزی، درِ جهانِ درونی بازمی‌شود. اجازه‌ای کوچک برای ورود، و نشانی خاموش بر اینکه به اینجا تعلق داری. تنها کسی که می‌داند چه زمانی برای به‌دست‌آوردنش صرف شده، سنگینیِ آن را می‌فهمد."},"ICON-0231":{"nm":"دستبند ورود موقت","de":"یک‌بار که به مچ بسته شود، تا زمانی که بازش کنی عضوِ آن روز هستی. یک نوارِ کاغذی، درون را از بیرون جدا می‌کند و نشانه‌ای می‌شود بر اینکه روزی مشترک را با هم گذرانده‌اید. حتی پس از پاره‌شدن، ردّش مدت‌ها برجا می‌ماند."},"ICON-0232":{"nm":"برچسب مهمان","de":"با یک برچسبِ کوچکِ اسم که به سینه می‌چسبانی، جایی ناآشنا جای خودت می‌شود. وقتی کلمه‌ی «خوش‌آمدید» بر یک برگه‌ی کاغذ سوار و تقدیم می‌شود، حتی تازه‌واردترین کس هم بالاخره مهمان می‌شود."},"ICON-0233":{"nm":"لوله‌ی پوستر","de":"استوانه‌ای محکم که پوستری لوله‌شده را بی‌کوچک‌ترین چروکی نگاه می‌دارد. چون هرچه تصویر عزیزتر باشد، باید صاف‌تر فرستاده شود. درونش دیده نمی‌شود، اما با دلسوزیِ کسی به راه می‌افتد."},"ICON-0234":{"nm":"جلد پوشه","de":"اولین برگه‌ای که بسته‌ی ضخیمِ اسناد را در بر می‌گیرد. چهره‌ای که پیش از محتوا به دست می‌رسد. اگر جلد مرتب باشد، حتی طرزفکرِ درونش هم مرتب به نظر می‌رسد؛ آغازِ مهربانِ یک آداب کوچک."},"ICON-0235":{"nm":"کارت‌پستال یادگاری","de":"بر تکه‌ای از منظره‌ی دوردست، احوال‌پرسی می‌نویسی و می‌فرستی. تا زمانی که برسد، دلی که فرستاده‌ای هم اندکی کهنه می‌شود و همین باعث دلنشین‌ترشدنش می‌شود. گرمای آرامِ نامه‌ای دست‌نویس که پیامِ صفحه‌ی نمایش هرگز نمی‌تواند از پیِ آن برسد."},"ICON-0236":{"nm":"برچسب هدیه","de":"برگه‌ی کوچکی که به هدیه می‌بندند. فقط با دو کلمه‌ی «برای تو»، بسته‌بندی از پیش کامل می‌شود. کوتاه‌ترین نامه‌ی دنیا، که نه اینکه چه می‌دهی، بلکه به یاد چه کسی بوده‌ای را می‌نویسد."},"ICON-0237":{"nm":"رول برچسب بسته‌بندی","de":"هر بار که یک تکه از آن را جدا و استفاده می‌کنی، پایانِ کار مرتب‌تر می‌شود. گرهی کوچک که لبه‌ی درحال‌بازشدن را منظم نگاه می‌دارد. آخرین حرکتِ یک بسته‌بندیِ باسلیقه، همیشه از همین نوارِ لوله‌شده می‌آید."},"ICON-0238":{"nm":"جلد شفاف نامه","de":"لایه‌ای شفاف که نامه‌ی دست‌نویس را از رنگ‌باختن در گذرِ زمان محفوظ نگاه می‌دارد. حروف همچنان دیده می‌شوند، اما اثرِ دست به آن‌ها نمی‌رسد. پرده‌ای نادیده، خاموش از دلِ عزیز کسی نگهبانی می‌کند."},"ICON-0239":{"nm":"مهر موم رنگی","de":"آخرین نقطه‌ای که پاکت را می‌بندد؛ هرچه رنگش روشن‌تر، دل کمتر بیرون نشت می‌کند. قولی که تا پیش از پاره‌شدن، دستِ هیچ‌کس به آن نرسیده است. حتی رازها هم به گره‌ای این‌قدر زیبا نیاز دارند."},"ICON-0240":{"nm":"دفترچه‌ی پیام","de":"کتابچه‌ای کوچک که یادداشت‌های کوتاه را با هم می‌بندد. هر برگه سخنی‌ست که قرار است به کسی برسد. اگر کلماتی را که نتوانستی بگویی، آرام‌آرام گرد بیاوری، روزی جرأتِ رساندنشان می‌روید."},"ICON-0241":{"nm":"تابلوی تاشو","de":"باز کنی می‌گوید «این‌طرف است»، تا کنی می‌گوید «امروز تا همین‌جا». پاهایش را دهانه‌ی کوچه باز گذاشته، تمامِ روز برای کسی که ممکن است راه را گم کند سرِ پا می‌ایستد. غروبی که تا می‌شود، برایم مهربان‌ترین استراحت است."},"ICON-0242":{"nm":"نوار مرتب‌سازی نامه","de":"اگر دسته‌ای کارت‌پستال را دورِ کمر بپیچی و در آغوش بگیری، احوال‌پرسی‌هایی که در حالِ پراکنده‌شدن بودند، سرانجام یک دسته دل می‌شوند. یک نوارِ سبک، کلماتی را که تا راه‌های دور می‌روند مرتب می‌بندد و پشتِ راهی که راه می‌افتد را آرام بدرقه می‌کند."},"ICON-0243":{"nm":"بسته یادداشت‌های تشکر","de":"چون کلمه‌ی «ممنونم» پیوسته از زبان می‌لغزد، آن را روی کاغذی به‌اندازه‌ی کف دست می‌نویسی و آرام می‌بندی. هرچه بسته ضخیم‌تر شود، ضخامتِ دلِ مدیونی که به کسی داری هم به همان اندازه رشد کرده است."},"ICON-0244":{"nm":"برگه‌ی نمونه‌ی شعار تشویقی","de":"برگه‌ی نمونه‌ای که رویش نوشته «این‌طور فریاد بزنید». تشویقی که هنوز صدایی بر آن ننشسته، مثل نُتِ خالی‌ای که منتظرِ اولین ضرب است، تنها هیجانی خاموش در دل دارد."},"ICON-0245":{"nm":"یادداشت درخواست ضبط پیش","de":"یادداشتی که برای رزروِ ضبطِ پیش نوشته شده، همیشه در خانه‌ی ساعتِ پنجِ صبح می‌ماند. کاغذِ کوچک، دلی را که خواب را کوتاه می‌کند تا جایی نگه دارد، انگار همه‌چیز را می‌فهمد، بی‌صدا می‌نویسد و نگه می‌دارد."},"ICON-0246":{"nm":"بلیت نوبت جلسه‌ی امضا","de":"یک برگه که تعیین می‌کند چندمین نفر سلامت را می‌رسانی. صف‌ایستادن، منتظرِ نوبت‌بودن نیست؛ چون نمی‌شود به میزانِ دوست‌داشتن شماره داد، لحظه‌ای نوبتی قرض گرفته می‌شود."},"ICON-0247":{"nm":"دستبند شماره‌ی نوبت","de":"یک عدد تعیین می‌کند امروز در چه ترتیبی صف بکشی. چه اول صف چه آخر صف، آن‌ها که این نوارِ کوچک و سبک را به مچ بسته‌اند، سرانجام رفقایی هم‌دل‌اند که برای دیدنِ یک صحنه گرد آمده‌اند."},"ICON-0248":{"nm":"جدول مرتب‌سازی فتوکارت","de":"با اینکه چهره یکی‌ست، می‌گویی همه فرق دارند و خانه‌به‌خانه یادداشت می‌کنی. هرچه جدول پرتر شود، دل مرتب‌تر می‌شود، و آن یک خانه‌ی خالی‌مانده، سینه را با هیجانِ پرکردنِ امروز به تپش می‌اندازد."},"ICON-0249":{"nm":"چک‌لیست آلبوم","de":"نسخه، فتوکارت، حتی مهروموم بودن یا نبودن؛ فهرستی از عشق که با عدد نوشته شده. غرورِ روزی را که همه‌چیز پر می‌شود از پیش تصور می‌کنی و امروز هم روی یک خط، دایره‌ای مرتب می‌کشی."},"ICON-0250":{"nm":"یادداشت راهنمای تشویق","de":"شکلِ دست‌ها، ضربِ فریاد، حتی جایی که باید نفس تازه کرد. برای اینکه حتی تازه‌واردی زود در یک صدا حل شود، یادداشتِ کوچک راهنمایی مهربان می‌شود و از دستی به دستی می‌گذرد."},"ICON-0251":{"nm":"دفترچه‌ی یادداشت خصوصی","de":"فقط جملاتی را که به هیچ‌کس نشان نخواهی داد، اینجا برمی‌گزینی و می‌نویسی. اینکه صفحه‌ای که هرگز باز نشده صادق‌ترین است، این دفترچه با جلدی بسته، خاموش نگاه می‌دارد."},"ICON-0252":{"nm":"برگه‌ی مهر یادبود","de":"فشار می‌دهی، و روزی دیگر خاص می‌شود. با یک مهرِ کوچک که روی تاریخِ عادی می‌نشیند، «امروز» آرام نامش را در فهرستِ روزهایی که می‌خواهد به یاد بماند می‌نویسد."},"ICON-0253":{"nm":"جلد کلیپ‌بورد","de":"حتی اگر باد بوزد، حتی اگر باران بزند، کاغذِ گیره‌شده را تا آخر نگاه می‌دارم. من که زرهِ تخته‌ام را به عهده گرفته‌ام، محافظِ مطمئنِ حروفِ نوشته‌شده‌ام."},"ICON-0254":{"nm":"نمایه‌ی پرونده","de":"برای اینکه در میان اسنادِ ضخیم راه گم نکنی، زبانِ کوچکی بیرون می‌زند و می‌گوید «اینجاست». یک برچسبِ رنگی، صد صفحه را در یک نگاه اداره می‌کند."},"ICON-0255":{"nm":"برچسب زبانه‌ی دسته‌بندی","de":"این در این خانه، آن در آن خانه. کارِ من مرتب‌کردنِ آشفتگیِ دنیاست، خط‌به‌خط. لحظه‌ای که برچسب می‌چسبد، چیزهای درهم‌ریخته سرانجام جای خود را می‌یابند."},"ICON-0256":{"nm":"تخته تأیید کوچک","de":"لحظه‌ای که مهر را می‌کوبی، حسِ عجیبی از بزرگ‌شدن می‌آید. کوچک است اما اقتداری زیرکانه دارد؛ با یک مهرِ تأیید، کارهای انباشته با سرعت به پایان می‌رسند."},"ICON-0257":{"nm":"پاکت شفاف اسناد","de":"درونش کاملاً پیداست، چیزی برای پنهان‌کردن نیست. کاغذِ مهم را در بر می‌گیرد و مبادا از باران خیس شود یا چروک بخورد، با بدنِ شفافِ خودش آن را در آغوش می‌کشد و تا محلِ قرار می‌برد."},"ICON-0258":{"nm":"نوار حضور و غیاب","de":"آمدم، و یک خانه‌ی دیگر پر می‌شود. وقتی ردِپای هر روز پشتِ سرِ هم در طولِ نوار انباشته می‌شود، پشتکاری که دیده نمی‌شد، سرانجام نقشی می‌شود که با یک نگاه پیداست."},"ICON-0259":{"nm":"دفترچه‌ی جمع‌بندی غلط‌ها","de":"نوشتنِ چیزی که اشتباه بوده، جمع‌کردنِ شرم نیست. برای اینکه دوباره در همان‌جا نلغزی، اشتباهِ دیروز را به راهنمای امروز بازمی‌نویسی."},"ICON-0260":{"nm":"تخته‌ی مهر برنامه","de":"یک مهر که روی برنامه‌ی خالی بکوبی، «قراری» زاده می‌شود. جادوی روزی که با یک تکانِ مچ تعیین می‌شود؛ آن جادو در واقع نامی دیگر برای پشتکارِ آماده‌شدنِ زودهنگام است."},"ICON-0261":{"nm":"برچسب پشت‌جلد کتاب","de":"نشانِ نامِ کتاب‌هایی که پشت به کتابخانه ایستاده‌اند. حروفِ کوتاهِ نوشته‌شده بر کمرِ باریک، در میانِ صدها کتاب، همان یکی را که دنبالش بودی با یک اشاره صدا می‌زند."},"ICON-0262":{"nm":"محافظ عکس","de":"دستِ برهنه ممنوع. می‌گوید حتی یک اثرانگشت هم بر جا نگذار، و به‌آرامی بدنش را روی یک قابِ عزیز می‌کشد. دلِ دوست‌داشتن این‌گونه، با دستانی محتاط، سال‌ها و سال‌ها دوام می‌آورد."},"ICON-0263":{"nm":"برگه‌ی نمایه‌ی فیلم","de":"اگر روی هر نوارِ فیلم شماره‌ای بگذاری، لحظه‌های پراکنده دوباره نوبتِ خود را در داستان بازمی‌یابند. راهنمایی کوچک که خاطراتِ نوشته‌شده با نور را از درهم‌آمیختن نگاه می‌دارد."},"ICON-0264":{"nm":"کیف جیب‌دار عکس","de":"خانه‌ای شفاف که خوشبختی‌های مربع‌شکل را یکی‌یکی در خود جای می‌دهد. بی‌هیچ نگرانی از لهیدنِ گوشه‌ها، عزیزترین چهره در آن، در هر چهار فصل مرتب می‌درخشد."},"ICON-0265":{"nm":"پاکت کوچک چاپ عکس","de":"پیش از آنکه گرمای عکسِ تازه‌چاپ‌شده سرد شود، پاکتی کوچک دو بازو باز می‌کند و آن را در آغوش می‌گیرد. عکسی که از دهانه‌ای به‌اندازه‌ی کف دست وارد می‌شود، پیش از آنکه بفهمی، گنجینه‌ی کیفِ کسی می‌شود."},"ICON-0266":{"nm":"جلد لنتیکولار","de":"مأموریت من نگهبانی، بی‌کوچک‌ترین خراشی، از عکسی سخت‌گیر است که با هر خمشدن حالتش عوض می‌شود. برای محافظت از تمامِ چهره‌های گوناگون در هر زاویه، خودم هم باید کم‌کوتاهی نکنم."},"ICON-0267":{"nm":"برچسب دسته‌بندی فریم","de":"از میانِ چهار فریم، برچسب به‌جای تو نشان می‌دهد کدام بهترین است. این کارِ کوچکِ جداکردنِ خوب‌درآمده از خنده‌دار، کنارِ هم، رازِ دوباره‌لذت‌بردن از یک خاطره است."},"ICON-0268":{"nm":"نوار نگهداری عکسِ چهارتایی","de":"خاطره‌ی باریک و بلندِ چهارخانه‌ای را مرتب دور می‌پیچد و می‌بندد. خنده‌ی آن روز را که در حالِ پراکنده‌شدن بود، محکم در یک بسته در آغوش می‌گیرد و تا اعماقِ کیف، سالم می‌رساند."},"ICON-0269":{"nm":"برچسب گوشه‌ی عکس","de":"وقتی عکسی را در آلبوم می‌چسبانی، دستی کوچک که به‌نرمی چهار گوشه‌اش را می‌گیرد. بی‌آنکه چسب را انبوه بمالی، نمی‌افتد؛ ظرافت این‌گونه، درست از گوشه‌ها آغاز می‌شود."},"ICON-0270":{"nm":"جدول تصحیح چاپ","de":"کمی گرم‌تر، اندکی کم‌نورتر. برگه‌ای که تا رسیدن به رنگِ دلخواه با اعداد بازی می‌کنی، آرام‌آرام یک عکسِ معمولی را به یک اثرِ هنری بدل می‌کند."},"ICON-0271":{"nm":"گیره‌ی رسید","de":"رسیدهای مچاله‌شده را مرتب گاز می‌گیرد و رها نمی‌کند. با دهانِ کوچکش هزینه‌ی هر روز را باسلیقه نگاه می‌دارد، پس حساب‌وکتابِ آخر ماه کمی سبک‌تر می‌شود."},"ICON-0272":{"nm":"برگه‌ی تأیید رزرو","de":"با یک خط «رزرو شد»، دل آرام‌آرام آسوده می‌شود. یک برگه کاغذ، مدرکِ یک قول می‌شود و تا آن روزِ موعود، هیجان را ذره‌ذره در خود نگاه می‌دارد."},"ICON-0273":{"nm":"رسید بازگرداندن","de":"مدرکی کوچک اما سربلند، بر اینکه آنچه امانت گرفته بودی سرِ جایش برگردانده‌ای. لحظه‌ای که این کاغذ در دست می‌نشیند، دِینی که گوشه‌ی دل سنگینی می‌کرد، سبک پاک می‌شود."},"ICON-0274":{"nm":"جاکارتی رسید امانت","de":"برای اینکه بلیتِ پس‌گرفتنِ چیزی که سپرده‌ای گم نشود، من به‌جایت محکم نگهش می‌دارم. چون سرنوشتِ یک برگه‌ی کوچک، گاه پایانِ روزِ کسی را رقم می‌زند."},"ICON-0275":{"nm":"دم‌برچسب امانت","de":"بر هر چیزِ امانت‌گرفته‌شده، برچسبی کوچک تاب می‌خورد. اگر این دم را دنبال کنی، یک‌باره روشن می‌شود چه کسی چه چیز را برده، پس رازِ گم‌شدن هم زود حل می‌شود."},"ICON-0276":{"nm":"چک‌لیست بازرسی","de":"با چشم، یکی‌یکی وارسی می‌کنی که چیزی جا نمانده باشد. وقتی علامت‌های تیک پشتِ سرِ هم پر می‌شوند، دقتی که دیده نمی‌شد، سرانجام نامِ اعتماد می‌گیرد."},"ICON-0277":{"nm":"پاکت یادداشت تسویه‌حساب","de":"اگر پول‌های واردشده و خارج‌شده را روی پاکت بنویسی، اعدادِ درهم‌ریخته آرام صف می‌بندند. پایانِ تسویه‌حساب همیشه با همین یادداشتِ کوچک، نقطه‌ی پایانی صبورانه می‌گیرد."},"ICON-0278":{"nm":"برچسب ارسال","de":"با نوشتنِ اینکه کجا می‌رود و به دستِ چه کسی می‌رسد بر بدنِ خود، به راه می‌افتد. لحظه‌ای که این برچسب می‌چسبد، جعبه مسافری با مقصد می‌شود و با هیجان راه می‌افتد."},"ICON-0279":{"nm":"نوار تأیید دریافت","de":"کلمه‌ی «به‌خوبی رسید» را در یک نوار می‌بندد و برمی‌گرداند. آسودگیِ گیرنده و اطمینانِ فرستنده، آرام روی این ریسمانِ کوچک دست یکدیگر را می‌گیرند."},"ICON-0280":{"nm":"حلقه کارت واژه","de":"واژه‌هایی که اگر پراکنده و تک‌برگ می‌ماندند گم می‌شدند، یک حلقه‌ی کوچک همه را به هم می‌دوزد و نگاه می‌دارد. باز و بسته که کنی، کلماتِ ناآشنا پیش از آنکه بفهمی، دوستانی می‌شوند که بر زبان جاافتاده‌اند."},"ICON-0281":{"nm":"نوار یادداشت تلفظ","de":"جایی که نوکِ زبان پیوسته می‌لغزد، برچسبی کوچک آویزان می‌کنی. حتی صدایی ناآشنا که در دهان راه گم می‌کرد، اگر این یادداشت را دنبال کنی، پیش از آنکه بفهمی تلفظِ خودش را می‌یابد. صفحه‌ی نخستِ اهلی‌کردنِ صدایی ناشیانه، ذره‌ذره."},"ICON-0282":{"nm":"جعبه یادداشت ترجمه","de":"پل‌های کوچکی که میانِ کلمه و کلمه می‌گذرند، خانه‌به‌خانه، تا‌شده و مرتب در آن جای گرفته‌اند. اگر جمله‌ای را که به‌سختی یافته‌ای بنویسی و آرام تقدیم کنی، حتی دلی که ارتباط برقرار نمی‌کرد، با یک یادداشت در میان نزدیک‌تر می‌شود."},"ICON-0283":{"nm":"برگه‌ی بریده‌ی جملات","de":"جمله‌ای که درست به دل می‌نشیند، تنها اگر با دست کپی شود، ماندگار می‌ماند. اگر خطی را که از گوشه‌ی کتابی بریده‌ای جلوی میز بچسبانی، آن حروف آرام روزِ در‌حالِ‌فروریختنِ امروز را نگه می‌دارند."},"ICON-0284":{"nm":"نمایه‌ی یادداشت","de":"پرچم‌های کوچک و رنگارنگ که در کتابی ضخیم جای گرفته تا راهت را گم نکنی. زبانه‌هایی که بیرون زده‌اند، آرام از میان صفحات می‌گویند: تنها وقتی جای بازگشت را بدانی، می‌توانی دورتر سرگردان شوی."},"ICON-0285":{"nm":"چیپ چک حفظیات","de":"نشانه‌ای که کنار چیزی که حفظ کرده‌ای می‌گذاری. لنگری کوچک که چیزهایی را که لحظه‌ای در ذهن سر می‌زنند و می‌خواهند ناپدید شوند نگه می‌دارد، پس هر خانه‌ی سیاه‌شده، خاموش تلاشِ دیشب را در خود دارد."},"ICON-0286":{"nm":"بسته پاکت مسابقه","de":"تا پاکت را پاره نکنی، هیچ‌کس نمی‌داند چه بیرون می‌آید. آن چند ثانیه که با نوکِ انگشت جایِ مهروموم را لمس می‌کنی؛ بسته‌ای از هیجان که یک سؤال در آن مرتب تا شده و همراه با تپشِ دل مهروموم شده است."},"ICON-0287":{"nm":"دفترچه زبانه‌دار گرامر","de":"قاعده را نه با ذهن، که با دست باید آموخت. از برچسبِ رنگیِ صفحه‌ای که بیشتر بازش می‌کنی تا دفترچه‌ای که نرم‌نرم فرسوده می‌شود، همان گوشه‌ی فرسوده حلقه‌ی سالیانِ زمانی‌ست که تاب آورده‌ای."},"ICON-0288":{"nm":"جدول تمرین صحبت","de":"برگه‌ای برای کسی که باز کردن دهان، سخت‌ترین کارِ دنیاست. اگر با انگشت خانه‌به‌خانه پایین بروی، حتی نخستین کلمه‌ای که در گلو لرزیده، پیش از آنکه بفهمی صدای خودش را می‌یابد. چون جرأت هم نوبت دارد."},"ICON-0289":{"nm":"برگه‌ی رنگ‌آزمایی خام","de":"رنگ‌هایی که پیش از کامل‌شدن، خام و بی‌نظم دراز کشیده‌اند و نفس تازه می‌کنند. نه پاسخِ درست، که هنوز حالتی از امکان است؛ روی این برگه‌ی ناپرداخته، بیش از هر چیزِ دیگر، فردایی موج می‌زند."},"ICON-0290":{"nm":"تکه‌ی مودبورد","de":"اگر برداشت‌های پراکنده را یک‌جا جمع و بچسبانی، فضایی که به‌سختی به دست می‌آمد، مبهم چارچوبش را نشان می‌دهد. حسی که هنوز نامی ندارد، تکه‌ها به هم تکیه می‌دهند و آرام به آن اشاره می‌کنند."},"ICON-0291":{"nm":"کتاب نمونه‌ی طرح","de":"شبکه‌ی پارچه‌ی بقچه و بافتِ نرده‌ی پنجره، یکی‌یکی در یک جلد مرتب چیده شده‌اند. جایی که یک طرح تا آخر تکرار می‌شود، تنبلی نیست، قولی‌ست؛ دلِ استواری که یک بافت را تا انتها نگاه می‌دارد."},"ICON-0292":{"nm":"برگه‌ی نمونه‌ی پارچه لباس","de":"با اینکه نور یکی‌ست، بافت و سایه روی هر تکه‌پارچه فرق می‌کند. پیش از انتخابِ لباسِ صحنه، شبی که با نوکِ انگشت بارها آن را لمس کردی و دودل ماندی، به‌تمامی در یک نمونه‌ی کوچک نگه داشته شده است."},"ICON-0293":{"nm":"برگه‌ی راهنمای ممنوعیت لوگو","de":"کاغذی که نخست، شمرده‌شمرده، چیزهایی را که نباید کرد می‌نویسد. در چارچوبی که با ضربدرِ قرمز خط خورده، آزادی درست همان‌جا روشن‌تر می‌شود، پس راهی تازه، درست در جایی که بن‌بست می‌پنداشتی، باز می‌شود."},"ICON-0294":{"nm":"چیپ مرجع رنگ","de":"تکه‌نمونه‌ای که چون رنگ اصلاً با کلمه توضیح‌پذیر نیست، جداگانه ساخته شده. لحظه‌ای را که غروب سرخ‌ترین بود در یک کف‌دستِ کوچک به بند می‌کشد، تا بتوانی به نفرِ بعدی دقیقاً بگویی «همین رنگ است»."},"ICON-0295":{"nm":"کارت طرح‌بندی خام","de":"اولین طرحی که سبک کشیده‌ای از اینکه چه چیز کجا باشد. جای‌گذاری خود تعیینِ دل است، پس میانِ خطوطِ ناشیانه‌ی پراکنده، توازنِ کل آرام‌آرام چشم می‌گشاید."},"ICON-0296":{"nm":"تخته یادداشت متریال","de":"چوب، خاک، سنگ؛ نام چیزهای لمس‌کردنی انبوه نوشته شده است. رازی که فقط کسی که ابتدا با دست بافت را می‌خواند می‌داند: با چه چیزی می‌سازی، از پیش نیمی از اینکه چه خواهد شد را تعیین می‌کند."},"ICON-0297":{"nm":"کاغذ ترسیم طرح","de":"کاغذی نازک روی طرحِ زیرین می‌گذاری و آرام خطوط را دنبال می‌کنی. مدتی که راهِ دیگری را قرض می‌گیری، دستت آن راه را می‌آموزد، و میانِ خطوطی که کپی می‌کردی، بی‌آنکه بفهمی، خطی از آنِ خودت آرام می‌روید."},"ICON-0298":{"nm":"نوار مسیر ورود","de":"مردم پشت سرِ هم، در امتدادِ نواری که روی زمین کشیده شده، وارد می‌شوند. خطی که آرام راهنمایی می‌کند تا قدم‌های پرشور درهم نگره؛ دستی مهربانِ نادیده که مبادا هیجان فروبریزد، آن را نگاه می‌دارد."},"ICON-0299":{"nm":"تابلوی راهنمای رویداد","de":"تابلویی که به‌جای گفتنِ «این‌طرف است» ایستاده. مهربانیِ کوچکی که در هر سرِ راه گذاشته شده تا کسی سرگردان نشود، دستِ روزِ ناآشنای یک تازه‌وارد را می‌گیرد و آرام همراهش راه می‌رود."},"ICON-0300":{"nm":"برچسب شماره‌ی غرفه","de":"عددی که به هر غرفه داده می‌شود، به‌روشنی صاحبِ آن یک خانه را تعیین می‌کند. عددی کوچک، اما قولِ «اینجا جای توست» است، پس در محلِ رویدادی ناآشنا، جایی برای بازگشتن پیدا می‌شود."},"ICON-0301":{"nm":"فرم رضایت‌نامه عوامل","de":"امضایی کوتاه، بر جایی که دل‌ها برای همکاری هم‌داستان شدند. تنها یک برگ نازک کاغذ است، اما وزن اعتماد کردن به یکدیگر را در خود دارد؛ و هر دست یاری‌گری در این رویداد، درست از همین‌جا آغاز می‌شود."},"ICON-0302":{"nm":"بسته بلیت‌های تجربه","de":"دسته‌ای نرم و ضخیم از بلیت‌های تجربه که به‌راحتی در یک دست جا می‌گیرد. هرچه بیشتر پخش شود، نه‌تنها کم نمی‌شود بلکه «اولین‌بار»های بیشتری به دیگران هدیه می‌دهد؛ بسته‌ای از سخاوت که هرچه لمسش کنی، گرم‌تر می‌شود."},"ICON-0303":{"nm":"برچسب نشانگر صف","de":"«از همین‌جا منتظر بمانید»، زمین آرام زمزمه می‌کند. وقتی دل‌هایی که نوبت خود را نگه می‌دارند کنار هم جمع شوند، حتی صفی طولانی به منظره‌ای دل‌نشین بدل می‌شود؛ و یک نشانه‌ی کوچک، بی‌قراری را به آرامش تبدیل می‌کند."},"ICON-0304":{"nm":"برچسب تحویل حضوری","de":"برچسبی کوچک که آرام به جایی آویزان می‌شود که سفارش از پیش داده‌شده را تحویل می‌گیری. همان لحظه که در دست می‌گیری‌اش، آن آرامش لطیف از روی شانه‌هایت فرو می‌ریزد؛ گرهی که دلی دیرمنتظر، سرانجام در آن شکل می‌گیرد."},"ICON-0305":{"nm":"بلیت جعبه شانسی","de":"لذت انتخاب کردن چیزی بدون دانستن آنچه درون آن است. تکانش می‌دهی و صدای تلق‌تلق درونش پیش از هر چیز قلبت را به تپش می‌اندازد؛ و آن لحظه‌ی کوتاه پیش از باز کردن، پرامیدترین لحظه‌ی روز می‌شود."},"ICON-0306":{"nm":"برچسب تکمیل مبادله","de":"مهری کوچک و گرد که خبر می‌دهد مبادله بی‌دردسر به پایان رسیده است. نقطه‌ی صافی‌ست که میان دست‌های داده و ستانده باقی می‌ماند، و همین‌که چسبانده شود، آن معامله سرانجام با گرمی گرد و کامل می‌شود."},"ICON-0307":{"nm":"نوار مهروموم اسناد","de":"جعبه‌ای گران‌بها را یک دور با نواری می‌پیچند و آرام مهروموم می‌کنند. خواهشی‌ست که سرسری باز نشود، و مؤدبانه‌ترین شکل ارج نهادن به آنچه درون است، تماماً در یک نوار جای گرفته است."},"ICON-0308":{"nm":"کپسول یادداشت مخفی","de":"حرفی که دلت می‌خواست بگویی، آرام درون قوطی‌ای کوچک محبوس و نگه‌داشته می‌شود. آن را محکم می‌بندی، انگار احساسی نرسیده را دفن می‌کنی، و گاوصندوقی کوچک در کف دست، تا روزی که دوباره بازش کنی، زمان را پاس می‌دارد."},"ICON-0309":{"nm":"کارت کوچک یادگاری","de":"تکه‌ای بریده و چسبانده‌شده، که حس‌وحال آن روز را آرام در خود نگه داشته. سبک‌تر از دفتر خاطرات و دست‌سازتر از یک عکس؛ برگه‌ای به اندازه‌ی کف دست، روزی را که به‌آسانی از میان انگشتان می‌لغزید، محکم نگه می‌دارد."},"ICON-0310":{"nm":"برگه ثبت اولین بازدید","de":"لرزش روزی که برای اولین بار پا به این جزیره گذاشتی، در یک خط کوتاه باقی می‌ماند. درست پیش از آنکه غریبگی به صمیمیت بدل شود، کاغذ آن نخستین احساسِ زلال را به‌جای تو در آغوش می‌گیرد و مدت‌ها نگه می‌دارد."},"ICON-0311":{"nm":"جدول دسته‌بندی خاطرات","de":"جدولی که خاطرات را بر پایه‌ی رگه و شاخه‌شان، یکی‌یکی جدا و یادداشت می‌کند. اگر همه‌ی خاطرات را بی‌نظم در یک کشو انبار کنی، حتی عزیزترین روزت هم گم می‌شود؛ پس هرچه چیزی گران‌بهاتر باشد، جای خود را با ظرافت بیشتری می‌یابد."},"ICON-0312":{"nm":"چیپ یادداشت حباب‌گفتار","de":"حرفی که می‌خواستی بگویی، مثل بادکنکی گرد باد می‌کند و روی کاغذ معلق می‌ماند. حتی جمله‌ای که زبانت یارای گفتنش را نداشت، درون آن قاب گرد آرام‌آرام شجاعت می‌یابد؛ گذرگاهی کوچک و گرم که دل از آن بیرون می‌خزد."},"ICON-0313":{"nm":"پایه تاریخ","de":"پایه‌ای کوچک که امروز را راست نگه می‌دارد تا رودررویت بایستد. از میان روزهایی که پی‌درپی می‌گذرند، یکی را برمی‌گزینی و در برابر خود می‌نشانی، و حتی تاریخی معمولی هم گرمایی درخور جشن می‌گیرد."},"ICON-0314":{"nm":"برچسب شماره مجموعه","de":"شماره‌ای یکتا که به هر چیز عزیزی اختصاص داده می‌شود. جمع‌آوری کردن یعنی سوگند خوردن که آن یک چیز را تنها نمونه‌ی خود در سراسر جهان بخوانی؛ پس عددِ روی آن برچسب کوچک، وزن دل را به‌روشنی حک می‌کند."},"ICON-0315":{"nm":"جلد آرشیو","de":"جلدی نازک که هر چیز دیربازمانده را یکی‌یکی درون آن سُر می‌دهی. کاری برای فاصله انداختن یک لایه میان آن و نور و زمان؛ عاشق چیزی بودن، سرانجام یعنی خوب نگهش داشتن."},"ICON-0316":{"nm":"بند نگه‌دارنده تاپ‌لودر فوتوکارت","de":"بندی باریک که تاپ‌لودر را به گردن می‌آویزد. راهی از هواداری‌ست: گذراندن روز با محبوبت نزدیک قلبت؛ و در همین یک نخ باریک، همراهی مهربان یک روز تمام گره خورده است."},"ICON-0317":{"nm":"سنجاق پایه فوتوکارت","de":"با یک سنجاق کوچک، فوتوکارت راست روی میز می‌ایستد. خوابیده که باشد فقط یک برگ کاغذ است، اما ایستاده، سرانجام چهره‌ای می‌شود که چشم در چشمت می‌دوزد؛ و آرام جایی برای ماندن نگاهت می‌سازد."},"ICON-0318":{"nm":"فیلم هولوگرافیک فوتوکارت","de":"لایه‌ای نازک که با هر زاویه، رنگین‌کمانی جاری می‌شود. غشایی که کمی نور را در خود گیر می‌اندازد و کارتی عادی را در نور ستاره می‌پوشاند؛ جادویی کوچک که با هر تکان مچ، حالتی تازه برق می‌زند و بیدار می‌شود."},"ICON-0319":{"nm":"کاور محافظ فوتوکارت","de":"با یک فشار به گوشه‌اش، انگار دل عزیزت هم چین می‌خورد. زرهی شفاف که یک برگ گران‌بها را محکم در آغوش می‌گیرد؛ عزیز داشتن واقعی، همیشه با همین دقت و مراقبت همراه است."},"ICON-0320":{"nm":"سینی چیدمان فوتوکارت","de":"سینی کم‌عمقی که ده‌ها فوتوکارت را رگه‌به‌رگه، مرتب می‌خواباند. پراکنده که باشند فقط یک توده‌اند، اما ردیف‌شده مجموعه‌ای می‌شوند؛ و با هر دستِ مرتب‌کننده، ترتیب علاقه لایه‌لایه حک می‌شود."},"ICON-0321":{"nm":"پاکت مبادله فوتوکارت","de":"وقتی یک فوتوکارت را برای دادن درون پاکت می‌گذاری، نوک انگشتانت لحظه‌ای مردد می‌ماند. این بدرقه نیست، بلکه خواهشی‌ست که محبوب کسی دیگر شود. همان لحظه که لبه‌ی پاکت را تا می‌زنی، پیوندی کوچک آرام دست عوض می‌کند."},"ICON-0322":{"nm":"خودکار تزیین فوتوکارت","de":"آنچه فضای خالی را پر می‌کند نوشته نیست، احساس است. هرجا نوک قلم می‌گذرد، قلب‌ها و ستاره‌های کوچک می‌رویند، و برگه‌ای ساده به تشویقی یگانه در جهان بیدار می‌شود. تزیین کردن، نام دیگر اعتراف است."},"ICON-0323":{"nm":"کلیپس حلقه‌ای فوتوکارت","de":"صدای تیک، گاز گرفتن گیره. با همان یک قفل کوچک، کارت‌هایی که نزدیک بود پراکنده شوند، در یک ردیف گرد هم می‌آیند. حتی اگر تمام روز درون کیف تکان بخورند، یک گوشه هم آسیب نمی‌بیند. استحکام، این‌قدر بی‌صداست."},"ICON-0324":{"nm":"کیف حمل فوتوکارت","de":"عادتی نامحسوس در دستی که زیپش را باز و بسته می‌کند نشسته است. حتی زیر بارانی ناگهانی، حتی در ازدحام جمعیت، فقط درونش خشک می‌ماند. نگه‌داشتن عزیزترین چیز در عمیق‌ترین جا، همان کار مهربانانه‌ی حمل کردن است."},"ICON-0325":{"nm":"بند دستبند فن‌میتینگ","de":"دست‌های گرم عوامل که بند را دور مچش بست، هوادار برای مدت‌ها به یاد داشت. یک گره، نشانه‌ی تعلق به این‌جا و امروز است. دوبار پیچیده تا باز نشود، آن بند تمام هیجانِ یک روز را در جای خود نگه می‌دارد."},"ICON-0326":{"nm":"دستبند ورود","de":"درست همان لحظه‌ای که از درگاه می‌گذری، سرانجام درون و بیرون به‌روشنی از هم جدا می‌شوند. تمام روز که بسته باشد، کم‌کم به پوستت خو می‌گیرد، و وقتی بازش می‌کنی، ردی باریک باقی می‌ماند؛ چون گواهی بر جایی که در آن مانده‌ای."},"ICON-0327":{"nm":"چیپ گوشه گفتگو","de":"وقتی گوشه‌ی گفتگو باز می‌شود، چیپی غلت‌زنان پیش می‌رود. کی اول حرف بزند، کدام سؤال انتخاب شود؛ همین تصادف کوچک، تمام فضا را دگرگون می‌کند. هوس یک چیپ کوچک، از فیلم‌نامه‌ای از پیش نوشته‌شده دلنشین‌تر است."},"ICON-0328":{"nm":"بلیت نوبت جلسه امضا","de":"برگه‌ای شماره‌دار به دست، در صف می‌ایستی. شماره‌ی ۱۴۲. تا وقتی ۱۴۱ نفر پیش از خود را می‌شماری، قلبت زودتر نوبتش را می‌شمارد. انتظار طولانی‌ست، اما به‌لطف همین یک برگه، حتی آن زمان هم بخشی از هیجان می‌شود."},"ICON-0329":{"nm":"دستکش های‌تاچ","de":"در لحظه‌ای که دو کف دست به هم می‌رسند، دستکش به‌جای تو آن گرمای کوتاه را می‌پذیرد. دستی که تمام روز برای لمسی ۰.۵ ثانیه‌ای گرم شده بود. تازه آن‌جاست که همه می‌فهمند حتی پارچه هم نمی‌تواند آن لرزش را متوقف کند."},"ICON-0330":{"nm":"سنجاق عکس یادگاری","de":"با صدای کلیک، امروز درست همان‌طور که هست، ثبت می‌شود. درون قابی که سنجاق نگه‌اش داشته، حتی لبخندی دست‌وپاچلفتی هم روزی دلتنگ‌کننده‌ترین صحنه می‌شود. ثبت کردن، مهربان‌ترین حرصِ نگه‌داشتنِ یک لحظه است."},"ICON-0331":{"nm":"روبان برچسب صندلی","de":"روبانی کوچک که به پشتی صندلی آویزان است، بی‌آنکه بادی بوزد، تکان می‌خورد. نشانه‌ای که کسی بسته، ردی از اینکه اینجا کسی بوده. حتی روی صندلی خالی پس از پایان اجرا، انگار فقط این روبان هنوز ضرب‌آهنگ را به یاد دارد."},"ICON-0332":{"nm":"برچسب بازرسی هدیه","de":"روی هر هدیه، برچسبی می‌نشیند. آیا فرستاده شده، آیا بررسی شده، آیا چیزی جا نمانده. حتی گرفتن دل کسی هم خانه‌داری می‌خواهد؛ این برچسب کوچک، مراقبت را بی‌هیچ شکافی به مراقبت دیگر پیوند می‌زند."},"ICON-0333":{"nm":"برگه یادبود","de":"برگه‌ای که برای نگه‌داشتن و بازبینی طولانی‌مدت نوشته شده. آب‌وهوای آن روز، شماره‌ی صندلی، حتی نام آخرین آهنگ. خاطره کم‌رنگ می‌شود، اما فقط این برگه کم‌رنگ نمی‌شود. نگهداری خاطره هم قالبی کوچک لازم دارد."},"ICON-0334":{"nm":"حلقه حوله تشویق","de":"حلقه‌ای به انتهای حوله وصل کن تا از شانه‌ات نلغزد. میان پاک کردن عرق، چرخاندنش بالای سر، و دوباره انداختنش دور گردن، یک اتصال کوچک، حرکات تشویق را بی‌وقفه به هم پیوند می‌دهد."},"ICON-0335":{"nm":"گیره شعار","de":"گیره‌ها دو سر شعار را محکم می‌گیرند. تا حتی وقتی هر دو دست بالا برود، حروف تا نخورد و پرپر نزند. اینجا، در جایی نادیده، پیام را صاف نگه می‌دارد؛ ساکت‌ترین نقش مکمل."},"ICON-0336":{"nm":"کیف بی‌صدا","de":"زیپ آرام و بی‌صدا سُر می‌خورد. سکوتی طراحی‌شده که حتی یک صدای کوچک هم در جایی که آرامش وعده داده شده نشت نکند. این کیف آرام می‌گوید که ملاحظه‌کاری، گاهی یعنی خودت را ناشنیدنی کردن."},"ICON-0337":{"nm":"چیپ ریتم کف‌زدن","de":"هر بار که کف دست‌ها به هم می‌خورند، چیپ ضرباهنگ را می‌شمارد. تَق، تَق، تَق؛ کف‌زدن‌های پراکنده در لحظه‌ای در یک ریتم جمع می‌شوند. جادوی هزاران کف‌زدن که به یک نفس واحد بدل می‌شود، چیپی کوچک آرام یاری‌اش می‌کند."},"ICON-0338":{"nm":"پوشه راهنمای تشویق","de":"بازش کن، راهنمای تشویق مرحله‌به‌مرحله نوشته شده. در کدام بیت چه رنگی را بالا ببری، کِی فریاد بزنی. حتی تازه‌واردی هم با همین یک پوشه، به‌سرعت یکی از خانواده می‌شود. راهنمایی کوچک برای شریک شدن در یک پیمان."},"ICON-0339":{"nm":"بند بادبزن صندلی","de":"بندی به دسته‌ی بادبزن ببند تا اگر از دستت افتاد گم نشود. در روزی گرم، وقتی هر دو دست برای تشویق آزاد می‌شوند، از مچت آویزان می‌ماند. یک بند، گرما و هیجان را با هم خنک می‌کند."},"ICON-0340":{"nm":"تکه فیلم درخشان","de":"نور که بگیرد، هر تکه‌اش را از زاویه‌ای متفاوت می‌شکند. روی کف دستت بگذاری، رنگین‌کمانی کوچک سوسو می‌زند و با هر تکان، رنگ‌ها زنده حرکت می‌کنند. شاید درخشیدن، یعنی نور را ریزریز تقسیم کردن."},"ICON-0341":{"nm":"میله کوچک بنر","de":"میله‌ی کوچک را باز کنی، پارچه باد را می‌گیرد و کشیده می‌شود. با دو دست بالا ببری‌اش، حروف تا آن‌سوی جایگاه می‌رسند؛ ببندی‌اش، در گوشه‌ی کیف جا می‌شود. اندازه‌ی دل با طول میله سنجیده نمی‌شود."},"ICON-0342":{"nm":"پک استیکر تشویقی","de":"روی هر برچسب، جمله‌ای تشویقی حک شده. روی دفترچه، روی گوشی، روی گوشه‌ی لپ‌تاپ؛ هر جا بچسبانی‌اش، زندگی روزمره رنگ تشویق می‌گیرد. دل شیفته این‌گونه ردی از خود در همه‌جا برجا می‌گذارد."},"ICON-0343":{"nm":"کاور محافظ آلبوم","de":"دستی که آلبوم را در کاور می‌پیچد، محتاط است. تا گوشه‌هایش نساید، تا زیر نور آفتاب رنگ نبازد. موسیقی با گوش شنیده می‌شود، اما این یک برگه را دست به یاد می‌آورد. زرهی از دل که می‌خواهد عزیزش را مدت‌ها نزدیک نگه دارد."},"ICON-0344":{"nm":"حلقه جلد دیسک","de":"دیسک‌ها را در جلد بگذار و با حلقه ببند، آلبومی کتاب‌مانند می‌شود. صدای خش‌خش هر بار ورق‌زدن، دل‌پذیر است. جمع کردن موسیقی پراکنده، مرتب در کف دست؛ همان خوشبختی آرام یک گردآورنده است."},"ICON-0345":{"nm":"جداکننده نگهداری گودز","de":"با یک جداکننده، کالاهایی که نزدیک بود قاطی شوند، جای خود را می‌یابند. اینجا فوتوکارت، آنجا جاکلیدی، کنارش لایت‌استیک. مرتب کردن یعنی برای اشیا خانه ساختن. همان لحظه که خانه‌ها جدا می‌شوند، بی‌نظمی به نظم بدل می‌شود."},"ICON-0346":{"nm":"نخ مهروموم پک شانسی","de":"دهانه‌ی پک شانسی را با نخ ببند تا سرنوشت هیچ‌کس هنوز رقم نخورده باشد. تا وقتی بازش نکنی، همه قهرمان امیدشان هستند. لرزش نوک انگشتان هنگام باز کردن مهروموم، همان لذتی‌ست که این نخ حفظ کرده است."},"ICON-0347":{"nm":"جعبه دسته‌بندی هدایای ویژه","de":"هدایای ویژه درون جعبه، دسته‌دسته صف می‌کشند. کارت‌پستال کنار کارت‌پستال، نشانه‌کتاب کنار نشانه‌کتاب. خانه‌هایی که هرچه بیشتر پر می‌شوند، تمام زمانی که جمع کرده‌ای را یک‌جا نشانت می‌دهند. مرتب کردن، همان فهرست خاطرات است."},"ICON-0348":{"nm":"برچسب تفکیک نسخه","de":"چیزهایی هستند که شبیه‌اند اما یکسان نیستند. یک برچسب، نسخه‌ی A را از نسخه‌ی B، چاپ اول را از چاپ دوباره جدا می‌کند. به‌لطف نشانه‌ای کوچک، سردرگمی محو می‌شود و بر جهانِ گردآوری، برچسبی شفاف نصب می‌گردد."},"ICON-0349":{"nm":"یادداشت ثبت فروش هفته اول","de":"هفته‌ی انتشار، دل با یک عدد به لرزه می‌افتد. نشانه‌های تیک، منظم روی کاغذ یادداشت. چند روز که ثبت شود، کارنامه‌ی کوچک حمایت می‌شود. عادتی دقیق برای ترجمه‌ی دل شیفته به زبان اعداد."},"ICON-0350":{"nm":"کلاهک نگهدارنده پوستر","de":"کلاهکی به سر پوستر لوله‌شده بزن تا باز و آرام بماند. تا وقتی تصمیم بگیری بر دیوار بیاویزی‌اش یا در قاب بگذاری، چروک نخورد. مسدودکننده‌ای کوچک که محبوب‌ترین صحنه را صاف نگه می‌دارد."},"ICON-0351":{"nm":"پایه ایستاده عکس","de":"عکس روی پایه، کج می‌ایستد. در گوشه‌ی میز، درست در زاویه‌ای هم‌تراز نگاه. اختراعی که هر بار می‌گذری، نگاهت را به دیدار می‌رساند. ساده‌ترین راه برای آوردن چهره‌ای دوست‌داشتنی به منظره‌ی هرروزه‌ات."},"ICON-0352":{"nm":"رول چسب تمرین","de":"چسبی روی زمین می‌چسبانند تا جای ایستادن را نشان دهد. یک خانه، دو خانه، دقیقاً اینجا. با گام گذاشتن بر همان رد، ده‌ها بار، مسیر حرکت در بدن حک می‌شود. زیر صحنه‌ی پرزرق‌وبرق، همین ردهای صادق چسب پهن شده‌اند."},"ICON-0353":{"nm":"سنجاق مسیر صحنه","de":"سنجاقی کوچک که در کف صحنه فرو رفته، گام بعدی را نشان می‌دهد. حتی در تاریکی، نوک پا زودتر از هر چیز آن جا را می‌یابد. مسیری دقیق اما نادیدنی؛ نقشه‌ای نامرئی که تمرین‌های بی‌شمار ترسیمش کرده‌اند."},"ICON-0354":{"nm":"گوشی محافظ عوامل","de":"گوشی را می‌گذاری و غرش جایگاه یک لایه فروکش می‌کند، فقط صدای رساننده‌ی کیو واضح می‌ماند. گوش عوامل پشت‌صحنه همیشه دو جهان را هم‌زمان می‌شنود. ابزاری کوچک برای جدا کردن سیگنال از میان هیاهو."},"ICON-0355":{"nm":"برچسب چوب‌لباسی اتاق انتظار","de":"روی هر چوب‌لباسی، برچسبی آویزان است. لباس شماره‌ی یک، لباس شماره‌ی دو، لباس آنکور. با نگاه به آن جدول که ترتیب تعویض را ردیف کرده، صحنه‌ی امروز از پیش با ترتیب لباس‌ها ترسیم می‌شود. نظمی آرام که شلوغی را رام می‌کند."},"ICON-0356":{"nm":"تگ بازرسی وسایل صحنه","de":"پیش از رفتن روی صحنه، به هر وسیله‌ای تگ می‌بندند. چیزی جا نمانده؟ سالم است؟ جایگاه تماشاگران نمی‌داند، اما همین بازرسی کوچک، از حادثه جلوگیری می‌کند. پشت صحنه‌ای که بی‌نقص به نظر می‌رسد، همیشه دستی موشکاف هست."},"ICON-0357":{"nm":"چیپ نشانه کیو","de":"چیپ کیو از دستی به دست دیگر می‌رسد. حالا، برو تو. لحظه‌ای که زمان‌بندی بی‌هیچ کلامی منتقل می‌شود. در تاریکی کنار صحنه، این نشانه‌ی کوچک، همه را از دست دادن ریتم باز می‌دارد."},"ICON-0358":{"nm":"پچ پشت‌صحنه","de":"دری هست که فقط کسی با این پچ می‌تواند از آن بگذرد. پشت صحنه، جایی که هلهله از پشت دیوار به گوش می‌رسد. تکه‌پارچه‌ای کوچک، جلوی پرزرق‌وبرق را از پشتِ پرمشغله جدا می‌کند. نشانه‌ی کسانی که صحنه را برپا نگه می‌دارند."},"ICON-0359":{"nm":"صفحه محافظ پرومپتر","de":"صفحه‌ای که نور پرومپتر را از نشت به سمت جایگاه نگه می‌دارد. فقط کسی که روی صحنه است می‌بیندش، تماشاگر خبردار نمی‌شود. نگهبان مؤدب رازِ صحنه، که کمکی را که نباید لو برود، آرام پنهان می‌کند."},"ICON-0360":{"nm":"روکش آینه اتاق انتظار","de":"در اتاق انتظار پس از پایان اجرا، آینه با پارچه پوشانده می‌شود. شیشه‌ای که تمام روز حالت‌های بی‌شمار را بازتاب می‌داد، لحظه‌ای چشم می‌بندد. آخرین چیزی که چهره‌ی بی‌آرایش با آن روبرو می‌شود، آینه نیست، تاریکی‌ای آرام است."},"ICON-0361":{"nm":"دستبند ورود ضبط از پیش","de":"بندی کوچک که وقتی بسته شود، تا بریده نشود باز نمی‌شود. برای همان یک شرط ورود به جایگاه ضبط از پیش، یکی خود را سوار اولین قطار در سپیده‌دمی سیاه کرد. وزن روی مچ دست، همان هیجانِ یک روز تمام می‌شود."},"ICON-0362":{"nm":"برچسب آماده‌باش ضبط","de":"درست پیش از روشن شدن چراغ قرمز، کار من این است که نفس همه را در یک ردیف گره بزنم. در سکوتِ منتظر کیو، خودم تا آخرین لحظه آرام مقاومت می‌کنم. همان لحظه که کنده می‌شوم، سرانجام پرده‌ی پخش زنده بالا می‌رود."},"ICON-0363":{"nm":"چیپ موقعیت دوربین","de":"یک نشانه‌ی کوچک روی زمین، مسیر شش دوربین را با دقت تعیین می‌کند. کجا گرفته شود که درخشان‌ترین باشد، کارگردان حتی پیش از تمرین هم می‌داند. دستی که پیش از هر چیز، درون قاب را از بیرون آن ترسیم می‌کند."},"ICON-0364":{"nm":"تگ چک صدا","de":"میکروفن را به سمت جایگاه خالی، آرام می‌کوبی. اگر پژواک طولانی بود، یک لایه دیگر عایق صوتی روی سقف. مراقبتی که بی‌آنکه تماشاگر بداند، بافت صدا را صیقل می‌دهد، آرام از همین برچسب کوچک آغاز می‌شود."},"ICON-0365":{"nm":"دفترچه مهر میدانی","de":"هر بار که از مکانی می‌گذری، مهری دیگر در یک خانه جمع می‌کنی. در هر لکه‌ی جوهر پخش‌شده، آب‌وهوا و تپش دل آن روز هم مهر خورده است. صفحه‌ای که پر شود، نقشه‌ی ردپایی می‌شود که هیچ‌کس نمی‌تواند تقلید کند، فقط از آنِ من."},"ICON-0366":{"nm":"بند کارت بازدید ایستگاه پخش","de":"بدون این بند، دروازه‌ی لابی باز نمی‌شود. دور گردن آویزان، در حالی که راهرو را گام‌به‌گام می‌پیمایی، جهانی که تا دیروز فقط از پشت صفحه می‌دیدی، آرام‌آرام آن‌قدر نزدیک می‌شود که دست به آن برسد."},"ICON-0367":{"nm":"پک روکش کفش استودیو","de":"کف استودیو همیشه سرد و لغزنده است. کفش را درمی‌آوری، روکش نازک پا می‌پوشی و صدای قدم‌ها آرام محو می‌شود. چون دوربین رقص را ثبت می‌کند نه صدای قدم را؛ محو کردن صدا هم نوعی ادب نسبت به صحنه است."},"ICON-0368":{"nm":"برچسب تنقلات اتاق انتظار","de":"میان تمرین و پخش زنده، گرسنگی صادقانه‌ترین چیزی‌ست که سراغت می‌آید. روی هر تنقلات گوشه‌ی اتاق انتظار، برچسب کوچکی نوشته سهمِ کیست. همان مهربانیِ کنار گذاشتن، تو را تا انتهای روزی طولانی و طولانی نگه می‌دارد."},"ICON-0369":{"nm":"نوار یادداشت مانیتورینگ","de":"پخش را دوباره می‌بینی و می‌نویسی. اینجا نگاه را، آنجا نیم‌ضرب را. خط‌های فشرده، نامه‌ای مخفی برای خودِ فردا هستند. نواری که به انتهایش چسبانده، وعده‌ای آرام برای بهتر شدنی به‌اندازه‌ی یک وجب از دیروز است."},"ICON-0370":{"nm":"برگه دعوت‌نامه شوکیس","de":"یک برگه‌ی کاغذ، برای کسی می‌تواند تمام یک سال انتظار باشد. جمله‌ای کوتاه که به شوکیس دعوت می‌کند، به‌عنوان کوچک‌ترین دعوت‌نامه‌ی جهان زاده شده، و حتی لرزش نوک انگشتانِ بازکننده‌ی پاکت را هم در خود دارد."},"ICON-0371":{"nm":"بند گردنی خبرنگاری","de":"به گردن خبرنگاران آویزان است و درست وسط صدای شاتر می‌رود و می‌آید. گام‌هایی که شتاب‌زده به‌دنبال بهترین زاویه می‌دوند، و همان سرعت، به گذرگاهی بدل می‌شود که گرمای صحنه را به دنیای بیرون می‌برد."},"ICON-0372":{"nm":"جدول ترتیب تعظیم پایانی","de":"تا حتی در لحظه‌ای که کف‌زدن سیل‌آسا فرومی‌ریزد کسی جا نماند، اینکه چه کسی اول و چه کسی بعدی‌ست در یک خط نوشته می‌شود. چیدمانِ آخرین تعظیم، به همان دقتی که ورود نخست بافته می‌شود."},"ICON-0373":{"nm":"نشانگر کف دیوار عکس","de":"کف جلوی دیوار عکس، جای نوک پا از پیش حک شده. حتی یک قدم کج بایستی، لوگوی پس‌زمینه بریده می‌شود. راز آن موقعیتی که درخشان‌ترین ثبت می‌شود، آرام زیر پا نشانه‌گذاری شده است."},"ICON-0374":{"nm":"دستبند نمایش نخست","de":"بندی کوچک که درست پیش از خاموش شدن چراغ‌های سینما به مچ بسته می‌شود. وقتی پرده بالا می‌رود، همه در همان تاریکی، برای اولین‌بار در عمرشان با یک صحنه روبرو می‌شوند. نشانه‌ای کوچک از حضور در آن نخستین لحظه."},"ICON-0375":{"nm":"تکه یادگاری پرده","de":"در روز آخرین اجرا، پس از آخرین تعظیم، پرده آرام پایین آمد. تکه‌ای بریده از همان پارچه، درون قاب. روی پارچه، گرمای نورافکن‌ها و لرزش کف‌زدن‌ها هنوز نیمه‌گرم مانده، هنوز سرد نشده است."},"ICON-0376":{"nm":"مهر رونمایی نخست","de":"روزی که برای نخستین‌بار خود را به جهان نشان می‌دهی، مهری حک‌شده برای همان یک بار. رونمایی دومی وجود ندارد، پس حتی لحظه‌ی کوتاه خشک شدن جوهر هم زمانی‌ست که هرگز بازنمی‌گردد."},"ICON-0377":{"nm":"کارت لحظه صحنه","de":"درخشان‌ترین قاب یک صحنه، بریده و روی کارتی نشسته. موسیقی و نور متوقف شده‌اند، اما همان لحظه که در دستت می‌گیری‌اش، هلهله‌ی آن روز دوباره در گوشت باد می‌کند. جادویی کوچک که صحنه‌ای متوقف‌شده را زنده می‌کند."},"ICON-0378":{"nm":"یادداشت ژست پایانی","de":"درست لحظه‌ای که آخرین نت پایان می‌یابد، یادداشتی که زاویه‌ی نوک انگشتان و نگاهی را که باید در جا خشک شود، ترسیم می‌کند. فقط کسی که می‌داند یک قاب پایانی می‌تواند سرنوشتِ چند روز را رقم بزند، این نقاشی کوچک را با دقت تا می‌زند و نگه می‌دارد."},"ICON-0379":{"nm":"سنجاق شهرهای تور","de":"روی نقشه، به هر شهری که رفته‌ای، سنجاقی فرو می‌رود. نسیم دریای بوسان و نیمروز گوانگجو، هر دو در نوک همین میخ‌های کوچک نشسته‌اند. نقطه‌ها را آرام به هم وصل کن، خط بلند سفری را می‌بینی که یک فصل تمام را درنوردیده."},"ICON-0380":{"nm":"کلیپس بخش صندلی","de":"ده‌ها هزار صندلی را به بخش‌هایی تقسیم می‌کند و راه را نشان می‌دهد. تا گم نشوی، تا با کسی برخورد نکنی. مرا دنبال کن تا هرکس به جای خودش برسد. نظم، در نهایت، مهربانی‌ای کوچک برای همه است."},"ICON-0381":{"nm":"برچسب دروازه ورود","de":"جلوی دروازه، یکی‌یکی نوبت‌به‌نوبت بررسی می‌شوند. آخرین دروازه‌ای که دستِ بلیت‌به‌دست و دلِ تندتپنده را به درون راه می‌دهد. همان لحظه که از من می‌گذری، انتظار طولانی پایان می‌یابد و صحنه‌ی امروز آغاز می‌شود."},"ICON-0382":{"nm":"کپسول نگهداری دستبند","de":"حتی اگر رنگ بپرد، همان هلهله‌ی آن روز دست‌نخورده مهروموم می‌ماند. نمی‌توانی بند مچت را دور بریزی، پس آرام درون کپسولی کوچک می‌پیچی‌اش. چون دلت می‌خواهد حتی به خاطره‌ای عزیز هم گوشه‌ای برای آرمیدن بدهی."},"ICON-0383":{"nm":"میله مبادله میدانی","de":"میان هوادار و صحنه، چیزی از دست به دست می‌رسد. شاید نامه‌ای، شاید هدیه‌ای کوچک. من راهی می‌سازم تا آن دل بی‌خطر برسد، شلوغ‌ترین پلِ میدان."},"ICON-0384":{"nm":"مهر تاریخ اجرا","de":"تاریخ آن روز درون مهری گرد حک می‌شود و برای همیشه می‌ایستد. تقویم ورق می‌خورد، اما فقط این دایره‌ی کوچک همان‌جا در آن یک روز باقی می‌ماند. وقتی روزی نمی‌خواهی فراموش شود، آدم‌ها همیشه چیزی را مهروموم می‌کنند."},"ICON-0385":{"nm":"پچ کیف تور","de":"کیفی که همراه تور گشته، برای هر شهر یک پچ بیشتر می‌گیرد. نام‌های شهرهایی که روی پارچه دوخته شده‌اند، بی‌آنکه بدانی به رزومه‌ای بدل می‌شوند. حتی گوشه‌های ساییده و فرسوده‌اش، مدرکی می‌مانند از این‌که همه‌جا با هم رفته‌اند."},"ICON-0386":{"nm":"بند تخته بلیت","de":"تخته‌ای که در انتهای صف ورود تکان می‌خورد، نخی که نوکش را محکم بسته. میان منظره‌ی دست‌هایی که بلیت را بالا گرفته و صفی طولانی کشیده‌اند، من آرام سرِ صفِ آن رژه‌ای که هیجان در آن ایستاده را نشانه‌گذاری می‌کنم."},"ICON-0387":{"nm":"تکه روبان آنکور","de":"شبی که فریادهای خواستارِ آنکور بلندترین بودند، تکه‌ای از روبان تزیین‌کننده‌ی صحنه افتاد. مثل ترانه‌ای که چون دریغ از تمام‌شدنش بود، طولانی‌تر خوانده شد، در این تکه هم دلی که دلش نمی‌خواهد برود، گره خورده است."},"ICON-0388":{"nm":"بطری کپسول پیام","de":"کلامی که با دقت تا شده، درون بطری شیشه‌ای جای گرفته. مثل قایقی کوچک که به امید رسیدن روزی رها شده، من دلی را در خود دارم و آرام روی زمان شناورم. تا روزی که بازم کنند، وعده در درونم آرام به خواب رفته است."},"ICON-0389":{"nm":"برچسب اعتراف کوچک","de":"حرفی که زبان توانِ گفتنش را نداشت، روی برچسبی کوچک نوشته و آرام لای چیزی جا داده می‌شود. خط‌ها می‌لرزیدند، اما فقط صداقتش روشن بود. گاهی کوچک‌ترین کاغذ، بزرگ‌ترین شجاعت را در خود دارد."},"ICON-0390":{"nm":"صندوقچه یادداشت‌های تشویق ناشناس","de":"حتی بی‌آنکه نامی نوشته شود، دل به مقصد می‌رسد. با هر یادداشتی که وارد صندوق می‌شود، تشویق کسی، ناشناس، یکی‌یکی روی هم انبار می‌شود. مجموعه‌ای از مهربانیِ بی‌چهره، که هرچند ندانی چه‌کسی نوشته، فقط گرمایش روشن است."},"ICON-0391":{"nm":"کاغذ تاکردن آرزو","de":"کاغذی چهارگوش، به‌دنبال نوک انگشتانت، جرثقیل می‌شود، ستاره می‌شود. با هر تا خوردن، آرزو هم لایه‌ای دیگر روی خود تا می‌خورد. در شکلی که با دقت تا شده، صداقتی زندگی می‌کند که از کلام دیرپاتر می‌ماند."},"ICON-0392":{"nm":"موم مهروموم روبانی","de":"قطره‌ی موم را بچکان و مهر را محکم فشار بده، نامه سرانجام مهروموم می‌شود. همان شیوه‌ی کهن برای سفت کردن یک دل. روی موم قرمزِ رو به سرد شدن، رازی آرام قفل می‌شود."},"ICON-0393":{"nm":"کاغذ ضربه‌گیر هدیه","de":"از ترس آسیب دیدنِ هدیه، دور آن را نرم می‌پیچد. در هر چین مچاله‌شده، خواهشی نشسته که نشکند. کسی که هدیه را می‌گیرد شاید هرگز نفهمد، لایه‌ای محتاطانه از دل در جایی نادیده."},"ICON-0394":{"nm":"نخ رنگی نامه","de":"حتی نخی که نامه را می‌بندد، رنگ دارد. زرد برای تشویق، آبی برای دلتنگی. احساسی که کلمات یارای گفتن کاملش را ندارند، با رنگ انتخاب و گره می‌خورد. پیش از باز کردنش هم، دمای دل زودتر به نوک انگشتانت می‌رسد."},"ICON-0395":{"nm":"نوار پوشاننده دست‌نوشته","de":"نواری که تا لحظه‌ی آخرِ دادن، نوشته را پنهان نگه می‌دارد. اعترافی را که از لو رفتن هراسان است، تا آخرین ثانیه نگهبانی می‌کند. صداقتی که با کمی بالا زدن آشکار می‌شود، وزن آن لرزش را من از همه نزدیک‌تر می‌شناسم."},"ICON-0396":{"nm":"چیپ جمله تشویقی","de":"شبی که لایت‌استیک‌ها موج می‌زنند، جمله‌ای که باید با یک صدا فریاد زده شود، درون چیپ حک شده. کلماتِ پیمانی که دل‌های پراکنده را در یک خط جمع می‌کند. وقتی همه با هم بخوانندش، آن جمله درخشان‌ترین می‌شود."},"ICON-0397":{"nm":"جاکلیدی کهنه اتاق تمرین","de":"جاکلیدی‌ای که در اتاق تمرین را صدها بار باز و بسته کرده. رنگش پوسته‌پوسته شده و حلقه‌اش شل شده، اما در آن، عرقِ دست‌وپاچلفتی‌ترین روزها به‌شکل رد دست باقی مانده. کهنه بودن، یعنی همان‌قدر طولانی ماندن."},"ICON-0398":{"nm":"تکه مدادرنگی گریم صحنه","de":"آرایش صحنه، فقط زیر نور کامل می‌شود. تکه‌ای از آن رنگ تیره. در ردی که محکم زده شده تا با عرق پخش نشود، همان دلسوزی برای رساندن حالت چهره تا دورترین ردیف جایگاه، دست‌نخورده باقی مانده."},"ICON-0399":{"nm":"جعبه ایرتیپ","de":"ایرتیپ‌های کوچکی که روی صحنه صدای خودت را به گوشت می‌رساندند. اجرا که تمام شود، آرام درون جعبه می‌خوابانی‌شان. هرچه چیزی موسیقی را نزدیک‌تر به تو رسانده باشد، بیشتر دلت می‌خواهد با دقت نگهش داری."},"ICON-0400":{"nm":"برچسب کمد شخصی","de":"انتهای راهرو اقامتگاه، روی هر کمد برچسب اسمی. خط کوچکی که می‌گوید جای کیست، فضایی غریب را به خانه بدل می‌کند. داشتنِ خانه‌ی خودت، یعنی اجازه‌ای مهربان برای اینجا ماندن."},"ICON-0401":{"nm":"بطری قابل‌حمل مراقبت از گلو","de":"میان تمرین‌ها، جرعه‌ای آب ولرم را آرام می‌بلعی. گلو سازی است که خواننده به امانت می‌گیرد، پس این بطری کوچک که پیش از سرد شدن آب پر می‌شود، اولین نتِ فردا را از پیش پاس می‌دارد. دلواپسی همیشه همین‌قدر بی‌صداست."},"ICON-0402":{"nm":"سنجاق یادآور برنامه","de":"روی روزی که دقیقه به دقیقه پر شده، یک سنجاق به خانه‌ی بعدی اشاره می‌کند. در میان آن ردیف‌های فشرده، خوش‌آیندترین چیز همان یک خانه‌ی خالی است. زمانی که می‌شود لحظه‌ای از پنجره بیرون را نگاه کرد، همان‌جا، کوچک، پنهان شده است."},"ICON-0403":{"nm":"گیره‌ی پتوی اتاق انتظار","de":"بعدازظهری که آرایش تمام شده بود و روی صندلی چرت زده بودی، کسی آرام پتویی روی شانه‌هایت انداخت. این گیره که آن را محکم گرفته تا نلغزد، گرمای آن دست را تا لحظه‌ی رفتن به روی صحنه بی‌صدا نگه می‌دارد."},"ICON-0404":{"nm":"نمونه عطر کوچک","de":"اگر آرام روی مچ دست بزنی، رایحه فقط در فاصله‌ی یک وجب شکوفا می‌شود. لازم نیست دور دست‌ها پخش شود. ردی که فقط کسی که نزدیک شده متوجهش می‌شود، پنهانی‌تر است و به همین خاطر بیشتر شبیه خودِ من است."},"ICON-0405":{"nm":"برچسب شست‌وشوی لباس تمرین","de":"هرچند بار که بشویی‌اش، بوی عرق که در عمق پارچه نشسته هیچ‌وقت کاملاً پاک نمی‌شود. لباس تمرینی را که زیر آفتاب آویزان و نرم خشک شده دوباره تا می‌کنی و فکر می‌کنی، آن لکه‌ای که پاک نمی‌شود، در واقع صادقانه‌ترین ردّ است."},"ICON-0406":{"nm":"فیلم ژلاتینی نورپردازی","de":"یک ورقه فیلم رنگی نازک را که جا بدهی، نور سفید به رنگ غروب پخش می‌شود، و اگر یک لایه دیگر روی آن بگذاری، سپیده‌دم فرو می‌نشیند. پشت پرده، دستی نفس در سینه حبس کرده، حتی به نور هم لباس می‌پوشاند و تصمیم می‌گیرد صحنه را به رنگ کدام فصل درآورد."},"ICON-0407":{"nm":"درپوش لنز اسپات‌لایت","de":"حتی وقتی دوربین خاموش است، کسی این درپوش کوچک را باز می‌کند تا لنز را پاک کند. برای صحنه‌ای که هنوز فیلم‌برداری نشده. بر فراز زمانی که در تصویر ثبت نمی‌شود، پرمشغله‌ترین دست از پیش فوکوس را تنظیم می‌کند."},"ICON-0408":{"nm":"صفحه‌ی بازتاب‌دهنده‌ی صحنه","de":"تخته‌ای هست که خودش نمی‌درخشد، اما نوری را که گرفته به چهره‌ای در سایه بازمی‌گرداند. مرکز صحنه آن‌قدر روشن است چون در گوشه‌ای، بازوی کسی بی‌صدا زاویه را تنظیم می‌کند و نور را بازتاب می‌دهد."},"ICON-0409":{"nm":"آستین فیلتر رنگی","de":"اگر نور آبی را در آستین شفاف جا بدهی، تمام جایگاه تماشاگران به دریا تبدیل می‌شود، و اگر به رنگ قرمز عوضش کنی، غروبی همان‌جا فرومی‌نشیند. جادوی این‌که همان صحنه با یک رنگ به فصلی دیگر بدل شود، از همین یک لایه‌ی نازک آغاز می‌شود."},"ICON-0410":{"nm":"سنجاق شماره‌ی نور","de":"هر یک از نورهای بی‌شمار شماره‌ای کوچک دارد. این‌که کدام روشن شود و کدام بخوابد، جریان اجرای امشب از پیش با ترتیب همین اعداد چیده شده. پشت پرده‌ی خیره‌کننده همیشه فهرستی موشکافانه گسترده است."},"ICON-0411":{"nm":"نوار نشانه‌گذاری نور","de":"روی کف صحنه‌ی خاموش، نوار فسفری بی‌صدا جایی را که پا باید بایستد روشن می‌کند. از جایگاه تماشاگران دیده نمی‌شود، اما نوک پای بازیگر این نور کم‌سو را می‌جوید تا جایش را پیدا کند. حتی در تاریکی هم راهنمایی مهربان هست."},"ICON-0412":{"nm":"صفحه‌ی مسدودکننده‌ی سایه","de":"تخته‌ای که نور نشتی را می‌بندد تا سایه‌ای واضح بیفتد. کنترل تاریکی هم در نهایت کنترل نور است، پس این‌که چه چیزی نشان داده شود، اول با آنچه آرام پنهان می‌ماند تعیین می‌شود."},"ICON-0413":{"nm":"چیپ سنجش روشنایی","de":"تراشه‌ی کوچکی که روشنایی فضا را می‌سنجد، روی کف دست عددها را می‌خواند. چون هم روشنایی زیاد و هم تاریکی زیاد به چشم آزار می‌رساند. این تراشه بی‌صدا آن خط میانه‌ی نامرئی را، جایی که آدم راحت‌تر می‌آرامد، پاس می‌دارد."},"ICON-0414":{"nm":"سایبان اسپات‌لایت سوزنی","de":"سایبانی که نور نقطه‌ای را از نشت به جای نادرست بازمی‌دارد. متمرکز کردن نور فقط روی یک نفر، توجهی مهربانانه است. لحظه‌ای که پا در آن دایره‌ی نور می‌گذاری، دنیا برای مدتی فقط به یک نفر نگاه می‌کند."},"ICON-0415":{"nm":"ست تیپ ایرفون","de":"جفتی تیپ ایرفون که دقیقاً در گوش جا می‌گیرد. اگر اندازه‌اش کمی هم نادرست باشد صدا نشت می‌کند و همان لحظه ریتم از دست می‌رود. آوازی که روی صحنه سر مویی هم نمی‌لرزد، گاهی از همین یک تکه لاستیک کوچک آغاز می‌شود."},"ICON-0416":{"nm":"بند چسبی کابل","de":"بندی چسبی که سیم‌های درهم را در یک رشته مرتب می‌بندد. پشت صحنه، جایی که کسی نمی‌بیند، نظم بیشتر می‌درخشد. مرتب بودن یک دسته کابل، بی‌صدا صدایی را که روبه‌روی جمعیت بی‌لرزش جاری می‌شود سرپا نگه می‌دارد."},"ICON-0417":{"nm":"برچسب بررسی خط","de":"برچسب‌هایی که با دست‌خط روی ده‌ها سیم نوشته شده‌اند تا معلوم شود کدام مربوط به کدام ساز است. فقط وقتی هر خط کج‌ومعوجِ آن نوشته جایش را حفظ کند، صداهایی که جدا جدا می‌نواختند سرانجام در یک قطعه به هم می‌پیوندند."},"ICON-0418":{"nm":"پد بی‌صدا","de":"یک تکه پد بی‌صدا که صدای پا و لرزش را بی‌صدا می‌بلعد. جایی پهن می‌شود که سکوت واقعاً لازم است. گاهی پاک‌ترین صدا فقط روی همین کف آرام، جایی که هیچ سروصدایی نشت نمی‌کند، زاده می‌شود."},"ICON-0419":{"nm":"توکن بررسی صدا","de":"توکنی که هنگام تنظیم صدا پیش از اجرا در دست گرم می‌شود. هر بار که یک میکروفون یا بلندگو بررسی می‌شود، جایش عوض می‌شود. کمالِ صحنه‌ی اصلی قدم به قدم در همین تمرین آرام شکل می‌گیرد."},"ICON-0420":{"nm":"کلاهک روکش میکروفون","de":"چون این جایی است که صداهای بی‌شماری به آن رسیده، این کلاهکِ دور نوک میکروفون را با دقتی بیشتر پاک می‌کنی. ظرفی است که آواز را در خود جای می‌دهد، پس برای خواننده مثل دستی دیگر است. حین پاک کردنش، اولین مصرع فردا را از پیش در ذهن می‌کشی."},"ICON-0421":{"nm":"گیره‌ی فیلتر پاپ","de":"لایه‌ی نازک توری که بین لب‌ها و میکروفون آویزان است. به لطف گیره‌ی کوچکی که آن پرده را نگه می‌دارد، نفس‌هایی که خشن نشت می‌کردند به‌زودی به صدایی گرد و نرم صاف می‌شوند و بیرون می‌ریزند."},"ICON-0422":{"nm":"برچسب رَک صوتی","de":"برچسبی کوچک که پشت صحنه‌ی تاریک، میان قفسه‌های انباشته از تجهیزات، آویزان شده تا کسی گم نشود. سرچشمه‌ی صدای پرشکوهی که سالن را پر می‌کند، همیشه در همین گوشه‌های کم‌نور، منظم و لایه‌لایه چیده شده است."},"ICON-0423":{"nm":"سنجاق توری بلندگو","de":"سنجاقی که توری بلندگو را محکم نگه می‌دارد. پنجره‌ای که صدا از آن بیرون می‌آید، اولین جایی است که گرد و غبار می‌نشیند، پس یک لایه توری نازک صدا را پاس می‌دارد. هر چیزی که به گوش می‌رسد، یک لایه محافظت نامرئی روی خود دارد."},"ICON-0424":{"nm":"استیکر نشانه‌گذاری قدم","de":"استیکرهایی که نقطه به نقطه روی زمین چسبانده شده‌اند. راز این‌که رقص گروهی مثل تیغ دقیق جفت و جور می‌شود، در واقع زیر پا پنهان است. روی نشانه‌های بی‌شمار وعده‌داده‌شده‌ای که ده‌ها نفر یک نقطه را لگد می‌زنند، پراکنده می‌شوند و دوباره جمع می‌شوند."},"ICON-0425":{"nm":"صفحه‌ی تمرین چرخش","de":"صفحه‌ی تمرینی که در جا می‌چرخد و می‌چرخد. برای غلبه بر سرگیجه، اول باید یاد گرفت نگاه را به یک نقطه دوخت. هر چقدر هم سریع بچرخی، تعادلی که آرام‌آرام در بدن حک می‌شود، طوری است که آن یک نقطه را هرگز رها نمی‌کنی."},"ICON-0426":{"nm":"رول نوار زانو","de":"رولی از نوار که زانو را محکم می‌پیچد. مفاصلی که هزاران بار پریده و فرود آمده‌اند سرانجام ساکت می‌مانند، اما این یک لایه بی‌صدا زیر آن سکوت را نگه می‌دارد. پشت بدنی که تا آخرین لحظه دوام می‌آورد، همیشه مراقبت کسی هست."},"ICON-0427":{"nm":"صفحه‌ی تراز نوک پا","de":"تخته‌ای که زاویه‌ی نوک پا را مرتب می‌کند. می‌گویند رقص بیشتر در نوک پا کامل می‌شود تا نوک انگشتان دست. ده‌ها نوک پا که به یک سو کشیده شده‌اند گرد هم می‌آیند و جادوی این‌که چند نفر مثل یک نفر به‌نظر برسند را می‌آفرینند."},"ICON-0428":{"nm":"پد ضدلغزش اتاق تمرین","de":"پدی ضدلغزش که روی کف اتاق تمرین پهن می‌شود. برای این‌که با خیال راحت بجهی، اول باید امن باشی. فقط روی کفی که می‌شود بدون نگرانی از افتادن غلتید، جسورانه‌ترین و بی‌باک‌ترین حرکت‌ها سرانجام شکوفا می‌شوند."},"ICON-0429":{"nm":"کارت تجزیه‌ی حرکت","de":"کارتی که کورئوگرافی را ضربه به ضربه به قطعات ریز تقسیم کرده. هر حرکتی هرچقدر هم سخت باشد، اگر خانه به خانه تقسیمش کنی، بی‌آنکه بفهمی می‌توانی دنبالش کنی. جریان روان و مثل آب صحنه، از همین تصویرهای بریده‌بریده و حفظ‌شده ساخته شده."},"ICON-0430":{"nm":"سنجاق پرده‌ی پوشش آینه","de":"سنجاقی که پرده‌ی پوشاننده‌ی آینه‌ی اتاق تمرین را نگه می‌دارد. زمانی که فقط با حس بدن می‌رقصی، بدون هیچ بازتابی، هم لازم است. می‌دانی که همان لحظه‌ای که آینه پوشیده می‌شود، موسیقی سرانجام تا زیر پوست نفوذ می‌کند."},"ICON-0431":{"nm":"مهره‌ی شمارش ضرب","de":"تیک، با هر ضرب یک مهره را با نوک انگشت هل می‌دهی و می‌شماری. لمس‌پذیر، مثل روش‌های قدیمی شمارش. ضرب، ستون فقرات موسیقی، فقط وقتی با چیزی لمس‌شدنی مثل این آموخته شود، محکم در بدن جا می‌گیرد."},"ICON-0432":{"nm":"بند بررسی گرم‌کردن بدن","de":"بندی که نشان می‌دهد آیا بدن کاملاً گرم شده یا نه. پیش از تمرین جدی همیشه یک آماده‌سازی آرام می‌آید. به‌جای پشیمانی بعد از آسیب دیدن، بستن یک بند و بیدار کردن آرام بدن، در نهایت رقصیدن طولانی‌تری را ممکن می‌کند."},"ICON-0433":{"nm":"گیره‌ی شماره‌ی لباس صحنه","de":"گیره‌ای که شماره‌ای به هر لباس می‌گزد تا چند دست لباس با هم قاطی نشوند. در تعویض نفس‌گیر لباس، اگر حتی یک دست هم اشتباه شود فاجعه است، پس نوبت هر لباس واضح نوشته شده. حتی شلوغی هم وقتی نظم پشتیبانش باشد ظریف می‌شود."},"ICON-0434":{"nm":"بالشتک سنجاق اتاق خیاطی","de":"بالشتک سنجاقی که در گوشه‌ی اتاق خیاطی جا خوش کرده. دستی که بی‌صدا درزهای پاره و دکمه‌های افتاده را ترمیم کرده، همین‌جا مانده. پشت هیبت بی‌نقص لباس روی صحنه، دقتِ کوک‌هایی پنهان است که هرگز صحنه را ندیده‌اند."},"ICON-0435":{"nm":"حلقه‌ی تکه‌پارچه","de":"حلقه‌ای که تکه‌های اضافی پارچه را به هم می‌رشته. همان پارچه از پیش کنار گذاشته می‌شود برای وقتی که لباس اصلی آسیب ببیند. این آماده‌سازی کوچک که با امید به اتفاق‌نیفتادن چیزی نگه داشته شده، درست در لحظه‌ای که مصیبتی بزرگ می‌رسد، لباس صحنه را نجات می‌دهد."},"ICON-0436":{"nm":"پک دکمه‌ی فوری","de":"بسته‌ای دکمه که در لحظه‌ی اضطرار می‌شود سریع دوخت. درست پیش از اجرا، اگر یک دکمه بیفتد، تمام اتاق آرایش یک‌باره به هم می‌ریزد. جعبه‌ی کمک‌های اولیه‌ای کوچک اما بی‌نهایت مطمئن، که این هراس کوتاه و گیج‌کننده را در یک لحظه فرومی‌نشاند."},"ICON-0437":{"nm":"نگه‌دارنده‌ی کمربند صحنه","de":"نگه‌دارنده‌ای که کمربند لباس صحنه را محکم می‌گیرد. تا با پریدن و چرخیدن شدید هم لباس درهم نریزد. آزادی‌ای که با خیال راحت روی صحنه از آن بهره می‌بری، در نهایت از جایی نامرئی که محکم بسته شده می‌آید."},"ICON-0438":{"nm":"پرقو گردگیر","de":"چون زیر نور، حتی یک پرز کوچک هم توی چشم می‌زند، با پرقو آرام روی لباس را جارو می‌کنی. درست پیش از قدم گذاشتن روی صحنه، آن نوازش مهربانی که آخرین‌بار لباس را صاف می‌کند، همیشه سهم همین پر نرم است."},"ICON-0439":{"nm":"برچسب دمپایی اتاق انتظار","de":"برچسب اسمی که روی هر دمپایی اتاق انتظار چسبیده. در همان یک برچسب کوچکِ نوشته‌شده که مال کیست، آرامشِ این‌که ما یک تیم هستیم بی‌صدا نهفته است. آن اتاقی که کفش‌هایت را درمی‌آوری و پاهایت را دراز می‌کنی، راحت‌ترین خانه پشت صحنه می‌شود."},"ICON-0440":{"nm":"تخته‌گیره‌ی استایلینگ","de":"تخته‌گیره‌ای که هنگام درست کردن مو، دسته‌ها را نگه می‌دارد. در فاصله‌ی صاف‌کردن تار به تار مو، انگشت‌ها موهایی را که می‌خواهند پراکنده شوند لحظه‌ای به این گیره می‌سپارند. نظم و آراستگی در نهایت از همین توقف‌های کوچک ساخته می‌شود."},"ICON-0441":{"nm":"کپسول مرتب‌ساز سنجاق قفلی","de":"سپیده‌دمی که درزی پاره شد، درِ کپسول را که باز می‌کنی، نقره‌ای کوچک و سرد مرتب دراز کشیده است. دستی که از جایی نامرئی، از داخل، محکم‌تر از همه لباس را نگه می‌دارد؛ سنجاق قفلی همیشه بی‌صدا پشت صحنه کار می‌کند."},"ICON-0442":{"nm":"دستمال تمیزکننده‌ی لنز","de":"هوف، یک‌بار نفس می‌زنی و به‌شکل دایره پاک می‌کنی، و دنیای مه‌گرفته شفاف می‌شود. آن لحظه‌ی کوتاه آن‌قدر خوب است که باز هم لنز را پاک می‌کنی. تکه‌ای کوچک از آفتاب بهاری که دید کسی دیگر را به‌جای او روشن می‌کند."},"ICON-0443":{"nm":"پایه‌ی لاستیکی سه‌پایه","de":"وقتی لاستیک را روی سه نوک پایه جا می‌زنی، دیگر کفِ چوبی جیغ نمی‌کشد. تا این نقطه‌های کوچک لرزش را می‌بلعند، منظره‌ی داخل تصویر انگار به دروغ آرام می‌شود. ثبات همیشه بی‌صدا از زیر پا آغاز می‌شود."},"ICON-0444":{"nm":"روکش باران دوربین","de":"حتی وقتی قطره‌های باران می‌چکند، لنز خشک می‌ماند و دنیا را در خود ثبت می‌کند. در بعدازظهر ابری فیلم‌برداری بیرون، بارانی‌ای شفاف آرام روی دوربین کشیده می‌شود. چون آنچه عزیز است باید پیش از خیس‌شدن، اول پیچیده شود."},"ICON-0445":{"nm":"نوار نشانه‌گذاری فیلم‌برداری","de":"اینجا بایست، آن‌طرف برگرد؛ ردهای کوتاه رنگارنگ بی‌هیچ کلامی راه را دقیق نشان می‌دهند. حتی وقتی بعد از پایان صحنه بی‌هیچ دلتنگی کنده می‌شوند، نوک پاهایی که به آن‌ها عادت کرده‌اند مدت‌ها آن نقطه را به یاد می‌آورند."},"ICON-0446":{"nm":"گیره‌ی جداکننده‌ی کات","de":"گیره‌ی کوچکی که کاغذهای در حال پراکنده‌شدن را یک‌جا می‌گزد. با یک صدای شاداب کلیک، دیروز و امروز مرتب به هم بسته می‌شوند. مرتب‌سازی، عادتی مهربان است برای نگه‌داشتن آرام چیزی که نزدیک بود گم شود."},"ICON-0447":{"nm":"تخته‌ی وایت بالانس","de":"تخته‌ای سفید را که جلوی صحنه بگیری، رنگ‌ها آرام‌آرام جای خودشان را پیدا می‌کنند. غروب زرد، سپیده‌دم آبی، بی‌هیچ دروغی. یک تخته که رنگ سفید واقعی را می‌شناسد، بقیه‌ی رنگ‌ها را وامی‌دارد صادقانه سخن بگویند."},"ICON-0448":{"nm":"قوطی نگه‌داری خاطره","de":"داخل یک قوطی حلبی کوچک، تراشه‌های خاطره آرام خوابیده‌اند. درِ آن را که باز کنی، کلیک، صحنه‌های فصل گذشته به کف دستت می‌ریزند. خاطره این‌گونه در یک قوطی محکم، با محبت نگه داشته می‌شود و می‌ماند."},"ICON-0449":{"nm":"کلاهک سایبان مانیتور","de":"سایبانی سیاه را که دور مانیتور بپیچی، بازتاب نور یک‌باره متوقف می‌شود. حتی کنار پنجره‌ای که آفتاب در آن سرریز می‌شود، صفحه رنگ خودش را از دست نمی‌دهد. برای دیدن خوب، اول باید نور اضافی را پوشاند، سایبان بی‌صدا این را می‌گوید."},"ICON-0450":{"nm":"سنجاق عایق صدای لوکیشن","de":"سنجاق کوچکی که در شکاف در جا زده شده، آرام صدای بیرون را قطع می‌کند. صدای قدم‌ها در راهرو، خنده‌ی اتاق کناری، هیچ‌کدام تا این‌جا نمی‌رسند. چون برای ثبت صدایی پاک، اول باید سکوت را ساخت."},"ICON-0451":{"nm":"پک اسفنج آرایش","de":"دسته‌ای اسفنج نرم و لطیف که مرتب روی هم خوابیده‌اند. اگر با نوک انگشت کمی پودر بزنی، صورت یک درجه روشن‌تر می‌شود. پشت هر لبخند درخشان روی صحنه، همین نوازش‌های نرم پنهان است."},"ICON-0452":{"nm":"جعبه‌ی سنجاق مو","de":"خانه‌ای مرتب برای سنجاق‌های ریزی که به‌راحتی گم می‌شوند. درش را که باز کنی، ردیفی از نقره‌ای‌ها صف‌کشیده به استقبالت می‌آیند. پراکنده که باشند دیده نمی‌شوند اما جمع که شوند دلگرمی‌اند؛ حتی کوچک‌ترین چیزها هم به خانه‌ای برای خود نیاز دارند."},"ICON-0453":{"nm":"جعبه‌ی ضدعفونی‌کننده‌ی برس","de":"برس‌هایی که تمام روز رنگ در خود نگه داشته‌اند، داخل جعبه دوش نور فرابنفش می‌گیرند. تا این نور نامرئی کهنگی را می‌شوید، نوک برس فردا دوباره مثل روز اول نرم و پرپشت می‌شود. پاکیزگی هم لایه‌ای از دلسوزی است."},"ICON-0454":{"nm":"توری پاف پودر","de":"پاف‌های گرد و کوچک در توری آرام نفس تازه می‌کنند. با عبور هوا از شکاف توری، نرمی‌شان بیشتر دوام می‌آورد. یک دانه پاف خوب‌خشک‌شده، از پیش درخشش صبح فردا را در خود دارد."},"ICON-0455":{"nm":"کلاهک اسپری نگه‌دارنده‌ی مو","de":"چیک، یک اسپری و دیگر حتی باد هم تاری از مو را تکان نمی‌دهد. کلاهک کوچکی برای نگه‌داشتن مدلی که با دقت درست شده، در تمام شب. نور روشن روی موهایی که محکم ثابت شده، انگار می‌شکند و فرومی‌ریزد."},"ICON-0456":{"nm":"روکش برس رژ لب","de":"کلاهک کوچکی که نوک باریک برس را آرام در خود می‌پیچد. حتی اگر داخل کیف این‌سو و آن‌سو تکان بخورد، برس صاف و تمیز می‌ماند. مراقبت از یک برس کوچک، یک ضربه‌قلم رنگ روی لب را کامل می‌کند."},"ICON-0457":{"nm":"آینه‌ی شماره‌ی نوبت","de":"آینه‌ای کوچک آرام کنار عددی که نوبتت را اعلام می‌کند نشسته. درست پیش از رفتن روی صحنه، جایی برای آخرین‌بار صاف کردن طره‌ی درهم موهاست. حتی دلهره هم اگر یک‌بار در آینه بازتاب شود، کمی سبک‌تر می‌شود."},"ICON-0458":{"nm":"حوله‌ی مچ‌بند","de":"نواری نرم که عرق پیشانی را با یک حرکت مچ پاک می‌کند. هرچه کورئوگرافی شدیدتر شود، دست بیشتر به سراغش می‌رود. دلداری کوچکی روی مچ دست، که در هر لحظه‌ی نفس‌بریده کنارت می‌ماند."},"ICON-0459":{"nm":"برچسب کیف وسایل صحنه","de":"حتی اگر ده کیف کاملاً یکسان در اتاق آرایش ردیف بایستند، هیچ اشتباهی پیش نمی‌آید. برچسب اسمِ هر کیف واضح می‌گوید مال کیست. نوشتن «مال من» روی چیزی، نشانه‌ای کوچک اما مهربان است."},"ICON-0460":{"nm":"سنجاق رزرو اتاق تمرین","de":"امروز چه کسی این اتاق تمرین را استفاده می‌کند؟ سنجاق کوچکی که روی تابلوی جلوی در فرو رفته، بی‌صدا زمان را تقسیم می‌کند. دل‌هایی که منتظر نوبت بعدی‌اند، آرام پشت همین یک سنجاق صف می‌بندند."},"ICON-0461":{"nm":"حلقه‌ی روکش ساعت دیواری","de":"روکشی شفاف آرام روی ساعت دیواری می‌نشیند تا گرد و غبار را دور نگه دارد. عقربه‌های تیک‌تاک هرگز محو نمی‌شوند و زمان شفاف جریان می‌یابد. چیزهای عزیز همیشه به لایه‌ای نامرئی از محافظت نیاز دارند."},"ICON-0462":{"nm":"پد محافظ کف","de":"پد نازکی که زیر پایه‌ی صندلی چسبیده، از پیش زخم روی کف چوبی را می‌گیرد. بکشی هم خط نمی‌افتد، جابه‌جا کنی هم اثری نمی‌ماند. مراقبت نامرئی از کف زمین، همان راز دوام طولانی آن است."},"ICON-0463":{"nm":"چیپ نشانه‌ی ممنوعیت نوشیدنی","de":"چیپ کوچک با مهربانی می‌خواهد که فعلاً نوشیدنی‌ها را این‌طرف‌تر بگذاریم. چون نُت‌ها و تجهیزات اگر خیس شوند دردسر می‌شوند. حتی کلمه‌ای مثل «ممنوع» وقتی این‌گونه گفته شود، ملاحظه‌ای گرم می‌شود."},"ICON-0464":{"nm":"برچسب دکمه‌ی تهویه","de":"وقتی می‌خواهی هوای خفه را عوض کنی، اینجا را فشار بده، برچسب کوچک کنار دکمه راه را نشان می‌دهد. باز شدن نفس، به‌طرز عجیبی، آرام از همین نشانه‌ی کوچک آغاز می‌شود."},"ICON-0465":{"nm":"پایه‌ی لاستیکی بلندگو","de":"پایه‌ی لاستیکی زیر بلندگو آرام لرزش کدر را می‌بلعد. چون باس دیگر روی کف پخش نمی‌شود، صدا بسیار شفاف‌تر طنین‌انداز می‌شود. طنین خوب فقط روی پایه‌ای محکم است که سرانجام پاک می‌شود."},"ICON-0466":{"nm":"آهن‌ربای شماره‌ی کمد","de":"آهن‌ربای شماره‌ی کوچکی که به در کمد می‌چسبد. وسایل امروزم در کدام خانه می‌خوابند؟ حتی اگر جا هر روز عوض شود، یک آهن‌ربا کافی است تا فوراً کمدی از آنِ من داشته باشم. تعلق از همین نشانه‌ی سبک می‌آید."},"ICON-0467":{"nm":"تی‌شیشه‌ی آینه","de":"یک حرکت روی آینه، و بخار به‌طور کامل پاک می‌شود. لحظه‌ای که چهره‌ی محوی من دوباره واضح می‌شود. برای دیدن درست خودم، اول باید آرام آنچه دید را کدر کرده پاک کنم."},"ICON-0468":{"nm":"پد ضربه‌گیر درِ ورودی","de":"ضربه‌گیر نرمی که در شکاف دری که محکم بسته می‌شود جا داده شده. هم صدای بلند و هم گیر کردن دست را نرم می‌گیرد. حفاظت کوچکی که میان برخوردهای خشن، لایه‌ای از مهربانی جا می‌دهد."},"ICON-0469":{"nm":"بلوک روکش کابل","de":"روکشی محکم روی کابل‌هایی که کف زمین را قطع می‌کنند، پلی استوار می‌سازد. نه پایی گیر می‌کند و نه سیمی زیر پا لگد می‌شود. آرامش بی‌صدای یک بلوک که راه را می‌بندد بدون این‌که راه را ببندد."},"ICON-0470":{"nm":"مخروط هشدار کف لغزنده","de":"مخروطی زرد تنها روی کف خیس ایستاده و بی‌صدا هشدار می‌دهد. با احتیاط، آرام قدم بگذار. پشت صحنه‌ای روشن، این نگهبان کوچک بی‌صدا از هر قدم مراقبت می‌کند."},"ICON-0471":{"nm":"چوب نور اضطراری","de":"پرتوی نوری که در راهروی بی‌برق روشن می‌شود. تا حتی در تاریکی هم راه را گم نکنی، این نور اضطراری در دستت گذاشته می‌شود. قطعاً چیزهایی در دنیا هست که در تاریک‌ترین لحظه روشن‌ترین می‌شوند."},"ICON-0472":{"nm":"کلاهک محافظ نرده","de":"کلاهک گردی که روی نوک نرده‌ی پله کشیده شده، لبه‌ی تیز را نرم می‌پوشاند. حتی برخورد بی‌احتیاط دست هم آسیبی نمی‌رساند. پوشاندن آرام تیزی، خودش هم نوعی ملاحظه برای کسی دیگر است."},"ICON-0473":{"nm":"بالشتک لبه‌ی صحنه","de":"بالشتکی نرم دور لبه‌ی صحنه پیچیده شده. تا حتی نوک پایی که در کورئوگرافی شدید به آن می‌خورد کبود نشود. پشت هر حرکت درخشان، محافظتی نامرئی همراهش می‌رقصد."},"ICON-0474":{"nm":"صفحه‌ی نشانه‌ی کف","de":"صفحه‌ای گرد روی زمین بی‌صدا می‌گوید «اینجا بایست». چه کسی که در صف است چه کسی که دنبال جایش می‌گردد، همه در همین یک نقطه آرام می‌ایستند. نظم از نشانه‌ای کوچک می‌روید."},"ICON-0475":{"nm":"بند چراغ‌قوه","de":"بندی که به انتهای چراغ‌قوه آویزان است را یک‌دور دور مچ بپیچی، حتی در تاریکی هم نور را از دست نمی‌دهی. بی‌نگرانی از افتادن، هر دو دست آزاد می‌شوند؛ حلقه‌ای کوچک اما مطمئن."},"ICON-0476":{"nm":"طناب کنترل مسیر","de":"لطفاً از اینجا جلوتر نیایید، طنابی به آرامی خط می‌کشد. مرزی مهربان که بی‌صدا جای خطرناک را از جای امن جدا می‌کند. بازداشتن هم راهی است برای محافظت از کسی."},"ICON-0477":{"nm":"سنجاق تأیید ایمنی","de":"در هر جایی که بازرسی تمام شده، سنجاق کوچکی «تأیید شده» را جا می‌گذارد. نقطه‌ای مثل مهرِ ذهنی که همه‌جا را بدون جا انداختن نگاه کرده. ایمنی چیز پرطمطراقی نیست؛ مجموع همین نشانه‌هایی است که یکی‌یکی زده شده."},"ICON-0478":{"nm":"کلاپ‌برد کوچک","de":"با صدای شاداب «تاق»ی که اولین ضرب را می‌برد، نفس همه‌ی حاضران در محل یک‌باره هماهنگ می‌شود. هرچند کوچک است، خط شروع هر صحنه همیشه همین یک ضرب است. آغاز هیجان‌انگیز فیلم‌برداری همین‌جا باز می‌شود."},"ICON-0479":{"nm":"روکش میکروفون رومیزی","de":"روکشی نرم آرام روی میکروفون روی میز کشیده می‌شود. حتی نفس تندی که ناگهان می‌ترکد، بدون نویز و صاف منتقل می‌شود. گرم‌ترین چیزی که صدا را در خود می‌پیچد، همین یک لایه‌ی کوچک و نرم است."},"ICON-0480":{"nm":"تکه‌ی پنل جذب صدا","de":"تکه‌ای پنل جذب صدا که در دیوار نشسته، بی‌صدا پژواک را جمع می‌کند. چون صدا دیگر برخورد و پراکنده نمی‌شود، آواز بسیار شفاف‌تر می‌ماند. طنین خوب از پرداختن دقیق به سکوت آغاز می‌شود."},"ICON-0481":{"nm":"کلاهک قلاب هدفون","de":"آویزان کردن هدفون اینجا، وعده‌ای کوچک است. سیم را باز و مرتب می‌کنی تا نفر بعدی بی‌درنگ بردارد و برود. یک قلاب، نظمی آرام به این باجه‌ی پرمشغله می‌آورد."},"ICON-0482":{"nm":"چراغ در حال ضبط","de":"لحظه‌ای که چراغ قرمز روشن می‌شود، هر نفسی داخل باجه می‌ایستد. علامتی که حتی صدای قدم بیرون از در را هم متوقف می‌کند. ثبت صدا از پاسداری این سکوت عمیق آغاز می‌شود."},"ICON-0483":{"nm":"جعبه‌ی مرتب‌ساز پیک","de":"پیک‌هایی که بر اساس رنگ در خانه‌های جداگانه چیده شده‌اند. ضخامت و وزن، عادت نوک انگشت را می‌سازد. درست پیش از صحنه، آن دقتی که بی‌نگاه‌کردن یک‌باره پیک درست را برمی‌دارد، از همین‌جا می‌روید."},"ICON-0484":{"nm":"برچسب‌زن کابل","de":"برای این‌که حتی روی کفی با ده‌ها رشته درهم گم نشوی، باید روی دو سرش اسمی نوشت. فقط کسی که از کجا آمده و به کجا می‌رود را نوشته، در تاریکی هم دستش کورمال نمی‌شود."},"ICON-0485":{"nm":"دکمه‌ی میکسر کوچک","de":"به اندازه‌ی یک بند انگشت که بچرخانی‌اش، بافت صدا عوض می‌شود. اگر بالا ببری خشن می‌شود و اگر پایین بیاوری گم می‌شود، و جستجوی همان یک نقطه‌ی میانی است. ظریف‌ترین لمس، بزرگ‌ترین تغییر را می‌سازد."},"ICON-0486":{"nm":"واشر قفل‌کننده‌ی استند","de":"آنچه صحنه را نگه می‌دارد، نور خیره‌کننده نیست بلکه همین حلقه‌ی کوچک است. لرزش را محکم بسته نگه می‌دارد، بی‌آنکه چشم کسی ببیندش، بی‌صدا سر پستش می‌ایستد."},"ICON-0487":{"nm":"برچسب جمع‌آوری صحنه","de":"حتی خواباندن دوباره‌ی هر چیزی که ساخته شده، ترتیبی روشن دارد. یک برگه که می‌گوید کجا باز کنی و کجا ببری. دستی که جمع می‌کند، به اندازه‌ی دستی که می‌سازد استوار است."},"ICON-0488":{"nm":"چیپ پاکت اشیای گمشده","de":"هر چیزی که کسی جا گذاشته و رفته، داستان خودش را با خود دارد. گذاشتنش در پاکتی کوچک و انتظار برای نام صاحبش، مهربانی‌ای است که لحظه‌ای حتی دل آدم گم‌کرده را هم نگه می‌دارد."},"ICON-0489":{"nm":"نشانه‌ی مسیر نظافت","de":"اگر پیکان‌های کشیده‌شده روی کف را دنبال کنی، بی‌هیچ جای خالی تمیز می‌شود. حتی جارو هم به مسیر نیاز دارد تا بیهوده نچرخد. درخشان‌ترین جا، در انتهای بهترین ردِ قدم‌های ترسیم‌شده است."},"ICON-0490":{"nm":"چوب راهنمای خروج","de":"وقتی آخرین کف‌زدن‌ها فرو می‌نشیند، این چوب راه را باز می‌کند. دستی که دل‌های هنوز پرشوق را آرام و بی‌آسیب بیرون می‌فرستد. حتی راهنمایی برای پایان‌دادن هم مراقبتی گرم دارد."},"ICON-0491":{"nm":"توپ نوار باقی‌مانده","de":"اگر پس‌مانده‌ی استفاده‌شده را گرد بپیچی، باز کاربردی پیدا می‌کند. همان‌طور که ته‌مانده‌ای که نزدیک بود دور ریخته شود، به توپی محکم بدل می‌شود، دل صرفه‌جو از نوک انگشتانی کوچک می‌روید."},"ICON-0492":{"nm":"کلاهک شماره‌ی صندلی","de":"هر صندلی در سالن باید شماره‌ای داشته باشد تا کسی سرگردان نماند. یک کلاهک کوچک که جایی را تعیین می‌کند، دلهره‌ی تازه‌وارد را به آرامشی راحت تبدیل می‌کند."},"ICON-0493":{"nm":"سنجاق تفکیک زباله","de":"سنجاقی کوچک برای جدا کردن کاغذ از پلاستیک. مخلوط که باشند فقط زباله‌اند، اما جدا که شوند دوباره به منبعی قابل استفاده بدل می‌شوند. تفکیک، کاری مهربانانه است که زندگی دومی به اشیا برمی‌گرداند."},"ICON-0494":{"nm":"برچسب بازگرداندن تجهیزات","de":"آنچه امانت گرفته شده باید حتماً به جایش برگردد. با هر نوک انگشتی که برچسب‌زده برش می‌گرداند، اعتماد لایه‌به‌لایه انباشته می‌شود. کسی که خوب پس می‌دهد، دفعه‌ی بعد هم با خیال راحت امانت می‌گیرد."},"ICON-0495":{"nm":"کلید تسویه‌ی اتاق انتظار","de":"تمام آرایش و لباس امروز را درمی‌آوری و در آخر، این کلید را برمی‌گردانی. آنچه هنگام ورود گرفته‌ای را هنگام خروج سر جایش می‌گذاری. آغاز و پایان یک روز در یک دست جای می‌گیرد."},"ICON-0496":{"nm":"جعبه‌ی پاف کوشن","de":"پاف نرم اگر فشرده شود، بافتش را از دست می‌دهد. دلیل این‌که در خانه‌ای گرد با محبت خوابانده می‌شود همین است. برای نگه‌داشتن طولانیِ نرمی، اول باید با نرمی رفتار کرد."},"ICON-0497":{"nm":"چیپ سایه‌چشم","de":"یک نقطه رنگ که روی پلک گذاشته می‌شود، کل حالت چهره را عوض می‌کند. رنگی که در چیپ کوچک خوابیده، فقط زیر نور بیدار می‌شود و به نگاهی رو به صحنه عمق می‌بخشد."},"ICON-0498":{"nm":"کلاهک برس رژگونه","de":"اگر نوک برس خراب شود، درخشش رنگ هم فرومی‌ریزد. کلاهک‌گذاری برای نگه‌داشتن آن بافت، عادتی آرام از کسی است که می‌خواهد ابزار خوبش را مدتی طولانی کنارش نگه دارد."},"ICON-0499":{"nm":"پالت رژ لب باریک","de":"پالت ضخیم تمام جای کیف را می‌گیرد. دستی که می‌داند یک ردیف باریک کافی است. لحظه‌ای که کم کردن، خودش به معنای خوب همراه‌بردن بدل می‌شود."},"ICON-0500":{"nm":"گارد ماسکارا","de":"تا مژه‌هایی که تار به تار بالا زده شده‌اند پخش نشوند، گاردی کوچک آرام از خمیدگی‌شان محافظت می‌کند. آنچه با دقت بالا رفته باید با دقت نگه داشته شود، زمان جلوی آینه این را یادآوری می‌کند."},"ICON-0501":{"nm":"جعبه گوش‌پاک‌کن","de":"خانه‌ی کوچکی که نمی‌گذارد گوش‌پاک‌کن‌های سفید به هر سو پراکنده شوند. دستی که همیشه برای آخرین رتوش نزدیک نگه داشته می‌شود. آماده‌سازی‌های ریز، خلأهای صحنه‌ای بزرگ را پر می‌کنند."},"ICON-0502":{"nm":"پد لاستیکی مژه‌گیر","de":"وقتی لاستیک سفت می‌شود، فر دادن مژه‌ها نیشگون می‌زند و می‌سوزاند. نگه داشتن پدهای یدکی از آن مهربانی‌ای می‌آید که حتی دردهای کوچک را هم به حساب می‌آورد."},"ICON-0503":{"nm":"قلم‌موی کنسیلر","de":"نوک باریک موها به‌آرامی سایه‌ها را پاک می‌کند. کاری که روشنایی را به جایی می‌برد که نور هرگز به آن نرسیده بود. دستی که به‌جای پوشاندن عیب، نور می‌افزاید، کار را با ظرافتی بیشتر به پایان می‌رساند."},"ICON-0504":{"nm":"الک پودر","de":"پودر نرم را یک‌بار که الک کنی، بی هیچ کلوخه‌ای صاف می‌نشیند. زحمتِ یک‌بار دیگر از صافی گذراندنش. در نهایت، اخلاص همان چیزی است که در نوک انگشتی پیداست که یک قدم بیشتر برمی‌دارد."},"ICON-0505":{"nm":"گیره‌ی فر چتری","de":"گیره‌ای که چتری را گرد پیچیده و لحظه‌ای نگه می‌دارد. در حین انتظار، شکل به‌آرامی جا می‌افتد. آراستگی از جایی می‌شکفد که بلد باشی بی‌عجله منتظر بمانی."},"ICON-0506":{"nm":"قاشقک واکس مو","de":"پیش از آنکه واکس به دست بخورد، با این قاشقک کوچک برداشته می‌شود. خویشتن‌داریِ برداشتن دقیقاً به‌اندازه‌ی نیاز. دستی که بلد است بی‌زیاده‌روی مصرف کند، طبیعی‌ترین بافت را می‌سازد."},"ICON-0507":{"nm":"پایه‌ی اتوی مو","de":"نمی‌شود اتوی داغ‌شده را هرجا دلت خواست گذاشت. یک زیرانداز، هم میز را حفظ می‌کند هم دست را. جایی که با گرما سروکار دارد، همیشه به پناهگاهی امن نیاز دارد."},"ICON-0508":{"nm":"نمونه‌ی روغن مو","de":"یک قطره برای درخشش کافی است، پس در بطری نمونه‌ی کوچکی زیبا جای می‌گیرد و گوشه‌ی کیف پنهان می‌شود. یک بطری کوچک، برخلاف بطری بزرگ، بیشتر به دست می‌رسد."},"ICON-0509":{"nm":"شانه‌ی تمیزکننده‌ی برس","de":"موهای گره‌خورده در تارهای برس را با این شانه به‌آرامی شانه می‌زند و پایین می‌کشد. مراقبت از ابزار، آیینی آرام است پس از پایان کار. برسی که خوب مراقبتش کرده‌ای، بافتِ فردا را زیبا شکل می‌دهد."},"ICON-0510":{"nm":"قرقره‌ی کش مو","de":"فقط دور یک قرقره پیچیده شوند، همه با یک نگاه دیده می‌شوند. این بسته‌ی کوچکِ منظم، آسایشی مهربانانه است که به صبح‌های شلوغی هدیه می‌شود که کش‌های مو به هر سو می‌غلتیدند."},"ICON-0511":{"nm":"دستکش رنگ مو","de":"دستکش نازکی که پوشیده می‌شود تا دستی که رنگ می‌زند، رنگی نشود. آرزوی اینکه حتی پس از پایان کار، با دستانی پاک به سراغ کار بعدی بروی. محافظت، خود نام دیگری‌ست برای همین آماده‌بودن."},"ICON-0512":{"nm":"کیسه‌ی تور مو","de":"کیسه‌ی کوچکی برای تا کردن و نگه‌داشتن مرتبِ توری که فرم مو را حفظ می‌کند. هرچه چیزی بی‌حجم‌تر باشد، گم‌شدنش آسان‌تر است، پس دستی دلسوز که برایش خانه‌ای تعیین می‌کند، ارزشمند است."},"ICON-0513":{"nm":"قلم فیکسر موهای سرکش","de":"قلمی که با ضربه‌ای آرام، موهای سرکش بیرون‌زده را سر جایشان می‌نشاند. آخرین لمس پس از پایان همه‌ی حالت‌دهی‌های بزرگ. اتمام کار همیشه نوازش کوچک‌ترین نقطه است."},"ICON-0514":{"nm":"درپوش تست عطر","de":"هنگام انتخاب عطر، آن را مستقیم به نوک بینی نمی‌برند. باید روی درپوش کوچکی زد و در هوا پخشش کرد تا بافت واقعی‌اش آشکار شود. عطر هم فقط وقتی از فاصله‌ای بو کشیده شود، صادق می‌شود."},"ICON-0515":{"nm":"بطری عطر رول‌آن","de":"مهره‌ای گرد می‌غلتد و عطر را روی مچ دست نقش می‌زند. برخلاف بطری‌های قدیمیِ ضربه‌ای، خطی یکپارچه لغزیده و پخش می‌شود. عطر، با هر شیوه‌ی لمسی، داستانی متفاوت به‌جا می‌گذارد."},"ICON-0516":{"nm":"درپوش میست بدن","de":"درپوش کوچکی که عطری را که چون مه پخش می‌شود، در خود نگه می‌دارد. بستن و نگه‌داشتن چیزی که تنها با بازشدن پراکنده می‌شود. کمی دریغ‌کردن، آن عطر را مدتی طولانی‌تر کنار تو نگه می‌دارد."},"ICON-0517":{"nm":"جاسوئیچی کرم دست","de":"به کرم کوچکی که به دست می‌مالی حلقه‌ای وصل کن تا همه‌جا همراهت باشد. همراهی که بیرون از کیف آویزان و تاب می‌خورد، به احوال‌پرسیِ مهربانانه‌ای برای نوک انگشتان خشک تبدیل می‌شود."},"ICON-0518":{"nm":"قلاب لیف حمام","de":"پس از درست‌کردن کف حباب‌دار، باید خوب خشک شود. توپ توری‌ای که به قلابی گوشه‌ی حمام آویزان است، قطره‌قطره آبش را می‌تکاند و منتظر صبحی تازه می‌ماند."},"ICON-0519":{"nm":"کیسه‌ی توپ ماساژ","de":"کیسه‌ای کوچک برای نگه‌داشتن توپ سفتی که شانه‌های گرفته را باز می‌کند. استراحتی کوتاه پشت صحنه، زمانی برای نوازش آرام بدنی خسته. مراقبت همیشه از خود آغاز می‌شود."},"ICON-0520":{"nm":"قوطی پچ خنک‌کننده","de":"قوطی‌ای که پچ‌هایی را گرد هم آورده که با چسباندن، خنکی می‌بخشند. در شبی که صحنه‌ای پرحرارت به پایان رسیده، تسلای کوچکی در آن خفته که آرام‌آرام بدن و دلِ داغ‌شده را فرو می‌نشاند."},"ICON-0521":{"nm":"قلم روغن ناخن","de":"فشار بده، بمال، برق بزن. برای نوک انگشتان خشک، یک قطره کافی‌ست. نیازی به هیچ نسخه‌ی پرزرق‌وبرقی نیست؛ درخششی ملایم که از نوک قلمی کوچک پخش می‌شود، به‌زیبایی روی ناخن‌ها می‌پیچد. مراقبت، از همین یک قطره‌ی کوچک آغاز می‌شود."},"ICON-0522":{"nm":"گیره‌ی ساشه‌ی عطر","de":"گره‌ی کوچکی که عطر را به کاغذ می‌بندد. هر بار که کشو را باز می‌کنی، مشتی عطر ملایم پیش از دستت به استقبالت می‌آید. مهربانی‌ای که هرچند دیده نمی‌شود، کنارت می‌ماند؛ یک گیره، به‌آرامی تسلای یک روز را در خود دارد."},"ICON-0523":{"nm":"سینی نوک ناخن","de":"صحنه‌ای کوچک برای پهن‌کردن پیشاپیش رنگ‌های ده انگشت. کدام رنگ با امروز جور است؟ روی سینی، اودیشنی آرام برپاست. همان لحظه‌ی کوتاه انتخاب، به‌نوعی هیجان‌انگیز است، و روز نوک انگشتان از همین‌جا آغاز می‌شود."},"ICON-0524":{"nm":"درپوش هل‌دهنده‌ی کوتیکول","de":"حتی در پس‌راندن هم مهربانی هست. یک پوست اضافه، با نوک گردی به‌آرامی، بی‌هیچ شتابی. دستِ شتاب‌زده همیشه چیزی را از دست می‌دهد، پس مرتب‌کردن به دلی نزدیک‌تر است که آهسته می‌نگرد."},"ICON-0525":{"nm":"سوهان و پولیش‌کن مینی","de":"یک روی زبر و یک روی نرم، دو چهره در یک دست. صاف‌کردنِ آرام لبه‌های ناهموار کاری کوچک است، اما تکمیل همیشه از همین لمس‌های کوچک می‌آید. کلام آخر، در پایان، از آنِ نرمی‌ست."},"ICON-0526":{"nm":"ورق استیکر ناخن","de":"ستاره، گل، قلب؛ کافی‌ست یکی را که با حال‌وهوای امروز جور است برداری و بچسبانی. روی ورقی که تصویرهای کوچک به‌اندازه‌ی ناخن ردیف شده‌اند، یک استیکر مانند امضایی مهربانانه بر نوک انگشت می‌درخشد."},"ICON-0527":{"nm":"صفحه‌ی سایه‌بان لامپ ژل","de":"پرده‌ای نازک که نور را لحظه‌ای در خود حبس می‌کند. در حین سفت‌شدن، چشم‌ها استراحت می‌کنند و تنها نوک انگشتان به‌آرامی سخت می‌شوند. حتی انتظار هم به تکه‌ای سایه نیاز دارد؛ در زمانی بی‌عجله، نوک انگشتان امروز به کمال می‌رسند."},"ICON-0528":{"nm":"قوطی قطعات آرت ناخن","de":"تکه‌های برّاق، خانه‌به‌خانه در خواب‌اند. سنگ‌های شیشه‌ای، مرواریدها، غبار ستاره؛ درپوش را با هیجانِ بازکردن صندوق‌جواهری بی‌نام بلند می‌کنی. کدام نور را روی ناخن بگذاری؟ همان لحظه‌ی انتخاب بیش از هر چیز می‌درخشد."},"ICON-0529":{"nm":"دستکش مراقبت از دست","de":"تعطیلاتی کوتاه که دست‌ها هنگام خواب می‌گیرند. درون دستکش، پوست خشک آرام‌آرام در طول شب پرآب می‌شود. مراقبت، در نهایت، چیزی‌ست که در جایی نادیده رخ می‌دهد؛ صبح که شود، نوک انگشتان نخستین کسانی‌اند که آن مهربانی را می‌شناسند."},"ICON-0530":{"nm":"بطری پمپی ریموور","de":"یک فشار، دقیقاً به‌اندازه‌ی نیاز. عطری خنک در پنبه می‌نشیند و دیروز را از روی ناخن‌ها پاک می‌کند. حتی خالی‌کردن هم ریتمی دارد؛ یک پمپ، به‌آرامی جایی برای رنگی تازه باز می‌کند."},"ICON-0531":{"nm":"پنس نگین","de":"برای برداشتن نگینی نازک‌تر از نوک انگشت، دستی نازک‌تر لازم است. نوک پنس بی‌هیچ لرزشی یک نقطه را جابه‌جا می‌کند؛ ظرافت به‌اندازه‌ی دل، سهم ابزار هم هست. نوری کوچک جای خود را می‌یابد."},"ICON-0532":{"nm":"صفحه‌ی نگهداری گوشواره","de":"تا گوشواره‌ی جفت‌گم‌شده دیگر در کشو سرگردان نماند. هر جفت را سرجایش که بگذاری، صبح‌های شلوغ، زمانِ انتخاب سبک‌تر می‌شود. مرتب‌کردن، مهربانی کوچکی‌ست که به خودِ آینده‌ات هدیه می‌دهی."},"ICON-0533":{"nm":"حلقه‌ی سایزسنج انگشتر","de":"دسته‌ای حلقه‌ی کوچک که دور انگشت را به عدد تبدیل می‌کند. امتحان‌کردن هر اندازه، یکی‌یکی، شبیه است به آهسته شناختن چیزی که دقیقاً برازنده‌ی توست. مثل آن آرامشِ لحظه‌ی جفت‌شدنِ کامل."},"ICON-0534":{"nm":"پین بند ساعت","de":"وقتی بند ساعت شل می‌شود، همین سنجاق کوچک، زمان را دوباره به مچ می‌بندد. آنچه عمیق‌ترین جا پنهان است، بیشترین دوام را دارد؛ ساعتی که سال‌ها بسته‌اند، این را بی‌کلام می‌داند."},"ICON-0535":{"nm":"صفحه‌ی ضدگره‌ی گردنبند","de":"خانه‌هایی جداشده تا زنجیرهای نازک به هم گره نخورند. صبحی بی‌گره، از خانه‌های کوچکی آغاز می‌شود که شب پیش از پیش جدا شده بودند. آسودگی، در نهایت، دلی‌ست که پیش از رسیدن دست، مرتب شده است."},"ICON-0536":{"nm":"قفل پشت بروش","de":"هرچه روی کار پرزرق‌وبرق‌تر باشد، پشت آن ساکت‌تر است. قفل کوچکی که بروشِ سنجاق‌شده به لباس را محکم نگه می‌دارد؛ پشتِ هر درخششی، همیشه دستی بی‌نام ایستاده که تاب می‌آورد. جایی که چون دیده نمی‌شود، مطمئن‌تر است."},"ICON-0537":{"nm":"کیف عینک آفتابی","de":"پارچه‌ای نرم، لنزهایی را که نور تابستان را مسدود کرده‌اند، در آغوش می‌گیرد. کیسه‌ی کوچکی که دیدِ یک جفت عینک را از تلاطم درون کیف حفظ می‌کند. دلی که چیزی را ارزشمند می‌شمارد، همیشه چنین لایه‌ای نرم می‌آورد."},"ICON-0538":{"nm":"منگنه‌ی سوراخ کمربند","de":"چه کمری یک شماره باریک‌تر شود، چه فصلی یک شماره فراخ‌تر. تنها یک سوراخ دیگر که سوراخ شود، کمربند دوباره به تن می‌آید. این همیشه من‌ام که تغییر می‌کنم، و این ابزار کوچک است که بی‌کلام خود را با من هماهنگ می‌کند."},"ICON-0539":{"nm":"گیره‌حلقه‌ی روسری","de":"گیره‌ای که روسریِ درحال لغزیدن را در یک نقطه جمع و نگه می‌دارد. ظرافتی که در باد باز می‌شد، سرانجام جای خود را می‌یابد. حتی ظرافت هم گاهی به این گیره‌ی کوچک تکیه می‌کند و روزی را که نزدیک بود بهم بریزد، مرتب می‌کند."},"ICON-0540":{"nm":"ست حلقه‌ی چارم","de":"حلقه‌های کوچکی که برای آویزان‌کردن به کنار کیف، دسته‌ای رسیدند. دلِ نگه‌داشتنِ چیزهای دوست‌داشتنی در کنار خود؛ آویزان‌کردن حال‌وهوای روز به یک چارم، آیینی کوچک است که تنها خودت می‌دانی، و به‌نوعی لذت‌بخش است."},"ICON-0541":{"nm":"قوطی پرزگیر","de":"وقتی ژاکتی گویی یک‌شبه پیر شده و پرز زده، این قوطی را به‌آرامی رویش بغلتان تا دوباره چهره‌ای تازه بگیرد. صدای نرم وزوزی که کهنگی را می‌زداید، به‌نوعی دلگرم‌کننده است. لباس دوست‌داشتنی این‌گونه بار دیگر زنده می‌شود."},"ICON-0542":{"nm":"کارت عطر لباس","de":"عمیق در کمد که جا بگیرد، روزها را به‌آرامی از عطر پر می‌کند. نامه‌ای نوشته‌شده با عطر به‌جای واژه؛ ورقی که بی‌بازشدن هم خوانده می‌شود. هر صبح که لباسی بیرون می‌آوری، مهربانیِ دیروزنوشته پیش از هر چیز پخش می‌شود."},"ICON-0543":{"nm":"سنجاق ضداستاتیک","de":"در صبح زمستانی که دامن به پا می‌چسبد، یک سنجاق آن چسبندگی را آرام باز می‌کند. آرامشی کوچک که حتی اصطکاک نادیده را هم می‌نوازد؛ وقتی یک آزار کوچک ناپدید شود، روز بسی روان‌تر می‌گذرد."},"ICON-0544":{"nm":"برس جیبی لباس","de":"درست پیش از بیرون‌رفتن، ردی از گرد که آرام روی شانه نشسته. برسِ تاشده را باز کن، یک ضربه، و تأثیر نخست دوباره آراسته می‌شود. اتمام کار همیشه دم درگاه رخ می‌دهد و آراستگی با همان یک لمس کامل می‌شود."},"ICON-0545":{"nm":"برچسب کیسه‌ی لباسشویی","de":"چیزهایی را که نباید با هم مخلوط شوند، در توری حبس می‌کند و برچسبی به‌آرامی نامشان را می‌نویسد. حتی لباس‌ها هم جایی دارند و آن جا، نشانه‌ای کوچک به همراه دارد. نظمِ روزی که به‌آسانی به‌هم می‌ریزد، از همین برچسب کوچک می‌روید."},"ICON-0546":{"nm":"قلم لکه‌بر","de":"حتی رد یک قطره قهوه روی پیراهن هم، با چند ضربه‌ی آرام، خاموش کنار می‌رود. قلمی که اشتباه را نمی‌پوشاند بلکه آرام پاکش می‌کند. هرکسی به یک فرصت نیاز دارد تا روز را دوباره پاک آغاز کند."},"ICON-0547":{"nm":"پارچه‌ی واکس کفش","de":"یک بار که پارچه را بکشی، چرم درخشش خود را بازمی‌یابد. هرچه کفشی بیشتر پوشیده شود، برقش عمیق‌تر می‌نشیند. جلا، پاداشِ زمانی‌ست که با هم راه رفته‌اید؛ کفش، آن سال‌ها را بی‌صدا روی روی پا حک می‌کند."},"ICON-0548":{"nm":"سرپوش بند کفش","de":"کلاهکی کوچک که به سرِ بندِ بازشده بسته می‌شود. تا خط پایان چشمت جای دیگر نرود، سرش محکم مهر و موم می‌شود. یک بند خوب‌بسته، یک قدم را دورتر می‌فرستد؛ یک احتیاط کوچک، شجاعتِ دویدن تا آخر می‌شود."},"ICON-0549":{"nm":"تگ نام چوب‌لباسی","de":"در میان چوب‌لباسی‌های شبیه به هم، همین تگ کوچک به‌آرامی «جای من» را می‌گوید. راهنمایی خاموش که سردرگمی صبح‌های شلوغ را کم می‌کند؛ وقتی جست‌وجو کمتر شود، آغاز روز هم سبک‌تر می‌شود."},"ICON-0550":{"nm":"قوطی پنس لنز","de":"گاهی به نوکی دقیق‌تر از نوک انگشت نیاز است. پنسی که لنزی کوچک را بی‌لرزش بلند می‌کند، درون قوطی نوبتش را می‌نشیند. دقت همیشه خاموش و آماده در خواب است، تا صدا شود و در یک لحظه بیدار شود."},"ICON-0551":{"nm":"بسته‌ی مینی پنبه‌ی آرایشی","de":"بسته‌ای کوچک که فقط دقیقاً به‌اندازه‌ی یک بار مصرف در خود دارد. حجم کیف را کم می‌کند بی‌آنکه نرمی چیزی کم شود. کم بردن هم نوعی مهربانی‌ست؛ روزی سبک، در جایی که کنار گذاشته شده، جا می‌گیرد."},"ICON-0552":{"nm":"جعبه‌ی دستمال جاذب چربی","de":"درخشش پخش‌شده روی بینیِ ظهر را با ورقی نازک آرام فشرده و پاک می‌کنی. کاغذهایی که ردیف‌منظم درون جعبه خفته‌اند؛ همان لحظه‌ای که یکی را بیرون می‌کشی، هرکسی لحظه‌ای مکث می‌کند تا با مهربانی به خودش در آینه بنگرد."},"ICON-0553":{"nm":"آینه‌شانه‌ی تاشو","de":"تاشده کف دست است، بازشده آینه و شانه. همه‌کاره‌ی کوچکی که از گوشه‌ی کیف، مرتب‌کردنی فوری را به عهده می‌گیرد. آراستگی چیز پرطمطراقی نیست؛ نزدیک‌تر است به دلی که هرجا بشود بازش کرد و یک لمس زد."},"ICON-0554":{"nm":"درپوش ریش‌تراش سفری","de":"تیغه‌ی تیز را در کیف سفر با امنیت به خواب می‌برد. به لطف این درپوشِ کند اما محکم، حتی نوک انگشتانِ سرگردان در صبحی شلوغ هم آسیب نمی‌بینند. مراقبت‌کردن همیشه یعنی یک قدم زودتر خطر را پوشاندن."},"ICON-0555":{"nm":"حلقه‌ی بالم لب","de":"سپری کوچک که از بند کیف آویزان است و تاب می‌خورد. بی‌نگرانیِ غلتیدن و شکستن در جیب، لب‌های خشک همیشه در دسترس دست می‌مانند. نگه‌داشتنِ چیزی نزدیک، در نهایت، دلی‌ست که نیاز را در نزدیک‌ترین فاصله می‌گذارد."},"ICON-0556":{"nm":"نگه‌دارنده‌ی ژل ضدعفونی","de":"با یک دست فشار بده و مشتی پاکیزگی می‌چکد. کنار در، روی میز، هرجا آویزانش کنی، عادتِ دست‌شستن هم به همان اندازه نزدیک‌تر می‌شود. عادت خوب پرطمطراق نیست؛ درست از دسترسِ دست آغاز می‌شود."},"ICON-0557":{"nm":"کیف نازک دستمال‌کاغذی","de":"بدنه‌ای باریک، مشتی دستمال‌کاغذی در خود جای داده. بی‌آنکه جیب را برجسته کند، همیشه آرام آماده‌ی آبریزش ناگهانی بینی یا اشک است. ورقی که پنهانی به کسی می‌دهی؛ هرچه آمادگی باریک‌تر باشد، زیباتر است."},"ICON-0558":{"nm":"بطری کوچک دهان‌شویه","de":"روزی که باید پس از خوردن رامیون تند کسی را ببینی، این بطری کوچک بی‌سروصدا آبرویت را نگه می‌دارد. یک جرعه طراوت گاهی اعتمادبه‌نفسی بزرگ می‌شود و سلامی مردد را بسیار سبک‌تر می‌کند."},"ICON-0559":{"nm":"تکه پودر برّاق","de":"کمی روی نوک انگشت بزن و روی گونه بگذار، مثل غبار ستاره زیر نورها پخش می‌شود. گونه‌ای معمولی در یک لحظه با جادوی همین تکه‌ی کوچک می‌درخشد. نور همیشه این‌گونه، روی گَردی نشسته بر نوک انگشت، از راه می‌رسد."},"ICON-0560":{"nm":"استیکر کاهش برق","de":"در جایی که برق بیش‌ازحد و ناراحت‌کننده است، این استیکر آرام نور را فرو می‌نشاند. برداشتن یک لایه از زرق‌وبرق هم بخشی از آراستن است؛ ظرافتی که در آن جای کاسته‌شده باقی می‌ماند، گاهی حسی تازه می‌شود."},"ICON-0561":{"nm":"قلم برداشتن سنگ","de":"سنگ کوچکی که هنگام راه‌رفتن به پا خورده. قلمی که به‌عمد خم می‌شود تا آن را بردارد. دلی که با نوک انگشت، آنچه را می‌شد به‌سادگی رد شد، آرام جمع می‌کند؛ مهربانی همیشه از ایستادن آغاز می‌شود."},"ICON-0562":{"nm":"صفحه‌ی نگهداری مژه‌ی مصنوعی","de":"صفحه‌ای کوچک برای دراز کشاندن مرتب مژه‌ها، تار به تار. حتی پس از جداشدن هم آن خمِ زیبا بهم نمی‌ریزد. تسلای آرام و منظمِ نگهداری‌ای که می‌گوید حتی چیزهایی که لحظه‌ای کنار گذاشته شده‌اند، جای خود را به یاد دارند."},"ICON-0563":{"nm":"درپوش قیچی چسب پلک","de":"دو تیغه به هم می‌رسند و گره‌ای را یک‌ضرب می‌برند. هرچه جای بریده تمیزتر باشد، گره‌ی بعدی آراسته‌تر می‌شود. از نوک انگشتی که خوب گره می‌زند و خوب می‌برد، آغازی تازه هم بسیار سبک‌تر باز می‌شود."},"ICON-0564":{"nm":"چسب خط صورت","de":"یک نوار در امتداد خط فک، با نفس‌حبس‌شده و احتیاط چسبانده می‌شود. کانتور یعنی نه کشیدن خطی که نبوده، بلکه اشاره‌کردن به جایی که از پیش زیبا بوده. لمسی که با مهربانی، بافتی را که همیشه آنجا بوده دنبال می‌کند."},"ICON-0565":{"nm":"پودر بازتاب‌دهنده‌ی نور","de":"پودری که نور را تمام‌وکمال می‌نوشد و به‌زیبایی بازش می‌گرداند. هرچند خود نمی‌درخشد، با پاشیدن نور دریافتی به ذرات ریز، روشن می‌شود. مثل انتقالِ مهربانیِ دریافتی به دیگری، درخشش هرچه بیشتر تقسیم شود، بزرگ‌تر می‌شود."},"ICON-0566":{"nm":"پنکه‌ی ثابت‌کننده‌ی آرایش","de":"نسیم پنکه‌ای که آرایشی پرزحمت را تا پایان روز نگه می‌دارد. تا فرونریزد، تا آب نشود، آرام سرد و ثابتش می‌کند. تا چهره‌ای که با دقت آراسته شده، تا افتادن پرده‌ی صحنه شفاف بماند."},"ICON-0567":{"nm":"تکه پالت اصلاح‌رنگ","de":"تکه‌های کوچکی که رنگ نامتعادل را خانه‌به‌خانه آرام می‌کنند و اصلاح می‌کنند. رنگی که تنها می‌گشت، سرانجام با رنگی هماهنگ در کنارش روشن می‌شود. تنها وقتی رنگ دست رنگ را بگیرد، بومی روشن و یکدست پدید می‌آید."},"ICON-0568":{"nm":"بسته‌ی شال گردن","de":"دور گردن که بپیچی، هوای سرد اتاق تمرین سحرگاهی بسیار ملایم‌تر می‌شود. گرم مثل دستِ مادربزرگی که آن را دور گردن نوه‌اش می‌پیچید. سرما همیشه نخست از نازک‌ترین جا می‌رسد، پس نخست گردن را در آغوش می‌گیرد."},"ICON-0569":{"nm":"پاکت چشم‌بند گرم","de":"پاکت کوچکی برای نگه‌داشتن چشم‌بندِ گرم‌شده. همان لحظه که درش را باز کنی، گرمایی خواب‌آلود آرام روی پلک‌ها پخش می‌شود. آیینی مهربانانه پیش از خواب که روزی خسته‌کننده را لحظه‌ای مهر و موم می‌کند، سپس رهایش می‌کند."},"ICON-0570":{"nm":"فیلتر رطوبت‌ساز جیبی","de":"پرده‌ی صافیِ کوچکی که رطوبت را به اتاقی خشک بازمی‌گرداند. از درونی نادیده، بی‌صدا آنچه را که تیره است می‌گیرد. رطوبتی که اتاق را پر کرده، صفایی‌ست که با تلاش نادیده‌ی کسی نگه داشته شده."},"ICON-0571":{"nm":"جعبه‌ی مرتب‌ساز ویتامین","de":"جعبه‌ای که قرص‌های روزانه را خانه‌به‌خانه تقسیم می‌کند. با وفاداری خوردنشان، پیمانی‌ست برای فردا هم روی صحنه ایستادن. در هر خانه‌ی کوچک، دلی که خودش را عزیز می‌دارد، منظم و مرتب چیده شده."},"ICON-0572":{"nm":"جعبه‌ی گوش‌گیر خواب","de":"خانه‌ای برای گوش‌گیرهایی که لحظه‌ای صدای دنیا را می‌بندند. حتی سکوت هم به مراقبت نیاز دارد، پس زیبا درون جعبه دراز می‌کشند. شبی که خوب خوابیده شود، صدای فردا را شفاف بیدار می‌کند؛ استراحت این را می‌داند."},"ICON-0573":{"nm":"گیره‌ی حوله‌ی خنک","de":"گیره‌ای که محکم روی شانه گاز می‌گیرد تا حوله‌ی خنک‌شده نلغزد. در روزی گرم، یک رشته خنکی روی گردن، بعدازظهری طولانی را قابل‌تحمل می‌کند. حتی خنکی کوچکی هم اگر نگه داشته شود، دیرتر می‌ماند."},"ICON-0574":{"nm":"کیسه‌ی توپ کشش","de":"کیسه‌ای برای بازگرداندن توپی که بدن را باز کرده بود. کشیدنِ کامل و سپس دوباره جمع‌کردنِ کوچک، شبیه دم و بازدم است. میان باز و جمع، بدن و ذهن هر دو آرام‌آرام استوار می‌شوند."},"ICON-0575":{"nm":"رول باند فشاری","de":"باندی که مچ‌پای پیچ‌خورده را دور تا دور در آغوش می‌گیرد. نه فشردن، بلکه آرام نگه‌داشتن است. هرچه جایی بیشتر رنج کشیده باشد، بیشتر به دستی نیاز دارد که بی‌صدا کنارش تاب بیاورد، رول چنین چیزی را زمزمه می‌کند وقتی می‌پیچد."},"ICON-0576":{"nm":"تگ بررسی حال","de":"برچسبی که حال امروز را در یک خط می‌نویسی و آویزان می‌کنی. صادقانه آویختنِ خوبی و بدی، شجاعتی کوچک است. به‌جای وانمود به خوب‌بودن، خودِ امروزت را بنویس، و کسی آن یک خط را می‌خواند و بی‌صدا مراقبت می‌کند."},"ICON-0577":{"nm":"کپسول خوشبوکننده‌ی کفش","de":"کپسول عطری که آرام درون کفش گذاشته می‌شود. تسلایی کوچک و ملایم برای پاهایی که تمام روز روی صحنه دویده‌اند. بهترین عطر برای رنج‌کشیده‌ترین جا؛ مهربانی تا نوک انگشتان پا هم بی‌کم‌وکاست می‌رسد."},"ICON-0578":{"nm":"جدول اندازه‌ی کفی","de":"جدولی که حتی روی کفی هم اندازه‌ی پا را شفاف حک کرده. یک جفت کاملاً برازنده، قدم‌های روی صحنه را سبک می‌کند. به‌حساب‌آوردن هر گامِ متفاوت؛ اندازه‌ی درست، در نهایت، دلی‌ست که با عمق به دیگری می‌نگرد."},"ICON-0579":{"nm":"جاسوئیچی پاشنه‌کش","de":"جاسوئیچی‌ای با پاشنه‌کشی کوچک‌شده به‌اندازه‌ی کف دست. ملاحظه‌ی کوچکی که آن لحظه‌ی کوتاهِ پاکردن کفش را روان می‌کند. پاهایی که به راه می‌افتند، همیشه دستِ کمک‌کننده‌ی مهربان کسی را همراه دارند، آرام آویزان."},"ICON-0580":{"nm":"روکش گردگیر کیف","de":"پارچه‌ای که کیف عزیز را آرام از گرد و غبار می‌پوشاند. حتی زمانی که استفاده نمی‌شود، آن را زیبا به خواب می‌برد و بافتش را نگه می‌دارد. چیزهایی که دل کمتر به‌سراغشان می‌رود اما در آن می‌ماند، چنین مراقبت آرامی همراهشان است."},"ICON-0581":{"nm":"سنجاق تنظیم بند","de":"سنجاقی که بندِ شل‌شده را دقیقاً به تن می‌چسباند. شل که باشد شانه می‌لغزد، سفت که باشد نفس تنگ می‌شود. در همان تنظیمِ کوچک برای یافتنِ اندازه‌ی درست، لباس صحنه و دل هر دو سرانجام آسوده می‌شوند."},"ICON-0582":{"nm":"قلم روان‌کننده‌ی زیپ","de":"یک بار روی زیپ سفت بکش، دوباره نرم می‌لغزد. صدای رهاشدنِ آرامِ چیزی که گیر کرده بود، چقدر دلپذیر است. آنچه جایی متوقف‌شده را دوباره جاری می‌کند، همان یک رگه نرمی است."},"ICON-0583":{"nm":"نوک تمیزکننده‌ی کفش ورزشی","de":"نوک برسی که کفش خاک‌آلود را نقطه‌به‌نقطه پاک می‌کند. بیرون از صحنه، ردهای نادیده‌ی تمرین را با دقت می‌زداید. با دیدن پنجه‌ی کفشی دوباره سفیدشده، حس می‌کنی فردا هم می‌شود با دلی تازه دوید."},"ICON-0584":{"nm":"درپوش اسپری ضدآب","de":"درپوشِ ضدآبی که قطرات باران را گِرد می‌غلتاند و می‌ریزد. پیشاپیش لایه‌ای زدن تا خیس نشوی، مهربانی‌ای‌ست که دور را می‌بیند. چون می‌دانی روزهای بارانی خواهند آمد، امروزِ صاف را با یک لایه پرده می‌پوشانی."},"ICON-0585":{"nm":"پارچه‌ی محافظ چرم","de":"پارچه‌ای که آرام روی چرم پهن می‌شود تا از چروک‌خوردن جلوگیرد. مثل دست کهنه‌ای که پرده‌ی تاشو را در کاغذ هانجی می‌پیچید، بافت را نگه می‌دارد. هرچه چیزی را بیشتر بخواهی نزدیک نگه‌داری، آهسته‌تر پیش برو؛ کار انداختن نامی دیگر برای زمانِ مراقبت‌کردن است."},"ICON-0586":{"nm":"بند نام چمدان","de":"بندی با نام که در میان انبوه چمدان‌ها، مالِ تو را یک‌نگاه شناسایی می‌کند. میان بارهایی که دور و دور روی نوار نقاله می‌چرخند، با یک حرف دست بلند می‌کند. هرچقدر هم دور سفر کنی، یک نام همان آسودگیِ دوباره دیدن است."},"ICON-0587":{"nm":"گیره‌ی کیسه‌ی فشرده‌ساز","de":"گیره‌ای که بارِ پفکرده را صاف فشرده و می‌بندد. نه چندان خالی‌شدن که تاشدنِ منظم. از نوک انگشتی که خانه را زیبا کوچک می‌کند، حرص هم کوچک می‌شود؛ بارِ محکم‌فشرده آرام این را می‌گوید."},"ICON-0588":{"nm":"ورق مواد شوینده‌ی سفری","de":"ورقی که با یک تکه، لباس‌شویی در دستشویی را ممکن می‌کند. شبیه است به خرد مسافری که در راهی دور، لباس را با دست می‌شست. سبک سفرکردن اما آراستگی را هم همراه بردن، طرز فکر دیرینه‌ی مسافران راه است."},"ICON-0589":{"nm":"روکش بالش گردنی","de":"روکشی تمیز که تازه روی بالشی که گردن را نگه می‌داشت کشیده می‌شود. جایی که تکیه می‌کنی، باید همیشه پاکیزه باشد تا خیال آسوده شود. جایی را نرم و خالی نگه‌داشتن برای اینکه کسی راحت تکیه کند؛ مهمان‌نوازی از همان‌جا آغاز می‌شود."},"ICON-0590":{"nm":"بند ترازوی چمدان","de":"بندی که کیف را بالا می‌کشد تا وزنش را بسنجد. پیش از رفتن، وزن بار را پیشاپیش با دست در آغوش می‌گیری. میان آنچه باید ببری و آنچه باید بگذاری، لحظه‌ای که حتی وزن دل را هم آرام می‌سنجی."},"ICON-0591":{"nm":"جفت کیف کفش","de":"جفت کیفی که دو کفش، چپ و راست، را کنار هم جای می‌دهد. چیزی که جدا گذاشته شود آسان گم می‌شود، اما جفت‌شده اطمینان‌بخش است. چیزهایی که همیشه با هم می‌روند، قدرتی دارند که آرام از هم مراقبت کنند."},"ICON-0592":{"nm":"حلقه‌ی کمکی کیف","de":"روزی که یک دست کم می‌آید، حلقه‌ای کوچک برای آویزان‌کردن لحظه‌ای کیف. جایی اضافه برای روزهایی که بار بیش از آن است که بشود همه را حمل کرد. فقط داشتنِ جایی برای لحظه‌ای آویزان‌کردن، شانه‌ها را بسیار سبک‌تر می‌کند."},"ICON-0593":{"nm":"تکه‌چیپ برنامه‌ی سفر","de":"مسیر روزانه را شفاف روی یک تکه‌چیپ حک می‌کند. کجا ملاقات و به کجا جریان؛ خط راهنمایی که پیشاپیش برای قدم‌های کم‌تجربه در راه‌یابی کشیده شده. راهی که با هم پیموده می‌شود، اگر خانه‌به‌خانه یادداشت شود، به‌سختی گم می‌شود."},"ICON-0594":{"nm":"درپوش آداپتور چندکاره","de":"درپوشی که حتی در پریز کشوری ناآشنا هم دقیق جفت می‌شود. شکلی متفاوت، اما سرانجام همه به یک چیز متصل می‌شوند. به‌هم‌پیوستن چیزهایی که از جاهای گوناگون آمده‌اند؛ هماهنگی آرام از یک تبدیل کوچک آغاز می‌شود."},"ICON-0595":{"nm":"جلد کارت بلیت","de":"ورقی شفاف که هر بار کارت از دروازه می‌گذرد، از آن محافظت می‌کند. رفت‌وآمد روزانه، حتی رد ضربه‌های کهنه‌اش را هم زیبا در بر می‌گیرد. حتی راهی معمولی هم اگر عزیز داشته شود خاطره می‌شود، همین لایه‌ی نازک این را ثابت می‌کند."},"ICON-0596":{"nm":"گیره‌ی بلیت","de":"گیره‌ای که بلیتی را که به‌سرعت مچاله می‌شود، مرتب می‌گیرد. اگر در راه بلیت را گم کنی، حتی دلت هم می‌لرزد. هرچه کاغذ کوچک‌تر باشد، محکم‌تر نگهش می‌داری؛ آسودگیِ سفر، درست از همان یک خانه می‌آید."},"ICON-0597":{"nm":"تکه‌چیپ یادداشت تعویض","de":"تکه‌چیپ کوچکی که کجا باید تعویض کرد را در یک خط نوشته. در هر دوراهیِ گیج‌کننده، یک کلمه‌ی پیشاپیش‌نوشته‌شده راه را روشن باز می‌کند. یادداشت، نجوایی مهربانانه است که آرام به خودِ آینده‌ات که ممکن است راه را گم کند، می‌دهی."},"ICON-0598":{"nm":"تگ عبور از گیت","de":"تگ عبوری که هنگام گذشتن از در، آرام شناسایی می‌شود. حتی راهی که مسدود می‌نمود، وقتی صلاحیت خودت را داشته باشی، به‌آرامی باز می‌شود. رودررو عبورکردن، یعنی بی‌هیچ درنگی سبک به خانه‌ی بعدی گام‌برداشتن."},"ICON-0599":{"nm":"نگه‌دارنده‌ی رسید تاکسی","de":"هر برگه‌ی کوچک، رد شفافی از راهی که آن روز پیموده شد را در خود دارد. رسیدهایی را که به هر سو می‌غلتیدند جمع کن و مرتب کنار هم بگذار، و روزی که چیز خاصی نبود، برگه‌به‌برگه انباشته و سفری راستین می‌شود."},"ICON-0600":{"nm":"نوار بازتاب‌دهنده‌ی دوچرخه","de":"نواری که در راهی تاریک، نورهای عبوری را می‌گیرد و آرام می‌درخشد. هرچند خودش نمی‌تابد، با نور دیگری روشن می‌شود. دیده‌شدن، خواهشی مهربانانه از راه شب است که بگو سالم بازگرد."},"ICON-0601":{"nm":"روکش چرخ چمدان","de":"دلیل اینکه گوشه‌های چمدانت بعد از هزاران بار چرخیدن روی نوار فرودگاه هنوز سالم مانده، همین روکش کوچکی‌ست که دور چرخ‌ها پیچیده شده. جایی که اول از همه با ناهموارترین راه روبه‌رو می‌شود؛ مراقبت بی‌صدا از کسی، همیشه همین‌جا، در جایی نامرئی پنهان است."},"ICON-0602":{"nm":"روکش پشتی‌سر صندلی","de":"در یک سفر طولانی با اتوبوس، روکشی روی پشتی‌سر می‌کشی و سرت را به شیشه تکیه می‌دهی. نه رایحه‌ی مسافر قبلی و نه خستگی دیروز، هیچ‌کدام تا اینجا نمی‌رسند. تمیز بودن جایی برای تکیه دادن سر، در جاده‌ای غریب، آرامشی به‌طرز عجیبی بزرگ است."},"ICON-0603":{"nm":"سنجاق نشانگر پارکینگ","de":"«کدام طبقه، کدام جای پارک بود؟» هرکس که در پارکینگی خالی سرگردان مانده باشد، می‌داند این سنجاق چقدر دلگرم‌کننده است. یک نشانه‌ی کوچک به‌جای حافظه‌ای که کم‌کم محو می‌شود، از پیش راه بازگشت را مشخص می‌کند."},"ICON-0604":{"nm":"بند نگه‌دارنده کلید اتاق","de":"کلید اتاق چطور این‌قدر راحت گم می‌شود؟ آن را به بندی وصل کن و دور مچت بینداز، دیگر هیچ‌وقت اتاقی را که امشب منتظرت است فراموش نمی‌کنی. حتی در شهری غریب، آسودگیِ کوچکِ داشتن جایی از آنِ خودت، از مچ دستت آویزان می‌ماند."},"ICON-0605":{"nm":"تراشه علامت درِ اتاق","de":"وقتی تمرین شروع می‌شود، تراشه‌ای روی در آویزان می‌کنی. مزاحم نشوید—این زمان تمرکز کامل است. سکوت عمیق پشتِ صحنه، همیشه با نشانه‌های کوچکی مثل این، بی‌صدا محافظت می‌شود."},"ICON-0606":{"nm":"کیف لوازم بهداشتی","de":"مسواک، شوینده صورت، حوله‌ای به اندازه کف دست. به هر کجا که بروی، همین کیف را بردار، تا پایان و آغاز هر روز با همان دست‌های آشنا مرتب شود. مشتی کوچک از خانه‌داری که رختخوابی غریب را ناگهان آشنا می‌کند."},"ICON-0607":{"nm":"گیره حوله اضافه","de":"کنار دستشویی، آن حوله‌ی اضافه که جایی برای آویختن نداشت، همیشه نمور می‌ماند. با گیره‌ای بگیرش و آویزانش کن، بالاخره جای خودش را پیدا می‌کند. فراهم کردن جایی برای خشک شدن—مهربانی معمولاً همین‌قدر کوچک است."},"ICON-0608":{"nm":"کیف چندراهی برق","de":"هر بار که کیفت را باز می‌کردی، شارژرها در هم گره خورده بودند. چندراهی را با سیم‌ها لوله کن و داخل بگذار، همه‌چیز مرتب می‌شود. باز شدن گره‌ی سیم یعنی گوشه‌ای از دلت هم پیش از سفر آرام باز می‌شود."},"ICON-0609":{"nm":"برچسب شماره تخت","de":"روی هر تخت طبقه‌ی دوم خوابگاه، برچسب شماره‌ای چسبانده شده. با همین یک برچسب که می‌گوید کدام جا مال توست، حتی اتاقی تازه و غریب هم تا شب به خانه‌ی ما تبدیل می‌شود. آغاز همیشه همین‌قدر کوچک است."},"ICON-0610":{"nm":"بند رخت کوچک","de":"دو سرش را بین دو لبه‌ی پنجره ببند، خودش بند رختی می‌شود. در روزی آفتابی، چند جفت جوراب دست‌شسته در باد تکان می‌خورند و خشک می‌شوند. حتی دور از خانه، زندگی روزمره همین‌طور روی یک بند خشک می‌شود."},"ICON-0611":{"nm":"برچسب تفکیک دمپایی","de":"وقتی دمپایی‌ها جلوی در انبوه می‌شوند، دیگر معلوم نیست کدام مال کیست. با یک برچسب کوچک، حتی کفش هم صاحبش را می‌شناسد. زندگی جمعی و تنگاتنگ، به همین نشانه‌های مهربان نیاز دارد."},"ICON-0612":{"nm":"جاکوپنی صبحانه","de":"جایی برای گذاشتن کوپن صبحانه. در سحرگاهی گرسنه، همین یک برگه یعنی یک کاسه سوپ داغ در انتظار است. روز یک سفر همیشه آرام‌آرام با یک وعده غذای گرم آغاز می‌شود."},"ICON-0613":{"nm":"بند بازتاب‌دهنده مچ پا","de":"دور مچ پا که ببندیش، در تاریکی نور را پس می‌تاباند. در پیاده‌روی شبانه، از دور به ماشینی که نزدیک می‌شود بی‌صدا دست تکان می‌دهد: «اینجا آدم هست.» ایمنی همین‌قدر ساده می‌درخشد."},"ICON-0614":{"nm":"درپوش دستمال مرطوب","de":"درپوشی که دقیقاً روی دهانه‌ی بسته‌ی دستمال مرطوب جا می‌گیرد. هر برگ به‌نرمی بیرون می‌آید و بقیه خشک نمی‌مانند. شاید بی‌اهمیت به‌نظر برسد، اما چیزهایی که هر روز دست به آن‌ها می‌رسد، همیشه دلیلی پنهان دارند."},"ICON-0615":{"nm":"بند حصیر پیک‌نیک","de":"حصیر را لوله می‌کنی و با بند می‌بندی. کنار رودخانه، زیر سایه‌ی شکوفه‌های گیلاس، هر جا پهنش کنی، همان‌جا جای ماست. بندی که قلمرویی به‌اندازه کف دست، روی چمن، همراه خودت می‌بری."},"ICON-0616":{"nm":"جعبه برچسب ضدپشه","de":"ضروریِ شب‌های تابستان، جعبه‌ای برای نگه‌داشتن برچسب‌های ضدپشه. دلسوزی‌ای که پیش از خارش شروع می‌شود، در همین یک خانه‌ی کوچک جا گرفته. ردیف‌های عقب صحنه‌ی روباز، همیشه با همین احتیاط‌های کوچک محکم می‌شوند."},"ICON-0617":{"nm":"قلاب بطری آب پیاده‌روی","de":"قلابی برای آویختن بطری آب به کیف هنگام پیاده‌روی. آب در دسترس بودن درست وقتی تشنه می‌شوی، یعنی می‌توانی خیلی دورتر راه بروی. پیوندی کوچک که نمی‌گذارد پیاده‌رو متوقف شود."},"ICON-0618":{"nm":"سبد خرید تاشو","de":"باز کنی سبد خرید است، تا کنی جا می‌شود در کف دست. مناسب همان یک بسته سبزی که در کوچه‌پس‌کوچه‌های بازار به آن دل بسته‌ای. خرد خانه‌داری همیشه به‌سمت کمتر شدن حجم، به‌سمت سبک‌تر حمل‌شدن رشد کرده است."},"ICON-0619":{"nm":"گیره بادشکن","de":"در روزی بادی، لبه‌ی پارچه‌ای چادر را که تکان می‌خورد محکم می‌گیرد. یک گیره کافی‌ست تا چیزی که مدام می‌لرزید سرجایش بماند. در فضای باز، قابل‌اعتمادترین چیز، عجیب است، به‌اندازه‌ی یک انگشت است."},"ICON-0620":{"nm":"سنجاق سایه‌بان آفتاب","de":"سنجاقی که به پنجره می‌زنی تا نور خورشید را کج کند. وقتی نور نیمروز خیلی تند است، آرام مشتی سایه می‌اندازد. کم کردن خیرگی هم می‌تواند برای کسی، لطف بی‌نظیری باشد."},"ICON-0621":{"nm":"درپوش سوت اضطراری","de":"درپوشی که دهانه‌ی سوت اضطراری را می‌پوشاند. تا گرد و غبار وارد نشود، و در لحظه‌ی واقعاً لازم، یک‌نفس صدا کند. بعضی چیزها فقط با بودن در کنارت آرامش می‌دهند، حتی وقتی امیدواری هرگز لازمشان نشود."},"ICON-0622":{"nm":"درپوش نوک چتر","de":"درپوش کوچکی که روی نوک چتر می‌کشی. وقتی نوک تیز کند می‌شود، نه کسی که کنارت راه می‌رود آسیب می‌بیند و نه کیف خودت. ادب روزهای بارانی، آرام از همین گرد کردن یک نوک تیز آغاز می‌شود."},"ICON-0623":{"nm":"کیسه نگهداری بارانی","de":"کیسه‌ای برای لوله کردن و جا دادن بارانی تاشده. تا رگبار بعدی در گوشه‌ی کیف بی‌صدا منتظر می‌ماند. آماده‌بودن در نهایت، همان تکه‌ای از دل است که چیزی را که شاید هرگز لازم نشود، از پیش با خود می‌برد."},"ICON-0624":{"nm":"روکش ضدآب کفش","de":"روی کفش بکشی، دیگر باران نمی‌تواند نفوذ کند. حتی در راه مدرسه زیر بارانِ موسمی، جوراب‌ها خشک می‌مانند. روزی که نوک انگشتان پا خیس نمی‌شود، بیش از آنچه فکرش را بکنی حال‌وهوا را عوض می‌کند."},"ICON-0625":{"nm":"پد ضدلغزش برف","de":"زیر کفش که بچسبانی، راه یخ‌زده دیگر آن‌قدر ترسناک نیست. آن زمستانی که با گام‌های تندتند از کوچه‌های پربرف می‌گذشتی، این پد بی‌صدا نگهت داشت تا نلغزی. استحکامی پنهان زیر قدم‌های محتاط."},"ICON-0626":{"nm":"حلقه خنک‌کننده گردن","de":"دور گردن که ببندیش، جریانی خنک آرام می‌چرخد. خرد تابستانی که در گرمای سوزان، رشته‌ای خنکی را روی پس‌گردن حمل می‌کند. هر سال کمی هوشمندانه‌تر یاد می‌گیریم گرما را تاب بیاوریم."},"ICON-0627":{"nm":"پایه پنکه دستی","de":"پایه‌ای برای بالا نگه داشتن پنکه دستی. وقتی هر دو دست آزاد می‌شوند، هم می‌شود صفحه‌ها را ورق زد و هم به‌جای بادزدن نوشت. یک نسیم کوچک، تابستانی طولانی پشت میز را قابل‌تحمل می‌کند."},"ICON-0628":{"nm":"کیف کاور کیسه گرمازا","de":"کیفی برای حمل کیسه‌ی گرمازا. وقتی برای گرم کردن نوک انگشتان یخ‌زده دست در جیب می‌کنی، گرمای کوچکی از پیش آنجا منتظرت است. بیرون‌رفتن زمستانی با همین یک مشت گرما تاب می‌آورد."},"ICON-0629":{"nm":"کیف گوش‌گیر زمستانی","de":"جعبه‌ای برای نگه‌داشتن گوش‌گیرها. جایی که با احتیاط تا سرمای بعدی نگهشان می‌دارند. چیزهایی که با تغییر فصل نمی‌توانی دورشان بیندازی، ایمانی آرام به زمستانی که دوباره از راه می‌رسد دارند."},"ICON-0630":{"nm":"تراشه سنجش اشعه فرابنفش","de":"نزدیک نور که بگیریش، شدت اشعه فرابنفش امروز را با رنگ نشان می‌دهد. شدت نامرئی نور خورشید را بالاخره قابل‌دیدن می‌کند. یعنی چشمی کوچک برای خواندن آسمان را آرام به مچ دستت می‌بندی."},"ICON-0631":{"nm":"تخته مهر کوچه","de":"تخته‌ای که با گرفتن مهر از هر مغازه‌ی سر کوچه پر می‌شود. با هر خانه‌ای که مهر می‌خورد، نقشه‌ی محله واضح‌تر در دل نقش می‌بندد. خاطراتی که با پا جمع شده‌اند، این‌طور به شکل جای مهرها می‌مانند."},"ICON-0632":{"nm":"برد سنجاق مقصدهای سفر","de":"تخته کوچکی که برای هر جایی که رفته‌ای سنجاقی می‌زنی. هرچه نقطه‌ها بیشتر شوند، محدوده‌ی دنیای تو هم گسترده‌تر می‌شود. هر سنجاق، ردی‌ست که آرام می‌گوید: «من اینجا بودم.»"},"ICON-0633":{"nm":"بند قطب‌نمای کوچک","de":"هرچقدر هم سرگردان بمانی، شمال همیشه ثابت سرجایش می‌ماند. قطب‌نمای کوچکی که به گردن آویزان است، وقتی نمی‌دانی به کدام سو باید بروی، اول از همه دل لرزانت را آرام می‌کند."},"ICON-0634":{"nm":"حلقه یادداشت مسیریابی","de":"یادداشت‌هایی که هنگام پیدا کردن راه نوشته‌ای، در یک حلقه بسته شده‌اند. «سر صندوق پست قرمز بپیچ به چپ.» خط دست‌خط ناشیانه‌ی کسی، کوچه‌ای غریب را آرام راهنمایی می‌کند. راهی که روی کاغذ باقی می‌ماند، به‌این‌سادگی محو نمی‌شود."},"ICON-0635":{"nm":"کتاب استیکر بناهای تاریخی","de":"کتابی که با یک استیکر از هر مقصد پر می‌شود. برج‌ها، پل‌ها، دیوارهای قدیمی قلعه صفحه به صفحه انباشته می‌شوند. جمع کردن جاهایی که رفته‌ای، شبیه دوباره لمس‌کردن زمانی است که پشت سر گذاشته‌ای."},"ICON-0636":{"nm":"تراشه تعویض خط مترو","de":"تراشه‌ای که در ایستگاه تعویض خط، جایی که مسیرها از هم جدا می‌شوند، محکم در دست می‌گیری. همان لحظه‌ی کوتاه انتخاب مسیر بعدی، گاهی مسیر کل روز را عوض می‌کند. شهر با یک انتخاب کوچک، چهره‌ای دیگر نشان می‌دهد."},"ICON-0637":{"nm":"کارت ماجراجویی محله","de":"«امروز تا نانوایی همین محله.» یک کارت بکش، مقصد امروز مشخص می‌شود. حتی کوچه‌ای آشنا که همیشه از آن می‌گذشتی، با یک ماموریت راهی تازه می‌شود. کارتی که یادآوری می‌کند ماجراجویی دور نیست."},"ICON-0638":{"nm":"جاکارت‌ویزیت مغازه","de":"جایی برای نگه‌داشتن کارت‌ویزیت‌هایی که از مغازه‌های مورد علاقه‌ات گرفته‌ای. آن مغازه خوش‌طعم، آن صاحب مغازه‌ی مهربان، یکی‌یکی در جای خود جمع می‌شوند. دل بستن به یک شهر، از همین برگه‌های کوچک کاغذ آغاز می‌شود."},"ICON-0639":{"nm":"برد نشان تکمیل مسیر","de":"تخته‌ای که با تمام‌کردن یک مسیر پیاده‌روی، نشانی به آن اضافه می‌شود. پاداش رسیدن به انتها، به شکل قطعه‌ای فلزی گرد در دستت می‌ماند. غروری که فقط کسی که تا آخر راه رفته می‌شناسد، اینجا واضح حک می‌شود."},"ICON-0640":{"nm":"قفل‌کلید کیف","de":"قفل کوچک و جاکلیدی که به زیپ کیف می‌بندی. چیزهای عزیز را محکم نگه می‌دارد و درعین‌حال کنار کیف جینگ‌جینگ صدا می‌کند. همراهی نسبتاً باهوش برای مسافر، جایی که امنیت و تزیین یکی می‌شوند."},"ICON-0641":{"nm":"برچسب ضدگم‌شدن","de":"در تاریک‌ترین گوشه‌ی کیف مچاله شده، تا آن لحظه‌ای که همه امیدشان را از دست داده‌اند، آرام چشمک می‌زند: «همین‌جام.» صدای بازگشتن چیزی که فکر می‌کردی گم شده، به نوک انگشتانت. کوچک است، اما تا آخر کنار صاحبش می‌ماند."},"ICON-0642":{"nm":"حلقه قفل زیپ","de":"کلیک، وقتی یک‌بار بسته شود، دیگر با هر دستی باز نمی‌شود. لجاجتی که هم ناخنِ عجول را متوقف می‌کند، هم انگشتی که بی‌صدا نزدیک می‌شود. امنیت با وزن سنگینش می‌گوید که گاهی کمی سفت بودن اشکالی ندارد."},"ICON-0643":{"nm":"بند زنگ ضدسرقت","de":"نگهبانی نامرئی که تا پیش از پرداخت پول نمی‌گذارد کالاهای روی قفسه بی‌اجازه بیرون بروند. وقتی دست صادقی از کنارش می‌گذرد، تا آخر ساکت می‌ماند. زنگی که صدا نمی‌کند، آرام‌ترین زنگ است."},"ICON-0644":{"nm":"برچسب پوشاننده اطلاعات تماس","de":"آرام لایه‌ای روی نام و شماره نوشته‌شده بر جعبه بسته‌بندی می‌کشد. اینکه چه کسی اینجا زندگی می‌کند، به کجا می‌رود، فقط باید گیرنده بداند. خوب پوشاندن هم نوعی مهربانی‌ست، همین‌طور بی‌صدا سرجایش می‌ماند."},"ICON-0645":{"nm":"بند روکش پاسپورت","de":"فرودگاهی غریب، ده‌ها روکش یک‌شکل که سحرگاه روی نوار می‌چرخند. در آن میان با رنگی که فقط تو می‌شناسی می‌گوید: «این طرف.» کت کوچکی که به سندی می‌پوشانند که راهی سفری دور می‌شود. حتی وقتی روکش فرسوده شود، سفر روشن می‌ماند."},"ICON-0646":{"nm":"کیف تفکیک پول نقد","de":"اسکناس سمت چپ، سکه سمت راست، پول اضطراری در خانه‌ای که کسی از آن خبر ندارد. اولین جایی‌ست که دستِ تازه از بازار برگشته لمس می‌کند. حتی روزی درهم‌ریخته هم داخل این کیف، منظم و جینگ‌جینگ جای خود را پیدا می‌کند."},"ICON-0647":{"nm":"برچسب مهر امنیتی","de":"یک‌بار که کنده شود، ردش می‌ماند. وجدانی کوچک و صادق که هرگز نمی‌تواند «کسی بازش کرده» را تا آخر پنهان کند. زیر هر جعبه‌ای که مهروموم و سالم رسیده، همیشه سکوت پایدار همین دوست خوابیده است."},"ICON-0648":{"nm":"تراشه تماس اضطراری","de":"جیب کودکی که راهش را گم کرده، داخل کیف لپ‌تاپ، انتهای بند گردن سگ. حتی وقتی لحظه نمی‌تواند حرف بزند، به‌جایش شماره را واضح فریاد می‌زند. یک تراشه‌ی کوچک، تمام حرف «مرا به خانه ببرید» را در خود دارد."},"ICON-0649":{"nm":"درپوش ریموت مونوپاد سلفی","de":"عکس‌های دسته‌جمعی که همیشه یکی به‌خاطر کوتاهی دست بیرون می‌ماند. حالا فقط با فشار دکمه‌ای انتهای چوب، کل خانواده در یک قاب جا می‌گیرند. در همان لحظه که همه می‌خندند، آرام دکمه را می‌فشارم و خودم هم می‌پرم داخل تصویر."},"ICON-0650":{"nm":"بند کیف لنز","de":"بندی که لنزهای اضافه را محکم در آغوش می‌گیرد تا در کیف به هم نخورند. چون یک تکه شیشه، همان یک منظره است، آن وزن را بی‌احتیاط تکان نمی‌دهی. مراقبت عکاس در هر گره‌اش بسته شده است."},"ICON-0651":{"nm":"حلقه جعبه فیلتر","de":"یک ورقه‌ی نازک، همان آسمان را به نوری دیگر تبدیل می‌کند. جایی که این جادوهای کوچک را مرتب در آشیانه‌ای گرد نگه می‌دارند. هر بار که جعبه را باز می‌کنی، نوک انگشتانت لحظه‌ای می‌لرزد: امروز کدام غروب را ثبت کنم؟"},"ICON-0652":{"nm":"کیف سه‌پایه","de":"تا کنی به‌اندازه‌ی یک وجب، باز کنی سه پای استوار بی‌لرزش. به‌جای دست لرزان، دوستی را که منظره را ثابت نگه می‌دارد، آرام لوله می‌کنی. هرچه وسیله سنگین‌تر باشد، باید روی پارچه‌ای نرم‌تر بخوابد؛ این حق اوست."},"ICON-0653":{"nm":"پد بند دوربین","de":"تمام روز که راه بروی، لحظه‌ای می‌رسد که دوربین روی شانه سنگینی می‌کند. آن‌وقت یک پد آرام آن وزن را با تو تقسیم می‌کند. تسلی‌ای کوچک و نرم که روی شانه‌ای می‌نشیند که برای یک عکس خوب راه دوری رفته است."},"ICON-0654":{"nm":"کارت دسته‌بندی کارت حافظه","de":"شبی که گیج می‌شوی کدام کارت خاطرات صدها عکس را در خود خوابانده. نشانه‌های رنگی مسیر را نشان می‌دهند: سفر بهاری آبی، اولین اجرا زرد. کتابدار کوچک و مهربانی که حتی به خاطره‌ها هم قفسه‌ای جداگانه می‌دهد."},"ICON-0655":{"nm":"رول کابل شارژ","de":"پیش از آنکه کابل‌ها داخل کیف نمایش گره‌بازی راه بیندازند، آن‌ها را گرد لوله می‌کنی و مرتب می‌خوابانی. یک سیم را که مرتب کنی، انگار یک رشته از دلت هم باز می‌شود. دیدن آن پیچیدگی مرتب، خودش آرامش‌بخش است."},"ICON-0656":{"nm":"برچسب پشتیبان عکس","de":"«این عکس‌ها را پشتیبان گرفتم یا نه؟» یادداشتی کوچک که از پیش پاسخ آن نگرانی نیمه‌شب را می‌دهد. هرچه لحظه‌ای عزیزتر باشد، باید در بیش از یک جا زنده بماند؛ این را برچسب واضح می‌نویسد."},"ICON-0657":{"nm":"تخته قاب ترکیب‌بندی","de":"از پشت پنجره‌ای مربعی که به دنیا نگاه کنی، یک‌باره روشن می‌شود چه چیزی را نگه داری و چه چیزی را رها کنی. عکس خوب افزودن نیست، خوب کاستن است؛ این را قاب خالی اول از همه به تو یاد می‌دهد."},"ICON-0658":{"nm":"آویز کیف سکه","de":"از لبه‌ی کیف آویزان می‌ماند و چند سکه را در خود جا می‌دهد. اولین گنجینه‌ی کوچکی که جلوی دستگاه فروش، یا جلوی بساط داغِ نان‌ماهی باز می‌شود. آن صدای جینگ‌جینگ، صدای پس‌زمینه‌ی شادی‌های کوچک است."},"ICON-0659":{"nm":"میله جمع‌آوری رسید","de":"تکه‌کاغذهایی که نزدیک بود دور بریزی، یکی‌یکی سیخ می‌خورند. امروز چه خوردی، چه خریدی؛ رسید صادق‌تر از هر دفتر حساب و کتابی است. یک ماه از آن‌ها را که جمع کنی، دفترچه‌ای نسبتاً قطور از زندگی می‌شود."},"ICON-0660":{"nm":"برچسب سبد بازار","de":"به مچ دستی که برای خرید بیرون رفته آویزان است و همراهش در کوچه‌های بازار می‌گردد. یک تکه توفو، یک بسته پیازچه، حتی مهری که رایگان روی آن‌ها گذاشته‌اند. تمام آن وزن را بی‌گله می‌پذیرد؛ دوستی که از پرشدن بیشتر از خالی‌شدن ذوق می‌کند."},"ICON-0661":{"nm":"آهن‌ربای یادگاری","de":"از هر مقصد یکی بردار و به یخچال بچسبان، آشپزخانه نقشه‌ی کوچکی از دنیا می‌شود. شهرهایی که رفته‌ای کنار هم آویزانند و زمزمه می‌کنند: «دوباره برویم.» حتی یک تکه فلز ساده، قدرت نگه‌داشتن خاطره را دارد."},"ICON-0662":{"nm":"کتاب مهر مناطق","de":"یک مهر در هر صفحه، کوچه‌هایی که راه رفته‌ای دوباره با جوهر زنده می‌شوند. رد قرمزی که در سفر به سراسر کشور جمع کرده‌ای، نقشه‌ی رد پاهایت است. هرچه خانه‌های خالی کمتر شوند، سفر بعدی بیشتر بی‌صدا صدایت می‌زند."},"ICON-0663":{"nm":"قرقره نوار بسته‌بندی","de":"صبری طولانی و بی‌پایان که برای بستن فقط یک جعبه‌ی هدیه باز می‌شود. فقط به دستی که بلد است به‌موقع ببرد، گره‌ای مرتب اجازه می‌دهد. لوله‌شده، بی‌صدا منتظر نوبت بعدی می‌ماند."},"ICON-0664":{"nm":"بالشتک محافظ هدیه","de":"قلبی شکننده را در آغوشی نرم می‌پیچد. حتی داخل صندوق تحویلی که تکان می‌خورد، محکم و پرملایمت می‌ایستد: «نگران نباش، من نگهت می‌دارم.» حتی لبخند روشن کسی که جعبه را باز می‌کند، از پیش محافظت می‌شود."},"ICON-0665":{"nm":"برچسب پوشاننده قیمت","de":"دروغی کوچک و مهربان که قیمت هدیه را آرام می‌پوشاند. «لازم نیست بدانی چقدر بوده، فقط دل را بگیر»، این را می‌گوید و نرم روی برچسب قیمت می‌نشیند. پوشاندن نیست، درخشان‌تر کردن همان دل است."},"ICON-0666":{"nm":"تراشه چرخ‌دستی خرید کوچک","de":"نمی‌توانی چرخ‌دستی واقعی را هل بدهی، اما این دوست کوچک که از نوک انگشتت آویزان است، تمام هیجان یک گشت‌وگذار در فروشگاه را در خود دارد. کوچک است، ولی همان دلهره‌ی «امروز چی بخرم؟» به‌اندازه‌ی چیز واقعی سنگین است."},"ICON-0667":{"nm":"گیره فسفری کفش","de":"در نوک کفش ورزشی‌ای که به پیاده‌روی شبانه رفته، برقی می‌زند و به ماشین در حال عبور علامت می‌دهد: «اینجا آدم هست.» اولین نور کوچکی که در کوچه‌ای تاریک به استقبالت می‌آید. ایمنی همیشه آرام از نوک پا آغاز می‌شود."},"ICON-0668":{"nm":"کلاهک چراغ‌قوه کوچک","de":"روی سر چراغ‌قوه که بکشی، نور دورتر و نرم‌تر پخش می‌شود. جادوگر کوچکی که خوشه‌ای از ستاره‌ها را روی سقف تاریک چادر نقش می‌زند. در شبی که تاریکی کمی ترسناک است، دوستی بهتر از این نیست."},"ICON-0669":{"nm":"دکمه اطلاع بازگشت به خانه","de":"فشارش بده، پیامی به خانواده‌ای دور می‌رسد: «سالم رسیدم.» به‌جای صدای در ورودی در نیمه‌شب، همین یک دکمه‌ی کوچک خبر سلامتی را می‌رساند. یک نفر منتظر همین علامت به خواب می‌رود."},"ICON-0670":{"nm":"رول برچسب بازتاب‌دهنده","de":"یک تکه ببر و روی کیف، دوچرخه، چتر بچسبان، راه شبانه کمی کمتر خطرناک می‌شود. خواب‌آلودی که فقط با دیدن چراغ جلوی ماشین روشن بیدار می‌شود. لوله‌شده منتظر تاریکی بعدی می‌ماند."},"ICON-0671":{"nm":"کارت تاکسی اضطراری","de":"در جیب کیف پول بگذارش، حتی ایستگاهی خالی در نیمه‌شب کمتر ترسناک می‌شود. یک شماره، یک خط آدرس مثل قولی نوشته شده: «تا خانه می‌رسانمت.» کی فکرش را می‌کرد کلمه‌ی اضطراری این‌قدر دلگرم‌کننده باشد."},"ICON-0672":{"nm":"بند نقشه راه شبانه","de":"مسیری با چراغ‌های کم‌نور را با آن دور مچ راه می‌روی. کدام کوچه روشن است، کجا تاریک، میان‌بری که فقط شب می‌شناسد را آرام لو می‌دهد. بندی که کنار تو گره می‌خورد تا حتی در تاریکی هم جهت را گم نکنی."},"ICON-0673":{"nm":"کیف زنگ ایمنی","de":"در لحظه‌ی اضطراری بکشیش، آن‌قدر بلند فریاد می‌زند که کل کوچه از جا می‌پرد. بقیه‌ی وقت آرام داخل کیف پنهان است و صدایش را برای همان یک لحظه نگه می‌دارد. بزرگ‌ترین فریاد، در کوچک‌ترین کیف جا خوش کرده."},"ICON-0674":{"nm":"جاکلیدی چراغ‌دار جلوی در","de":"خداحافظ با شب‌هایی که کورمال‌کورمال دنبال سوراخ کلید در انتهای راهرویی تاریک می‌گشتی. کنار در آویزان است و با نوری گرد به استقبال دستِ بازگشته می‌آید. جاکلیدی اول از همه سلام می‌دهد: «خسته نباشی، رسیدی.»"},"ICON-0675":{"nm":"یادداشت بازگشت به اقامتگاه","de":"«چترت رو بردار، وقتی می‌ری چراغ رو خاموش کن.» یادآوری کوتاهی روی یخچال، اتاق خالی را نگهبانی می‌کند. یادداشتی کوچک برای کسی که قرار است برگردد. مهربانی نهفته در یک ورقه کاغذ، آرام تا در ورودی هم همراهش می‌شود."},"ICON-0676":{"nm":"شانه مرتب‌کننده کابل","de":"سیم‌های درهم‌پیچیده را مثل شانه‌کردن مو، آرام و نرم مرتب می‌کند. جنگل سیم‌های پشت میز با چند بار شانه‌زدن مرتب می‌شود. تنها مو نیست که درهم می‌پیچد، شانه آرام همین را یادآوری می‌کند."},"ICON-0677":{"nm":"جداکننده جاقلمی","de":"مداد این طرف، ماژیک فسفری آن طرف، قیچی در خانه‌ی آخر. دهکده‌ای کوچک داخل یک لیوان می‌سازد و جای هر قلم را مشخص می‌کند. وقتی خانه‌بندی هست، دیگر دست سرگردان نمی‌ماند. آغاز یک نظم کوچک روی میز."},"ICON-0678":{"nm":"گیره یادداشت مانیتور","de":"کنار مانیتور آویزان می‌شود و «کار امروز» را دقیقاً روبه‌روی چشم می‌گذارد. تخته‌اعلانات کوچکی که بی‌فرصت فراموشی، رودررو دیده می‌شود. یک گیره، ذهنی را که دائم می‌خواهد کارها را عقب بیندازد، آرام می‌گیرد."},"ICON-0679":{"nm":"سینی تفکیک کشو","de":"گیره کاغذ و کش، پونز و پاک‌کن. به هر قبیله‌ی کوچک داخل کشو اتاقی جداگانه می‌دهد. وقتی دست به خانه‌های تفکیک‌شده می‌رسد، زمان جست‌وجو کم می‌شود و گوشه‌ای از دل سبک‌تر می‌گردد."},"ICON-0680":{"nm":"لوله برس گردگیری","de":"یک ذره گرد و غبار روی لنز، در عکس به لکه‌ای بزرگ تبدیل می‌شود. برای همین، برس همیشه داخل لوله‌اش، تمیز و آماده منتظر است. نوک انگشتی سخت‌کوش که پاکیزگی‌ای را که کسی نمی‌بیند، حفظ می‌کند."},"ICON-0681":{"nm":"گوشه زیرمیزی رومیزی","de":"نرمی‌ای به‌اندازه‌ی یک وجب که گوشه‌ی میز پهن شده. خودکار غلت نمی‌خورد و به‌جای شیشه‌ی سرد، رگه‌ای گرم مچ دست را نگه می‌دارد. کف مهربانی که اول از همه جا می‌دهد، تا نوشته‌های شبی طولانی نلرزند."},"ICON-0682":{"nm":"نگه‌دارنده سیم موس","de":"وقتی سیم گره می‌خورد، انگار جایی از دل هم گره می‌خورد. دستی که از پیش رشته‌ای سرگردان را می‌گیرد و مرتب می‌خواباند. به‌سختی دیده می‌شود، اما بی‌صدا رگه‌ی میز را منظم نگه می‌دارد؛ آراستگی‌ای کوچک و پرتلاش."},"ICON-0683":{"nm":"پایه داک شارژ","de":"دستگاهی را که دراز کشیده بود، کج و راست می‌کند، صفحه بالاخره با چشمانت روبه‌رو می‌شود. حتی زمان انتظار حین شارژ شدن، مرتب می‌گردد. بلند نگه‌داشتن یعنی حتی به چیزی که در حال استراحت است هم قامتی درست دادن."},"ICON-0684":{"nm":"برچسب سطل زباله کوچک","de":"حتی کوچک‌ترین سطل هم اسم خودش را دارد. یک خط «اینجا بریز» روی میزی شلوغ نظمی آرام می‌آورد. برچسب در نهایت سلامی کوچک است که به یک شیء می‌گوید: کاربردت اینجاست."},"ICON-0685":{"nm":"سنجاق برد جداکننده","de":"ورقه‌ای کاغذ را محکم روی برد فشار می‌دهد. سپردن احساسی که نمی‌خواهی فراموش شود، مدتی به دیوار. عزم امروز که به نوک سنجاق آویزان است، در نسیم کمی تکان می‌خورد و هر بار که رد می‌شوی، تو را می‌گیرد."},"ICON-0686":{"nm":"تراشه قاب برچسب","de":"یک قاب مربعی، نوشته‌ای معمولی را به جمله‌ای واضح تبدیل می‌کند. تراشه‌ای که وقاری مرتب دور یادداشت‌های راحت‌پراکنده‌شونده می‌پیچد. زندانی کردن نیست، در آغوش گرفتن حرف‌های مهم است تا گم نشوند."},"ICON-0687":{"nm":"دستگیره کشوی شفاف","de":"به کشویی شفاف دستگیره‌ای وصل کنی، می‌توانی ببینی چه داخلش هست بدون آنکه بی‌احتیاط بازش کنی. فاصله‌ای به‌اندازه‌ی یک وجب: دیده می‌شود اما نزدیک نمی‌شوی. کشو زمزمه می‌کند که شفافیت هم به ادب نیاز دارد."},"ICON-0688":{"nm":"گیره قفل درب","de":"بازش که بگذاری، عطر و رنگش آرام فرار می‌کنند. با یک گیره کوچک که درب را محکم می‌گیرد، رنگ دیروز تا فردا سالم می‌ماند. بستن در واقع، پاسداری از چیزی است که دوستش داری."},"ICON-0689":{"nm":"نگه‌دارنده رطوبت‌گیر","de":"نگهبانی کوچک که از نمی بیزار است و بی‌صدا پاسش را نگه می‌دارد. نزدیک نگه‌داشتن هوای خشک، اولین شرط نگهداری طولانی است؛ این نگه‌دارنده مرتب آرام یادآوری می‌کند. خشکی این‌طور حفظ می‌شود."},"ICON-0690":{"nm":"برچسب سبد نظم‌دهی","de":"یک برچسب اسم کوچک روی هر سبد. وقتی مشخص کنی کدام خانه چه چیزی را در خود دارد، همان زمانی که برای جست‌وجو صرف می‌شد، به زمان استراحت تبدیل می‌شود. مرتب کردن، یادداشتی مهربان است که از پیش به خودِ فردایت می‌دهی."},"ICON-0691":{"nm":"تخته جداکننده کوچک","de":"جداکننده‌ای کوچک که در یک چشم به هم زدن، اتاقکی دنج روی میز برپا می‌کند. با همین یک تخته، گوشه‌ای آرام که کمی از دنیا رو برگردانده پدید می‌آید. جایی دنج و کاملاً از آنِ خودت، مناسب برای نشستن تمرکز."},"ICON-0692":{"nm":"پایه ایستادن پاکت","de":"پایه‌ای که پشت پاکت‌هایی را که دائم می‌افتادند، آرام نگه می‌دارد. فقط با ایستادن مرتب در یک ردیف، انتخاب کردن خیلی راحت‌تر می‌شود. راست ایستادن چیزها، یعنی از پیش به دست بعدی توجه کردن."},"ICON-0693":{"nm":"تراشه نشانگر جای خالی","de":"تراشه‌ای که عمداً خالی‌بودن را نشان می‌دهد. جایی را برای پرشدن باز نگه‌داشتن هم به‌راستی یک برنامه است. جای خالی تنبلی نیست، بلکه فضایی به‌اندازه‌ی یک وجب است که با ادب برای چیزی که به‌زودی می‌رسد باز گذاشته شده."},"ICON-0694":{"nm":"کلاهک روکش مسواک","de":"نسبت به برسی که به دهان می‌رسد، دلی سخت‌گیرتر پیدا می‌کنی. کلاهک کوچکی که حتی یک ذره گرد و غبار را هم راه نمی‌دهد. مراقبت از پاکیزگی‌ای که دیده نمی‌شود، همان توجه کوچکی است که هر صبح را تازه می‌گشاید."},"ICON-0695":{"nm":"توری زیرصابونی","de":"توری‌ای که آرام صابون را بالا نگه می‌دارد تا داخل آب نرم نشود. این حقیقت که رهاکردن آب باعث می‌شود چیزی بیشتر دوام بیاورد، هر روز آرام از پایین‌ترین و کوچک‌ترین گوشه‌ی حمام ثابت می‌شود."},"ICON-0696":{"nm":"گیره پمپ شامپو","de":"سرِ پمپ را آرام نگه می‌دارد تا با یک فشار، فقط مقدار درست بیرون بیاید. عادت صرفه‌جویانه، پایه‌ی خانه‌داری‌ای است که راه دور می‌رود. یک گیره کوچک، ولخرجی را با مهربانی مهار می‌کند."},"ICON-0697":{"nm":"کلاهک آویز خودتراش","de":"به چیزهای تیز، خانه‌ای کوچک جداگانه می‌دهند. خودتراش را داخل کلاهک بگذار و آویزانش کن، هم رطوبت هم خطر با هم می‌ریزد. مراقبت با احتیاط از تیزی، در نهایت راهی هم برای مراقبت از خودت است."},"ICON-0698":{"nm":"حلقه حوله دوش","de":"حوله‌ای دراز که حلقه‌ای می‌سازد و به پشتی که دست به آن نمی‌رسید، می‌رسد. در امتداد همان یک رشته که کف صابون رویش سر می‌خورد، گرمای مهربانِ کسی که خودش پشتش را می‌شست، گرم در سراسر حمام پخش می‌شود."},"ICON-0699":{"nm":"توری فیلتر چاهک","de":"توری کوچکی که آب را رها می‌کند و خرده‌ها را نگه می‌دارد. جایی که کسی نمی‌بیند، بی‌صدا از گرفتگی جلوگیری می‌کند. چیزهایی که در پایین‌ترین جا کار می‌کنند، جریان خانه را حفظ می‌کنند؛ چاهک بی‌کلام همین را یادآوری می‌کند."},"ICON-0700":{"nm":"تخته قلاب مکنده","de":"بدون کوبیدن حتی یک میخ، جای تازه‌ای روی دیوار می‌سازد. فشارش می‌دهی، می‌چسبد؛ می‌کنی، حتی ردی هم نمی‌ماند. هنر مدتی ماندن و بی‌ردپا رفتن—تخته‌ی مکنده این ادب سبک را خوب می‌شناسد."},"ICON-0701":{"nm":"برچسب دمپایی حمام","de":"جفتی که مرتب پیش از آستانه چیده شده. مراقبتِ خانه‌ای که کفش از پا در می‌آورند، با دلسوزی تا درِ حمام هم می‌رسد. برچسبی کوچک، جای این پذیرایی کوچک را که نوکِ سرد پا را گرم می‌کند، آرام مشخص می‌کند."},"ICON-0702":{"nm":"لیوان کوچک دهان‌شویی","de":"لیوانی کوچک و گرد که یک جرعه برای مسواک زدن را در خود جای می‌دهد. در لحظه‌ی کوتاهِ آب دهان کشیدن، آغاز و پایان روز را آرام در آغوش می‌گیرد. پرزرق‌وبرق نیست، اما هر روز کنار توست—سادگی، ماندگارترین خانه‌داری است."},"ICON-0703":{"nm":"آستین گردگیر پرمانند","de":"آستینی که روی پرهای برسی کشیده می‌شود که گویی با نوازش، گرد و غبار را جمع می‌کند. مثل پرنده‌ای که وقتی پرواز نمی‌کند بال‌هایش را آرام می‌خواباند، ابزاری که جای استراحتش را می‌شناسد، مدت‌ها کنار تو می‌ماند."},"ICON-0704":{"nm":"یدک غلتک برچسب‌گیر","de":"یک لایه را که جدا کنی، سطحی تازه و پرزدار زیرش نمایان می‌شود. برگ‌های چسبناکِ درونی که پرز و مو را جمع می‌کنند. در یدکِ گردی که پس از تمام شدن دوباره پر می‌شود، فضیلتِ تکرارِ پرکار پیچیده شده است."},"ICON-0705":{"nm":"گیره‌ی دستمال نظافت","de":"گیره‌ای که دستمال را به جای دست، محکم می‌گیرد. یک وجب فاصله میان کف سرد و انگشتانت می‌گذارد. یک دسته که کارِ ناخوشایند را به جای تو می‌پذیرد، نظافتِ سخت را بسیار سبک‌تر می‌کند."},"ICON-0706":{"nm":"کلاهک برس شکاف‌گیر","de":"کلاهکی کوچک که نوکِ نرمِ برسِ باریکی را که برای نفوذ در شکاف‌های تنگ ساخته شده، محافظت می‌کند. قلبی که حتی گوشه‌هایی را که دست به آن‌ها نمی‌رسد مراقبت می‌کند. کسی که جاهای نادیده را تمیز می‌کند، آغوشِ خانه را یک وجب بزرگ‌تر می‌کند."},"ICON-0707":{"nm":"حلقه برچسب بطری اسپری","de":"برچسبی کوچک که نرم روی شانه‌ی بطری اسپری نشسته. اینکه درونش آب زلال است یا مواد شوینده، در یک خط روشن می‌گوید. برچسبی که سردرگمی را از پیش پاک می‌کند، عادتِ دیرینه‌ی خانه‌داری چابک‌دست است."},"ICON-0708":{"nm":"نوار یدک دستمال‌کاغذی","de":"نواری که رول تازه را در جای خالی جا می‌دهد و محکم می‌بندد. ساده‌ترین لمسی که چیزِ بریده‌شده را دوباره پیوند می‌زند. دلِ کسی که پیش از تمام شدن، از پیش پر می‌کند، در این حلقه‌ی کوچک به دور خودش پیچیده است."},"ICON-0709":{"nm":"قلاب دستکش نظافت","de":"قلابی که دستکش خیس را درست پس از پایان کارِ آب‌ودار، آویزان می‌کند تا خشک شود. به دست‌های زحمت‌کشیده لحظه‌ای جای استراحت می‌دهد. تا رطوبت آرام‌آرام خشک شود، وقفه‌ای کوتاه برای گرفتنِ نفس پیش از کار بعدی است."},"ICON-0710":{"nm":"سنجاق آویز جارو","de":"اگر جارو را وارونه آویزان کنی، موهایش خم نمی‌شود و راست می‌ماند. حالتی که ایستاده منتظرِ حیاطِ بعدی می‌ماند. جایی کوچک اما محکم که کمک می‌کند حتی پس از پایانِ کارش، شکل خودش را نگه دارد."},"ICON-0711":{"nm":"گیره‌ی کیسه زباله","de":"دهانه‌ی کیسه را محکم می‌گزد و بدون کوچک‌ترین نشتی، آن را سفت می‌بندد. یک لمسِ آخر که سرِ کیسه را محکم می‌بندد، جمع‌وجورکردن را بسیار مرتب‌تر می‌کند. تمام کردن، در نهایت، از خوب بستن آغاز می‌شود."},"ICON-0712":{"nm":"ظرف گیره‌ی رخت","de":"ظرفی که گیره‌های رخت، که وقتی پراکنده شوند به‌آسانی گم می‌شوند، در آن با هم زندگی می‌کنند. به چیزهای کوچک، خانه‌ای مشترک برای ماندن می‌دهد. سربازانِ کوچکِ نوکِ انگشتانت را در یک‌جا جمع کن تا وقت لازم، یک‌نگاه پیدایشان کنی."},"ICON-0713":{"nm":"حلقه‌ی جفت‌کردن جوراب","de":"جورابِ تک‌مانده همیشه یواشکی جایی گم می‌شود. اگر پیش از شستن هر جفت را با حلقه‌ای ببندی، حتی پس از خشک‌شدنِ نرم و پرزدار، آن دو از هم جدا نمی‌شوند. دسته‌بندی، وعده‌ای کوچک است که از پیش جلوی گم‌شدن را می‌گیرد."},"ICON-0714":{"nm":"کیسه‌ی توپ لباسشویی","de":"درون ماشین لباسشویی می‌غلتد و آلودگیِ جاگرفته در لباس را با ضربه‌های آرام بیدار می‌کند. ریتمی که با تن گردش، رخت را نوازش می‌کند. میان جریانِ خروشانِ آب، غریزه‌ی دیرینه‌ی شست‌وشو—ضربه‌زدن—را در کیسه‌ای پیچیده و می‌غلتاند."},"ICON-0715":{"nm":"درپوش پیمانه‌ی شوینده پشمی","de":"به لباس‌های ظریف، اندازه‌ای به همان ظرافت. درپوشی که دقیقاً یک درِ کامل از شوینده‌ی پشمی را با ظرافت اندازه می‌گیرد. در یک خط کوچک، لمسِ محتاطانه‌ی برخورد با پشم نهفته است. کم کردنِ زیاده‌روی هم، خود نوعی دلسوزی است."},"ICON-0716":{"nm":"وصله‌ی مرمت پارچه","de":"وصله‌ای کوچک که آرام روی جای فرسوده گذاشته می‌شود. دلِ نوکِ انگشتی که جای ساییده را با غفلت دور نمی‌اندازد، بلکه آرام مراقبتش می‌کند. در هر جای وصله‌شده، نقشِ سال‌هایی که با آن لباس گذشته، به‌ظرافت باقی می‌ماند."},"ICON-0717":{"nm":"سنجاق ثابت‌کننده جادرختی","de":"سنجاقی که آرام جادرختی را نگه می‌دارد تا رخت با باد ناگهان پرواز نکند. حتی در روزهایی که رخت زیر آفتاب موج می‌زند، کمک می‌کند در میان تکان‌خوردن، جایش را حفظ کند. سهمِ یک وزنه‌ی تعادلِ کوچک اما مطمئن."},"ICON-0718":{"nm":"برچسب کیسه‌توری لباس‌زیر","de":"لباس‌زیرِ ظریف را جداگانه درون توری می‌شویند. توری که چیزهای نرم را از جریان خروشانِ آب، محکم در آغوش می‌گیرد. یک کیسه‌ی کوچکِ برچسب‌دار یادآوری می‌کند که محافظتِ محتاطانه از چیزِ شکننده هم، خود خانه‌داری است."},"ICON-0719":{"nm":"آویز قاشق شوینده","de":"قاشقِ برداشتنِ شوینده‌ی پودری را مرتب روی دیوار آویزان کن. بدون دردسرِ افتادنش در ظرف و خیس‌شدنِ دست. عادتِ منظمِ نگه‌داشتنِ ابزار همیشه در یک جای ثابت، محکم در این آویزِ کوچک جای گرفته است."},"ICON-0720":{"nm":"توقف‌گیر بند رخت","de":"انتهای بندِ رخت را محکم می‌گزد تا حتی با بارِ سنگینِ رخت، شل و رها نشود. گره‌ی آخری که تا انتها تاب می‌آورد تا بندِ کشیده افتاده نشود. یک پایانِ محکم، به همین وابسته است."},"ICON-0721":{"nm":"برچسب روبالشی","de":"جایی که هر شب گونه اول از همه به آن می‌رسد، با برچسبی به اندازه‌ی ناخن در پشتش دوخته شده. حروف ریزِ دمای شست‌وشو را چه کسی می‌خواند؟ با این‌همه، نزدیک‌ترین راهنماست که کنارِ چهره‌ی خوابیده پاس می‌دهد."},"ICON-0722":{"nm":"گیره‌ی پتو","de":"شبی که پنجره باز مانده، حتی اگر باد بیاید، پتو فرار نمی‌کند. چون گیره‌ای با دهانِ محکم بسته، گوشه‌اش را گاز گرفته. دستی بی‌کلام که به جای خوابیده، لبه را نگه می‌دارد."},"ICON-0723":{"nm":"تخته‌ی سایه‌بان چراغ‌خواب","de":"«اگر نور به چشم برسد، خواب دور می‌شود.» با یک تخته‌ی سایه‌بان که کسی یواشکی بر پا کرده، نور عقب می‌نشیند و فقط پاییِ تخت را کمی خیس می‌کند. حائلی کوچک که یک وجب تاریکی قرض می‌دهد."},"ICON-0724":{"nm":"جیب شکاف کنار تخت","de":"آن شکاف میان تشک و دیوار را به یاد بیاور، جایی که دست هرگز نمی‌رسید. کنترلی که غلتید و افتاد، عینکی هم، حالا همین‌جا جمع می‌شوند. جیبی که تخت آرام باز می‌کند تا چیزهایی را که نزدیک بود گم شوند، بگیرد."},"ICON-0725":{"nm":"سینی نگه‌داری عینک","de":"عینک را که برداری، دنیا نرم محو می‌شود، و بشقابی کم‌عمق آن بی‌دفاعیِ لحظه‌ای را می‌پذیرد. صبح، حتی بدون آنکه انگشت‌ها کورمال‌کورمال بگردند، عینک همیشه در همان جا منتظر است."},"ICON-0726":{"nm":"پایه‌ی ساعت زنگ‌دار","de":"ساعت شش صبح، روی پایه‌ای محکم که منفورترین صدا از آن بلند می‌شود. بی‌لرزش، ساعت را نگه می‌دارد و در نهایت، روزِ کسی را می‌گشاید. بی‌کلام، وعده‌ی خشنِ بیدارشدن را بر دوش می‌کشد."},"ICON-0727":{"nm":"نگه‌دارنده کابل کنار بالش","de":"کابلِ شارژی که پیش‌تر از کنار تخت‌خواب سُر می‌خورد، دیگر روی زمین نمی‌افتد. چون نگه‌دارنده‌ای کوچک، سرِ سیم را آرام می‌گیرد. فاصله‌ای که فقط دست‌درازکردن می‌طلبد—لمسی که مسیرِ شب را مرتب کرده."},"ICON-0728":{"nm":"نوار نگه‌داری لباس‌خواب","de":"نواری که یک دور به دور لباس‌خوابِ تا‌شده‌ی مرتب می‌پیچد و می‌بندد. حتی نرمیِ آسان‌آشفته هم به آراستگی نیاز دارد. برای من فردا شب، منِ امروز آن را مرتب لوله می‌کند—آمادگی‌ای کوچک."},"ICON-0729":{"nm":"نگه‌دارنده کارت خوشبو","de":"کارتی خوشبو را کج بگذار و مثل ورق‌زدنِ صفحه، فصل را با نوکِ بینی ورق می‌زنی. از اسطوخودوس تا مرکبات—دفتر خاطراتِ آن روز می‌شود که با بو نوشته شده."},"ICON-0730":{"nm":"پد بشقاب کلید","de":"گوشه‌ای از ورودی، جایی که کلیدها با صدای جرینگ می‌افتادند. بشقابی با پدِ نرم، آن صدای تیز را می‌بلعد. اولین حرکتِ کسی که برگشته را، پایه‌ای کوچک آرام می‌پذیرد."},"ICON-0731":{"nm":"کلاهک قطره‌گیر چتر","de":"از نوکِ چتری که به داخل آورده‌ای، آب باران قطره‌قطره می‌چکد. یک کلاهک آن چکه را مرتب می‌گیرد، پس گویی کسی از پیش، حوضچه‌ی کوچکی را که یواشکی روی زمینِ چوبی پخش می‌شد، حدس زده و جلویش را گرفته."},"ICON-0732":{"nm":"تراشه آویز ماسک","de":"تراشه‌ای به اندازه‌ی ناخن، چسبیده به دیوارِ کنارِ ورودی. مثل آخرین آیینِ بیرون‌رفتن، ماسک اینجا آویزان می‌شود. دستگاهِ حافظه‌ی کوچکی که کنار در، ارتفاعِ نگاه را نگه می‌دارد تا چیزی که باید برداری از یاد نرود."},"ICON-0733":{"nm":"غلاف محافظ کاتر بسته‌پستی","de":"پوششِ محافظی که روی تیغِ بازکننده‌ی جعبه‌های پستی کشیده می‌شود. خطرِ بریدگیِ پنهان پشتِ هیجانِ بازکردن بسته را آرام می‌پوشاند. توجهی نامرئی که پایانِ انتظار را ایمن می‌گشاید."},"ICON-0734":{"nm":"پایه‌ی برس کفش","de":"جایی که برسِ کفشِ تازه‌کاربردهْ خیس گذاشته می‌شود. حتی با نگه‌داشتنِ رطوبت، کف خشک و مرتب می‌ماند. پایه‌ای کوچک یادآوری می‌کند که حتی ابزارِ سازنده‌ی پاکیزگی هم، جایی برای استراحت لازم دارد."},"ICON-0735":{"nm":"تخته‌یادداشت مهمان","de":"«یک لحظه سر زدم و رفتم.» خطی کوتاه که روی تخته‌یادداشتِ ورودی باقی مانده. میدانی کوچک که آدم‌هایی که همدیگر را جا انداخته‌اند، از میانِ زمان با هم به اشتراک می‌گذارند. روی یک خانه‌ی کاغذ، احوال‌پرسی، خواهش و یک قلب روی هم انباشته می‌شود."},"ICON-0736":{"nm":"رول بندِ کشِ درزِ در","de":"هوای سردی که از شکافِ به‌اندازه‌ی انگشتِ زیرِ در نفوذ می‌کرد. بندِ کشِ لوله‌شده آرام آن گذرگاه را می‌بندد. گرمایی را که نادیدنی به بیرون نشت می‌کرد، یک لایه‌ی دیگر در اتاق نگه می‌دارد."},"ICON-0737":{"nm":"آویز نگه‌دارنده در","de":"آویزی کوچک که پایینِ درِ کاملاً بازشده را نگه می‌دارد تا دوباره بسته نشود. برای بادِ رفت‌وآمد و صدای قدم‌ها، سنگین‌وزن جایش را حفظ می‌کند. لجاجتی مهربانانه که بازبودن را ادامه می‌دهد."},"ICON-0738":{"nm":"روکش کلید چراغ ورودی","de":"کلیدِ ورودی که در شبِ دیرهنگام کورمال‌کورمال دنبالش می‌گشتی. روکشی شب‌تاب، آرام در تاریکی جایش را نشان می‌دهد. تا دست سرگردان نشود—راهنمایی کوچک که پیش از روشن‌شدنِ نور، خودش اول می‌درخشد."},"ICON-0739":{"nm":"پد نگه‌دارنده لیوان","de":"لحظه‌ای که لیوانِ گذاشته‌شده روی میز شروع به سُرخوردن می‌کند، یک پد آرام پایه‌اش را می‌گیرد. زیرلیوانی‌ای که آرام جایش را حفظ می‌کند، حتی وقتی قطره‌های آب می‌نشینند، هیچ اثری باقی نمی‌گذارد."},"ICON-0740":{"nm":"کلیپس خوشبوکننده خودرو","de":"کلیپسِ خوشبوکننده‌ی کوچکی که داخل ماشین آویزان است. سوار بر بادِ دریچه‌ی کولر، عطری ملایم آرام‌آرام فضای تنگ را پر می‌کند. آسایشی مهربان در صندلی راننده، که حتی خستگیِ توقف پشت چراغ قرمز را با عطر گرم می‌کند."},"ICON-0741":{"nm":"روکش کمربند ایمنی","de":"روکشی نرم که روی کمربندِ گذرنده از شانه کشیده می‌شود. زبریِ برخوردکننده با پشتِ گردن، آرام‌آرام محو می‌شود. حتی بندی برای ایمنی هم می‌تواند مهربانی بگیرد، این یک وجب پارچه می‌گوید."},"ICON-0742":{"nm":"تخته پوشش شماره پارکینگ","de":"تخته‌ای که پیش از عکس‌گرفتن، آرام تابلوی شماره‌ای را که جای پارکِ تو را در پارکینگِ زیرزمینی نشان می‌داد، می‌پوشاند. هر کسی اطلاعاتی دارد که نمی‌خواهد باقی بماند. لایه‌ای که با احتیاط از یک صحنه‌ی روزمره پاک می‌شود."},"ICON-0743":{"nm":"کلاهک زنگ دوچرخه","de":"ترینگ‌ترینگ. سلامِ روشنی که دوچرخه در پیچِ کوچه می‌دهد. کلاهکی روی زنگ، حتی در باران، آن صدا را نگه می‌دارد. با یک زنگِ کوچک، مردم لبخند می‌زنند و یک قدم کنار می‌روند."},"ICON-0744":{"nm":"حلقه دستگیره فرمان","de":"حلقه‌ای که لمسِ فرمان در کف دست را نرم می‌پیچد. حتی پس از مدت‌ها گرفتن و راندن، دست بی‌حس نمی‌شود. هر چه راه دورتر باشد، راحتیِ جایی که می‌گیری، آن فاصله را کوتاه‌تر می‌کند."},"ICON-0745":{"nm":"استیکر برچسب کلاه‌ایمنی","de":"استیکرِ اسمی که داخلِ کلاه‌ایمنی چسبانده شده. میانِ کلاه‌های ایمنیِ یکسان، آرام فریاد می‌زند «این مالِ من است». شخصی‌ترین نشانه، حکاکی‌شده روی محکمیِ که سرت را حفاظت می‌کند."},"ICON-0746":{"nm":"کلاهک بازتاب‌دهنده چرخ","de":"کلاهکی که تازه با غروبِ آفتاب کارش را آغاز می‌کند. نورِ عبوری را می‌گیرد و چرخ را روشن بازمی‌تاباند. در تاریکی، با نور، پیام کوچکی می‌فرستد: «اینجا کسی هست.»"},"ICON-0747":{"nm":"کیف محافظ سوییچ خودرو","de":"سوییچی که در جیب، برخورد با کلیدهای دیگر، خط‌وخش می‌انداخت. کیفی نرم، آن سطح را محکم می‌پیچد. آرزوی اینکه چیزی که هر روز در دست می‌گیری، بدون خراش، عمر طولانی داشته باشد، در آن جای گرفته."},"ICON-0748":{"nm":"سنجاق قفسه مکشی","de":"سنجاق قفسه‌ی مکشی که بدون کوبیدنِ حتی یک میخ، به دیوار می‌چسبد. حتی دیواری که نمی‌خواهی رویش اثری بگذاری، یک خانه‌ی انبار پیدا می‌کند. مهارتی بی‌رد که در اتاقی که موقتاً در آن مانده‌ای، خانه‌داری آویزان می‌کند."},"ICON-0749":{"nm":"تخته‌قلاب بدون سوراخ‌کاری","de":"باورت می‌شود می‌توان چیزی را بدون سوراخ‌کردنِ دیوار آویزان کرد؟ تخته‌قلابِ بدون سوراخ‌کاری، یواشکی باری سبک را بر عهده می‌گیرد. دلِ نگرانِ آسیب‌نرساندن به فضایی قرضی، به‌ظرافت در یک قلابِ کوچک جای گرفته."},"ICON-0750":{"nm":"میله‌ی مرتب‌ساز مغناطیسی","de":"صدای «تیک»ی که فلز درست سرِ جایش می‌چسبد. ابزارهای ریزِ پراکنده در هر گوشه را با آهنربا یک‌ضرب جمع کن، و لذتی کوچک از پیِ آن می‌آید که میزِ کارِ آشفته، یک‌ردیف مرتب می‌شود."},"ICON-0751":{"nm":"میله‌ی نگه‌دارنده شکاف","de":"آن شکافِ باریکِ فراموش‌شده میان یخچال و دیوار را تصور کن. میله‌ای باریک آن فاصله را با کاربرد پر می‌کند. ایده‌ای صرفه‌جویانه که از فضایی که بی‌فایده پنداشته می‌شد، جای انبار بیرون می‌کشد."},"ICON-0752":{"nm":"ورق پد چسبی","de":"ورق پد چسبی که یک بار بچسبانی، حتی چیز سنگین را هم به‌آسانی نگه می‌دارد. جدا کنی، به‌طرزی شگفت‌انگیز، هیچ اثری باقی نمی‌ماند. نیرویی آرام و سرسخت که در جایی نادیده، وزن را تاب می‌آورد."},"ICON-0753":{"nm":"کلاهک قلاب روی‌در","de":"کلاهک قلابی که فقط باید سبک روی لبِ در آویزان شود. کیف هم، حوله هم، درست در ارتفاعِ دستِ در دسترس آویزان می‌شوند. آویزی که بدون یک میخ به دنیا آمده، به فضایی تنگ، یک وجب آسودگیِ بیشتر می‌افزاید."},"ICON-0754":{"nm":"گیره دیواری کابل","de":"گیره‌ای که سیم‌های آویزان روی دیوار را در یک خط مرتب جمع می‌کند. کلافِ درهم‌پیچیده‌ی پشتِ میز، به خطی تمیز صاف می‌شود. مرتب‌سازیِ نادیده، حتی هوایِ اتاق را سبک‌تر می‌کند."},"ICON-0755":{"nm":"پد پایه چراغ‌رومیزی","de":"پدی که آرام زیرِ پای چراغِ رومیزی گذاشته می‌شود. روی میز خراشی به‌جا نمی‌گذارد و حتی ریزترین لرزش را هم آرام می‌کند. حتی برای برافراشتنِ نور هم، اول باید کفی باشد که نلرزد."},"ICON-0756":{"nm":"صفحه چسبی ضدلغزش","de":"فرشی که زیرِ پا یواشکی جابه‌جا می‌شد، بالاخره سرِ جایش می‌ایستد، چون صفحه‌ی چسبی زمین را محکم می‌گزد. تورِ ایمنیِ نادیده که لحظه‌ی نزدیک‌به‌افتادن را از پیش، آرام برمی‌دارد."},"ICON-0757":{"nm":"کلاهک پیچ‌گوشتی دقیق","de":"«این یک پیچِ کوچک باز نمی‌شود.» کلاهکی که روی نوکِ پیچ‌گوشتیِ دقیق کشیده شده، تیغه را حفاظت می‌کند. ظریف‌ترین ابزارِ نوکِ انگشتان، که دنیای به‌اندازه‌ی کفِ دست را درونِ یک دستگاه می‌گشاید."},"ICON-0758":{"nm":"حلقه آچار آلن","de":"حلقه‌ای که چند آچار آلن را به یک حلقه می‌کشد و می‌بندد. فلزی که به ترتیب اندازه ردیف شده، مثل بادبزن با یک تکان باز می‌شود. ریتمِ مرتبِ دستی که در یک حرکت، درست همان یکی موردنیاز را انتخاب می‌کند."},"ICON-0759":{"nm":"آویز متر جیبی","de":"آویزی وصل‌شده به متر جیبی‌ای که دقیقاً در کفِ دست جا می‌شود. از دسته‌کلید آویزان است و هر جا می‌روی همراهت می‌آید. دوستی کوچک که هر طولی را که ناگهان کنجکاوت می‌کند، همان‌جا اندازه می‌گیرد و پاسخ می‌دهد."},"ICON-0760":{"nm":"جعبه‌ی دسته‌بندی پیچ","de":"جعبه‌ی دسته‌بندی‌ای که پیچ‌های نامتجانس، هر کدام خانه‌ی خودشان را پیدا می‌کنند. حتی قطعاتِ ریزی که پیش‌تر درهم‌ومغشوش می‌غلتیدند، نظم می‌یابند. دستی که پیش از تعمیرِ چیزی، اول مرتب‌کردن را می‌آموزد."},"ICON-0761":{"nm":"کلاهک نازل چسب","de":"بسته بمانم، سفت نمی‌شوم؛ باز بمانم، خشک می‌شوم—من در همین میانه زندگی می‌کنم. با هر قطره‌ای که می‌چکد، جایی چیزی شکسته دوباره به هم می‌پیوندد. یک درپوش کوچک، آرام مرزِ میانِ سکون و جریان را نگهبانی می‌کند."},"ICON-0762":{"nm":"جاکلیدی تراز","de":"صداقتی به اندازه‌ی کفِ دست که از انتهای دسته‌کلید آویزان است. همیشه همین حبابِ کوچک اولین کسی است که قفسه‌ای کج را متوجه می‌شود. دوستی را در جیب می‌گذارم که آرام به من می‌گوید دنیا کمی کج شده."},"ICON-0763":{"nm":"کلاهک محافظ موچین","de":"هر چه چیزی نوک‌تیزتر باشد، بیشتر به لباسی برای آرام‌کردنش نیاز دارد. نوک را آرام بپوشان تا نه دست آسیب ببیند و نه قطعات. اولین ادبِ برخورد با چیزِ تیز، پوشاندنِ آرامِ نوکِ آن است—و این کلاهکِ کوچک، آن مهربانی را بر عهده می‌گیرد."},"ICON-0764":{"nm":"زیرانداز کوچک برش","de":"تخته‌ای که زخم‌هایش پس از هزاران بار عبورِ تیغه هم خودش التیام می‌یابند. کارِ بعدی دوباره روی جای بریده گذاشته می‌شود، و دوباره التیام می‌یابد. کفی خاموش که تن خودش را می‌دهد تا چیزهای دیگر تمیز بریده شوند."},"ICON-0765":{"nm":"کیسه‌ی قطعات تعمیر","de":"کیسه‌ای که دهانش را می‌بندد تا یک پیچ، یک فنر، برای همیشه گم نشود. چیزهای کوچکِ باقی‌مانده پس از تعمیر، اینجا آرام منتظرِ نوبتِ بعدی‌شان می‌مانند. همیشه همین خانه‌های ناچیز و کوچک است که جلوی گم‌شدن را می‌گیرد."},"ICON-0766":{"nm":"گیره‌ی بسته‌ی تنقلات","de":"نگه‌داشتنِ ترد‌بودنِ بسته‌ی بازشده، در نهایت به یک گازِ قاطع خلاصه می‌شود. وعده‌ای کوچک برای اینکه هیچ فرصتی برای نم‌کشیدن نگذارد. عادتِ گازگرفتنِ محکمِ سرِ بسته، تنقلاتِ فردا را نجات می‌دهد."},"ICON-0767":{"nm":"لیوان تقسیم ژله","de":"برای تقسیمِ یک بسته میان چند نفر، اول باید عادلانه جدایش کرد. دلی که در هر لیوانِ کوچک، سهمی برابر می‌ریزد. باور دارم که سهیم‌شدن، از سهمی درست برابر آغاز می‌شود، طوری که کسی دلگیر نشود."},"ICON-0768":{"nm":"تکه فویل شکلات","de":"نقره‌ای که شیرینی را پیچیده بود، زیرِ نوکِ انگشت به‌آسانی چروک می‌خورد. صافش کنی، لحظه‌ای برق می‌زند؛ تایش کنی، خاطره می‌شود. تکه‌ای از نور که فقط پس از خورده‌شدن، زیباترین می‌شود—پیش از دورانداختن، یک‌بارِ دیگر نگاهش کن."},"ICON-0769":{"nm":"نوار برچسب تنقلات","de":"چه چیزی درونش هست، تا کِی خوب می‌ماند—به‌جای بسته‌ی خاموش، من می‌گویم. لحظه‌ای که یک نوارِ خطی چسبانده می‌شود، حتی تنقلات هم اسم و وعده می‌گیرند. دسته‌بندی، در واقع، مهربان‌ترین شیوه‌ی به‌خاطرسپردن است."},"ICON-0770":{"nm":"جعبه دسته‌بندی آبنبات","de":"ترش‌ها و شیرین‌ها را در یک خانه نمی‌گذاریم. کاری که از پیش انجام می‌شود تا دست دودل نماند. وقتی جعبه‌های کوچک ردیف می‌شوند، لذتِ انتخاب‌کردن یواشکی دوبرابر می‌شود."},"ICON-0771":{"nm":"کاغذ ضربه‌گیر کوکی","de":"کاغذی نازک که میانِ کوکی‌ها گذاشته می‌شود تا در راه کبود نشوند. هر چه چیزی شکننده‌تر باشد، به همراهیِ نرم‌تری نیاز دارد. گاهی نرمی، بهتر از سختی محافظت می‌کند."},"ICON-0772":{"nm":"نخ جعبه دونات","de":"گرهی ضربدری، مسئولِ سالم‌رسیدنِ کیکِ داخلِ جعبه است. دسته می‌شود، مهر می‌شود، نشانه‌ی انتظارِ پرشوق می‌شود. لحظه‌ای که این نخ باز می‌شود، همان تولدِ کسی است."},"ICON-0773":{"nm":"گیره‌ی بسته‌ی نان","de":"یک‌بار پیچ‌بزن، تا کن و مرا سرِ بسته بگذار، تا نرمیِ نان تا صبحِ فردا مهر بماند. لجاجتی کوچک و سرسخت که هوا را بیرون نگه می‌دارد. نگه‌داشتنِ چیزی نرم برای مدتی طولانی، همیشه کارِ چیزی محکم است."},"ICON-0774":{"nm":"برچسب مبادله تنقلات","de":"سهمِ تو برای من، سهمِ من برای تو. یادت هست آن هیجانِ روزی که اسم‌ها را روی برچسب‌های کوچک می‌نوشتیم و تنقلات را عوض می‌کردیم؟ کاغذی که به دلِ سهیم‌شدن می‌چسبد، همیشه اسمِ یک دوست را با خطی زیبا رویش دارد."},"ICON-0775":{"nm":"کلاهک درپوش نی","de":"وقتی برای لحظه‌ای میانِ جرعه‌ها مکث می‌کنی، مرا می‌بندی. تا چیزی نریزد، تا سرد نشود، تا همان‌جا آرام منتظر بماند. کارِ درپوشِ کوچکی که برای لحظه‌ی بازگشتِ لب‌ها، دهانه را نگهبانی می‌کند."},"ICON-0776":{"nm":"حلقه‌ی اسم لیوان سفری","de":"حلقه‌ای کوچک که میانِ ردیفی از لیوان‌های سفری کنارِ هم می‌گوید «این مالِ من است». با یک رنگ، اشتباه‌گرفتن آرام‌آرام حل می‌شود. یک حلقه برای نشان‌دادنِ اینکه چه چیزی مالِ توست، به‌قدرِ کافی روشن است."},"ICON-0777":{"nm":"آستین نگه‌دارنده لیوان","de":"یک لایه از مقوای موج‌دار که یواشکی میانِ لیوانِ داغ و کفِ دست جا می‌گیرد. توجهی که چیده شده تا نه بسوزی و نه دستت بلغزد. حفاظت از فاصله‌ی میانی، همان چیزی است که یک فنجانِ سالم را کامل می‌کند."},"ICON-0778":{"nm":"برچسب قالب یخ","de":"کسانی هستند که تاریخِ ساختنِ هر دسته یخ را می‌نویسند. با این باور که حتی سرما هم نظمی دارد. یک برچسبِ کوچک، زمانِ فریزر را با صداقت، نوبت‌به‌نوبت جاری می‌کند."},"ICON-0779":{"nm":"انبرک کیسه چای","de":"زمانِ دم‌کشیدن را زیر نظر می‌گیری، و درست در لحظه‌ی مناسب بیرونش می‌کشی. مهارتِ دست که می‌داند پیش از تلخ‌شدنِ زیاد، کِی متوقف شود. عمقِ چای را نه مدتِ دم‌کردن، که زمانِ بیرون‌کشیدن تعیین می‌کند."},"ICON-0780":{"nm":"پایه‌ی فیلتر دریپ","de":"فیلتر را نگه می‌دارد و خاموش می‌ایستد تا آبِ داغ آرام‌آرام پایین بریزد. به‌خوبی می‌داند که عجله، عطر را کم‌رنگ می‌کند. حتی نگه‌داشتنِ صبر هم، به ایستادنی بی‌لرزش نیاز دارد."},"ICON-0781":{"nm":"بند بطری","de":"بندی که بطریِ آب را به مچ یا شانه آویزان می‌کند تا با تو راه برود. شیوه‌ای از همراهی که بدون آنکه لازم باشد عمداً همراه ببری، همیشه کنارت نگهش می‌دارد. برای فراموش‌نکردن، گاهی یک گره‌ی کوچک، مهربان‌ترین راه است."},"ICON-0782":{"nm":"درپوش قوطی نوشابه","de":"دهانه‌ی قوطیِ نیمه‌خورده را می‌پوشاند تا از گرد و افتِ گاز جلوگیری کند. کلاهکی کوچک که تا جرعه‌ی بعدی، مسئولِ تازگی است. حتی پوشاندنِ آرامِ چیزی که لحظه‌ای باز مانده، ذره‌ای دلسوزی دارد."},"ICON-0783":{"nm":"نگه‌دارنده کوپن نوشیدنی","de":"فنجانِ رایگانِ دهم—آن وعده را در آغوش می‌گیرد تا کارتِ مهر گم نشود. تا روزهایی که خانه‌به‌خانه پر شده‌اند، چروک نخورند. درونِ این نگه‌دارنده، قدم‌های پرکارِ مشتری‌ای که مدام سر می‌زند، انباشته می‌شود."},"ICON-0784":{"nm":"بند جعبه ناهار","de":"بندی که یک دور، جعبه‌ی ناهار را محکم در آغوش می‌گیرد تا درب باز نشود. اطمینانی کوچک از اینکه هیچ آبگوشتی داخلِ کیف نشت نمی‌کند. سالم‌رسیدن تا وقتِ ناهار، بر عهده‌ی همین یک‌دورِ محکم است."},"ICON-0785":{"nm":"ست لیوان‌های خوراکی جانبی","de":"به هر خوراکِ جانبی جای خودش را بده، تا طعم‌ها با هم مخلوط نشوند. کیمچی از آنِ کیمچی، سبزی از آنِ سبزی، هر کدام واضح. تقسیم‌بندیِ خانه‌ای که این لیوان‌های کوچک ساخته‌اند، هم نظمِ جعبه‌ی ناهار است، هم مهربانی روی دستِ آشپز."},"ICON-0786":{"nm":"جعبه چاپ‌استیک","de":"خانه‌ای کوچک که چاپ‌استیک‌هایی را که هر سه وعده‌ی روز را همراهی کرده‌اند، تمیز نگه می‌دارد و همراه می‌برد. همراهی خاموش که حتی درونِ کیفِ مدرسه هم مرتب می‌ماند. همان دلِ همراه‌بردن، در نهایت، وعده‌ای آراسته می‌سازد."},"ICON-0787":{"nm":"برچسب بطری سس","de":"سویا یا سرکه؟ به بطری‌ای که پیش‌تر اشتباه می‌گرفتی، وضوح می‌بخشد. لحظه‌ای که یک خط چسبانده می‌شود، دودلیِ نوکِ انگشت ناپدید می‌شود. سرعتِ آشپزخانه‌ی شلوغ، آرام با همین نشانه‌های کوچک ساخته می‌شود."},"ICON-0788":{"nm":"ورق پیچیدن کیمباپ","de":"ورقی نازک از جلبک که برنج و مواد داخل را در یک تن می‌پیچد. باید محکم پیچید تا هنگامِ برش، از هم نپاشد. هیجانِ صبحِ روزِ پیک‌نیک، درست از این یک لایه، گرد پیچیده بیرون می‌آید."},"ICON-0789":{"nm":"جاچوب‌های سیخ","de":"سیخ‌ها و خلال‌دندان‌ها را در یک جا بایست کن، تا لحظه‌ی لازم، دست سرگردان نشود. حتی به چیزهای نوک‌تیز هم خانه‌ای ثابت بده. مرتب‌سازی، در نهایت، مهربانیِ کوچکی برای دستی است که بعداً دراز می‌شود."},"ICON-0790":{"nm":"روکش کیف یخ","de":"برای نگه‌داشتنِ کمی بیشترِ سرما، کیف یخ را در یک لایه‌ی دیگر می‌پیچانی. همراهش، جلوگیری از خیس‌شدنِ کیف با میعان هم می‌آید. نگه‌داشتنِ خنکی تا آخرین لحظه، همیشه کارِ همین یک لایه‌ی ضخیم است."},"ICON-0791":{"nm":"جداکننده جعبه ناهار","de":"دیواری کوچک که برپا شده تا برنج و خوراکی‌های جانبی به قلمروِ هم تجاوز نکنند. آرامشِ یک خانه که آبگوشت از آن سرریز نمی‌شود. جعبه‌ی ناهارِ خانه‌خانه‌شده، دلِ دقیقِ سازنده‌اش را دست‌نخورده در خود نگه می‌دارد."},"ICON-0792":{"nm":"کارت ترتیب غذا","de":"از سوپ شروع کنیم یا از برنج؟ کارتی که آرام مسیرِ امروز را پیشنهاد می‌کند. راهنمایی مهربان که می‌گوید خوردن به‌ترتیب، خوش‌طعم‌تر است. آرام یادآوری می‌کند که حتی یک وعده‌غذا هم، مثلِ یک داستان، جریانی دارد."},"ICON-0793":{"nm":"استیکر لیوان اندازه‌گیری","de":"استیکری کوچک کنارِ خط‌کشی، دقیقاً می‌گوید «تا همین‌جا». نشانه‌ای که مقداری را که همیشه اشتباه می‌گرفتی، یک‌باره درست می‌کند. دقت، از یک خط‌راهنمای کوچکِ اینچنینی سرچشمه می‌گیرد."},"ICON-0794":{"nm":"دسته سیلیکونی درب","de":"دسته‌ای کوچک که اجازه می‌دهد درِ داغ را بدون سوزاندنِ انگشتان بلند کنی. آرام شجاعتِ بازکردنِ قابلمه‌ی بخارگرفته را به تو قرض می‌دهد. ایمنی همیشه از آماده‌کردنِ از پیشِ جایی برای گرفتن می‌آید."},"ICON-0795":{"nm":"آویز گیره کوچک","de":"گیره‌ای کوچک که به دستمال یا کیسه، جایی می‌دهد که قبلاً جایی برای آویزان‌شدن نداشتند. تکه‌ای شلوغِ دیوار را به منظره‌ای مرتب تبدیل می‌کند. یک عادتِ آویزان‌کردن، آشپزخانه را همان‌قدر سبک‌تر می‌کند."},"ICON-0796":{"nm":"کلاهک برس روغن","de":"نوکِ برسِ روغن‌مالی را که بپوشانی، هم گرد و غبار و هم سفت‌شدن از آن دور می‌مانند. کلاهکی که آن نرمی را تا غذای بعدی نگه می‌دارد. مراقبتِ کوچک از ابزار، در نهایت، طعم را برای مدتی طولانی حفظ می‌کند."},"ICON-0797":{"nm":"ظرف قاشق نمک","de":"قاشقِ کوچکی که درونِ ظرفِ نمک زندگی می‌کند. هر بار با دقت، اندازه‌ی درستِ یک ذره نمک را برمی‌دارد. مهارتِ چاشنی‌زدن، همان دلی است که این قاشقِ کوچک به یاد می‌سپارد."},"ICON-0798":{"nm":"تخته مغناطیسی تایمر","de":"به درِ یخچال چسبیده، سه‌دقیقه‌ی رامن را می‌شمرد و سی‌ثانیه‌ی ورزش را اندازه می‌گیرد. با یک تکه‌ آهنربا، زمانی که در حالِ گذر است، لحظه‌ای پیشِ چشم می‌ماند. دایره‌ای پرکار که چیزِ در حالِ گذر را لحظه‌ای به دیوار سنجاق می‌کند."},"ICON-0799":{"nm":"روکش دسته قابلمه","de":"لایه‌ای که دور دسته می‌پیچد تا دسته‌ی داغ را با دستِ برهنه نگیری. سپری کوچک ایستاده میانِ گرما و کفِ دست. جابه‌جاییِ سالم، همیشه از همین پیچشِ نرم آغاز می‌شود."},"ICON-0800":{"nm":"پایه لاستیکی تخته برش","de":"وقتی زیرِ آن پهن می‌شوم، تخته‌ی برش دیگر لیز نمی‌خورد. تکه‌ای لاستیک که هر بار چاقوزدن می‌لرزد، از زیر تکیه‌گاه می‌شود. ثبات، کارِ گازگرفتنِ محکم در جایی نادیده است."},"ICON-0801":{"nm":"گیره دستکش آشپزخانه","de":"جایی که دستی که بی‌وقفه پیش شعله می‌جنبید، لحظه‌ای می‌آسایـد. یک لنگه دستکش بادبزن‌مانند را به دیوار بیاویز، و نفسی کوتاه تا وعده‌ی بعدی آغاز می‌شود. مرتب کردن، در نهایت، نام دیگری برای مهربانی است."},"ICON-0802":{"nm":"جاهم‌زن قهوه","de":"کنار پیشخوان، جایی که چوب‌های باریک شانه به شانه‌ی هم تکیه داده‌اند و مرتب چیده شده‌اند. آماده‌اند تا در فنجان صبحگاهی کسی دایره‌ای بکشند؛ صف‌شان درست شبیه گروه کر است، درست پیش از آنکه صدایشان را یکی کنند."},"ICON-0803":{"nm":"نوار دسته زیرلیوانی","de":"نواری که آن تیک‌تیک کوچک برخورد لیوان با میز را به‌آرامی می‌پذیرد. زیرلیوانی‌های گرد را که کنار هم ببندی، پذیرایی از مهمان آماده می‌شود. میهمان‌نوازی همیشه از همین جاهای کوچک آغاز می‌شود."},"ICON-0804":{"nm":"برچسب شربت","de":"یک نام روی بطری. شیرین، غلیظ - همان یک کلمه‌ی کوتاه، صبحی شلوغ را کمی منظم‌تر می‌کند. برچسب کاغذی است برای یادداشت از پیش یک وعده‌ی کوچک."},"ICON-0805":{"nm":"ظرف چوب میوه دسر","de":"ظرفی که چوب‌های نوک‌تیزی که تکه‌ای میوه را سیخ می‌زنند در آن کنار هم زندگی می‌کنند. پیش از آنکه مثل پرچمی روی بشقاب دسر فرو روند، اینجا بی‌صدا نوبتشان را انتظار می‌کشند. حتی شیرینی هم نظم و ترتیب دارد."},"ICON-0806":{"nm":"آستین هم‌زن نوشیدنی","de":"لباسی کاغذی که مشتی چوب هم‌زن را در آغوش می‌گیرد. رطوبتی را که نوشیدنی سرد پس می‌دهد به‌جای دست جذب می‌کند و نوک انگشتانی را که لیوان را نگه داشته‌اند خشک و آسوده می‌دارد. مراقبتِ نادیده همیشه از حاشیه‌ها می‌آید."},"ICON-0807":{"nm":"برچسب دسته‌ی لیوان بیرون‌بر","de":"در لحظه‌ای که دو دست کافی نیست، دسته‌ای کوچک به‌جای تو لیوان‌ها را نگه می‌دارد. گرمای بسته‌بندی‌شده را چنان می‌گیرد که حتی یک قطره نریزد و آن گرما را تا سر کوچه‌ی کسی بدرقه می‌کند."},"ICON-0808":{"nm":"روکش بیبر کافه","de":"پوششی که انتظار تا لحظه‌ی لرزیدن را آرام در بر می‌گیرد. در گوشه‌ای از کافه از شماره‌ی نوبتِ درخشان نگهبانی می‌کند و آن هیجان را نیز که «به‌زودی شماره‌ام صدا زده می‌شود» با خود نگه می‌دارد."},"ICON-0809":{"nm":"حلقه کوپن مهر","de":"کاغذی که وقتی ده خانه‌اش پر شود، یک فنجان هدیه می‌دهد. با هر مهری که اضافه می‌شود، نام «مشتری ثابت» هم کمی رشد می‌کند. لذتی ساده و بی‌آلایش که به حلقه‌ای کوچک آویخته شده است."},"ICON-0810":{"nm":"پاکت نمونه دانه قهوه","de":"پاکتی که مشتی دانه‌ی قهوه را در خود دارد و پیش از هر چیز عطرش را پیشکش می‌کند. ترشی و شیرینیِ گذرا بر نوک بینی، همان نخستین برداشتی است که سرنوشت یک فنجان را رقم می‌زند. عطر، زودتر از هر توضیحی می‌رسد."},"ICON-0811":{"nm":"آهن‌ربای برچسب یخچال","de":"برچسب مغناطیسی کوچکی که به در یخچال می‌چسبد. اگر بنویسی چه چیزی کِی وارد شده، حتی خورشتی که نزدیک بود فراموش شود، نوبتش را بازمی‌یابد. خانه‌داری یعنی نگه‌داشتنِ خاطره‌ای که در حال گذر است."},"ICON-0812":{"nm":"برچسب تاریخ نگهداری","de":"قطعه‌ای که روز نگهداری را واضح حک می‌کند. شاهدی کوچک که حتی پس از چند روز آرام می‌گوید «این هنوز خوب است». تازگی با نوک انگشتانی که تاریخ را به یاد می‌آورند، پاسداری می‌شود."},"ICON-0813":{"nm":"باند ظرف تقسیم‌بندی","de":"باندی که دور کمر ظرف تقسیم‌شده حلقه می‌زند و آن را در آغوش می‌گیرد. دربِ لق را محکم می‌فشارد و نظمی کوچک را در دل یخچال حفظ می‌کند. بستن چیزی، به مرتب‌کردن دل شباهت دارد."},"ICON-0814":{"nm":"نوار رنگی گیره دربندی","de":"گیره‌های رنگارنگی که دهانه‌ی پاکت را محکم می‌گزند. قرمز یعنی تند، زرد یعنی شیرین - دست فقط با دیدن رنگ می‌فهمد. چراغ‌راهنمای آشپزخانه این‌گونه، بی هیچ کلامی، راه را نشان می‌دهد."},"ICON-0815":{"nm":"برچسب نام بسته فریزری","de":"برچسبی که به‌آرامی روی چیزی منجمد گذاشته می‌شود. حتی در دل پاکتِ یخ‌زده هم به آن یادآوری می‌کند که خودش چه بوده است. سلامی کوچک به موادی که به خواب زمستانی رفته‌اند."},"ICON-0816":{"nm":"تور نگهداری سبزیجات","de":"توری باز و بخشنده که سبزیجات خاک‌آلود را در آغوش می‌گیرد. آشپزخانه‌ی مادربزرگ از دیرباز می‌دانست که فرصت نفس‌کشیدن، عمر را طولانی می‌کند. تهویه، حاشیه‌ای مهربان است که به سبزیجات هدیه می‌شود."},"ICON-0817":{"nm":"کلاهک دسته‌بندی درب بطری","de":"کلاهکی که درب‌ها را یکی‌یکی بر اساس اندازه جفت می‌کند. یافتنِ دوباره‌ی جفتِ گمشده، مهربان‌تر از آن است که فکرش را بکنی. وقتی جفتِ درست کنار هم می‌نشیند، آشپزخانه هم مرتب‌تر می‌شود."},"ICON-0818":{"nm":"برچسب سینی تخم‌مرغ","de":"نشانه‌ای که با دقت به هر یک از ده لانه‌ی کوچک اختصاص داده شده. خرد خانه‌داری که می‌گوید تخم‌مرغ‌های قدیمی‌تر را اول مصرف کن. حتی یک نیمرو در صبحگاه هم دلی دارد که به نظم اهمیت می‌دهد."},"ICON-0819":{"nm":"برچسب باقی‌مانده غذا","de":"بنویس «این مالِ من است!» و بچسبانش، تا یخچال هم لحظه‌ای آرامش بگیرد. اعلان جنگی بامزه که پیشاپیش صاحبِ میان‌وعده‌ی شبانه را مشخص می‌کند. خانواده امروز هم با همین معاهده‌های کوچک می‌چرخد."},"ICON-0820":{"nm":"زیرقاشقی کوچک","de":"تکه‌ای کوچک که به‌آرامی قاشق و چوب‌غذاخوری را نگه می‌دارد تا مستقیم با میز تماس نگیرند. همین نظم کوچک، به‌آرامی، شأن یک وعده غذا را بالا می‌برد. آداب سفره در چنین جاهایی، بی‌سروصدا، رشد می‌کند."},"ICON-0821":{"nm":"حلقه نگه‌دارنده دستمال کاغذی","de":"حلقه‌ای که دستمالی را که در باد پراکنده می‌شد، آرام نگه می‌دارد. کاغذ سفیدی را که منتظر نوبتِ باز شدن است، مرتب گرد هم می‌آورد و نظمی کوچک را روی میز حک می‌کند."},"ICON-0822":{"nm":"گیره گوشه رومیزی","de":"تکه‌ای که گوشه‌ی بلندشده‌ی رومیزی را به‌آرامی فشار می‌دهد و آرام می‌کند. میز هر روز درس می‌دهد که فقط وقتی یک سر گرفته شود، کل سطح صاف می‌ماند. حتی یک گوشه هم سهمی از مسئولیت دارد."},"ICON-0823":{"nm":"سینی کوچک ادویه","de":"سینی کوچکی که کاسه‌ای سس سویا و ذره‌ای نمک را کنار هم می‌نشاند. آغوش گشاده‌ی سفره‌ای که حتی به یک چاشنی هم جای خودش را می‌دهد. غذای کره‌ای در دلِ توجه به همین همراهی‌های کوچک عمق می‌گیرد."},"ICON-0824":{"nm":"پلاک شماره میز","de":"همان عددی که در رستورانی شلوغ با صدای «میز فلان!» صدا زده می‌شود. به انتظار نوبت می‌دهد و انصاف را برای همه حفظ می‌کند. آنچه در یک پلاک نهفته، وعده‌ای کوچک است و کاسه‌ای گرم که به‌زودی می‌آید."},"ICON-0825":{"nm":"نوار نشانه لیوان آب","de":"نواری که دور لیوان آب می‌پیچد و آرام می‌گوید مال کیست. پرچمی کوچک که جای مرا میان لیوان‌های شبیه به هم مشخص می‌کند. در سفره‌ای که دور هم نشسته‌اند، همین توجه جلوی سوءتفاهم‌های بیهوده را می‌گیرد."},"ICON-0826":{"nm":"سنجاق دسته‌بندی بشقاب کوچک","de":"سنجاقی که بشقاب‌های کوچک را با رنگ از هم جدا می‌کند. مرزی مهربان میان مال من و مال تو می‌کشد و لذتِ اشتراک را پاکیزه‌تر می‌کند. محبت را قسمت کن، اما بهداشت را هم دقیق نگه‌دار."},"ICON-0827":{"nm":"پرده حائل منو","de":"زمانِ تردید، پشتِ منوی بازشده پنهان می‌ماند. همان دودلیِ کوتاه بر سرِ اینکه چه بخوریم، در واقع بخشی از وعده‌ی غذاست. امروز چه بخوریم؟ - آن هیجان را آرام پنهان می‌کند."},"ICON-0828":{"nm":"پایه کارت نام صندلی","de":"پایه‌ی کوچکی که کارت نام را ایستاده نگه می‌دارد. چه در مراسمی، چه سر سفره‌ای جشن، واضح اعلام می‌کند که اینجا جای توست. میهمان‌نوازی تنها همان لحظه که نامی خوانده می‌شود، کامل می‌گردد."},"ICON-0829":{"nm":"آستین لیوانی مافین","de":"لباسی کاغذی که کمر تپلِ مافینِ تازه‌پخته را در آغوش می‌گیرد. بدنِ گرمش را چنان نگه می‌دارد که از دست نلغزد و گرما را تا همان لحظه‌ی نخستین گاز، به‌آرامی حفظ می‌کند. حتی دسر هم به لباسی نیاز دارد."},"ICON-0830":{"nm":"درپوش کیسه قنادی","de":"درپوشی که دهانه‌ی کیسه‌ی فشردن خامه را محکم می‌بندد. در زمان استراحت، اجازه نمی‌دهد حتی یک قطره بیرون بریزد. آن گلِ کوچک روی کیک، از همین خویشتن‌داری شکوفا می‌شود."},"ICON-0831":{"nm":"حلقه قالب کلوچه","de":"مجموعه‌ای گرد از قالب‌ها که خمیر را به شکل ستاره و خرس می‌برند. همان یک آرد، از میان نوک انگشتان، به ده‌ها حالت بیدار می‌شود. هرچه بپزی، اولین چیزی که به خمیر دست می‌زند، همیشه دلسوزی است."},"ICON-0832":{"nm":"آویز کاردک خمیر","de":"دستی صاف که خمیر را با صرفه‌جویی جمع می‌کند و پاکیزه تقسیم. همان پشتکاری که حتی مشتِ چسبیده به کاسه را هم به یاد می‌آورد، حجمِ یک قرص نان را تعیین می‌کند. پخت و پز، کارِ دستی است که مضایقه می‌کند."},"ICON-0833":{"nm":"تخته قاشق پیمانه‌ای","de":"تخته‌ای که قاشق‌های پیمانه‌ای را بی‌لرزش، مرتب می‌خواباند - یک قاشق چای‌خوری، نیم قاشق غذاخوری. یک قاشقِ دقیق، تعادل طعم را استوار می‌کند. پشتِ عبارتِ «دستِ خوب»، در واقع اندازه‌گیریِ دقیق پنهان است."},"ICON-0834":{"nm":"قلاب دستکش فر","de":"قلابی برای آویختن دستکشی که پیش روی فر داغ نگهبانی می‌داد. دست ضخیمی که از سوختگی جلوگیری کرد، حتی در زمان استراحت هم در دسترس آرام می‌ماند. ایمنی همیشه از همان چیزی آغاز می‌شود که سرِ جای خودش می‌ماند."},"ICON-0835":{"nm":"گیره توری خنک‌کننده","de":"گیره‌ای که توری‌ای را که شیرینیِ تازه‌پخته روی آن خنک می‌شود، مرتب می‌گزد. در حالی که بخار می‌رود، اجازه نمی‌دهد جابه‌جا شود و همراه منتظر می‌ماند تا ترد شدن کامل شود. حتی خنک‌شدن هم مشتی صبر می‌طلبد."},"ICON-0836":{"nm":"پایه تاپر کیک","de":"پایه‌ای که پنج حرفِ «تولدت مبارک» را روی کیک می‌نشاند. درست پیش از خاموش‌شدن شمع‌ها، همین پرچم کوچک روشن‌ترین روز یک نفر را می‌سازد. جشن، وقتی بالا برافراشته شود، بهتر دیده می‌شود."},"ICON-0837":{"nm":"پودرپاش قند","de":"ظرفی که آخرین پاشیدنِ سبک را در خود دارد. مثل برفی سفید روی دسرِ تازه‌پخته می‌نشیند و تکه‌ای معمولی را به هدیه‌ای کوچک تبدیل می‌کند. لمسِ پایانی همیشه از سبک‌ترین دست می‌آید."},"ICON-0838":{"nm":"برچسب گیم‌باپ مثلثی","de":"نایلون را به ترتیب ۱، ۲، ۳ باز کن و جلبک روی آن مثلث، ترد و تازه زنده می‌شود. یک خط که دوست وفادار سحرگاهیِ فروشگاه را در یک نگاه می‌شناساند. شب‌های گرسنه‌ی بعد از کلاس‌های اضافی، همین‌جا آویخته‌اند."},"ICON-0839":{"nm":"نگه‌دارنده درب نودل فوری","de":"نگه‌دارنده‌ای که در سه دقیقه انتظار، آرام درب را از بلند شدن باز می‌دارد. جای همان چوب‌غذاخوری را می‌گیرد که روی درب می‌گذاشتند تا بخار بیرون نرود. آن دقایق کوتاهِ پختن رشته، هیجان‌انگیزترین لحظه‌ی میان‌وعده‌ی شبانه است."},"ICON-0840":{"nm":"درپوش سیخ هات‌بار","de":"کلاهک کوچکی که سرِ سیخ را محکم در برمی‌گیرد. طوری نگهبانی می‌کند که گاز زدن راحت باشد و حتی یک قطره سس هم روی دست نریزد. لذتِ خوراکیِ جلوی دکه‌ی فست‌فود، همیشه از همین چیزهای کوچک کامل می‌شود."},"ICON-0841":{"nm":"دسته کیسه پلاستیکی","de":"آن را به انگشت بیاویز و نایلون خفیف جیرجیر می‌کند. وزن خریدها به یک طرف کج می‌شود و راهِ تا خانه، اثری سرخ روی کف دست به‌جا می‌گذارد. در دل آن صدای سبک، بارِ سنگین خانه‌داریِ امروز، آویزان تاب می‌خورد."},"ICON-0842":{"nm":"گیره تاکردن رسید","de":"رسیدِ درازی را که باز شده، از وسط تا کن و محکم بگیر، تا خرجِ امروز بسته‌ای مرتب شود. همان‌طور که کاغذهای خوش‌بوی جوهر روی هم انباشته می‌شوند، خاطراتِ کوچک خانه‌داری هم مرتب می‌شوند."},"ICON-0843":{"nm":"برچسب مایکروویو","de":"پیش از آنکه صدای «تینگ» به‌گوش برسد، برچسب آرام زمانِ گرم‌شدن را می‌شمارد. راهنمایی کوچک که چند دقیقه و چند ثانیه و نام چیزی که باید گرم شود را ثبت می‌کند. حتی دلی که منتظر نوبتِ گرم‌شدن است، چنین خط‌کشی‌هایی دارد."},"ICON-0844":{"nm":"رول برچسب تخفیف","de":"هر بار که خانه‌ای را جدا می‌کنی، صدای چسبناک و ریزی نوک انگشتانت را قلقلک می‌دهد. وقتی اعدادِ قرمز رج به رج باز می‌شوند، سبد خرید کسی کمی سبک‌تر می‌شود. رولی کوچک از مهربانی، حلقه‌شده و منتظر."},"ICON-0845":{"nm":"حلقه پاکت سس","de":"چیزی ترش کنارِ لب می‌ترکد و روزِ عادی هم کمی شیرین‌تر می‌شود. وقتی پاکتِ آویخته به حلقه‌ای گرد با هر قدم تاب می‌خورد، یک شیرینیِ کوچک تمامِ روز در جیبم همراهم می‌آید."},"ICON-0846":{"nm":"سبد فروشگاه ۲۴ ساعته","de":"در دست بگیرش و پلاستیک به‌آرامی خم می‌شود. مغازه‌ای پرنور در نیمه‌شب، به عمقی که یکی‌دو گیم‌باپ مثلثی و یک نوشیدنی جا می‌گیرد. ظرفی مهربان برای درست یک وعده، جایی که حتی تنها هم باشی، تنها نیستی."},"ICON-0847":{"nm":"نوار جعبه ماکارون","de":"نواری که جعبه را آرام در آغوش می‌گیرد تا ماکارون‌های رنگارنگ پراکنده نشوند. کسی که هدیه‌ای دریافت کرده، با نوک انگشتانش می‌داند که هیجانِ درست پیش از باز کردن روبان، شیرین‌ترین لحظه است."},"ICON-0848":{"nm":"گیره تور میوه","de":"دهانه‌ی تور را جمع کن و بگیر، تا عطرِ سیب به‌آرامی از میان تور بیرون بزند. دستی کوچک که نمی‌گذارد میوه‌ها بغلتند. توصیه‌ای مهربان و بی‌صدا که پیش از نرم‌شدن، زودتر بخورشان."},"ICON-0849":{"nm":"پارچه درب شیشه مربا","de":"آشپزخانه‌ی تابستانیِ مادربزرگ به یاد می‌آید، که پارچه‌ای گرد را روی درب می‌کشید و با کش می‌بست. در یک تکه پارچه‌ی چهارخانه، زمانِ شیرینِ پختنِ مربا و دلسوزی با هم مهر و موم می‌شود. مزه‌ی دست، این‌گونه پوشیده و نگه‌داشته می‌شود."},"ICON-0850":{"nm":"روبان بستنِ کلوچه","de":"کلوچه‌ی تازه‌پخته را در سلفون بگذار و روبان را بپیچ و ببند، تا عطرِ کره تا انتهای روبان نفوذ کند. دستی که چیزی دست‌ساز را به کسی می‌دهد، همیشه کمی می‌لرزد. گره‌ای که دل را هم همراه می‌بندد."},"ICON-0851":{"nm":"تخته جداکننده شکلات","de":"خانه به خانه، جایی تعیین می‌کند تا شکلات‌ها به هم نخورند. تا آب نشوند، تا خرد نشوند. آنچه یک جداکنندهٔ کوچک تا آخر پاسداری می‌کند، در نهایت، دلِ کاملِ یک قطعه است که قرار است به کسی هدیه شود."},"ICON-0852":{"nm":"برچسب هدیه چای","de":"روی برچسبی که دور پاکت چای پیچیده شده، نامی با خط دست، منظم نوشته شده است. کاغذ کوچک از پیش زمزمه می‌کند که وقتی دم بکشد، عطرِ علف همراه بخار بالا می‌آید. فنجانی که حتی پیش از نوشیدن، دست را گرم می‌کند."},"ICON-0853":{"nm":"گردنبند بطری آب‌نبات","de":"گردنبندی که با پیچیدنِ بندی دور گردنِ بطریِ پر از آب‌نبات‌های رنگارنگ ساخته شده. با هر قدم، صدایی مثل غلتیدنِ مهره‌های ریز درونش می‌پیچد. گنجینه‌ای مغرور از دوران کودکی که شیرینی را به گردن می‌آویخت."},"ICON-0854":{"nm":"آویز قاشق هدیه","de":"با یک آویزِ کوچک که از انتهای دسته آویزان است، قاشقی معمولی ناگهان به هدیه تبدیل می‌شود. با هر بارِ برداشتن، صدایی زلال و سبک به گوش می‌رسد. زیوری ریز که کمی زیبایی به دلی که هدیه می‌دهد، می‌افزاید."},"ICON-0855":{"nm":"تگ تشکر میان‌وعده","de":"دلی که می‌خواهد حتی کمی از آنچه گرفته، پس بدهد. برگه‌ی تشکری که آرام به کیسه‌ی میان‌وعده آویخته شده. به‌جای «متشکرم»ی که تمام نشد، سلامی کوچک آرام از دستی به دستِ دیگر می‌رود."},"ICON-0856":{"nm":"حلقه نمونه نوار تزئینی","de":"طرح‌هایی که هر کدام به اندازه‌ی یک وجب بریده و چسبانده شده، در نوار کوچکی رج شده‌اند. تا با نوک انگشت آرام‌آرام رنگِ دلخواه را انتخاب کنی، فقط فکرِ تزیین کردن هم روز را رنگارنگ می‌کند. ردیفی از نمونه‌ها که حتی دودلی هم در آن لذت‌بخش است."},"ICON-0857":{"nm":"درپوش موچین برچسب","de":"کلاهکی روی نوک تیزِ موچین بگذار، و برچسبی به اندازه‌ی ناخن هم آسیب نمی‌بیند. دستی دقیق که گوشه‌هایی را که انگشت به آن‌ها نمی‌رسد، به‌آرامی برمی‌دارد. مراقبت از آنچه دوست داری، همیشه با کمی احتیاط همراه است."},"ICON-0858":{"nm":"استیکر گوشه دفترچه خاطرات","de":"استیکری روی چهار گوشه‌ی دفترچه بچسبان، و صفحه‌های بادبزن‌مانند مثل معجزه آرام می‌گیرند. حسِّ فشرده‌شدنِ آرام کاغذ، آیینی کوچک که امروز را زیبا مهر و موم می‌کند. ثبت، از همان گوشه‌ها استوار می‌شود."},"ICON-0859":{"nm":"تخته راهنمای پانچ","de":"تخته‌ای که پیشاپیش جای سوراخ‌ها را نشان می‌دهد. با خط‌چین آرام تنظیمش کن و هیچ کجی پیش نمی‌آید. دلی که بی‌عجله یک‌بار دیگر می‌سنجد، دقت همیشه از همان یک لحظه آرامش کوچک، بی‌صدا می‌آید."},"ICON-0860":{"nm":"سینی خرده‌کاغذ","de":"خرده‌کاغذهای باقی‌مانده از قیچی‌کاری، آرام درون سینی جمع می‌شوند. سرپناهی کوتاه برای تکه‌های کوچک، تا میز به‌هم‌نریزد. پایانِ کاردستی، این‌گونه بی‌صدا مرتب می‌شود."},"ICON-0861":{"nm":"پد جوهر رنگی","de":"پد را سبک فشار بده و بردار، رنگ روی نوک انگشت مرطوب پخش می‌شود. قرمز، زرد، آبی - رنگین‌کمانی کوچک که با یک مهر بیرون می‌آید. جایگاهی نرم برای کاشتنِ رنگ، تلق‌تلق، روی کاغذ سفید."},"ICON-0862":{"nm":"رول نوار تزئینی","de":"طرحی که پیچ‌درپیچ باز می‌شود، بی‌پایان ادامه می‌یابد. یک تکه بکن و بچسبان، و در جای یکنواخت گل می‌شکفد. رولی از جادوی کوچک، حلقه‌شده و منتظر، که هرچه دست پیش برود زیباتر می‌شود."},"ICON-0863":{"nm":"درپوش مهر تِم‌دار","de":"کلاهکی کوچک که سرِ مهر را محکم می‌پوشاند تا جوهر خشک نشود. آرام نگهبانی می‌کند تا طرحِ بعدی واضح باقی بماند. رنگی که خوب نگهداری شود، روی کاغذ بعدی هم به همان زلالی می‌شکفد."},"ICON-0864":{"nm":"خرده پانچ تزئینی","de":"تکه‌های کوچکی که پانچ با تلق آن‌ها را می‌اندازد. خرده‌کاغذهای رنگی بریده به شکل ستاره و قلب و گلبرگ، آرام روی کف دست انباشته می‌شوند. جواهرهایی کوچک که دور انداختنشان حیف است، پس دوباره جایی می‌چسبانی‌شان."},"ICON-0865":{"nm":"حلقه برچسب قرقره نخ","de":"برچسبی کوچک با نامِ نخِ رنگی نوشته‌شده روی هر قرقره. نشانه‌ای مهربان که پیش از درهم‌پیچیدن، جای خود را یادآوری می‌کند. نخِ گره‌خورده، و دل هم، با یک برچسب باز شدنشان آسان‌تر می‌شود."},"ICON-0866":{"nm":"جلد کتابچه سوزن","de":"جلدی نرم برای کتابچه‌ی نمدیِ پر از سوزن‌های فشرده. بازش کن و ابزار خیاطی مرتب دراز کشیده به استقبالم می‌آید. کتابچه‌ای کوچک که نوک‌تیزها را مهربان به خواب می‌برد تا نوک انگشت آسیب نبیند."},"ICON-0867":{"nm":"حلقه نمونه پارچه","de":"خشن یا نرم، زمانِ آهسته‌ی لمسِ بافتِ پارچه، یکی‌یکی با نوک انگشت برای انتخاب. میان تکه‌های پارچه‌ای که به‌ترتیبِ رنگ چیده شده‌اند، پیش از آنکه لباس شود، پارچه آرام منتظر است تا اول لمس شود."},"ICON-0868":{"nm":"حلقه گیره گلدوزی","de":"پارچه را در حلقه‌ی گرد بگذار و سفت کن، مثل پوستِ طبل کشیده می‌شود. نشانه‌ای کوچک که آماده‌ای بند‌بند گلدوزی کنی. آنچه حلقه محکم نگه می‌دارد پارچه نیست، دلِ متمرکز است."},"ICON-0869":{"nm":"کپسول دسته‌بندی دکمه","de":"دکمه‌هایی که همیشه می‌غلتیدند، حالا آرام هر کدام به رنگِ خود در خانه‌ای از کپسول می‌نشینند. خردِ خانه‌داری که برای گم‌نشدن، آن‌ها را به بخش‌های کوچک تقسیم می‌کند. حتی گردآوریِ چیزهای پراکنده هم این‌قدر دلسوزی می‌طلبد."},"ICON-0870":{"nm":"نگه‌دارنده گچ خیاطی","de":"نگه‌دارنده‌ای که گچِ خط‌کشی روی پارچه را راحت در دست می‌گیرد. چیزی را که به‌آسانی می‌شکند، محکم می‌گیرد. همان دلِ آرامِ پیش از برداشتنِ قیچی، که خط اول اگر صاف باشد، لباس هم صاف می‌شود."},"ICON-0871":{"nm":"شیشه سنجاق ته‌گرد","de":"درون شیشه‌ی شفاف، سنجاق‌ها به هم می‌خورند و ریزریز صدا می‌دهند. اگر رو به نور بگیری، بر نوکِ هر سوزن، برقی کوچک می‌نشیند. ظرفی محکم و مرتب که چیزهای خطرناکِ پراکنده را در یک‌جا جمع می‌کند و مهربانانه می‌خواباند."},"ICON-0872":{"nm":"رول نوار وصله","de":"نواری جادویی که با اتوکشیدن روی جای پارگی، آرام می‌چسبد. بی هیچ بخیه‌ای، لباسِ کهنه به‌آرامی التیام می‌یابد. دلی که دور نمی‌انداخت و وصله می‌زد، لایه‌به‌لایه در دلِ رولِ گرد پیچیده شده است."},"ICON-0873":{"nm":"کاغذ الگوی وصله","de":"برگه‌ی الگویی که شکل وصله از پیش رویش کشیده شده. خط‌چین مهربانانه راهِ عبورِ قیچی را نشان می‌دهد. اول طرحِ کلیِ چیزی را که می‌خواهی بسازی کشیدن - هیجان همیشه از همین طرحِ کم‌رنگ آغاز می‌شود."},"ICON-0874":{"nm":"درپوش ظرف آب رنگ","de":"روی دهانه‌ی ظرف بگذار، و آبِ رنگی هرچقدر هم تکان بخورد، یک قطره نمی‌ریزد. حتی نگرانیِ پخش‌شدنِ آبِ کدرِ شسته‌شده‌ی قلم‌مو روی میز را هم می‌پوشاند. درپوشی آرام که بی‌صدا از جای نقاشی کشیدن نگهبانی می‌کند."},"ICON-0875":{"nm":"نوار محافظ پاستل","de":"نواری دور پاستلی که گردِ سفیدرنگش می‌ماسد بپیچ، تا انگشت‌ها کمتر کثیف شوند. کاغذی که رنگ لطیف را آرام در بر می‌گیرد تا خرد نشود. هرچه نرم‌تر باشد، باید لطیف‌تر گرفته شود، تا روی کاغذ هم لطیف رنگ بگیرد."},"ICON-0876":{"nm":"درپوش بلندکننده مداد رنگی","de":"کلاهکی به سرِ مدادرنگیِ کوتاه‌شده وصل کن، و یک تکه دوباره بلند می‌شود. دلی که چیزی را فقط چون کوتاه شده، به‌آسانی دور نمی‌اندازد. از نوک انگشتانی که تا آخر استفاده می‌کنند، رنگِ نقاشی تا آخرین خانه پررنگ‌تر کامل می‌شود."},"ICON-0877":{"nm":"قلاب لیوان شست‌وشوی قلم‌مو","de":"لیوانِ شست‌وشو را به قلاب بیاویز، و قطره‌های افتاده از قلم‌مو آرام فرو می‌چکند. پیش از رنگ زدنِ رنگِ بعدی، سکوتِ کوتاه و زلالِ شستنِ قلم‌مو. در همان صدای پاک‌شدن هم ریتمی آرام جاری است."},"ICON-0878":{"nm":"درپوش کاردک پالت","de":"کلاهکی کوچک که تیغه‌ی کاردکِ پخش‌کننده و خراشنده‌ی رنگ را کاملاً می‌پوشاند. آرام مراقب است تا نوکِ تیز کند نشود. بافتِ رنگِ ضخیم‌مالیده، از همین یک لبه‌ی خوب‌نگه‌داشته‌شده زاده می‌شود."},"ICON-0879":{"nm":"گیره بوم نقاشی","de":"گیره‌ای محکم که پارچه‌ی بوم را با قدرت روی قاب می‌کشد و ثابت نگه می‌دارد. محکم که بگیرد، سطحِ نقاشی مثل پوستِ طبل کشیده می‌شود. تنها با زمینه‌ای بی‌لرزش، قلم‌مویی که رویش می‌دود هم آزادانه رها می‌شود."},"ICON-0880":{"nm":"بند تخته نقاشی","de":"بند را روی شانه بیانداز و تخته پشتِ سرت همراهت می‌آید. هرجا بنشینی، همان‌جا استودیوی خودت می‌شود. استودیویی کوچک بر پشت، که سبک‌بار به دنبال منظره‌ای برای کشیدن راه می‌افتد."},"ICON-0881":{"nm":"تیوپ رنگ آکریلیک","de":"یک قطره آب بیشتر، سپیده‌دم می‌شود؛ کمتر، نیمه‌شب. همان آبی، هر بار زیر نوک انگشت آسمانی متفاوت می‌گشاید. لحظه‌ای که تیوپی را می‌فشاری، رنگِ دلِ امروز روی کاغذ پخش می‌شود."},"ICON-0882":{"nm":"برگه نمونه طیف رنگ","de":"این کاغذ اول از همه فهمید که غروب یک‌باره سرخ نمی‌شود. پله‌های کوچکی که از کم‌رنگ به پررنگ عبور می‌کنند. چشم آرام میانشان قدم می‌زند و زمانِ رسیدنِ رنگ را آرام دنبال می‌کند."},"ICON-0883":{"nm":"درپوش قلاب بافتنی","de":"سپری کوچک به اندازه‌ی انگشتانه که پیش از فرورفتنِ نخ در انگشت به آن می‌زنی. دستی که مدت‌ها قلاب‌بافی کرده، این را می‌داند. تنها اگر آسیب نبینی، می‌توانی تا آخرین بند مهربانانه همراهی کنی."},"ICON-0884":{"nm":"نشانگر حلقه بافتنی","de":"با یک نشانه، اینکه تا کجا رسیده‌ای دوباره واضح می‌شود. آرامشی که دیگر لازم نیست یک بند را دوبار بشماری. دل هم همین‌طور، تنها وقتی جایی را که از آن گذشته آرام نشانه‌گذاری کند، راهش را گم نمی‌کند."},"ICON-0885":{"nm":"آویز شمارشگر ردیف","de":"مدرکی آرام از پایانِ یک ردیف، خانه‌به‌خانه انباشته می‌شود. حتی کاری که بی‌پایان به‌نظر می‌رسید، وقتی یک‌به‌یک شمرده شود، ناگهان از نیمه گذشته است. یک شمارش کوچک، دلِ امروز را تا انتها تاب می‌آورد."},"ICON-0886":{"nm":"سنجاق مرتب‌کننده دم‌نخ","de":"اگر دم‌نخِ بازشده را همین‌طور رها کنی، معلوم نیست گره‌ی بعدی کجا گره می‌خورد. دستی که جایی را که دیده نمی‌شود، از پیش مرتب می‌کند. مهربانی معمولاً همین‌طور، اول در جاهایی که به چشم نمی‌آید، حرکت می‌کند."},"ICON-0887":{"nm":"بند تمرین گره","de":"گره‌ی ساده، گره‌ی پروانه‌ای، گره‌ی حلقه‌ای. همان بند را می‌بندی و باز می‌کنی تا دست شکلش را حفظ کند. وقتی نوک انگشتانِ ناشی یک شب ناگهان روان می‌شود، همان یک رشته اول از همه می‌فهمد."},"ICON-0888":{"nm":"باند برچسب کلاف پشم","de":"نواری کوچک که روی هر کلاف، ضخامت و رنگش را می‌نویسد. عادتی که از شب‌هایی زاده شد که بعد از تمام‌شدنِ نخ، بیهوده به دنبال همان نخ گشتی. ثبت، یادداشتی مهربان برای خودِ آینده است."},"ICON-0889":{"nm":"خط‌کش نمونه بافت","de":"در ۱۰ سانتی‌متر چند بند جا می‌شود؟ - همان عدد کوچک، اندازه‌ی یک لباس کامل را تعیین می‌کند. اینکه تکه‌ای به اندازه‌ی کف دست، اندازه‌ی کل را در خود دارد، وقتی برش می‌داری، کاری نسبتاً سنگین است."},"ICON-0890":{"nm":"نشانگر جادکمه","de":"پیش از دوختنِ دکمه، اول یک نقطه در جای سوراخ می‌گذاری. به لطف همان نشانه‌ای که به‌زودی محو می‌شود، یقه‌ی لباس کج نمی‌شود. دلسوزی معمولاً در جایی که در نهایت دیده نمی‌شود، آرام باقی می‌ماند."},"ICON-0891":{"nm":"حلقه منگوله کوچک","de":"مثل منگوله‌ی انتهای نوریگه، یک حلقه‌ی کوچک تابی می‌سازد. آنچه آویزان آرام موج می‌زند، همیشه نگاه آدم را نگه می‌دارد. بافتی که با هر عبور باد، آرام زنده و پرتحرک می‌شود."},"ICON-0892":{"nm":"شیشه رنگ کوچک","de":"نه مضایقه‌کردن، بلکه دقیقاً استفاده کردن، شیوه‌ی درستِ کار با رنگ است. رنگی که یک قطره‌اش کافی است، با دستی که کنارِ شیشه‌ی کوچک سنجیده می‌شود. اعتدال از جایی می‌آید که یک‌بار طمع را کنار بگذاری."},"ICON-0893":{"nm":"چوب سمباده کوچک","de":"از سطحِ خشن شروع می‌کنی و آرام‌آرام به سمتِ نرم می‌روی. هیچ سطحی نیست که یک‌باره صاف شود. از نوک انگشتانی که بافت را پله‌پله پایین می‌آورند، جای خشن آرام نرم می‌شود."},"ICON-0894":{"nm":"پایه گیره مدل‌سازی","de":"قطعه‌ی چسب‌خورده را در دست نگه‌داری و اثر انگشت به‌جا می‌ماند. اگر آرام در گیره بگذاری، دست آزاد می‌شود و خشک‌شدن بی‌صدا خودش تمام می‌شود. حتی انتظار هم، وقتی کسی زیرش را بگیرد، سبک‌تر می‌شود."},"ICON-0895":{"nm":"صفحه زیرِ چسب‌کاری","de":"یک قطره چسب که روی میز بیفتد، اثرش دیر پاک می‌شود. عادتِ پهن‌کردنِ اول یک صفحه‌ی زیرین. شاید نیمی از کار، از همان دلی آغاز می‌شود که نمی‌خواهد جا را کثیف کند."},"ICON-0896":{"nm":"خانه‌های دسته‌بندی قطعات","de":"ده‌ها قطعه‌ی هم‌شکل که با هم مخلوط شوند، مونتاژ به‌زودی هزارتو می‌شود. لمسِ تقسیم‌کردن آن‌ها به هر خانه، از پیش زمانِ سردرگمی را کم می‌کند. نظم، مهربانی‌ای است که به خودِ آینده هدیه می‌شود."},"ICON-0897":{"nm":"پلاک ترتیب مونتاژ","de":"پلاکی کوچک که نوشته کدام قطعه‌ی شماره‌دار را اول جا بزنی. اگر ترتیب را رعایت کنی، به‌آسانی فرو نمی‌ریزد. مدل‌سازی، و هر روزی که پله‌پله ساخته می‌شود، بر همان وعده‌ی آرام استوار می‌شود."},"ICON-0898":{"nm":"جالقلمی کوچک","de":"قلم‌موی استفاده‌شده را بخوابانی، موهایش فشرده و خم می‌شود. جایی برای آویختنِ وارونه تا آب آن خارج شود. کسی که ابزارش را مدت‌ها کنار خود نگه می‌دارد، بعد از پایان کار، برعکس، شلوغ‌تر و مهربان‌تر می‌شود."},"ICON-0899":{"nm":"ظرف خرده پلاستیک مدل","de":"ظرفی که خرده‌های جداشده از قاب، آرام در آن جمع می‌شوند. دورریخته‌شده به‌نظر می‌رسند، اما روزی به جزئیاتی کوچک بازمی‌گردند. ظرف بی‌صدا منتظر می‌ماند و می‌داند که حتی باقی‌مانده‌ها هم نوبت خود را دارند."},"ICON-0900":{"nm":"درپوش اسپری پرداخت نهایی","de":"آخرین لایه اگر از فاصله‌ای خیلی نزدیک اسپری شود، همان‌طور می‌چکد. از فاصله‌ی یک وجب، سبک، سبک. جلاکاری شاید تمرینی است برای یک‌بار کنار گذاشتنِ طمعِ دل."},"ICON-0901":{"nm":"قوطی نوک اتود","de":"نوک نازک اتود در جیب به‌راحتی می‌شکند. وقتی آن را مرتب و دراز‌کش در قوطی کوچکی بگذاری، حتی یک نوک هم هدر نمی‌رود. مرتب کردن در نهایت، مراقبتی آرام از «من فردا» است که از پیش انجام می‌شود."},"ICON-0902":{"nm":"روکش پاک‌کن","de":"لباس کاغذی کوچکی که روی پاک‌کن پوشانده می‌شود. هرچه با دست خوردن سیاه‌تر شود، ردّ اصلاح‌های بیشتری روی خود جمع کرده است. پاک کردن، در واقع اجازه‌ای مهربانانه است برای اینکه بشود دوباره از اول شروع کرد."},"ICON-0903":{"nm":"لوله نگهداری نوک قلم","de":"نوک قلم وقتی خشک شود ترک می‌خورد و با ضربه کج می‌شود. یک لوله کوچک که آن را جدا و خوابیده نگه می‌دارد، رگه‌ی نوشته را برای مدتی طولانی سالم نگه می‌دارد. ابزاری که با ملایمت با آن رفتار شود، سرانجام با ملایمت هم می‌لغزد و پاسخ می‌دهد."},"ICON-0904":{"nm":"نمونه جوهر خودنویس","de":"جوهرهایی که قطره‌قطره برای امتحان روی کاغذ چکانده می‌شوند. رنگی که گمان می‌کردی سبزآبی است، روی کاغذ به دریایی تیره بدل می‌شود. رنگ را همیشه باید از نزدیک دید تا شناخت؛ رنگی که در ذهن تصور کرده‌ای اغلب به خطا می‌رود."},"ICON-0905":{"nm":"قوطی نشانگر صفحه","de":"پرچم کوچکی که به‌آرامی در جایی که مطالعه نیمه‌کاره رها شده جا داده می‌شود. دفعه بعد که کتاب را باز کنی، «من دیروز» دست تکان می‌دهد و منتظر می‌ماند. حتی جایی که توقف کرده‌ای هم به یک وعده بدل می‌شود؛ این کار محبت‌آمیز آن نشانه‌ی کوچک است."},"ICON-0906":{"nm":"بسته برچسب‌پرچمی یادداشت","de":"یک برگ را جدا کن و بچسبان، داستان درست از همان‌جا دوباره آغاز می‌شود. وقتی این پرچم‌های کوچک کنار لبه‌ی کتاب صف می‌کشند، افکار پراکنده مرتب در نقشه‌ای واحد گرد هم می‌آیند."},"ICON-0907":{"nm":"آهنربای جمع‌آوری گیره","de":"آهنربای کوچکی که گیره‌های پراکنده را یک‌جا جمع می‌کند. هرچه چیزی کوچک‌تر باشد گم‌شدنش آسان‌تر است، پس یک نیروی جمع‌کننده به‌آرامی میز شلوغ را نجات می‌دهد. حتی در کشیدن و جذب‌کردن هم مهربانی هست."},"ICON-0908":{"nm":"ست کلاهک مداد","de":"کلاهک‌های کوچکی که نوک مداد را می‌پوشانند و داخل کیف را در امان نگه می‌دارند. هر چیز نوک‌تیزی بالاخره جایی را سوراخ می‌کند، پس نیاز به دستی دارد که آرام رویش را بگیرد. تا نه کند شود، نه کسی را زخمی کند."},"ICON-0909":{"nm":"برچسب تابلوی نام میز","de":"لحظه‌ای که نام خود را می‌نویسی و روی میز می‌چسبانی، آن گوشه سرانجام از آنِ کسی می‌شود. وقتی حتی فضایی به اندازه‌ی یک وجب هم صاحب پیدا کند، طرز نشستن و آرام‌گرفتن دل هم به‌کل تغییر می‌کند."},"ICON-0910":{"nm":"کلاهک دسته طناب","de":"کلاهکی که پیش از آنکه انتهای دسته فرسوده و ترک بردارد، رویش کشیده می‌شود. ریتم طنابی که هزاران بار چرخانده شده، پیش از ذهن، کف دست آن را به یاد می‌آورد. ضربی که در تن حک شده، به‌آسانی فراموش نمی‌شود."},"ICON-0911":{"nm":"تسمه حلقه یوگا","de":"حلقه را بگیر و آرام‌آرام بدن را باز کن. هرچه تسمه کشیده‌تر شود، شانه‌های سفت‌شده لایه‌به‌لایه رها می‌شوند. کشش دادن، بیشتر از آنکه کشیدنی به‌زور باشد، به صبر کردنی آرام تا باز شدن بدن شبیه است."},"ICON-0912":{"nm":"جعبه توپ پینگ‌پنگ","de":"توپی سفید که چون سبک است دور می‌غلتد و همین که پا رویش بگذاری له می‌شود. یک جعبه کوچک، همان توپ آسیب‌پذیر را تا مسابقه‌ی بعدی محافظت می‌کند. استواری اغلب از در آغوش‌گرفتنی نرم می‌آید."},"ICON-0913":{"nm":"نوار گریپ بدمینتون","de":"یک لایه به‌آرامی دور دسته‌ای که از عرق می‌لغزد می‌پیچد. روی گریپی که خوب پیچیده شده، راکت بخشی از دست می‌شود. راز ضربه‌زدن با حس، نه با زور، در همین یک لایه‌ی نازک پنهان است."},"ICON-0914":{"nm":"مهره کوچک امتیاز","de":"یک امتیاز، بعد یکی دیگر. با جابه‌جا کردن مهره‌های کوچک، امتیازها آرام‌آرام روی هم انباشته می‌شوند. وقتی شمارش دیدنی باشد، بازی روشن‌تر می‌شود و شجاعت جبران یک امتیاز عقب‌ماندگی هم آهسته سر برمی‌آورد."},"ICON-0915":{"nm":"گیره جهت‌نمای کفش","de":"نوک کفش‌هایی که مرتب کنار هم گذاشته شده‌اند همیشه به یک سو نگاه می‌کنند. یک چرخش کوچک دست هنگام درآوردن کفش‌ها. یک مرتب‌کردن کوچک، قدم‌های صبح فردا را کمی سبک‌تر می‌کند."},"ICON-0916":{"nm":"بند گردنی سوت","de":"سوت را به گردن که بیندازی، اختیار گفتنِ «بایست» به دستت می‌رسد. صحنه‌ای که با یک صدای کوتاه، تمام زمین بازی یکباره می‌ایستد. دل‌هایی که به آن صدای کوچک اعتماد می‌کنند، گرد هم می‌آیند و یک وعده می‌سازند."},"ICON-0917":{"nm":"قوطی سوزن تلمبه توپ","de":"حتی توپی که بادش خالی شده هم با یک سوزن نازک دوباره سفت می‌شود. همان سوزنی که با احتیاط در یک قوطی کوچک نگه‌داری می‌شود، همین که گم شود کل تلمبه را بی‌فایده می‌کند. زمانی که کوچک‌ترین چیز، مهم‌ترین چیز است."},"ICON-0918":{"nm":"مخروط نشانگر کوچک","de":"از اینجا تا آنجا، یک مخروط کوچک مرزی را که دیده نمی‌شد ترسیم می‌کند. حتی بدون خطی روی زمین، آدم‌ها به‌طور طبیعی با پیروی از این نشانه صف می‌بندند. نظم، آرام‌آرام از همین نشانه‌های کوچک رشد می‌کند."},"ICON-0919":{"nm":"کیسه توکن","de":"کیسه‌ای که توکن‌های جرینگ‌جرینگ را یک‌جا جمع می‌کند. دهانه‌اش را که ببندی، دیگر چیزی پراکنده نمی‌شود. حتی چیزهای کوچک و پیش‌پاافتاده هم باید جایی برای نگه‌داشتن داشته باشند تا بتوانند نقش خود را ایفا کنند؛ این را کیسه بی‌هیچ کلامی نشان می‌دهد."},"ICON-0920":{"nm":"زیرانداز بُرزدن کارت","de":"روی میز لغزنده، کارت‌ها به‌خوبی در دست جا نمی‌گیرند. یک زیرانداز کافی‌ست تا هم بُر زدن و هم برداشتن کارت‌ها نرم‌تر شود. حتی در خوب‌بازی‌کردن هم، آماده‌سازی مهربانانه‌ای هست که ابتدا سطح را انتخاب می‌کند."},"ICON-0921":{"nm":"محافظ گوشه تخته بازی","de":"وقتی شب بازی رومیزی به پایان می‌رسد، یکی بی‌هیچ حرفی نخست به چهار گوشه‌ی تخته می‌رسد. چون می‌داند اگر خط تای عمیق‌تر شود، دور بعدی کج خواهد بود. در نوک انگشتانی که گوشه‌ها را صاف می‌کنند، آرزوی «فردا هم با هم بازی کنیم» نهفته است."},"ICON-0922":{"nm":"درِ لیوان تاس","de":"آن لحظه‌ی کوتاهی که همه تکان می‌دهند، می‌غلتانند و با هم نفس در سینه حبس می‌کنند. سقفی کوچک است که نمی‌گذارد تاس‌ها بیرون بجهند. زیر آن در، شانس امروز لحظه‌ای نفسی تازه می‌کند و سپس با صدای تلق‌تلق بیرون می‌غلتد."},"ICON-0923":{"nm":"صفحه ردیف‌کننده کاشی","de":"هرچه کسی از بازی هیجان‌زده‌تر باشد، ردیفش کج‌تر می‌شود. کاری که وقتی کاشی‌ها کج می‌شوند آرام آن‌ها را هل می‌دهد تا مرتب شوند. ردیف‌کردن، دستی است که با مهربانی بی‌تابیِ ذوق‌زده‌ی کسی را می‌پذیرد."},"ICON-0924":{"nm":"قوطی مهره‌های امتیاز","de":"هرچه مهره‌ها در قوطی بیشتر شوند، بازی هم داغ‌تر می‌شود. وقتی امتیازهای گرد در کف دست تلق‌تلق به هم می‌خورند، آن صدا پیش از برد و باخت، خودش لذت‌بخش می‌شود."},"ICON-0925":{"nm":"حلقه نشانگر نوبت","de":"حلقه‌ی کوچکی که می‌گوید حالا نوبت توست. تنها در همان لحظه‌ای که آن را یک خانه جابه‌جا می‌کنی، چشم همه آرام روی من جمع می‌شود. حلقه‌ای که آرام میان انتظار و هیجان می‌چرخد."},"ICON-0926":{"nm":"پایه مهره بازی","de":"هرچه مهره‌ای راحت‌تر بیفتد، زیر پایش باید محکم‌تر باشد. یک پایه، حتی روی تخته‌ای که کمی می‌لرزد هم جای مهره را نگه می‌دارد. باید چیز کوچک تاب بیاورد تا چیز بزرگِ رویش سرافراز بایستد."},"ICON-0927":{"nm":"گیره دفترچه راهنما","de":"دفترچه‌ی راهنما همیشه در حالی که باز مانده، صفحاتش یواشکی ورق می‌خورد. پیش از آنکه باد صفحات را فراری دهد، این گیره آرام یک صفحه را گاز می‌گیرد و نگه می‌دارد. باید قواعد را نگه داشت تا بازی تا انتها ادامه یابد."},"ICON-0928":{"nm":"بند جعبه پیک گیتار","de":"پیک گیتار همیشه درست در هیجان‌انگیزترین لحظه از میان انگشت‌ها فرار می‌کند. یک بند آویزان از جعبه، جلوی آن فرار کوچک را می‌گیرد. فقط کسی که شبی را تجربه کرده که موسیقی متوقف شد، قدر این بند را می‌داند."},"ICON-0929":{"nm":"لوله نگهداری قمیش","de":"قمیش همان لحظه‌ای که خشک شود صدای خودش را از دست می‌دهد. درون لوله‌ای مرطوب، تکه‌ای باریک از نی منتظر اجرای بعدی می‌ماند. جایی که پیش از دمیدنِ نفس، ابتدا خودِ نفس را به خواب می‌برند."},"ICON-0930":{"nm":"دستگاه کوک‌کننده سیم ساز","de":"وقتی سیم شل می‌شود، صدا هم آرام‌آرام افت می‌کند. چرخاندن آهسته‌ی دسته برای بازگرداندن کشیدگی؛ توجه همیشه از سر مچ دست می‌آید. صدای مرتب، از همین نظم‌دهی‌های کوچک آغاز می‌شود."},"ICON-0931":{"nm":"پارچه تمیزکننده ساز","de":"وقتی نوازش تمام می‌شود، عرقی نازک هم روی ساز می‌ماند. یک بار کشیدن پارچه‌ای نرم، همراه با درخشش، نت‌های امروز را هم آرام فرو می‌نشاند. دلبستگی همیشه در پایان‌بندی خودش را نشان می‌دهد."},"ICON-0932":{"nm":"روکش پین کوک","de":"پین کوک اگر برهنه بماند، بی‌آنکه بفهمی زنگ می‌زند. یک روکش کوچک، فصل زنگ‌زدنِ فلز را یک ضرب به تعویق می‌اندازد. کسی که اول گوشه‌های دیده‌نشده را مراقبت می‌کند، مدت‌ها طولانی می‌نوازد."},"ICON-0933":{"nm":"چراغ گیره‌ای پایه نت","de":"پشت صحنه‌ی تاریک، لحظاتی هست که فقط باید نُت روشن باشد. چراغ کوچکی که به پایه‌ی نت گیره می‌شود و نور را آرام پایین می‌ریزد. مشتی نور که زیر پا را روشن می‌کند تا نت‌ها راه را گم نکنند."},"ICON-0934":{"nm":"کلاهک خاموش‌کننده تمرین","de":"تمرین سحرگاهی همیشه به‌آرامی با خواب همسایه‌ها درگیر می‌شود. یک کلاهک که سوار کنی، صدای بلند به زمزمه‌ای کوچک می‌شود. موسیقی‌ای هم هست که در حال مراقبت از خواب شیرین کسی رشد می‌کند."},"ICON-0935":{"nm":"برچسب پد درام","de":"نشانه‌های کوچکی که روی پد درام چسبانده شده‌اند. اینکه کجا زده شود چه صدایی درمی‌آید را، پیش از آنکه دست حفظ کند، چشم مسیرش را می‌آموزد. ریتم این‌گونه، آرام‌آرام در تن حک می‌شود."},"ICON-0936":{"nm":"مهره یادداشت ملودی","de":"ملودی‌ای که زیر لب می‌خوانی، اگر نگیریش خیلی زود ناپدید می‌شود. چند خط شتاب‌زده روی یک مهره یادداشت‌شده، گاهی روزی به یک آهنگ کامل تبدیل می‌شود. الهام همیشه دوباره به سراغ دستی می‌آید که پُرکار یادداشت برمی‌دارد."},"ICON-0937":{"nm":"بند روکش کتاب","de":"مزاحمتی است وقتی کتابی نیمه‌خوانده در کیف خودسرانه باز می‌شود. یک بند به‌آرامی صفحات را می‌بندد و کتاب مطیع می‌ماند. وعده‌ای است برای مرتب‌تر تا‌کردن چیزها برای صفحه‌ی بعد."},"ICON-0938":{"nm":"حلقه نگه‌دارنده صفحه","de":"روزی که دلت می‌خواهد کتاب را با یک دست باز نگه‌داری و قهوه‌ی گرم بنوشی. حلقه‌ای که به انگشت می‌کنی، به‌جای تو صفحات را نگه می‌دارد. آسودگی‌های کوچک از همین اختراع‌های کوچک آغاز می‌شود."},"ICON-0939":{"nm":"مهره تایمر مطالعه","de":"می‌نشینی که فقط یک فصل بخوانی، اما بی‌آنکه بفهمی شب عمیق می‌شود. با فشردن مهره و تعیین زمان، حتی مطالعه هم یک نقطه‌ی توقف پیدا می‌کند. هرچه چیزی را بیشتر دوست داشته باشی، بیشتر به شجاعتی مهربانانه برای دانستن زمان توقف نیاز داری."},"ICON-0940":{"nm":"کلاهک محافظ گوشه کتاب","de":"کتابی که بیشتر دوستش داری، گوشه‌هایش زودتر و یواشکی فرسوده می‌شود. یک کلاهک که رویش بکشی، گوشه‌های جلد گرد و ایمن نگه داشته می‌شوند. زره‌ای کوچک که برای نگه‌داشتن چیزی که می‌خواهی مدت‌های طولانی کنارت باشد، آرام رویش می‌کشی."},"ICON-0941":{"nm":"نوار یادداشت برداشت","de":"لحظاتی هست که یک خط از جمله، سنگینی‌اش در سینه فرو می‌نشیند. برداشتی که روی یک نوار نوشته می‌شود، مثل نشانگر کتاب روی همان صفحه می‌ماند. گرمای زیرِ خط، چیزی است که فقط کسی که خوانده می‌شناسد."},"ICON-0942":{"nm":"برچسب بازگشت کتابخانه","de":"تاریخ بازگشت همیشه یک روز زودتر از موعد از راه می‌رسد. وقتی تاریخ نوشته‌شده روی برچسب آرام پشتت را هل می‌دهد، حتی کتاب امانتی هم ادب پایان‌یافتن پیدا می‌کند. برای دست‌های نفر بعدی، کتابخانه این‌طور صبر می‌کند."},"ICON-0943":{"nm":"چراغ گیره‌ای کتاب","de":"شبی که کنار خانواده‌ی خواب‌رفته، تنها بیدار می‌مانی برای خواندن. یک نور کوچک که به لبه‌ی کتاب گیره می‌شود کافی است. لازم نیست تمام تاریکی را پس بزنی؛ برای یک صفحه، همین لحظه‌ی آرام کفایت می‌کند."},"ICON-0944":{"nm":"کارت رایحه کتاب","de":"کتاب‌های قدیمی بویی می‌دهند که آفتاب و کاغذ در آن با هم آمیخته‌اند. کارتی که می‌گویند آن رایحه را در یک برگ نگه داشته، وقتی بازش می‌کنی، لحظه‌ای کوچه‌ی کتاب‌فروشی دست‌دوم را زیر بینی زنده می‌کند. حافظه با بو هم نشانگر صفحه می‌گذارد."},"ICON-0945":{"nm":"سنجاق نشانگر صفحه خوانده‌شده","de":"تا کجا خوانده بودم؟ سنجاق کوچکی که آن پرسش سردرگم‌کننده را پاک می‌کند. آن را به آخرین جمله بزن، فردا دیگر سرگردان نمی‌شوی. نشانه‌ای مهربان که به‌جای تو جای توقف را به یاد می‌سپارد."},"ICON-0946":{"nm":"آویز بند گوشی","de":"یک آویز کوچک روی بند گوشی، آدم را کمی متفاوت نشان می‌دهد. رنگ دلخواه، شکل دلخواه. یک سلیقه‌ی کوچک در دست، حال‌وهوای آن روز را به‌آرامی تکان می‌دهد."},"ICON-0947":{"nm":"کلاهک محافظ لنز دوربین","de":"سرنوشت عکس‌های سفر به یک تکه لنز بسته است. لحظه‌ای که کلاهک محافظ را برمی‌داری، همان آمادگی دل برای فشردن شاتر است. آیینی کوچک، نخستین چیزی که پیش از ثبت منظره چشم می‌گشاید."},"ICON-0948":{"nm":"درپوش پورت شارژ","de":"گرد و غبار درون کیف همیشه اول سراغ سوراخ شارژ می‌رود. با بستن آن دهانه‌ی کوچک با یک درپوش، پورت مدتی طولانی تمیز می‌ماند. اینجا سخت‌کوشی‌ای هست که حتی درزهای دیده‌نشده را هم مراقبت می‌کند."},"ICON-0949":{"nm":"حلقه پاپ‌ساکت پایه گوشی","de":"کاری برای دیدن راحتِ یک ویدیو، اینکه گوشی را کج نگه داری. حلقه‌ی پشت گوشی را که باز کنی، هم دست و هم صفحه آسوده‌تر می‌شود. یک پایه‌ی کوچک برآمده، یک لحظه‌ی عصرگاهی را با آرامش کش می‌دهد."},"ICON-0950":{"nm":"پچ تمیزکننده صفحه نمایش","de":"صفحه‌ای پر از اثر انگشت، به‌نوعی حتی دل را هم تار می‌کند. یک بار پاک کردن با پچ، جهان دوباره واضح می‌شود. تمیزی گاهی کاری کوتاه، فقط یک حرکت انگشت است."},"ICON-0951":{"nm":"جعبه سنجاق سیم‌کارت","de":"سنجاق سیم‌کارت پری‌ای‌ست که فقط در لحظه‌ی واقعاً لازم ناپدید می‌شود. آن را در یک خانه از جعبه بگذار، دیگر لازم نیست کل خانه را برای یک گیره مو بگردی. یک نظم کوچک، لحظه‌ای اضطراری را آرام نجات می‌دهد."},"ICON-0952":{"nm":"برچسب پد شارژ بی‌سیم","de":"شبی که وقتی آرام روی پد می‌گذاری، خودش پر می‌شود. برچسبی که چسبانده شده، جای خوابیدن گوشی را کمی نشان می‌دهد. جریانی نادیدنی، بی‌صدا انرژی یک روز را پر می‌کند."},"ICON-0953":{"nm":"برچسب پوشاننده اعلان","de":"برخی اعلان‌ها بهتر است پنهان بمانند تا دل آسوده‌تر باشد. یک برچسب، نور کوچک سحرگاهی را می‌خواباند. گاهی ندیدن هم راهی مهربانانه برای مراقبت از خود است."},"ICON-0954":{"nm":"حلقه محافظ لنز","de":"همان لحظه‌ای که لنز دوربین به زمین می‌خورد، دل با لرزشی فرومی‌ریزد. یک حلقه دور تا دورش، آن سقوط کوچک را آرام دفع می‌کند. لبه‌ای که پیش از هر چیز از چشمی که خاطرات را ثبت می‌کند محافظت می‌کند."},"ICON-0955":{"nm":"برچسب نام کابل","de":"از میان توده‌ای درهم‌پیچیده از کابل‌ها، بالاخره پیدا کردن مالِ خودت. یک برچسب کافی‌ست تا سیم شارژ هم اسمی برای خودش داشته باشد. پرچمی کوچک که میان سیم‌های شلوغ راه را نشان می‌دهد."},"ICON-0956":{"nm":"کیف شارژر","de":"شارژرهای داخل کیف سفر همیشه در هم گره می‌خورند و با هم دعوا دارند. وقتی مرتب در یک خانه از کیف جمع شوند، سرانجام آشتی می‌کنند. هنر بستن بار، در فراخواندن مهربانانه‌ی چیزهای پراکنده به یک‌جاست."},"ICON-0957":{"nm":"برچسب پریز چندخانه","de":"سوراخ‌های چندراهی همه شبیه هم‌اند و هر بار اشتباه می‌گیری. با چسباندن برچسب و مشخص‌کردن جای هرکس، صبح شلوغ خیلی روان‌تر می‌شود. یک برچسب کوچک، دعواهای کوچک روزمره را کم می‌کند."},"ICON-0958":{"nm":"قرقره جمع‌کننده سیم","de":"باز‌شده برای استفاده و دوباره جمع‌شده، یک روز مرتبِ سیم. لایه‌به‌لایه که دور یک قرقره بپیچی، گره‌ها یکسره ناپدید می‌شوند. دستی که پس از استفاده چیزی را سرجایش برمی‌گرداند، فردا را سبک‌تر می‌کند."},"ICON-0959":{"nm":"کلاهک کانکتور مغناطیسی","de":"کانکتور مغناطیسی بی‌آنکه بفهمی، خرده‌های ریز فلز را جمع می‌کند. با کلاهک که رویش بگذاری، گرد و خاک چسبنده دیگر نمی‌چسبد. دستگاهی که با یک مراقبت دیگر لمس شده، عمری طولانی‌تر کنارت می‌ماند."},"ICON-0960":{"nm":"بند پاوربانک","de":"اگر پاوربانک و کابلش را جدا بگذاری، همیشه یکی گم می‌شود. با بستن‌شان با یک بند، آن دو سرانجام جفت می‌شوند. گره‌ی کوچکی که درست پیش از بیرون‌رفتن، آرام آن‌ها را می‌بندد تا با هم سفر کنند."},"ICON-0961":{"nm":"درپوش گردگیر پریز","de":"سوراخ خالی پریز فقط بعد از چند روز به‌آرامی خانه‌ی گرد و خاک می‌شود. وقتی این کلاهک کوچک به‌جای آن نگهبانی می‌دهد، شارژری که دفعه‌ی بعد وصل می‌شود می‌تواند نخستین نفس تمیزش را بکشد. دربانی که زمان خالی را با ظرافت پاک نگه می‌دارد."},"ICON-0962":{"nm":"حلقه رنگی کابل","de":"شبی که میان سیم‌های درهم دنبال مالِ خودت می‌گشتی، کسی گفت بیا رنگشان کنیم. آبی برای تو، زرد برای من. با یک حلقه‌ی کوچک، دیگر با هم اشتباه گرفته نمی‌شویم. ردّ یک وعده‌ی مهربانانه که در گوشه‌ای از اتاق تمرین باقی مانده."},"ICON-0963":{"nm":"مهره دسته‌بندی آداپتور","de":"پایه‌های گرد و پایه‌های پهن، ۱۱۰ و ۲۲۰. مهره‌ای که چهره‌ی متفاوت پریزها را در هر کشور آرام از بر کرده. در گوشه‌ی چمدانِ نخستین سفر آن‌سوی دریا به‌سوی صحنه، همیشه همین برگه‌ی کوچک دسته‌بندی جا خوش می‌کرد."},"ICON-0964":{"nm":"سینی دسته‌بندی نوک هندزفری","de":"می‌گویند مجرای گوش هر کس عمق و پهنایی متفاوت دارد. کنار هم خواباندن سه اندازه‌ی بزرگ، متوسط و کوچک، و برگزیدن جفتی که دقیقاً اندازه‌ی گوش توست. رسمی مهربانانه برای هماهنگ‌کردن ابتدا بدن، پیش از شنیدن صدا."},"ICON-0965":{"nm":"حلقه سیلیکونی قاب","de":"لباس صحنه تا هر یک بخیه‌اش با دقت مراقبت می‌شود، اما گوشه‌های قاب گوشی همیشه برهنه به چیزی می‌خورند. وقتی این نوار نازک سیلیکونی به‌آرامی دور لبه می‌پیچد، حتی در سحرگاهی که از دست می‌لغزد هم صفحه سالم به صبح می‌رسد."},"ICON-0966":{"nm":"برچسب حذف نویز","de":"روزهایی هست که دلت می‌خواهد صدای جهان را لحظه‌ای خاموش کنی. این برچسب کوچک روی گوشی هدفون، نشانه‌ای است که سکوت را روشن می‌کند. طلسمی که هلهله‌ی سالن و سروصدای مترو را تا پایان یک آهنگ به دوردست می‌برد."},"ICON-0967":{"nm":"ست قلاب هندزفری","de":"وقتی می‌رقصی، همیشه یکی از هندزفری‌ها زودتر فرار می‌کند. این قلاب‌ها را که آرام لاله‌ی گوش را در آغوش می‌گیرند بیندازی، حتی میان کوریوگرافی سرسختانه هم فقط موسیقی تا انتها در گوشت می‌ماند. کشف کوچکی که آدم‌های اتاق تمرین با هم رد و بدل کردند."},"ICON-0968":{"nm":"کلاهک برس نظافت","de":"کلاهک کوچکی که رویش می‌کشند تا گرد و خاک روی موی برس دوباره پخش نشود. اینکه حتی ابزار نظافت هم به نظافت نیاز دارد را، دستی که مدت‌ها پیش پس از جارو کردن، جارو را وارونه می‌ایستاند، از قبل می‌دانست."},"ICON-0969":{"nm":"پد کف پایه شارژ","de":"علت اینکه پایه‌ی شارژ روی میز مدام سُر می‌خورد، این بود که پا نداشت. وقتی این پد نازک کف را جای پا گرفت، دستگاه سرجایش آرام ماند و تمام شب بی‌صدا انرژی جمع کرد."},"ICON-0970":{"nm":"نشانگر چپ و راست","de":"چپ L، راست R. یک نقطه‌ی اضافه گذاشته می‌شود تا حتی در تاریکی با لمس هم شناخته شود. آرزوی اینکه پای چپ و راست روی صحنه حتی یک‌بار هم اشتباه گرفته نشود، دقیقاً روی همین نشانه‌ی کوچک نقش بسته."},"ICON-0971":{"nm":"کلاهک جک تقسیم‌کننده صدا","de":"همان جکی که یک جریان صدا را میان چند نفر تقسیم می‌کرد، در زمان استراحت باید انتهایش پوشیده بماند. تا گرد و خاک به مدار نفوذ نکند. دستی کوچک و محتاط که آرزو دارد آهنگی را که با هم شنیدید، دفعه‌ی بعد هم شفاف جاری کند."},"ICON-0972":{"nm":"قرقره سیم هندزفری","de":"مثل حرکت دست قدیمی برای پیچیدن کلاف نخ، سیم هندزفری هم وقتی این‌جا دایره‌ای پیچیده شود مرتب می‌شود. لحظه‌ای که موسیقی‌ای که درهم‌پیچیده در کیف می‌غلتید، مرتب می‌شود. باز کردنِ فردا کمی سبک‌تر خواهد شد."},"ICON-0973":{"nm":"بند نگه‌دارنده کلاهک لنز","de":"هر بار که لنز باز می‌شد، کلاهک همیشه راهش را گم می‌کرد. آن را با بندی کنار دوربین ببند، دیگر لازم نیست بیهوده جیب را بگردی. دست پیش از هر چیز یاد گرفت که برای گم‌نکردن چیزی، باید آن را نزدیک خود ببندی."},"ICON-0974":{"nm":"آویز روکش هات‌شو","de":"در جای خالی هات‌شو روی دوربین، یک تزئین کوچک آرام جا داده می‌شود. همان آویزِ بی‌کارکرد، بی‌آنکه بفهمی وسیله‌ی سنگین و خشک را مثل دارایی خودت گرم و صمیمی نشان می‌دهد. کار دلبسته‌شدن به یک ابزار."},"ICON-0975":{"nm":"سگک تنظیم بند","de":"هر بار که بند کیف در شانه فرو می‌رود، این سگک کمی شل و سفت می‌شود. یک حرکت انگشت برای گزینش طولی که با تن تو جور دربیاید. حتی حمل بار هم، در نهایت مراقبت از خودت است؛ سگک آرام همین را می‌گوید."},"ICON-0976":{"nm":"جعبه انباشت فیلتر","de":"خانه‌ی کوچکی که تکه‌های شیشه‌ای که نور را می‌شکافند لایه‌به‌لایه در آن خوابانده می‌شوند. مه‌آلودگی و صافی، غروب و شب. مثل کشویی که آب‌وهوا از پیش انتخاب و ذخیره شده، عکاس همیشه پیش از راه‌افتادن، اول همین جعبه را باز می‌کند."},"ICON-0977":{"nm":"کلاهک گردگیر بلوئر","de":"توپ لاستیکی‌ای که با فوت باد گرد و خاک را می‌راند، دهانه‌ی خودش هم به همان اندازه در برابر گرد و خاک آسیب‌پذیر است. در زمان استراحت، همین کلاهک را رویش می‌گذارند. اینکه ابزاری که چیزهای دیگر را پاک می‌کند، اول دهان خودش را آرام می‌بندد، به‌نوعی مهربانانه است."},"ICON-0978":{"nm":"روکش دکمه شاتر","de":"اینکه شاتر داخل کیف خودسرانه فشرده شود و صد قاب از آسمان خالی ثبت شود، تجربه‌ای است که همه دست‌کم یک‌بار از سرگذرانده‌اند. این روکش کوچک روی دکمه، جلوی آن تلاش بیهوده را می‌گیرد. قفلی کوچک، برای ثبت‌کردن فقط لحظاتی که واقعاً می‌خواهی نگه‌داری."},"ICON-0979":{"nm":"برچسب دسته‌بندی باتری","de":"همیشه دردسر است وقتی باتری خالی و پر در یک جیب با هم قاطی شوند. برچسب رنگی روی هر باتری، آرام آن سردرگمی را مرتب می‌کند. قرمز یعنی خالی، سبز یعنی مطمئن. چراغ راهنمایی خاموشی که در محل فیلم‌برداری روشن نگه داشته می‌شود."},"ICON-0980":{"nm":"جداکننده کیف دوربین","de":"کیف را طوری تقسیم می‌کنند که لنز، بدنه و باتری اضافی به هم نخورند. کار ساختن چند اتاق کوچک درون یک بار. هر جا صاحب مشخصی دارد، پس حتی با تکان‌خوردن هم چیزی جایش را گم نمی‌کند."},"ICON-0981":{"nm":"پد دستکش عکاسی","de":"فیلم‌برداری زمستانی در فضای باز، جایی که فقط نوک انگشتی که شاتر را می‌فشارد نباید سرد شود. یک پد کلفت روی کف دست، دستکشی که در نوک انگشتان حس را باقی می‌گذارد. مصالحه‌ای مهربانانه از میدان کار، برای نگه‌داشتن گرما و دقت هر دو در یک دست."},"ICON-0982":{"nm":"لوله نوک قلم تبلت","de":"اینکه نوک قلم هم مثل نوک اتود فرسوده می‌شود را، کسی که مدت‌ها تبلت به دست گرفته می‌داند. این لوله‌ی کوچک که نوک‌های اضافه در آن غلتان جمع شده، مثل پس‌اندازی اضطراری برای سرانگشت است که خطی را که نباید قطع شود از پیش پر می‌کند."},"ICON-0983":{"nm":"سینی کیکپ کیبورد","de":"روزی که کیکپ‌ها را یکی‌یکی درآوردی، شستی و دوباره سوار کردی، این سینی به گلزاری کوچک بدل شد. منظره‌ی صامت‌ها و مصوت‌ها که خانه‌به‌خانه دراز کشیده‌اند و رطوبتشان خشک می‌شود. مراقبتی هست که فقط با یک‌بار باز کردن دیده می‌شود."},"ICON-0984":{"nm":"بسته پایه‌های ماوس","de":"رازِ لغزیدن روان ماوس روی میز، در همین پاهای کوچک چسبیده به کف آن است. بسته‌ای که وقتی فرسوده شد جایگزینش می‌کنی. زحمت چیزهایی که بی‌صدا از جایی نادیدنی، نرمی حرکت را بر دوش می‌کشند."},"ICON-0985":{"nm":"پایه لاستیکی لپ‌تاپ","de":"شبیه دفترچه است اما در واقع پایه‌ای لاستیکی است که لپ‌تاپ را بالا نگه می‌دارد. کمی بالابردن صفحه تا ارتفاع چشم، برای صاف‌کردن گردنی که خمیده شده. توجهی که وضعیت بدن را برای کسی که مدت‌ها می‌نویسد و می‌نگرد، درست می‌کند."},"ICON-0986":{"nm":"اسلایدر پوشاننده وب‌کم","de":"با انگشت هل می‌دهی و لنز را می‌پوشانی، دوباره هل می‌دهی و بازش می‌کنی. آرزوی اینکه فقط زمانی دیده شوی که خودت بخواهی. در همین یک اسلایدر کوچک، آسودگی بزرگی به‌نام حریم خصوصی جای گرفته. صدای بسته‌شدنش به‌نوعی اطمینان‌بخش است."},"ICON-0987":{"nm":"برچسب دسته‌بندی USB","de":"پنج میله‌ی سیاه شبیه به هم، و هیچ راهی برای دانستن اینکه در کدام‌یک چه چیزی ذخیره شده. با چسباندن یک برچسب کوچک و دادن نامی به آن، تازه از آن پس عضو خانواده‌ی تو می‌شود. برای پیدا‌کردنِ آسان هم، اول باید نامی برای صدا زدن داشته باشد."},"ICON-0988":{"nm":"گوشه‌گیر زیردستی میز","de":"وقتی گوشه‌های زیردستی میز مدام لوله می‌شوند، حتی دست‌خط هم کج می‌شود. این قطعه‌های کوچک که چهار گوشه را آرام پایین نگه می‌دارند، صلح صاف روی میز را نگهبانی می‌کنند. سطح باید آرام باشد تا نوک انگشت هم آرام شود."},"ICON-0989":{"nm":"گیره پایه هاب","de":"گیره‌ای که هابی را که چند سیم در آن جمع می‌شود، به‌طور مایل روی لبه‌ی میز نگه می‌دارد. منظره‌ی سیم‌های شلوغ که به یک نقطه جمع و مرتب می‌شوند. مهارت گره‌زدن آشفتگی به یک رشته، اینجا هم زنده است."},"ICON-0990":{"nm":"درپوش اسپری تمیزکننده صفحه","de":"درپوش کوچکی برای دهانه‌ی اسپریی که ردّ انگشت روی صفحه را پاک می‌کند. همیشه محکم بسته می‌شود تا مایع نه نشت کند و نه خشک شود. برای دیدن روشن، اول باید وسیله‌ی تمیزکردن را حفظ کرد؛ این ترتیب ساده‌ی خانه‌داری است."},"ICON-0991":{"nm":"کیف کارت حافظه","de":"چند روز از تصاویر صحنه، آرام درون کارتی به اندازه‌ی ناخن به خواب رفته. اگر گم شود، کل آن روز یک‌جا محو می‌شود، پس آن را با عزیزداشتن در کیفی کوچک جمع می‌کنند. خانه‌ای که کوچک‌ترین و در عین حال بزرگ‌ترین خاطره را در خود جای می‌دهد."},"ICON-0992":{"nm":"برچسب‌گذاری هارد اکسترنال","de":"پنج هارد اکسترنال سیاه با چهره‌ای یکسان در کشو خوابیده‌اند. کار چسباندن برچسب و نام‌گذاری‌شان به «آن تابستان» یا «کلیپ‌های منتشرنشده». کاری برای نصب یک نمایه‌ی روشن روی خاطره‌ای مبهم."},"ICON-0993":{"nm":"مهره چک‌کردن بکاپ","de":"اینکه بکاپ گرفته شده یا نه، همان تفاوت مویینه‌ای‌ست که دل را می‌فشارد. این مهره‌ی کوچک که در جای تمام‌شده آرام جا داده می‌شود، می‌گوید «تا اینجا امن است». اطمینان، از جا‌گذاشتن یک نشانه می‌آید."},"ICON-0994":{"nm":"توکن یادداشت ابری","de":"توکنی که یک خط یادداشت را به سوی انباری جایی در آسمان می‌فرستد. جادویی کوچک که هر جا روشنش کنی، همان نوشته به استقبالت می‌آید. آسمان شبی که در آن بادبادک فرستاده و آرزو نوشته می‌شد، حالا گویی آرام روی کف دست فرود آمده."},"ICON-0995":{"nm":"ست کلاهک محافظ USB","de":"اگر انتها با کانکتور برهنه داخل کیف بغلتد، تماس‌گاه‌ها بالاخره خراب می‌شوند. روی هر انتها کلاهک کوچکی می‌گذارند و به‌صورت یک دست جمع می‌کنند. کاری برای خواباندن آرام زمان بی‌استفاده. آرام‌ترین آماده‌سازی برای اتصال بعدی."},"ICON-0996":{"nm":"بند جعبه داده","de":"بندی که دستگاه حامل داده‌ی باارزش را دور تا دور محکم می‌گیرد و می‌بندد. در کیفی که تکان می‌خورد، یک دور محکم دورش می‌پیچند تا چیزی به هم نخورد. دستی که زمانی بقچه را با دقت گره می‌زد، در دنیای دیجیتال هم همچنان زنده است."},"ICON-0997":{"nm":"برچسب مرتب‌سازی فایل","de":"وقتی صدها فایل بی‌نام روی هم انباشته شوند، پیدا‌کردن خودش سرگردانی می‌شود. لحظه‌ای که با نصب برچسب‌های رنگارنگ شاخه‌ای باز می‌شود، میان توده‌ی شلوغ راهی پدیدار می‌شود. مرتب‌کردن، در نهایت کاری برای بازکردن یک راه است."},"ICON-0998":{"nm":"کارت راهنمای رمز عبور","de":"نوشتن کامل رمز خطرناک است، و اصلاً ننوشتن هم باعث فراموشی می‌شود. پس فقط سرنخی که تنها خودت می‌فهمی باقی می‌گذاری. مثل «همان شهرِ اولین اجرا». روشی هوشمند و مهربانانه برای به‌یادسپردن، که راه را می‌نویسد، نه پاسخ را."},"ICON-0999":{"nm":"برچسب تاریخ نگهداری","de":"اگر روز گذاشتن چیزی را ننویسی، نگهداری خیلی زود به فراموشی بدل می‌شود. برچسب تاریخی که روی هر جعبه چسبانده شده، «از کِی» را واضح حک می‌کند. دل انبار قدیمی که روز درست‌کردن سس تخمیری خانه را می‌نوشت، روی همین کاغذ کوچک ادامه می‌یابد."},"ICON-1000":{"nm":"کلاهک مینی رینگ‌لایت","de":"کلاهکی که سوراخ نورِ چراغ کوچکی که نور گرد می‌تاباند را می‌پوشاند. نور را لحظه‌ای می‌خواباند تا لنز داخل کیف خط نیفتد. نگه‌داشتن آرام تاریکیِ پیش از روشن‌شدن هم، یکی از راه‌های عزیزداشتن روشنایی است."},"ICON-1001":{"nm":"پیچ محکم‌کننده‌ی پایه","de":"یک دور دیگر، همین و بس. شکاف شل شده ناپدید می‌شود و اطمینانی سنگین زیر کف دست می‌نشیند. پشت صحنه‌ای که نمی‌لرزد، همیشه یک چرخش ماهرانه‌ی مچ دست کسی پنهان است. آنچه این پیچ کوچک بر دوش می‌کشد، استحکامی است که دیده نمی‌شود."},"ICON-1002":{"nm":"نشانه‌ی «در حال پخش زنده»","de":"همان لحظه که چراغ قرمز روشن می‌شود، صدای قدم‌ها در راهرو آرام‌آرام به نوک پا تبدیل می‌شود. پیش از آن یک کلمه‌ی «در حال پخش»، همه نفس در سینه حبس می‌کنند. این تراشه‌ی کوچک بی‌صدا اعلام می‌کند که حتی سکوت پشت در هم دلی‌ست رو به کسی."},"ICON-1003":{"nm":"دفترچه یادداشت گفتگو","de":"تشویق‌هایی را که از صفحه می‌گذرند و ناپدید می‌شوند، با نوک انگشت نگه می‌دارد. لحظه‌ای که هر کلمه‌ای که قرار بود بگذرد و برود، شمرده و روشن روی کاغذ می‌ماند. ثبت کردن، جایگاهی است که در آن مهربانیِ خواستنِ رسیدن، حتی با تأخیر، ماندگار می‌شود."},"ICON-1004":{"nm":"روکش بی‌صدای صفحه‌کلید","de":"ساعت دو نیمه‌شب، و صدای فشردن دکمه‌ها انگار دروغی بوده که ناپدید می‌شود. یک پوشش نازک، تا نفس‌های آرام هم‌اتاقیِ در خواب را بیدار نکند. آرام‌ترین ملاحظه همیشه از جایی بی‌صدا آغاز می‌شود."},"ICON-1005":{"nm":"گیره‌ی بازوی میکروفون","de":"بین لب‌ها و میکروفون، دقیقاً همان فاصله‌ای که آواز نمی‌لرزد. این گیره‌ی کوچک آن قول را محکم نگه می‌دارد. پشت صحنه همیشه دستی این‌گونه پیش‌تر آمده تا چیزها را استوار نگه دارد."},"ICON-1006":{"nm":"گیره‌ی پارچه‌ی پس‌زمینه","de":"حتی وقتی باد می‌وزد، پارچه‌ی پس‌زمینه تکان نمی‌خورد. چون یک فک کوچک که گوشه را محکم گاز گرفته، تمام صحنه را نگه داشته است. پشت منظره‌ای که نمی‌لرزد، کسی در جایی نادیده دندان‌هایش را به هم فشرده است."},"ICON-1007":{"nm":"برچسب دسته‌ی استریم","de":"روی ده‌ها دکمه، برچسب‌های کوچک اسم می‌گذارند تا دست راهش را گم نکند. یک خط برچسب، یک اشتباه پخش زنده را از پیش پاک می‌کند. آرامش از حروفی می‌آید که پیش از لرزیدن نوشته شده‌اند."},"ICON-1008":{"nm":"دکمه‌ی مهر زمان","de":"فشارش بده، و پرچمی کوچک روی زمانی که در حال گذر بود کاشته می‌شود. کاری برای مهر زدن بر همین لحظه‌ای که دیگر هرگز باز نمی‌گردد. مدتی بعد که نگاه کنی، آن نشانه دری شده به سوی خاطره."},"ICON-1009":{"nm":"جاکلیدی خواننده‌ی تگ","de":"نزدیکش کنی، «بیپ»ی می‌کند و اطلاعات بیدار می‌شود. همراهی کوچک آویزان از جاکلیدی که در جیب تلق‌تلق صدا می‌دهد. یک روز عادی با همین بوق‌های کوچک به سلامت ادامه پیدا می‌کند."},"ICON-1010":{"nm":"برچسب پریز هوشمند","de":"به هر پریز نامی بدهی، دیگر سردرگم نمی‌شوی که کدام سیم مال کدام است. دلی که حتی به برقِ نادیده هم نامی می‌بخشد. نظم و ترتیب، چهره‌ی دیگری‌ست که مهربانی گاهی به عاریت می‌پوشد."},"ICON-1011":{"nm":"پایه‌ی حسگر دما و رطوبت","de":"نگهبانی به اندازه‌ی کف دست که بی‌صدا دما و رطوبت اتاق را می‌پاید. آسایش هرگز دهان باز نمی‌کند، اما این پایه هر لحظه آرام حال تو را می‌سنجد. سلامتی این‌گونه، آرام و بی‌صدا، محافظت می‌شود."},"ICON-1012":{"nm":"کلاهک حسگر بازشدن در","de":"چشمی کوچک که آن لحظه‌ی آرام باز شدن در را از دست نمی‌دهد. بی‌صدا نشانه‌ی برگشتن کسی را می‌رساند. آنچه از خانه‌ی خالی نگهبانی می‌کند، همیشه همین چیزهای بی‌کلام‌اند."},"ICON-1013":{"nm":"نگه‌دارنده‌ی دکمه‌ی ریموت","de":"کنترل‌هایی که این‌سو و آن‌سو می‌غلتیدند، بالاخره جای همیشگی خود را می‌یابند. جایگاهی کوچک که آرام چیزی را که نزدیک بود گم شود نگه می‌دارد، دستی که از پیش قول دیدار دوباره را حک می‌کند."},"ICON-1014":{"nm":"نشان اپلیکیشن خواب","de":"هر شبی که خوب می‌خوابی، یک پاداش گرد دیگر می‌غلتد و روی هم می‌نشیند. اپلیکیشن با مهربانی می‌گوید که خواب هم مثل تمرین، کم‌کم انباشته می‌شود. کوچک‌ترین جایزه‌ی دنیا، هدیه‌ای به تویی که خوب استراحت کردی."},"ICON-1015":{"nm":"پایه‌ی مکعب تایمر","de":"در حالی که سه دقیقه شمرده‌شمرده می‌گذرد، مکعب بی هیچ لرزشی زمان خودش را می‌شمارد. جایگاهی کوچک به اندازه‌ی کف دست که از پایین آرام نگهش می‌دارد. حتی انتظار هم به کفی نیاز دارد که بتوان با آرامش رویش ایستاد."},"ICON-1016":{"nm":"روکش چراغ اعلان","de":"تا زیادی روشن نباشد، نور را در یک لایه نرم در آغوش می‌گیرد. اعلان می‌تواند فوری باشد، اما بگذار دست‌کم چشم‌ها آسوده بمانند. ملاحظه، دلی است که حتی شدت نور را هم آرام می‌سنجد."},"ICON-1017":{"nm":"کارت تعویض باتری","de":"وقتی این کارت پیدایش می‌شود، یعنی وقت آن رسیده که قلب کوچک درون دستگاه را عوض کنی. اشاره‌ای مهربان برای رسیدگی پیش از آنکه بایستد. راز همراهی طولانی، همیشه در مراقبتی است که یک قدم جلوتر می‌آید."},"ICON-1018":{"nm":"مجموعه کلاهک جویستیک","de":"کلاهک‌های کوچکی که آرام سر می‌شوند تا شست نلغزد. حس نوک انگشت باز هم روشن‌تر می‌شود. همین یک کلاهک کوچک گاهی برد و باخت یک دستِ عرق‌کرده را رقم می‌زند."},"ICON-1019":{"nm":"روکش داک سوییچ","de":"جایگاه استراحت کنسول را آرام از گرد و غبار می‌پوشاند. چون حتی دستگاهی که اندکی خوابیده هم به یک پتو نیاز دارد. دلِ مراقب، در واقع وقتی چیزی استفاده نمی‌شود، روشن‌تر خودش را نشان می‌دهد."},"ICON-1020":{"nm":"کیف کنسول دستی","de":"هنگام جابه‌جایی، حتماً درون این. کیسه‌ای که کنسول دستی را نرم در آغوش می‌کشد. تا حتی با تکان‌های این‌سو و آن‌سو در کیف هم آسیب نبیند؛ چیزهای عزیز را بهتر است یک بار دیگر هم بپیچی."},"ICON-1021":{"nm":"مجموعه استیکر دکمه","de":"فقط یک نقش کوچک روی دکمه‌ی ساده بگذاری، همان لحظه کاملاً از آنِ تو می‌شود. کاری برای برجای‌گذاشتن نشانی خودت روی دستگاهی یکسان با بقیه. فردیت همیشه آرام از همین گوشه‌های کوچک شکوفا می‌شود."},"ICON-1022":{"nm":"جعبه کارتریج بازی","de":"یک بازی که تمام شب در آن غرق بودی، درون این جعبه‌ی کوچک به خواب عمیق می‌رود. درش را دوباره باز کنی، همان شب دست‌نخورده بیدار می‌شود. خاطرات، به‌طرز عجیبی، اغلب در جعبه‌ای به اندازه‌ی کف دست جای می‌گیرند."},"ICON-1023":{"nm":"پایه فن خنک‌کننده","de":"در حالی که باد گرما را خنک می‌کند، جایگاهی که دستگاه را کمی کج نگه می‌دارد. برای بدنی داغ‌شده فرصتی می‌سازد تا نفسی تازه کند. برای دور دویدن، باید بلد باشی لحظه‌ای بایستی و خنک شوی."},"ICON-1024":{"nm":"پین بند مچی","de":"دور مچ بپیچی و پین را ببندی، هرچقدر هم حرکت شدید باشد، کنترلر از کنارت جدا نمی‌شود. این بند که آزاردهنده به نظر می‌رسد، در واقع همان اطمینانی است که می‌گذارد با خیال راحت بازی کنی."},"ICON-1025":{"nm":"کلاهک دسته‌ی آنالوگ","de":"روی دسته‌ای که از دست‌مالی طولانی صاف و براق شده، لباسی نو می‌پوشانی. حسی را که دستت به آن عادت کرده همان‌طور رها می‌کنی، فقط سطحش تازه می‌شود. لحظه‌ای که آشنایی و هیجانی تازه در یک دست کنار هم آرام می‌گیرند."},"ICON-1026":{"nm":"برچسب اسلات ذخیره","de":"روی هر خانه‌ی ذخیره، شمرده می‌نویسی ماجراجویی از آنِ کیست. یک خط برچسب، بی‌صدا از سفر چند روز گذشته نگهبانی می‌کند. بهتر است روی خاطرات عزیز نامی حک شود، تا رویشان نوشته نشود."},"ICON-1027":{"nm":"کیف ضبط‌صوت","de":"دستگاهی که صدا را در خود جای می‌دهد، به خاطر آنچه درونش هست، عزیزتر می‌شود. آن را با ظرافت درون کیسه‌ای نرم که از ضربه محافظت می‌کند، حمل می‌کنی. شاید صدای کسی درونش خفته باشد، پس با احتیاط بیشتر."},"ICON-1028":{"nm":"کلاهک باد‌شکن میکروفون","de":"صدای باد را کنار می‌زند و تنها صدا را باقی می‌گذارد. کلاهی نرم که در ضبط بیرون، آرام روی میکروفون کشیده می‌شود. صافی‌ای کوچک که از میان همهمه‌ی درهم، فقط صداقت را برمی‌گزیند."},"ICON-1029":{"nm":"برچسب یادداشت صوتی","de":"این یکی شعری‌ست که به ذهن رسیده، آن یکی آهنگی زیرلبی. روی هر یادداشت صوتی برچسبی رنگی می‌چسبانی. تکه‌های الهام که این‌سو و آن‌سو پراکنده بودند، بالاخره جای خود را می‌یابند و به صف می‌ایستند."},"ICON-1030":{"nm":"تراشه‌ی دکمه‌ی سمپلینگ","de":"فشارش بده، و تکه‌ای صدا که از پیش ذخیره شده بیرون می‌جهد. قطره‌ی باران، کف‌زدن، خنده‌ی کسی؛ تکه‌های جهان زیر نوک انگشتت بیدار می‌شوند. موسیقی، همسرایی مهربان همین تراشه‌های کوچک است."},"ICON-1031":{"nm":"پاکت جمع‌آوری صدا","de":"صداهایی را که در راه رفتن ناگهان می‌یابی، آرام درون این پاکت می‌گذاری. بافت باد، حتی سکوت کوچه‌ای در سپیده‌دم. موادی که روزی آهنگ می‌شوند، همیشه همین‌گونه ساده گرد هم می‌آیند."},"ICON-1032":{"nm":"پایه‌های سه‌پایه کوچک","de":"سه پا روی میز صحنه‌ای کوچک می‌گسترانند. به‌جای دستی لرزان، محکم می‌ایستند و صحنه را نگه می‌دارند. یک نمای شفاف، بالاخره از سه پایی زاده می‌شود که بی‌صدا ثابت ایستاده‌اند."},"ICON-1033":{"nm":"برچسب فایل ضبط","de":"روی صدها فایل ضبط‌شده، یک‌به‌یک برچسبی کوتاه می‌زنی. تا در یک نگاه بدانی کدام‌یک اولین بیتی بود که فلان روز جاری شد. نشانه‌ای کوچک که کمک می‌کند صداهای پراکنده را دوباره بیابی."},"ICON-1034":{"nm":"نوار استیکر موج صدا","de":"نواری موج‌دار که درست به شکل خودِ صدا شکل گرفته. دور دفتر یا جلدی بپیچی‌اش، انگار موسیقی پیش چشمانت پیداست. فریبی مهربان که آنچه شنیده می‌شود را دیدنی می‌کند."},"ICON-1035":{"nm":"قلاب آویز هدست","de":"وقتی تمرین تمام می‌شود، آرام جایی برای استراحت هدست خسته آماده می‌کند. قلابی کوچک که درست در گوشه‌ی میز فرو رفته. میزی مرتب، جایی‌ست که انگیزه‌ی فردا را از پیش آویزان می‌کنی."},"ICON-1036":{"nm":"نوار جعبه‌ی هدیه کوچک","de":"آخرین دوری که دور کمر جعبه‌ی هدیه پیچیده می‌شود. با همین یک نوار، دل بالاخره کامل می‌شود. صداقت اغلب پیش از آنچه درون است، از دستی که سطح بیرونی را نوازش می‌کند، منتقل می‌شود."},"ICON-1037":{"nm":"کلاهک دم روبان","de":"آرام دور انتهای روبان می‌پیچد تا باز نشود. جزئیاتی که به‌سختی به چشم می‌آید، آرام اولین برداشت از هدیه را دگرگون می‌کند. وقتی پایان‌بندی زیبا باشد، دل هم زیبا به مقصد می‌رسد."},"ICON-1038":{"nm":"موم مهر و موم","de":"قطره‌ای داغ را روی پاکت می‌چکانی تا مهرش کنی. مثل نامه‌ای قدیمی، قولی سنگین که می‌گوید بی‌خودی باز نکن. رسمیت گاهی همین‌طور، وزنی گرم در خود دارد."},"ICON-1039":{"nm":"نگه‌دارنده‌ی کارت تشکر","de":"کارتی را که کلمات تشکر در خود دارد، صاف نگه می‌دارد تا چروک نخورد. تا دل ایستاده و راست به مقصد برسد. سپاس وقتی حتی شکلش هم مرتب باشد، بیشتر در دل می‌ماند."},"ICON-1040":{"nm":"کاغذ پرکننده‌ی ستاره‌ای","de":"کاغذهایی که به شکل ستاره بریده شده‌اند، فضای خالی جعبه را نرم پر می‌کنند. پنبه‌ی دلی که آرزو می‌کند حتی با تکان خوردن هم چیزی آسیب نبیند. حتی در تاریکی درون بسته‌بندی، انگار یک ستاره‌ی کوچک معلق است."},"ICON-1041":{"nm":"برچسب فهرست هدیه","de":"پیش از خانه‌ی نام گیرنده، قلم مدتی طولانی می‌ایستد. چهره‌ای که هنگام نوشتن نام به ذهن می‌آید، فصل‌هایی که با هم گذرانده‌اید. لحظه‌ای که بسته می‌شود، این کاغذ کوچک رازی می‌شود که تا باز نشود کسی نمی‌تواند بخواند."},"ICON-1042":{"nm":"مهر تبریک","de":"فشارش بده، و تبریکی گرد و روشن چاپ می‌شود. در آن لحظه‌ی کوتاه که منتظر خشک شدن جوهر می‌مانی، دلی که فکر می‌کند به چه کسی بدهد، گرم‌ترین لحظه است. اگر عیبی داشته باشد، همین است که دوباره دلت می‌خواهد مهرش کنی."},"ICON-1043":{"nm":"قرقره‌ی نخ هدیه","de":"با دقت پیچیده شده، سپس شاداب زیر نوک انگشتان هیجان‌زده‌ی کسی باز می‌شود. در آن لحظه‌ی کوتاه پیچیدن و باز شدن، دلی که به نخ بسته بود، بالاخره هدیه می‌شود."},"ICON-1044":{"nm":"آویز گره (نه یک گل)","de":"تقلیدِ گل نیست، بلکه شکلی است که یک رشته‌ی تنها بارها خودش را در آغوش گرفته و خودبه‌خود شکفته. صبر نوک انگشتانی که تمام شب گره‌ها را انتخاب می‌کرد، همچون این غنچه‌ی کوچک باقی مانده است."},"ICON-1045":{"nm":"کیسه‌ی سکه‌ی خوش‌یمن","de":"دلی که چند سکه را آرام در جیب کسی که به راه دوری می‌رفت می‌گذاشت. کاری برای پر کردن نه با وزن، بلکه با مهربانی. صدای جرینگ‌جرینگ هر قدم، جای احوال‌پرسیِ سفر خوش را می‌گیرد."},"ICON-1046":{"nm":"آویز کپسول آرزو","de":"درون پوسته‌ای گرد، آرزویی تاشده آرام به خواب رفته. این‌که باز کردنش آرزو را برآورده می‌کند دروغ است، اما این‌که نگه‌داشتنش بی‌آنکه باز شود، آن آرزو را برای همیشه زنده نگه می‌دارد، حقیقت است."},"ICON-1047":{"nm":"بند گره‌ی محافظ","de":"بندی که محکم با نخ‌های پنج‌رنگ بافته شده، انرژی بد را از پشت سرت برمی‌گرداند. مثل دست مادربزرگ که در کودکی گره‌ای دور مچت می‌بست، در هر جای بسته‌شده دعای کسی به‌زیبایی نشسته است."},"ICON-1048":{"nm":"جعبه‌ی جرثقیل کاغذی کوچک","de":"از هزار جرثقیل کاغذی که باید تا زد تا آرزویی برآورده شود، خانه‌ای کوچک تنها یکی را از آسیب مصون نگه می‌دارد. چون اگر حتی یک بال هم چروک بخورد، درست همان دلبستگی‌ای که آن شب صرف شد آرام باز می‌شود."},"ICON-1049":{"nm":"کیسه‌ی سنگ‌های برّاق","de":"دانه‌های نور که از لباس صحنه فرو ریخته‌اند، جایی که دلت نمی‌آید دورشان بیندازی و جمعشان می‌کنی. حتی برقی که وقتی یک‌بار بنشیند تا یک هفته دنبالت می‌آید، اینجا آرام مثل روی کف دست به خواب می‌رود."},"ICON-1050":{"nm":"تراشه‌ی مهر روز خوب","de":"کارتی کوچک که هنگام انتخاب روز خوب، آرام اضافه می‌کنی. نه بر آستانه‌ی فالگیر، بلکه روی میز خودم، تکه‌ای خرافه‌ی مهربان که آرام مهرش می‌زنی و آرزو می‌کنی امروز فقط اتفاق‌های خوب بیفتد."},"ICON-1051":{"nm":"کارت دستبند آرزو","de":"روی یک برگ کاغذ که به شکل دستبند چاپ شده، آرزوی آرام کسی نشسته. حتی اگر نتوانی دور مچت ببندیش، در عمق کیف پولت بگذاری‌اش، آن دل همیشه به کنارت بسته می‌ماند و همراهت راه می‌رود."},"ICON-1052":{"nm":"شیشه‌ی نمک جلوی در","de":"نمک درشت را در شیشه‌ای کوچک ریخته و آرام کنار در می‌گذارند. حساب‌وکتاب قدیمی‌ای که انرژی بد را برمی‌گرداند و تنها مهمان‌های خوش‌آمد را راه می‌دهد. هر دانه‌ی شور، دربان کوچکی است که از خانه‌مان نگهبانی می‌کند."},"ICON-1053":{"nm":"برچسب پوششِ شماره‌ی شانس","de":"درست پیش از خراشیدن، همه برای لحظه‌ای برنده‌اند. این برچسب که آرام شماره‌ی خوش‌شانس را می‌پوشاند، از آخرین ثانیه‌ای که امید بیشترین اوج را دارد نگهبانی می‌کند. حتی اگر نوک انگشتان خراشنده بلرزند، بی‌اعتنا چشمانش را می‌بندد."},"ICON-1054":{"nm":"کلاهک نگه‌داری شمع تولد","de":"دلی مرتب که حتی شمعی را که یک‌بار روشن شده تا تولد بعدی به‌زیبایی نگه می‌دارد. اگر آرزوی پارسال هنوز برآورده نشده، حساب‌وکتاب مهربانی می‌گوید امسال از همان‌جا ادامه بدهی و دوباره آرزو کنی."},"ICON-1055":{"nm":"انگشتر شمارش معکوس سالگرد","de":"چیزی گستاخ که روز موعود را روی انگشتت می‌گذارد. هر بار که شماره‌ی روزهای باقی‌مانده یک پله پایین می‌آید، قلب هم به همان اندازه جلوتر کشیده می‌شود. خودش تنهایی اصرار می‌کند که روزی که به صفر برسد، خودش می‌درخشد."},"ICON-1056":{"nm":"بند کلاه مهمانی","de":"بندی نازک که کلاه مخروطی را آرام روی سر ثابت نگه می‌دارد. صاحب اصلی جشن به‌زودی از تنگی شکایت می‌کند و درش می‌آورد، اما در عکس همان یک قاب برای همیشه سرش مانده. همین برای مأموریتش کافی است."},"ICON-1057":{"nm":"نشان کوچک کیک","de":"نشانه‌ای کوچک فرورفته در کیکی به اندازه‌ی دو بند انگشت. حتی روی شیرینی‌ای که با یک گاز ناپدید می‌شود، تبریک قدش را راست نگه می‌دارد. هرچند کوچک، تولد باز هم تولد است، و ستاره‌ی امروز تویی."},"ICON-1058":{"nm":"برچسب ترقه‌ی جشن","de":"صدای «پاف» ندارد، اما چشم‌نوازترین ترقه‌ی کاغذی است. لحظه‌ای که به پاکت می‌چسبد، یک محموله‌ی پستی معمولی به نامه‌ای از یک جشن تبدیل می‌شود. خیلی‌ها دلشان نمی‌آید بکنندش و همان‌طور رهایش می‌کنند."},"ICON-1059":{"nm":"گیره‌ی آویز عکس","de":"نگران از دست دادن خاطره‌ای که به بند آویزان است، همیشه دهانم را محکم بسته نگه می‌دارم. تا وقتی که یک عکس در گازم گرفته شده، حتی نسیمی که از لای پنجره می‌آید هم نمی‌تواند آن روزها را بیندازد."},"ICON-1060":{"nm":"وصله‌ی بادکنکِ تاریخ","de":"وصله‌ای به شکل بادکنک با عددی رویش. به لباس بچسبانی‌اش، تمام محله می‌فهمند امروز چندمین روز خاصی است. بکنی‌اش، ردی می‌ماند، و همان رد کم‌رنگ هم یادگاری دیگری می‌شود."},"ICON-1061":{"nm":"نشانه‌ی تبادل هدیه","de":"نشانه‌ای شیطنت‌آمیز که دست گیرنده و دهنده را کمی به‌هم می‌ریزد. قانونی کوچک و مهربان بر سر میز تبادل هدیه، که می‌گوید بیشتر از آنکه به‌یاد بیاوری چه کسی داد، به‌یاد بیاور چه چیزی رد و بدل شد."},"ICON-1062":{"nm":"شماره‌ی میز جشن","de":"شماره‌ای کوچک که روی هر میز جشن ایستاده. تعیین از پیش اینکه چه کسی کجا بنشیند، از خجالت کشیدن جلوگیری می‌کند و حکمت گرم کسانی را در خود دارد که بارها جشن برگزار کرده‌اند."},"ICON-1063":{"nm":"کیسه‌ی هدیه‌ی دستگیره‌ی در","de":"راهی برای رساندن دل بی‌آنکه زنگ را بزنی. آرام روی دستگیره‌ی در آویزانش کنی و مثل فراری ناپدید شوی، آنگاه چهره‌ی متعجب کسی که پیدایش می‌کند، بزرگ‌ترین هدیه‌ای می‌شود که به فرستنده بازمی‌گردد."},"ICON-1064":{"nm":"برچسب تحویل مخفی","de":"روی سطحش هیچ چیز نوشته نشده. پنهان نگه‌داشتن فرستنده تا آخر، غرور کوچک همین برچسب است. هرچه گیرنده بیشتر سرش را کج کند و بخندد، این مأموریت مخفیانه کامل‌تر می‌شود."},"ICON-1065":{"nm":"تراشه‌ی یادداشت زنگ در","de":"یادداشتی کوچک که وقتی جرأت در زدن نیست، به‌جایش می‌چسبانی. خطی کوتاه مثل «سری زدم و رفتم» بیشتر از صدای زنگ در ماندگار می‌ماند. چون خط خط دست‌نویس، چهره‌ی خودش را دارد."},"ICON-1066":{"nm":"کلاهک ایمنی کاتر بسته","de":"وقتی تیغ‌ کاتر بی‌احتیاط نوک انگشتان را نشانه می‌رود، قهرمانی کوچک آرام جلویش می‌ایستد. نوک انگشتانی را که از هیجان چیز نو شتاب گرفته‌اند، تا آخرین برش با امنیت نگه می‌دارد."},"ICON-1067":{"nm":"تکه‌ی پلاستیک حبابدار","de":"من برای فشرده شدن به دنیا آمده‌ام. با همان صدای «تاپ» که می‌ترکد، تنش روز چطور آرام باز می‌شود. روزهایی هم هست که خودم بیشتر از چیزی که دورش پیچیده بودم دوست داشته می‌شوم."},"ICON-1068":{"nm":"پین زمان رسیدن","de":"پینی که دقیقاً می‌گوید چه ساعتی می‌رسد. حتی انتظاری مبهم، وقتی یک نقطه پیدا می‌کند، تحمل‌پذیرتر می‌شود. اینکه تا آن ساعت چند بار به در ورودی سرک بکشی، کاملاً بر عهده‌ی خودت است."},"ICON-1069":{"nm":"جاکلیدی کمد بسته‌ی بدون نگهبان","de":"همراهی کوچک برای کسی که همیشه رمز کمد بسته را فراموش می‌کند. آویزان از جاکلیدی تلق‌تلق می‌کند، و هنر پنهانش این است که درست در لحظه‌ی حیاتی یک «آها، درسته» را از تو بیرون بکشد."},"ICON-1070":{"nm":"برچسب سبد ورودی","de":"برچسب اسمی روی سبد گوشه‌ی ورودی. قول بی‌کلامی رویش نوشته: «همین‌جا بگذار و برو». حتی خالی هم که باشد، جایی که منتظر دل کسی است، هرگز تنها نیست."},"ICON-1071":{"nm":"استیکر پوشاننده‌ی آدرس","de":"روی جعبه‌ای که دور می‌اندازی، نام را می‌گذاری و فقط آدرس را پاک می‌کنی. تا نام هم که همه بدانند اشکالی ندارد، اما محل زندگی رازِ خودت بماند. لحظه‌ای که این یک لایه را می‌کَنی و می‌چسبانی، آرامشی کوچک زاده می‌شود."},"ICON-1072":{"nm":"برچسب ظرف تنقلات","de":"برچسبی که در یک نگاه می‌گوید داخل ظرف چیست. اما نکته‌اش این است که نوشتن «تنقلات» بی‌آنکه در را باز کنی هم به تو دلگرمی می‌دهد. برچسب البته مسئولیت اشتهایت را برعهده نمی‌گیرد."},"ICON-1073":{"nm":"آویز گردنبند کوچک","de":"دانه‌ای کوچک که زیر لباس آرام دمای بدنت را با تو قسمت می‌کند. همیشه در جایی که چشم هیچ‌کس نمی‌بیند تماس دارد، و درست به همین دلیل عزیزتر است. نزدیک‌ترین دوستی که کنار قلبت همراهت راه می‌رود."},"ICON-1074":{"nm":"تشک مهر جای پا","de":"روی کف پا فشارش بدهی، ردیفی از جای پاهای کوچک باقی می‌ماند. دفتر خاطرات روزانه‌ی پیاده‌روی، شمرده روی کاغذ نوشته‌شده که چه کسی کجا رفته. اولین قدمِ آغشته به جوهر، همیشه از همه واضح‌تر است."},"ICON-1075":{"nm":"کلاهک برس مو","de":"کلاهکی کوچک که موهای درگیر شده در برس را با دقت رسیدگی می‌کند. در فصل ریزش، وقتی یک بار برس زدن یک مشت مو جمع می‌کند، بدون این کلاهک تمام خانه به دشتی برفی و کرکی بدل می‌شود. نظافتچی‌ای پرتلاش که ردی از خودش به‌جا نمی‌گذارد."},"ICON-1076":{"nm":"جعبه‌ی کیسه‌ی پیاده‌روی","de":"خانه‌ای کوچک که کیسه‌ی لازم برای پیاده‌روی را مرتب با خود حمل می‌کند. این جعبه هر روز آرام ثابت می‌کند که فقط کسی که از پیش آماده شده می‌تواند با آسودگی قدم بزند. همان یک کیسه‌ای که اگر فراموشش کنی، دردسر می‌شود."},"ICON-1077":{"nm":"برچسب پوشاننده‌ی نام","de":"برچسبی که اسم واقعی را زیرکانه می‌پوشاند و فقط لقب را باقی می‌گذارد. در این دنیا نوعی مهربانی هم هست که دلت نمی‌خواهد به هر کسی نشان بدهی. آن صدا زدنی خاص که فقط آشنایان می‌دانند، اینجا آرام پنهان شده."},"ICON-1078":{"nm":"زیرانداز کاسه‌ی آب","de":"زیر کاسه‌ی آب پهن شده، من همیشه خیسم. قطره‌هایی را که به هر سو می‌پاشند به‌جای زمین می‌گیرم و کف چوبی را خشک نگه می‌دارم. هیچ‌کس مرا تحسین نمی‌کند، اما من هم هرگز شکایتی ندارم."},"ICON-1079":{"nm":"نخ تعمیر عروسک","de":"عروسکی که درزش پاره شده را دور نمی‌اندازند، دوباره می‌دوزندش. با هر بخیه‌ای که می‌زنی، زمانی که با آن کوچولو گذرانده‌ای دوباره استوار می‌شود. تعمیر کردن، در نهایت، آرام به تعویق انداختن یک خداحافظی است."},"ICON-1080":{"nm":"گردنبند عکس یادگاری","de":"دلی که روشن‌ترین لبخند را دور گردن آویزان می‌کند. آن روز درون عکس، به‌جای اینکه بی‌حرکت بماند، با هر قدم همراهت تکان می‌خورد و تا امروز ادامه می‌یابد. آن لحظه‌ی خوب هرگز متوقف نمی‌شود."},"ICON-1081":{"nm":"تراشه‌ی رنگِ حال و هوا","de":"اگر دل هم رنگی داشت، امروز رنگ تو چه بود؟ همان لحظه که یک تراشه انتخاب می‌کنی و روی میز می‌گذاری، احساسی که کلمات از بیانش عاجز بودند، آرام گسترده می‌شود. رنگ غروب یا نور سپیده‌دم، هر دو خوب‌اند؛ آینه‌ای کوچک که آرام تویِ همان روز را بازتاب می‌دهد."},"ICON-1082":{"nm":"تسبیح ثبت امروز","de":"وقتی روز به پایان می‌رسد، امروز به‌شکل دایره‌ای درون تسبیح می‌نشیند. کارهای خوب و لحظات دست‌وپاچلفتی، همه با هم جمع و جور می‌شوند و می‌غلتند. روی کف دستت بگذاری‌اش، دیروزِ تو کمی گرم می‌شود و به پشتت می‌زند: امروز هم خوب زندگی کردی."},"ICON-1083":{"nm":"شیشه‌ی یادداشت‌های تحسین","de":"کلمات خوب خیلی راحت پراکنده می‌شوند، پس یکی‌یکی تایشان می‌زنی و درون این شیشه می‌گذاری. وقتی تحسین مثل عطر جمع می‌شود، در شب‌هایی که دل خالی است درش را باز می‌کنی. مهربانی‌ای را که کسی داده دوباره بیرون می‌کشی و می‌خوانی، و گرمای همان روز دوباره زنده می‌شود."},"ICON-1084":{"nm":"بند روبان آشتی","de":"دل درهم‌تنیده شبیه گره است؛ باز کردنش هم دقت می‌خواهد. دو نفر دو سر بند را بگیرند و آرام بکشند، ناگهان روبانی زیبا شکل می‌گیرد. این بند آرام یادآوری می‌کند که آشتی، بریدن نیست، دوباره بستن است."},"ICON-1085":{"nm":"نشان قدردانی","de":"روزهایی که «ممنونم» به‌سختی از زبانت جدا می‌شود، به‌جایش نشانی را آرام به دست کسی می‌دهی. دستی که آن را می‌گیرد، از همان وزن کوچک تمام دلت را می‌خواند. صداقتی که پیش از کلمات می‌رسد، محبتی که در یک دانه‌ی گرد جابه‌جا می‌شود."},"ICON-1086":{"nm":"نشانه‌ی زمان استراحت","de":"حتی استودیوی تمرینی که تمام روز دویده هم به یک نفس تازه نیاز دارد. این نشانه را روی در آویزان کنی، زمان لحظه‌ای آهسته می‌شود. هرکس روزی نفس‌گیر را گذرانده باشد، می‌داند که آواز برای نفس کشیدن به یک مکث نیاز دارد."},"ICON-1087":{"nm":"کشوی احساسات پنهان","de":"روزهایی هست که نمی‌توان همه‌ی درونت را بیرون ریخت. آن روزها، غم و هیجان را آرام درون کشویی کوچک در ذهن می‌گذاری و درش را می‌بندی. الان بگذاری‌شان اشکالی ندارد؛ روزی خواهد رسید که آرام بازش کنی و همه را مرتب کنی."},"ICON-1088":{"nm":"رول استیکر لبخند","de":"یک خانه جدا کنی، نشان لبخندی به نوک انگشتت می‌چسبد. شادیِ کوچکی که آرام روی گوشه‌ی دفتر یا کمد دوستی می‌چسبانی. وقتی خورشیدی کوچک روی کاغذ طلوع می‌کند، روز هرکسی که پیدایش کند کمی روشن‌تر می‌شود."},"ICON-1089":{"nm":"آویز زنگوله‌ی احوال‌پرسی","de":"دلی که آرزو می‌کند به تو در آن دور دست برسد، در یک زنگوله جمع شده. تکانش بدهی، صدایی روشن به‌جای تو احوال‌پرسی می‌کند. روزهایی که نتوانستی بگویی «حالت خوبه؟»، این طنین کوچک سوار بر باد پیشاپیش می‌رسد."},"ICON-1090":{"nm":"پین روکش باران بهاری","de":"در روزهای بارانی بهار، چیزهایی که بیشتر عزیزشان می‌داری، راحت‌تر خیس می‌شوند. با این پین جلد را ببندی، قطره‌های باران کج می‌شوند و می‌گذرند. دلی که یک کتاب عزیز را در آغوش می‌پیچد، پینی کوچک به‌جای آن مهربانی می‌کند."},"ICON-1091":{"nm":"استیکر خنک‌کننده‌ی تابستان","de":"یک برگ سریع روی پشت دستی خسته از گرمای نیمروز تابستان. حسی خنک مثل نعنا پخش می‌شود و عرق کمی فروکش می‌کند. همان خنکای دراز کشیدن روی ایوان چوبی و باد زدن با بادبزن را، کاغذی به اندازه‌ی کف دست با دلسوزی تقلید می‌کند."},"ICON-1092":{"nm":"تکه‌ پارچه‌ی چهارخانه‌ی پاییزی","de":"تکه‌ پارچه‌ی چهارخانه‌ای که به دشت پاییزی شباهت دارد. اثر وصله‌ای است که کسی با دقت روی جای فرسوده زده. دلی که به‌جای دور انداختن، وصله می‌زند؛ پارچه‌های کوچک گرد هم می‌آیند و چیز کهنه را دوباره گرم زنده می‌کنند."},"ICON-1093":{"nm":"گیره‌ی دستکش زمستانی","de":"دستکش‌های زمستانی چرا آن‌قدر تک‌تک فرار می‌کنند؟ این گیره دو تای‌شان را به هم وصل کند، دستان سرد راهشان را گم نمی‌کنند. آرزوی گم نکردنشان درون یک تکه فلز کوچک جای گرفته و دو تا را کنار هم نگه می‌دارد."},"ICON-1094":{"nm":"برچسب ضدآب فصل باران","de":"در فصل باران، حتی برچسب اسم هم زیر باران پخش می‌شود. این برچسب ضدآب حتی زیر بارانی سیل‌آسا نوشته‌اش را حفظ می‌کند. خطی که پس از قطع باران هم واضح می‌ماند، تا از کیست فراموش نشود."},"ICON-1095":{"nm":"شیشه‌ی نگهداری اولین برف","de":"اولین برف همان لحظه که به دست می‌رسد ناپدید می‌شود، پس دست‌کم آن هیجان را درون شیشه‌ای نگه داشته‌اند. آنچه پشت شیشه گیر افتاده برف نیست، بلکه دلی است که آن روز می‌تپید. تکانش بده، و یک زمستان دوباره می‌بارد و تو را به همان صبح می‌برد."},"ICON-1096":{"nm":"نوار پاکت عید","de":"یک نوار سرخ که دور پاکت عید پیچیده می‌شود. همه می‌دانند مهرِ دستی که می‌بخشد بیشتر از آنچه درون است می‌ارزد. دلی که آرزوی سلامتی را همراه برکت در خود می‌پیچد، در همین نوار باریک به‌زیبایی بسته شده."},"ICON-1097":{"nm":"نوار ظرف پیک‌نیک","de":"زیرانداز را پهن کنی و ناهار را باز کنی، باد پیوسته درها را بلند می‌کند. این نوار ظرف‌ها را محکم ببندد، پیک‌نیک از هم نمی‌پاشد. دلی که می‌خواهد یک وعده غذای آماده‌شده را تا آخر نگه دارد، در یک نوار کوچک جای گرفته."},"ICON-1098":{"nm":"کارت نمونه‌ی عطر فصل","de":"تا حتی بدون باز کردن هم فصل را بشناسی، عطر آن فصل در یک کارت جای گرفته. بهار بوی گل، پاییز بوی برگ خشک. لحظه‌ای که به بینی می‌رسد، تمام فصل یک‌جا به یاد می‌آید: «این هوای ماه آوریل است»."},"ICON-1099":{"nm":"کلیپ‌بورد برچسب قیمت","de":"دردسر بساطی که برچسب قیمتش پیوسته پرواز می‌کرد را همین یک کلیپ‌بورد آرام کرد. عدد را محکم گاز می‌گیرد و صاف جلوی مشتری می‌گیرد. اولین سلام یک کسب‌وکار، از یک خط صادق و بی‌آشفتگی آغاز می‌شود."},"ICON-1100":{"nm":"تخته‌ی برگردان «باز است»","de":"این تخته را جلوی در برگردانی و آویزان کنی، مغازه بالاخره بیدار می‌شود. از «در حال آماده‌سازی» به «خوش آمدید». نشانه‌ای کوچک که آغاز روز را اعلام می‌کند، جایی که دست صاحب هر صبح اول از همه به آن می‌رسد."},"ICON-1101":{"nm":"پد مهر کارت امتیاز","de":"وقتی همه‌ی ده خانه پر شود، انگار اتفاق خوبی در راه است. هر مهر، قدم یک مشتری همیشگی است و محبتی که کم‌کم انباشته شده. روی هر جای مهری که تا خشک‌شدن جوهر روی پد مانده، وعده‌ی کوچکِ «باز هم می‌آیم» نفس می‌کشد."},"ICON-1102":{"nm":"کلاهک دسته‌ی کیسه‌کاغذی","de":"دسته‌ی کیسه‌ی کاغذی همیشه در برابر وزن ضعیف است. این کلاهک را که بپوشانی، بندی که نزدیک بود پاره شود محکم می‌شود. آرزوی این‌که آنچه درون است سالم به خانه برسد؛ یک قطعه‌ی کوچک، این راه را تا انتها نگه می‌دارد."},"ICON-1103":{"nm":"سینی سکه‌ی صندوق","de":"این سینی آرام، تردیدِ دست‌به‌دست شدنِ پول خرد را کم می‌کند. صدای جرینگ‌جرینگِ سکه‌ها که جای خود را پیدا می‌کنند. دادوستد به لطف همین ملاحظه‌ی گرد و کوچک، گرم‌تر می‌شود."},"ICON-1104":{"nm":"تراشه‌ی امتیاز","de":"قدم‌های امروز، یکی‌یکی در یک تراشه انباشته می‌شوند. حسابی عجیب که هرچه بیشتر جمع شود، دل سبک‌تر می‌شود. لذتِ پرکردن آرام‌آرام، به شادیِ تماشای پر شدن ناگهانیِ کوزه‌ای خالی شبیه است."},"ICON-1105":{"nm":"پین شماره‌ی قفسه","de":"روی هر قفسه، شماره‌ای کوچک با محبت سنجاق شده است. راهنمایی خاموش که می‌گوید چه چیزی کجاست. دلی که از پیش جا را نشان می‌دهد تا کسی سرگردان نشود؛ حتی نظم هم می‌تواند این‌قدر گرم باشد."},"ICON-1106":{"nm":"لیوان سیخ چشش","de":"لیوانی کوچک که یک لقمه‌ی مزه‌مزه‌کردن را جلو می‌گیرد. حتی مشتریِ مردد هم با همین یک تکه، آرام‌آرام دلش باز می‌شود. سخاوتِ «یکی امتحان کن»، از نوک سیخ آویزان است و قدم‌های تازه‌وارد را نگه می‌دارد."},"ICON-1107":{"nm":"نگه‌دارنده‌ی فهرست رزرو","de":"نام مهمانان امروز، منظم در این نگه‌دارنده ایستاده‌اند. وعده‌ای مهربان که حتی انتظار هم نوبت دارد. سرپا نگه‌داشتن یک برگه‌ی کاغذ، اولین آماده‌سازیِ دقیق برای استقبال از روزِ کسی می‌شود."},"ICON-1108":{"nm":"گیره‌ی طناب عکس دیواری","de":"طنابی روی دیوار می‌بندند و عکس‌ها را یکی‌یکی با گیره آویزان می‌کنند. لحظه‌های خندان، مثل لباس‌های شسته کنار هم آویزانند و خشک می‌شوند. خاطرات را در جایی که آفتاب می‌تابد پهن کن؛ هر بار که رد می‌شوی، خنده‌ی همان روز دوباره به اهتزاز درمی‌آید."},"ICON-1109":{"nm":"گوشه‌ی قالیچه‌ی کوچک","de":"قالیچه‌ای کوچک که در گوشه‌ی اتاق پهن شده. جایی که اول از همه، گرما را روی کف سرد می‌پاشد. اولین وجب‌جایی که پای برهنه لمس می‌کند؛ نوک پاهایی که به خانه برگشته‌اند، اینجا بالاخره آسوده و کرخت می‌شوند."},"ICON-1110":{"nm":"پارچه‌ی پوشش تابلوی نام","de":"پارچه‌ای که به‌آرامی تابلوی نام را می‌پوشاند. پنهان‌کردن اسم برای مدتی هم نوعی ظرافتِ خانه‌داری است. پرده‌ای زیبا روی مرز میان درون و بیرون؛ دلی که امروز می‌خواهد آرام استراحت کند، نرم آویزان می‌شود."},"ICON-1111":{"nm":"گیره‌ی سیم چراغ","de":"این گیره، سیمِ آویزانِ چراغ را مرتب نگه می‌دارد. دستی که راه را صاف می‌کند تا نور پراکنده نشود. غروب که فرا می‌رسد، یک سیمِ درهم را که مرتب کنی، هم نورِ اتاق و هم دل آرام‌تر می‌شود."},"ICON-1112":{"nm":"کلاهک مغناطیسی پوستر","de":"کلاهکی مغناطیسیِ کوچک برای چسباندن پوستر به دیوار. کاغذ بی‌آنکه حتی یک سوراخ پونز بخورد، جایش را حفظ می‌کند. دستی که با چیز عزیزش برخورد می‌کند همیشه نرم است؛ دلِ آسیب‌نرساندن، همین‌جا نهفته است."},"ICON-1113":{"nm":"بند منگوله‌دار پرده","de":"بندی منگوله‌دار که پرده را به یک‌ سو می‌بندد. راهی زیبا برای ورود آفتاب صبحگاهی باز می‌کند. یک‌بار بند منگوله‌دار را بکش، روزی روشن با قدم‌های بلند به اتاق سرازیر می‌شود و می‌ماند."},"ICON-1114":{"nm":"برچسب پایه‌ی شمع معطر","de":"برچسبی کوچک که روی پایه‌ی شمع چسبانده می‌شود. با دقت می‌نویسد چه رایحه‌ای می‌سوزد و اولین بار کِی روشن شده. اسم گذاشتن روی بویی که دوست داری؛ همان آراستگی است که هوای اتاق را مهربان‌تر می‌کند."},"ICON-1115":{"nm":"پایه‌ی لاستیکی قفسه‌ی تزئینی","de":"چهار پایه‌ی لاستیکی که قفسه را از لرزیدن نگه می‌دارند. از جایی نامرئی، بی‌صدا وزن را تحمل می‌کنند. کوچک و پایین‌اند و به چشم نمی‌آیند، اما آنچه در پایین‌ترین جا محکم می‌ایستد، سرانجام از همه بیشتر دوام می‌آورد."},"ICON-1116":{"nm":"آویز فلش تابلوی راهنما","de":"برای کسی که در تردید است به کدام سو برود، یک فلش آرام مسیر را نشان می‌دهد. اشاره‌ای مهربان که می‌گوید راهت را گم نکن. به لطف دلی که پیش‌تر در هر دوراهی نصب شده، امروز هم بی‌سرگردانی پیش می‌رویم."},"ICON-1117":{"nm":"بند کلید دعوت‌نامه‌ی جزیره","de":"بند کلیدی که در دست دعوت‌کننده به جزیره گذاشته می‌شود. آن را بگیری، از این پس تو هم عضوی از این خانواده‌ای. مهمان‌نوازیِ خوش‌آمدگویی به مهمانی غریبه در آغوشی گرم، محکم در وعده‌ی کوچکِ آویزان از انتهای بند نهفته است."},"ICON-1118":{"nm":"تراشه‌ی دمای صمیمیت","de":"یک تراشه به‌آرامی دمای میان دو نفر را نشان می‌دهد. هنوز آبیِ سرد و دست‌وپاچلفتی است یا بی‌آنکه بفهمی به سرخِ گرم رسیده. سرعتِ عمیق‌شدنِ محبت را سخت می‌توان سنجید، اما کف دست، آن گرما را زودتر می‌شناسد."},"ICON-1119":{"nm":"جعبه‌ی نمونه‌ی سلیقه","de":"وقتی هنوز نمی‌دانی چه چیزی را دوست داری، نمونه‌های کوچک را در یک جعبه می‌ریزند و به دستت می‌دهند. در لذتِ انتخاب‌کردن، سلیقه آرام‌آرام رشد می‌کند. کدام‌یک مالِ تو خواهد شد؛ جعبه پر از احتمال‌های هیجان‌انگیز است."},"ICON-1120":{"nm":"سنجاق رزرو مراقبت","de":"وعده‌ی مراقبت از کسی، واضح در همین یک سنجاق فرو رفته است. اسم و زمان را که بنویسی، دل راهش را گم نمی‌کند. آن همیاریِ مهربانِ نوبتی‌مراقبت‌کردن از بچه‌های یکدیگر، همین‌جا زنده و نفس‌کش است."},"ICON-1121":{"nm":"کپسول ثبت رشد","de":"همان‌طور که ردِ اندازه‌گیریِ قد روی چارچوب در، خط‌به‌خط انباشته می‌شود، این کپسول آرام تو را همان‌طور که دیروز بودی مهر و موم می‌کند. روزی دور، درش را که باز کنی خواهی فهمید قدم‌های کوچک چقدر راه پیموده‌اند."},"ICON-1122":{"nm":"نوار یادگاری اولین دیدار","de":"لرزشِ اولین بار دست‌به‌دست‌گرفتن، آرام در یک نوار گره خورده است. گره برای باز شدن آنجا نیست؛ برای این می‌ماند که گرمای آن روز همچنان روی مچ دست زنده بماند."},"ICON-1123":{"nm":"برچسب دکور اتاق من","de":"«اینجا جای من است.» لحظه‌ای که یک برچسب کوچک به گوشه‌ی میز می‌چسبد، اتاقِ غریبه بالاخره نفس می‌کشد و اتاقِ من می‌شود. یک برچسبِ اسم، اولین جایی است که دل در آن می‌نشیند."},"ICON-1124":{"nm":"کوزه‌ی تیله‌های صمیمیت","de":"تکانش بده، تلق‌تلق، صدای یک‌قدم نزدیک‌ترشدنِ دو نفر می‌غلتد. تا کوزه لبریز شود، همین‌که اسمت را صدا بزنند، خنده زودتر به استقبالت می‌آید."},"ICON-1125":{"nm":"مهر آب‌ولاک آمادگی دبیوت","de":"آخرین برگی که پاکت را می‌بندد. تا اینجا آماده‌سازی بود؛ صفحه‌ی بعد را که ورق بزنی، صحنه است. کارآموز با نوک انگشت محکم فشارش می‌دهد و نفسش را منظم می‌کند. بالاخره، آغاز می‌شود."},"ICON-1126":{"nm":"آب","de":"از همه رایج‌تر است، پس از همه گران‌بهاتر. در سالن تمرینِ خاموش‌چراغِ سپیده‌دم، یک جرعه، کسی را که فروافتاده دوباره سرپا می‌کند. مهربانی‌ای بی‌شکل که در هر ظرفی جا خوش می‌کند."},"ICON-1127":{"nm":"آب زلال","de":"شفافیتی که حتی سنگ‌ریزه‌های ته را روشن نشان می‌دهد. چشمه‌ی کوهستانی هرگز از زلالی خودش به خود نبالیده. دلی که چیزی برای پنهان‌کردن ندارد، همیشه این‌طور تا ته دیده می‌شود."},"ICON-1128":{"nm":"آب دریا","de":"لحظه‌ای که به نوک زبان می‌رسد، موج‌های دور به سمتت می‌آیند. در یک جرعه‌ی شور، افق و مرغ‌های دریایی و بندری که ترک کرده‌ای، همه در هم حل شده‌اند. دریا همیشه با طعمی شور در خاطره می‌ماند."},"ICON-1129":{"nm":"یخ","de":"روی کف دست آرام‌آرام کوچک می‌شود، به‌اندازه‌ی فشاری که می‌آوری ناپدید می‌شود. هرچند سخت به‌نظر برسد، می‌داند سرانجام به آب برمی‌گردد. یخ، رودخانه‌ای است که برای مدتی نفسش را نگه داشته."},"ICON-1130":{"nm":"گلوله‌ی برف","de":"یک گلوله‌ی فشرده، سفید در کوچه می‌چرخد و پرواز می‌کند. خنده‌ی بلند و گونه‌های سرخ‌شده از سرما. سفیدترین اسباب‌بازی‌ای که زمستان آرام در دست بچه‌ها می‌گذارد."},"ICON-1131":{"nm":"خاک","de":"بذر را در آغوش می‌گیرد، باران را می‌نوشد و رد پاهای گذرا را بی‌صدا می‌پذیرد. پوستی سیاه که همه‌چیز را در بر می‌گیرد. در اولین جایگاهِ هرچیز که می‌روید، همین یک مشت خاک هست."},"ICON-1132":{"nm":"خاک حاصلخیز","de":"انگشتانت را که فرو کنی، چربیِ سیاهی نرم دورشان می‌پیچد. رازِ سبز ماندنِ سالانه‌ی باغچه‌ی مادربزرگ، درست همین‌جا بود. خاکِ خوب‌رسیده با بوی کود، از محصولی پربار زمزمه می‌کند."},"ICON-1133":{"nm":"خاک رس","de":"لحظه‌ای که رطوبت می‌گیرد، مطیعانه هر شکلی را می‌پذیرد. گوشتی مهربان که به دنبال دستِ تو، پرنده می‌شود، کاسه می‌شود. تا چرخ می‌چرخد، یک مشت خاک بالاخره خواب می‌بیند."},"ICON-1134":{"nm":"شن","de":"دانه‌های ریزی که آرام از میان انگشتان می‌گریزند. هرچه بیشتر بگیری، سریع‌تر فرو می‌ریزند و بیشتر به زمان شبیه می‌شوند. در یک مشت ساحل، دیروزهای بی‌شماری خفته‌اند."},"ICON-1135":{"nm":"سنگریزه","de":"سنگ‌هایی که کنار جویبار گرد شده‌اند. رد دستی است که آب سال‌ها و سال‌ها نوازش کرده تا لبه‌های تیز محو شوند. هرچه بیشتر غلتیده باشد، نرم‌تر در دست جا خوش می‌کند."},"ICON-1136":{"nm":"سنگ","de":"تکه‌ای که بی‌اعتنا کنار جاده افتاده. یکی با لگد ردش می‌کند و می‌گذرد، یکی آرام برش می‌دارد و برجی می‌سازد. همان سنگ، بسته به دل آدم، هم بار می‌شود هم آرزو."},"ICON-1137":{"nm":"سنگ‌فرش پهن","de":"سنگی پهن که حیاط کاخ کهن را می‌پیماید. صدها سال کفش که رویش راه رفته‌اند، وسطش را گود کرده. هر کس که قدم به قدم رویش می‌ایستد، لایه‌ای دیگر از زمان به آن می‌افزاید."},"ICON-1138":{"nm":"سنگ آهک","de":"صدف‌هایی که روزگاری دریا بودند، لایه‌لایه سخت شدند و سنگی سفید شدند. در کوره که بگذاردش، به آهک وامی‌شود و دیوار را سپید می‌کند. آرام به‌نظر می‌رسد، اما سنگی است که یک دوران کامل را در خود دارد."},"ICON-1139":{"nm":"زغال‌سنگ","de":"جنگلی کهن که به خوابی سیاه فرورفته. سرخس‌های صدها میلیون سال پیش، عمیق زیر زمین محکم فشرده شده‌اند. آتشش بزنی، آفتابی که مدت‌ها مدفون بود دوباره شعله‌ور بیدار می‌شود."},"ICON-1140":{"nm":"زغال چوب","de":"آتش را در خود نگه می‌دارد اما دود را آرام فرو می‌بلعد. چوبی که در کوره سیاه فشرده شده، بی‌کلامی روی منقل سرخ می‌شکفد. هرچه ساکت‌تر باشد، طولانی‌تر گرم می‌ماند."},"ICON-1141":{"nm":"شاخه‌ی کوچک","de":"شاخه‌ای که برای نشکستن، بی‌صدا خم شده، راهِ نرمش را بلد است. در هر جایی که بادی سخت را تاب آورده، گرهی بسته می‌شود، و استحکام واقعی سرانجام همان ردِ خوب‌خم‌شدن است."},"ICON-1142":{"nm":"تنه‌ی درخت","de":"در حلقه‌های بریده‌اش، صد بهار و زمستان گرد هم لایه شده‌اند. سال‌هایی که یک درخت زیسته، اکنون تمام‌قد دراز کشیده و آرام منتظر نوبتش برای تبدیل‌شدن به ستون خانه‌ای است."},"ICON-1143":{"nm":"چوب برش‌خورده","de":"هر بار که رنده رد می‌شود، رگه‌ای معطر لایه‌به‌لایه آشکار می‌شود. تا چوبِ خشن نرم شود، خاک‌اره مثل برفِ زرد روی زمین انباشته می‌شود. دستِ صیقل‌دهنده، کاربردش را بیدار می‌کند."},"ICON-1144":{"nm":"تخته چوب","de":"کف را می‌پوشاند، نیمکت می‌سازد، حصار می‌کشد. وقتی تخته‌های صاف‌بریده‌شده یکی‌یکی گرد هم می‌آیند، بالاخره جایی برای زندگیِ آدمی برپا می‌شود. چیزهای معمولی روی هم می‌روند و آشیانه می‌شوند."},"ICON-1145":{"nm":"بامبو","de":"درونش خالی است اما در برابر باد راست می‌ایستد. آن عزمی که در هر بند می‌شکند و دوباره می‌روید، دانشوران کهن آرزو داشتند شبیهش شوند. اینجا چیزی هست که به‌سبب توخالی‌بودن، حتی راست‌تر ایستاده است."},"ICON-1146":{"nm":"چوب‌پنبه","de":"فشارش بده و رهایش کن، دوباره به ضخامت اصلی‌اش باد می‌کند. با نگاه به این رگه‌ی سبک اما سرسخت، می‌فهمی که نرمی هرگز به‌معنای ضعف نیست. از درپوش بطری تا تخته‌اعلانات، آرام همه‌چیز را نگه می‌دارد."},"ICON-1147":{"nm":"علف","de":"لگدمال شود هم با بارانِ بعدی دوباره سرپا می‌ایستد. سرسختیِ سبزی که بی‌هیچ نامی، دشتی را یکسره می‌پوشاند. کوچکی‌اش را دست‌کم نگیر؛ اولین خبردهنده‌ی بهار همیشه همین جایگاه پست است."},"ICON-1148":{"nm":"کاه","de":"چیزی که پس از پایان برداشت پاییزی، زرد در مزرعه باقی می‌ماند. بافته شود سقف می‌شود، پهن شود بستری گرم می‌شود. دلی که با وجود بخشیدنِ همه‌ی دانه‌ها، تا آخرین لحظه هم آدم را می‌پوشاند."},"ICON-1149":{"nm":"نی","de":"بادی که می‌گذرد خش‌خش می‌کند و کنار رودخانه یکسره آواز می‌خواند. ساقه‌ای که چون توخالی است، دورتر می‌گرید. نی ذره‌ای شرم ندارد از اینکه همان لرزیدنش، آوازِ خودش است."},"ICON-1150":{"nm":"پنبه","de":"وقتی غلاف رسیده تَرَق باز می‌شود، ابری کوچک شکوفا می‌شود. این پرزِ سبک و نرم، نخ می‌شود و لباس می‌شود و در شب سرد زمستان، آرام شانه‌های کسی را گرم می‌کند."},"ICON-1151":{"nm":"پشم گوسفند","de":"به دست که بمالی، چربی‌اش می‌چرخد و گرمایش آرام می‌ماند. پالتویی که گوسفند به تن خود می‌پیچید تا کوهستان سرد را تاب بیاورد. آن گرمای چیده‌شده، اکنون به زمستانِ آدمی منتقل می‌شود."},"ICON-1152":{"nm":"نخ","de":"هرچند نازک و به‌سختی دیده شود، همیشه همین است که دو لبه‌ی جداافتاده را دوباره به هم می‌رساند. یک رشته‌اش ضعیف است اما بافته شود، پارچه‌ای کامل می‌شود. در کارِ پیونددادن، ضخامت اهمیتی ندارد."},"ICON-1153":{"nm":"پارچه","de":"تار و پود بی‌شمار بار در هم متقاطع می‌شوند تا پهنه‌ای شکل بگیرد. نتیجه‌ی نخ‌هایی است که تنها می‌بودند از هم می‌گسستند اما محکم به هم چسبیده‌اند. اینکه هرچه بافت متراکم‌تر باشد گرم‌تر است، درباره‌ی آدم‌ها هم درست است."},"ICON-1154":{"nm":"چرم","de":"هرچه بیشتر استفاده شود، اثرِ دست بیشتر در آن می‌نشیند و کم‌کم به صاحبش شبیه می‌شود. تا سفتیِ اولیه رام شود، رنگش عمیق‌تر و بافتش نرم‌تر می‌شود. آن جلایی که زمان حک کرده، به هیچ چیز دیگری تقلیدپذیر نیست."},"ICON-1155":{"nm":"پر","de":"آنقدر سبک است که حتی روی کف دست هم وزنی احساس نمی‌شود. رشته‌ای که خاطره‌ی پرواز در آسمان را درست همان‌طور در خود نگه داشته. فراموش نکن که سبک‌ترین چیز، بالاترین جا پرواز کرده است."},"ICON-1156":{"nm":"صدف دریایی","de":"ناگهان حرف مادربزرگ به یادت می‌آید که می‌گفت به گوشت بگیرش. روی رنگین‌کمانِ درونش، دریایی که ترک کرده‌ای یکسره حک شده، طوری که حتی از صدفِ خالی هم موج‌خیزیِ روزگاری گذشته شنیده می‌شود."},"ICON-1157":{"nm":"مرجان","de":"مثل سنگ سفت شده، اما زمانی قطعاً گروهی زنده و نفس‌کش بود. در دریای آرام، صدها سال وقت می‌گذارد تا شاخه‌هایش را بگستراند. سفت‌ترین شاخه، تنها پس از طولانی‌ترین انتظار می‌روید."},"ICON-1158":{"nm":"مروارید","de":"صدف که نتوانست آزارِ یک دانه‌ی شن را تاب بیاورد، آرام آن را در نور پیچید. اگر درد را گرد کنی و در آغوش بگیری، این‌طور درخشان می‌شود؛ تسلی کوچکی که دریا هدیه می‌دهد."},"ICON-1159":{"nm":"جلبک دریایی","de":"نواری سبز که روی صخره‌های ساحلیِ جزرکرده، لغزان افتاده. در دست که بگیریش، بوی تند دریا یک‌باره می‌پیچد. بی‌ریشه، تن به جریان آب سپرده، دریا آرام باغچه‌ی خودش را می‌پرورد."},"ICON-1160":{"nm":"جلبک نوری","de":"یک برگ سیاه را کمی روی آتش بگیری، سبز می‌شود و بویی خوش پخش می‌شود. آن صبحی که دورِ برنج تازه‌پخته پیچیده می‌شد. هرچند نازک است، به‌راحتی خوشیِ یک وعده غذا را در آغوش می‌گیرد."},"ICON-1161":{"nm":"نمک","de":"من همان بلورِ سفیدی‌ام که دریا زیر آفتاب جا گذاشته. یک ذره‌ام، سوپِ بی‌مزه را عمق می‌بخشد، اما دستی که بلغزد همه‌ی طعم‌ها را می‌پوشاند. تنها نوک انگشتی که اندازه را می‌شناسد، درست می‌تواند مرا به کار گیرد."},"ICON-1162":{"nm":"تکه‌شیشه","de":"تنها در همان جایی که شکسته، بالاخره نور را می‌شکند و رنگین‌کمانی می‌شکفاند. هنری که وقتی سالم بود اصلاً نمی‌دانست دارد. حتی چیز شکسته هم سهمی از آفتاب برای بخشیدن دارد؛ تکه‌ای که کنار پنجره افتاده، آرام همین را می‌گوید."},"ICON-1163":{"nm":"شیشه","de":"شفاف‌بودن فقط به‌معنای این نیست که چیزی برای پنهان‌کردن نداری. برای اینکه نور را یکسره از خود بگذراند، شکل خودش را پاک کرده. حتی در ماندنِ نادیدنی در آن‌جا، وقتی دستی لمسش کند، آراستگیِ خنکی هست."},"ICON-1164":{"nm":"بطری شیشه‌ای","de":"باید درونش خالی باشد تا بتواند چیزی را در خود جای دهد. مربا باشد یا یک مشت گل صحرایی یا نامه‌ای تاشده، اسمش با هرچه وارد می‌شود عوض می‌شود. ظرفی که از خالی‌ماندن نمی‌ترسد، سخاوتمندترین است."},"ICON-1165":{"nm":"بطری خالی","de":"سکوتی که بعد از نوشیده‌شدن آخرین قطره می‌آید را دوست دارم. یکی مرا دور می‌اندازد، یکی می‌شویدم و روی لبه‌ی پنجره می‌گذارد تا پر از آفتاب شوم. یافتنِ کاربردی دوباره در جایی که پایان یافته، همان زندگیِ دومِ خالی‌شده‌هاست."},"ICON-1166":{"nm":"کاغذ","de":"سفید و گسترده منتظرم تا هرچه باشد را بنویسم. همیشه من هستم که طولانی‌ترین نگاه را به دلِ کسی که در نوشتنِ خط اول تردید دارد می‌اندازم. صبرِ صفحه‌ی سفید، یک وجب از جوهر هم عمیق‌تر است."},"ICON-1167":{"nm":"کاغذ کهنه","de":"زردیِ رنگ‌باخته، پیری نیست، تحمل است. در هر جای تاشده، گرمای دستی که بازش کرده و خوانده، نشسته. کاغذ کهنه، برای اینکه فراموش نشود، زمانِ سپری‌شده را با رنگ خودش می‌نویسد."},"ICON-1168":{"nm":"جوهر","de":"با یک قطره آغاز می‌شود، جمله می‌شود، و وقتی خشک شود مثل یک وعده باقی می‌ماند. اگر پخش شود، همان پخش‌شدنش رد همان روز است. چون کارم این است که چیزها را برگشت‌ناپذیر کنم، مردم یک‌بار دیگر با احتیاط مرا فرو می‌فشارند."},"ICON-1169":{"nm":"سنگ آهن","de":"سنگی‌ام که زیر زمین خوابی سرخ می‌خفت. تنها پس از یک‌بار گذر از آتش، بالاخره آهنِ درونش را می‌بخشد. سختی از ابتدا سخت نیست؛ نامی است که پس از گذر از گرما دریافت می‌شود."},"ICON-1170":{"nm":"شمش آهن","de":"کانه تنها پس از تحمل آتش، در یک قطعه سرد شد. این شکلِ سرد و سنگین، پل می‌شود و تیغه می‌شود و بیل می‌شود. چون کاربردم هنوز تعیین نشده، می‌توانم هر چیزی شوم."},"ICON-1171":{"nm":"سنگ مس","de":"با زنگاری به رنگ سیب سبز از خاک بیرون آمدم. آبم کنی، زنگ به صدا درمی‌آید، مجسمه سرپا می‌شود، سیم جریان می‌یابد. حتی در خوابِ زمین سیاه‌رنگ هم، همیشه منتظر نوبتم بودم تا به چیزی خوانده شوم."},"ICON-1172":{"nm":"شمش مس","de":"اگر مدتی طولانی کنارت بماند، جامه‌ای آبی به دست خودش برای خود می‌دوزد. برخی آن رنگ را عیب می‌خوانند، برخی مثل نقشِ سال‌ها نوازشش می‌کنند. فلزی که از رنگِ درحال‌تغییرش شرمنده نیست، از همه بیشتر دوست داشته می‌شود."},"ICON-1173":{"nm":"سنگ طلا","de":"دانه‌ای است که با غربال‌کردن پی‌درپیِ شنِ رودخانه به دست می‌آید. گران‌بها نیست چون کمیاب است، گران‌بهاست چون تغییر نمی‌کند. مردمان قدیم آن را در دست می‌گذاشتند و به‌عنوان یادگاری می‌بخشیدند تا دلی زنگ‌نزدنی را به یاد بیاورند."},"ICON-1174":{"nm":"شمش طلا","de":"بی‌آنکه کدر شود یا زنگ بزند، یک‌تکه دراز کشیده‌ام. بیشترین طمعِ آدم‌ها را شنیده‌ام، اما خودم چیزی آز نمی‌ورزم. فقط سکوتی سنگین که تنها به کارِ درخشیدن وفادار است."},"ICON-1175":{"nm":"آهن‌قراضه","de":"کاربردش تمام نشده؛ منتظر کاربرد بعدی است. میخ‌های شکسته و قوطی‌های له‌شده کنار هم جمع می‌شوند تا دوباره آتشی داغ را ملاقات کنند. برای من، کلمه‌ی «دورانداخته‌شده» یعنی «در حال استراحتِ کوتاه»."},"ICON-1176":{"nm":"پیچ","de":"به‌تنهایی هیچ کاری از دستم برنمی‌آید. تنها وقتی چرخانده و فرو رفته دو تخته را محکم به هم قفل می‌کنم، بالاخره سهم خودم را ادا می‌کنم. هنرِ تنی کوچک که چیزی بزرگ را نگه می‌دارد؛ حتی در آن نیرویِ سفت‌کردن هم دلسوزی نهفته است."},"ICON-1177":{"nm":"میخ","de":"یک‌بار که فرو روم، به‌آسانی عقب نمی‌نشینم. با هر ضربه‌ی چکش، آنچه عمیق‌تر می‌شود زخم نیست، وعده است. اگر کارْ محکم‌پیونددادنِ چیزی باشد، با کمال میل سرم را تقدیم می‌کنم."},"ICON-1178":{"nm":"چرخ‌دنده","de":"دندانه‌ی همسایه‌ام را هل می‌دهم و با هم می‌چرخیم. تلاش نمی‌کنم تنها جلو بیفتم، بلکه بلدم سرعتم را با کنارم هماهنگ کنم. مثل ساعتی که تنها وقتی دندانه‌ها درگیر می‌شوند زمان جاری می‌شود، باور دارم هماهنگی خودش حرکت است."},"ICON-1179":{"nm":"فنر","de":"هرچه بیشتر فشرده شوم، بیشتر نیروی بازگشت را در خود جمع می‌کنم. خم‌شدن تسلیم نیست؛ آماده‌شدن برای بازگشودنِ دوباره است. مارپیچی کوچک که به‌اندازه‌ی ضربه‌ای که جذب کرده پس می‌زند، جایی که انعطاف خودش استحکام است."},"ICON-1180":{"nm":"سیم برق","de":"بیرونش پوششی آرام است، درونش راهی است که بی‌وقفه جریان دارد. از جاهای نادیدنی، نور و صدا را حمل می‌کند. مثل دستی که بی‌صدا پشتِ‌صحنه را به هم پیوند می‌دهد، گذرگاهی است که چون نمایان نمی‌شود، اعتمادپذیرتر است."},"ICON-1181":{"nm":"باتری","de":"نورِ روشنِ نیم‌روز را یکی‌یکی در بدن کوچکش انبار می‌کند. وقتی تمام شد، دوباره پرش کن، می‌گوید و هرگز خالی‌بودن را پایان نمی‌داند. غروبی کوچک را در آغوش دارد که شبِ طولانیِ کسی را روشن کند."},"ICON-1182":{"nm":"لامپ","de":"یک رشته‌ی نازک، سرخ و داغ می‌شود و تاریکی را پس می‌راند. بدنِ خودش را می‌سوزاند، نه برای گرم‌کردنِ اتاق بلکه برای روشن‌کردنش. لحظه‌ای که روشن می‌شود، داغ‌ترین است، و از همین رو، خورشیدی کوچک از یک لحظه‌ی روشن‌ترین."},"ICON-1183":{"nm":"لنز","de":"نورِ پراکنده را جمع می‌کند و در یک نقطه، واضح می‌ایستاند. هم ستاره‌ی دوردست را و هم نوشته‌ی ریزِ روی کف دست را آرام فرا می‌خواند. برای کمک به دیدن، خودش را پنهان می‌کند؛ خواستگارِ گرد و شفافی است."},"ICON-1184":{"nm":"لاستیک","de":"فشارش دهی یا بکشیش، سرانجام به جای خودش برمی‌گردد. حتی آنانی که سرزنشش می‌کردند به‌خاطر نرمی، روزهای بارانی مرا برای پوشیدن انتخاب می‌کنند. کارِ نرم‌پذیرفتنِ ضربه‌ای سخت؛ در همین نرمی، سرسختی زندگی می‌کند."},"ICON-1185":{"nm":"تکه‌ی پلاستیک","de":"تکه‌ای کوچکم که از بدنه‌ی اصلی جدا شده. نزدیک بود دورانداخته شوم، اما اگر تعدادی گرد هم بیایند، دوباره چیزی نو می‌شویم. سبک نیستم چون کوچکم، بلکه چون سبکم می‌توانم دور برسم؛ بخشی از چیزی هستم."},"ICON-1186":{"nm":"طناب","de":"تنها با تابیدنِ رشته‌های بسیار، سرانجام یک بند می‌شوم. تنها به‌آسانی از هم می‌گسلم، اما بافته‌شده قایق می‌کشم و بار می‌بندم. گره‌ی کهنِ همکاری، زبر روی کف دست، که به‌اندازه‌ی درهم‌پیچیدنِ مشترک، سرسخت‌تر می‌شود."},"ICON-1187":{"nm":"پارچه‌ی بادبان","de":"باد را دشمن نمی‌دارد، بلکه با آغوش باز در سینه می‌گیرد. تنها وقتی سفت و پرباد شوم، قایق را دور می‌فرستم؛ حتی بادِ مخالف هم برایم نیرو می‌شود. راهِ پیش‌رفتن با درآغوش‌گرفتنِ چیز خشن به‌جای مقاومت در برابرش را، از دریا آموختم."},"ICON-1188":{"nm":"تکه‌ی لنگر","de":"تنها گوشه‌ای از یک لنگرم، اما وزنش را کامل به یاد دارم. روزگاری که کف عمیق را می‌گرفت و کشتی را به توقف وامی‌داشت. حتی حالا که جدا افتاده‌ام، تکه‌ای سنگینم که وزنِ ماندن را می‌شناسد."},"ICON-1189":{"nm":"میخ کشتی","de":"میخی که عرشه‌ی موج‌خورده را نقطه‌به‌نقطه محکم نگه می‌داشت. حتی وقتی از نمک سرخ و زنگ‌زده شد، تا آخر جایش را رها نکرد. حتی محکم‌نگه‌داشتنِ چیزی شناور هم پایداری می‌خواهد."},"ICON-1190":{"nm":"پارچه‌ی ضدآب","de":"درباره‌ی کارِ جلوگیری از باران، حرفی نمی‌زند. آنچه از بالا می‌ریزد را بی‌صدا می‌گیرد و آنچه زیرش هست را خشک نگه می‌دارد. زرق‌وبرقی ندارد اما لایه‌ای مطمئن است که بارِ کسی را از خیس‌شدن نگه می‌دارد."},"ICON-1191":{"nm":"رنگ‌مایه","de":"آرام که در پارچه‌ی ساده نفوذ کند، بالاخره رنگ می‌شود. نیلی باشد یا رنگِ روناس، مادرانِ قدیم با رنگین‌کردنِ نوک انگشتانشان، رنگ را بر پارچه می‌پوشاندند. حتی در فرونشستن و نفوذکردن هم، عمقی هست که به‌سختی محو می‌شود."},"ICON-1192":{"nm":"روغن معطر","de":"تنها یک قطره، و دشتی پهناور یک‌باره در اتاق می‌گسترد. مهمانی که با اینکه دیده نمی‌شود، اول از همه می‌رسد. منظره‌ای که اول به نوک بینی می‌رسد و آرام دامنِ خاطره‌های خفته را می‌کشد."},"ICON-1193":{"nm":"موم","de":"با گرما جاری می‌شود و با سرما سفت شکل خود را نگه می‌دارد. میان نرمی و سختی رفت‌وآمد می‌کند و آرام از هر چیز قالب می‌گیرد. ماده‌ای مهربان که می‌بندد، مهر می‌کند و جلا می‌دهد و با دما چهره عوض می‌کند."},"ICON-1194":{"nm":"شمع","de":"بدن خودش را آرام آب می‌کند تا یک خانه از تاریکی را روشن کند. وقتی تمام سوخت، فقط قدِ کوتاه‌شده‌اش می‌ماند، اما زمانی که شبِ کسی را گرم کرده هرگز محو نمی‌شود. فتیله‌ای راست‌قامت که راهِ درخشیدنِ در حالِ کوچک‌شدن را بلد است."},"ICON-1195":{"nm":"کمپوست","de":"چیزهایی که در حال پوسیدن‌اند، گرد هم می‌آیند و حاصلخیزترین خاک می‌شوند. پوست‌های دورریخته و برگ‌های خشکِ افتاده، غذای جوانه‌های تازه‌ی بهاری می‌شوند. در همان جایی که فکر می‌کردی تمام شده، حیاتِ بعدی آرام اولین نفسش را می‌کشد."},"ICON-1196":{"nm":"برنج","de":"تا یک دانه به دست بیفتد، هشتادوهشت‌بار دست به کارش می‌رود. از نشاکاری تا خرمن‌کوبی، سال کامل کشاورز، درست در همین دانه‌ی کوچک نهفته است. یک کاسه برنجِ بخارگرفته، خودش چهار فصلِ زندگی کسی است."},"ICON-1197":{"nm":"برنج قهوه‌ای","de":"تنها پوستِ بیرونی‌اش کمی گرفته شده و رنگ اصلی‌اش را همان‌طور حفظ کرده. اینکه هرچه بیشتر بجوی خوش‌طعم‌تر می‌شود، طعمِ صداقتی است که عجله نکرده. سرسختیِ محکمِ دانه‌ای که از صیقل‌خوردنِ ظریف سر باز زده و بافتِ خشنش را نگه داشته."},"ICON-1198":{"nm":"گندم","de":"مزرعه‌ی طلایی‌ای را به یاد دارد که در باد یکصدا سر خم می‌کرد. نان می‌شود و رشته می‌شود و خمیرِ سوپ می‌شود و سفره‌های سراسر دنیا را گرم می‌کند. غله‌ای که چون رایج است، عمیق‌تر در زندگی آدم‌ها ریشه دوانده."},"ICON-1199":{"nm":"آرد","de":"تنها پس از تبدیل‌شدن به پودری سفید و ظریف، بالاخره آماده می‌شود تا هرچیزی شود. آب که ببیند باد می‌کند، آتش که ببیند می‌پزد. چون شکلِ ثابتی ندارد، زمینه‌ای رام است که هرشکلی که دست بورزد را می‌گیرد."},"ICON-1200":{"nm":"خمیر","de":"پودر و آب زیر کف دست در یک تکه در هم می‌آمیزند. هرچه بیشتر ورز بدهی، کِشدارتر می‌شود، هرچه بیشتر صبر کنی، برآمده‌تر باد می‌کند. عجله کنی سفت می‌شود، پس زمانِ خمیرمایه را نمی‌توان شتاباند، این را نانوایی کهنه می‌گوید."},"ICON-1201":{"nm":"خرده نان","de":"انگشتانت را که از آن گرد سفید پاک می‌کنی، ناگهان می‌بینی آستینت هم سفید شده. وقتی پوشش سرخ‌کردنی می‌شود ترد است، وقتی روی هم می‌نشیند مثل اولین برف. سبک‌ترین ردی‌ست که یک قرص نان از پخته‌شدنش به جا می‌گذارد، اما فایده حتی در چیزهای کوچک هم رشد می‌کند."},"ICON-1202":{"nm":"پاستا","de":"همان لحظه که یک مشت را مثل بادبزن در آب جوش باز می‌کنی، نور خورشیدی دوردست به آشپزخانه می‌رسد. رشته‌های بلند کار مچ دست است، و «آل دنته» یعنی صبری که می‌داند کمی نیم‌پز صبر کند. آن برق و درخشش را ببین که دور چنگال می‌پیچد."},"ICON-1203":{"nm":"رامیون فوری","de":"سپیده‌دم، وقتی تمام آرایش صحنه پاک شده، پاکتی که مخفیانه روی اجاق می‌گذاری. سه دقیقه‌ای که رشته‌ها نرم می‌شوند خصوصی‌ترین لحظه‌ی روز است. با هر فوت‌کردن، تنش هم با نفس سرد می‌شود و پشت عینک بخارگرفته، امروز آرام به پایان می‌رسد."},"ICON-1204":{"nm":"تُک (کیک برنجی)","de":"برنج فقط پس از تحمل ضربه‌های هاون است که سرانجام تُک می‌شود. ساده، یا به شکل اینجولمی، یا سونگ‌پیون—یک دانه‌ی واحد از دستانی که آن را می‌سازند صد نام می‌گیرد. وقتی روی سفره‌ی جشن می‌نشیند، پیش از دهان، محبت را صدا می‌زند؛ غذایی که طعمش را باید در جمع چشید."},"ICON-1205":{"nm":"تُک سوپ سال نو","de":"استوانه‌ی تُک را اریب که برش بزنی، حلقه‌هایش مثل سکه‌های کوچک گرد بیرون می‌آیند. آیا این تُکی‌ست که در آب سفید شناور است، یا آرزویی گرد و کوچک؟ خوردن یک کاسه در صبح سال نو یک سال به سن آدم اضافه می‌کند—شیوه‌ی مهربانانه‌ی این سرزمین برای شمردن سال‌ها."},"ICON-1206":{"nm":"سیب‌زمینی","de":"خاک را که بتکانی، چهره‌ای گرد نمایان می‌شود. غده‌ای که در سکوت، در برابر بادهای دامنه‌های گانگ‌وون فربه شده—بخارپز که می‌شود پوک و لطیف است، سرخ که می‌شود خوش‌عطر. حتی در روزهایی که جیب سبک بود، صادقانه شکم خانواده را پر می‌کرد."},"ICON-1207":{"nm":"سیب‌زمینی شیرین","de":"وقتی دیگ سیب‌زمینی‌شیرینِ کبابی سر کوچه بر پا می‌شد، یعنی زمستان آغاز شده. فویل را که باز می‌کنی، بخار زرد اول انگشتانت را گرم می‌کند؛ آن شیرینی پاداشِ ریشه‌ای‌ست که سرما را تاب آورده. گرمایی که برای فوت‌کردن و نصف‌کردن و باهم‌خوردن ساخته شده."},"ICON-1208":{"nm":"هویج","de":"نیزه‌ای نارنجی که راست در دل خاک فرو رفته. فکر می‌کردی فقط خرگوش‌ها دوستش دارند، اما تفت که بدهی شیرینی پنهانش بیدار می‌شود، در سوپ هم رنگ می‌بخشد. حرف بزرگ‌ترها که می‌گفتند برای چشم خوب است، عموماً درست از آب درآمد."},"ICON-1209":{"nm":"ترب","de":"با همین یک ریشه‌ی سفید و سنگین، سفره‌ی زمستان استوار می‌شود. به شکل دونگ‌چیمی سردکننده، به شکل سوپ ترب تازه‌کننده، به شکل کاک‌دوگی ترد. چیزی از آن دور ریخته نمی‌شود—حتی برگ‌های سبزش هم زیر ایوان خشک و به سیرَگی تبدیل می‌شوند، سبزی‌ای صرفه‌جو."},"ICON-1210":{"nm":"پیاز","de":"پوستش را که می‌کنی، قطره‌ای اشک می‌غلتد. گوشت تند و گزنده‌اش وقتی به روغن داغ می‌رسد، مثل دروغی، شیرین می‌شود. نامش در سطر اول تقریباً هر غذای کره‌ای نوشته شده—قهرمانِ آرامی که خاموش زیربنای طعم را می‌چیند."},"ICON-1211":{"nm":"پیازچه","de":"ته‌ی سفید ریزخردشده و برگ‌های سبز را روی سوپ که بپاشی، انگار تازه یک کاسه کامل می‌شود. ته‌مانده را در لیوان آب فرو کنی، دوباره سبز می‌شود و بالا می‌آید—باغچه‌ای کوچک روی طاقچه برای اهل خانه‌داری."},"ICON-1212":{"nm":"سیر","de":"شش حبه دور هم جمع شده‌اند تا یک سر سیر بسازند. ریشه‌ی تندی که، می‌گویند، خرسی را به انسان تبدیل کرد. با پشت چاقو که کوبیده شود، عطرش یک‌باره شعله می‌کشد؛ بی‌یک‌مشت از آن نه کیمچی معنایی دارد و نه خورشت."},"ICON-1213":{"nm":"زنجبیل","de":"ریشه‌ای کوچک و ناهموار مثل گره‌ای در هم پیچیده. یک تکه‌اش کافی‌ست تا بوی ماهی را بخواباند و بدن سرد را از درون گرم کند. شب‌هایی که از سرماخوردگی می‌نالیدی، آن فنجان گرمی که با عسل دم می‌کردی، از همین تندی تیز آغاز می‌شد."},"ICON-1214":{"nm":"کلم ناپا","de":"برگ‌های پرِ آن را که در نمک بخوابانی، آنگاه اولین فصلِ کیمچی گشوده می‌شود. در پاییز دیرهنگام، در هر حیاطی مثل کوه انباشته می‌شد. تمام خانواده که دور هم می‌نشستند تا یک خمره درست کنند، پیمانی بود برای گذراندنِ زمستانِ طولانی، با هم."},"ICON-1215":{"nm":"کلم","de":"برگ‌های گرد و لایه‌لایه‌اش را یکی‌یکی که باز کنی، انگار پایانی ندارد، و پیش از آنکه بفهمی دلت آرام می‌گیرد. آب‌پز که شود نرم است، تفت که بخورد شیرین. زیر ظاهری ساده، این سبزی مهربانی‌ای غافلگیرکننده پنهان کرده."},"ICON-1216":{"nm":"کاهو فرنگی","de":"تکه‌ای گوشت را در برگِ گودش می‌گذاری، کمی سسّامجانگ رویش، و یک لقمه‌ی پر در دهان می‌چپانی. دور یک حلقه که بنشینی و بپیچی و بخوری، هرکسی آرام‌آرام تشریفات را کنار می‌گذارد—این چیزی نیست جز مهمان‌نوازیِ سبز."},"ICON-1217":{"nm":"کاهو برگی","de":"اولین برگی که در گوشه‌ی باغچه سر می‌کشد. بچینی، دوباره می‌روید و تمام تابستان سفره را پر می‌کند. آن بوی سبز و تازه—که در آب سرد شسته و با دست پیچیده و خورده می‌شد—برای بعضی‌ها، تمام طعمِ خانه است."},"ICON-1218":{"nm":"اسفناج","de":"همان سبزِ کارتونی که وقتی قوطی‌اش خالی می‌شد، نیرو می‌بخشید. آب‌پز که شود به یک مشت جمع می‌شود، اما عطر و توانش دست‌نخورده می‌ماند. چه با دست له‌شده چه در سوپ سویا حل‌شده، خوب است—سبزی‌ای که نباید فقط به‌خاطر معمولی بودنش، دست‌کم گرفته شود."},"ICON-1219":{"nm":"سرخس خوراکی","de":"جوانه‌های لطیفی را که کوه بهاری هدیه داده می‌چینند، می‌جوشانند و باز خشک می‌کنند. تنها پس از این زحمتِ طولانی‌ست که سرانجام به سفره‌ی یادبود یا کاسه‌ی بی‌بیم‌باب راه می‌یابد. به همان اندازه که دست‌گیر است، عنایت لایه‌لایه در آن نشسته—سبزیِ گران‌بهایی که کوه در یک فصل پرورانده."},"ICON-1220":{"nm":"سبزی‌های کوهی","de":"انگار بی‌نام‌اند، اما هرکدام عطر خودشان را دارند—هدیه‌ی بهار. دست‌های مادربزرگ در یک نگاه می‌داند کدام برگ در مسیر کوه خوردنی‌ست. در یک سبد سبزی، یک فصل کامل، با تمام عطرش، همراه می‌آید."},"ICON-1221":{"nm":"بومادران کوهی (سوک)","de":"علفی تلخ اما خوشبو که اول از همه زمین یخ‌زده را می‌شکافد. وقتی به تُک تبدیل شود، نور بهار مستقیم به دهان می‌رود. در ماه اول سال باور داشتند جوشاندنِ آن در سوپ بدشانسی سال را دور می‌کند، پس بهار همیشه از همین عطر آغاز می‌شد."},"ICON-1222":{"nm":"برگ پریلا","de":"یک برگ تنها کافی‌ست تا تمام دهان را با عطرش رنگ کند. کنار گوشتِ خوک برشته‌شده بگذاری یا لایه‌لایه در سس سویا بخوابانی، یک کاسه برنج در یک چشم‌به‌هم‌زدن ناپدید می‌شود. این عطر یکتا فقط روی سفره‌ی این سرزمین معنا دارد."},"ICON-1223":{"nm":"فلفل دلمه‌ای سبز","de":"میوه‌ای سبز و توخالی که با صدای تردی می‌شکند. تلخیِ خفیفش ذائقه‌ی خسته را بیدار می‌کند و در روغن که تفت بخورد، رنگش روشن‌تر می‌شود. فقط با ریز خرد شدن و پاشیده شدن، هر غذایی را در یک لحظه تازه می‌کند."},"ICON-1224":{"nm":"فلفل دلمه‌ای","de":"قرمز، زرد، نارنجی—رنگ‌هایی مثل چراغ راهنما که سبدی را پر کرده‌اند. یک گاز خام و آب شیرینش می‌چکد؛ فقط رنگش سفره را روشن می‌کند. این ضرب‌المثل که سبزیِ خوش‌قیافه اشتها را هم باز می‌کند، دقیقاً درباره‌ی همین است."},"ICON-1225":{"nm":"گوجه‌فرنگی","de":"گردِ سرخی که همیشه سر اینکه میوه است یا سبزی بحث بوده. که خوب بپزد طعمش عمیق می‌شود، خام که بخوری بی‌نهایت تازه است. میوه‌ای‌ست که صادقانه‌ترین نور آفتاب میان‌تابستان را در خود جمع کرده، پس یک گاز، تمام یک روز روشن را می‌ترکاند."},"ICON-1226":{"nm":"خیار","de":"سبزی که گرمای تابستان را خنک‌ترین‌جور فرو می‌نشاند. در سوپ سرد شناور کنی دهان یخ می‌زند و تر و تازه می‌شود، و به شکل سوباگی که ترشی بگذاری، ترد بودنش زنده می‌شود. روزهای طاقت‌فرسا حتی می‌شود نازک برشش زد و روی چشم گذاشت—سبزی‌ای که هم درون هم بیرون خنک است."},"ICON-1227":{"nm":"کدو حلوایی","de":"نوک بوته‌اش گرد آویزان می‌شود و تا اواخر پاییز آرام‌آرام از شیرینی پر می‌شود. که خوب بپزد آش زردی می‌شود که معده را آرام می‌کند، سرخ که شود پنکیک طلایی می‌شود. زیر ایوان که آویزانش کنی، تمام زمستان مثل انباری استوار خدمت می‌کند."},"ICON-1228":{"nm":"کدو سبز جوان","de":"سبزِ روشنی که در باغچه‌ی تابستانی هر روز کمی فربه‌تر می‌شود. در خورشت سویا تکه‌تکه، سرخ‌شده طلایی—آنقدر نرم که حتی برای دهان بچه‌ی کوچک هم ملایم است. معمولی‌ست، و به همین دلیل بیشتر شکرگزارش هستیم: مهمان همیشگیِ سفره‌ی میان‌تابستان."},"ICON-1229":{"nm":"بادمجان","de":"میوه‌ای دراز که برق ارغوانی روی تنش می‌درخشد. روغن که به خودش بگیرد بی‌نهایت نرم می‌شود، و بخارپز که شود بافتش مثل ابریشم لطیف است. ساده به‌نظر می‌رسد اما با هرچیزی خوب جفت می‌شود—بازیگر نقش مکمل و مهربانِ سفره."},"ICON-1230":{"nm":"ذرت","de":"دانه‌های زردی که یکی‌یکی مرتب در ردیف ایستاده‌اند. تنقلات تابستانی‌ست که در دیگ بخارپز می‌شود و با فوت کردن گاز می‌زدی، و هم نشانه‌ی خوشایندی که مزارع رسیده‌اند. در آن دسته‌ی کرکیِ ابریشمی، شیرینی تا لبریز جا خوش کرده."},"ICON-1231":{"nm":"لوبیای سویا","de":"دانه‌های کوچک و سفت که یک شب آب می‌خورند و فربه می‌شوند. نرم که آسیاب شود شیر سویا، خوب که بگذارد بماند جانگ می‌شود—بیشتر پروتئینِ سفره‌ی این سرزمین از همین‌جا آغاز شده. یک دانه در خاک بکاری، دوباره به‌شکل یک بوته کامل بازمی‌گردد."},"ICON-1232":{"nm":"توفو","de":"وقتی سویا آب می‌خورد و آسیاب و منجمد می‌شود، به قالبی سفید با گوشه‌های صاف تبدیل می‌شود. نرم و بی‌ادعا، در هیچ سوپی روی رنگ خودش پافشاری نمی‌کند. حتی با لمس یک قاشق آرام فرومی‌ریزد—غذایی که فضیلتش همان سادگی‌ست."},"ICON-1233":{"nm":"لوبیا قرمز","de":"دانه‌های ریز و سرخ را که خوب بجوشانی، شیرینیِ قرمزِ تیره‌ای غلیظ دم می‌کشد. در بلندترین شب سال، یک کاسه آش گرمِ لوبیا قرمز روزگاری هم سرما و هم ارواح شرور را با هم می‌راند—آن نیت هنوز در آن زنده است. در لایه‌های کیک بخارپز، آن سرخی چیزی نبود جز فداکاری."},"ICON-1234":{"nm":"خمیر لوبیا قرمز","de":"لوبیای قرمزِ پخته که ریز کوبیده و بارها و بارها تغلیظ شده تا این پُرِ نرم را بسازد. یک قاشق میان نان، درون تُک، روی یخ‌تراش—یک رشته شیرینی حتی خاطرات کهنه را هم گرم می‌کند. آن ساعت‌های طولانیِ صاف‌کردن و تغلیظ‌کردن، خودشان به شیرینی بدل می‌شوند."},"ICON-1235":{"nm":"قارچ","de":"پس از باران که آرام می‌شود، بی‌صدا سر از سایه‌ی تاریک جنگل بیرون می‌آورد. هنر خاک است که بدون یک مشت آفتاب، عطر خودش را می‌پرورد. فقط با یک مشت در سوپ، بی‌گوشت، طعم عمیقی دم می‌کشد—رازی که جنگل پنهان کرده."},"ICON-1236":{"nm":"قارچ شیتاکه","de":"چتری قهوه‌ای که کلاهش کاملاً باز شده. زیر آفتاب که کاملاً خشک شود، عطرش چند برابر عمیق‌تر می‌شود، تا جایی که یک تکه‌ی خشک به‌تنهایی یک دیگ کامل آبگوشت را مسئول می‌شود. ستونی استوار از سفره‌ی گیاهی، و همیشه مشتریِ ثابتِ کسانی که طعم عمیق را می‌شناسند."},"ICON-1237":{"nm":"قارچ کاج","de":"در عمق جنگل کاجِ پاییزی، فقط کنار درختان کاج، آرام سر بلند می‌کند. نمی‌شود کاشتش، فقط باید با پاپیمایی پیدایش کرد، و همین عطرش را گرانبهاتر می‌کند. کمی کباب و کمی نمک کافی‌ست تا تکه‌ای از جنگل در دهان بنشیند."},"ICON-1238":{"nm":"قارچ دکمه‌ای پادشاهی","de":"ساقه‌ی ضخیمش را که در امتداد رگه‌ها بکشی و پاره کنی، جویدنی بودنش زیر دست حس می‌شود. در هر فصل استوار می‌روید، پس هرگز از سفره دور نمی‌شود. کبابی یا تفت‌داده—در گوشتِ فراوانش، استواریِ بی‌دردسر لبریز است."},"ICON-1239":{"nm":"توت‌فرنگی","de":"در انتهای گلخانه‌ای که زمستان را تاب آورده، اول از همه سرخ می‌رسد. یک گاز، ترش و شیرین است، درست مثل اولین سلام اوایل بهار. یک دانه‌ی گرد روی کیک بگذاری، حتی یک امروزِ معمولی هم به سالگردی بدل می‌شود."},"ICON-1240":{"nm":"بلوبری","de":"یک تلق که بترکد، ترشیِ روشنی تمام دهان را روشن می‌کند. مرواریدهای ارغوانی کوچک را که یکی‌یکی برداری، پیش از آنکه بفهمی ظرف خالی شده؛ روی شیر سفید که بپاشی، آسمانِ کوچک شبانه‌ای همان‌جا باز می‌شود."},"ICON-1241":{"nm":"سیب","de":"یک گاز که بزنی، صدای ترد و پاییز با هم می‌شکنند. آن سرخی که مادربزرگِ باغ با پیش‌بندش پاک می‌کرد و دستت می‌داد، رنگی‌ست که فقط از نگه‌داشتنِ طولانیِ نور خورشید می‌آید. هرچه سفت‌تر باشد، بهتر می‌داند تا آخر شیرین بماند."},"ICON-1242":{"nm":"گلابی","de":"پوستش را که بکَنی، نوک انگشتانت اول سرد می‌شود. جلوترین ردیف سفره‌ی چوسوک—همان لحظه که آب شیرین و یخ‌زده‌اش دهان را پر می‌کند، اندکی از نسیم شبانه‌ی پاییز آرام می‌آید و کنارت می‌نشیند."},"ICON-1243":{"nm":"هلو","de":"هرجا شکوفه‌ی هلو ریخته، تابستانی کرکی شکل می‌گیرد. کمی که فشارش بدهی، عطرش اول پخش می‌شود؛ همان لحظه‌ی گازگرفتن، تمام فصل به‌دنبالش وارد دهان می‌شود."},"ICON-1244":{"nm":"انگور","de":"دانه‌های ارغوانی روی یک خوشه آویزان‌اند و شانه‌به‌شانه به هم تکیه داده‌اند. یکی که بترکد، ترشی اول می‌آید، شیرینی نیم‌ضرب دیرتر—مثل گروه‌سرایی منظم که در واپسین روزهای تابستان صدا می‌زند."},"ICON-1245":{"nm":"انگور سبز","de":"سبزِ روشنش نور خورشید را مستقیم از خود عبور می‌دهد و در هر دانه چراغی روشن می‌کند. بی‌هسته و پاک، خنکای شفافی دارد، شیرینیِ بی‌هیچ زیاده‌ای، مثل اولین مصرعی که تازه بیرون کشیده شده."},"ICON-1246":{"nm":"لیمو ترش","de":"پوست زردش را با ناخن که بخراشی، عطرش یک‌باره نوکِ بینی را بیدار می‌کند. یک قطره که بریزی، گوشه‌های لب خودبه‌خود جمع می‌شود، اما ته آن ترشی، عجیب گوشه‌ای دارد که تمام روز را روشن می‌کند."},"ICON-1247":{"nm":"لیمو ترش سبز (لایم)","de":"کوچک‌تر و سبزتر از لیموترش، این میوه‌ی کوچک اول با عطر تند و تیزش سلام می‌دهد. یک برش کافی‌ست تا آب ولرم هم یک‌باره بیدار شود—مشتی خنکای کوچک، ریز اما سرسخت."},"ICON-1248":{"nm":"پرتقال","de":"همان لحظه که پوستش را می‌کنی، بوی نور خورشید به انگشتانت می‌چسبد. هر پَر را در دهان بگذاری، بادکنک‌های کوچک آب شیرین یکی‌یکی می‌ترکند—و آن گردی، حتی خلق‌وخو را هم گرد می‌غلتاند."},"ICON-1249":{"nm":"نارنگی","de":"آن طعم را یادت هست؟ زیر لحاف گرمِ زمستانی، پاها را قایم کرده و پوستش می‌کندی؟ عطری که از لای ناخن‌ها پخش می‌شد، تمام اتاق را زرد می‌کرد. یک کیسه از آن بهانه‌ای می‌شود تا خانواده دور هم بنشیند."},"ICON-1250":{"nm":"موز","de":"در سپیده‌دم‌های گرسنه‌ی گوشه‌ی اتاق تمرین، روزهایی بود که با یک زرد که از کیف بیرون می‌غلتید، وعده‌ای می‌ساختی. نرم، شیرین و سیرکننده—مهربان‌ترین چاره‌ی موقت."},"ICON-1251":{"nm":"آناناس","de":"باید از یک لایه پوستِ خاردار عبور کنی تا گوشتِ زردش نمایان شود. یک تکه در دهان بگذاری، ترش‌وشیرین زبان را نیش می‌زند، و بوی دریای جنوب دور و بر لب‌ها می‌پیچد."},"ICON-1252":{"nm":"انبه","de":"گوشتِ رسیده را با دست باز کنی، بوی چسبناک و شیرینش انگشتانت را تر می‌کند. وقتی زردِ عمیقش در دهان آرام آب می‌شود و ناپدید می‌شود، رؤیایی شیرین مثل یک چرت کوتاه تابستانی از کنارت می‌گذرد."},"ICON-1253":{"nm":"نارگیل","de":"پوسته‌ی سفتش را که تکان بدهی، صدای شلپ‌شلپِ آب از درون می‌آید. که بشکنی—گوشت سفید و آب خنک—کوزه‌ی کوچکی‌ست که دریایی دوردست را کامل درون خود نگه داشته و تکان می‌دهد."},"ICON-1254":{"nm":"میوه اژدها","de":"ظاهر فلس‌مانندِ صورتی‌اش اول کمی مکث می‌اندازد، اما نصفش که کنی، درون سفیدش پر از دانه‌های ریز سیاه است. طعمش ساده و لباسش پرزرق‌وبرق—حقه‌بازی که درون و بیرونش کاملاً برعکس هم است."},"ICON-1255":{"nm":"کیوی","de":"پوست کرکیِ قهوه‌ای‌اش را نصف کنی، جواهری سبز نمایان می‌شود. برشی که دانه‌های سیاهش مثل ستاره نشسته، یک قاشق برداری، یک گازِ ترش خواب را از تنت می‌پراند."},"ICON-1256":{"nm":"مرغ","de":"روی تابه‌ی روغن‌خورده که بگذاری، اول صدای جلزوولزِ طلایی می‌پزد. ملایم و نرم، بی‌دردسر روی سفره‌ی هر کسی می‌نشیند—مشتری همیشگیِ یک وعده‌ی ساده."},"ICON-1257":{"nm":"گوشت خوک","de":"روی گریل جلز و ولز می‌کند، چربی جرقه می‌زند و طلایی می‌شود. شب‌های مهمانیِ شرکت که یک برگ کاهو با کمی سسّامجانگ پر دهان می‌چپاندی، خوش‌طعمی‌اش تمام میز را گرم می‌کند."},"ICON-1258":{"nm":"گوشت گاو","de":"در هر رگه‌ی سرخش، چربی ظریف مثل مروارید نشسته و می‌درخشد. روی سنگ داغ که بگذاری، اول عطرش فضا را پر می‌کند؛ همان لحظه که یک تکه در دهان می‌رود، خستگیِ روز آرام‌آرام باز می‌شود."},"ICON-1259":{"nm":"بیکن","de":"روی تابه‌ی صبحگاهی ترد می‌شود و چربی می‌رقصد. همان بوی شور کافی‌ست تا حتی خانواده‌ای که دیر خوابیده، چشمان‌مالان، به آشپزخانه بیایند—وعده‌ای که اول با بویش صدا می‌زند."},"ICON-1260":{"nm":"سوسیس","de":"برش‌های داده‌شده کاملاً باز می‌شوند و آبِ گوشتش می‌ترکد. شکل هشت‌پای سرخی که گوشه‌ای از جعبه‌ی ناهار را نگه می‌داشت، تجملی کوچک بود که وقت ناهارهای کودکی از آن لذت می‌برد."},"ICON-1261":{"nm":"پپرونی","de":"یک تکه گرد و تند از لبه‌هایش روی پنیر داغ جمع می‌شود. کمی که روغن جمع شود، آنجاست اوج تمام پیتزا—کوچک، اما با حضوری گرد و غلیظ."},"ICON-1262":{"nm":"پتی (کتلت)","de":"ضخیم که شکل بدهی و روی گریل بگذاری، از لبه‌ها به قهوه‌ای می‌پزد. سبزی را که میان دو تکه‌ی فشرده و کبابی بگذاری، استواری‌ای که در یک دست جا می‌گیرد کامل می‌شود."},"ICON-1263":{"nm":"تخم‌مرغ","de":"تلق که بشکند، زرده مثل خورشیدی گرد سر می‌خورد. با برنج تازه که مخلوط شود هم خوب، به شکل خط زرد درون گیم‌باپ هم خوب—معمولی‌ترین پروتئین، پس مهربان‌ترین."},"ICON-1264":{"nm":"شیر","de":"بطری سردی که سپیده‌دم جلوی در می‌گذاشتند؛ اغلب روز با همان خنکایی که کف دست حس می‌کرد شروع می‌شد. که گرم شود بخار برمی‌خیزد، سرد که شود خوش‌طعم است—سپیدی که همیشه کنارت می‌ماند."},"ICON-1265":{"nm":"پنیر","de":"برش زردی آرام روی نان گرم فرومی‌ریزد. دلی که در انتظار همان لحظه‌ی کِش آمدنش می‌ماند—هرچه بیشتر آب شود، خوش‌طعمی‌اش عمیق‌تر و غلیظ‌تر می‌شود."},"ICON-1266":{"nm":"پنیر چدار","de":"نارنجیِ عمیقش از همان نگاهِ اول طعمِ شور را نوید می‌دهد. نازک که برش بزنی و میان تُست بگذاری، خوش‌طعمی تمام دهان را پر می‌کند—به همان اندازه که رنگش روشن است، طعمش هم روشن است."},"ICON-1267":{"nm":"کره","de":"تکه‌ای که در تابه‌ی داغ رها کنی، آرام آب می‌شود و بخار خوش‌عطری بلند می‌شود. روی نان که بمالی، در برنج که مخلوط کنی، جادوی زردی‌ست که هرچه لمس کند را کمی نرم‌تر می‌کند."},"ICON-1268":{"nm":"خامه فرم گرفته","de":"هرچه بیشتر با همزن بزنی، سپیدیِ رقیق بیشتر به ابرهای سفت تبدیل می‌شود. یک قاشق که روی کیک بگذاری، همان لحظه یک بعدازظهرِ معمولی مثل جشن تولدی کوچک روشن می‌شود."},"ICON-1269":{"nm":"ماست","de":"قاشق که فرو کنی، سپیدیِ ترش نرم بالا می‌آید. یک تکه میوه که مخلوط شود، صبح سبک‌تر می‌شود؛ یک لیوان که بخوری، درون آرام مرتب می‌شود—طعمِ شروعی ملایم."},"ICON-1270":{"nm":"ماهی خال‌مخالی","de":"روی توری که بگذاری، روغن جرقه می‌زند و دودی هم ماهی‌مانند هم خوش‌عطر آشپزخانه را پر می‌کند. آن دستانی که استخوان‌ها را جدا می‌کردند و روی برنج می‌گذاشتند—عمیق‌ترین فداکاری در دل سفره‌ای معمولی."},"ICON-1271":{"nm":"ماهی سالمون","de":"رگه‌های صورتی لایه‌لایه روی هم خوابیده‌اند. سرد که بخوری در دهان نرم باز می‌شود، کبابی که شود روغنش نفوذ می‌کند و خوش‌طعم می‌شود—طعمی استوار که برخلاف جریان دریایی دور شنا کرده و برگشته."},"ICON-1272":{"nm":"تن ماهی","de":"در قوطی را که باز کنی، عطر شوری یک‌باره بالا می‌زند. شب‌های اتاق کوچکِ اجاره‌ای، وقتی با برنج مخلوط یا در جلبک پیچیده می‌خوردی، روزگاری بود که یک قوطی یک وعده‌ی استوار می‌شد."},"ICON-1273":{"nm":"ماهی روغن‌کاد","de":"گوشت روشنش آنقدر ملایم است که جوشاندنش از همان اول آبگوشتی تازه‌کننده می‌دهد. ماهی سفیدی که باد تیغ‌مانندِ بندر زمستانی را تاب آورده—یک کاسه خورشتِ داغ کافی‌ست تا حتی دستان سرد هم آرام‌آرام آب شوند."},"ICON-1274":{"nm":"میگو","de":"پشتش را گرد جمع می‌کند و که بپزد، خاکستری به صورتی می‌زند. برجستگیِ تلق‌ترکنده و عطر خوش‌طعم—یکی‌یکی که پوست بگیری و بخوری، پیش از آنکه بفهمی بشقاب خالی‌ست."},"ICON-1275":{"nm":"خرچنگ","de":"بیرون‌کشیدنِ گوشت سفید از پوسته‌ی سفت، لحظه‌ای کوچک از صبر است. تکه‌ای که در انتهای این زحمت به دهان می‌رود شیرین است—دریای پاییزی کامل وارد دهان می‌شود."},"ICON-1276":{"nm":"ماهی مرکب","de":"روی گریل گرد جمع می‌شود و بوی خوش‌طعم بلند می‌کند. یک گاز جویدنی که در سس چیلی فرو رفته و به دهان رفته، دریای شوری به‌دنبالش می‌آید."},"ICON-1277":{"nm":"صدف","de":"در آبگوشت شفاف دهان باز می‌کنند و آرام عطر خودشان را می‌بخشند. با صدای جوش‌وخروشِ آرام، بوی دریا پخش می‌شود، و یک هورت کافی‌ست تا معده‌ی سرد گرم و باز شود."},"ICON-1278":{"nm":"کیک ماهی (اومک)","de":"روی سیخ در آبگوشت داغ که فرو کنی، بخار پیچ‌درپیچ بالا می‌رود. روز سرد جلوی چادر خیابانی، دستانی که در لیوان کاغذی آبگوشت می‌گرفتند و فوت می‌کردند—آرامشی کوچک که کوچه هدیه می‌دهد."},"ICON-1279":{"nm":"کیمچی","de":"درون خمره آرام می‌رسد و عطری ترش و عمیق می‌پروراند. با دست پاره کنی و روی برنج تازه بگذاری، همین کافی‌ست؛ طعمی که در هر خانه فرق می‌کند، همان تاریخِ آن خانه است."},"ICON-1280":{"nm":"ترب شور زرد","de":"یک تکه زرد که ترد و شاداب در دهان می‌شکند. رفیق ثابت کنار یک رول گیم‌باپ یا یک بشقاب فست‌فود—ترش‌وشیرینی‌اش دهان چرب را تازه می‌شوید."},"ICON-1281":{"nm":"ترشی","de":"خیارها لحظه‌ای در نمک نفس‌شان را نگه می‌دارند، سپس در سرکه چشم باز می‌کنند. تا آن لحظه‌ی بازگشتِ تردی از دست نرود، شیشه‌ی شفاف هرگز طاقچه‌ی آفتابگیر را ترک نمی‌کند. زمانی که آرام‌آرام ترشی می‌گیرد، طعم را با خود می‌آورد."},"ICON-1282":{"nm":"خمیر فلفل قرمز","de":"سرخی‌ای که درون خمره یک سال کامل را تاب آورده. پشت تندی‌اش شیرینیِ لوبیای سویا آرام پنهان شده، پس یک قاشق که باز شود، خورشت سرانجام چهره‌ی خانه‌ی ما می‌شود. عمقی که خمره‌های حیاط با نور آفتاب پرورانده."},"ICON-1283":{"nm":"خمیر لوبیای سویا","de":"قالبِ مِجو کپک را در آغوش کشید و یک زمستان را زندگی کرد. خوش‌طعمی‌اش رقصی روی طناب است، میان رسیدن و بیش از حد رسیدن—مادربزرگ آن مرز را فقط با بوییدنِ نوک انگشتش می‌شناخت. طعمی که هرچه بیشتر منتظر بمانی، عمیق‌تر می‌شود."},"ICON-1284":{"nm":"سس سویا","de":"هرچه لوبیای سویا تیره‌تر شود، درونش عمیق‌تر می‌شود. یک قطره کافی‌ست تا سبزیِ ساده جان بگیرد و خورشت برق بزند، پس تمام رنگ‌های آشپزخانه سرانجام از همین قهوه‌ای گرم آغاز می‌شوند. خوش‌طعمی‌ای فراتر از شوری."},"ICON-1285":{"nm":"خمیر لوبیای سیاه","de":"حتی همان سیاهی هم بافت متفاوتی دارد. طعمِ شیرین‌وشورِ نهاییِ چیزی که یک‌بار دیگر با کارامل تفت داده شده—در نودل که مخلوط شود، آن برق سیاهش اشتها را تکان می‌دهد و بیدار می‌کند. اولین دکمه‌ای که طعم چینیِ آتشین را آغاز می‌کند."},"ICON-1286":{"nm":"پودر کاری","de":"پودری زرد که چند ادویه در یک قاشق دوستانه با هم درمی‌آمیزند. در آب که حل شود، قل‌قل‌کنان می‌جوشد و تمام خانه را گرم می‌کند—پیش‌نمایشِ سیرکننده‌ترین کاسه در غروب بارانی."},"ICON-1287":{"nm":"فلفل سیاه","de":"کامل که آسیاب شود عطرش زنده می‌ماند، از پیش که آسیاب شود عطرش آرام فرار می‌کند. آخرین چرخش همیشه درست پیش از خاموش‌کردنِ شعله است—نقطه‌ی کوچکی که دستِ آشپز صرفه‌جویانه می‌گذارد."},"ICON-1288":{"nm":"پودر فلفل قرمز","de":"فلفل‌های آفتاب‌خشکِ زیر نور پاییزی سرانجام سرخی‌شان را کامل می‌کنند. اینکه ریز آسیاب شود یا درشت، شخصیتِ کیمچی را رقم می‌زند، پس دستِ خوش‌طعم، در نهایت، از انتخاب دانه‌بندیِ همین پودر می‌آید."},"ICON-1289":{"nm":"نمک","de":"چاشنی‌زدن یعنی قدم‌به‌قدم به سمتِ کم‌نمک‌تر رفتن. شوری‌ای که یک‌بار اضافه شد، برنمی‌گردد، پس دستِ کارکشته همیشه در آخر کمی کمتر می‌ریزد و می‌چشد. آن‌چه کنار می‌گذاری، همان فضای نفس‌کشیدنِ توست."},"ICON-1290":{"nm":"شکر","de":"تلخی را آرام می‌کند و گوشه‌های ترشی را گرد می‌کند. اما شیرینی نباید حضورش لو برود، پس هرچه چاشنی بهتر باشد، شکر آرام‌تر در پایان از چشم پنهان می‌شود. شیرینی‌ای که بلد است پنهان شود."},"ICON-1291":{"nm":"عسل","de":"شیشه‌ای که زنبورها با هزاران بار رفت‌وآمد به کشتزار گل جمع کرده‌اند. که سفت شود، در آب گرم دوباره جانش برمی‌گردد؛ در چای که حل شود، آرام گلو را در آغوش می‌گیرد. یک قاشق طلایی از یک فصل کامل که تغلیظ شده."},"ICON-1292":{"nm":"روغن آشپزی","de":"یک دور روی تابه‌ی داغ که بچرخانی، مواد فراموش می‌کنند بچسبند. زود که بریزی می‌سوزد، دیر که بریزی می‌چسبد، پس همان یک ضربان که دود تازه بلند می‌شود، قاعده‌ی سرخ‌کردن است. زمان را با صدا می‌سنجند."},"ICON-1293":{"nm":"روغن زیتون","de":"در سبزِ فشردهٔ اول، بوی علف و کمی تندیِ ملایم با هم زندگی می‌کنند. بیشتر از اینکه روی آتش برود، در آخر که ریخته شود عطرش تا انتها زنده می‌ماند، پس نپختنش صادقانه‌ترین کاربردش است."},"ICON-1294":{"nm":"روغن کنجد","de":"در آخر یک قطره که بچکد، سبزی‌های چاشنی‌زده سرانجام کامل بودنشان را اعلام می‌کنند. خوش‌طعمی‌اش خصلتی دارد که به‌راحتی روی آتش فرار می‌کند، پس همیشه نقطه‌ای‌ست که آرام، پس از تمام‌شدنِ پخت‌وپز، اضافه می‌شود."},"ICON-1295":{"nm":"دانه وانیل","de":"یک غلاف که بشکافی و دانه‌های سیاه را بیرون بکشی، دسر لباسش را با عطر عوض می‌کند. پوسته‌ی مصرف‌شده را هم دور نریختن و در شکر دفنش کردن—صرفه‌جویی کهنه‌ای‌ست که قناد به ارث برده."},"ICON-1296":{"nm":"کاکائو","de":"گوشت سفید و دانه‌های تلخ درون میوه. فقط پس از تخمیر و خشک‌شدن زیر آفتاب است که سرانجام به شیرینیِ آشنایی که می‌شناسیم ترجمه می‌شود. پیش از آنکه شکلات شود، وحشی‌ترین چهره‌ی اولیه‌اش را دارد."},"ICON-1297":{"nm":"شکلات","de":"خصلتی دمدمی‌مزاج که با همان گرمای کف دست هم آرام آب می‌شود. باید نزدیک بیست‌وهشت درجه سفت شود تا آن ترق و برقش زنده بماند، پس پشت شیرینی‌اش، غافلگیرکننده، قاعده‌ای سختگیر از دما پنهان است."},"ICON-1298":{"nm":"دانه قهوه","de":"پیش از آسیاب، یک دانه به سکوتی سفت نزدیک است. اما که با آب داغ روبه‌رو شود، باد می‌کند و عطرش را بیرون می‌ریزد—اولین علامتی که صبح را بیدار می‌کند، همیشه از همین دانه‌ی کوچک آغاز می‌شود."},"ICON-1299":{"nm":"برگ چای","de":"در آب داغ که خیلی بماند تلخ می‌شود، کوتاه که باشد بی‌مزه. آرام شمردنِ زمانی که برگ‌ها آرام باز می‌شوند—دم‌کردنِ چای یعنی سنجیدنِ انتظار با نوک انگشتان."},"ICON-1300":{"nm":"نعناع","de":"که له شود تلخی‌اش بیرون می‌زند، پس همیشه باید با ملایمت با این برگ لطیف رفتار کرد. کمی که به آرامی بزنی، عطر خفته‌اش بیدار می‌شود و روزهای گرم در لیوانی شیشه‌ای شناورش کنی، میان‌تابستان یک درجه خنک‌تر می‌نشیند."},"ICON-1301":{"nm":"گیاهان معطر","de":"اگر با ساقه به کار برود، رایحه‌اش عمیق می‌شود و اگر تنها برگ‌ها استفاده شوند، رایحه‌ای زلال به‌جا می‌ماند. خشک که شود، تندتر می‌گردد و تازه که باشد، طراوتی تازه دارد؛ به وسعت رایحه‌ای که یک دسته در خود جای داده، حال‌وهوای آشپزخانه نیز گسترده‌تر می‌شود."},"ICON-1302":{"nm":"شاه‌بلوط","de":"در دل پوستی خاردار، مغزی براق و نرم پنهان شده است. اگر رویش شکاف بزنی و بو دهی، با صدایی ترکان باز می‌شود و رایحه‌ای شیرین می‌پراکند؛ گویی گرمای کیسه‌ی شاه‌بلوط بو داده در کوچه‌ای سردباد را می‌شود در دست لمس کرد."},"ICON-1303":{"nm":"بادام‌زمینی","de":"خوش‌طعمی‌اش بر شعله‌ی برشته‌کردن کامل می‌شود. دانه‌ای کوچک که وقتی یکی‌یکی پوستش را می‌کَنی، گذر زمان از یاد می‌رود؛ اگر دورهم روی ایوان بنشینید و آن را قسمت کنید، حرف‌ها هم آرام‌آرام همراه با پوست دانه‌ها باز می‌شوند."},"ICON-1304":{"nm":"بادام","de":"اگر کمی در آب داغ بخیسانی و پوستش را بگیری، درونش سفیدتر و نرم‌تر می‌شود. اگر بکوبی و آسیاب کنی، شیرگون می‌شود و اگر کامل بو دهی، ترد؛ وسعت دگرگونی‌ای که یک دانه در خود دارد، تخیل قنادان را تا بی‌نهایت می‌گستراند."},"ICON-1305":{"nm":"کنجد","de":"اگر روی شعله‌ای ملایم آرام‌آرام تکانش دهی، لحظه‌ای فرامی‌رسد که دانه‌ها شروع به جهیدن می‌کنند. درست پیش از آنکه آن صدا فرو بنشیند، خوش‌طعم‌ترین لحظه است؛ پس برشته‌کردن کنجد در نهایت کاری است که با گوش انجام می‌شود."},"ICON-1306":{"nm":"نیشکر","de":"اگر یک بند از آن را بجوی، همراه با بویی علفی، آبی شیرین بیرون می‌تراود. ساقه‌ای که باید بارها و بارها جوشانده شود تا به شیرینی‌ای که می‌شناسیم بدل گردد؛ آغاز شکر، به‌طرزی شگفت‌انگیز، همین‌قدر سبز و بلندقامت است."},"ICON-1307":{"nm":"شکر خام","de":"شیرینی‌ای زبر که کمتر تصفیه شده و رنگ خود را دست‌نخورده نگاه داشته است. عمقی شبیه بوی خاک به‌آرامی در آن باقی مانده، از این‌رو دست‌هایی که صداقتِ پیش از پرداخت‌شدن را دوست دارند، عمداً به سراغش می‌آیند."},"ICON-1308":{"nm":"دانه‌ی کاکائو","de":"دانه‌ای که تازه از غلاف بیرون آمده، تلخ و گس است. باید چند روز تخمیر را خاموش تحمل کند تا رایحه شکوفا شود؛ پس شیرینی، جایزه‌ای کوچک است که این دانه پس از صبری طولانی دریافت می‌کند."},"ICON-1309":{"nm":"خرده‌های کاکائو","de":"در تکه‌های خردشده‌ی دانه‌ی بوداده حتی یک ذره شکر هم نیست. وقتی در دهان می‌گذاری، نخست تلخی می‌آید و خوش‌طعمی با تأخیر از پی آن؛ این‌گونه صادقانه‌ترین ملاقات با کاکائو، پیش از شیرینی، رخ می‌دهد."},"ICON-1310":{"nm":"دانه‌ی سبز قهوه","de":"دانه‌ای سبز که هنوز بویی خام دارد. به همین شکل، رایحه‌اش در خوابی عمیق فرورفته است، پس تا پیش از آنکه تعمید آتش را دریافت کند، آرام به‌صورت امکانی باقی می‌ماند که خود هنوز نمی‌داند چه خواهد شد."},"ICON-1311":{"nm":"دانه‌ی قهوه‌ی بوداده","de":"بر سطح قهوه‌ای‌رنگی که کمی روغن از آن تراویده، رایحه به‌تمامی نشسته است. باید پیش از سرد شدن آسیاب شود تا آن رایحه کامل بماند؛ پس سرنوشت یک فنجان، آرام‌آرام در چند روز پس از بوداده‌شدن رقم می‌خورد."},"ICON-1312":{"nm":"دانه‌ی وانیل","de":"یک رشته رایحه، تمام یک قابلمه شیر را رنگ می‌زند. حتی غلاف مصرف‌شده‌اش را اگر در شیشه‌ی شکر فرو کنی، چند روز بعد تمام شکر معطر می‌شود؛ تجملی که حتی یک ذره‌اش هم دورریختنی نیست."},"ICON-1313":{"nm":"فلفل سیاه","de":"رایحه‌ی یک دانه فلفل کامل، از همان لحظه‌ی آسیاب‌شدن رو به کاهش می‌گذارد. برای همین آن را کامل روی میز می‌گذارند و هر بار تازه می‌کوبند؛ تازگی از دلی می‌شکفد که چیزی را به تعویق نمی‌اندازد."},"ICON-1314":{"nm":"فلفل سفید","de":"دانه‌ای که با گرفتن پوست، هموارتر شده، تندی‌اش کمتر و لطافتش بیشتر است. زاده‌ی مراقبتی است که نمی‌خواهد حتی یک نقطه‌ی سیاه در سسی سفید بر جای بگذارد؛ ظرافتی در جایگاهی ناپیدا."},"ICON-1315":{"nm":"دارچین","de":"اگر یک تکه از آن را دم کنی، تندی‌ای گرم به‌آرامی در چای می‌پراکند. اگر به‌جای پودر، به‌شکل کامل افزوده شود، رایحه‌اش دیرپاتر می‌ماند؛ پس عمق نوشیدنی زمستانی، از پایداری همین پوست خشکیده می‌آید."},"ICON-1316":{"nm":"میخک","de":"در یک غنچه‌ی کوچک شبیه میخ، رایحه‌ای فشرده و پر جای گرفته است. اگر بیش از حد بریزی، طعمش کل غذا را می‌بلعد؛ پس خویشتنداری در تنها یک دانه است که تعادل طعم را آرام نگه می‌دارد."},"ICON-1317":{"nm":"جوزهندی","de":"دانه را کامل نگه می‌دارند و هر بار کمی از آن را می‌سایند. طبیعتش چنان است که اگر از پیش آسیاب شود، رایحه‌اش زود پراکنده می‌شود؛ پس همان یک بار خراشیدن آخر، رایحه‌ی شیر را عمیق‌تر می‌کند."},"ICON-1318":{"nm":"هل","de":"اگر غلاف سبزش را با صدایی خفیف بترکانی، از درونش رایحه‌ای تیز و خنک بیرون می‌ریزد. تنها با کوبیدن یکی‌دو دانه در چای، یک فنجان معمولی ناگهان بوی سرزمینی دوردست را می‌گیرد."},"ICON-1319":{"nm":"زعفران","de":"رشته‌های سرخی که تنها سه‌تای آن از یک شکوفه به‌دست می‌آید. اگر در آب گرم حل شود، رنگی زرد به‌آرامی می‌گستراند؛ پس ارزشمندی، همچنین سنگینیِ زمانی است که با دست، دانه‌به‌دانه چیده شده است."},"ICON-1320":{"nm":"زردچوبه","de":"اگر ریشه‌ی درون خاک را بسایی، تا نوک انگشتانت زرد می‌شود. طبیعتش چنان است که تنها با بو دادنی سبک در روغن، رایحه‌اش بیدار می‌شود؛ پس رنگ طلایی کاری، همان رنگی است که این ریشه‌ی کوچک بر شعله شکوفانده است."},"ICON-1321":{"nm":"برگ بو","de":"برگی که می‌گویند بر پیشانی پیروزمندان می‌نشست. اگر یک برگ در آب جوش بیندازی، از میان بخار، برای لحظه‌ای فریاد شور تماشاگران میدانی کهن برمی‌خیزد. حتی در روزی که پیروز نشده‌ای، اگر رایحه‌اش را به درون بکشی، تسلایی سبز می‌شود که تو را، همان‌گونه که امروز هستی، آرام در آغوش می‌گیرد."},"ICON-1322":{"nm":"شیر نارگیل","de":"آبی سفید که تنها با شکستن پوستی سخت، سرانجام جاری می‌شود. در گوشه‌ای از بازار سرزمینی گرم، اگر نی‌ای در آن فرو کنی و جرعه‌ای بنوشی، تشنگیِ نیمروز یک‌جا فرومی‌نشیند. شیرینی خنکی که در دهان می‌پراکند، سایه‌ی گرمسیر را با خود می‌آورد."},"ICON-1323":{"nm":"روغن نارگیل","de":"وقتی می‌بندد، سفید است چون نخستین برف، و اگر در کف دست گرم شود، رایحه‌اش به‌آرامی می‌پراکند. خردِ مهربان خانه‌داری مادربزرگی جزیره‌نشین که می‌گفت یک قوطی از سر تا نوک پا کافی است، به‌تمامی در همین ظرف گرد جای گرفته است."},"ICON-1324":{"nm":"موز خشک","de":"اگر چند روز زیر آفتاب بگسترانی‌اش، گوشت زردش لطیف و کِشدار می‌شود. اگر تکه‌تکه، با احتیاط گاز بزنی، بوی شیرین و چسبناک فصل برداشتِ بارانی به‌آرامی در دهان زنده می‌شود. شیرینی‌ای که آهسته رسیده، این‌گونه یک فصل را در خود جای می‌دهد."},"ICON-1325":{"nm":"انبه خشک","de":"گوشتی نرم که زیر آفتاب متراکم شده و به ژله‌ای کهربایی‌رنگ بدل گشته است. سه طعم ترش و شیرین و کِشدار، هر سه در یک تکه جمع‌اند؛ اگر آرام در دهان بگردانی‌اش، یک بسته می‌تواند بعدازظهر را طولانی کند."},"ICON-1326":{"nm":"آناناس خشک","de":"برخلاف پوسته‌ی خاردارش، درونش زردی روشن و بی‌همتاست. اگر زیر آفتاب خشک شود، ترشی‌اش متمرکز می‌گردد، پس همین‌که یک تکه گاز بزنی، گوشه‌ی لب‌هایت خودبه‌خود بالا می‌رود. طعمِ تازه‌ای که پس از یک تکه باقی می‌ماند، مدت‌ها دوام می‌آورد."},"ICON-1327":{"nm":"سبد میوه‌های گرمسیری","de":"رنگ‌های تازه‌چیده در یک سبد به هم می‌آمیزند. نارنجیِ انبه، زردیِ موز، طلاییِ آناناس؛ پیش از آنکه دست به سمتش دراز کنی تا انتخاب کنی، تابستان از نوک بینی‌ات نزدیک می‌شود. بغلی از میوه که تنها با نگاه‌کردن، دل را روشن می‌کند."},"ICON-1328":{"nm":"بسته‌ی جلبک دریایی","de":"موهای دریا، برچیده از صخره‌های ساحلی هنگام جزر. در بوی شور ساحل، صدای موج تنیده شده است؛ اگر آرام در آب سرد خیس بخورد، رایحه‌ی ماهی‌گونِ دریا به‌آرامی تا آشپزخانه پیش می‌آید. یک مشت از آن، تالابی کوچک روی میز می‌گستراند."},"ICON-1329":{"nm":"آبزیان خشک‌شده","de":"مشتی از دریایی که سخت و محکم خشکیده است. اگر با دست در امتداد رگه‌هایش پاره کنی، همراه با نمک، بادی شور از بندری کهن آزاد می‌شود. دوستی دیرینه در کنار سفره‌ای پرمهر، که ناخودآگاه یاد یک کاسه ماکولی را زنده می‌کند."},"ICON-1330":{"nm":"ماهی مرکب خشک","de":"ده پایش را منظم گسترده و زیر آفتاب خشک کرده‌اند. اگر کمی روی آتش کبابش کنی و بوی خوشش بلند شود، در امتداد رگه‌ها پاره‌اش می‌کنی. با آن طعم کِشدار و قابل‌جویدن، شأن یک بشقاب میان‌وعده‌ی نیمه‌شب یک پله بالاتر می‌رود."},"ICON-1331":{"nm":"ماهی شور","de":"اگر ماهی را در نمک درشت مدفون کنی، شیوه‌ی تاب‌آوردنِ زمان را می‌آموزد. یک تکه از گوشتش با شوری عمیق کافی است تا یک کاسه برنج در چشم‌به‌هم‌زدنی خالی شود؛ رازی مهربان که مادربزرگی ساحل‌نشین با نوک انگشتانش به نسل بعد سپرده بود."},"ICON-1332":{"nm":"میگوی شور","de":"میگوهای کوچک به‌آرامی در نمک می‌رسند و به طعمی عمیق و لذیذ بدل می‌شوند. لحظه‌ای که یک قاشق از آن به درون کلم چینی فصل کیمچی افزوده می‌شود، بویی شور در تمام حیاط می‌پیچد. همان یک قاشق است که طعم کیمچی یک سال را رقم می‌زند."},"ICON-1333":{"nm":"ماهی آنچوی","de":"بدنی به‌اندازه‌ی یک انگشت، مسئول عمق یک قابلمه آبگوشت است. آشپزخانه‌ی دوران کودکی که سرها و روده‌هایش را جدا می‌کردیم و آرام‌آرام گفت‌وگو می‌کردیم؛ ماهی کوچکی سپاسگزار که استوار در قلب زندگی خانه ایستاده بود."},"ICON-1334":{"nm":"کلپ","de":"نواری سیاه که در اعماق دریا بلند روییده است. آن را در آب سرد می‌ریزند و درست پیش از جوشیدن آرام بیرون می‌کشند؛ پیمانی که دستان آبگوشت‌پز نسل به نسل نگه داشته‌اند. طعم عمیق و لذیذ، هرگز شتاب نمی‌کند."},"ICON-1335":{"nm":"جلبک هیجیکی","de":"بافتی دانه‌دانه که در دهان می‌ترکد. جلبکی که در بهار صخره‌های ساحلی را سبز رنگ می‌کرد؛ اگر با دست آرام مزه‌دارش کنی، دریایی کوچک و تازه در گوشه‌ی سفره می‌گستراند. طعمی است که بهار را می‌جوی."},"ICON-1336":{"nm":"صدف مروارید","de":"نوری گرد که در میان دو لنگه‌ی سخت، مدت‌ها در آغوش گرفته شده و شکل یافته است. تا آنکه ناراحتیِ یک دانه شن به جواهر بدل شود، دریا حتی یک‌بار هم شتاب نکرد. اگر آن را در کف دست بگذاری، وزن آن صبر طولانی نیز همراهش می‌نشیند."},"ICON-1337":{"nm":"زیورِ مرجانی","de":"شاخه‌ی درختِ دریا که موج‌ها صدها سال پرداختش کرده‌اند. اگر نور خورشید بر آن بتابد، به رنگ صورتی و نارنجی می‌گراید، چنان‌که حتی با گذاشتنش بر یک قفسه، تمام اتاق رنگ جزیره‌ای گرم می‌گیرد. حتی رگه‌ی زبرش زیر نوک انگشت، دوست‌داشتنی است."},"ICON-1338":{"nm":"دکمه‌ی صدفی","de":"از جایی که گوشت صدف رفته، درونِ درخشانش را گرد بریده‌اند. اگر بر یقه‌ی لباس بدوزی‌اش، هر بار که می‌بندی‌اش، رنگین‌کمانی کوچک در نوک انگشتانت می‌درخشد. آخرین هدیه‌ی مهربان دریاست، که همه‌چیز بخشید و رفت."},"ICON-1339":{"nm":"تیله‌ی شیشه‌ای","de":"اگر در کف دست بغلتانی‌اش، نوری که در آن محبوس شده نیز همراهش می‌غلتد. آن روزهایی که در کوچه چمباتمه می‌زدیم و بی‌خبر از غروب آفتاب بازی می‌کردیم؛ جیب کودکی که یک دانه بیشتر برده بود، به‌طرزی خاص سنگین و پر از غرور بود."},"ICON-1340":{"nm":"تراشه‌ی چوب ارس","de":"از هر رگه‌ی تراشیده، رایحه‌ای ملایم بیرون می‌تراود. مردمان قدیم با سوزاندن این چوب، دلِ آشفته‌شان را آرام می‌کردند. اگر یک تکه از آن را آرام در دست بگیری، از نوک انگشتانت آرامش به‌آرامی سرازیر می‌شود."},"ICON-1341":{"nm":"عود","de":"رشته‌ای باریک که آرام می‌سوزد و راهی به سوی بالا می‌گشاید. اگر با چشم منحنی‌ای را که دود ترسیم می‌کند دنبال کنی، دلی که تمام روز شتاب داشت نیز بی‌آنکه بفهمد گام‌هایش را کند می‌کند و آرام همان‌جا می‌ماند."},"ICON-1342":{"nm":"گل رنگرزی","de":"اگر رنگی را که در دل گلبرگ‌ها پنهان است در دیگی جوشان حل کنی، پارچه‌ای زلال به‌آرامی به همان رنگ درمی‌آید. قرض‌گرفتنِ لحظه‌ای رنگی که طبیعت از پیش نقاشی کرده بود؛ رنگرزی، در اصل، سلامی مهربان بود که به گل‌ها می‌دادند."},"ICON-1343":{"nm":"رنگ نیل","de":"آبیِ عمیق و ژرفی که از تخمیر بارها و بارها گیاه نیل به‌دست آمده است. هر بار که پارچه را فرو می‌بری و بیرون می‌کشی، رنگش آرام‌آرام از آبی آسمان به آبی دریا می‌گراید. رنگی است از جنس انتظار، که تنها با کنارگذاشتن شتاب می‌شکفد."},"ICON-1344":{"nm":"رنگ سرخ","de":"اگر ریشه‌ی روناس را دم کنی، غروبی که در دل خاک به خواب رفته بود، درون دیگ بیدار می‌شود. رنگی که در روز جشن، دامن عروس تازه را به‌زیبایی می‌آراست؛ فرخنده‌ترین و روشن‌ترین رنگ روستا بود."},"ICON-1345":{"nm":"نخ طلا","de":"طلایی نازک‌تر از تار مو را می‌کشند و رشته‌رشته با دقت می‌ریسند. هرجا که گلدوزی شده، نور را در خود نگه می‌دارد، چنان‌که حتی در اتاقی تاریک با چراغ خاموش، تنها همان نقش است که به‌آرامی و از خود، روشن و درخشان پدیدار می‌شود."},"ICON-1346":{"nm":"ابریشم","de":"نخی که کرم ابریشم بیرون داده، باید بارها و بارها بافته شود تا فقط یک تکه پارچه شود. لمسی که روی پشت دست، همچون آب بهاری می‌لغزد؛ پارچه‌ای ظریف که مردمان قدیم یک فصل کامل را در آغوش گرفتند و آرام پروراندند."},"ICON-1347":{"nm":"دکمه‌ی مروارید","de":"تنها نور درونی مروارید را برگزیده‌اند و گرد پرداخته‌اند. هر بار که یکی از آن‌ها را بر یقه‌ی جوگوری می‌بندی، نوک انگشتانت لحظه‌ای ظریف و باوقار می‌شود. دانه‌ای مرتب که هرچند کوچک، شأن پوشش را به‌آرامی بالا می‌برد."},"ICON-1348":{"nm":"تکه‌نقشه‌ی دریانوردی","de":"فراتر از لبه‌ی پاره‌شده، خطی ساحلیِ ناشناخته ناگهان قطع می‌شود. می‌گویند تنها کسی که بقیه‌ی تکه‌ها را گرد آورد به گنج می‌رسد، اما شاید همان سفری که در پی آن، همراه با باد سرگردان بود، خود از پیش گنج بوده است."},"ICON-1349":{"nm":"نقشه‌ی دریایی کهنه","de":"مسیری که آب دریا در آن پخش شده و نگاره‌ای رنگ‌باخته از قطب‌نما. اگر با نوک انگشت خطی را دنبال کنی که ملوانی در شبی سیاه، تنها با نگاه به ستارگان کشیده بود، جزیره‌ای که مدت‌ها پیش ناپدید شده، آرام‌آرام دوباره روی همان کاغذ کهنه پدیدار می‌شود."},"ICON-1350":{"nm":"نامه در بطری","de":"در درون بطری شیشه‌ای‌ای که موج‌ها به ساحل رانده‌اند، یک ورق کاغذ لوله‌شده. سلامی که معلوم نیست چه کسی و چه زمانی آن را رها کرده، سرانجام به دست کسی رسیده است. دریا نیز، اگر دل داشته باشد، این‌گونه پستچی‌ای کند می‌شود."},"ICON-1351":{"nm":"صندوق به‌گِل‌نشسته","de":"ماجراجویی تا همان لحظه‌ای است که دری را که در آب شور ورم کرده و سفت شده، باز می‌کنی. چه درونش گنج باشد چه فقط شنی خالی، صندوقی که از دور به ساحل رانده شده، همیشه داستان کسی ناشناس را نیز با خود آورده است."},"ICON-1352":{"nm":"کلید کوچک","de":"تکه‌فلزی کهنه که درست در کف دست جای می‌گیرد. هرچند فراموش شده که کدام در را باز می‌کند، وزنی مهربان بر نوک انگشتان سنگینی می‌کند، وزنی که پیش از قفل‌کردن، باز‌کردن را به یاد می‌آورد."},"ICON-1353":{"nm":"سکه‌ی نقره","de":"نقره‌ای گرد که نقشش زیر دست‌های بی‌شمار محو شده است. سکه‌ای که روزی کرایه‌ی قایق کسی یا جای‌خواب یک شب پرمشقت بوده؛ اگر سطح سردش را نوازش کنی، گرمای مبادله‌ای دیرینه، مبهم بر نوک انگشتانت زنده می‌شود."},"ICON-1354":{"nm":"سکه‌ی طلا","de":"اگر آن را در کف دست بگذاری، همان وزن سنگین است که نخست دل را می‌لرزاند. سکه‌ای که زیر نور خورشید زرد می‌درخشد، گویی اگر آن را داشته باشی ثروتمند خواهی شد؛ اما آنچه در واقع روشن‌تر از همه می‌درخشد، تپشِ دل درست پیش از آن است که در دستت بنشیند."},"ICON-1355":{"nm":"مهر ناخدا","de":"پیمانی که ناخدا با فشاری محکم بر موم سرخ می‌زد. با یک نقش، فرمانی برپا می‌شد و مسیری خطرناک تعیین می‌گشت. اقتدار، در نهایت، همان مهر کوچک و محکمی بود که همه‌ی همراهانِ یک کشتی توافق کرده بودند به آن باور داشته باشند."},"ICON-1356":{"nm":"میکروفون دستی","de":"همان لحظه که در دست می‌گیری‌اش، وزنی به‌طرزی عجیب مطمئن، کف دستت را پر می‌کند. چه در لحظه‌ی سلام گفتنِ نخستین با صدایی لرزان، چه در لحظه‌ای که بالاخره صدایی بلند بیرون می‌کشی، همین میله‌ی کوچک است که به‌آرامی بر صدایت بال می‌بندد."},"ICON-1357":{"nm":"میکروفون بی‌سیم","de":"با ناپدیدشدنِ سیم، تمام صحنه گسترده‌تر شد. حتی اگر تا انتهای صندلی‌های تماشاگران بدوی، صدا حتی یک‌بار هم قطع نمی‌شود؛ گویی کسی به‌آرامی پشتت را هُل می‌دهد تا هر طور دلت می‌خواهد بدوی و بخوانی."},"ICON-1358":{"nm":"پایه‌میکروفون","de":"زیر پا استوار می‌ایستد و بی‌صدا منتظر خواننده می‌ماند. اگر دو دست آزاد شوند، ترانه به‌جای نوک انگشتان، در سراسر بدن می‌پراکند. این میله آرام می‌گوید که در ماندن استوار در یک جا تا پایان، جذابیتی روشن نهفته است."},"ICON-1359":{"nm":"پاپ‌فیلتر","de":"لایه‌ای پارچه که به‌شکلی گرد جلوی میکروفون را می‌پوشاند. نفس‌های خشن را نرم صاف می‌کند و تنها صدای زلال را عبور می‌دهد. شنیده‌شدنِ خوب، یعنی محافظتی که تا پایان، از جایگاهی ناپیدا، بی‌صدا انجام می‌شود."},"ICON-1360":{"nm":"این‌ایر مانیتور","de":"اگر درست در گوش جای بگیرد، ترانه‌ی خودت فراتر از فریاد ده‌ها هزار نفر، واضح دوباره زنده می‌شود. کوچک‌ترین و پنهان‌ترین همراهی که روی صحنه‌ای پر از نور و صدا، نمی‌گذارد ریتم را از دست بدهی."},"ICON-1361":{"nm":"هدفون","de":"همین‌که گوش‌ها را می‌پوشاند، جهان اندکی کوچک‌تر می‌شود و تنها ترانه بزرگ باقی می‌ماند. اتاقی گرد که هیچ‌کس نمی‌تواند به آن راه یابد. عجیب است که در دل هدفونی که تنها به‌تنهایی به گوش زده‌ای، تنها نیستی."},"ICON-1362":{"nm":"نت موسیقی","de":"وقتی نقطه‌های سیاه آرام روی خطوط می‌نشینند، کاغذی که تا آن لحظه ساکت بود، صدا را در خود جای می‌دهد. نوشته‌ای که نه خوانده، بلکه شنیده می‌شود. همان لحظه که بازش می‌کنی، ترانه‌ای که ایستاده بود، دوباره نفس می‌کشد."},"ICON-1363":{"nm":"نت آواز","de":"در هر جایی که باید نفس کشید، دایره‌ای کوچک کشیده‌اند. اینجا دم بگیر، آنجا آرام رها کن. نقشه‌ای مهربان که راهی می‌گشاید تا صدا آسیب نبیند."},"ICON-1364":{"nm":"نت پیانو","de":"صفحه‌ای که ده انگشت هم‌زمان از آن راه می‌پرسند. دست چپ ریشه را نگه می‌دارد، دست راست ترانه را می‌کشد. دو دستی که داستان‌های متفاوتی می‌گفتند، سرانجام در آخرین میزان، در یکدیگر تا می‌خورند."},"ICON-1365":{"nm":"جدول آکورد گیتار","de":"زبان بیگانه‌ای که انگشتان برای نخستین‌بار می‌آموزند، نخستین واژه‌اش همین‌جا نوشته شده است. تنها وقتی شش نقطه در دایره‌ای گرد جمع شوند، صدایی به گریه می‌افتد. در هر شبی که فشار می‌دهی و باز فشار می‌دهی، پینه‌ای بر نوک انگشت می‌روید."},"ICON-1366":{"nm":"مترونوم","de":"تیک، تیک؛ گامی استوار و بی‌لرزش در کنارت می‌کوبد. وقتی دل پیش‌دستی می‌کند و می‌دود، از پشت سر آرام‌آرام نگاهت می‌دارد. زیرا ریتم، در نهایت، پیمانی است برای با هم راه رفتن."},"ICON-1367":{"nm":"کوک‌سنج","de":"وقتی سوزن به‌آرامی به مرکز می‌لغزد، صدا سرانجام جای خود را می‌یابد. همان یک نقطه که نه بلند است و نه پست. کوک‌بودن یعنی همین، دیگر نلرزیدن و آرام از حرکت ایستادن."},"ICON-1368":{"nm":"کارت کلاویه‌ی پیانو","de":"هر بار که یک برگ را ورق می‌زنی، کلاویه‌ای به درون کف دستت راه می‌یابد. از دو تا سی، هفت خانه، کیهانی کوچک. حتی در شبی که پیانویی واقعی نیست، ترانه در همین‌جا آرام رشد می‌کند."},"ICON-1369":{"nm":"پیک گیتار","de":"تکه‌ای کوچک و سفت که میان شست و انگشت اشاره جای می‌گیرد. اگر بیفتد، زیر صندلی برای همیشه ناپدید می‌شود، اما همان لحظه که در دست بگیری‌اش، هر شش سیم یک‌جا به صدا درمی‌آیند."},"ICON-1370":{"nm":"چوب طبل","de":"وقتی دو چوب در هوا به‌هم می‌خورند، همان‌جا نشانه‌ای فرود می‌آید. یک، دو، سه، چهار. قلب‌های پراکنده‌ی همه، هماهنگ با آن چهار ضرب، با یک ریتم شروع به تپیدن می‌کنند."},"ICON-1371":{"nm":"دایره‌زنگی","de":"با یک ضربه، صدایی زلال، همچون نور خورشیدِ ریزشکسته، در همه‌سو می‌پراکند. هرچند سبک به‌نظر می‌رسد، اما وقتی شور فروکش می‌کند، اولین چیزی است که دست به‌سویش می‌رود. کوچک است، اما هیچ‌کس نمی‌تواند نادیده‌اش بگیرد."},"ICON-1372":{"nm":"کفش رقص","de":"برای پاهایی که لغزان روی زمین می‌چرخند، اصطکاک خود سلاح می‌شود. در هر کفی فرسوده، چرخش‌های بارها تکرارشده حک شده است. جذاب‌ترین حرکت همیشه از یک جفت کفش استوار آغاز می‌شود."},"ICON-1373":{"nm":"زانوبند","de":"تنها کسی که بارها زانو زده و دوباره برخاسته، قدر همین یک لایه پارچه‌ی نازک را می‌داند. چیزی که دیگر زمین را ترسناک نمی‌کند؛ گاهی شجاعت، این‌گونه دور زانو پیچیده شده است."},"ICON-1374":{"nm":"مچ‌بند","de":"اگر جای خم‌شدن را از پیش بپوشانی، حتی حرکتی سنگین هم بخشوده‌تر می‌شود. مچ دست چیزی نمی‌گوید و تنها تا لحظه‌ی درد، خاموش تحمل می‌کند. آن سکوت طولانی را، یک لایه به‌جای او بر عهده می‌گیرد."},"ICON-1375":{"nm":"مچ‌پابند","de":"در انتهای هر پرش بلند، فرودی هست، و در انتهای آن فرود، مچ پا. جایی در پایین‌ترین نقطه که وزن تمام بدن را می‌پذیرد. همین نوار کوچک است که تمرین فردا را بی‌صدا نگه می‌دارد."},"ICON-1376":{"nm":"کش کشش","de":"اگر بکشی‌اش، به همان اندازه تلاش می‌کند تا به جای خود بازگردد. در طول تاب‌آوردنِ آن مقاومت، بدن بی‌آنکه بفهمد کمی‌کمی بلندتر می‌شود. کشیدگی، در نهایت، رد پایی است که زمانِ تحمل‌شده برجا می‌گذارد."},"ICON-1377":{"nm":"مت یوگا","de":"همان لحظه که آن را پهن می‌کنی، بر روی زمین، قطعه‌ای زمین به‌اندازه‌ی یک نفر پدید می‌آید. قلمروی کوچک برای درازکشیدن و به‌رو‌خوابیدن و تنظیم نفس. آغاز و پایان روز، آرام روی همین یک تکه جمع‌وجور می‌شود."},"ICON-1378":{"nm":"فوم‌رولر","de":"اگر جای گرفته را آرام فشار دهی، ابتدا دردناک است، اما به‌زودی احساس آسودگی می‌کند. در باز کردن چیزی که سفت شده، همیشه کمی درد نهفته است. زیرا هم بدن و هم دل، برای رهاشدن، باید یک‌بار فشرده شوند."},"ICON-1379":{"nm":"دمبل","de":"همان وزن را بارها و بارها بلند می‌کنی. فقط یک بار بیشتر از دیروز، همین و بس. در تکراری بی هیچ زرق‌وبرقی، بازو بی‌صدا کلفت‌تر می‌شود. تکه‌آهنی که چیزی جز صداقت نیست."},"ICON-1380":{"nm":"کتل‌بل","de":"با یک دستگیره، تمام بدن یک‌جا تاب می‌خورد. وقتی وزن گرد آن دایره‌وار می‌چرخد، تعادل کسی که تحملش می‌کند به آزمایش گذاشته می‌شود. برای اینکه نلرزی، نخست باید مرکز خودت را بشناسی."},"ICON-1381":{"nm":"طناب‌ورزشی","de":"از روی طنابی که با صدایی سریع زیر پا رد می‌شود، می‌پری، و باز می‌پری. مثل همان بازی‌ای که در حیاط با دوستان می‌شمردیم؛ هرچه عدد بالاتر می‌رود، نفس تنگ‌تر و خنده بیشتر می‌شود."},"ICON-1382":{"nm":"کفش دو","de":"جفتی که ارزش واقعی‌اش را تنها روی جاده می‌شناسی. اگر هوای سپیده‌دم را بشکافی و همان راه را دوباره بدوی، پیچی که دیروز دور بود، امروز درست جلوی چشمانت است. مسافت را پاها به یاد می‌آورند."},"ICON-1383":{"nm":"حوله‌ی ورزشی","de":"اگر عرقِ پیشانی را پاک کنی، خطی از تلاش امروز در آن نشسته است. اگر بشوییش، ردش محو می‌شود، اما هرچه ریخته‌ای، جایی مرتب انباشته می‌شود. صادقانه‌ترین تشویق، همیشه در کنارت خشک می‌شود."},"ICON-1384":{"nm":"بطری آب","de":"اگر خالی شود پرش می‌کنی، اگر خشک شود جرعه‌ای می‌نوشی. همین رفت‌وآمد ساده، بی‌صدا روز را نگه می‌دارد. مثل سطلی که کنار چاه بالا و پایین می‌رفت، روز دوباره از همین پرکردن آغاز می‌شود."},"ICON-1385":{"nm":"شیک پروتئین","de":"اگر خوب تکانش دهی و جرعه‌ای بنوشی، عضله‌ای که امروز فرسوده‌ای، فردا دوباره پر می‌شود. طعمش پرزرق‌وبرق نیست، اما بدن می‌داند این زبانِ بازیابی است. رشد همیشه آرام نوشیده می‌شود."},"ICON-1386":{"nm":"بار انرژی","de":"میله‌ای که در جیب صاف و لهیده می‌شود. جیره‌ای اضطراری که خلأِ میان وعده‌های غذایی را پر می‌کند. چیز پرافتخاری نیست، اما همین یک لقمه‌ی کوچک، یک حرکت دیگر از بعدازظهر را تاب‌آوردنی می‌کند."},"ICON-1387":{"nm":"آبنبات گلو","de":"اگر در دهان بگردانی‌اش، نعنایی خنک، آرام گلوی زبرشده را نوازش می‌کند. روزی که زیاد حرف زده‌ای، شبی که زیاد خوانده‌ای؛ همان یک آبنبات کوچک، راهِ زبر را آرام می‌کند. شیرینی هم بی‌شک کاربردی دارد."},"ICON-1388":{"nm":"چای صدا","de":"بخاری گرم گلو را گرم می‌کند و با یک جرعه، تنش شانه‌ها به‌آرامی رها می‌شود. نسخه‌ای قدیمی، همچون چای زنجبیلی که مادربزرگ می‌جوشاند. سلامی مهربان که پیش از خواندن به صدا تقدیم می‌شود."},"ICON-1389":{"nm":"آب‌عسل","de":"یک قاشق عسل را آرام در آب ولرم حل می‌کنند. همان جامی که بزرگ‌ترها هر وقت گلو خشک و خشن می‌شد، همیشه برایمان درست می‌کردند. نه دارو است، نه نوشیدنی، فقط شیرینی‌ای که بدن را از درون آرام نوازش می‌کند."},"ICON-1390":{"nm":"مخزن دستگاه بخور","de":"ظرفی که مه‌ای کوچک را در اتاق رها می‌کند. در شب‌های زمستانی که هوای خشک گلو را می‌خراشد، به‌طور نامرئی رطوبت را قسمت می‌کند. مراقبت از کسی، معمولاً همین‌گونه بی‌صدا جاری می‌شود."},"ICON-1391":{"nm":"کوپن استراحت","de":"یک ورق کاغذ که رویش نوشته شده اجازه داری استراحت کنی. همان لحظه‌ای که آن را در دست می‌گیری، بار دلت یک پله سبک‌تر می‌شود. اینکه توقف‌کردن نیز نوعی تمرین است را همین بلیت کوچک به‌جای تو اجازه می‌دهد."},"ICON-1392":{"nm":"برنامه‌ی تمرین","de":"بر روی زمان‌هایی که خانه‌به‌خانه نوشته شده، روز مرتب می‌نشیند. صبح تمرین صدا، بعدازظهر رقص، شب استراحت. حتی فردایی مبهم، اگر با خط تقسیم شود، ناگهان قابل‌قدم‌زدن می‌شود."},"ICON-1393":{"nm":"مهر حضور","de":"نشانه‌ای که می‌گوید امروز هم آمده‌ای را محکم می‌کوبند. هرچه دایره‌های کمی جوهرزده در هر خانه بیشتر می‌شود، پشتکاری که چیزی به‌نظر نمی‌رسید، بی‌آنکه بفهمی به یک راه بدل شده است. مدرکی کوچک از هر روز."},"ICON-1394":{"nm":"استیکر تشویقی","de":"به‌جای گفتنِ آفرین، ستاره‌ای را آرام می‌چسبانند. برقی به‌اندازه‌ی ناخن است، اما همان لحظه که در گوشه‌ی دفتر می‌نشیند، تمام روز روشن می‌شود. تشویق کوچک است، اما به‌طرزی عجیب، مدت‌ها می‌درخشد."},"ICON-1395":{"nm":"یادداشت ذهنی","de":"صفحه‌ای که دلی را که پشت صحنه می‌لرزید، به کلمات باز کرده و نوشته است. حتی روزی که خوب پیش نرفته اگر با صداقت نوشته شود، جایی سبک‌تر می‌شود. دل به همان اندازه که در آن نگاه کنی، استوارتر می‌شود."},"ICON-1396":{"nm":"کارت تجسم ذهنی","de":"اگر چشم‌هایت را ببندی و آن را در دست بگیری، صحنه‌ای آرام در ذهنت می‌گسترد. یک دور پیشاپیش راه‌رفتن در جایی که هنوز رویش نایستاده‌ای. مسیری که با تخیل کشیده شده، یک گام پیش از نوک پاهای واقعی می‌رسد."},"ICON-1397":{"nm":"آینه‌ی تمرین حالت چهره","de":"جلوی آینه می‌خندی، بعد صورتت را جدی می‌کنی، همان چهره را بیش از صد بار می‌سازی. اینجا می‌آموزی که هم شادی و هم اندوه به تمرین نیاز دارند. زیرا حالت چهره، همان نوشتنِ دل به بیرون است."},"ICON-1398":{"nm":"یادداشت رقص","de":"صفحه‌ای که مسیر عبور پا و بازو را به نقاشی درآورده است. در هر هشت‌ضرب، فلش‌ها بی‌صدا نشان می‌دهند بدن باید کجا برود. حرکتی که به‌سختی حفظ می‌شد، روی همین صفحه آرام‌آرام رام می‌شود."},"ICON-1399":{"nm":"چیپ ویدیوی رقص","de":"در یک تراشه‌ی کوچک، صدها حرکت به‌تمامی ذخیره شده است. اگر پیش از خواب یک‌بار دیگر پخشش کنی، نوک انگشتانت خودبه‌خود همان مسیر را دنبال می‌کنند. تکرار، ثبتِ دیگری است که با بدن نوشته می‌شود."},"ICON-1400":{"nm":"نمودار حرکت صحنه","de":"نقشه‌ای از صحنه که از بالا نگاه شده است. اینکه چه کسی کجا با کسی روبه‌رو می‌شود و به کجا پراکنده می‌شود، از پیش با خط و نقطه پیمان بسته شده. برای ترسیم یک تصویر با هم، نخست باید مسیرها را تقسیم کرد."},"ICON-1401":{"nm":"پاس تمرین","de":"صندلی‌های تماشاگران خالی‌اند و نورها هنوز در خوابند. این یک پاس، تو را به دل آن سکوت راه می‌دهد. صحنه‌ای که کسی تماشایش نمی‌کند، و از همین‌جاست که زمان دیدار با صادق‌ترین خودت آغاز می‌شود."},"ICON-1402":{"nm":"کتاب سبک","de":"امروز با چه حسی بپوشم؟ حتی یک پیراهن هم حسی دارد که به آن می‌آید، این کتاب آرام همین را به تو می‌گوید. هرچه صفحات بیشتری ورق بزنی، در نوک انگشتانی که پیش‌تر جلوی آینه مردد بودند، ذوقی کوچک پیوسته انباشته می‌شود."},"ICON-1403":{"nm":"اسپری مو","de":"یک بار که بزنی، حتی باد هم نمی‌تواند بی‌پروا آن را بر هم بزند. جاه‌طلبی کوچکی برای نگه‌داشتن آن چند دقیقهٔ روی صحنه، بی هیچ نقصی، در جای خود. لحظهٔ کامل همیشه بر فراز همین لجاجت‌های به‌ظاهر ناچیز کامل می‌شود."},"ICON-1404":{"nm":"پالت آرایش","de":"دوازده خانهٔ رنگ، دوازده حالت متفاوتند. اینکه امروز با کدام حالت بخواند، نوک انگشت‌ها اول انتخاب می‌کنند و دل از پی می‌آید. در هر خانه‌ای که خالی می‌شود، روزهایی که روی صحنه جا مانده‌اند، آرام رسوب کرده‌اند."},"ICON-1405":{"nm":"سنجاق لباس","de":"در خیره‌کننده‌ترین لحظه، در جایی که هرگز دیده نمی‌شود، سنجاقی کوچک پارچه را نگه می‌دارد. تا نلغزد، تا بر هم نریزد. درخشش روی صحنه همیشه بر استواری کسی دیگر ایستاده است."},"ICON-1406":{"nm":"تابلوی نام","de":"لحظه‌ای که نامی تابلوی خالی را پر می‌کند، وعده‌ای مبهم روشن می‌شود. اینکه چه کسی در این جایگاه خواهد ایستاد را یک خط نوشته تعیین می‌کند. نام، کوتاه‌ترین و استوارترین عهد است."},"ICON-1407":{"nm":"کارت محبت به هوادار","de":"گیرنده تنها یک نفر است، اما برای همان یک نفر تمام دنیاست. کاری که در یک خط سلام کوتاه، شب‌ها سپاسگزاری را فشرده و فشرده‌تر جا می‌دهد. دل، حتی روی کاغذی به اندازهٔ کف دست هم این‌گونه سرریز می‌شود."},"ICON-1408":{"nm":"برگهٔ تمرین امضا","de":"در آغاز حتی نام خودت هم غریب به نظر می‌رسد. در سپیده‌دم‌هایی که صد بار می‌کشی و هزار بار صیقل می‌دهی، تا دست، پیش از دل، آن جریان را از بر کند. این‌گونه است که یک نام، سرانجام امضا می‌شود."},"ICON-1409":{"nm":"برگهٔ سوالات مصاحبه","de":"«به این سوال چه بگویم؟» نوک انگشتانی که کاغذ را گرفته‌اند کمی می‌لرزند. نه از بر کردن پاسخ‌ها، بلکه زمانِ ردیف کردن صداقت، چون مصاحبه هم مثل اعتراف، در نهایت پرسشی است دربارهٔ ترتیب دل."},"ICON-1410":{"nm":"دفترچهٔ لغات","de":"فرسوده‌ترین گوشه، کلمه‌ای را نشان می‌دهد که بیشترین نگاه را دیده است. به همان اندازه که طول می‌کشد تا صدایی ناآشنا بر زبان بنشیند، فاصله با جهانی که هرگز به آن سفر نکرده‌ای هم وجبی نزدیک‌تر می‌شود."},"ICON-1411":{"nm":"کارت اصلاح تلفظ","de":"«ر» غلتان، «س» لغزان. سپیده‌دم‌هایی هست که کارت‌ها را یکی‌یکی ورق می‌زنی و زبان را رام می‌کنی. به همان اندازه که گفتارت شفاف‌تر می‌شود، چهرهٔ کسی که می‌خواهی با آن کلمات به او برسی هم شفاف‌تر می‌شود."},"ICON-1412":{"nm":"چک‌لیست اجرای زنده","de":"میکروفون روشن، این‌ایر بررسی‌شده، مسیر حرکت چک‌شده. با هر خانه‌ای که پر می‌شود، نگرانی درون سینه هم خانه‌به‌خانه خالی می‌شود. پیش از رفتن روی صحنه، دقت، آرام‌ترین گونهٔ شجاعت است."},"ICON-1413":{"nm":"پچ ترمیم بدن","de":"جایی هست که لحظهٔ چسباندن، گرم می‌شود و پخش می‌شود. شانه‌ای خسته، ساق پایی سفت، دلجویی‌ای به اندازهٔ کف دست که آرام به نشانه‌های کوچک بدن پاسخ می‌دهد. خوب استراحت کردن هم بخشی از تمرین است."},"ICON-1414":{"nm":"کیسهٔ یخ","de":"آرام روی مچ پای ورم‌کرده می‌گذاری‌اش. تنها وقتی سرما به‌آرامی نفوذ می‌کند، تازه می‌فهمی امروز چقدر دویده‌ای. بهبودی پشت صحنه همیشه این‌گونه بی‌صدا از راه می‌رسد."},"ICON-1415":{"nm":"کیف کمک‌های اولیه","de":"باند، مسکن، آینهٔ جیبی. لحظه‌ای می‌رسد که این کیسهٔ کوچک پر از چیزهای به‌ظاهر بی‌اهمیت، دلگرم‌کننده‌ترین چیز می‌شود. مهربانی‌ای که از پیش آماده شده، جلوی بحرانی ناگهانی درخشان‌ترین جلوه را می‌یابد."},"ICON-1416":{"nm":"کارت راهنما","de":"کسی از پشت دوربین آرام آن را بالا می‌گیرد. جمله‌ای که نزدیک بود فراموش شود، آنجا با خطی مرتب نوشته شده است. پشت برنامه‌ای که بی‌وقفه پیش می‌رود، همیشه دستی این‌چنین هست که هرگز روی تصویر نمی‌افتد."},"ICON-1417":{"nm":"پاکت مأموریت","de":"هیجان‌انگیزترین لحظه، درست پیش از پاره کردن پاکت است. هرچه درونش باشد، آن شکاف کوتاه از هیجانِ ندانستن است. لذت برنامه‌های تفریحی، تمام و کمال در همان یک لحظهٔ مهر و موم‌شده زنده است."},"ICON-1418":{"nm":"بج نام","de":"نامی کوچک که روی سینه نصب شده، جای اولین سلام را می‌گیرد. میان آدم‌هایی که هنوز یکدیگر را نمی‌شناسند، یک بج نام یخ خجالت را می‌شکند. از همان لحظه‌ای که نامی خوانده می‌شود، رابطه‌ای آغاز می‌گردد."},"ICON-1419":{"nm":"استیکر تنبیه","de":"یک برگهٔ کوچک که روی پیشانی بازنده می‌چسبد، خنده را یکباره سر می‌دهد. آن‌قدر بامزه است که نمی‌شود تنبیهش نامید، حتی باختن هم خاطره‌ای ماندگار می‌شود. نشانه‌ای کوچک و مهربان، ساخته‌شده برای خندیدن با هم."},"ICON-1420":{"nm":"کارت تنبیه تصادفی","de":"تا نکشی، هیچ‌کس نمی‌داند. ده دور راه رفتن مثل فیل یا یک بار ادا و اطوار. لحظه‌ای که سرنوشتت را تمام و کمال به یک برگه کاغذ می‌سپاری، این خنده است که اول از همه بی‌اختیار رها می‌شود."},"ICON-1421":{"nm":"کارت راهنمایی","de":"چیزی شبیه دستی که آرام به سمت جایی گیرافتاده دراز می‌شود. تمام پاسخ را نمی‌دهد، اما راه را نشان می‌دهد. یک راهنمایی خوب، پاسخ درست نیست، بلکه آرام سپردن شجاعتِ یک بار دیگر فکر کردن است."},"ICON-1422":{"nm":"کارت شانس","de":"یک فرصت یگانه برای برگرداندن یک‌باره تختهٔ کج‌شده. اینکه این کارت را کِی بیرون بیاوری، سرنوشت بازی را رقم می‌زند. شانسی که نگه داشته و نگه داشته شده، تنها در سرنوشت‌سازترین لحظه ارزش واقعی‌اش را نشان می‌دهد."},"ICON-1423":{"nm":"کارت تایم‌اوت","de":"اینکه لحظه‌ای توقف کنی هم اشکالی ندارد، این کارت به‌جای تو می‌گوید. وقتی نیاز به گرفتن نفسی داری با اطمینان دست بلند کردن؛ توقف هم استراتژی درستی است، و خوب استراحت کردن هم جایگاهی از مهارت است."},"ICON-1424":{"nm":"دکمهٔ خنده","de":"تلق، همان لحظه که فشارش می‌دهی، صدای خندهٔ شاد و بلندی سرریز می‌شود. صحنه‌های واقعاً خنده‌دار همیشه به کمک همین جلوهٔ صوتی نیاز دارند. گرمای یک جمع، از همین شوخی‌های کوچک گرم می‌شود."},"ICON-1425":{"nm":"ریموت جلوهٔ صوتی","de":"یک دکمه برای کف زدن، دکمه‌ای دیگر برای هو کردن. جادوگری که فقط با نوک انگشت جو را می‌سازد، آرام در اتاق کنترل نشسته است. کارگردانی‌ای که هرگز روی تصویر نمی‌افتد، همان چیزی است که آن صحنه را زنده و نفس‌کشان می‌کند."},"ICON-1426":{"nm":"کلاکت","de":"تق، با همان صدای رسا یک برداشت آغاز می‌شود. میان ده‌ها NG و تنها یک OK، این تختهٔ سیاه هر لحظه را با دقت می‌شمارد. این نخستین ضرباهنگی است که ثبت، پا در آن می‌گذارد."},"ICON-1427":{"nm":"نوار علامت‌گذاری صحنه","de":"لحظه‌ای که نوک پا آرام به آن خط می‌رسد، نورها گویی منتظر بوده‌اند، به‌آرامی فرود می‌آیند. تنها همان یک نقطه که تا فرسودگی از بر شده، صحنه سرانجام با یک نوار رنگی کوچک کشیده‌شده روی زمین کامل می‌شود."},"ICON-1428":{"nm":"فیلتر نور","de":"همان چهره را رنگ نور یکسره دگرگون می‌کند. در فیلتر آبی سپیده‌دم می‌نشیند، در فیلتر سرخ غروب. فضا هرگز دور نیست، آرام در دل یک برگ نازک کاغذ رنگی تا شده است."},"ICON-1429":{"nm":"باتری دوربین","de":"همین که چراغ قرمز چشمک زدن می‌گیرد، دل اول از همه بی‌قرار می‌شود. چون بهترین صحنه همیشه درست در یک درصد باقی‌مانده از راه می‌رسد. یک باتری اضافه در جیب، به‌زودی آرامشِ نفسی تازه می‌شود."},"ICON-1430":{"nm":"کارت حافظه","de":"خندهٔ یک روز و قطرات عرق، در تراشه‌ای به اندازهٔ ناخن، فشرده و انباشته جا می‌گیرند. آن‌قدر کوچک که گم کردنش آسان است، و به همان اندازه هم بی‌نهایت باارزش. وزن خاطراتی که در خود جای داده، هرگز با اندازه سنجیده نمی‌شود."},"ICON-1431":{"nm":"فیلم پولاروید","de":"کلیک، و سپس انتظاری آرام. آن چند ثانیه که چهره‌ای به‌آرامی روی سطح سفید نمایان می‌شود، به شکلی عجیب هیجان‌انگیز است. حتی عکسی فوری در دست هم دقیقاً یک قاشق صبر می‌خواهد."},"ICON-1432":{"nm":"فیلم فوتوکارت","de":"اینکه چه حالتی روی این یک برگ چاپ شود، تا لحظهٔ چاپ راز باقی می‌ماند. چهره‌ای که قرار است محبوب کسی شود، درست همین‌جا زاده می‌شود. یک برگ کوچک کاغذ، دلی به این بزرگی را در خود جای می‌دهد."},"ICON-1433":{"nm":"جلد فوتوکارت","de":"فوتوکارت هرگز با دست خالی لمس نمی‌شود. یک فشار به گوشه‌اش، حتی لبخند آن روز را هم زخمی می‌کند. پیچیدن محبوب کسی با مراقبت در یک برگ شفاف، حتی عزیز داشتن هم به همین اندازه فداکاری می‌خواهد."},"ICON-1434":{"nm":"تاپ‌لودر","de":"میان دو ورقهٔ سفت که بگذاری‌اش، حتی زمان هم نمی‌تواند بی‌پروا مچاله‌اش کند. خم نشو، تا نخور. نگه داشتن چیزی گران‌بها همیشه لایه‌ای از استحکام قرض می‌گیرد."},"ICON-1435":{"nm":"بستهٔ استیکر","de":"یکی‌یکی جدا می‌کنی و گوشهٔ دفتر خاطرات، پشت لپ‌تاپ می‌چسبانی. با یک نقاشی کوچک، روزی بی‌رنگ رنگارنگ می‌شود. آرزوی زیبا کردن اطراف، هیچ سن و سالی نمی‌شناسد."},"ICON-1436":{"nm":"ماژیک امضا","de":"با صدای خش‌خش جوهر روی کاغذ، صف کم‌کم درازتر می‌شود. روی آلبومی که با دستی لرزان جلو گرفته شده، دیداری فقط چند ثانیه‌ای، مدت‌ها به یاد می‌ماند. دل از نوک قلم عبور می‌کند و به آن‌سو می‌رسد."},"ICON-1437":{"nm":"آلبوم امضاشده","de":"جلد را که باز کنی، امضایی با خطوطی آشنا اول سلام می‌دهد. پیوندی که با موسیقی شکل گرفته، روی کاغذ یک وجب نزدیک‌تر می‌شود. نگه داشتن یعنی آن لحظه را آرام متوقف کردن."},"ICON-1438":{"nm":"باتری لایت‌استیک","de":"«روشن شو، خواهش می‌کنم.» درست پیش از ورود، دست‌ها شتاب‌زده باتری تعویض می‌کنند. تا میان ده‌ها هزار نور، آن یکی که مال توست خاموش نشود؛ باتری کوچکی آن شب بزرگ را روشن نگه می‌دارد."},"ICON-1439":{"nm":"کیف لایت‌استیک","de":"بی هیچ خراشی، مرتب و پاکیزه، تا فریادهای شب بعد هم سالم بماند. حتی وقتی آن فضای پرشور کاملاً سرد شده، آن را با احتیاط به خانه می‌بری. ابزار هواداری هم جای خودش را دارد، و دلی که به آن جا رسیدگی می‌کند."},"ICON-1440":{"nm":"بنر شعار","de":"جمله‌ای نوشته‌شده روی پارچه‌ای بلند، عرض سالن را می‌پیماید. لحظه‌ای که حمایتی که به زبان آوردنش دشوار بود کاملاً باز می‌شود، صداقت یک نفر به فریاد همه بدل می‌شود. آن پارچه، خودش صدا می‌شود."},"ICON-1441":{"nm":"بنر کوچک","de":"حمایتی کوچک که درست در کف دست جا می‌گیرد. بنری که دوردست آویزان است مال همه است، اما این یکی فقط روی گوشهٔ میز تو موج می‌زند. با نوسانی آرام ثابت می‌کند که کوچک بودن اندازه، دل را کوچک نمی‌کند."},"ICON-1442":{"nm":"نامهٔ هوادار","de":"نام گیرنده را سه بار دوباره نوشتم و اولین جمله را هفت بار پاک کردم. اینکه نوک انگشتانم درست پیش از بستن پاکت می‌لرزند، از این است که دلم زیادی صادق است. صداقتی سنگین‌تر از یک تمبر، در آن تا شده است."},"ICON-1443":{"nm":"کاغذ کادو","de":"کاغذ کادو بهتر از هرکسی می‌داند که هیجان‌انگیزترین لحظه، همان یک ثانیهٔ پیش از باز شدن است. با آنکه می‌داند سرنوشتش پاره شدن است، خود را با ظریف‌ترین بافت می‌پیچد، درست شبیه دل کسی که آن را هدیه می‌دهد."},"ICON-1444":{"nm":"روبان","de":"خیلی محکم که ببندی خفه می‌کند، خیلی شل که ببندی باز می‌شود، پس پیدا کردن همان نقطهٔ میانه، خودِ دلسوزی است. شکل دل، در یک گره‌ای است که نوک انگشت‌ها انتخاب می‌کنند. آخرین خط یک هدیه را همیشه روبان به‌جای آن می‌نویسد."},"ICON-1445":{"nm":"کارت تشکر","de":"سپاسگزاری‌ای که با زبان گفته شود، در باد پراکنده می‌شود، اما وقتی با دست نوشته شود، مدت‌ها می‌ماند. کاری برای پس فرستادنِ محبتی که دریافت شده، با کمی بیشتر روی آن. هر حرفی که فشرده می‌نویسی، دل را دو برابر عمیق‌تر می‌کند."},"ICON-1446":{"nm":"کوپن ناهار","de":"با یک برگ کاغذ، نگرانی ناهار به‌آرامی حل می‌شود. برنجی تازه‌پخته با بخاری خوش‌رنگ، وعده‌ای با خانه‌های پر از غذاهای جانبی وعده داده شده است. طلسمی کوچک که بعدازظهری گرسنه را استوار نگه می‌دارد."},"ICON-1447":{"nm":"کوپن میان‌وعده","de":"ساخته شده تا ساعت سه بعدازظهر، وقتی گرسنگی نشانه‌ای کوچک می‌فرستد، بیرون کشیده شود. کوپنی که می‌داند یک شیرینی کوچک، حال آدم را نیم‌وجب بالا می‌برد. پاداشی بزرگ نیست، اما درست در لحظه‌ای که لازم است، آرام از راه می‌رسد."},"ICON-1448":{"nm":"کوپن کافه","de":"یک فنجان گرم و یک صندلی کنار پنجره، تمام آن چیزی است که این کوپن وعده می‌دهد. شاید چیز مهمی به نظر نرسد، اما برای کسی، جایزه‌ای کوچک برای دوام آوردن روز می‌شود. دعوت‌نامه‌ای مهربان که رایحه‌اش یک قدم زودتر می‌رسد."},"ICON-1449":{"nm":"کارت نظافت اقامتگاه","de":"پنجره‌ها را کاملاً باز کن و پتوها را تکان بده، روزی که حتی ذره‌ای گرد و غبار هم فرار می‌کند. چه کسی می‌دانست که لازم نبودنِ انجامش با دست خودت، این‌قدر تجملی است. وقتی اتاق می‌درخشد، دل هم آرام مرتب می‌شود."},"ICON-1450":{"nm":"کیت تعمیر","de":"پیچ‌گوشتی، نوار چسب، چند قطعهٔ نامعلوم. وقتی همه جمع می‌شوند، به نظر می‌رسد چیزی نیست که نتوان تعمیرش کرد، اما وقتی بازش می‌کنی همیشه یکی کم است. با این همه، جعبه‌ای از اعتماد به نفس که همین که در دست بگیری‌اش، عجیب دلگرمت می‌کند."},"ICON-1451":{"nm":"بلیت شانس","de":"بلیتی خالی، بی‌صندلی و بی‌شماره. نکتهٔ اصلی این است که چه اتفاق خوبی امروز می‌افتد، رویش نوشته نشده. پر کردن آن جای خالی، کار کسی است که آن را در جیبش حمل می‌کند."},"ICON-1452":{"nm":"تاس","de":"دوستی که کلمهٔ انصاف را بهتر از هرکسی می‌شناسد. طرف هیچ‌کس را نمی‌گیرد و هر شش رو را به یک اندازه دوست دارد. همان لحظه‌ای که از کف دست جدا می‌شود و غلت‌غلتان می‌رود، حتی مهارت و روابط هم لحظه‌ای جایشان را به شانس می‌سپارند."},"ICON-1453":{"nm":"بلیت سفر","de":"وعده‌ای که از اینجا تا آنجا، یک قدم کافی است. کاغذی جادویی که راهی دور را کوچک تا می‌کند و در جیب می‌گذارد. روزی که برای رفتن دودل می‌شوی، هیچ بهانه‌سنجی بهتر از این نیست."},"ICON-1454":{"nm":"بلیت تلاش دوباره","de":"به‌جای دراز کردن دست به سوی کسی که افتاده، بلیتی که آرام پشتش را هل می‌دهد و می‌گوید دوباره امتحان کن. آرام‌تر از هر چیز به تو می‌گوید که شکست پایان نیست، بلکه فقط یک ویرگول کوتاه است. شجاعتِ یک بار دیگر، درست همین‌جا لبریز می‌شود."},"ICON-1455":{"nm":"بلیت اتمام سریع","de":"کلید تقلبی مهربانی که کمی از انتظار می‌گذرد. چه کسی می‌تواند دلی را که حتی سه دقیقه تاب نمی‌آورد سرزنش کند؟ اینجا لذتی است کمی شبیه تقلب، مثل هل دادن شن‌های ساعت شنی با نوک انگشت."},"ICON-1456":{"nm":"تقویت‌کنندهٔ تولید","de":"همان دست‌ها، همان زمان، اما محصول دو برابر. گویی می‌گوید رازش را نپرس، روی میز کار وزوزکنان و شاداب می‌چرخد. دستگاهی کوچک که آرام به دو دست پرتلاش بال می‌دهد."},"ICON-1457":{"nm":"آب‌نبات صمیمیت","de":"حتی خجالتی که با کلمات دشوار می‌شود باز کرد، جلوی چیزی شیرین به‌آرامی آب می‌شود. رابطه‌ای که با یک آب‌نبات که با هم پوستش را کندند، یک وجب از دیروز نزدیک‌تر می‌شود. کشفی بامزه، که شیرینی همان سرعت نزدیک شدن است."},"ICON-1458":{"nm":"ژله ترمیم حال","de":"در روزی که دل شکسته است، چیزی سرد و نرم بی‌درنگ اثر می‌کند. یک گاز که بزنی، چهره‌ای ابری آرام باز می‌شود. ترمیم دل ذاتاً چیزی گران‌بهاست، پس اینکه رتبهٔ R به آن چسبیده بی‌دلیل نیست."},"ICON-1459":{"nm":"پودر درخشان","de":"کمی که روی چیزی معمولی بپاشی، ناگهان خاص می‌شود. هویتش فقط پودری برق‌دار است، اما همان لحظه که می‌نشیند، دنیا کمی سرخوش‌تر به نظر می‌رسد، عجیب است. چیزی شبیه چاشنیِ شادی که روی زندگی روزمره پاشیده می‌شود."},"ICON-1460":{"nm":"نوار صحنه","de":"وقتی روی صحنه می‌ایستی، شمار بی‌شماری نور یکباره تو را پیدا می‌کنند. یک ایکس کوچک روی زمین، بی‌صدا آن نقطه را نشانه‌گذاری کرده است. دقیق‌ترین چیز از جایی نادیده، سرانجام بزرگ‌ترین صحنه را نگه می‌دارد."},"ICON-1461":{"nm":"بست کابل","de":"قهرمانی کوچک که سیم‌های گره‌خورده را یک‌باره مرتب می‌کند. اینکه وقتی محکم شد دیگر بازگشتی نیست، هم عیبش است هم جذابیتش. وسیله‌ای ضروری که آن‌ها که به تمیزی جدی‌اند آرام کنار خود نگه می‌دارند."},"ICON-1462":{"nm":"کابل یدکی","de":"چیزی که وقتی هست حضورش حس نمی‌شود، و تنها وقتی نیست به‌شدت آرزویش می‌کنی. عمیق در ته کیف پشت‌صحنه خوابیده، و درست در لحظهٔ سرنوشت‌ساز با برقی از خواب می‌پرد. آماده بودن را با تمام وجودش ثابت می‌کند."},"ICON-1463":{"nm":"جدول بررسی تمرین","de":"کاغذی پر از خانه‌های ریز، از مسیر حرکت تا کیو و حتی تعویض لباس. اگر یک تیک از اینجا هم جا بماند، دل کسی فرو می‌ریزد. صحنه‌ای بی‌نقص، تنها پس از پر شدن کامل این جدول پرده‌اش را بالا می‌برد."},"ICON-1464":{"nm":"تابلوی صحنهٔ فیلمبرداری","de":"اینجا کافه‌ای است، آنجا کوچه‌ای، اگر پیکان‌ها را دنبال کنی، به دنیایی کاملاً متفاوت می‌رسی. دروغی نقاشی‌شده روی تخته سه‌لا، اما جلوی دوربین واقعی می‌شود. راهنمایی صادق که تمام عمرش را وقف نشان دادن مسیر کرده است."},"ICON-1465":{"nm":"جام کوچک","de":"تکه‌ای طلایی که همین که آن را می‌گیری، انگار قدت یک وجب بلندتر شده. روی میز می‌درخشد و می‌گوید که مقام اول نبودن هم واقعاً اشکالی ندارد، که تمام تلاش امروزت را می‌داند. دلداری بزرگی که یک پاداش کوچک هدیه می‌دهد."},"ICON-1466":{"nm":"کوله‌پشتی","de":"همین که آن را به دوش می‌اندازی، انگار می‌شود به هر کجا رفت. درونش شاید چیز خاصی نباشد، اما از امکان تا لبریز پر است. ماجراجویی همیشه با محکم کشیدن همین بندهای شانه آغاز می‌شود."},"ICON-1467":{"nm":"قطب‌نما","de":"اینکه گم شده باشی و دستپاچه نشوی، از آن روست که نوک عقربه همیشه رو به شمال است. نوسان طولانی‌اش و سرانجام یافتن جای درست، درست شبیه دل آدمی است. می‌گوید سرگردان بودن هم اشکالی ندارد، با همان نوک لرزانش."},"ICON-1468":{"nm":"دفترچه","de":"صفحهٔ اول همیشه خالی است. تنها کسی که قلم به دست دارد می‌داند چه بنویسد. من فقط منتظرم تا فکر امروز به نوشته بدل شود و آرام روی من فرود آید. رتبهٔ R، وزن امکانی است که به‌زودی پر خواهد شد."},"ICON-1469":{"nm":"مداد","de":"اینکه اشتباه کردن هم اشکالی ندارد، مهربان‌ترین وجه این ابزار است. تا وقتی دوستِ پاک‌کن کنارت باشد، می‌توانی هر چند بار که بخواهی از نو شروع کنی. هرچه تراشیده می‌شود کوتاه‌تر می‌شود، اما آن کوتاهی، نشانهٔ آن است که مدت‌ها دوستش داشته‌اند."},"ICON-1470":{"nm":"فیلم عکاسی","de":"همان لحظه که نور از آن می‌گذرد، رنگ آن روز بی‌کم‌وکاست حک می‌شود. اینکه وقتی یک قاب می‌گذرد دیگر هرگز نمی‌شود برش گرداند، هم تنش است هم جذابیت. انتخاب کسانی که در عصری پرشتاب، عمداً می‌خواهند یک ضرب کندتر به یاد بسپارند."},"ICON-1471":{"nm":"دوربین فوری","de":"کلیک، و سپس انتظاری کوتاه. در دست بگیری‌اش و آرام تکانش بدهی، لحظه‌ای تار کم‌کم شفاف می‌شود. ماشینی کمی جادویی که همین‌جا و همین لحظه را بی‌کم‌وکاست روی یک برگ کاغذ گیر می‌اندازد."},"ICON-1472":{"nm":"عکس قدیمی","de":"اینکه رنگ چقدر پریده، یعنی چقدر زمان گذشته است. در هر گوشهٔ فرسوده، دست کسی مانده است. اینکه قدیمی‌ترین عکس، شفاف‌ترین خاطره را در خود دارد، شاید به‌خاطر همان دست‌هاست."},"ICON-1473":{"nm":"دفتر یادگاری","de":"تکه‌هایی که دور انداختنشان دریغ است، جمع می‌شوند و جمع می‌شوند تا یک جلد شوند. بلیت سینمای رنگ‌پریده، گلبرگی خشک‌شده، یادداشتی کوتاه. برای چشم دیگران شاید فقط خرت‌وپرت باشد، اما برای کسی که آن را ورق می‌زند، یک فصل کامل دوباره زنده می‌شود."},"ICON-1474":{"nm":"دفتر سفر دریایی","de":"باد و موج امروز، و یک خط از دل. نوشتن دقیق حتی در روزهای بی‌اتفاق، قاعدهٔ سفر دریایی است. مدرک اینکه به سلامت رسیده‌ای، همیشه جایی در دل همین دفتر ضخیم نوشته شده است."},"ICON-1475":{"nm":"تکهٔ نقشه","de":"فقط یک گوشه از کل است، اما بدون آن هرگز راه پیدا نمی‌شود. آن لذتی که وقتی لبهٔ پاره‌شده دقیقاً با تکه‌ای دیگر جفت می‌شود چه حسی دارد. رتبهٔ R حضوری دارد شبیه آخرین قطعهٔ یک پازل."},"ICON-1476":{"nm":"پیام در بطری","de":"بی‌آنکه بداند چه کسی آن را خواهد خواند، آرام خود را به دست موج‌ها می‌سپارد. پاسخی انتظار ندارد، تنها آرزو دارد این دل جایی برسد. کندترین اما رمانتیک‌ترین شیوهٔ فرستادن نامه است."},"ICON-1477":{"nm":"تاس","de":"شش رویی که گرد و گرم می‌خندد، انگار می‌گوید باز هم تویی؟ همان شکل، اما هر بار که می‌غلتد پاسخی متفاوت می‌دهد، این هوس بی‌تغییر این دوست است. همان لحظه که از دستت جدا می‌شود، انتخاب را لحظه‌ای به سرنوشت می‌سپاری."},"ICON-1478":{"nm":"چرخ بادی","de":"تنها وقتی باد بوزد، زنده می‌شود. اگر بی‌حرکت بماند، فقط بال‌هایی از کاغذ است، اما اگر کسی رویش فوت کند، شاداب چرخیدن آغاز می‌کند. خجالت نکشیدن از کمک گرفتن، خرد همین گل کوچک است."},"ICON-1479":{"nm":"سبد پیک‌نیک","de":"در که باز می‌شود، بوی گیمباپ اول سلام می‌دهد. چمن سبز، زیرانداز پهن‌شده، و دست‌هایی که غذا با هم قسمت می‌کنند. روزهایی که این سبد پر می‌شد، به‌طرز عجیبی همیشه آسمان صاف بود."},"ICON-1480":{"nm":"گلدان","de":"حتی با گذاشتن یک شاخه، هوای اتاق دگرگون می‌شود. وقتی خالی است، صبورانه منتظر ماندن وظیفهٔ اوست. متواضع‌ترین وسیلهٔ صحنهٔ اتاق، که برای درخشیدن بیشتر گل، آرام حضور خودش را کوچک می‌کند."},"ICON-1481":{"nm":"گلبرگ","de":"وقتی باد یک برگ را با خود می‌برد، بهار به همان اندازه سبک‌تر می‌شود. درخت کهن حیاط هر سال همان سلام را می‌دهد، اینکه افتادن هم بخشی از کار شکفتن است. پراکنده شدن پایان نیست، نامه‌ای است که پیشاپیش برای بهار بعدی پست شده."},"ICON-1482":{"nm":"گل رز","de":"اینکه اول خارها را برمی‌افرازد، وعده‌ای است که بی‌پروا لمس نشود. در درونش، سرخ‌ترین دل پنهان است. کسی یک شاخه را آرام کنار پا گذاشت و رفت، دلش را به‌جای نام، تنها با رنگ نوشت."},"ICON-1483":{"nm":"سوسن","de":"کنار چینی سفید و آراسته، همیشه همین گل سفید جای می‌گرفت. باشد که رایحه‌اش دور برود اما وقارش هرگز بر هم نخورد. در آن جایگاهی که به‌جای شکوه، پاکی را برگزید، سوسن بی‌هیچ کلامی، وقاری یک اندازه را نگه می‌دارد."},"ICON-1484":{"nm":"لاله","de":"با سری کمی خمیده، ایستاده در ردیف، به‌طرز عجیبی مرتب به نظر می‌رسد. گلی که ردیف اول باغچهٔ بهاری را برعهده دارد. آن صداقتِ یکباره شکفتن و یکباره افتادن، فصل کوتاه را عمیق‌ترین رنگ می‌زند."},"ICON-1485":{"nm":"سنبل","de":"روی یک ساقه، زنگوله‌های کوچکی فشرده آویزان کرده است. تکانش بدهی صدایی نیست، اما رایحه به‌جایش اتاق را طنین‌انداز می‌کند. در آستانهٔ بهار، تجملی مهربان که با یک گلدان، هوای اتاق را یکسره عوض می‌کند."},"ICON-1486":{"nm":"نمونهٔ قورباغه","de":"بدنی کوچک که زمان درون جعبه‌ای شیشه‌ای برایش متوقف شده. روی برچسب نوشته شده: «شالیزار و برکه، پرنشاط‌ترین روز پس از باران.» تنها پس از توقف است که حتی دمای کنار آبی که موجودی در آن زیسته، در سند باقی می‌ماند."},"ICON-1487":{"nm":"نمونهٔ مارمولک","de":"حتی وقتی نمونه شده، آن زیرکیِ قطع کردن دم و فرار کردن پاک نمی‌شود. مهمانی کوچک که دیوارهای سنگی آفتاب‌گیر را دوست داشت. در یادداشت کنارش، جهت آن نقطهٔ آفتابی که دوست داشت بالا برود، با خطی مرتب نوشته شده است."},"ICON-1488":{"nm":"یادداشت موش کور","de":"خاطرات کسی که زیر زمین می‌رود، با بافت خاک نوشته می‌شود. کجا را کند و کجا ایستاد، نقشه‌ای از مسیرهای نادیده. زمانی که با پشت به نور زیسته شده، برای کسی به‌راستی وسواسی‌ترین ثبت می‌شود."},"ICON-1489":{"nm":"نمونهٔ صدف","de":"نقشی استوار که موج هزاران بار صیقلش داده و فرستاده. مردم جزر و مدی تنها با نگاه به بافت صدف می‌فهمیدند از کدام دریاست. شکل دریایی که زمانی زنده بود و نفس می‌کشید، بی‌کم‌وکاست در نمونه‌ای به اندازهٔ کف دست جای گرفته است."},"ICON-1490":{"nm":"نمونهٔ مرجان","de":"در اعماق دریا، در طول صدها سال به‌سختی یک وجب رشد می‌کند. شبیه شاخه‌ای به نظر می‌رسد، اما در واقع خانه‌ای است که شمار بی‌شماری موجود کوچک با هم ساخته‌اند. هرچه کندتر باشد، بیشتر می‌ماند، مرجان این را با سکوت ثابت می‌کند."},"ICON-1491":{"nm":"سرنخ آیدونگ","de":"تکه‌ای از داستانی پراکنده‌شده جایی در جزیره. یک تکه‌کاغذ کوچک آرام قدم بعدی را نشان می‌دهد. هر ماجراجویی سرانجام با برداشتن همین ردهای کوچک آغاز می‌شود، این را راهنمای کهنسال می‌گوید."},"ICON-1492":{"nm":"تکهٔ امضا","de":"وقتی نقش پراکنده جای خودش را می‌یابد، سرانجام یک نشان کامل می‌شود. تکه‌ای که بافت یگانهٔ کسی روی آن حک شده است. پیش از جفت شدن، معنایش را پنهان می‌کند، و همان لحظه که جفت می‌شود، سرانجام نام می‌شود."},"ICON-1493":{"nm":"تکهٔ خاطرهٔ صحنه","de":"حتی وقتی آهنگی تمام می‌شود، گرمای باقی‌مانده میان صندلی‌ها می‌ماند. آن گرما را جدا کنی و سفت کنی، تکه‌ای کوچک مثل این می‌شود. تکه‌های پراکندهٔ کف‌زدن و فریاد، وقتی آرام جمع شوند، آن شب بی‌کم‌وکاست دوباره زنده می‌شود."},"ICON-1494":{"nm":"مهر دبیوت","de":"روزی که برای اولین بار نامت خوانده شد، همان اثر جوهر که پشت دستت زده شد. حتی مراقبتی که با احتیاط خشکش می‌کردی تا لک نشود، بخشی از خط شروع بود. یک مهر کوچک، روزی خاص را برای همیشه از پاک شدن نجات می‌دهد."},"ICON-1495":{"nm":"مدال تاپ آیدل","de":"سنگینی‌ای که تنها به کسی که به بالاترین جایگاه رسیده اجازه داده می‌شود. اما سنگینی این مدال از فلز نیست. از این است که وزن دست‌های بی‌شماری که صحنه را با هم پر کردند، بی‌کم‌وکاست در یک نقطه جمع شده است."},"ICON-1496":{"nm":"کلید کوچک","de":"نخستین کلید اقامتگاه همیشه مال درونی‌ترین اتاق بود. جایی که پیش از یاد گرفتن قفل کردن، باز کردن را یاد می‌گرفتی. روز رفتن، روی فلز سرد، گرمایی که کف دست برجای گذاشته، مدت‌ها می‌ماند."},"ICON-1497":{"nm":"صندوقچهٔ گنج","de":"تا باز نشود، هیچ‌کس نمی‌داند درونش چیست. همان ندانستن، گنج واقعیِ صندوقچهٔ گنج است. در آن لحظهٔ کوتاهِ بالا بردن در، هر کسی لحظه‌ای به هیجان روزهای کودکی برمی‌گردد."},"ICON-1498":{"nm":"نقشهٔ ساختمان","de":"روی خط‌هایی که خانه‌به‌خانه کشیده شده‌اند، ساختمانی هنوز ساخته‌نشده زندگی می‌کند. باز کردن نقشه، یعنی یک بار پیشاپیش در فردا قدم زدن. یک خط خوب‌کشیده‌شده، فردایی را نگه می‌دارد که فرو نمی‌ریزد."},"ICON-1499":{"nm":"کارت دستور پخت","de":"روی یک کارت دست‌مالیده، مزهٔ دست مادربزرگ به‌صورت مقدار نوشته شده است. کلماتی مبهم مثل «یک چیمچه نمک» دقیق‌ترین رمز آن است. هرچه خط محوتر شود، آشپزخانه‌ای که آن غذا در آن می‌جوشید، شفاف‌تر به یاد می‌آید."},"ICON-1500":{"nm":"مجوز تأسیسات","de":"یک برگ کاغذ، زمینی خالی را به «جایی قابل استفاده» تبدیل می‌کند. ساختمانی تازه همیشه اول به مهر روستا نیاز داشت. اجازه، در نهایت، مهری گرم است که می‌گوید اینجا می‌توانی چیزی را آغاز کنی."},"ICON-1501":{"nm":"مجوز بندر","de":"پیش از آنکه کشتی لنگر بیندازد، باید نخست همین یک برگه را می‌داشت. مهر رنگ‌باخته‌ی بندر، نخستین سلامِ آن به کسانی‌ست که از دور دست می‌آیند. میان رفتن و رسیدن، بندر همیشه با یک تکه کاغذ دل می‌گشاید."},"ICON-1502":{"nm":"نشان شهروندی جزیره","de":"گواهی کوچکی که نشان می‌دهد اکنون از اهالی این جزیره شده‌ای. روستای قدیمی هرگاه همسایه‌ی تازه‌ای می‌آمد، نامش را به فهرست می‌افزود و برنج شیرین گرم پخش می‌کرد. تنها یک برگه کاغذ است، اما بر آن این خوش‌آمدگویی روشن نوشته شده: «حالا تو هم یکی از مایی.»"},"ICON-1503":{"nm":"تابلوی نامِ اتاق","de":"با یک نام که کنار در آویخته شود، اتاقی خالی سرانجام خانه‌ی کسی می‌شود. حتی در اتاق‌های مهمانِ قدیم نیز نخستین چیزی که آویخته می‌شد، لوحی بود با نام صاحب‌خانه حک‌شده بر آن. تابلوی نام کوچک است، اما درونش پر از گرمای «اینجا کسی زندگی می‌کند» است."},"ICON-1504":{"nm":"تمبر طرفداری","de":"حتی آن دقتِ لیسیدن و محکم چسباندنش هم بخشی از یک نامه‌ی کامل بود. کارِ چسباندن دلی دوست‌داشتنی به تکه‌ای کاغذ کوچک و فرستادنش به دوردست. حتی در عصر دیجیتال هم کسی هست که دلش را با دست پست می‌کند."},"ICON-1505":{"nm":"نشان جزیره‌ی درخشان","de":"به یقه که آویزانش کنی، نوری کوچک در هر مسیری همراهت می‌آید. اگر در راه کسی را با همین نشان ببینی، بی هیچ کلامی با هم همدلید. درخشش، فخرفروشی نیست، بلکه نشانه‌ای آرام است: «ما عاشق همین یک جزیره‌ایم.»"},"ICON-1506":{"nm":"میز کار","de":"رویه‌ی پر از خراش، گواهِ دستانی است که بیشترین چیزها را ساخته‌اند. جایی که چیزی تعمیر شد، به هم پیوست، صیقل خورد. میز کارِ درهم‌ریخته، بیش از یک میز تمیز، در دل خود داستان‌های بیشتری نهفته دارد."},"ICON-1507":{"nm":"جعبه‌ی نگهداری","de":"هرچه چیزی گران‌بهاتر باشد، زودتر جایش را معین می‌کنی. پیشینیان نیز اسناد گران‌بها را جداگانه در صندوق‌های چوب پائولونیا نگه می‌داشتند. نگهداری خوب، در نهایت یعنی امروز را تاخورده و مرتب برای کسی در آینده کنار گذاشتن."},"ICON-1508":{"nm":"صندوق ذخیره","de":"وقتی فراوان است، جمعش کن؛ وقتی کم است، بردار و استفاده کن. در این‌جا خردِ روزگاری نهفته که انبار پر، دل را هم استوار می‌کرد. ذخیره کردن یعنی از پیش، وعده‌ای مهربان به خودِ آینده تقدیم کردن."},"ICON-1509":{"nm":"جعبه‌ی خنک‌کننده","de":"صندوقی پر از یخ، حتی در گرمای تابستان هم خنکی را نگه می‌داشت. گویی خردِ کهنِ یخچال‌های سنگی، در اندازه‌ی کف دست به این‌جا رسیده است. سرد نگه‌داشتن چیزی، یعنی تازه‌ترین لحظه را کمی بیشتر نگه داشتن."},"ICON-1510":{"nm":"تلمبه‌ی آب","de":"دسته را بالا و پایین که ببری، آب عمیقِ زیرِ زمین بالا می‌جوشد. ماشینی صادق که تنها پس از یک پیمانه آب چکاننده، به‌راستی فوران می‌کرد. کنار چاه از دیرباز این حقیقت را می‌دانست: باید نخست بدهی تا بگیری."},"ICON-1511":{"nm":"دستگاه تصفیه‌ی آب","de":"معجزه‌ای کوچک که در آن آبِ گل‌آلود لایه‌به‌لایه زلال بیرون می‌آید. پیشینیان با چیدن شن و زغال لایه‌روی‌لایه در کوزه‌ها، آب را صاف می‌کردند. زلالی رایگان به دست نمی‌آید؛ دقتی‌ست در آرام‌آرام صاف کردن."},"ICON-1512":{"nm":"جاآب‌پاش","de":"لحظه‌ای که آب‌پاش جای استراحت خود را می‌یابد، روزِ باغچه مرتب می‌شود. تعیین جایی برای آویختن ابزار، عادتِ کسی است که کارش را دوست دارد. وقتی یک جا مشخص شود، تمام حیاط یکدست‌تر می‌شود."},"ICON-1513":{"nm":"جاقلاب ماهیگیری","de":"تا رسیدنِ طعمِ صید، آدم می‌رود اما قلاب ماهیگیری جایش را نگه می‌دارد. همان حالتِ منتظرِ صید کردن سال‌ها در کنار رودخانه، درست همین‌جا حک شده است. جاقلاب، در نهایت، تکیه‌گاهی است برای کنار گذاشتنِ کمی بی‌تابی."},"ICON-1514":{"nm":"سبد جمع‌آوری","de":"مشتی سبزی کوهی، یک شاخه گل وحشی؛ باری بود در دستِ مادر. از شکاف‌های بافته‌شده‌ی بامبو، بوی خاک آرام بیرون می‌زند. بسته به آنچه در آن بگذاری، سبد خالی می‌تواند بهار باشد یا پاییز."},"ICON-1515":{"nm":"هاون","de":"کوب، کوب، با ضربی یکنواخت غله را می‌کوبید و روز روستا بیدار می‌شد. ابزاری که صدای کوبیدنش در روزهای جشن، کوچه را پر می‌کرد. برای نرم کردنِ چیزِ سخت، به ریتمِ پیوسته‌ی دستی کارکشته نیاز است."},"ICON-1516":{"nm":"تخته‌ی آشپزخانه","de":"هر ردی که چاقو بر جای می‌گذارد، تاریخِ یک وعده غذا را حک می‌کند. تخته‌ی چوبیِ پر از خراش، نشانِ افتخارِ آشپزخانه‌ای است با پرکارترین دست‌ها. بریدن چیزی، از خواستِ پذیرایی دلسوزانه از آن آغاز می‌شود."},"ICON-1517":{"nm":"قابلمه","de":"صدای جوشیدنِ آرام، مهربان‌تر از هر موسیقی‌ست. در سپیده‌دمی گرسنه، آن سه دقیقه‌ی انتظار برای پخته‌شدنِ رشته، صمیمی‌ترین دلداری‌ست. در سراسر ته‌ی گرد آن، گرمای خواستنِ سیر کردنِ کسی داغ می‌شود."},"ICON-1518":{"nm":"ماهیتابه","de":"مهارتِ پختنِ چیزی در یک دم روی آتش، به همین یک تابه بستگی دارد. هرچه سطحش پخته‌تر باشد، کمتر می‌چسبد و بیشتر می‌درخشد. تابه‌ی چدنیِ کهنه، خود گواهِ سال‌هایی‌ست که آشپزخانه از سر گذرانده."},"ICON-1519":{"nm":"فر","de":"هنگامی که در بسته می‌ماند و منتظری، درونش آرام‌آرام جادو رخ می‌دهد. زمانی که خمیر ور می‌آید و رنگش می‌پزد. حتی وقتی نمی‌بینی، اگر با ایمان منتظر بمانی، نتیجه‌ای گرم در را می‌گشاید و بیرون می‌آید."},"ICON-1520":{"nm":"مخلوط‌کن","de":"چیزِ سفت را هم که در آن بریزی، در یک لحظه جامی نرم می‌شود. گردابی کوچک که در آن مواد گوناگون می‌آمیزند و طعمی تازه زاده می‌شود. هماهنگی، در نهایت، یعنی هرکس اندکی از تیزی‌های خود را کنار بگذارد."},"ICON-1521":{"nm":"همزن","de":"یک تکان مچ، هوا را به دام می‌اندازد و به همان سرعتِ هم‌زدن، آنچه رقیق بود سفت می‌شود. تا کف‌ها مثل قله‌ای بالا می‌آیند، تنها خمیر نیست که باد می‌کند. آرزوی سیر کردن کسی امروز هم همراهش باد می‌کند."},"ICON-1522":{"nm":"آسیاب قهوه","de":"با یک مشت دانه‌ی قهوه، دسته را که بچرخانی، عطر پیش از هر چیز میان دندانه‌ها می‌شکند. تا بازو خسته شود، پودر تازه نرم می‌شود، و اولین جرعه به اندازه‌ی همان زحمت عمیق می‌شود. دلسوزی همیشه از مچ دست آغاز می‌شود."},"ICON-1523":{"nm":"آسیاب آرد","de":"دانه از میان سنگ‌ها می‌گذرد و آردی سفید بیرون می‌آید. عیب ندارد اگر یک‌بار نرم نشد، دوباره بکوبش کافی‌ست. حتی برای نرم کردنِ چیزِ خشن هم ترتیبی هست که آسیاب بی‌صدا یادآوری می‌کند."},"ICON-1524":{"nm":"میز اره‌کشی","de":"وقتی تنه‌ی درختی بالا می‌آید، اره نخست رگه‌هایش را می‌خواند. باید از گره‌ها گذشت و فقط مسیر مستقیم را برید تا تخته کج نشود. بریدن چوب، در نهایت، یعنی زمانی را که یک درخت زیسته، مرتب پهن کردن."},"ICON-1525":{"nm":"چرخ خیاطی","de":"خرخر—صدای سوزنی که پارچه را گاز می‌گیرد و می‌دود، شبِ دیرهنگام را پر می‌کند. یک درز، دو تکه پارچه را به یک تن پیوند می‌زند، و در هر بخیه‌ی پنهانِ درونِ لباس صحنه، ساعت‌های بی‌خوابیِ کسی محکم دوخته می‌شود."},"ICON-1526":{"nm":"میز رنگرزی","de":"پارچه‌ی سفید را که فرو ببری و بیرون بکشی، ابتدا سبزِ کم‌رنگ است، و تنها با برخورد هوا سرانجام آبی می‌شود. رنگی که می‌گویند تنها پس از سه بار خیساندنِ نیل بیرون می‌آید. اینکه انتظار خودش رنگ می‌شود را من نخستین بار پیش همین میز رنگرزی آموختم."},"ICON-1527":{"nm":"سه‌پایه‌ی دوربین","de":"لحظه‌ای که سه پایه باز می‌شوند و زمین را لمس می‌کنند، دنیای لرزان می‌ایستد. نمایی که در دست می‌لرزید، بر عهدِ همین سه نقطه، واضح می‌شود. برای نگاه کردنِ طولانی به چیزی، نخست باید بلد باشی چگونه بی‌حرکت بایستی."},"ICON-1528":{"nm":"پایه‌ی نور","de":"نوری بر یک ستون بگذاری، هر گوشه‌ی اتاق صحنه‌ای کوچک می‌شود. زاویه را کمی که بچرخانی، سایه‌ها بلندتر می‌شوند و حالت چهره زنده می‌شود. تاریکی را پاک نمی‌کند، بلکه حتی تاریکی را هم مهربانانه سرِ جایش می‌گذارد."},"ICON-1529":{"nm":"پایه‌ی میکروفون","de":"لحظه‌ای که ارتفاع را تنظیم می‌کنی، فاصله‌ی میان دهان و آواز مشخص می‌شود. دست را که برداری، صدا همان‌جا می‌ماند. تنها روی صحنه‌ای که هر دو دست آزادند، آوازی که با تمام تن خوانده می‌شود، آغاز می‌شود."},"ICON-1530":{"nm":"پایه‌ی نت","de":"وقتی برگه‌ی بازشده کج تکیه می‌دهد، نت‌ها در ارتفاع چشمِ نوازنده صف می‌کشند. حتی وقتی با یک اشاره میزانِ بعدی می‌رسد، پایه نمی‌لرزد. پشت نوازندگیِ هرکس، همیشه جایی بی‌کلام هست."},"ICON-1531":{"nm":"باغچه","de":"خاک را که شخم بزنی و جوی بکشی، خطوطِ کوچکِ وعده روی زمین پدیدار می‌شود. چند روزِ پس از کاشتنِ بذر انگار هیچ اتفاقی نمی‌افتد، اما یک صبح، لپه‌های لطیف خاک را کنار می‌زنند و بالا می‌آیند. منظره‌ای که فقط کسی که منتظر مانده می‌بیند."},"ICON-1532":{"nm":"باغچه‌ی حاصلخیز","de":"همان بذر است، اما در این خاک برگ‌ها دو برابر بزرگ‌ترند. انگشتت را که فرو کنی، خاکِ سیاه و نرم تا زیرِ ناخنت همراهت می‌آید. رشدِ خوب، در نهایت، کاری بود که زیر پا، به‌آرامی و ناپیدا، انجام شده بود."},"ICON-1533":{"nm":"گلخانه","de":"زیر سقف شیشه‌ای، فصل‌ها یک ضرب کندتر جاری می‌شوند. حتی وقتی بیرون شبنم می‌نشیند، درون با رطوبتِ نیمه‌تابستان مرطوب است. برای چیزهایی که در برابر سرما ضعیف‌اند، کسی نور خورشید را آرام در سقف زندانی کرده است."},"ICON-1534":{"nm":"باغچه‌ی گیاهان معطر","de":"نوکِ انگشت که برگ را لمس کند، عطر پیش از هر چیز سلام می‌دهد. ریحان، رزماری، نعنا—هر نام که صدا زده شود، بویی دیگر به انگشتانت می‌چسبد. یک باغچه‌ی کوچک، تمام آشپزخانه را مهربانانه دگرگون می‌کند."},"ICON-1535":{"nm":"باغ میوه","de":"در بهار زیر سایه‌ی شکوفه، در پاییز زیر وزنِ میوه، شاخه‌ها خم می‌شوند. از نردبان بالا برو، یکی بچین، گاز بزن، و شیرینیِ نورِ خورشید که در تمام سال ذخیره شده، در دهانت می‌ترکد. گویی جوابی است که درخت به انسان می‌دهد."},"ICON-1536":{"nm":"کنده‌ی قارچ","de":"در تنه‌ی بریده‌شده سوراخ بزن و اسپور بکار، و درختِ مرده باز چیزی می‌پروراند. چند روز بعد، صبحی که کلاهک‌ها دسته‌دسته می‌رویند، جایی که پایانش می‌پنداشتی، زندگی تازه‌ای آرام آغاز می‌شود."},"ICON-1537":{"nm":"کندوی عسل","de":"گوش را نزدیک ببری، از درون لرزشی آهسته و پرتلاش می‌شنوی. هزاران بار بال‌زدن جمع می‌شود تا فقط یک قاشق شیرینی به دست آید. زحمتِ یک‌روزه‌ی رفت‌وآمد در مزرعه‌ی گل، چسبناک و طلایی، همین‌جا انباشته شده است."},"ICON-1538":{"nm":"مرغدانی","de":"پیش از سپیده‌دم، آن‌ها که روی چوب‌بست نشسته‌اند نخست به جنب‌وجوش می‌افتند. دست را در کاه گرم فرو کنی، تخمی می‌گیری که هنوز گرمایش مانده است. جایی که نخست خبر از صبح می‌دهد، نخست هم سفره‌ی صبحانه را می‌چیند."},"ICON-1539":{"nm":"مرتع","de":"دشتی پهناور که بوی علف با بوی آفتاب می‌آمیزد. بر پشتِ آن‌ها که در حصار به‌آرامی نشخوار می‌کنند، سایه‌ی ابرها می‌گذرد. در این‌جا که عجله‌ای در کار نیست، حتی زمان هم مثل چرا کردن، آرام جاری می‌شود."},"ICON-1540":{"nm":"کارگاه پنیر","de":"شیرِ تازه‌دوشیده با گذر از انعقاد و رسیدن، به‌آرامی سفت می‌شود. چند ماه روی قفسه‌ای خنک چون غار منتظر بمان، تا طعمی عمیق در توده‌ی سفید بنشیند. پنیر نامی است که تنها به شیری داده می‌شود که عجله نکرده است."},"ICON-1541":{"nm":"کارگاه توفو","de":"لوبیا را خیس کن، آسیاب کن، بجوشان، و شیرِ خامِ لوبیا معطر می‌شود. یک قطره آب‌نمک، پراکنده‌ها را جمع می‌کند و توفوی نرم می‌سازد، و اگر آرام فشرده شود، گوشه‌های مربع می‌گیرد. اینجا دستی هست که دلِ پراکنده را آرام می‌کند و شکل می‌بخشد."},"ICON-1542":{"nm":"سکوی کوزه‌های سسِ تخمیری","de":"در گوشه‌ی آفتابگیرِ حیاط، کوزه‌های کوتاه کنار هم جمع‌اند و آفتاب می‌گیرند. درش را که برداری، بوی زمانِ کهنه ناگهان بیرون می‌زند. طعمِ سسی که مادربزرگ تخمیر کرده بود، در حقیقت خوردن سال‌ها به‌قاشق‌قاشق است."},"ICON-1543":{"nm":"آسیاب دستی","de":"با غرشِ سنگ‌ها که می‌چرخند، غله به آرد باز می‌شود. غبار سفید در نور آفتاب شناور است، و آنانی که می‌خواهند یک ظرف برنج‌کیک بسازند، نوبت خود را منتظرند. روزِ جشنِ روستا همیشه انگار از همین آستانه آغاز می‌شد."},"ICON-1544":{"nm":"نانوایی","de":"از لای در فر، بوی کره و شکر بیرون می‌زند. وقتی خمیرِ ورآمده طلایی می‌شود، قدم‌هایی که از جلوِ مغازه می‌گذرند ناخودآگاه کند می‌شوند. یک قرص نانِ تازه‌پخته، مهربانی‌ای دارد که هیچ‌کس تاب مقاومت در برابرش را ندارد."},"ICON-1545":{"nm":"چادر خوراکی‌فروشی","de":"چادرِ نایلونی در باد تکان می‌خورد و آبگوشتِ توک‌بوکی به‌آرامی جوشیده کم می‌شود. غروبی با سیخِ کیک ماهی و لاجرعه نوشیدنِ آبگوشت در لیوان کاغذی، جایی که سرما و گرسنگی را یک‌جا آب می‌کند. تسلایی کوچک در انتهای کوچه."},"ICON-1546":{"nm":"آشپزخانه‌ی غربی","de":"تابه داغ می‌شود و روغن زیتون جلز و ولز می‌کند. با یک تنظیمِ آتش، سس گاه غلیظ می‌شود و گاه می‌سوزد. اینجا که حتی توازنِ رنگ‌ها روی بشقاب هم سنجیده می‌شود، یک وعده غذا به نمایشی با دقت آراسته بدل می‌شود."},"ICON-1547":{"nm":"آشپزخانه‌ی چینی","de":"روی آتشی تند، ووک انگار در حال رقصیدن سریع می‌چرخد. در آن لحظه‌ی کوتاه که شعله‌ها زبانه می‌کشند، عطرِ مواد به‌تمامی محبوس می‌شود. سریع و داغ، رازِ آشپزیِ چینی در همان یک نفس نهفته که اگر مردد شوی از دستش می‌دهی."},"ICON-1548":{"nm":"کافه","de":"در را که هل بدهی، عطر دانه‌ی قهوه و موسیقیِ آرام پیش از هر چیز به استقبالت می‌آیند. صندلیِ کنار پنجره، یک فنجان لاته که سرد می‌شود، و دفترچه‌ای باز. برای اینکه در روزِ شلوغ لحظه‌ای نفس تازه کنی، شهر جاهایی کوچک مثل این را این‌سو و آن‌سو پنهان کرده است."},"ICON-1549":{"nm":"شیرینی‌فروشی","de":"در ویترین شیشه‌ای، کیک‌های رنگارنگ صف کشیده‌اند و منتظر مشتری‌اند. لحظه‌ای که نوکِ چنگال خامه را می‌شکافد، گوشه‌ی لب پیش از هر چیز بالا می‌رود. نسخه‌ای کوچک و شیرین که حتی در روزِ غمگین، با یک تکه، تحمل‌پذیر می‌شود."},"ICON-1550":{"nm":"قصابی","de":"زیر نورِ سرخ، گوشت مرتب در امتدادِ رگه‌هایش چیده شده. با یک جمله‌ی «امروز این خوب است»، چاقو با ضخامتی دقیق می‌لغزد. استحکامِ سفره‌ی شام، آرام از همین دستی آغاز می‌شود که هر روز همان جا را نگه می‌دارد."},"ICON-1551":{"nm":"میز کار دریایی","de":"میزی که بوی ماهی سپیده‌دم با سردیِ یخ درمی‌آمیزد. فلس‌ها می‌پرند و دست‌ها یخ می‌زنند، اما چشمی که تازه‌ترین را انتخاب می‌کند، هرگز باز نمی‌ایستد. چیزهایی که تازه از دریا بالا آمده‌اند، همین‌جا راهِ رسیدن به سفره را می‌یابند."},"ICON-1552":{"nm":"نمکزار","de":"آب دریا را که محبوس کنی، آفتاب و باد بقیه‌ی کار را انجام می‌دهند. چند روز منتظر بمان تا آب خشک شود، آنگاه بلورهای سفید مثل ستاره روی کف می‌رویند. یک مشت شوری، در حقیقت، هدیه‌ای است که دریا و آسمان با هم و به‌آرامی ساخته‌اند."},"ICON-1553":{"nm":"جای خشک‌کردن جلبک","de":"بر بندی بلند، خوارک دریایی و کلپ کنار هم آویزانند و در باد تاب می‌خورند. آن‌ها که آب دریا در خود دارند، هرچه خشک می‌شوند، به سبزِ عمیق‌تری می‌روند. لطیف‌ترین طعمِ دریا، ساخته‌ی مشترکِ آفتاب و نسیم شور، همین‌جا آویزان است."},"ICON-1554":{"nm":"اسکله‌ی کوچک","de":"تخته‌های چوبیِ نیمه‌غرق در آب، زیر پا سبک تاب می‌خورند. جایی درست‌اندازه برای بستنِ یک قایق کوچک. رفتن به دوردست و بازگشتنِ سالم، هر دو از همین یک بند آغاز و پایان می‌یابند."},"ICON-1555":{"nm":"انبار بندر","de":"درِ چوبیِ عطرگرفته از باد دریا را که بگشایی، تور و بشکه و طناب تا سقف انباشته‌اند. باری که راهیِ سفری دوردست است و باری که تازه رسیده، لحظه‌ای زیر یک سقف می‌مانند. جایی چون ایستگاهِ ترانزیت، که رفتن و بازگشتن لحظه‌ای از کنار هم می‌گذرند."},"ICON-1556":{"nm":"فانوس دریایی","de":"تنها هنگامی که دریای شب تاریک‌ترین حالتش را می‌گیرد، کارش آغاز می‌شود. نوری که می‌چرخد، مه را می‌شکافد و می‌گوید: «راهی این‌جاست.» نگهبانی بلندبالا که برای بازگشتِ سالمِ کسی، تا پایان به خواب نمی‌رود."},"ICON-1557":{"nm":"کارگاه کشتی‌سازی","de":"تیرِ کیل را بر پا کن و دنده‌ها را نصب کن، و اسکلتِ کشتی شکل می‌گیرد. در حیاطی که صدای چکش تمام روز طنین می‌اندازد، کشتی‌ای که هنوز طعمِ آب را نچشیده، رویای اولین سفرش را می‌بیند. جایی که پیش از رفتن، نخست استوار می‌شود."},"ICON-1558":{"nm":"اتاقک ضبط","de":"در که بسته شود، تمام صداهای بیرون در یک لحظه محو می‌شوند. تنها چیزی که از پشت هدفون شنیده می‌شود، صدای نفس و ریتم خودت است. در سکوتِ این اتاقِ کوچک، صدایی که می‌تواند آزادانه بلرزد، سرانجام زاده می‌شود."},"ICON-1559":{"nm":"اتاق موسیقی","de":"هارمونی‌ای که از لای در بیرون می‌زند، راهرو را پر می‌کند. یکی گام‌ها را دنبال می‌کند، یکی ریتم می‌شمارد. جایی که صداهای ناشی و صداهای پخته می‌توانند در هم بیامیزند، کلاسی مهربان که هر آوازی نخستین قدمش را در آن برمی‌دارد."},"ICON-1560":{"nm":"اتاق پیانو","de":"درِ کلاویه را که بگشایی، لایه‌ای نازک از غبار روی کلیدهای سفید نشسته. لحظه‌ای که انگشت آن‌ها را لمس می‌کند، طنینی زلال تمام اتاق را پر می‌کند. اگر شب‌هایی هست که حتی تنها بودن هم تنهایی نیست، احتمالاً به‌خاطر همین یک پیانوست."},"ICON-1561":{"nm":"اتاق رقص","de":"نوکِ پا را که فشار دهی، کف زیرِ پا دوباره تو را بالا می‌راند. تا آینه‌های چهار دیوار همان حرکت را چهار بار تکرار کنند، بدن نیم‌ضرب زودتر از ریتم، کورئوگرافی را از بر می‌کند. اتاقی که عرق و نفس بیشترین مدت را در آن می‌مانند؛ حرکتی که این‌جا رشد کرده، به روی صحنه قدم می‌گذارد."},"ICON-1562":{"nm":"اتاق بدنسازی","de":"وزن دروغ نمی‌گوید. به‌خاطر همین صداقت که دقیقاً به اندازه‌ی آنچه بلند می‌کنی به شانه‌هایت واریز می‌شود، مردم هر سپیده‌دم سراغم می‌آیند. آنچه آرام‌آرام در آینه حک می‌شود عضله نیست، بلکه ساعت‌هایی است که بی‌تسلیم دوام آورده‌ای."},"ICON-1563":{"nm":"اتاق یوگا","de":"نفس را عمیق که فرو ببری، حس می‌کنی کفِ چوبی هم همراهت باد می‌کند. اتاقی که روزی را که با شتاب دویده تا این‌جا رسیده، به‌آرامی تا می‌زند؛ روی یک تشک، هرکسی به سرعتِ نفسِ خودش بازمی‌گردد. حتی دلِ شتاب‌زده هم این‌جا لحظه‌ای زمین گذاشته می‌شود."},"ICON-1564":{"nm":"اتاق گریم","de":"درست پیش از قدم گذاشتن به صحنه، آدم‌ها این‌جا لحظه‌ای کسی دیگر می‌شوند. وقتی لامپ‌های دورِ آینه صورت را یکدست گرم می‌کنند، لرزش به نوکِ پوکده‌ی پودر می‌چسبد و آرام پشت یقه پنهان می‌شود. جایی که دگرگونی آغاز و هم پایان می‌یابد."},"ICON-1565":{"nm":"اتاق لباس","de":"تا یک دست لباسِ صحنه کامل شود، لباس‌های آویزان این‌جا ده‌ها بار پوشیده و درآورده می‌شوند. مانکنی که با سنجاق‌های موقت می‌چرخد، خطِ درزی کشیده با گچ. پشتِ درخشش، همیشه ردِ سوزنِ دستِ کسی بر جای می‌ماند."},"ICON-1566":{"nm":"صحنه‌ی استودیو","de":"زود آموختم که کافی است فقط طرفی که دوربین نشان می‌دهد واقعی به نظر برسد. پشتِ تخته‌سه‌لا که بروی، تنها اسکلتی خالی است. آنچه شکوهِ روبه‌رو را بی‌صدا نگه می‌دارد، همیشه بر عهده‌ی چوب‌های نامرئی است."},"ICON-1567":{"nm":"استودیوی عکاسی","de":"نخستین راز، انداختنِ نور از سه جهت برای پاک کردنِ سایه‌هاست. نورِ اصلی چهره را نمایان می‌کند، نورِ کمکی سایه را، نورِ پشت نوکِ موها را زنده می‌کند. در همان لحظه‌ای که شاتر می‌افتد، یک زمینه‌ی سفید بهترین لبخندِ امروز را به دام می‌اندازد."},"ICON-1568":{"nm":"سالن کنسرت","de":"در تاریکیِ سقف‌بلند، همیشه همان یک عهد را در دل دارم: که وقتی پرده بالا برود، حتی صندلی‌های خالی هم چون یک تن نفس در سینه حبس می‌کنند. برای همان یک لحظه که ضربِ اول فرود می‌آید، من تمام سال، آرام و خالی می‌ایستم."},"ICON-1569":{"nm":"غرفه‌ی ملاقات با هواداران","de":"فاصله‌ی میان دست و دست، دقیقاً به اندازه‌ی یک میز است. یک سلامِ کوتاه، یک امضای لرزان، حرفی که سرانجام گفته نشد، پشتِ سرِ هم می‌گذرند. در این غرفه‌ی کوچک، دلی که مدت‌ها پرورده شده، نخستین بار رودررو می‌شود."},"ICON-1570":{"nm":"تخت‌خواب","de":"همیشه من نخستین کسی بودم که پایانِ روز را می‌پذیرفت. وقتی پاهای سنگین از تمرین و لرزشِ باقی‌مانده از پشتِ صحنه همه فروکش کنند، صبح دوباره با نوکِ پای سبک آغاز می‌شود. شب‌بخیر می‌گویم و بی‌کلام در آغوشت می‌گیرم."},"ICON-1571":{"nm":"تخت دوطبقه","de":"میان طبقه‌ی بالا و پایین، پنج پله‌ی نردبان دو نفر را به هم می‌پیوندد. صدای آرامِ گفتگو پس از خاموش کردنِ چراغ، ستاره‌های شب‌نمای چسبیده به سقف. اتاق کوچک، وسیع‌ترین می‌شود، به‌لطفِ داستان‌هایی که هر شب از نردبان بالا و پایین می‌روند."},"ICON-1572":{"nm":"قفسه","de":"آنچه رویش بگذاری، آدم را نشان می‌دهد. نامه‌ای که رسیده، اولین جام، بلیط ورودیِ رنگ‌باخته، کنار هم صف کشیده‌اند. من مبلی نیستم که فخرفروشی کند، بلکه جایی‌ام که خاطراتی را که کسی نتوانسته دور بریزد، آرام به نمایش می‌گذارد."},"ICON-1573":{"nm":"میز تحریر","de":"با دفترچه‌ی متن‌های آواز باز، روی خطوطِ پاک‌شده دوباره خطی تازه کشیده می‌شود. لیوان‌های کاغذیِ انباشته در طول شب و یک خطِ آهنگ که به‌سختی نجات یافته. کارِ کند و آرامِ انتقال دل به کلمات، همیشه بی‌صدا روی همین سطحِ صاف رخ می‌دهد."},"ICON-1574":{"nm":"صندلی","de":"«لحظه‌ای بنشین» جمله‌ای است که به‌طرزی غافلگیرکننده مهربان است. هرچه جلسه طولانی شود یا تمرین کش بیاید، پشتی بی‌صدا وزنِ آدم را می‌پذیرد. من می‌دانم هرکه بیشتر ایستاده باشد، بیشتر به من خوش‌آمد می‌گوید."},"ICON-1575":{"nm":"مبل","de":"برای تبدیل کردنِ اقامتگاهِ نیمه‌شب به یک اتاق نشیمن، فقط من کافی‌ام. همه کنار هم فشرده بنشینید و برنامه‌ی سرگرمی تماشا کنید، پیش از آنکه بفهمید یکی تکیه به دسته‌ی مبل خواب رفته است. صندلیِ میانیِ فرورفته، گرمای همان خانه را ثابت می‌کند."},"ICON-1576":{"nm":"میز","de":"دورش که بنشینند، دیگر هیچ‌کس صدرنشین نیست. خورشتِ تازه‌جوش و صدای برخوردِ قاشق‌ها، اتفاقاتِ امروز به مرکز جمع می‌شوند. وقتی یک سطحِ گرد پهن می‌شود، حتی روزی که پراکنده بود هم دوباره یک‌جا می‌نشیند."},"ICON-1577":{"nm":"کمد لباس","de":"هر بار فصل عوض می‌شود، از درون داستان‌های کهنه بیرون می‌ریزد. لباس صحنه و لباس روزمره شانه‌به‌شانه، پشتِ درِ بسته لباس‌ها منتظر نوبت بعدی‌شان‌اند. تنها با گشودنِ در است که سرانجام روزِ امروز چه بپوشی معین می‌شود."},"ICON-1578":{"nm":"آینه","de":"تعریف و عیب را با همان صداقت بازمی‌گردانم. جایی برای آخرین بازبینی پیش از رفتن به صحنه؛ آدم‌ها روبه‌رویم حالت چهره را می‌آرایند و قامت را راست می‌کنند. صادق‌ترین دوست هرگز حتی یک کلمه هم نمی‌گوید."},"ICON-1579":{"nm":"میز آرایش","de":"در هر کشوی کوچک، چهره‌ای دیگر خفته است. یک قوطی برای صحنه، یک قوطی برای روزمره، یک قوطیِ محدود که کنار گذاشته‌ام. جلوی آینه که بنشینی، آرام‌آرام تصمیم می‌گیری امروز چه کسی می‌شوی و از در بیرون می‌روی."},"ICON-1580":{"nm":"قالیچه","de":"لمسی که پای برهنه نخست حس می‌کند، دمای اتاق را تعیین می‌کند. ردِ دورهم‌نشستن و خوردنِ تنقلات و غلتیدن، پرزی به‌جا می‌ماند. مبلی که از پایین‌ترین جا کار می‌کند، کفِ سرد را یک وجب گرم‌تر می‌کند."},"ICON-1581":{"nm":"پرده","de":"چقدر صبح را راه بدهم، من تصمیم می‌گیرم. کمی که کنار بروم، آفتاب دراز به درون می‌آید؛ محکم که بسته شوم، حتی خواب ماندنِ زیاد هم بخشوده می‌شود. ایستادن میان پنجره و اتاق و تنظیمِ آرامِ مقدارِ نور، همیشه سهمی است سپرده‌شده به من."},"ICON-1582":{"nm":"چراغ","de":"همان اتاق، بسته به رنگِ نور، زمانِ کاملاً دیگری می‌شود. نورِ زرد شب را دراز می‌کند، نورِ سفید سپیده‌دم را واضح بیدار می‌کند. جادوگری به‌اندازه‌ی کف دست، که با یک کلید، حال‌وهوای روز را زیرکانه دگرگون می‌کند."},"ICON-1583":{"nm":"ساعت دیواری","de":"صدای عقربه‌ی ثانیه‌شمار تنها در اتاقی ساکت شنیده می‌شود. هرچه تمرین عمیق‌تر شود، مرا فراموش می‌کنی، و ناگهان که سر بلند کنی، بیرونِ پنجره از قبل سپیده‌دم شده. بی‌آنکه زمانِ گذشته را سرزنش کند، فقط بی‌صدا به خانه‌ی بعدی اشاره می‌کند."},"ICON-1584":{"nm":"گلدان","de":"حتی وقتی گل پژمرده شود، جایش را خالی نمی‌گذارم. ظرفی که دلی هدیه‌شده را لحظه‌ای نگه می‌دارد؛ تا دستی هست که آب را عوض کند، سفره روشن می‌ماند. حتی وقتی خالی‌ام، به شکلِ کسی که منتظرِ کسی‌ست می‌ایستم."},"ICON-1585":{"nm":"قاب پوستر","de":"حتی آویختنِ چهره‌ای دوست‌داشتنی روی دیوار هم دقت می‌طلبد. جایی که آفتاب مستقیم به آن نمی‌رسد، یک میخِ کاملاً افقی. برگه‌ای که آرام پشتِ شیشه خوابانده شده، هر صبح نخستین کسی‌ست که به من که وارد اتاق می‌شوم سلام می‌دهد."},"ICON-1586":{"nm":"تخته‌ی فوتوکارت","de":"اینکه بر اساس الفبا بچینم یا بر اساس ترتیب انتشار، همان دودلیِ شیرین آغازِ طرفداری است. یک خانه‌ی خالی، جای بایاسی است که هنوز نیافته‌ام. هرچه یک‌به‌یک کارت‌ها پر شود، تخته به تاریخ‌نگاریِ کوچکِ خودم بدل می‌شود."},"ICON-1587":{"nm":"پایه‌ی چوب نورانی","de":"باتری را دربیاور، دسته را رو به بالا. حتی در زاویه‌ای که کج تکیه‌اش می‌دهی، مهارتی نهفته است. در انتظارِ فریادِ بعدی، چوب همین‌جا نورش را خاموش می‌کند و تنش را مرتب می‌خواباند. خوب که استراحت کند، روشن‌تر می‌درخشد."},"ICON-1588":{"nm":"قفسه‌ی جام‌ها","de":"در صفِ جلو، کهنه‌ترین را می‌گذارند. از مجسمه‌ی کوچکِ یک مسابقه تا جامِ صحنه‌ای بزرگ، نه بر اساس قد، بلکه بر اساس ترتیبِ دل صف می‌کشند. هر بار که پاکشان می‌کنم، لرزشِ همان روز روی صحنه دوباره به نوکِ انگشتانم می‌نشیند."},"ICON-1589":{"nm":"سبد پیک‌نیک","de":"درش را که برداری، بوی آفتابِ بهاری پیش از هر چیز بیرون می‌زند. گیم‌باپ و فلاسک و یک زیرانداز، مرتب روی هم چیده شده، آماده‌ی رفتن به دشت. قدم‌های کسی که مرا حمل می‌کند، همیشه انگار یک وجب از حالتِ معمول سبک‌تر می‌شود."},"ICON-1590":{"nm":"گلدان کوچک","de":"یک وجب طاقچه‌ی پنجره برایم کافی‌ست. سبزِ کوچکی که حتی وقتی مکرر فراموش می‌شوی آبش بدهی، بزرگوارانه تاب می‌آورد. در گوشه‌ی میزِ آدمی شلوغ، هر روز یک برگِ بیشتر می‌گشایم و بی‌صدا حالِ امروز را می‌پرسم."},"ICON-1591":{"nm":"گلدان بزرگ","de":"تا قدِ من رشد می‌کند، آدم هم همراهم رشد می‌کند. وقتی برگ‌های پهنی که گوشه‌ای از نشیمن را گرفته‌اند آفتاب می‌گیرند و سایه می‌اندازند، فصل هم آرام به درون اتاق می‌آید. پاداشی که تنها کسی می‌داند که فراموش نمی‌کند آب بدهد."},"ICON-1592":{"nm":"مجموعه شمع معطر","de":"لحظه‌ای که فتیله را روشن می‌کنی، هوای اتاق یک پله فرو می‌نشیند. عطر آرام‌آرام می‌پراکند و خستگیِ باقی‌مانده‌ی دیروز را گرم کرده بیرون می‌فرستد. با یک شعله‌ی کوچک، پایانِ روزِ شلوغ چون آیینی آرام به سرانجام می‌رسد."},"ICON-1593":{"nm":"یخچال کوچک","de":"در را که نیمه‌شب باز کنی، یک قوطی نوشیدنیِ سرد به استقبالم می‌آید. وزوزِ آرامِ لرزشِ کوچک، اقامتگاهِ خالی را کمی کمتر تنها می‌کند. خانه‌داریِ بزرگ از دستم برنمی‌آید، اما برای برعهده گرفتنِ سپیده‌دمِ گرسنه، چیزی به‌پایِ من نمی‌رسد."},"ICON-1594":{"nm":"کلاه تور حشره‌گیری","de":"لحظه‌ای که روی سر می‌گذاری، دشتِ تابستان روی شانه‌هایت همراهت می‌آید. توری گرد، آفتاب را نرم صاف می‌کند، و با هر قدم بوی علف آرام تاب می‌خورد. کلاهی که حتی اگر یک سنجاقک هم نگیری، خوب است، چون تمام یک فصل را دور سرت می‌پیچد."},"ICON-1595":{"nm":"کیسه‌ی تور جمع‌آوری","de":"به کمر آویخته می‌شود و همراهِ جمع‌آوری می‌شود. دهانه را کمی که تنگ کنی، آنچه گرفته‌ای دیگر فرار نمی‌کند—نخستین نکته‌ای که در دشت آموختم. یک کیسه‌ی پارچه‌ایِ سبک، برداشتِ یک‌روزه را محکم در آغوش می‌گیرد."},"ICON-1596":{"nm":"شیشه‌ی مشاهده‌ی حشرات","de":"می‌دانم برای مهمانی که فقط لحظه‌ای می‌ماند، سوراخِ هوا از همه چیز مهم‌تر است. راهِ نفسِ کوچکی که در در سوراخ شده، یک برگ علف پهن‌شده روی کف. تا وقتی مشاهده تمام شود و او را دوباره به بوته‌زار بازگردانی، این یک جفت کامل می‌شود."},"ICON-1597":{"nm":"قوطی سنجاق نمونه","de":"حتی در همان یک زاویه‌ی کج فرو بردنِ سنجاق، مهارتی زندگی می‌کند. اگر خیلی عمیق باشد می‌شکند، اگر کم‌عمق باشد می‌لرزد، پس باید نیروی نوکِ انگشت را دقیق تقسیم کرد. قوطی‌ای که بی‌صدا دلسوزیِ کسی را در خود جای می‌دهد که می‌خواهد به یک زندگیِ کوچک، طولانی خیره شود."},"ICON-1598":{"nm":"درِ تراریوم","de":"نگهبانیِ مرزِ میان درون و بیرون، وظیفه‌ی من است. اگر خیلی محکم بسته شود خفه می‌شود، اگر خیلی شل رها شود راه گم می‌کند، پس همیشه شکافی مثل یک خط مورب باقی می‌گذارم. محافظت کردن، آشکارا با محبوس کردن فرق دارد."},"ICON-1599":{"nm":"بشقاب غذای پروانه","de":"پنبه‌ی آغشته به آب‌شکر را وسط بگذار، و بال‌ها گرد هم می‌آیند. راز این است: کم‌عمق و پهن، به عمقی که پاهای کوچک در آن فرو نروند. یک بشقاب، بی‌صدا مهمانانی را که لحظه‌ای در باغی آفتابی توقف می‌کنند، گرد هم فرا می‌خواند."},"ICON-1600":{"nm":"چراغ جذب حشرات","de":"در تاریکی که کم‌نور روشنش بگذاری، بال‌های کوچک به دنبال نور جمع می‌شوند. روشنایی ملایم، جا دور از آدم‌ها. دعوت‌گری بی‌نهایت مهربان، که شبِ تابستانِ پر از وزوز را کمی آرام‌تر می‌نشاند."},"ICON-1601":{"nm":"برچسب حشره","de":"شش پا و یک جفت شاخک؛ درون تکه‌ای کاغذ به اندازه‌ی ناخن، یک زندگی کوچک به خواب رفته است. اگر آن را آرام به گوشه‌ی دفترچه بچسبانی، میان صفحات، یک وجب چمن‌زار بی‌صدا باز می‌شود."},"ICON-1602":{"nm":"برچسب مجوز جمع‌آوری","de":"پیش از برداشتن تور حشره‌گیری، بزرگ‌تر اول می‌پرسد: چند تا، و تا کجا؟ همین یک برچسب کوچک، مرزی مهربان میان کنجکاوی هیجان‌زده و وعده‌ای که باید نگه داشت می‌کشد."},"ICON-1603":{"nm":"قوطی طعمه","de":"درِ قوطی که باز می‌شود، بوی تند و خنکِ سحرگاه بالا می‌آید. شاید این طعمه نیست که ماهی را صدا می‌زند، بلکه دلی است که بلد است آرام صبر کند تا شناور بلرزد."},"ICON-1604":{"nm":"جعبه‌ی شناور ماهیگیری","de":"کمدی کوچک که شناورهای رنگارنگ، خانه به خانه در آن خوابیده‌اند. بعضی برای صبحِ دریاچه‌ای آرام‌اند، بعضی برای ظهرِ جریانی خروشان. برای هر حالتِ آب، جفتِ مناسبش تاخورده و مرتب کنار گذاشته شده است."},"ICON-1605":{"nm":"قرقره‌ی نخ ماهیگیری","de":"نخِ باز شده را دور انگشت نپیچ. اگر آن را با نظم روی این ابزار گرد باز پیچی کنی، گره‌ها هم آرام‌آرام باز می‌شوند. این کار شبیه دستی است که روزی شل‌شده و رها را دوباره مرتب می‌کند."},"ICON-1606":{"nm":"قلاب‌بازکن","de":"فقط کسی که یک‌بار با دست خالی قلابِ گیرکرده را بیرون کشیده و سوزشش را چشیده، این ابزار را می‌شناسد. راهی که هم برای آن موجود کوچک و هم برای نوک انگشتانم، درد کمتری دارد. ملاحظه همیشه از همین جزئیات کوچک آغاز می‌شود."},"ICON-1607":{"nm":"روکش بیل صدف‌جویی","de":"لایه‌ای که تیغه‌ی بیلِ تازه از گِل‌ولای درآمده را در بر می‌گیرد. تا گل و آب شور لبه‌اش را نخورد، میان دریا و ابزار، استراحتی نازک و نرم را آرام جای می‌دهد."},"ICON-1608":{"nm":"کارت جدول جزر و مد","de":"اینکه آب چه زمانی بالا می‌آید و چه زمانی پایین می‌رود را، کارتی به اندازه‌ی کف دست بی‌صدا می‌گوید. تقویمی کوچک که انسان از وعده‌ی قدیمیِ ماه و دریا رونویسی کرده است."},"ICON-1609":{"nm":"برس تمیزکاری آکواریوم","de":"اگر خزه‌ی سبزِ نشسته بر دیواره‌ی شیشه‌ای را آرام بروبی، نور دوباره به دنیای کوچکِ زیرِ آب نفوذ می‌کند. روشن‌کردنِ روزِ کسی، معمولاً همین‌قدر بی‌صدا جریان دارد."},"ICON-1610":{"nm":"چیپ دماسنج آکواریوم","de":"عددی چشمک می‌زند و وقتی روی درجه‌ی درست می‌ایستد، ماهی‌ها بالاخره آسوده می‌شوند. گرمایی در یک خانه، نه چندان سرد و نه چندان داغ. مراقبت حتی به جاهای دیده‌نشده هم می‌رسد."},"ICON-1611":{"nm":"لوله‌ی مشاهده‌ی جانداران دریایی","de":"مهمانی کوچک که مدتی کوتاه در این لوله‌ی شفاف می‌ماند. باله‌ی پشتی‌اش را آرام می‌شماری و دوباره به دریا بازش می‌گردانی. مشاهده یعنی تصاحب نکردن، بلکه لحظه‌ای قرض گرفتن."},"ICON-1612":{"nm":"برس فسیل","de":"آنچه رگه‌های سنگِ ده‌ها میلیون سال به خواب رفته را بیدار می‌کند، چکش نیست، نوکِ نرمِ یک برس است. پیشِ‌روی زمانی که با شتاب خرد می‌شود، دقت عمیق‌ترین ادب می‌شود."},"ICON-1613":{"nm":"کلاهک قلم‌موی حفاری","de":"وقتی نوکِ قلم‌مو خشک شود، خاک هم دیگر تمیز جدا نمی‌شود. کلاهکی کوچک، نفسِ قلم‌مو را مرطوب نگه می‌دارد. دستی که ابزارش را عزیز می‌دارد، اولین قدمِ کاوش را برمی‌دارد."},"ICON-1614":{"nm":"صفحه‌ی نمونه‌ی لایه‌های زمین","de":"در یک وجب خاک، صدها سال لایه‌لایه روی هم چیده شده‌اند. اگر آرام بر این صفحه برداری، نقش‌های زمانی که تا امروز دیده نمی‌شدند، خط می‌کشند و آهسته پدیدار می‌شوند."},"ICON-1615":{"nm":"سینی قطعات استخوان","de":"اگر تکه‌های پراکنده را خانه‌به‌خانه بخوابانی، زندگی‌ای که زمانی در باد پراکنده شده بود، آرام‌آرام راهِ بازگشت به جای خود را می‌جوید. بازسازی یعنی مهربانانه پرسیدنِ دوباره‌ی نظمی گم‌شده."},"ICON-1616":{"nm":"نوار بازسازی","de":"نواری نازک که جای شکسته را به هم می‌پیوندد. زخم را پنهان نمی‌کند، بلکه مهربانانه در آغوش می‌گیرد و نگه می‌دارد. آرام ثابت می‌کند که حتی چیزِ شکسته هم می‌تواند دوباره کامل شود."},"ICON-1617":{"nm":"روکش تابلوی نمایشگاه","de":"ورقه‌ای که آرام روی برچسبِ پشتِ شیشه را می‌پوشاند تا رنگ نبازد. در آن این آرزو نهفته که آن جمله‌ی کوتاه از اینکه چه کسی، کجا زیسته، تا سال‌های دور هم واضح خوانده شود."},"ICON-1618":{"nm":"برچسب مخزن نگهداری","de":"اتاقی عمیق که گنجینه‌هایی که هرگز پا به روشنایی نگذاشته‌اند، در آن خفته‌اند. هرچیزی درون آن، برچسب نامی کوچک به گردن دارد؛ تا حتی بی‌آنکه در جایی روشن بایستد، هرگز فراموش نشود."},"ICON-1619":{"nm":"پاکت اهدای موزه","de":"کسی حاصل عمرش را بی‌کلامی تقدیم می‌کند. آنچه در این پاکت جای گرفته شیء نیست، بلکه دلی است که سال‌ها در آغوش داشته. بخشش، طولانی‌ترین نمایشگاهی می‌شود که بر کسی می‌درخشد."},"ICON-1620":{"nm":"چیپ شماره‌ی نمونه","de":"درست همان‌جا که چیزی را جمع کرده‌ای، عددی کوچک را آرام به آن می‌دهی. کِی، کجا، برای اولین بار دیدیش. کشفی که نوشته نشود، به‌زودی مثل مهِ صبحگاهی پراکنده می‌شود."},"ICON-1621":{"nm":"بطری تکه‌ی شهاب","de":"تکه‌ای که آسمانِ شب را شکافته و افتاده، درون بطری شیشه‌ای به دام افتاده است. پرتوی نوری که پیش از فرصتِ آرزو کردن محو شد، اکنون در کف دست، آرام‌آرام دوباره می‌درخشد."},"ICON-1622":{"nm":"بند زنگوله‌ی صدفی","de":"صدف‌هایی را که یکی‌یکی از ساحل جمع کرده‌ای به نخ می‌کشی و از لبه‌ی بام می‌آویزی. هر بار که باد می‌گذرد، با صدای ریزِ خش‌خش، دریای همان تابستان آرام تا داخل خانه دنبالت می‌آید."},"ICON-1623":{"nm":"قطره‌ی شبنم رنگین‌کمان","de":"قطره‌ای که بعد از باران، روی نوکِ برگ حلقه بسته است. درون همان دایره‌ی کوچک، تمام آسمان و هفت رنگ گرد جای گرفته‌اند. گاهی کوچک‌ترین چیز، وسیع‌ترین منظره را در خود دارد."},"ICON-1624":{"nm":"بطری جمع‌آوری مه","de":"بطری‌ای پر از مهِ سحرگاهیِ دامنه‌ی کوه را با خودم آورده‌ام. اگر در دست بگیریش، خنک می‌شود و شیری‌رنگ کدر می‌گردد. طمعی کوچک و مهربان برای نگه‌داشتنِ لحظه‌ای، کنارِ خود، چیزی که نمی‌شود گرفتش."},"ICON-1625":{"nm":"فنجان شبنم‌گیر","de":"فنجانی کوچک که شبنمی را که تیغه‌های چمن قطره‌قطره در طول شب جمع کرده‌اند، می‌گیرد. حتی یک جرعه هم نمی‌شود، اما پاک‌ترین و زلال‌ترین بخشِ صبح، آرام در آن نشسته است."},"ICON-1626":{"nm":"سنجاق روبان نسیم","de":"روبانی که درست از روی رگه‌ای که باد از خود بر جا گذاشته، بسته شده است. اگر به مو بزنی، با هر قدم، نسیمی ملایم آرام‌آرام دنبالت می‌آید. سبکیِ روزی بهاری، آرام در یک سنجاق گره خورده است."},"ICON-1627":{"nm":"کپسول صدای موج","de":"اگر آرام کنار گوش بگیریش، موج‌های دریای دور به سراغت می‌آیند. انگار کسی همان صدایی را که در کودکی در صدفِ حلزون نگه می‌داشتیم، در دانه‌ای کوچک با دقت مهر و موم کرده باشد."},"ICON-1628":{"nm":"تکه‌ی ستاره‌ی شنی","de":"اگر در ساحلِ شب، مشتی شن برداری، خرده‌ستاره‌هایی درونش می‌درخشند. اینکه از آسمان افتاده‌اند یا موج‌ها آن‌ها را نرم ساییده‌اند، هیچ‌کس زحمتِ پرسیدن به خود نمی‌دهد."},"ICON-1629":{"nm":"چیپ ثبت آب‌وهوای جزیره","de":"آسمانِ جزیره روزی چند بار نظرش را عوض می‌کند. اگر آفتاب، مه و رگبار را با نظم روی چیپی کوچک ثبت کنی، می‌توانی آسمانِ دیروز را امروز دوباره باز کنی."},"ICON-1630":{"nm":"کیت پلکانِ صخره","de":"یک پله، و باز یک پله، برای بالا و پایین رفتن از شیبِ تند. اگر قطعاتِ پراکنده را کنار هم بگذاری، حتی صخره هم مسیری برای قدم‌زدنِ آرام می‌شود. راه ساختن یعنی از پیش، قدمِ بعدیِ کسی را جا گذاشتن."},"ICON-1631":{"nm":"رول طرح جاده‌ی خاکی","de":"رولی که درست رگه‌ی جاده‌ای خاکی و نرم را بازتاب می‌دهد. اگر آرام بازش کنی، کوره‌راهی روستایی که آدم را به پابرهنه راه رفتن ترغیب می‌کند، آرام زیر پایت پهن می‌شود."},"ICON-1632":{"nm":"چیپ طرح جاده‌ی سنگی","de":"نقشِ سنگ‌فرش‌هایی که زمانی کوچه‌های قدیمی را می‌پوشاندند، سالم درونِ چیپی کوچک جای گرفته است. با هر قدم، تق‌تق، صدای پای دهکده‌ای کهن دوباره در نوک انگشتانِ پا زنده می‌شود."},"ICON-1633":{"nm":"تکه‌ی نرده‌ی ساحلی","de":"قطعه‌ای از نرده‌ی کوتاهی که روی شن برپا شده تا موج نتواند بگذرد. نگهبانِ مرزیِ کوچک و ساکت که میان دریا و شن، خطی مهربان می‌کشد و می‌ایستد."},"ICON-1634":{"nm":"وصله‌ی ترمیم چمن","de":"تکه‌ای سبز که آرام روی جای لگدمال و برهنه گذاشته می‌شود. چند روز بعد، علف‌ها دستِ هم را می‌گیرند و جای خالی را پر می‌کنند. طبیعت همیشه راهِ خودالتیامی را بلد است."},"ICON-1635":{"nm":"میخ نشانه‌ی مسیر آب","de":"میخی که از پیش، مسیری را که آب باید در آن جاری شود نشان می‌دهد. تا آبِ باران سرگردان نماند و نداند کجا برود، نشانه‌ای کوچک که در زمین کوبیده شده، حتی روزهای بارانی هم بی‌صدا سرِ جایش می‌ایستد."},"ICON-1636":{"nm":"قطعه‌ی پل کوچک","de":"تکه‌ای از پلی کوچک که دو کرانه‌ی نهر را به هم می‌پیوندد. میان این‌سو و آن‌سو، وعده‌ی اینکه هر زمان بشود عبور کرد، آرام از همین یک قطعه‌ی کوچک آغاز می‌شود."},"ICON-1637":{"nm":"کلاهک نرده‌ی سکوی دیدبانی","de":"در بلندترین نقطه‌ی جزیره، قطعه‌ی پایانی‌ای که انتهای آن نرده را می‌پوشاند. جایی را که دستِ کسانی که برای نگاه به دوردست جمع شده‌اند، بیشترین لمس را دارد، آرام نگه می‌دارد و از آن محافظت می‌کند."},"ICON-1638":{"nm":"پایه‌ی آتش کمپ","de":"پیش از گذاشتنِ هیزم، جایگاهی که مانعِ پراکنده‌شدنِ جرقه‌ها می‌شود. شب‌هایی که بالای آن، زیرِ نگاهِ ستاره‌ها، گپ‌و‌گفتِ آرام جریان داشت، برای مدتی طولانی گرم شعله می‌کشند."},"ICON-1639":{"nm":"رول نمونه‌ی کاغذدیواری","de":"حال‌وهوای اتاق از یک دیوار آغاز می‌شود. باز کردنِ رولی کوچک برای انتخابِ رنگ، یعنی از پیش، آرام ترسیم کردنِ اینکه از این پس، چه روزهایی می‌خواهی زندگی کنی."},"ICON-1640":{"nm":"چیپ نمونه‌ی کف‌پوش","de":"با نوکِ انگشت، پیش از هر چیز، حسِ کفی را که پای برهنه لمسش خواهد کرد می‌سنجی. گرم است یا خنک؟ به همین یک چیپ کوچک، آرامشِ روزهایی که از این پس زندگی خواهی کرد آویزان است."},"ICON-1641":{"nm":"ست قلاب سقفی","de":"لحظه‌ای که قلابی به تیرِ سقف آویزان می‌کنی، سقفِ خالی جایی می‌شود که منتظرِ کسی است. زنگوله‌ی بادی یا گلدان؟ این قلابِ آهنیِ کوچک وزن را تحمل می‌کند، اما اینکه چه چیز آویزان شود را، دلِ ساکن‌اش تعیین می‌کند."},"ICON-1642":{"nm":"فیلم پوششیِ پنجره","de":"نورِ ظهر آن‌قدر صریح است که لایه‌ای نازک روی پنجره می‌کشی. آفتاب همان‌طور که هست وارد می‌شود، اما لبه‌ها نرم می‌شوند و هر چیز درونِ اتاق به رنگِ زردآلوییِ ملایم درمی‌آید. این پوشاندن نیست، بلکه مهربانانه پخش‌کردنِ نور است."},"ICON-1643":{"nm":"روکش زنگ در","de":"با این توجیه که حتی زنگی که مهمان فشار می‌دهد لباس لازم دارد، کسی روکشی گرد بر آن پوشانده. باران را دور نگه می‌دارد، گرد و غبار را هم، و از همه مهم‌تر، اولین دهانِ گرد و کوچکی است که پیامِ «اینجا کسی زندگی می‌کند» را می‌رساند."},"ICON-1644":{"nm":"پایه‌ی دفتر یادبود","de":"پایه‌ای که برپا شده تا هرکس می‌آید، نامش را بنویسد و برود. پیش از خشک‌شدنِ جوهر، از نوکِ قلم، سطری از احوال‌پرسی جاری می‌شود. وقتی قدم‌های رفته‌آمده سطر به سطر روی هم انباشته شوند، دفترچه‌ی خالی، بی‌آنکه بفهمی، ضخیم‌ترین آلبومِ این خانه می‌شود."},"ICON-1645":{"nm":"سنجاق چیدمان مبلمان","de":"جای میزی را که مدام میان جابه‌جا کردن و نکردن مردد بودی، سنجاقی با یک ضربه در کف می‌کوبد و تعیین می‌کند. میخی کوچک که آرام پای مبلمان را نگه می‌دارد. کفِ چوبی آرام سر تکان می‌دهد که جایی وقتی یک‌بار مشخص شود، دلبستگی می‌آورد."},"ICON-1646":{"nm":"قاب برچسب انبار","de":"کشو هرگز نمی‌تواند بگوید چه چیزی کجاست. پس برچسبی در قابی چهارگوش جای می‌گیرد تا به‌جایش سخن بگوید. لحظه‌ای که برچسبی سرِ جایش بنشیند، خانه‌های به‌هم‌ریخته نامِ خود را باز می‌یابند و آرام می‌گیرند."},"ICON-1647":{"nm":"چوب معطرکننده‌ی اتاق","de":"عطری که نوکِ چوب را خیس کرده، آرام‌آرام به بالا پخش می‌شود. یک لحظه لاوندر است، یک لحظه چمنزاری بعد از باران. وقتی رشته‌ای نامرئی از بو، هوای اتاق را عوض می‌کند، خستگیِ یک روزِ کامل از شانه‌های کسی که به خانه بازگشته آرام رها می‌شود."},"ICON-1648":{"nm":"گیره‌ی پاکت بذر","de":"بذرهایی که در بهار خریده بودی و کاملاً کاشته نشدند، همراه با پاکتشان محکم با یک گیره بسته می‌شوند. چون اگر حتی یک دانه هم بیرون بریزد، فصلِ بعد یک ردیف کوتاه‌تر می‌شود. درونِ این قفلِ کوچک، باغچه‌ی سالِ بعد به‌طور کامل خفته است."},"ICON-1649":{"nm":"سینی نشاء","de":"هر خانه را با خاک پر می‌کنی تا اولین اتاقِ جوانه‌ای تازه بسازی. در هر سوراخ یک زندگی، دانش‌آموزانی تازه که کنار هم، صف به صف رشد می‌کنند. اگر نگاه کنی، صبحی که سبزی‌ها گروه‌گروه حضور و غیاب می‌شوند، هر روز دوباره روی این سینی از نو آغاز می‌شود."},"ICON-1650":{"nm":"سنجاق نشانه‌ی آبیاری","de":"«تشنه‌ام.» گلدان که نمی‌تواند حرف بزند، پس تابلوی کوچکی که در خاک فرو رفته، به‌جایش علامت می‌دهد. وقتی رنگش تغییر کند، وقتِ آب‌دادن است. کوچک‌ترین مترجم میان گیاه و انسان، به‌تمامی در همین چوبِ به‌اندازه‌ی یک وجب جای گرفته است."},"ICON-1651":{"nm":"بند نگهدارنده‌ی گیاه","de":"مبادا ساقه‌ای که قد می‌کشد زیرِ وزنِ خودش تلوتلو بخورد، آن را با بندی نرم، آرام به تکیه‌گاهی می‌بندی. اگر خیلی سفت شود نفسش می‌گیرد، اگر خیلی شل شود می‌افتد؛ پس دستِ گره‌زننده به مهربانیِ درست‌اندازه نیاز دارد. حتی رشد کردن هم به کسی نیاز دارد که کنارت باشد."},"ICON-1652":{"nm":"تور محافظ آفات","de":"دهان‌های کوچکی که چشم به برگ‌های لطیف دوخته‌اند را توری ظریف‌بافته آرام سد می‌کند. باد و آفتاب را عبور می‌دهد و فقط آنچه آسیب می‌زند را کنار می‌گذارد؛ دربانی نامرئی. آرامشِ باغچه، مدیونِ همین ملاحظه‌ای است که در چشمه‌های تنگِ این تور بافته شده."},"ICON-1653":{"nm":"کارت سنجش نور آفتاب","de":"اینکه اینجا آفتاب چقدر می‌تابد را، کارتی که در باغچه ایستانده‌ای، آرام می‌پرسد. هرچه رنگش پررنگ‌تر شود، یعنی امروز نور بیشتری گرفته است. این ورقه‌ی کوچک، جای گیاهی که آفتاب دوست دارد را از آنکه سایه برایش راحت‌تر است، جدا می‌کند."},"ICON-1654":{"nm":"نوار تست اسیدیته‌ی خاک","de":"اگر نوار تست را به خاک بزنی، از صورتی تا آبی، زمین با رنگ، احوال درونی‌اش را فاش می‌کند. جایی که نه خیلی ترش و نه خیلی تلخ است، ریشه‌ها راحت‌ترین نفس را می‌کشند. دلِ پنهانِ خاک، خانه‌به‌خانه خوانده می‌شود."},"ICON-1655":{"nm":"برچسب سبد برداشت","de":"اینکه چیدنِ امروز کاهو است یا گوجه‌ی گیلاسی، برچسبی به هر سبد آویزان می‌شود. در صبحِ برداشت که بوی خاک و سبزیِ تازه در هم آمیخته، لحظه‌ای که برچسبی چسبانده می‌شود، آن سبد نخستین نشانِ راهِ رسیدن به سفره می‌شود."},"ICON-1656":{"nm":"شیشه‌ی نگهداری بذر","de":"بذرهای امسال را درون شیشه‌ای می‌گذاری و برای بهارِ آینده می‌فرستی. اگر در را ببندی، زمان لحظه‌ای می‌ایستد و دانه‌های کوچک در تاریکی نوبتِ خود را انتظار می‌کشند. شیشه‌ای شبیه نامه‌ای که از یک فصلِ کامل عبور می‌کند تا برسد."},"ICON-1657":{"nm":"نوار پیوندزنی","de":"اگر شاخه‌ی بریده و شاخه‌ی تازه را روبه‌روی هم بگذاری و با نوار دورشان بپیچی، آن‌دو به‌آرامی یک تن می‌شوند. شیره‌ای که دوباره در جای بریده جاری می‌شود، زخمی که آهسته التیام می‌یابد. پیوند زدن، در نهایت، پذیرفتنِ رگه‌ی یکدیگر است."},"ICON-1658":{"nm":"کلاهک قیچی هرس","de":"کلاهکی کوچک روی نوکِ تیزِ قیچی می‌گذاری. تا وقتی دستِ هرس‌کننده استراحت می‌کند، تیغه کند نشود و دست هم آسیب نبیند. با این توجیه که حتی ابزارِ کارِ تمام‌شده هم لباس‌خواب لازم دارد، باغچه با دقت ابزارهایش را می‌خواباند."},"ICON-1659":{"nm":"جعبه‌ی دسته‌بندی بذر گل","de":"بالسام، گل‌ناز، گلِ چهار ساعت؛ بذرهایی متفاوت در نام و رنگ، هرکدام اتاقی جدا در یک خانه می‌گیرند. اگر مخلوط شوند، در بهار دیگر معلوم نیست کدام کدام است. جداکننده‌های کوچکِ درونِ جعبه، از پیش نقشه‌ی باغی را که هنوز شکوفا نشده می‌کشند."},"ICON-1660":{"nm":"سینی چرخ‌دار گلدان","de":"اگر چهار چرخ ببندی، حتی گلدانِ سنگین هم به دنبالِ آفتاب راه می‌افتد. صبح کنارِ پنجره‌ی شرقی، ظهر در سایه. سبزینه‌ای که زمانی به وزنش زمین‌گیر بود، اکنون می‌غلتد و تمامِ روز به‌دنبالِ نور، بهترین جا را می‌جوید."},"ICON-1661":{"nm":"بند هدایت پیچک","de":"پیچکی که ندانسته در هوا کورمال‌کورمال راه می‌جوید را، بندی آرام به مسیر درست هدایت می‌کند. بالا، و باز هم بالاتر. اگر جایی برای گرفتن نشانش دهی، گیاه شگفت‌آور آن دست را می‌گیرد. حتی رشد کردن هم به یک راهنما نیاز دارد."},"ICON-1662":{"nm":"نگه‌دارنده‌ی کارتِ زبان گل","de":"روی کارتی که کنار گل فرو رفته، پیامی نوشته شده که آن گل می‌خواهد بگوید. هورتانسیا یعنی صداقت، بابونه یعنی معصومیت. تا قدم‌زدن در باغچه، خودِ خواندنِ نامه شود، نگه‌دارنده‌ای کوچک آرام صدایی به دهانِ خاموشِ گل قرض می‌دهد."},"ICON-1663":{"nm":"کلاهک تابلوی باغچه","de":"مبادا باد و باران حروف را محو کند، کلاهی شفاف روی تابلوی باغچه می‌گذاری. «اینجا گوجه»، «اینجا ریحان». نام‌هایی که نزدیک بود محو شوند، شفاف باقی می‌مانند، پس حتی بعد از یک سال، باغچه یک نفر از خانواده‌اش را هم فراموش نمی‌کند."},"ICON-1664":{"nm":"قاشق کود","de":"وقتی به خاک مواد مغذی می‌افزایی، طمع تنها ریشه را می‌سوزاند. پس یک قاشق، دقیقاً همان‌قدر. قاشقِ کوچک مقدار درست را برمی‌دارد و یادآوری می‌کند؛ دلی که خوب پرورش می‌دهد، همیشه از نوک انگشتانی می‌آید که اندازه‌نگه‌داشتن را می‌داند."},"ICON-1665":{"nm":"نازل مه‌پاش","de":"اگر نازل را بچرخانی، جریانِ آب مثل مه پراکنده و فرومی‌ریزد. برگی لطیف که زیرِ جریانی خشن آسیب می‌دید، زیرِ قطراتی شبنم‌مانند به‌آرامی سرش را بالا می‌گیرد. آبِ یکسان، بسته به اینکه چگونه داده شود، سلامی کاملاً متفاوت می‌شود."},"ICON-1666":{"nm":"پیمانه‌ی خوراک","de":"یک پیمانه، دو پیمانه. وعده‌ی غذای دوستت را نه با حدس، که با دقت می‌سنجی. اگر زیاد باشد باقی می‌گذارد، اگر کم باشد دلگیر می‌شود، پس درست‌اندازه را حساب می‌کنی. عشق گاهی درست به شکلِ سنجیدنِ دقیق می‌آید."},"ICON-1667":{"nm":"روکش برس ریزش مو","de":"در فصلِ ریزشِ مو، روکشی، کرک‌های نرمِ گیرکرده در برس را با دقت می‌پوشاند. اگر بعد از شانه‌کردن، کلاهی روی برس بگذاری، روزِ بعد هم آغازی تازه و پرزدار خواهد بود. درخشش خانواده‌ای که با هم زندگی می‌کنید، از همین مرتب‌کردن‌های کوچک بی‌صدا رشد می‌کند."},"ICON-1668":{"nm":"کلاهک ناخن‌گیر","de":"کلاهکی کوچک روی نوکِ تیزِ ناخن‌گیر می‌گذاری، تا ابزارِ کارِ تمام‌شده به دیگر وسایلِ درونِ کشو خراش نزند. بعد از پایانِ زمانِ مراقبت، آرام‌کردن و خواباندنِ ابزار هم بخشی از یک دورِ کاملِ مراقبت است."},"ICON-1669":{"nm":"آویز تزئینیِ قلاده","de":"اگر آویزی درخشان به قلاده ببندی، همان مسیرِ همیشگیِ پیاده‌روی کمی خاص‌تر می‌شود. زیوری کوچک که زیرِ آفتاب برق می‌زند. شاید پرزرق‌وبرق نباشد، اما همین اندازه کافی است تا نشان دهد این کوچولو، عضوی است که کسی عمیقاً دوستش دارد."},"ICON-1670":{"nm":"کارت سلامت حیوان خانگی","de":"امروز خوب غذا خورد؟ جایی دردش نمی‌آید؟ روزِ دوستِ هم‌خانه‌ات را سطر به سطر روی کارت می‌نویسی. وقتی حالِ عضوی از خانواده که نمی‌تواند حرف بزند به نوشته تبدیل شود، دلِ مراقبت‌کننده هم به همان اندازه دقیق‌تر و مطمئن‌تر می‌شود."},"ICON-1671":{"nm":"روکش بالشتک خواب","de":"بالشتکِ خواب را لباسی تازه و نرم می‌پوشانی. اگر پارچه‌ی فرسوده از غلتیدن و پوزه‌مالیدن را دربیاوری، بوی کرکِ خشک‌شده زیرِ آفتاب پخش می‌شود. تمیز نگه‌داشتنِ جایی که بیشتر از هرجا در آن دراز می‌کشد، عشقِ روزانه‌ای است برای عضوِ هم‌خانه."},"ICON-1672":{"nm":"سنجاق‌های نرده‌ی کوچک","de":"در لبه‌ی باغچه، سنجاق‌های کوچک را یکی‌یکی فرو می‌کنی تا نرده‌ای کوتاه برپا شود. نه هشداری تند برای «رد نشو»، بلکه مرزی مهربان که می‌گوید تا همین‌جا جای گل‌هاست. تا وقتی خطی برای نگه‌داشتن باشد، درونِ آن با خیال راحت رشد می‌کنند."},"ICON-1673":{"nm":"قوطی تنقلات صمیمیت","de":"حتی حیوانِ خجالتی هم با صدای تکان‌خوردنِ این قوطی گوش تیز می‌کند. درونش مشتی تنقلات است که دل را باز می‌کند. چون در نزدیک‌شدن، وعده‌ای کوچک از کلمات هم سریع‌تر عمل می‌کند، صدای جرینگ‌جرینگ زودتر از هر چیز پیش می‌رود."},"ICON-1674":{"nm":"تگ ثبت پیاده‌روی","de":"امروز کدام مسیر را چقدر رفتید؟ روی تگ، خاطره را مثل گره‌ای می‌بندی. اگر ردپاها جمع شوند نقشه می‌شوند، و اگر نقشه‌ها جمع شوند خاطره می‌شوند. هر روزی که با هم قدم زده‌اید، روی همین تگِ کوچک با نظم روی هم انباشته می‌شود."},"ICON-1675":{"nm":"بشقاب دانه‌ی پرندگان","de":"اگر بشقابی روی طاقچه بگذاری و چند دانه ارزن رویش بریزی، مهمان‌هایی گمنام یکی‌پس‌ازدیگری فرود می‌آیند. صدای نوک‌زدنِ تق‌تق، بال‌زدنِ پرپر. سفره‌ای کوچک که با یک مشتِ بخشیده، هر صبح کنسرتی کوچک به همراه می‌آورد."},"ICON-1676":{"nm":"ظرف مشاهده‌ی سنجاب","de":"درونِ ظرفِ شفاف، با چشم‌های گردِ سنجابی روبه‌رو می‌شوی. لپ‌هایش پر از بلوط و سری که کج می‌کند؛ چه منظره‌ای. روی وعده‌ی اینکه لحظه‌ای نگاه کنی و به‌زودی رهایش کنی، احوال‌پرسی کوتاهی با تکه‌ای از حیاتِ وحش رد و بدل می‌شود."},"ICON-1677":{"nm":"قالب گچیِ ردپا","de":"گچی نرم می‌ریزی تا ردپایی کوچک را قالب بگیری. تا زمانی که سفت شود منتظر می‌مانی، و زمانِ حیاط هم لحظه‌ای می‌ایستد. آن مهرِ پنجه‌ای به‌اندازه‌ی یک وجب که با بزرگ‌شدن محو خواهد شد را، قالبِ سفید مثل ابدیت بالا می‌آورد و آرام در دو دستت می‌گذارد."},"ICON-1678":{"nm":"کلاهک لنزِ رصد شب","de":"روی نوکِ لنزی که به شب نگاه می‌کند، کلاهکی کوچک می‌بندی. تا شیشه‌ای که ستاره و لانه دیده، بی‌هیچ ذره‌ای غبار منتظرِ شبِ بعد بماند. چشمی که تاریکی را واضح می‌بیند هم، طیِ روز به یک ویرگولِ استراحت نیاز دارد."},"ICON-1679":{"nm":"نشانه‌ی حفاظت از لانه","de":"اگر لانه‌ای میان شاخه‌ها بیابی، به‌جای نزدیک شدن، نشانه‌ای برپا می‌کنی. «اینجا خانواده‌ی پرنده‌ای زندگی می‌کند، لطفاً آرام.» نگاه‌کردن بدون تجاوز؛ همان یک قدمِ مهربانانه به عقب، لانه را در امن‌ترین حالت نگه می‌دارد."},"ICON-1680":{"nm":"چیپ ضبط صدای حیوانات","de":"آوازِ بوته‌زار، جیک‌جیکِ زیرِ سقف، صدای حشراتِ شب را، نه اینکه در چیپ حبس کنی، بلکه لحظه‌ای قرض می‌گیری. جعبه‌ی صدای کوچکی که وقتی دوباره پخش شود، حتی هوای همان لحظه را زنده می‌کند. تا هرچه شنیده شده، هرگز به‌کلی محو نشود."},"ICON-1681":{"nm":"روکش دوربین رصد","de":"درست پیش از آنکه پرنده‌ای پرواز کند، جنگل لحظه‌ای نفسش را نگه می‌دارد. در همان سکوت، پارچه‌ای که روی لنز کشیده شده، وضوحِ دوردست را بی‌آنکه حتی اثرِ انگشتی به آن برسد، نگهبانی می‌کند."},"ICON-1682":{"nm":"بند دوربینِ مسیر جنگل","de":"هر بار که از مسیرِ تندِ جنگل بالا می‌روی، دوربین آرام به سینه‌ات می‌خورد. ضربانِ قلب و صدای شاتر با یک ریتم می‌لرزند، و همین یک بند آن لحظه‌ها را استوار مقابلِ سینه‌ات نگه می‌دارد."},"ICON-1683":{"nm":"کارت راهنمای طبیعت","de":"حتی یک ساقه علف هم نامی دارد، کارت آرام به تو می‌گوید. وقتی چیزی که ندانسته از کنارش گذشته بودی، عنوانی بگیرد، مسیرِ کوه ناگهان با چهره‌های آشنا مهربانانه شلوغ می‌شود."},"ICON-1684":{"nm":"وصله‌ی تعمیر بادبان","de":"حتی پارچه‌ای که تمامِ بدنش باد را دریافت می‌کند، جای زخم دارد. با یک وصله‌ی کوچک که آرام روی جای پاره‌شده گذاشته می‌شود، بادبان دوباره شایستگیِ در آغوش گرفتنِ دریای دور را می‌یابد."},"ICON-1685":{"nm":"تخته‌ی تمرین گره","de":"بالا، پایین، یک‌بار دیگر دور؛ ترتیبی که دست از بر کرده، به گره تبدیل می‌شود. شبی که طوفان به عرشه می‌کوبد، همان یک روال، انسان و کشتی را با هم گره می‌زند."},"ICON-1686":{"nm":"کلاهک محافظِ زنجیرِ لنگر","de":"این کلاهکِ کوچک را که روی انتهای زنجیرِ آهنی کشیده می‌شود دست‌کم نگیر. زنگ پنهانی درونش رشد می‌کند، پس یک کلاهک که پشت به بادِ دریا می‌ایستد، عمرِ لنگر را آرام طولانی‌تر می‌کند."},"ICON-1687":{"nm":"پرچم نشانه‌ی مسیر","de":"روزی که مه چنان غلیظ است که پیشِ رو محو می‌شود، یک پرچم به‌جای همه، مسیر را می‌گوید. نقطه‌ای از رنگ که در باد موج می‌زند، بالاخره شانه‌های خشک‌شده‌ی سکاندارِ سرگردان را آزاد می‌کند."},"ICON-1688":{"nm":"جاکلیدیِ کابین","de":"روی دریای متلاطم، حلقه‌ای کوچک به درِ تنگِ کابین آویزان است. تا زمانی که کلید جایش را نگه دارد، اتاقی برای بازگشتن، هرگز برایت قفل نمی‌شود."},"ICON-1689":{"nm":"کیف ضدآب نقشه","de":"در باران، نقشه‌ی کاغذی اول از همه راه را پاک می‌کند. تا زمانی که یک ورق درونِ کیفِ شفاف خشک بماند، حتی سفری خیس هم هرگز جهتش را کاملاً گم نمی‌کند."},"ICON-1690":{"nm":"فتیله‌ی چراغِ کشتی","de":"روغنی که فتیله آرام‌آرام بالا کشیده، بالاخره به شعله تبدیل می‌شود. نقطه‌ای نور روی عرشه، و با همان یک لرزشِ کوچک، فاصله‌ی دورِ دریای شب کمی نزدیک‌تر می‌شود."},"ICON-1691":{"nm":"پارچه‌ی علامت خطر","de":"در فاصله‌ای که صدا نمی‌رسد، دستی که پارچه‌ی سرخی را بالا تکان می‌دهد، دورتر از کلمات می‌رود. همین یک تکه پارچه، باد را می‌شکافد و به‌جایِ تو فریاد می‌زند که کسی اینجا زنده است."},"ICON-1692":{"nm":"سنجاق جهتِ باد دریا","de":"کسی که می‌داند باد از کجا می‌وزد، مسیر را تعیین می‌کند. روی همان یک جهتی که سنجاقی کوچک آرام نشان می‌دهد، سرنوشتِ دریانوردیِ تمامِ روز آرام تکیه می‌دهد."},"ICON-1693":{"nm":"روکش بیل تاشو","de":"اگر تیغه را تا کنی و بپوشانی، حتی بیلِ پرکار هم لحظه‌ای نفس تازه می‌کند. آخرین کاری که دستِ خاک‌دربیاورده انجام می‌دهد، این است که مراقب باشد تیغه‌ی فردا کند نشود."},"ICON-1694":{"nm":"کیف قطب‌نمای جیبی","de":"عقربه همیشه بی‌لرزش رو به شمال است، اما آنچه از آن عقربه محافظت می‌کند، جعبه‌ای محکم است. هرکه یک‌بار راه را گم کرده باشد، جهت را عزیزتر در آغوش می‌گیرد."},"ICON-1695":{"nm":"توری ظروفِ کمپ","de":"ظرف‌های شسته‌شده را در توری آویزان می‌کنی تا زیرِ آفتابِ صبح خشک شوند. روز در اردوگاه با صدای خشک‌شدنِ آب آغاز می‌شود، و همان چیز کوچک، درونِ چادر را مطمئن پر می‌کند."},"ICON-1696":{"nm":"کارت مجوز کمپینگ","de":"اجازه‌ای که می‌گوید می‌توانی یک شب در این کوه بمانی. لحظه‌ای که ورقی کاغذ در دستت بیاید، حتی جنگلِ غریبه هم برای مدتی طرفِ تو می‌شود و چادرِ کوچکت را آرام می‌پذیرد."},"ICON-1697":{"nm":"بند پرچمِ مسیرِ اکتشاف","de":"اگر در هر دوراهی پرچمی ببندی، راهِ بازگشت در تاریکی پراکنده نمی‌شود. نشانه‌ی کوچکی که کسی که پیش‌تر رفته گذاشته، آرام پشتِ قدم‌های دنبال‌کننده را هل می‌دهد."},"ICON-1698":{"nm":"قوطی ضدآبِ کبریت","de":"کبریت با یک قطره خیس شود، برای همیشه خاموش می‌ماند. درونِ قوطیِ محکم‌بسته‌ای که حتی یک قطره آب هم راه ندارد، جرقه خشک و ساکت، فقط برای سردترین شب انتظار می‌کشد."},"ICON-1699":{"nm":"فیلتر تصفیه‌ی آبِ همراه","de":"حتی آبی که تیرگی‌اش تردید می‌آفریند، بعد از عبور از این فیلتر زلال می‌شود. وسیله‌ای کوچک که پیش از تشنگی، تردید را کنار می‌گذارد؛ باور به اینکه می‌توان نوشید، خودش یک جرعه آرامش است."},"ICON-1700":{"nm":"بسته‌ی پتوی اضطراری","de":"اگر تا شود، به‌اندازه‌ی کف دست است؛ اگر باز شود، گرمای یک انسان می‌شود. تا کلمه‌ی «اضطراری» کمی سبک‌تر باشد، پتو در گوشه‌ای از کوله‌پشتی، همیشه آماده‌ی گرم‌شدن است."},"ICON-1701":{"nm":"دستبند نشان‌دار شب","de":"در جاده‌ای کوهستانی که تاریکی بر آن فرود آمده، یک مچ‌دست به آرامی نوری خفیف می‌تاباند. آن نوار کوچک که جای هرکس را به دیگری اعلام می‌کند، همراهانِ هم‌راه را با ریسمانی نامرئی و مهربان به هم پیوند می‌زند."},"ICON-1702":{"nm":"برچسب کلاه‌ایمنی معدنچی","de":"برچسبی که روی کلاه‌ایمنی چسبانده شده، نام دیگرِ معدنچی است. در تونل عمیقی که حتی نور هم گران‌بهاست، همکار را با همان تصویر کوچکِ در پرتو چراغ افتاده، با مهربانی می‌شناسی."},"ICON-1703":{"nm":"سنجاق نشانگر رگه‌ی معدن","de":"در جایی که رگه‌ای پیدا شده، سنجاقی را به آرامی فرو می‌کنی. نقطه‌ای که تنها در دل تاریکی می‌درخشد، به مهربانی به هرکس که بعداً می‌آید می‌گوید از همین‌جا کندن را آغاز کن."},"ICON-1704":{"nm":"خط‌کش اندازه‌گیری ترک","de":"اندازه‌گیریِ شکافِ دیوار، صبری کند و پیگیر است. آیا از دیروز یک وجب دیگر باز شده؟ عدد کوچکی که خط‌کش می‌گوید، فروریختن را پیش از آنکه برسد، آشکار می‌کند."},"ICON-1705":{"nm":"کاغذ قالب‌گیریِ نقشِ سنگ","de":"کاغذ را روی نقشِ حک‌شده در سنگ می‌گذاری و آرام‌آرام با جوهر می‌کوبی. لحظه‌ای که لمسِ دستی از هزار سال پیش در رگه‌های سیاه پدیدار می‌شود، این قالب زمانِ گذشته را برای دمی روبه‌رویت می‌نشاند."},"ICON-1706":{"nm":"جعبه‌ی سکه‌ی باستانی","de":"این تکه‌فلزِ کوچک که به‌دور از زنگ‌زدگی به‌آرامی خفته، آخرین صدای ملتی ناپدیدشده را در خود دارد. یک عصر تمام در یک سکه جای گرفته و در جعبه‌ی شفاف، به‌آهستگی پیر می‌شود."},"ICON-1707":{"nm":"پایه‌ی تکه‌بلور","de":"حتی بلوری که نور را در خود حبس می‌کند، به تکیه‌گاهی نیاز دارد. در لحظه‌ای که آرام روی پایه‌ای کوچک می‌نشیند، آن چیز شکننده سرانجام درخشش خود را به‌تمامی می‌گشاید."},"ICON-1708":{"nm":"تکه‌نقشه‌ی غار","de":"نقشه‌ای پاره‌شده تنها نیمی از راز خود را زیرکانه نشان می‌دهد. تا روزی که تکه‌ی باقی‌مانده پیدا شود، این یک برگ، باقیِ راه را جایی در دل غار نیمه‌پنهان نگه می‌دارد."},"ICON-1709":{"nm":"قلاب فرود با طناب","de":"برای سپردن بدن به دره، نخست باید به این قلاب کاملاً اعتماد کرد. آویختن وزن خود به یک تکه فولاد سرد—اعتماد، از اساس، همین‌قدر سنگین است."},"ICON-1710":{"nm":"مجوز حفاری","de":"برگه‌ای که مهرِ اجازه‌ی کندن زمین را واضح بر خود دارد. برای بیدار کردن آنچه مدفون است، نخست باید اجازه خواست؛ حفاری به‌آرامی می‌آموزد که با ادب باید آغاز کرد."},"ICON-1711":{"nm":"کیسه‌ی بادشکن","de":"وقتی پشت به باد می‌گشایی‌اش، در میان دشتِ توفانی قطعه‌ای از آرامش پدیدار می‌شود. پشت این یک لایه، شعله‌ای کوچک محفوظ می‌ماند و خسته‌ای دمی می‌آساید."},"ICON-1712":{"nm":"روکش عینک ضدطوفان‌شن","de":"هرچند شن به‌خشم بچرخد، دستِ‌کم دید باید تا پایان محفوظ بماند. یک روکشِ نازک روی عینک، به شجاعتِ باز نگه‌داشتنِ چشم و ادامه‌ی راه، حتی در دل توفان، بدل می‌شود."},"ICON-1713":{"nm":"سینی پذیرایی روز بارانی","de":"از نوک کفش مهمانی که آمده، آب باران چکه‌چکه می‌ریزد. سینی‌ای که آرام کنار درِ ورودی گذاشته شده، بی‌هیچ کلامی، پاهای خیس و سردشده را با گرمی می‌پذیرد."},"ICON-1714":{"nm":"برچسب خنک‌کننده‌ی گرمای شدید","de":"برچسبی کوچک که گرمای نیمروز را به‌آرامی می‌کاهد. آویخته از کیف، خنکایش را نگه می‌دارد تا وقتی عرق نشستن گیرد، دستی از سایه را پنهانی به تو می‌دهد."},"ICON-1715":{"nm":"کمربند گرم‌کن دست","de":"کمربندی گرم که یک‌بار دور کمر می‌پیچد. وقتی گرمای گرم‌کنِ دستی از کمر بالا می‌رود، حتی دشتِ زمستانِ سخت هم اندکی تحمل‌پذیرتر می‌شود."},"ICON-1716":{"nm":"بسته‌ی جاذب رطوبت","de":"نم بی‌صدا اشیا را می‌خورد. تا وقتی بسته‌ی کوچکی در جعبه بی‌سروصدا رطوبت را می‌مکد، چیزهای عزیز شکل خشک و سالمِ خود را نگه می‌دارند."},"ICON-1717":{"nm":"روکش کفش ضدگل","de":"گاهی حتی در گذر از باتلاق، تنها کفش باید پاک بماند. این پوششِ نازک که گل را بازمی‌دارد، قدم‌هایی را که آستانه‌ی خانه را رد می‌کنند، سبک‌تر می‌سازد."},"ICON-1718":{"nm":"روکش فانوس مه دریایی","de":"وقتی مهِ دریا می‌کوشد چراغ را یکباره ببلعد، این روکش به‌آرامی رشته‌ی نورِ پراکنده را گرد می‌آورد. حتی در سپیده‌دمِ کدر، نورِ یک بندرگاه هرگز خاموش نمی‌شود."},"ICON-1719":{"nm":"سنجاق هشدار صاعقه","de":"وقتی ابرهای تیره پایین می‌آیند، سنجاقی نخست هشدار می‌دهد. کلامِ خم‌شدن پیش از فرود صاعقه—فروتنی در برابر طبیعت را همیشه بهتر است زودتر آموخت."},"ICON-1720":{"nm":"نشانگر کتاب آشپزی","de":"نشانگری کوچک که میان صفحاتِ کتابِ آشپزیِ گشوده جای می‌گیرد. وقتی جلوی آتش دنبال خطی گم‌شده می‌گردی، طعمِ دست مادر هم در همان صفحه دوباره بیدار می‌شود."},"ICON-1721":{"nm":"چوب اندازه‌گیری چاشنی","de":"مادر همیشه فقط می‌گفت «یک چیمچه». هرچند تخمینِ چشمی هرگز دقیق نبود، اما دستِ او هیچ‌گاه نلرزید. با این چوب نمک را می‌سنجی و درمی‌یابی چیزی که بیش از هر پیمانه‌ای پخته بود، نه حدس، بلکه عشق بود."},"ICON-1722":{"nm":"نوار درپوش تخمیر","de":"می‌دانی خمره هم نفس می‌کشد؟ وقتی این نوار درپوش را محکم در آغوش می‌گیرد، درون و بیرون آرام‌آرام با هم به سخن می‌آیند. تنها پس از آن چند روزِ بی‌شتاب است که انتظار سرانجام نام طعم می‌گیرد."},"ICON-1723":{"nm":"تکه‌برچسب تاریخ تخمیر","de":"تکه‌برچسبی کوچک که تاریخِ درست‌شدن روی آن منظم نوشته شده. نوشته کم‌رنگ می‌شود اما آنچه درون است ژرف‌تر می‌گردد. نوشتنش چنان‌که گویی فراموش خواهد شد، و روزی ناگهان بیرون‌کشیدنش—تخمیر همین‌گونه پیمانی است که نگه داشته می‌شود."},"ICON-1724":{"nm":"صافی آبگوشت","de":"آبگوشتِ زلال تنها پس از صاف‌کردن و بازهم صاف‌کردن به‌دست می‌آید. توری را ببین که تکه‌ها را نگه می‌دارد و تنها گوهر را عبور می‌دهد؛ آن ضرب‌المثلِ آشپزخانه‌ی کهن که ژرفا در جایی می‌ماند که چیزی از آن کاسته‌ای، از نوک انگشتانت به تو می‌رسد."},"ICON-1725":{"nm":"پارچه‌ی تخمیر خمیر","de":"پارچه‌ای را به‌آرامی روی خمیر می‌کشی. در همان تاریکیِ زیرِ آن، تا مخمر پیوسته باد می‌کند، برای نخستین‌بار مهربانیِ چیزهایی را که در جاهای ندیده بی‌صدا رشد می‌کنند، می‌آموزی."},"ICON-1726":{"nm":"سنجاق آماده‌سازی مواد غذایی","de":"سنجاقی کوچک که رگه‌ی پیازچه را می‌شکافد و سیر را محکم نگه می‌دارد. آماده‌سازی چون نخستین سلامی است به مواد غذایی، پس هرچه با دقت بیشتری پیرایش کنی، نورِ سفره‌ی شب یک درجه روشن‌تر می‌شود."},"ICON-1727":{"nm":"انبرک چیدمان غذا","de":"اینکه آخرین لقمه روی بشقاب کجا گذاشته شود را سرانجام همین انبرک تعیین می‌کند. در آن لحظه‌ی کوتاه که دستی چیره در هوا نیم‌ضرب مکث می‌کند، یک وعده غذا آرام‌آرام به یک تابلوی نقاشی بدل می‌شود."},"ICON-1728":{"nm":"روکش عایق‌دار جعبه‌غذا","de":"ناهاری که جلوی درِ مدرسه به دست می‌گرفتی، باید تا زنگ ناهار گرم می‌ماند. گرمایی که در این روکش محبوس است، به اندازه‌ی ژرفای دلِ کسی که از سپیده‌دم کنار اجاق ایستاده بود، سرد نمی‌شود."},"ICON-1729":{"nm":"کارت دعوت به سفره","de":"«یه روز بیا خونه‌مون یه لقمه غذا بخوریم.» آیا سخنی مهربان‌تر از این هست؟ بی‌هیچ وعده‌ی بزرگی، تنها نشستن سر یک سفره—کهن‌ترین دعوتی که زبان کره‌ای می‌تواند بگوید، در همین یک برگ جای گرفته است."},"ICON-1730":{"nm":"ژتون رزرو میز","de":"نامت را می‌نویسی و جایت را نگه می‌داری. تا وقتی تکه‌ژتونی کوچک میزِ خالی را برای دمی از آنِ کسی می‌کند، آن ساعتِ موعود، آهسته چون صدای قدم‌ها، نزدیک می‌شود."},"ICON-1731":{"nm":"کارت ارزیابی مزه","de":"چهره‌هایی که یک گاز می‌زنند و با جدیتِ تمام ستاره می‌دهند. آن خط صادقانه‌ای که روی این کارت منظم نوشته می‌شود، گرم‌ترین سرزنشِ ممکن برای خوشمزه‌تر شدنِ بشقابِ بعدی است."},"ICON-1732":{"nm":"نوار سپاس جعبه‌غذا","de":"نواری دور جعبه‌ی خالی‌شده و پاکیزه می‌پیچی و بازش می‌فرستی. کسی هم که هرگز نتوانست بگوید «خوب خوردم»، دست‌کم در همین گره، دلی را که به‌زبان نیامد، گره می‌زند و می‌فرستد."},"ICON-1733":{"nm":"برچسب هشدار حساسیت","de":"همین یک برچسبِ کوچک به‌آرامی از سفره‌ی کسی نگهبانی می‌کند. اینکه چه چیزی درون است را واضح بنویسی، نامی دیگر برای مهمان‌نوازی است—مراقبتی که حتی به جاهای دیده‌نشده هم می‌رسد."},"ICON-1734":{"nm":"قاشق خاطره‌ی طعم","de":"آن طعمی که مدت‌ها بر نوک زبان ماند، در حقیقت منظره‌ی همان روز بود. وقتی یک قاشق در یک آن تو را به آشپزخانه‌ی کودکی بازمی‌گرداند، گویی خاطره چیزی است که دل، نه معده، برمی‌دارد و نگه می‌دارد."},"ICON-1735":{"nm":"ژتون منوی امروز","de":"امروز چی بخوریم؟ در برابر سخت‌ترین پرسش دنیا، هر بار می‌بازیم. این ژتون را که بچرخانی و منو را به سرنوشت بسپاری، دلت به‌شگفت‌آور سبک و شاد می‌شود."},"ICON-1736":{"nm":"زنگ سفره‌ی مشترک","de":"یک‌بار زنگ که به صدا درآید، خانواده‌ای که در اتاق‌ها پراکنده بودند، در یک‌جا گرد می‌آیند. آن صدای زنگ بر سفره‌ی گرد، مهربان‌ترین ترجمه‌ی این کلمات است: «حاضره، زود بیاین.»"},"ICON-1737":{"nm":"کارت نوبت دسر","de":"چیزهای شیرین همیشه آخر می‌آیند. این کارت به‌جای همه، پیمانی را که هیچ‌کس نمی‌داند چه‌کسی بسته، پاس می‌دارد. میزبانی کوچک و مهربان بر سر سفره که اوج لذت را برای یک لقمه دسر نگه می‌دارد."},"ICON-1738":{"nm":"ژتون چانه‌زنی","de":"در دل بازار، «یه‌کم تخفیف بده» و «خودم دارم ضرر می‌دم» با محبت به هم برمی‌خورند. این ژتون رسیدِ مشتری قدیمی‌ای است که در پایان چانه‌زنی، سرانجام با خنده تمام می‌شود."},"ICON-1739":{"nm":"سنجاق بررسی موجودی","de":"قفسه‌های انبار را آرام از نظر می‌گذرانی و جای خالی را می‌یابی و سنجاق می‌زنی. دانستن اینکه چه مانده و چه تمام شده—کارِ بزرگِ خانه‌داری همیشه از همین بازرسیِ کوچک آغاز می‌شود."},"ICON-1740":{"nm":"برس نظافت غرفه","de":"در شامگاهی که بازار بسته شده، صدای آرامِ جاروکشیِ غرفه‌ی خالی بر مغازه فرود می‌آید. در نوک انگشتانی که جایی را برای فردا از پیش تمیز می‌کند، پشتکاری نهفته که روز را به‌زیبایی گره می‌زند."},"ICON-1741":{"nm":"کارت پیشنهاد امروز","de":"«امروز این خوبه‌ها.» کارتی که صاحب مغازه پنهانی جلو می‌گذارد. در آن پیشنهاد که شانه‌ی مشتریِ مردد را آرام هل می‌دهد، غروری به‌اندازه‌ی یک روز، منظم جای گرفته است."},"ICON-1742":{"nm":"جاکارتی مهر مشتری‌دائمی","de":"ده بار پر کن، یکی مهمان توست. این جاکارتی که خانه‌های مهرش کم‌کم پر می‌شوند، چهره‌ی دیگری از واژه‌ی «مشتری دائمی» است، چراکه رفت‌وآمد زیاد، سرانجام یعنی دوست داشتن."},"ICON-1743":{"nm":"گیره‌ی دفتر تعویض","de":"گیره‌ای که سوابقِ چیزهای مبادله و بازپس‌داده‌شده را یک‌جا نگه می‌دارد. هرچه رفت‌وآمد بیشتر باشد، دفتر ضخیم‌تر می‌شود و به همان اندازه، اعتمادی که با همسایه‌ها ساخته شده هم پرمایه‌تر می‌گردد."},"ICON-1744":{"nm":"برچسب فروخته‌شد","de":"لحظه‌ای که این برچسب به آخرین قطعه می‌چسبد، دل به‌شکلی عجیب پر می‌شود. بدرقه‌ای کوتاه، چون «به‌سلامت»، برای چیزی که راهیِ سفره‌ی کسی یا گوشه‌ی اتاقی می‌شود."},"ICON-1745":{"nm":"سبد کالای رزروی","de":"سبدی با برچسب نامِ تو، جای یک قفسه را نگه داشته است. آن یک جای از پیش نگه‌داشته‌شده، به‌آرامی به تو که وارد می‌شوی می‌گوید: «همه‌ی این مدت منتظرت بودم.»"},"ICON-1746":{"nm":"زیرانداز میز بسته‌بندی","de":"زیراندازِ گسترده روی میز بسته‌بندی، صحنه‌ی دستانی پرمشغله است. در همان مدت کوتاهی که کاغذ تا می‌خورد و نخ منظم گره می‌خورد، چیزی معمولی آرام‌آرام به هدیه‌ی کسی بدل می‌شود."},"ICON-1747":{"nm":"یادداشت وعده‌ی سر زدن","de":"«فردا سر می‌زنم.» یادداشتی در یک خط، آرام میان درز در جا داده شده. حتی وقتی چهره‌ی هم را نمی‌بینید، پیمان بر یک برگ سوار می‌شود و پیش از خودِ آدم می‌رسد و آرام منتظر می‌ماند."},"ICON-1748":{"nm":"سبد هدیه‌ی همسایگی","de":"سبدی که از روی دیوار رد می‌شود، همیشه با بهانه‌ی «یه‌کم زیاد درست کردم» همراه است. مهرِ کره‌ای این‌گونه، با تظاهر به فراوانی و بی‌خیالی، آرام‌آرام از این سو به آن سو می‌رود."},"ICON-1749":{"nm":"صندوق اخبار محله","de":"خبرهای بزرگ و کوچک محله، آرام‌آرام در این صندوق انباشته می‌شود. اینکه چه‌کسی تازه اسباب‌کشی کرده و کدام خانه جشن گرفته، چند برگ کاغذ گرد می‌آیند تا نبض آرام محله را برسانند."},"ICON-1750":{"nm":"مهر سپاس دیدار","de":"سپاسِ آمدنِ کسی را با یک مهر محکم روی کاغذ می‌فشاری. آن یک لکه‌ی جوهر که در کاغذ پخش شده، بیش از جمله‌ی «فراموش نمی‌کنم» در جایش می‌ماند."},"ICON-1751":{"nm":"کارت تقدیر مهربانی","de":"کارتی که مهربانیِ کسی را که امروز نصیبت شده، آرام می‌نویسی و دوباره پس می‌دهی. در محله‌ای که زحمتِ نوشتنِ مهربانی‌های کوچک را می‌کشد، خوبی‌ها پیوسته می‌چرخند و بازمی‌گردند."},"ICON-1752":{"nm":"مهر پاکت‌نامه‌ی عذرخواهی","de":"مثل سیبی که سرخ و کامل رسیده، سخنِ «ببخشید» را هم تنها پس از رسیدنِ کافی می‌توان گفت. این مهری که محکم روی پاکت فشرده شده، نشانِ شجاعتی است که عذرخواهیِ ناگفتنی را تا آخر در خود نگه داشت."},"ICON-1753":{"nm":"جدول کار مشترک","de":"برگه‌ای که در خانه‌خانه نوشته چه‌کسی چه کاری برعهده دارد. کاری که تنهایی طاقت‌فرساست، وقتی نام‌ها میانش تقسیم شود، سبک‌تر می‌گردد؛ این را کسی که شانه‌به‌شانه کار کرده، خوب می‌داند."},"ICON-1754":{"nm":"روبان سلیقه‌ی همسایه","de":"با روبان‌هایی رنگارنگ، آرام علامت می‌زنی همسایه چه چیزی را دوست دارد. به‌خاطر سپردنِ سلیقه‌ی کسی، آرام‌ترین اعترافِ عزیز داشتنِ اوست، بی‌آنکه لازم باشد به‌زبان بیاوری."},"ICON-1755":{"nm":"حلقه‌ی دعوت روی تابلوی نام","de":"یک حلقه بر تابلوی نام، خبر می‌دهد که «امروز مهمان می‌پذیریم.» نشانه‌ای به اندازه‌ی کف دست، اما در آن دلی سراپا گشوده آویزان است، آماده برای پذیرفتنِ کسی."},"ICON-1756":{"nm":"دستبند ورود جشنواره","de":"نواری رنگ‌پریده که روزهایی چند، از دریغِ باز کردنش، همچنان بر مچ ماند. تنها وقتی بر مچ بسته شد، جشن براستی آغاز شد. درونش روزی خفته که حتی پس از پایان، هرگز واقعاً پایان نیافت."},"ICON-1757":{"nm":"جاکارتی بلیت آتش‌بازی","de":"درست پیش از آنکه آسمانِ شب بترکد، بلیتِ درون این جاکارتی، تپشِ قلب را محکم نگه داشته. پیمانی که تا کف دست عرق کند فشرده شده، همه برای همان یک لحظه که نخستین شعله با صدای «پوف» شکوفا می‌شود."},"ICON-1758":{"nm":"بشقاب رصد ماه","de":"شب‌هایی بود که گویی ماهِ بدر تمام را در یک ظرف بالا کشیده بودی. میوه‌ی تازه و سونگ‌پیون را زیبا در این بشقاب می‌چینی و به ماه تعظیم می‌کنی، و دلی گرد تا انتهای آسمان می‌رسد."},"ICON-1759":{"nm":"سنجاق دستکش جشنواره‌ی زمستانی","de":"حتی وقتی دست‌ها در برف کرخت می‌شوند، دستکش پیوسته از مچ درمی‌رود. تنها وقتی این سنجاق محکم به سرآستین بسته شود، سرانجام می‌توانی با خیال راحت در جشنواره‌ی زمستانی بدوی."},"ICON-1760":{"nm":"کارت بذر بهاری","de":"چند دانه بذر خفته در کارت، هرکدام منتظر بهارِ خویش‌اند. در خاک که دفنشان کنی، مثل یک پیمان بی‌خطا جوانه می‌زنند؛ گویی هر آغازی از یک نقطه‌ی کوچک و استوار سرچشمه می‌گیرد."},"ICON-1761":{"nm":"مهر ساحل تابستانی","de":"موجی مهرش را محکم بر شن می‌کوبد و آرام پس می‌نشیند. با آنکه می‌داند به‌زودی محو خواهد شد، بازهم نشانی کوچک می‌گذارد که کسی این‌جا بوده. تابستان همیشه این‌گونه یک‌بار واضح مهر می‌خورد و با بویِ شور می‌گذرد."},"ICON-1762":{"nm":"روبان برداشت پاییزی","de":"دستی که خوشه‌ها را می‌بست، در پایان روبانی زیبا می‌بندد. گرهی که عرقِ یک سال را با دقت جمع می‌کند. حتی وقتی دشت خالی می‌شود، پاییز با زیباترین رنگش، چون غروب، یک بار دیگر سلام می‌دهد."},"ICON-1763":{"nm":"حباب‌گفتار عکس یادگاری","de":"«ممنون که تا این‌جا اومدی.» سلامی که هرگز به‌زبان نیامد، روی کاغذ گرد باد می‌کند. تکه‌ای گرد از دل، که به‌آرامی به سکوتِ منجمدشده در عکس، صدایی وام می‌دهد."},"ICON-1764":{"nm":"سنجاق نقشه‌ی جشنواره","de":"نشانه‌ای که کسی محکم فرو کرده تا در میدانِ وسیع گم نشوی. حتی وقتی پاها پیش از تو به سمت صدای سازهای محلی می‌دوند، همین یک سنجاق تو را که سرگردانی، آرام به جای موعود می‌رساند."},"ICON-1765":{"nm":"کلید اصلی آلبوم","de":"آنچه قفل شده، آلبوم نیست، بلکه زمانی است که در آن مهر و موم شده. لرزشِ نخستین ضبط، سپیده‌دمِ آخرین میکس. کلید را آرام بچرخانی، درِ آن اتاقی که تنها سازندگانش می‌شناسند، با صدایی خفیف باز می‌شود."},"ICON-1766":{"nm":"کارت فهرست آهنگ‌ها","de":"ترتیبِ آهنگ‌ها روی یک برگ، در حقیقت ترتیبِ دل است. کجا بغض می‌گیرد، کجا باید نفس تازه کرد—کاغذ از پیش همه را می‌داند. هیجانی که پیش از شنیدنِ نخستین نت، سر می‌رود."},"ICON-1767":{"nm":"برچسب بازرسی صدا","de":"تنها کسی که همان قطعه را صدبار عقب کشیده، این برچسب را می‌زند. یک‌بار دیگر، فقط یک‌بار دیگر بشنویم. کنار مهرِ تأیید، شبِ کسی پنهان است که تا سپیده به گوش‌های خود شک کرده بود."},"ICON-1768":{"nm":"برچسب پیش‌سفارش","de":"پیمانی برای انتظار چیزی که هنوز به جهان نیامده. لحظه‌ای که برچسب می‌چسبد، جای خالی‌ای آرام به نام کسی رزرو می‌شود. حتی انتظارِ پرشور هم شماره‌ی نوبت دارد."},"ICON-1769":{"nm":"برچسب مهر چاپ نخست","de":"به لمسِ کهنِ پوشاندنِ خمره با هانجی و مهر و موم کردنش با چسب شباهت دارد. برگی که پیمان می‌بندد چیزها را همان‌گونه که نخستین‌بار بودند نگه دارد. چون می‌دانی با کندنش ناپدید می‌شود، همچنان بیشتر و بیشتر به حالتش خیره می‌مانی."},"ICON-1770":{"nm":"ژتون تقویم بازگشت","de":"یک دایره که به تقویم افزوده می‌شود، شب‌های باقی‌مانده تا آن روز را یک خانه کوتاه‌تر می‌کند. تاریخِ بازگشت روی ژتونِ کوچکی در دستت روشن است. برای کسی که منتظر است، زمان این‌گونه با دست شمرده می‌شود."},"ICON-1771":{"nm":"جلد شفاف عکس کانسپت","de":"پیش از آنکه کانسپتِ بعدی، رنگ این کانسپت را کنار بزند، برگی شفاف رگه‌اش را با دقت نگه می‌دارد. تا حتی با تغییرِ فصل فراموش نشود، رنگ روزهای گذشته را با تمام گوشه‌هایش آرام محافظت می‌کند."},"ICON-1772":{"nm":"ژتون رونمایی تیزر","de":"درست پیش از برداشتنِ پرده، سکه‌ای کوچک در کف دست فشرده می‌شود. لحظه‌ای که آن را جلو می‌گیری، نخستین صحنه‌ی قفل‌شده یک وجب به‌سوی جهان باز می‌شود. رونمایی، سرانجام، کارِ آن است که چه‌کسی زودتر دست دراز می‌کند."},"ICON-1773":{"nm":"پایه‌ی نمایش آلبوم","de":"لحظه‌ای که یک پایه‌ی کوتاه، آلبومی را کمی بالا می‌برد، صفحه‌ای معمولی به ستاره‌ی ویترین بدل می‌شود. نقش مکمل و مهربانی که از پشت، بی‌صدا، زاویه‌ای را نگه می‌دارد که نور زیباترین می‌افتد."},"ICON-1774":{"nm":"پاس شوکیس دبوت","de":"مجوزی که واژه‌ی «برای نخستین‌بار به شما نشان می‌دهیم» بر آن حک شده. از راهروی بلندِ پشتِ صحنه تا نخستین کف‌زدنِ تماشاگران، این پاس تو را از آستانه‌ی لرزانِ دبوت عبور می‌دهد."},"ICON-1775":{"nm":"ژتون علامت‌گذاری حرکت روی صحنه","de":"با نوک پا آرام دنبال ژتونِ چسبیده به کف می‌گردی. خانه‌ای که بدن حتی بی‌آنکه ببیند، پیش از هرچیز می‌شناسد. لحظه‌ای که درست بر همان جای حفظ‌شده می‌نشینی، لرزشِ نوک انگشتانت سرانجام حرکتی روشن می‌شود."},"ICON-1776":{"nm":"کارت متن سخنرانی تشکر","de":"حتی جمله‌ی معمولیِ «همه‌اش به‌لطف شماست» وقتی با خطی لرزان نوشته شود، دیگر معمولی نیست. چند خط که از پیش نوشته شده، از ترسِ آنکه هیجان همه را از یاد ببرد. صداقت گاهی به یک کارت تکیه می‌کند."},"ICON-1777":{"nm":"برگه‌ی رزرو عکاسی پروفایل","de":"برگه‌ای که تاریخ ایستادن روبه‌روی لنز، منظم روی آن نوشته شده. برنامه‌ای برای آرام‌آرام آماده‌کردنِ بهترین چهره. هرچه خانه‌های خالی پر می‌شود، شب‌های ماندن جلوی آینه هم طولانی‌تر می‌گردد."},"ICON-1778":{"nm":"برگه‌ی عضویت باشگاه هواداران","de":"برگی که با خجالت، نام و دل را در یک خط می‌نویسی و می‌دهی. گفتنِ «دوستت دارم» همیشه سخت است، اما این یک برگ، آن جمله را به‌جای تو منظم می‌نویسد. نخستین امضا بر تصمیمِ همراه بودن."},"ICON-1779":{"nm":"برگه‌ی بازرسی هدیه‌ی دبوت","de":"دستی که یکایک را وارسی می‌کند و کسی را که آن را دریافت می‌کند در ذهن می‌آورد. آیا گوشه‌ها آسیب ندیده؟ آیا دلی جا نمانده؟ هدیه پیش از آنکه حتی داده شود، یک‌بار دوست داشته شده و به‌راه می‌افتد."},"ICON-1780":{"nm":"نشانگر پایان صحنه","de":"درست پیش از فروافتادنِ پرده، نشانه‌ای گذاشته شده جایی که آخرین ژست می‌ماند. نه اعلانِ پایان، بلکه نقطه‌ای کوچک که پایان را زیبا گره می‌زند. تنها صحنه‌ای که خوب بسته شده، صحنه‌ی بعدی را می‌گشاید."},"ICON-1781":{"nm":"سنجاق انتظار مصاحبه","de":"سنجاقی که سکوتِ پیش از آغازِ پرسش‌ها را آرام نگه می‌دارد. در آن سکوتِ کوتاهِ گزینشِ پاسخ در ذهن، این نشانه‌ی کوچک به‌جای تو با مهربانی می‌گوید: «هنوز نه، اما به‌زودی.»"},"ICON-1782":{"nm":"پاکت یادگاری دبوت","de":"مثل آن دلِ کهن که نامه‌ای گران‌بها را همراه با پاکتش در دستِ رونده‌ای می‌گذاشت، یک لایه ثبتِ نخستین صحنه را با دقت در خود نگه می‌دارد. روزی که در آینده‌ای دور بازش کنی، لرزشِ همان روز هم یک‌جا فرو می‌ریزد."},"ICON-1783":{"nm":"نی تمرین تنفس آوازی","de":"تمرینِ فرستادنِ نفس، بلند و در یک رشته، از نوکِ لوله‌ای نازک. آواز، سرانجام، نفسی است که خوب مهار شده—این نی کوچک هر صبح آرام همین را می‌گوید. پیش از صدا، باد."},"ICON-1784":{"nm":"ژتون کلیک تمرین ریتم","de":"تیک، تیک، تیک—صادق‌ترین دوستِ دنیا. وقتی شتاب می‌گیری نگهت می‌دارد و وقتی کند می‌شوی پشتت را هل می‌دهد. حک‌کردنِ ریتم در بدن، چون گفتگویی طولانی با این ژتونِ استوار است."},"ICON-1785":{"nm":"روبان بررسی خط رقص","de":"کجا نوک انگشتان می‌ایستند و کجا شانه باز می‌شود—با یک روبان آرام خطِ حرکت را ردیابی می‌کنی. خطِ رقصی که خوب کشیده شده، حتی در جایی که از میان تماشاگران دیده نمی‌شود، صاف و منظم می‌ماند."},"ICON-1786":{"nm":"کارت بازخورد حالت چهره","de":"آن سخن که حتی خندیدن هم چیزی است که باید آموخت. برگی که زاویه‌ی گوشه‌ی چشم و ارتفاعِ گوشه‌ی لب را قدم‌به‌قدم می‌نویسد. حالتی که آینه نتوانست بگوید، این کارت به‌جای آن با مهربانی می‌گوید."},"ICON-1787":{"nm":"یادداشت جریان رپ","de":"«این‌جا کمی مکث کن، آن‌جا همه را بریز بیرون»—یادداشتی که از پیش، مسیرِ آبِ کلمات را ترسیم کرده. هرچه گذرگاه سریع‌تر باشد، مسیر نفس باید روشن‌تر باشد. در فلش‌های شتاب‌زده نوشته‌شده، ریتم یک بند زنده نفس می‌کشد."},"ICON-1788":{"nm":"برچسب دمای صدا","de":"صدا هم روزهای گرم و روزهای سرد دارد. نشانه‌ای کوچک که رگه‌ی امروز را با رنگ برمی‌گزینی و می‌چسبانی. با گرم و سرد شدنِ پیاپی، صدا هر روز در دمایی اندکی متفاوت بیدار می‌شود."},"ICON-1789":{"nm":"ژتون روتین استراحت","de":"سکه‌ای که با این سخن به دستت می‌دهند که استراحتِ خوب هم مهارتی است. آن را جلو بگیری، می‌توانی بی‌احساس گناه، دمی توقف کنی. برای کسی که پیوسته دویده، توقف، شجاعانه‌ترین انتخاب است."},"ICON-1790":{"nm":"سنجاق هدف رشد","de":"سنجاقی کوچک که با این جمله فرو رفته: «بیا تا این‌جا برویم.» هرچند دور به‌نظر برسد، هر روز یک گام به‌سویش رشد می‌کنی. هدف چیزی است مثل پیمانی مهربان که از دوردست دست تکان می‌دهد."},"ICON-1791":{"nm":"پاکت ارزیابی هفتگی","de":"عرق و اشکِ یک هفته را منظم در یک پاکت جمع می‌کنی و می‌دهی. آنچه خوب انجام شده و آنچه حسرت‌برانگیز است، کنار هم درون‌اند. بازکردنش تکلیفی کوچک است که به «خودِ هفته‌ی آینده» داده می‌شود."},"ICON-1792":{"nm":"قوطی قطعات تزئین صحنه","de":"پشت صحنه‌ی درخشان، قطعاتی بی‌نام زندگی می‌کنند. یک پیچ، یک حلقه گرد می‌آیند تا ستارگانِ سقف را معلق نگه دارند. قوطی را باز کنی، پر است از تلاش‌های کوچکی که بی‌صدا شکوه را برپا نگه داشته‌اند."},"ICON-1793":{"nm":"بورد کانسپت لباس","de":"تکه‌پارچه و رنگ را یکی‌یکی می‌چسبانی و لباسی را که هنوز در جهان نیست، از پیش می‌پوشی. لباس صحنه‌ای که نخست روی بورد کامل می‌شود. خیال همیشه یک قدم جلوتر از سوزن راه می‌رود."},"ICON-1794":{"nm":"ژتون تطبیق رنگ","de":"حتی لباس یکسان، بسته به نور، چهره‌ای کاملاً متفاوت دارد. کدام رنگ روشن‌ترین لبخند را با آن شخص می‌سازد، با نگه‌داشتن ژتون‌ها یکی‌یکی کنارش پیدا می‌شود. تناسب، کشفی است در پایان مقایسه‌ای طولانی."},"ICON-1795":{"nm":"تخته نمونه‌ی بندکفش","de":"آنچه یک گامِ استوار روی صحنه را ضمانت می‌کند، به‌طرزی شگفت‌آور بندی کوچک است. طوری‌که باز نشود، اما تنگ هم نباشد. مهربان‌ترین دغدغه در پایین‌ترین جا، از میان بندهایی با رگه‌های مختلف انتخاب می‌شود."},"ICON-1796":{"nm":"پاکت بازرسی اکسسوری","de":"هرچه چیزی بیشتر بدرخشد، یک خراش رویش عجیب بزرگ‌تر به‌نظر می‌رسد. دستی که زیورِ درون پاکت را زیر نور می‌گیرد و آرام وارسی می‌کند. دلی که چیزهای کوچک را تا آخر می‌نگرد، صحنه را نگهبانی می‌کند."},"ICON-1797":{"nm":"پچ رنگ مو","de":"نمونه‌ای کوچک برای پوشاندنِ فصلی تازه روی مو، از پیش. رنگی که آرام بر یک تار نشسته، آرام نخستین برداشت از کانسپتِ بعدی را نجوا می‌کند. تغییر همیشه از جایی به‌اندازه‌ی کف دست آغاز می‌شود."},"ICON-1798":{"nm":"کارت کانسپت ناخن","de":"برگی که نقشِ کوچکی را که باید روی ده نوک انگشت کشید، از پیش تعیین می‌کند. طوری‌که کانسپت حتی در یک اشاره‌ی دست به‌آرامی نمایان شود، حتی ریزترین جزئیات را با عشق به داستانی می‌آراید."},"ICON-1799":{"nm":"بلیت تغییر استایل","de":"«امروز کمی متفاوت از دیروز بشم؟»—بلیتی که همین یک خط را ممکن می‌کند. مو، لباس یا حال‌وهوا، این بلیت درِ هیجان‌انگیزِ رسیدن به چهره‌ای تازه را می‌گشاید."},"ICON-1800":{"nm":"برچسب اصلاح سایز","de":"برچسبی که جای تنگ‌کردن و گشادکردن را تا اندازه‌ی درست، با دقت یادداشت می‌کند. مثل آن دستِ کهن که لباسِ فرزند را بخیه‌به‌بخیه اصلاح می‌کرد، این تنظیمِ کوچک صحنه را یک وجب راحت‌تر می‌سازد."},"ICON-1801":{"nm":"کارت طرح خام بندانگشتی","de":"برگه‌ای که هنوز رنگ به آن نرسیده است. روی خطوط خشن مدادی، آرام حدس می‌زند صحنه‌ی بعدی به کجا جریان خواهد یافت. اتاق مونتاژ ساکت به‌آرامی یادآوری می‌کند که همیشه هیجان‌انگیزتر از اثر تمام‌شده، همین نخستین خط ناتمام است."},"ICON-1802":{"nm":"برچسب رضایت فیلم‌برداری","de":"«اجازه هست اینجا ثبت بشوم؟» به‌جای کلمات، یک نشان گرد کوچک روی سینه می‌چسبانی. یک برچسب کوچک، پیمانی مهربان میان دوربین و دل برقرار می‌کند."},"ICON-1803":{"nm":"سنجاق‌مکان دیوار عکس","de":"سنجاقی کوچک که در گوشه‌ی دیوار فرو رفته است. جایی است که از پیش تعیین می‌کند چه کسی کجا خواهد ایستاد. هر جا سنجاقی کاشته شود، لبخندی می‌ایستد و به یک عکس بدل می‌شود."},"ICON-1804":{"nm":"تراشه‌ی انتخاب نما","de":"انگشتی که از میان صدها نما، تنها یکی را نشان می‌زند. لحظه‌ای که این تراشه فرود می‌آید، همه‌ی حالت‌های کنارگذاشته‌شده گویی برای همان یک قاب زیسته‌اند. انتخاب‌کردن همیشه شبیه یک خداحافظی آرام است."},"ICON-1805":{"nm":"پاکت پشت‌صحنه","de":"هرچه پشت دوربین رخ می‌دهد، اینجا نگهداری می‌شود. لبه را که تا کنی، خنده و ان‌جی‌ها و خمیازه‌های خواب‌آلود همه با هم به خواب می‌روند. اغلب همین درونِ پاکت است که بیش از اثر اصلی عزیز می‌شود."},"ICON-1806":{"nm":"یادداشت درخواست ویرایش","de":"«اینجا یک ثانیه بیشتر، و موسیقی را کمی کم کن.» یادداشتی پر از خطوط قرمز. سخت‌گیریِ کسی، نفسِ ویدیو را ضربه‌ای دیگر می‌سنجد. کیفیت، بر همین دست‌کاری‌های کوچک می‌روید."},"ICON-1807":{"nm":"برچسب زمان‌بندی آپلود","de":"نشانی کوچک بر ویدیویی که فردا صبح ساعت هفت، خودش به‌تنهایی پا به دنیا می‌گذارد. حتی وقتی همه در خوابند، فقط این وعده بیدار می‌ماند. زمانی که از پیش تنظیم شده، دیر آمدن را نمی‌شناسد."},"ICON-1808":{"nm":"روکش قاب بندانگشتی","de":"پوششی که بهترین نخستین صحنه را در بر می‌گیرد. گوشه‌ها را چنان مرتب می‌بندد که نه اثر انگشتی و نه گردی به آن‌ها نرسد. تا پیش از نمایش، نخستین برداشت این‌گونه با ظرافت نگه داشته می‌شود."},"ICON-1809":{"nm":"تراشه‌ی طول فیلم","de":"تراشه‌ای کوچک که می‌سنجد امروز چند دقیقه فیلم گرفته شده است. نه بلندی همیشه خوب است و نه کوتاهی سبک‌سری. دلی که طول درست را می‌شناسد، نخستین دکمه‌ی ویرایش است."},"ICON-1810":{"nm":"برگه‌ی بازبینی شعار تشویق","de":"کاغذی که پیش از فریادزدن با تمام توان، یک‌بار دیگر بررسی می‌شود. اگر یک حرف جابه‌جا شود، هزاران صدا پراکنده می‌شوند. پشت هیاهوی تشویق، دستی نادیده از ویرایش پیش‌تر آنجا گذر کرده است."},"ICON-1811":{"nm":"جلد نگهداری فن‌آرت","de":"نقاشی‌ای که کسی تمام شب کشیده است. خانه‌ای شفاف به آن داده می‌شود تا چروک نخورد. گویی آنچه با دل کشیده شده باید با دل نگه داشته شود تا دوام بیاورد؛ جلد بی‌هیچ سخنی آن را در آغوش می‌گیرد."},"ICON-1812":{"nm":"نخ دسته‌بندی نامه‌ی طرفداران","de":"نخی که نامه‌های انبوه را بر اساس فرستنده مرتب می‌بندد. با هر گره، دلتنگی یک روز نظم می‌گیرد. حتی اگر پاسخی نتوان داد، دستی اینجاست که نمی‌گذارد حتی یک نامه از دست برود."},"ICON-1813":{"nm":"برگه‌ی ثبت‌نام مبادله‌ی کالا","de":"«کسی هست که بخواهد با مال من عوض کند؟» کاغذی که دلِ لرزانت را رویش می‌نویسی و پیش می‌گیری. فقط به این دلیل که چیز یکسانی را دوست دارند، دو غریبه برای لحظه‌ای دوست می‌شوند."},"ICON-1814":{"nm":"تراشه‌ی صندلی تشویق گروهی","de":"تراشه‌ای که جای نشستن کنار هم را برای افرادی با لباس هم‌رنگ تعیین می‌کند. وقتی دل‌های پراکنده در یک بخش گرد می‌آیند، جایگاه تماشاگران چون یک انسان عظیم به آواز درمی‌آید."},"ICON-1815":{"nm":"رسید تبلیغ تولد","de":"رسیدی که پس از به‌نمایش‌گذاشتن عشق روی تابلوی نورانی، به دست می‌گیری. آنچه کنار مبلغ نوشته نشده، دلسوزیِ گردآمده در طول شب است. این کاغذ تنها به‌عنوان گواه جشنی برای یک نفر باقی می‌ماند."},"ICON-1816":{"nm":"جلد کتاب پیام","de":"جلدی که کتابی گردآمده از دست‌خط افراد بسیار را می‌پوشاند. بازش کنی، خط‌های گوناگون در یک دل روی هم تا می‌خورند. بیرونش آراسته است، اما درونش پر از هیاهویی گرم است."},"ICON-1817":{"nm":"سنجاق عضویت باشگاه طرفداران","de":"سنجاقی کوچک که تنها به کسانی داده می‌شود که یک نام را صدا می‌زنند. لحظه‌ای که به سینه می‌زنیش، دوست‌داشتنیِ تنها به پیمانی جمعی بدل می‌شود. حس تعلق، شکلی این‌گونه گرد دارد."},"ICON-1818":{"nm":"توکن تشویق آنلاین","de":"نقطه‌ی نوری که دست‌های دور از هم، آن‌سوی صفحه تکان می‌دهند. فاصله هرچند دور باشد، ضرب‌آهنگ همان است. گواهی است بر اینکه حتی از جایگاه‌های نادیده، تشویق بی‌کم‌وکاست می‌رسد."},"ICON-1819":{"nm":"تکه‌ی کلید فرسوده","de":"تکه‌ای فلز با دندانه‌ای شکسته. دیگر هیچ‌کس به یاد نمی‌آورد کدام در را می‌گشوده است. آنچه از خودِ مکان قفل‌شده بیشتر دوام می‌آورد، همیشه همین نیمه‌ی بی‌مصرف یک کلید است."},"ICON-1820":{"nm":"نقشه‌ی راهروی مخفی","de":"کاغذی کهنه که مسیری پنهان پشت پیچک را رسم کرده است. میان‌بر را فقط کسانی می‌شناسند که می‌شناسند. لحظه‌ای که باز می‌شود، جزیره‌ای معمولی به‌آرامی چهره‌اش را به صحنه‌ی ماجراجویی تغییر می‌دهد."},"ICON-1821":{"nm":"کارت رمزگشایی","de":"کارتی که حروف درهم و پراکنده را به جای اصلی‌شان بازمی‌گرداند. وقتی یک سطر جفت شود، رازِ بعدی دست تکان می‌دهد. حتی گرهی که حل‌نشدنی به نظر می‌رسید، سرانجام از نخستین حرف آغاز می‌شود."},"ICON-1822":{"nm":"نخ جعبه‌ی مهروموم‌شده","de":"نخی که چنان محکم بسته شده که گویی می‌گوید باز نکن. تنها کسی که آن را بسته می‌داند در گره چه خفته است. آرزوی گشودن و آرزوی حفاظت، هر دو در این یک رشته کنار هم گره خورده‌اند."},"ICON-1823":{"nm":"تراشه‌ی پازل ویرانه","de":"تکه‌ای کوچک که از دیواری سنگی و کهن جدا شده است. آن را سرجایش بگذاری، هنر کسی از هزار سال پیش در سر انگشتانت زنده می‌شود. گردآوردن آنچه پراکنده است، کاری است برای پیوند دوباره‌ی زمان."},"ICON-1824":{"nm":"بریده‌ی افسانه‌ی جزیره","de":"کاغذی که افسانه‌های سرگردان در جزیره را با دست رونویسی کرده است. راست بودن یا نبودنش چندان مهم نیست. داستانی که از دهانی به دهان دیگر رسیده، خود به حلقه‌ای در تنه‌ی درختِ عمر جزیره بدل می‌شود."},"ICON-1825":{"nm":"سنگ نشانه‌ی پنهان","de":"سنگی که انگار بی‌قصد کنار راه افتاده است. تنها در چشم کسی که می‌داند، آرام جهت را نشان می‌دهد. هرچه رازی عمیق‌تر بخواهد پنهان بماند، با ساده‌ترین چهره همان‌جا می‌ایستد."},"ICON-1826":{"nm":"پاکت معما","de":"روی پاکت هیچ نوشته نشده است. همین لحظه‌ی کوتاه پیش از پاره‌کردن مهر، هیجان‌انگیزترین لحظه است. تا پاسخ در دست نیامده، همه‌ی امکان‌ها هنوز درون پاکت زنده‌اند."},"ICON-1827":{"nm":"درپوش ذره‌بین کارآگاه","de":"کلاهکی کوچک که به‌آرامی روی نوک ذره‌بین جا می‌گیرد. وقتی نگاهی از آن گذر نمی‌کند، لنز را در سکوت به استراحت می‌گذارد. کارآگاه زود می‌آموزد که برای دیدنِ خوب، نخست باید خوب نگهداری کرد."},"ICON-1828":{"nm":"بلیت اتوبوس دوار جزیره","de":"یک بلیت برای سوارشدن به اتوبوسی که یک دور کامل جزیره را می‌پیماید. ایستگاه آخر، دوباره نقطه‌ی آغاز است. روی جاده‌ای که چرخ می‌زند و به همان‌جا بازمی‌گردد، منظره هر بار اندکی تازه به نظر می‌رسد."},"ICON-1829":{"nm":"برچسب اجاره‌ی دوچرخه","de":"برچسبی آویزان از دسته‌ی دوچرخه‌ای قرضی. تا زمان بازگرداندن، آزادیِ کوتاهی مجاز شمرده می‌شود. وقتی زمانِ شکافتنِ باد به پایان می‌رسد، همین برچسب آرام آن پیمان را پس می‌گیرد."},"ICON-1830":{"nm":"بلیت سوارشدن به قایق کوچک","de":"بلیتی برای سوارشدن به یک قایق کوچک. روی عرشه‌ی لرزان، فاصله‌ی میان دو جزیره کوتاه‌تر می‌شود. عبور از آبراه همیشه اندکی هیجان و اندکی دلبه‌همخوردگی را با هم می‌آورد."},"ICON-1831":{"nm":"میخ‌پرچ چرخ گاری","de":"میخ‌پرچی که چرخ گاری را محکم نگه می‌دارد. همین یک قطعه‌ی کوچک فلزی است که بار سنگین را در حرکت نگه می‌دارد. کم‌دیده‌ترین قطعه، اغلب همان است که بیشترین وزن را در سکوت تحمل می‌کند."},"ICON-1832":{"nm":"توکن تله‌کابین","de":"توکنی گرد که در تله‌کابینِ شکافنده‌ی آسمان می‌اندازی. لحظه‌ای که پاها زمین را ترک می‌کنند، تمام جزیره در یک نگاه در آغوش گرفته می‌شود. هرچه بالاتر بروی، منظره سخاوتمندتر می‌شود."},"ICON-1833":{"nm":"بند سوارشدن به بالن هوای گرم","de":"بندی که پیش از سوارشدن به سبد، به مچ می‌بندی. وقتی شعله متورم می‌شود و زمین دور می‌گردد، دل هم به همراهش سبک می‌شود. اوج‌گرفتن یعنی برای لحظه‌ای وزن را بر زمین گذاشتن."},"ICON-1834":{"nm":"تراشه‌ی فراخوان تاکسی آبی","de":"تراشه‌ای کوچک برای صداکردن تاکسی‌ای که روی آب می‌دود. دست بلند کنی، قایقی شکافنده‌ی جریان نزدیک می‌شود. آنچه حتی در بی‌راهه راهی می‌گشاید، در نهایت شجاعت کسی است که نخست صدا می‌زند."},"ICON-1835":{"nm":"پاس ورودی مسیر کوهنوردی","de":"پاسی که در نخستین دروازه‌ی ورود به کوه به دست داده می‌شود. از اینجا به بعد، نوک پا مسیر را تعیین می‌کند. قله شاید دور باشد، اما تنها کسی که از این دروازه گذشته، آن منظره را وعده گرفته است."},"ICON-1836":{"nm":"کلید کمد بندرگاه","de":"کلیدی کوچک که کمدی کنار اسکله را می‌گشاید. با دستانی سبک‌شده پس از سپردن بار، به دریا چشم می‌دوزی. داشتن جایی برای گذاشتن بار برای مدتی، همان چیزی است که شجاعت سفر به دوردست را وام می‌دهد."},"ICON-1837":{"nm":"درپوش شیشه‌ی ترشی","de":"درپوشی که همه‌ی چیزهای ترش را در خود محبوس می‌کند. اگر محکم بسته شود، خیارهای تابستان تا زمستان طراوتشان را نگه می‌دارند. راز غلبه بر زمان، در نهایت از خوب‌بستن آغاز می‌شود."},"ICON-1838":{"nm":"برچسب توری خشک‌کن","de":"برچسبی که به چیزهای پهن‌شده روی توری برای خشک‌شدن می‌چسبانند. اگر بنویسی چه چیزی کِی پهن شده، انتظار از هم نمی‌پاشد. حتی در زمانِ آفتاب و باد، چیزی به نام نوبت لازم است."},"ICON-1839":{"nm":"پاکت تراشه‌ی دودی","de":"پاکتی که تراشه‌های چوب خوشبو را در خود نگه می‌دارد. دهانه را که باز کنی، رایحه‌ای شبیه آتشِ اردو نخست به بینی سلام می‌کند. طعمی که با دود عمیق شده، تنها به‌آرامی برای کسی می‌گشاید که انتظار را می‌شناسد."},"ICON-1840":{"nm":"برچسب غذای نگهداری‌شده","de":"برچسبی که برای گذراندن خوش یک سال، به خمره می‌چسبانند. روز خمیرشدن و دلسوزی روی آن نوشته می‌شود. غذایی که مدتی طولانی نگه داشته و خورده می‌شود، همیشه یادداشتی کوچک همراه دارد که می‌خواهد طعم دستِ آن روز را به یاد بسپارد."},"ICON-1841":{"nm":"برچسب ساعت تخمیر","de":"تخمیر به ساعت اعتماد ندارد. زیرا زمان را نه با عقربه‌ی دقیقه‌شمار، بلکه با رایحه می‌سنجد. لحظه‌ای که بویی ترش به بینی می‌رسد، برچسب در سکوت سر تکان می‌دهد: «حالا آماده است.» حتی انتظار هم خط‌کش خودش را دارد."},"ICON-1842":{"nm":"سنجاق دسته‌بندی طبقه‌ی یخچال","de":"پلیس راهنمایی کوچک یخچال همین‌جاست. سبزیجات بالا، خورش‌ها پایین، باقی‌مانده‌ی دیروز در ردیف جلو. یک سنجاق را که بکاری، دستی که هر بار در باز کردن یخچال سرگردان بود، به‌زودی راه را می‌شناسد."},"ICON-1843":{"nm":"بند گرم‌نگه‌دار جعبه‌ناهار","de":"مادر دور جعبه‌ی ناهار بندی می‌بست تا گرما تا ظهر فرار نکند. بند را باز می‌کردی و زیر درپوشِ بخارگرفته، دلسوزیِ صبح هنوز گرم دراز کشیده و منتظرم بود."},"ICON-1844":{"nm":"شیشه‌ی رسیدن سس","de":"چاشنیِ خوب هرگز عجله نمی‌کند. این کار، بخشیدن زمانی آرام است تا سویا و سیر در یکدیگر رخنه کنند. در تاریکیِ شیشه، طعم به‌آرامی عمیق می‌شود و خردِ کندِ ایوانِ خمره‌ها به شیشه‌ای کوچک نقل‌مکان می‌کند."},"ICON-1845":{"nm":"برچسب مربای فصلی","de":"بهار توت‌فرنگی، تابستان زردآلو، پاییز انجیر. یک برچسب فصل را با خط منظم روی شیشه می‌نویسد. در دل زمستان درپوش را باز کنی، آفتابِ پارسال قاشق‌به‌قاشق و آهسته آب می‌شود و بیرون می‌آید."},"ICON-1846":{"nm":"تخته‌نشان درصد گردآوری","de":"لازم نیست به‌زحمت بشماری چند تا گردآورده‌ای، چون تخته‌نشان به‌جای تو فخر می‌فروشد. با پرشدن هر خانه‌ی خالی، شانه‌ها اندکی بالا می‌رود—این عدد نیست، رد پایی است که با نوک پا زده شده."},"ICON-1847":{"nm":"کارت جایگاه کشف‌نشده","de":"جایی که هنوز ملاقات نکرده‌ای. سایه‌روشنِ درون کارت با طرحی محو، وعده‌ای پیش می‌کشد. خالی‌بودن یعنی به‌زودی پرشدن، پس هیجان همیشه به شکل علامت سؤال منتظر توست."},"ICON-1848":{"nm":"مهر تکمیل دانشنامه","de":"آن صدای «تاپ» فرودآمدن مهر بر آخرین خانه. دانشنامه را که ببندی و کف دست را باز کنی، نقطه‌ای جوهر قرمز چون مدال تکمیل به آن چسبیده است. آن آرامش عمیقی که فقط کسی می‌شناسد که تا انتها گردآورده است."},"ICON-1849":{"nm":"تراشه‌ی رنگِ کمیابی","de":"حتی با شکلی یکسان، اگر رنگ فرق کند، داستان فرق می‌کند. یک تراشه به‌آرامی مرزی میان معمولی و گران‌بها می‌کشد. چشم گردآورنده همیشه پیش از آن تفاوت ظریف رنگ، مدتی طولانی می‌ایستد."},"ICON-1850":{"nm":"کوپن مبادله‌ی گردآورده‌ی تکراری","de":"باز هم همان، باز هم. روزی که برای سومین بار چیزی را برداشتی که از قبل داشتی، این کوپن به‌آرامی دست دراز کرد. گویی دلداری‌ای مهربان که می‌گوید: تکراری هم اگر دور انداخته نشود و در آغوش گرفته شود، روزی به‌شکل چیزی گران‌بها بازمی‌گردد."},"ICON-1851":{"nm":"پلاک شماره‌ی جعبه‌ی گردآوری","de":"به هر جعبه شماره‌ای بدهی، انبار به کتابخانه‌ای کوچک بدل می‌شود. شماره‌ی هفده چیزهای بهار، شماره‌ی بیست‌وسه چیزهای کنار دریا را در خود دارد. من فهرستی خاموشم که خاطرات پراکنده را سطر به سطر مرتب می‌کند."},"ICON-1852":{"nm":"راهنمای چیدمان نمایش","de":"نیمی از نمایش را جانمایی می‌سازد. بلندقدها به پشت، درخشان‌ها به مرکز. به‌دنبال راهنما دست‌به‌کار شوی و جابه‌جا کنی، قفسه‌ی درهم‌ریخته به‌زودی چون گالری کوچکی نفسی تازه می‌کند."},"ICON-1853":{"nm":"گردگیر گردآورده","de":"هرچه چیزی عزیزتر باشد، گرد بهتر روی آن می‌نشیند. با نوک نرم برس، به‌آرامی، حتی احساس تقصیرِ مدت‌ها نگاه‌نکردن را نیز می‌روبی. در حین پاک‌کردن، خاطرات به‌خواب‌رفته نیز برای لحظه‌ای دوباره می‌درخشند."},"ICON-1854":{"nm":"کوپن گسترش سقف نگهداری","de":"هرچه بیشتر گردآوری کنی، کمبود جا هم دغدغه‌ای شیرین می‌شود. آسودگیِ آرامی که در دیدن یک قفسه‌ی افزوده حس می‌کنی—این طمع نیست، گواهی است بر آنکه چقدر دوست‌داشتنی داری."},"ICON-1855":{"nm":"کارت کد دعوت دوست","de":"دادن این کد، مهربان‌ترین دعوت‌نامه است که می‌گوید «بیا با هم بازی کنیم.» دلی که در چند رقم جای گرفته است. تنها زمانی که دوستِ گیرنده پا به جزیره می‌گذارد، داستانی فقط برای شما دو نفر آغاز می‌شود."},"ICON-1856":{"nm":"کلید انبار مشترک","de":"در انبار هرگز به‌تنهایی گشوده نمی‌شود. قفلی که تنها زمانی می‌چرخد که دو دست، دست تو و دست من، کنار هم بیایند. فضایی مشترک همیشه پیمانی مشترک را در خود دارد که به شکل کلید آویزان است."},"ICON-1857":{"nm":"برچسب گزارش شیء گمشده","de":"چیز گم‌شده هم برای کسی عزیز است. نوشتنِ یک سطر «اینجا هستم» و آویختنش—این برچسب رشته‌ای کوچک است که برای لحظه‌ای دلِ راه‌گم‌کرده را دوباره آرام به صاحبش پیوند می‌دهد."},"ICON-1858":{"nm":"پرچم درخواست کمک","de":"گفتن «کمکم کن» ضعف نیست، شجاعت است. پرچم که بالا برود، از جایی کسی می‌دود. آنچه در این جزیره سریع‌تر از هر شایعه‌ای پخش می‌شود، دستی است که به‌سوی دیگری دراز می‌شود."},"ICON-1859":{"nm":"دستبند تماس اضطراری","de":"آسودگیِ کوچکی که به مچ می‌بندی. هر اتفاقی بیفتد، شماره‌ای که اینجا نوشته شده، پیش از هرکس می‌دود. همراهی خاموش که در روزهای عادی فراموش می‌شود اما درست در لحظه‌ی نیاز، دلگرم‌کننده‌ترین می‌گردد."},"ICON-1860":{"nm":"تراشه‌ی تقسیم وظیفه","de":"چه کسی خرید کند و چه کسی آشپزی، تراشه‌ها را که تقسیم کنید، دعوایی باقی نمی‌ماند. نخستین گام ساختن چیزی با هم، از تعیین مهربانانه‌ی سهم هرکس آغاز می‌شود."},"ICON-1861":{"nm":"برگه‌ی ساخت مشترک","de":"کاری که تنها هرگز جرأتش را نداشتی، وقتی جمعی گرد هم می‌آیند، چون معجزه ممکن می‌شود. هرچه نام‌ها یک‌به‌یک روی برگه پر شود، خانه‌های خالی کم می‌شود و خنده بیشتر. همکاری در سکوت، میان خانه‌ها رشد می‌کند."},"ICON-1862":{"nm":"کارت آداب مهمانی","de":"وقتی به خانه‌ی دیگری قدم می‌گذاری، از نوک پا محتاط می‌شوی. آنچه روی کارت نوشته شده، قواعدی بزرگ نیست، فقط پیمان‌های کوچک و گرمی چون «کفش‌ها را مرتب بگذار، اول سلام کن»."},"ICON-1863":{"nm":"زنگ پایان مهمانی","de":"حتی شادی هم باید پایانی داشته باشد تا بعدی منتظرش بمانند. زنگ که «دینگ» بنوازد، همه با چهره‌ای دلتنگ وسایلشان را جمع می‌کنند. مهمانی‌ای که شیوه‌ی خوب خداحافظی‌کردن را می‌داند، طولانی‌ترین اثر را در دل می‌گذارد."},"ICON-1864":{"nm":"بند گوشه‌ی تشک","de":"هرچه لحاف را صاف پهن کنی، گوشه‌ها باز هم بلند می‌شوند. به‌لطف بندی که چهار گوشه را محکم می‌گیرد، تخت هر صبح چون اتاق هتلی مرتب چشم می‌گشاید."},"ICON-1865":{"nm":"بند دکمه‌ی یقه‌ی لحاف","de":"من بند دکمه‌ای هستم که یقه‌ی لحاف را نگه می‌دارم. هرقدر که شب غلت بزنی، محکم می‌گیرم تا یقه فرار نکند. لحافی که هنگام بیدارشدن حتی یک چروک هم ندارد، همان پاداش نگهبانیِ تمام‌شبِ من است."},"ICON-1866":{"nm":"گیره‌ی ثابت‌کننده‌ی روتختی نرم","de":"تاپر هر فرصتی پیدا کند، آرام‌آرام می‌خواهد بلغزد. هر بار گیره گوشه را محکم گاز می‌گیرد و جایش را نگه می‌دارد. یک لجباز خاموش که از گوشه‌ای نادیده، رختخواب را منظم نگه می‌دارد."},"ICON-1867":{"nm":"صاف‌کننده‌ی چروک ملحفه","de":"چروک‌های ریزی که ملحفه در طول شب می‌گیرد، به‌نوعی شبیه چین‌های دلند. مثل پارچه‌ای که با یک کشیدنِ صاف‌کننده صاف می‌شود، کاش روزی درهم‌ریخته هم این‌گونه با ظرافت اتو بخورد."},"ICON-1868":{"nm":"پایه‌ی تهویه‌ی تشک","de":"حتی تشک هم به فرصتی برای نفس‌کشیدن نیاز دارد. وقتی پایه از زیر راهی برای باد می‌گشاید، رطوبت بیرون می‌رود و خشکی نفوذ می‌کند. خوابِ خوب، آرام از همان هوایی آغاز می‌شود که پشتت را نگه داشته است."},"ICON-1869":{"nm":"روکش زیپ روکش لحاف","de":"آن آشوب نیمه‌شب که هنگام تعویض روکش لحاف، پنبه پیوسته بیرون می‌زند. زیپ را یک‌بار با روکشی بپوشانی، دیگر خطر بیدارشدن با گیرکردن پا هم نیست. آرامشی بزرگ که یک روکش کوچک به همراه می‌آورد."},"ICON-1870":{"nm":"پد ضدتوده‌شدن پر","de":"پرِ بالش به‌زودی به یک‌سو انباشته می‌شود و تپه‌ای کوچک می‌سازد. وقتی پد در سکوت میان آن‌ها می‌ایستد، صافی تا آخر باقی می‌ماند. به‌لطف آن، هر شب نرمیِ چون‌نو بی‌کم‌وکاست بازمی‌گردد."},"ICON-1871":{"nm":"قلاب کشسان ملحفه‌ی تخت","de":"ملحفه همیشه می‌خواهد آرام‌آرام از یک‌سو کنار برود. گوشه‌ها را با قلاب بیاویزی و محکم بکشی، هرچند شب غلت بزنی هم تکان نمی‌خورد. کشیدگی این‌گونه آرام، زیربنای خوابی عمیق می‌شود."},"ICON-1872":{"nm":"برچسب تعویض روبالشی","de":"وقتی ناگهان مطمئن نیستی امروز روبالشی را شسته‌ای یا نه، یک برچسب پاسخی روشن می‌دهد. برنامه‌ای که با خواب و خواب دوباره پیوسته فراموش می‌شود، همین نشان کوچک به‌جای تو با دقت به یاد می‌سپارد."},"ICON-1873":{"nm":"نشانه‌ی دفتر رؤیا","de":"رؤیایی که همین لحظه‌ی بیداری از میان انگشتانت پراکنده می‌شود، نشانه در صفحه‌ای که نشان کرده نگهش می‌دارد. بازش کنی، دریای دیشب و آسمانش هنوز همان‌جاست—پلی کوچک که آرام میان خواب و نوشتن گذاشته شده."},"ICON-1874":{"nm":"سنگریزه‌ی نوفه‌ی سفید","de":"شبی بیش از حد ساکت، اغلب بیشتر بیدارت می‌کند. وقتی سنگریزه صدایی نرم چون خش‌خش باران رها می‌کند، دل آرام‌آرام در امتداد آن رگه فرو می‌نشیند. سنگی کوچک که سکوت را به‌آرامی نوازش می‌کند."},"ICON-1875":{"nm":"تراشه‌ی خواب حسگر دما","de":"در خواب که پیشانی گرم است یا نوک پا سرد، تراشه در کنارت به‌آرامی می‌پاید. به‌لطف نگهبان شبی که دمای دقیقِ بدنت را در سکوت می‌یابد، خواب بی‌آنکه بیدار شوی تا سپیده‌دم جاری می‌ماند."},"ICON-1876":{"nm":"گیره‌ی پرده‌ی بلک‌اوت","de":"نور صبحگاهی چه‌قدر پرکار است که پیوسته از شکاف پرده می‌گذرد و می‌آید. دو سر را با گیره محکم گاز بگیری، اتاق دوباره چون دل شب سیاه می‌شود. همدست دلگرم برای یک بار دیگر خواب ماندن."},"ICON-1877":{"nm":"چراغ پرتاب‌کننده‌ی نور مهتاب","de":"چراغ را خاموش کنی، ماه روی سقف طلوع می‌کند. نور نرمی که چراغ به بالا می‌تاباند، اتاق را به آسمان شبی کوچک بدل می‌کند. همان دلی که با نگاه به ماه به خواب می‌رفت، درست کنار بالینت نگه داشته می‌شود."},"ICON-1878":{"nm":"آویز کیسه‌ی رایحه‌ی خواب","de":"کیسه‌ای که رایحه‌ی اسطوخودوس و علف در خود دارد، کنار بالین به‌آرامی تاب می‌خورد. رایحه‌ای که به بینی نفوذ می‌کند، شانه‌ها را آهسته باز می‌کند و یک کیسه‌ی رایحه پیش از بالش هم خواب را دعوت می‌کند."},"ICON-1879":{"nm":"سنجاق جعبه‌موسیقی لالایی","de":"فنر را به‌آرامی کوک کنی، ملودی‌ای کوچک باز می‌شود. لالایی‌ای که از نوک سنجاق می‌چرخد و بیرون می‌آید، به همان ضرب‌آهنگی می‌ماند که مادربزرگ پشتت را نوازش می‌کرد. هر نُت آرام‌آرام پلک‌هایت را سنگین می‌کند."},"ICON-1880":{"nm":"لیوان گیاه رطوبتی","de":"من لیوانی هستم که گیاه را به‌جای خاک، با آب زلال می‌رویانم. به ریشه‌های نازکی که در آب شناورند نگاه کنی، هوای اتاق هم اندکی مرطوب‌تر می‌شود. چاهی سبز و کوچک که روی میز جمع شده است."},"ICON-1881":{"nm":"بطری گردآوری تکه‌ی رؤیا","de":"رؤیایی که در خواب فرومی‌ریزد شکلی ندارد، و همین که بیدار شوی از میان انگشتانت نشت می‌کند. تکه‌ای در حال محوشدن را با درپوش بطری آرام مسدود کردن، نگه‌داشتنش تا صبح—آرزوی به‌یادسپردن، از همین اندازه‌ی کوچک آغاز می‌شود."},"ICON-1882":{"nm":"سینی عینک بالینی","de":"لحظه‌ای که عینک را برمی‌داری و می‌گذاری، به‌طرزی عجیب، خستگیِ یک روز هم همراهش پایین می‌آید. این جای کوچک کنار بالین، برای پذیرفتن همان یک حرکت آنجاست. سینی‌ای که پیش از خواب، جهان را در سکوت محو می‌کند."},"ICON-1883":{"nm":"زیرلیوانی حلقه‌ای پاتختی","de":"یک جای رد گرد که لیوان آب برجای می‌گذارد، شاید کوچک به‌نظر برسد، اما بر رگه‌ی چوب پاتختی لکه‌ای است. یک حلقه‌ی کوچک که برای جلوگیری از آن جا می‌گیرد. دلسوزی همیشه در همین جاهای نادیده، در سکوت کار می‌کند."},"ICON-1884":{"nm":"گوشه‌گیر تاکردن لحاف","de":"حتی تاکردن مربعیِ لحاف هم رگه‌ای دارد. با این ابزار گوشه‌گیر که گوشه‌ها را جفت کنی، حتی دلی درهم‌ریخته هم یک‌بار صاف می‌شود. فضایی مرتب، مؤدبانه‌ترین سلام برای گشودن روز است."},"ICON-1885":{"nm":"قلاب بالینی سیم شارژ","de":"قلابی آویخته کنار بالین، چون از این بیزار بودم که سیم شارژ تمام شب آرام‌آرام روی زمین بلغزد. سیمی که در خواب تو در سکوت پر از انرژی می‌شود، صبح پر و کامل منتظر سرانگشتانت می‌ماند."},"ICON-1886":{"nm":"سبد تنقلات بالینی","de":"سبدی که تنقلات محبوب را در دسترس دست گرد آورده است. آماده‌سازی‌ای مهربان که از پیش گرسنگیِ نیمه‌شب را حدس زده است. صدای خش‌خشِ برداشتن یک دانه در تاریکی، بی‌دلیل صمیمی است."},"ICON-1887":{"nm":"بال نگهدارنده‌ی کتاب خواب","de":"بالی که صفحه‌ی باز کتاب را به‌آرامی نگه می‌دارد تا حتی با هجومِ خواب‌آلودگی، خطی که می‌خوانی گم نشود. همان صفحه‌ای که درست پیش از بسته‌شدن چشم‌ها بستی، فردا شب در همان جا منتظرت می‌ماند."},"ICON-1888":{"nm":"پایه‌سنگی ساعت‌زنگ‌دار بالینی","de":"حتی ساعت زنگ‌داری که صبح را بیدار می‌کند هم به جایی ثابت و بی‌لرزش نیاز دارد. پایه‌سنگی گرد، وزن آن را سنگین می‌پذیرد و همچون پیمانی که حتی با آمدن سپیده‌دم نمی‌لغزد، جایش را نگه می‌دارد."},"ICON-1889":{"nm":"میخ آویز چشم‌بند خواب","de":"میخی برای آویختن چشم‌بندی که تمام شب نور را مسدود کرده، تا در طول روز نفس بکشد. دادنِ جایی خشک به پارچه‌ای که وظیفه‌اش را تمام کرده—مراقبتی کوچک این‌گونه بی‌هیچ لکه‌ای نفوذ می‌کند."},"ICON-1890":{"nm":"گیره‌ی چراغ‌قوه‌ی بالینی","de":"گیره‌ای که نور کوچکِ لازم در دل شب را به سویی که می‌خواهی نگه می‌دارد. چراغ‌قوه را به لبه‌ی تخت گاز بگیری، دستی که در تاریکی کورمال‌کورمال می‌گشت، بسیار آسوده‌تر می‌شود. لمسی که جهت نور را تعیین می‌کند."},"ICON-1891":{"nm":"بند حلقه‌ای پرده‌ی جداکننده","de":"بندی حلقه‌ای که پرده‌ی جداکننده‌ی فضای مشترک را نگه می‌دارد. تنها یک تکه پارچه‌ی نازک است، اما آن‌سوی آن، شبِ خصوصی کسی است. مرزی مهربان که در اتاقی مشترک، خواب یکدیگر را نگهبانی می‌کند."},"ICON-1892":{"nm":"تخته‌چوب تقسیم پریز مشترک","de":"تخته‌چوبی که ساخته شده تا یک پریز تنها را چند نفر با هم به کار ببرند. برق را یکسان می‌گرداند تا شب هیچ‌کس تاریک نماند. زندگیِ مشترک، سرانجام از همین تقسیم چیزهای کوچک آغاز می‌شود."},"ICON-1893":{"nm":"سنگ چشم‌پوشیِ روشنایی","de":"وقتی نور بیش از حد روشن است، به‌جای کلمه، آرام سنگی پیش می‌دهی. «می‌شود کمی کمش کنی؟» این یک چیز کوچک، آن یک جمله را به‌جای تو می‌رساند. مؤدبانه‌ترین درخواست در اتاقی مشترک."},"ICON-1894":{"nm":"توکن چشم‌پوشیِ زمان بیداری","de":"کارتی کوچک که روی کف دست کسی که زودتر بیدار می‌شود گذاشته می‌شود. اینکه چه کسی خواب سپیده‌دم بیشتری بگیرد و چه کسی زودتر بیدار شود را، بی‌هیچ دعوایی همین توکن تعیین می‌کند. دلی که نوبتِ چشم‌پوشی را با سرانگشت تعیین می‌کند."},"ICON-1895":{"nm":"حلقه‌شماره‌ی چوب‌لباسی مشترک","de":"حلقه‌های شماره‌دار که به چوب‌لباسی‌های مشترک بسته شده‌اند. تا کسی گیج نشود جای کدام‌یک است، یک عدد کوچک به‌آرامی نظم می‌سازد. خطی مهربان کشیده‌شده در زندگی روزمره‌ای که به‌راحتی به هم می‌آمیزد."},"ICON-1896":{"nm":"کلاهک پله‌ی تخت دوطبقه","de":"کلاهکی که روی پله‌ی صعود به طبقه‌ی بالا نصب می‌شود. تا پای برهنه‌ای که به آن می‌رسد نه سرد باشد نه لغزنده، ایمنیِ یک پله را برعهده می‌گیرد. همین مراقبتِ کوچک در انتهای نردبان، رؤیاهای طبقه‌ی بالا را استوار نگه می‌دارد."},"ICON-1897":{"nm":"بازوی نگهدارنده‌ی دستمال‌کاغذی مشترک","de":"نگهدارنده‌ای بازوشکل برای آویختن دستمال‌کاغذی توالت مشترک. جایی گرفته که هرکس بتواند با یک دست، یک برگ را به‌راحتی بکشد. شاید کوچک به‌نظر برسد، اما لمسی است که صبح‌های بسیاری را روان می‌کند."},"ICON-1898":{"nm":"تراشه‌ی نوبت خوشبوکننده‌ی هوا","de":"تراشه‌ای که نوشته نوبت چه کسی است که خوشبوکننده را دوباره پر کند. حتی رشته‌ای کم‌رنگ از عطر هم پیمانی است برای مسئولیت‌پذیریِ نوبتی. بوی خوش رایگان نمی‌آید، بلکه در نوبتِ کسی می‌شکفد."},"ICON-1899":{"nm":"دستگیره‌ی چراغ‌خواب مشترک","de":"دستگیره‌ی چراغ‌خوابی که چند نفر با هم روشن و خاموش می‌کنند. دستی که تا دیرترین لحظه بیدار مانده، آخرین بار نور را جمع می‌کند. پیمانی خاموش از کسانی که یک اتاق را به اشتراک می‌گذارند، و نوری نرم را دست‌به‌دست می‌کنند."},"ICON-1900":{"nm":"گودی لیوان دسته‌ی مبل","de":"جای گرد لیوان که در دسته‌ی مبل کنده شده است. برای لحظه‌ای لیوان را از دست بگذاری هم نگران ریختن نیستی. جایی برای استراحت، باید جایی هم برای گذاشتن یک لیوان داشته باشد تا سرانجام دل بتواند آسوده دراز بکشد."},"ICON-1901":{"nm":"دستگیره زیپ روکش کوسن","de":"دستگیره‌ای کوچک که به زیپ بازوبسته‌شوندهٔ روکش داخلی کوسن وصل شده است. یک حلقهٔ کوچک، زحمت تعویض روکش را کم می‌کند. توجه به عمق پنهان و نادیدنی—مهربانی خانه‌داری همیشه همان‌جا پنهان است."},"ICON-1902":{"nm":"کوسن گوه‌ای پشتی مبل","de":"کوسنی که شکاف پشتی را پر می‌کند و کمر را نگه می‌دارد. جای خالی را پر می‌کند تا حتی بعد از نشستنی طولانی، کمر درد نگیرد. آسایشی که بدن در همان لحظهٔ تکیه‌دادن، پیش از هر چیز آن را می‌شناسد و می‌گوید «آه، همین بود»."},"ICON-1903":{"nm":"بند نگه‌دارندهٔ گوشهٔ کوسن نشیمن","de":"کوسن نشیمنی که هر بار جابه‌جا می‌شد و آرام‌آرام کنار می‌رفت، حالا با بندی از گوشه‌ها محکم نگه داشته می‌شود. آن را در یک‌جا ثابت می‌کند تا نلغزد. نظم و ترتیب، از همین محکم‌کاری‌های کوچک و سرسختانه آغاز می‌شود."},"ICON-1904":{"nm":"نوار محافظ درز کوسن","de":"اولین جایی که در کوسن فرسوده می‌شود، همیشه درز گوشه‌هاست. نواری محافظ که از پیش دور آن جا پیچیده می‌شود تا از پارگی محافظت کند. دلی که می‌خواهد کوسن را مدت‌ها کنار خود نگه دارد، مثل کوک‌های محکم، استوار است."},"ICON-1905":{"nm":"جیب کنترل‌از‌راه‌دور لای مبل","de":"کنترلی که پیوسته میان کوسن‌ها گم می‌شد، سرانجام خانهٔ خودش را پیدا کرد؛ جیبی کوچک که در شکاف مبل جا می‌گیرد. دانستن این‌که چیزی که فکر می‌کردی گم شده، همیشه همان‌جاست، دلگرمی‌ای بزرگ‌تر از آن چیزی است که فکرش را می‌کردی."},"ICON-1906":{"nm":"بند پیچش پتوی زانو","de":"بندی برای پیچیدن و بستن پتوی زانو. گرمایی که وقتی پهن رها می‌شود پراکنده می‌گردد، برای شب بعد مرتب و منظم جمع می‌شود. اگر گرما را این‌گونه نگه داری، فردا هم می‌توانی دوباره آن را بیرون بیاوری و روی خود بکشی."},"ICON-1907":{"nm":"دکمهٔ روکش زیرپایی","de":"دکمه‌ای که روکش زیرپایی -جایی که پاها زودتر از همه فرسوده‌اش می‌کنند- را می‌بندد تا تعویضش آسان باشد. همان یک تِک‌بستن، عمر پارچه را طولانی‌تر می‌کند. دلی که می‌خواهد چیزها را مدت‌ها استفاده کند، در جزئیات کوچک هم موشکاف است."},"ICON-1908":{"nm":"کلاهک لغزندهٔ پایهٔ مبل","de":"حتی مبل سنگین هم نباید کف زمین را بخراشد. کلاهکی نرم که روی هر چهار پایه کشیده می‌شود، آرام‌آرام و با احتیاط کف چوبی را مراقبت می‌کند. اثاثیه‌ای که تا نوک پا هم محتاط باشد، به‌نوعی محبت بیشتری برمی‌انگیزد."},"ICON-1909":{"nm":"جاکنترلی دسته‌جمعی","de":"جایی که کنترل‌هایی را که هر کدام به‌سویی می‌غلتیدند و پراکنده می‌شدند، کنار هم و مرتب می‌ایستاند. وقتی میله‌های بلند و کوتاه در یک ردیف صاف می‌ایستند، همین کافی است تا هوای اتاق یک درجه آرام‌تر شود."},"ICON-1910":{"nm":"قلاب شارژ دسته بازی","de":"قلابی برای آویزان‌کردن و شارژ دستهٔ بازی، بعد از یک دور بازی پرشور. تا وقتی آویزان است و آرام انرژی می‌گیرد، دست‌ها هم لحظه‌ای استراحت می‌کنند. همین یک مکث کوتاه، دور بعدی را با اطمینان آماده می‌کند."},"ICON-1911":{"nm":"کیسهٔ مهره‌های بازی رومیزی","de":"کیسه‌ای کوچک که مهره‌هایی به هر رنگ را در خود جا داده. مهره‌هایی که در یک کیسه منتظر دور بعدی‌اند، هر بار که تکانشان می‌دهی صدای تلق‌تلق می‌دهند. با آن صدا، هیجان «یک دور دیگه؟» زودتر از همه بیدار می‌شود."},"ICON-1912":{"nm":"سینی تاس‌ریزی","de":"سینی‌ای مخصوص ریختن تاس. شانسی که پیش از این از لبهٔ میز می‌پرید و ناپدید می‌شد، حالا لبه‌های این سینی درونش نگه می‌دارد. در آن لحظهٔ کوتاهِ غلتیدن و توقف تاس، نفس همه لحظه‌ای با هم بند می‌آید."},"ICON-1913":{"nm":"بند نگه‌دارندهٔ دسته‌کارت","de":"بندی که یک دسته کارت را از پراکنده‌شدن نگه می‌دارد. تا پیش از بُر خوردن، همین ترتیب خودش یک قول است. در همان حرکتِ بازکردنِ بند و پهن‌کردنِ کارت‌ها، داستان یک دور بازی سرانجام آغاز می‌شود."},"ICON-1914":{"nm":"گیرهٔ مرتب‌کنندهٔ سیم کنسول","de":"گیره‌ای که سیم‌های درهم‌پیچیدهٔ پشت کنسول را می‌گیرد و مرتب شانه می‌کند. بی‌سروصدا، درهم‌ریختگیِ جایی را که به‌زحمت دیده می‌شود، منظم می‌کند. نظافت همیشه همین‌طور، آرام و از پشت‌صحنه، کامل می‌شود."},"ICON-1915":{"nm":"صفحهٔ گردان امتیاز","de":"صفحه‌گردان کوچکی برای نشان‌دادن امتیاز. کلیک، با هر خانه که عدد بالا می‌رود، هلهله همراهش می‌آید. حتی بدون شمردن در ذهن، نوک انگشت‌ها زودتر از همه نتیجهٔ آن روز را به‌خاطر می‌سپارند."},"ICON-1916":{"nm":"پایهٔ نگه‌دارندهٔ تختهٔ بازی","de":"پایه‌ای که تختهٔ بازی را کج نگه می‌دارد تا همهٔ کسانی که دورش نشسته‌اند، با یک نگاه تخته را ببینند. طوری که کسی مجبور نباشد گردن دراز کند، به‌آرامی دیدی عادلانه برای همه می‌گستراند."},"ICON-1917":{"nm":"لیوان قرعه‌کشی نوبت بازی","de":"لیوانی که برای تعیین ترتیب بازی، دست را در آن فرو می‌بری. همان یک چوبی که کورمال می‌گیری، نفر اول را تعیین می‌کند. در آن لحظهٔ کوتاهِ تکیه به شانس، همه با هم درون آن لیوان گرد، دلشوره‌ای شیرین دارند."},"ICON-1918":{"nm":"بشقاب خانه‌دار تنقلات مشترک","de":"بشقابی با خانه‌های جدا برای چیدن تنقلات به تفکیک نوع. با جداکردن جاها، دست‌ها به‌هم نمی‌خورند و هرکس می‌تواند مورد دلخواهش را بردارد. توجهی که به آدم‌های سهیم‌شونده فکر کرده، در هر خانه جای گرفته است."},"ICON-1919":{"nm":"روکش گرم‌نگه‌دار قوری","de":"روکشی که شانه‌های قوری را می‌پوشاند و گرمایش را نگه می‌دارد. تا چای آرام‌آرام دم می‌کشد، آن را می‌پیچد تا سرد نشود. این همان دلِ نوک‌انگشتان است که می‌خواهد یک فنجان گرم را تا آخر، گرم تقدیم کند."},"ICON-1920":{"nm":"زیرچایی‌کیسه‌ای","de":"تکیه‌گاهی که کیسهٔ چای دم‌کشیده را بیرون می‌آورد و لختی به استراحتش می‌گذارد. حتی آخرین قطرهٔ آب را هم بدون ریختن نگه می‌دارد. جایی که به برگی که سهم خود را تمام کرده، پایانی آراسته هدیه می‌دهد."},"ICON-1921":{"nm":"حلقهٔ تفکیک لیوان‌های مشترک","de":"شش لیوان یک‌شکل روی قفسهٔ آشپزخانهٔ مشترک. به‌جای پرسیدن مال کیست، حلقه‌هایی رنگارنگ به آن‌ها بستیم. یک نشانهٔ کوچک، شش نفر با سلیقه و ذائقه‌ای متفاوت را، آرام کنار یک میز به هم پیوند می‌زند."},"ICON-1922":{"nm":"سبد پاپ‌کورن مشترک","de":"تا از دستی به دستی می‌رود، بوی خوشش زودتر از همه سلام می‌کند. اگر چیزی باشد که هرچه بیشتر با مشت مشت برداری، عجیب کم نشود، همان دل شبی است که همه دورهم می‌نشینند و با هم سهیم می‌شوند."},"ICON-1923":{"nm":"جاقندی و انبرک قند حبه‌ای","de":"یک حبه قند مکعبی را با انبرک، تِق، داخل فنجان چای می‌اندازی. تماشای آب‌شدن آرام گوشه‌های سفید و ناپدیدشدنش—آدابی بی‌عجله برای شیرینی که اولین بار سر میز چای مادربزرگ آموختیم."},"ICON-1924":{"nm":"زیرانداز ضدلغزش سینی","de":"حتی اگر سینی کج شود، فنجان‌ها جای خود را حفظ می‌کنند. مثل همیشهٔ چیزهایی که آرام از پایین نگه می‌دارند، این زیرانداز تنها لحظهٔ نزدیک‌به‌لغزیدن را تحمل می‌کند و سرانجام هم لب فرومی‌بندد."},"ICON-1925":{"nm":"لیوان نگه‌دارندهٔ نی نوشیدنی","de":"اگر نی را صاف نگه داری، نه نوشیدنی و نه دل، از هم نمی‌پاشد. بعدازظهری که میز فقط با یک راستی کوچک مرتب می‌شود، لیوان ستون کوچکش را در آغوش می‌گیرد و آرام ساعت‌های کاهل را نگه می‌دارد."},"ICON-1926":{"nm":"جمع‌کنندهٔ خرده‌های کلوچه","de":"کرچ، همان لحظه که کلوچه خرد می‌شود، تکه‌های افتاده اینجا جمع می‌شوند. پذیرفتن حتی ردّ باقی‌مانده از خوشمزه‌ترین لقمه—پایان آرام میز، مهربان حتی با آخرین خرده."},"ICON-1927":{"nm":"بند آویز عکس با گیره","de":"عکس‌های پولاروید را یک‌به‌یک با گیره روی بندی مثل بند رخت آویزان می‌کنیم. تا خنده‌های امروز در نسیم می‌لرزند و خشک می‌شوند، یک تکه از دیوار به گالری کوچک و روشن خاطرات بدل می‌شود."},"ICON-1928":{"nm":"قرقرهٔ کلاف خاطرات","de":"قرقره‌ای که نخ درهم‌گره‌خورده را باز کرده و مرتب پیچیده. چیزهایی که در هر جای پاره‌شده، با گره‌ای دوباره پیوند خورده‌اند. اگر خاطره را هم این‌طور آرام، دور به دور، بازپیچی کنی، راهی که فکر می‌کردی کوتاه شده، دوباره طولانی می‌شود."},"ICON-1929":{"nm":"روکش کوچک محل میخ دیوار","de":"روکشی گرد و کوچک که رد میخ را می‌پوشاند. حتی زخم کوچکی را که پس از برداشتن چیزی که آنجا آویزان بود باقی مانده، آرام می‌پوشاند و دیوار انگار هیچ اتفاقی نیفتاده، دوباره چهره‌ای صاف پیدا می‌کند."},"ICON-1930":{"nm":"قاب عکس دسته‌جمعی","de":"عکسی دسته‌جمعی از شش نفر که شانه‌به‌شانه گرفته شده. همان لحظه که آن را در قاب می‌گذاری، خنده و گرمای آن روز با هم مهروموم می‌شود. قاب همان دستی است که آرام‌ترین شکل، روزی درحال‌گذر را متوقف می‌کند."},"ICON-1931":{"nm":"تخته‌چوب‌پنبه‌ای یادداشت","de":"تخته‌ای قهوه‌ای پر از جای سنجاق. قولی که نباید فراموش شود، یادداشت دلگرمی‌ای که کسی چسبانده، کارهای امروز، لایه‌لایه سنجاق می‌شوند. دیواری مطمئن کنار میز که به‌جای ذهن، به‌یاد می‌آورد."},"ICON-1932":{"nm":"گره آویز حلقهٔ تزئینی","de":"حتی برای آویزان‌کردن یک حلقهٔ تزئینی روی در، مهارت نوک انگشتان لازم است. گره باید محکم بسته شود تا در فصل بادخیز هم نیفتد. دلی که کسی را خوش‌آمد می‌گوید، همیشه از جایی نادیدنی محکم می‌شود."},"ICON-1933":{"nm":"روکش پارچه‌ای آونگ ساعت دیواری","de":"روکشی پارچه‌ای که آونگ تیک‌تیک‌کننده را می‌پوشاند تا گرد و غبار نگیرد. حتی کار سنجش زمان هم این‌گونه مراقبت می‌شود. اگر آرام از فرسودگی محافظتش کنی، ساعت دیواری کمی بیشتر کنار ما می‌ماند."},"ICON-1934":{"nm":"تخته گردآوری استیکر","de":"استیکرهایی که در هر کشو پراکنده بودند، روی یک تخته جمع می‌شوند و صف می‌بندند. یک شخصیت مورد علاقه، ستاره‌ای برّاق، یک ورق دست‌نوشته. وقتی لذت کوچک جمع‌آوری این‌طور مرتب می‌شود، حتی دل هم منظم می‌شود."},"ICON-1935":{"nm":"بند اتصال پرچم‌های تزئینی","de":"بندی که پرچم‌های رنگارنگ را در یک ردیف به‌هم وصل می‌کند. تولد باشد یا خوش‌آمدگویی، همان لحظه که بند سقف را طی می‌کند، اتاقی معمولی به خانهٔ جشن بدل می‌شود. جشن‌گرفتن یعنی به‌هم پیوستن دل‌های از‌هم‌گسیخته."},"ICON-1936":{"nm":"زیرکتری چوب‌پنبه‌ای","de":"یک ورق چوب‌پنبه که کف کتری داغ را نگه می‌دارد. تا میز نسوزد، آن گرما را تنها در آغوش می‌کشد. توجهی کوچک که آرام زیرش می‌ایستد تا گرمای کسی جای زخمی بر جای نگذارد."},"ICON-1937":{"nm":"سینی خرده‌نان توستر","de":"خرده‌هایی که نان برشته‌شده می‌ریزد، غلت‌زنان روی سینی می‌افتند. فقط بیرون بکش و تکان بده، تمام. صبح شلوغ را بی‌هیچ حرفی می‌پذیرد و دوباره برای وعدهٔ بعدی، پاک آماده می‌شود."},"ICON-1938":{"nm":"حلقهٔ صفحه‌گردان مایکروویو","de":"روی حلقه‌ای که می‌چرخد، بشقاب آرام یک دور کامل می‌زند. آن چرخشی که برای گرم‌شدن یکنواخت می‌چرخد، برنج سردشدهٔ دیروز را دوباره به وعده‌ای بخارآلود و گرم زنده می‌کند."},"ICON-1939":{"nm":"روکش کوچک صفحهٔ اجاق القایی","de":"هرچقدر هم روغن به هر سو بپاشد، اجاق همیشه تمیز می‌ماند. یک روکش، گرمای شدید را از دست جدا نگه می‌دارد. چیزهایی که نادیدنی سد راه می‌شوند، آشپزخانه را جایی می‌سازند که در آن نمی‌سوزی."},"ICON-1940":{"nm":"کلاهک تخلیهٔ بخار پلوپز","de":"صدای هیس بخار که بیرون می‌زند. به‌لطف کلاهک کوچکی که فشار انباشته را آرام رها می‌کند، برنج تازه‌پخته با نرم‌ترین چهره درش را باز می‌کند. زمان دم‌کشیدن، شتاب‌زدگی نمی‌شناسد."},"ICON-1941":{"nm":"پایهٔ ایستادهٔ ملاقه","de":"ملاقه‌ای که سوپ را هم زده، صاف نگه‌داشته می‌شود. دلی کوچک که نمی‌خواهد حتی یک لکه روی اُپن بریزد. نظم آشپزخانه همیشه از همین جاهای کوچک و نادیده آغاز می‌شود."},"ICON-1942":{"nm":"روکش سیلیکونی دستهٔ قابلمه","de":"اگر سیلیکون را روی دستهٔ داغ قابلمه بگذاری، دستت نمی‌سوزد. یک لایه که میان داغی و کف دست فاصله می‌اندازد. کسی را که غذای گرم می‌پزد، از نزدیک‌ترین جا محافظت می‌کند."},"ICON-1943":{"nm":"صافی رسوب کتری برقی","de":"حتی آبی که هر روز می‌جوشانی، ردّ کم‌رنگی از رسوب می‌گذارد. توری ریزبافتی آرام رسوب را صاف می‌کند و فقط فنجانی زلال بیرون می‌ریزد. دستی پرکار که از جایی نادیدنی، اولین جرعهٔ چای را نگه می‌دارد."},"ICON-1944":{"nm":"تایمر آشپزی با پایه‌های گیره‌ای","de":"«فقط سه دقیقهٔ دیگه»، تایمر می‌گوید و با پاهای گیره‌ای‌اش لبهٔ میز را محکم گاز می‌گیرد. تا نودل‌ها بپزند، روی پاهای کوچکش ایستادگی می‌کند و تیک‌تیک‌کنان، منتظرترین لحظهٔ روز را با هم می‌شمارد."},"ICON-1945":{"nm":"لیوان چکه‌گیر ظروف","de":"از قاشق و چنگالی که تازه آبکشی شده، آب قطره‌قطره پایین می‌ریزد. وقتی لیوان چکه‌گیر آرام آن رطوبت را جمع می‌کند، میز طولی نمی‌کشد که خشک می‌شود. نظافت، پشتکاری مهربان است که حتی یک قطرهٔ آب را هم مراقب است."},"ICON-1946":{"nm":"قفسهٔ خانه‌دار عمودی بشقاب","de":"بشقاب‌ها را عمودی می‌ایستانی، خانه‌به‌خانه جدا از هم. ظرف‌هایی که وقتی روی هم چیده می‌شدند به‌هم می‌خراشیدند، حالا هرکدام جایی برای خود می‌گیرند. نظم‌ودهی در نهایت یعنی دادن یک خانهٔ بی‌برخورد به همه."},"ICON-1947":{"nm":"حلقهٔ جفت‌کنندهٔ چوب‌غذاخوری","de":"چوب‌غذاخوری‌ای را که جفتش را گم کرده و تنها مانده، در حلقه می‌کشی و دوباره جفتش می‌کنی. چون یک چوب تنها، به‌زودی کارایی‌اش را از دست می‌دهد، همین حلقهٔ کوچک که آن‌ها را کنار هم می‌بندد، نظم کشو را حفظ می‌کند."},"ICON-1948":{"nm":"درخت آویز فنجان","de":"روی پایه‌ای که مثل شاخه به چند سو کشیده شده، فنجان‌ها را یک‌به‌یک آویزان می‌کنی. تا رطوبت از هر لیوانِ سرنگون خشک شود، گوشه‌ای از آشپزخانه، آرام، مثل درختی کوچک و مرتب می‌ایستد."},"ICON-1949":{"nm":"دستهٔ سینی خانه‌بندی قاشق‌چنگال","de":"سینی‌ای که قاشق و چنگال و چوب‌غذاخوری، خانه‌به‌خانه کنار هم دراز کشیده‌اند. دسته را می‌گیری و یکجا بیرونش می‌کشی، و چیدن میز بسیار سبک‌تر می‌شود. حتی درون کشو هم، زیبایی‌شناسی نظم بی‌وقفه زندگی می‌کند."},"ICON-1950":{"nm":"تختهٔ خشک‌کن سرنگون لیوان","de":"لیوان‌های شسته‌شده را سرنگون بگذار، قطره‌های آب یکی‌یکی می‌چکند. تا کنار پنجرهٔ آفتاب‌گیر آرام خشک می‌شوند، لیوان شیشه‌ای برای جرعهٔ بعدی، آرام‌آرام شفافیت نخستینش را بازمی‌یابد."},"ICON-1951":{"nm":"شانهٔ تمیزکنندهٔ شکاف چنگال","de":"با دندانه‌های ریزش، غذای گیرکرده میان دندانه‌های چنگال را آرام می‌شوید. به‌لطف دستی که حتی باریک‌ترین شکاف را مراقب است، وعدهٔ بعدی همیشه با اولین لقمه‌ای بی‌عیب و پاک آغاز می‌شود."},"ICON-1952":{"nm":"نمد ضدلغزش برای روی‌هم‌چیدن ظرف","de":"وقتی ظرف‌ها را روی هم می‌چینی، چینی به چینی برخورد می‌کند و صدایی تیز می‌دهد. یک ورق نمد که میان آن‌ها جا می‌گیرد، آن اصطکاک را آرام می‌کند. راز همراهی طولانی، در کمی نرم‌تر گذاشتن یکدیگر است."},"ICON-1953":{"nm":"بند حلقه‌ای آویز قاشق‌چای‌خوری","de":"قاشق‌چای‌خوری ظریف را به حلقه می‌بندی و روی دیوار آویزان می‌کنی. بی‌آنکه در کشو مدفون شود، همیشه در دسترس و درخشان، ابزاری کوچک که با غرور جای خودش را می‌گیرد. حتی خانه‌داری هم، جای مشخصی برای هر چیز دارد."},"ICON-1954":{"nm":"سینی خانه‌بندی یخچال","de":"وقتی قفسهٔ یخچال را به بخش‌ها تقسیم کنی، هر مادهٔ غذایی خانهٔ کوچک خودش را می‌گیرد. چیزهایی که پیش از این درهم‌ریخته و فراموش می‌شدند، جای خود را می‌یابند و هر بار در را باز کنی، در یک نگاه روشن می‌بینی چه چیزی کجاست."},"ICON-1955":{"nm":"گیرهٔ ایستاندهٔ کیسهٔ فریزری","de":"کیسهٔ نیمه‌خالیِ فریزر را با گیره می‌گیری و راست نگهش می‌داری. تا نیفتد و نریزد، تا دفعهٔ بعد راحت پیدایش کنی. حتی در دل فریزر سرد هم، خِرَد موشکاف خانه‌داری بی‌نقص جای می‌گیرد."},"ICON-1956":{"nm":"محکم‌کنندهٔ درب بطری","de":"بطری‌ای که کاملاً بسته نشده، بی‌آنکه بفهمی گازش خالی می‌شود. همان یک چرخش مچ که درب را محکم می‌بندد، عطر و گاز درونش را تا صبح فردا سالم نگه می‌دارد. موشکافی همیشه در چیزهای کوچک می‌درخشد."},"ICON-1957":{"nm":"زیرانداز ضدلغزش خانهٔ تخم‌مرغ","de":"زیراندازی که تخم‌مرغ‌های گرد را خانه‌به‌خانه نگه می‌دارد تا نغلتند و نشکنند. دلی که می‌خواهد شکننده‌ترین چیز را با بیشترین دقت نگه دارد، کوچک و مهربان، گوشه‌ای از در یخچال جای می‌گیرد."},"ICON-1958":{"nm":"نوار گسترش‌دهندهٔ جیب در یخچال","de":"جیب در یخچال را کمی به کنار می‌کشی تا یک خانهٔ دیگر پدید آید. چون هر چه خانه‌داری بیشتر شود، جایش هم باید زیاد شود. در مهارت گسترش‌دادن جای تنگ، دل خانه‌داری موشکاف بازتاب می‌یابد."},"ICON-1959":{"nm":"درپوش فشاری غذای باقی‌مانده","de":"درپوشی که آرام روی خورش باقی‌مانده فشرده می‌شود. آرام نگهش می‌دارد تا خشک نشود و بوی دیگری نگیرد. دستی که مراقبت می‌کند، حتی باقی‌ماندهٔ یک وعده را هم با دقت کنار می‌گذارد."},"ICON-1960":{"nm":"پرهٔ جهت‌دهندهٔ هوای سرد","de":"هوای سرد به کدام سو جریان بیابد؟ پرهٔ کوچکی آرام جهتش را تعیین می‌کند. مسیر نادیدنی نسیم را با نوک انگشت کمی بچرخان، تا سرما حتی به عمیق‌ترین گوشهٔ درون هم برسد."},"ICON-1961":{"nm":"پد رطوبت‌گیر قفسهٔ سبزیجات","de":"در تاریک‌ترین گوشهٔ قفسهٔ سبزیجات یخچال، من بی‌صدا رطوبت را در خود نگه می‌دارم. معجزهٔ کوچکِ برگی که دیروز پژمرده بود و صبح دوباره سرحال می‌شود. حتی بی‌آنکه کسی بداند، تازگی همیشه بر عهدهٔ من است."},"ICON-1962":{"nm":"لبهٔ توقف‌دهندهٔ غلتش قوطی نوشابه","de":"آرام به لبهٔ میز چسبیده و پای قوطی‌ای را که می‌خواست بغلتد، می‌گیرد. نوشیدنی‌ای که نزدیک بود بریزد، میزی که نزدیک بود پاک شود. آرامش خیال در خانه‌داری، از همین لبهٔ کوچک و نادیده آغاز می‌شود."},"ICON-1963":{"nm":"صفحهٔ گردان نوبت وظایف","de":"امروز نوبت ظرف‌شستن کیست، نوبت جدا کردن زباله‌ها با کیست؟ یک چرخش فلش و هر دعوایی به‌آرامی حل می‌شود. در خانه‌ای که پنج نفر با هم زندگی می‌کنند، رعایت نوبت خودش نوعی صلح مهربانانه است."},"ICON-1964":{"nm":"بند سیلیکونی تفکیک لیوان اعضا","de":"پنج لیوان تقریباً یکسان، و صبحی که معلوم نبود کدام مال کیست. یک بند رنگی به اندازهٔ مچ که می‌بندی، قول کوچکِ «این مال من است» روشن می‌شود و نظمی مهربان بر میز صبحانه می‌نشیند."},"ICON-1965":{"nm":"حلقهٔ اندازه‌گیری کاسهٔ غذا","de":"در روزهای شلوغ، خط‌های داخل کاسه دوستی مطمئن می‌شوند. یک خانه برای برنج، یک خانه برای خورش. نه کم و نه زیاد، خطی مهربان که آرام می‌گوید امروز چقدر باید بخوری."},"ICON-1966":{"nm":"ظرف انبرکی تنقلات مشترک","de":"اگر همهٔ کیسه را جلو بگیری، جای دستی که لمسش کرده مانده و کمی معذب‌کننده است. با انبرک یکی‌یکی تقسیمش کن، آن‌وقت است که سهم همه برابر می‌شود. برای سهیم‌شدن، دستی مرتب بهتر از یک مشت پرشور می‌آید."},"ICON-1967":{"nm":"جانام‌نوبتی کنار کتری","de":"جوشاندن آب همیشه سهم همان دست‌های همیشگی بود. از وقتی که برچسب اسم را به‌نوبت روی جاقاشقی کنار کتری می‌آویزیم، یک فنجان چای گرم، محبتی شد که به‌نوبت دم می‌کشد."},"ICON-1968":{"nm":"تراشهٔ هشدار روی کفگیر","de":"یک «چیزی رو نگذار» کوچک، از نوک کفگیر آویزان است. شاید غرغر به‌نظر برسد، اما هیچ نفرتی درونش نیست—چون روح میز غذای قدیم، جایی که هر وعده گرامی شمرده می‌شد، همین‌جا جا خوش کرده است."},"ICON-1969":{"nm":"قلاب کیسهٔ شخصی قاشق‌چنگال","de":"قاشق و چنگال دیگر در کشو غلت نمی‌خورد. همان لحظه که هرکدام در کیسهٔ خودش می‌رود و روی دیوار آویزان می‌شود، جای پنج عضو خانواده کنار هم صف می‌بندد. نظمی کوچک که آرامش هر روز را نگه می‌دارد."},"ICON-1970":{"nm":"تراشهٔ چوب‌پنبه‌ای تعیین جای سر میز","de":"تکه‌های چوب‌پنبه را روی میز بچین، آن‌وقت روشن می‌شود چه کسی کجا می‌نشیند. جایی که همیشه می‌نشستی، نیم‌رخی که همیشه روبه‌رویش بودی. جای ثابت، آرام‌ترین گواهِ عبارتِ «با هم زندگی‌کردن» است."},"ICON-1971":{"nm":"قلاب پیچش پیش‌بند نوبتی","de":"پیش‌بندی که ظرف‌شستن با آن تمام شده، هرجایی پرت نمی‌شود. اگر پیچیده و به قلاب آویزان شود، صبح فردا دوباره خشک و آماده به دست می‌رسد. دلی که به نفر بعدی فکر می‌کند، در همین گرهٔ کوچک زندگی می‌کند."},"ICON-1972":{"nm":"کیف تاشوی دمپایی یک‌بارمصرف","de":"روزی که مهمان می‌آید، من با کیف کاملاً باز می‌شوم. دمپایی‌های یک‌بارمصرف که مرتب داخل چیده شده‌اند، از پای تازه‌رسیده با گرمایی نرم استقبال می‌کنند. مهمان‌نوازی همیشه از دَمِ در، آرام آغاز می‌شود."},"ICON-1973":{"nm":"جیب دم‌کاغذی گوش‌پاک‌کن","de":"وقتی گوش‌پاک‌کن‌ها تمام می‌شوند و فقط دُم کاغذی می‌ماند، من آن نوک‌ها را با دقت جمع می‌کنم. جادادن حتی به چیزی که قرار است دور ریخته شود. می‌دانم راز میز مرتب، همین مهربانی‌های کوچک است."},"ICON-1974":{"nm":"بستهٔ قرقره‌های کیت خیاطی","de":"نخ‌های رنگی را باهم می‌بندم تا قرقره‌ها باز نشوند و درهم نپیچند. دکمه‌ای که افتاده، سرآستینی که شل شده، با همین یک بسته به‌سرعت مرتب می‌شوند. خیاطی دستی که بی‌سروصدا شبِ روزی مهم را نجات می‌دهد."},"ICON-1975":{"nm":"تکهٔ صابون تک‌بسته‌بندی","de":"تکه‌صابونی که تک‌تک با ظرافت پیچیده شده، در هر اتاق مهمان گذاشته می‌شود. بدنی به اندازهٔ کف دست، با یک مشت کف، گرد و غبار روز را می‌شوید. پاکیزگی همیشه از همین جاهای کوچک آغاز می‌شود."},"ICON-1976":{"nm":"کپسول تاشوی چروک‌دار کلاه حمام","de":"چروک‌ها را که تا کنی، در کف دست جا می‌گیرد؛ باز کنی، موها را کاملاً می‌پوشاند. تا با یک دوش، موهای مرتب‌شده به‌هم نریزد. این یک لایه، آراستگی صبح فردا را نگه می‌دارد."},"ICON-1977":{"nm":"غلاف محافظ سر مسواک","de":"موی مسواک حساس‌تر از آن است که فکرش را می‌کنی. یک غلاف که نوکش را می‌پوشاند، حتی گرد و غبار داخل کیف هم به آن نمی‌رسد. مراقبت از جاهای نادیدنی—کار واقعی بهداشت که در هر سفر دوباره یاد می‌گیریم."},"ICON-1978":{"nm":"انبرک برداشتن تک‌برگی پنبهٔ آرایشی","de":"پنبهٔ آرایشی فقط اگر یک‌به‌یک برداشته شود، تمیز بیرون می‌آید. اگر همه را یک‌جا بریزی، هدررفت بیشتری خواهی داشت. «یکی‌یکی، با دقت»—این قانون آرام روی میز آرایش است."},"ICON-1979":{"nm":"پاشنه‌کش تاشوی کوچک","de":"تا کنی، در جیب جا می‌گیرد؛ باز کنی، به پاشنه می‌رسد. با تن کوچکم، به کاری نسبتاً بزرگ افتخار می‌کنم. حتی در صبح‌های دیرخیزی، همیشه این من بودم که کفش را بی‌آنکه خراب شود، به پا می‌رساندم."},"ICON-1980":{"nm":"قرقرهٔ تک‌رشتهٔ نخ‌دندان","de":"یک رشته نخ‌دندان را با ظرافت می‌پیچی تا وقت لازم شد، دقیقاً به‌اندازه ببری. قرقره‌ای به‌اندازهٔ ناخن، اما هرگز از کار نگه‌داشتن لبخندی روشن غایب نیست. حتی لبخند هم آماده‌سازی‌ای نادیدنی دارد."},"ICON-1981":{"nm":"دستهٔ درب کتری برقی","de":"تا بخار آب جوش دستت را نسوزاند، من روی درب می‌نشینم. یک وجب فاصله میان داغی و کف دست. همین فاصلهٔ کوچک، صبح شلوغ کسی را با امنیت گرم می‌کند."},"ICON-1982":{"nm":"زیراتوی سیلیکونی","de":"خطرناک‌ترین لحظه، همان دمی است که موقع اتوکشیدن دست را لحظه‌ای رها می‌کنی. اتو را روی صفحهٔ سیلیکونی بایستان، نه میز می‌سوزد و نه لباس. صاف‌کردن چروک‌ها فقط روی این تکیه‌گاه، سرانجام تمام می‌شود."},"ICON-1983":{"nm":"قلاب چوب‌لباسی ضدسرقت","de":"تا لباس آویزان بی‌احتیاطی سُر نخورد، قلاب دهانش را محکم می‌بندد. نگهبانی کوچک که کنار پیراهن عزیز درون کمد می‌ایستد. مراقبت‌کردن، همیشه کاری آرام است، همین‌طور."},"ICON-1984":{"nm":"صافی رسوب کتری","de":"سهم من این است که رسوبی را که در آب جوش شناور است، آرام صاف کنم. تنها پس از صاف‌کردن حتی ته‌نشین‌های نادیدنی، یک فنجان چای زلال می‌شود. دلسوزی همیشه از جاهایی که کسی نمی‌بیند دم می‌کشد."},"ICON-1985":{"nm":"نوار ضدلغزش چوب‌لباسی","de":"چوب‌لباسی‌ای که با نوار ضدلغزش پیچیده شده، حتی ابریشم سبک را هم نمی‌اندازد. هرکس یک‌بار لباسی را دیده که روی زمین افتاده و چروک شده، قدر همین یک خط باریک را می‌داند."},"ICON-1986":{"nm":"گیرهٔ مرتب‌کنندهٔ سیم اتو","de":"سیمی که رها شده، به پا گیر می‌کند و کسی را متزلزل می‌سازد. یک لمس دست که با گیره آن را مرتب و یکجا می‌بندد. جلوگیری از حادثه، همیشه از همین نظم‌دهی‌های کوچک و ناچیز آغاز می‌شود."},"ICON-1987":{"nm":"شیار پایه‌ای نشیمن کتری","de":"کتری را محکم داخل شیار خودم می‌نشانم تا نلرزد. جای درست‌نشستن، یعنی آسودگی خیال. دلیلی دارد که آب گرم هر روز صبح در همان یک نقطه گرم می‌شود."},"ICON-1988":{"nm":"پایه‌های گیره‌ای آویز شلوار","de":"وقتی پاهای گیره‌ای لبهٔ شلوار را محکم می‌گیرند، حتی یک چروک هم نمی‌افتد. لباسی که خوب اتو شده، همان لحظه که روی چوب‌لباسی آویزان می‌شود، احترام می‌بیند. فیت تمیز، درون کمد کامل می‌شود."},"ICON-1989":{"nm":"قلاب آویز سشوار","de":"سشوار را هرجا بگذاری، سیمش زود درهم می‌پیچد. آن را محکم به قلاب آویزان کن، روشویی هم بازتر می‌شود و صبح فردا سبک‌تر. جای مرتب، کمی از فشار یک روز شلوغ را باز می‌کند."},"ICON-1990":{"nm":"زیرلیوانی مینی‌بار","de":"زیر لیوان که آرام قرارش می‌دهی، قطره‌های آب روی میز پخش نمی‌شود. لطف یک زیرلیوانی، حلقه‌ای بر جا نمی‌گذارد. نظافت، همان محبتی است که ردی از خود باقی نمی‌گذارد."},"ICON-1991":{"nm":"تابلوی آویز «مزاحم نشوید»","de":"تابلویی آویزان به دستگیرهٔ در، آرام زمزمه می‌کند «الان استراحت است». نگهبانی از یک نفسِ چرت بعدازظهر در پایان روزی طولانی. حتی یک وقفه هم به کسی نیاز دارد که با دقت آن را نگه دارد."},"ICON-1992":{"nm":"کلاهک دکمهٔ فراخوان سرویس اتاق","de":"به‌لطف کلاهکی که دکمه را می‌پوشاند، حتی برخورد گوشهٔ لباس هم آن را نمی‌فشارد. تا فقط در لحظهٔ واقعاً لازم، آشکار صدا بزنی. یک روکش کوچک، اتاقی شلوغ را باز هم مرتب‌تر می‌کند."},"ICON-1993":{"nm":"پاهای انبرکی یخ مینی‌بار","de":"یخ را با دست خالی بگیری، سرد است و پیوسته می‌لغزد. آن کار را انبرک به‌جای دست، محکم برعهده می‌گیرد. پشت شروع یک لیوان نوشیدنی خنک، دستی نادیدنی و یاری‌رسان پنهان است."},"ICON-1994":{"nm":"شیار کارت‌کلید اتاق","de":"کارت را در شیار فرو کنی، چراغ‌های اتاق تِق روشن می‌شوند. من فقط یک شکاف کوچکم، اما اولین حرکتی هستم که فضایی برای رهاکردن خستگی روز باز می‌کنم. در جایی که به آن بازمی‌گردی، چراغ دوباره روشن می‌شود."},"ICON-1995":{"nm":"حلقهٔ مهروموم گردن بطری","de":"اگر حلقهٔ مهروموم گردن بطری سالم باشد، یعنی هنوز کسی دستش را نزده. قولی کوچک که ثابت می‌کند همان‌طور که اول بود، همان است. اعتماد، از مهرومومی بی‌شکست آغاز می‌شود."},"ICON-1996":{"nm":"پایهٔ ایستادهٔ بروشور","de":"بروشور را کج بایستان، نگاه رهگذر خودبه‌خود روی آن می‌ماند. حالت متین اطلاعاتی که منتظر بازشدن است. فقط با در دید نگه‌داشتنش، راه کسی کمی هموارتر می‌شود."},"ICON-1997":{"nm":"تراشهٔ تخت درب‌بازکن مینی‌بار","de":"در گوشه‌ای از تن تختش، شکافی برای بازکردن درب بطری آرام پنهان شده. هرچقدر هم کوچک باشد، کارش را بی‌نقص انجام می‌دهد. اولین جرعهٔ خنک یک بطری، همیشه با همین تراشهٔ کوچک باز می‌شود."},"ICON-1998":{"nm":"روکش دستگیرهٔ تنظیم روشنایی","de":"دستگیرهٔ پوشیده‌شده را آرام بچرخان، روشنایی اتاق آرام‌آرام تغییر می‌کند. روشن، سپس ملایم. انتخاب نور هنگام خواب، آیینی است که روز را با مهربانی به پایان می‌رساند."},"ICON-1999":{"nm":"گوهٔ توقف چرخ چمدان","de":"زیر چرخ کمی جایش می‌دهی، چمدان دیگر خودسرانه نمی‌غلتد. حتی روی سکوی شیب‌دار ایستگاه هم، بار جای خود را نگه می‌دارد. آرامش خیال در راه رفتن، از همین گوهٔ کوچک استوار می‌شود."},"ICON-2000":{"nm":"تختهٔ تاکن سفر","de":"پیراهن یا شلوار را رویش پهن کنی، منظم و تمیز تا می‌خورد. تا درون کیف به‌هم نریزد، تا در شهر مقصد بی‌چروک بیرون بروی. باری که خوب بسته شده، پیش از حرکت هم به سفر کمک می‌کند."},"ICON-2001":{"nm":"دستگیره قفل گاوصندوق اتاق","de":"دستگیره را که می‌چرخانی، چفت کوچکی به آرامی به داخل می‌لغزد. سپردن اشیای قیمتی، یعنی وعده‌ای که فقط برای یک شب، دل را کاملاً آسوده بگذاری. قفل نه از سرِ نگرانی، بلکه به عنوان نامی دیگر برای آرامش خاطر، همان‌جاست."},"ICON-2002":{"nm":"روکش دستگیره چمدان","de":"در هر جای ساییده و دست‌خورده‌اش، رفتنِ کسی حک شده است. این روکش را که به اندازه‌ی مسافتی که کشیده شده فرسوده است در دست بگیری، به آرامی درمی‌یابی که رفتن، در نهایت واژه‌ای‌ست که بازگشت را در خود دارد."},"ICON-2003":{"nm":"گیره‌ی آویز پاوچ سفر","de":"پاوچ را به لبه‌ی روشویی بیاویزی، اتاق تنگ یک وجب بزرگ‌تر می‌شود. دستی که راه دور رفته، از پیش می‌داند که نظم درون کیف، از یک گیره‌ی کوچک آغاز می‌شود."},"ICON-2004":{"nm":"گیره‌ی چندراهی شارژر","de":"چند کابل را در یک پریز کنار هم جا می‌دهی. در شبی که منتظر پر شدن شارژ می‌مانی، این‌جا دست کوچکی هست که سیم‌های پراکنده را مهربانانه در یک‌جا نگه می‌دارد."},"ICON-2005":{"nm":"بند حلقه‌ی برچسب نام چمدان","de":"در میان کیف‌های سیاه یکسان، یک رشته بند است که مال تو را نشانت می‌دهد. آویختن نام، نشانه‌ای مهربانانه است که این بار، راهی برای بازگشت به سوی کسی دارد."},"ICON-2006":{"nm":"تخته‌ی نگه‌دارنده‌ی سیم شارژر دیوار اتاق","de":"تخته‌ی کوچکی که به دیوار بالای سر تخت چسبیده، سیم شارژر را مرتب نگه می‌دارد. در نخستین شبی که در اتاقی غریب می‌گذرد، وقتی نوری آشنا روشن می‌شود، همان‌جا هم برای لحظه‌ای خانه می‌شود."},"ICON-2007":{"nm":"پایه‌های تاشوی جاکیفی","de":"پایه‌های تا شده را که باز کنی، کیف یک وجب از خاک کف زمین بلند می‌شود. چمدانی که هنوز باز نشده روی آن گذاشته شده، سفری ناتمام را در سکوت در خود نگه می‌دارد و منتظر صبح بعد می‌ماند."},"ICON-2008":{"nm":"شکاف کارت کلید","de":"باید کارت را داخل بگذاری تا چراغ اتاق روشن شود. نوری که فقط در طول اقامت روشن می‌ماند؛ روز مسافر با همان اندازه روشنایی که این شکاف کوچک اجازه می‌دهد، گرم می‌شود."},"ICON-2009":{"nm":"حلقه‌ی بند کارت کلید","de":"یک کارت را به گردن بیاویزی، هر دو دست سبک می‌شوند. بستن نگرانی گم‌شدن به یک بند، هوشمندی کوچکی‌ست که مسافرانِ پرباروبنه از دیرباز به ارث برده‌اند."},"ICON-2010":{"nm":"دکمه‌ی زنگ فراخوان پذیرش","de":"فشارش دهی، جایی در پذیرش صدایی زلال طنین می‌اندازد. تا کمک خواستن هرگز شرم‌آور نباشد، زنگ همیشه مهربانانه در دسترسِ یک دست‌دراز کردن قرار دارد."},"ICON-2011":{"nm":"گیره‌ی شماره‌ی نوبت پذیرش","de":"برگه‌ی شماره‌ی نوبتی را که در انتهای صف گرفته‌ای، برمی‌داری و ثابت می‌کنی. حتی انتظار هم نوبت دارد؛ نظم از وعده‌ای کوچک برای پاسداشتِ آرام زمانِ یکدیگر می‌روید."},"ICON-2012":{"nm":"منگوله‌ی کلید اتاق","de":"منگوله‌ای که از انتهای کلید آویزان است، با هر قدم به آرامی تاب می‌خورد. دلی که ذره‌ای زیبایی را پنهانی به کاربرد می‌افزاید، تنها از آنِ کسی‌ست که لذت نوک انگشتان را می‌شناسد."},"ICON-2013":{"nm":"روکش زنگ در پذیرش","de":"روکشی روی زنگ در بکشی، سکوتِ نیمروز نمی‌شکند. ملاحظه‌ای کوچک برای پاسداری از خواب عمیقِ کسی؛ حتی سکوت هم چیزی‌ست که کسی با دقت ساخته است."},"ICON-2014":{"nm":"برچسب آویز شماره اتاق","de":"یادداشتی که به دستگیره‌ی در آویخته، شماره‌ی اتاق را واضح نوشته است. چند رقم، جایی را که امشب باید به آن بازگردم تعیین می‌کند و در راهرویی غریب، همان چراغ‌دریایی کوچکی می‌شود."},"ICON-2015":{"nm":"نوار مغناطیسی کارت کلید","de":"نوار سیاه را به لبه‌ی در نزدیک کنی، قفل به آرامی باز می‌شود. عصری که در آن نشانه‌ای نامرئی دری را می‌گشاید؛ چیزی که زمانی جادو به نظر می‌رسید، اکنون در کف دست، به زندگی روزمره فرونشسته است."},"ICON-2016":{"nm":"پایه‌ی مهر پذیرش","de":"هر بار که مهر فرود می‌آید، پایه جوهر را یکنواخت می‌پذیرد. تا خط تأیید واضح بماند، دستی هست که در جایی نادیده، خاموش و پابرجا تکیه‌گاه است."},"ICON-2017":{"nm":"میله‌ی آویز چرخ‌دستی بار","de":"میله‌ای بر چرخ‌دستی بار، کیف لباس را بی‌چروک نگه می‌دارد. دلت می‌خواهد گاهی به چیزهایی که روزی سنگین را به‌جای تو حمل می‌کنند، کلمه‌ای سپاس بگویی."},"ICON-2018":{"nm":"برچسب دستگیره‌ی چمدان","de":"برچسبی کوچک به دستگیره‌ی چمدان می‌آویزی. تا وقتی جای نوشتن نام خالی بماند، هیجانی باقی می‌ماند که مقصد بعدی این کیف هنوز تعیین نشده است."},"ICON-2019":{"nm":"گوه‌ی قفل چرخِ چرخ‌دستی بار","de":"زیر چرخ گوه‌ای می‌گذاری تا چرخ‌دستی روی سرازیری غلت نخورد. پاسداری از سکون، گاه چهره‌ی دیگری از استوارترین ایمنی‌ست."},"ICON-2020":{"nm":"سگک بند چمدان","de":"بند را محکم می‌کشی تا کیفی که از وسایل سفر ورم کرده، نترکد. حتی وقتی راه به پایان می‌رسد، حجم خاطرات کم نمی‌شود، پس سگک آن وزن را تا آخر نگه می‌دارد."},"ICON-2021":{"nm":"روکش قلاب چرخ‌دستی بار","de":"روکشی که روی قلاب چرخ‌دستی کشیده شده، حتی یک اثر روی لباس نمی‌گذارد. دلی که حتی خراش‌های نادیده را از پیش حساب می‌کند؛ مهمان‌نوازیِ خوب در چنین جاهای کوچکی کامل می‌شود."},"ICON-2022":{"nm":"جیب برچسب نام چمدان","de":"جیب کوچکی که کنار کیف نصب شده، برچسب نام را در آغوش می‌گیرد. نوشتنِ اینکه مال کیست، مانند حک کردن پیشاپیش حقِ دوباره دیدار است، حتی اگر گم شود."},"ICON-2023":{"nm":"گیره‌ی دستکش حمل بار","de":"هنگام جابه‌جایی بار سنگین، گیره دستکش را محکم می‌گیرد تا نلغزد. پاسداری از دست‌ها و خوب انجام دادن کار، در نهایت از یک دل سرچشمه می‌گیرند."},"ICON-2024":{"nm":"روکش توری چمدان","de":"توری را روی بار می‌کشی و خرت‌وپرت‌ها به هر سو پراکنده نمی‌شوند. هر چشمه‌ی ریز توری، در میان شلوغیِ جابه‌جایی، چیزهای کوچک را از دست رفتن باز می‌دارد."},"ICON-2025":{"nm":"نگه‌دارنده‌ی یادداشت چرخ‌دستی بار","de":"یادداشتی که در دستگیره‌ی چرخ‌دستی جا داده شده، شماره‌ی اتاق را نوشته است. عادتِ نوشتنِ مقصد؛ هرچه دست‌ها شلوغ‌تر باشند، بیشتر بر یک خط نوشته آرام تکیه می‌کنند."},"ICON-2026":{"nm":"گنبد روکش سینی غذا","de":"گنبد نقره‌ای را که بالا بیاوری، بخار یک‌باره برمی‌خیزد. دلی که غذا را می‌پوشاند تا سرد نشود، خودِ فداکاری‌ست، آرزوی رساندنِ گرمی همان‌طور که هست."},"ICON-2027":{"nm":"تابلوی دستگیره‌ی مزاحم نشوید","de":"این تابلو را به دستگیره‌ی در بیاویزی، حتی صدای قدم‌ها در راهرو هم محتاط می‌شود. یک جمله‌ی «بیدارم نکنید»؛ استراحت هم فقط وقتی کسی از آن پاسداری کند، کامل می‌شود."},"ICON-2028":{"nm":"حلقه‌ی دستمال کاغذی سرویس اتاق","de":"دستمال کاغذی را در حلقه‌ای گرد جا می‌دهی تا شکلی منظم بگیرد. آداب یک وعده غذا از همین حلقه‌ی کوچک آغاز می‌شود؛ دقت و توجه، در کوچک‌ترین چیزها واضح‌ترین جلوه را دارد."},"ICON-2029":{"nm":"زیرانداز ضدلغزش سینی","de":"زیراندازی روی سینی بگذاری، ظرف‌ها نمی‌لغزند. نگه داشتنِ چیزها سر جایشان حتی در میان تکان‌ها؛ حتی در آرامشِ پایدار هم طراحیِ دقیقِ کسی نهفته است."},"ICON-2030":{"nm":"برچسب سفارش صبحانه برای دستگیره‌ی در","de":"برچسب سفارش صبحانه را به دستگیره بیاویزی، صبح فردا از پیش وعده داده می‌شود. نوشتنِ نخستین وعده در همین امشب، چهره‌ی دیگری از انتظاری مهربانانه است."},"ICON-2031":{"nm":"پایه‌ی تاشوی سینی","de":"پایه‌های سینی را باز کنی، حتی روی تخت هم به میزی واقعی بدل می‌شود. یک سفره‌ی صبحانه که در حالِ درازکش دریافت می‌شود؛ پایه‌ای کوچک، اتاقی معمولی را به منظره‌ای پرتجمل بدل می‌کند."},"ICON-2032":{"nm":"روکش گرم‌نگه‌دار قوری","de":"روکشی روی قوری بکشی، گرمای آب مدتی طولانی‌تر می‌ماند. مانند شب‌های کهن که دور آتشدان می‌نشستند، آرزوی نگه‌داشتنِ گرما هیچ عصری را نمی‌شناسد."},"ICON-2033":{"nm":"دنباله‌ی درخواست نظافت برای دستگیره","de":"دنباله‌ی درخواست نظافت را به دستگیره‌ی در می‌آویزی تا نشانه‌ای بی‌کلام بماند. خواسته‌ای که بی‌آنکه لب باز شود منتقل می‌شود؛ پشتِ اتاقی مرتب، وعده‌ی دستی نادیده نهفته است."},"ICON-2034":{"nm":"نگه‌دارنده‌ی ادویه‌دان سینی","de":"نگه‌دارنده محکم می‌گیرد تا ادویه‌دان‌ها واژگون نشوند. حفظ توازنِ طعم حتی بر سینیِ لرزان، سهمِ خاموشِ همین یک نگه‌دارنده‌ی کوچک است."},"ICON-2035":{"nm":"پایه‌ی نگه‌دارنده‌ی یادداشت رزرو","de":"یادداشت‌های رزرو را عمودی جا بدهی، نوبت‌ها با یک نگاه خوانده می‌شوند. ابزاری کوچک از جنسِ نظم، که برگه‌ای واحد را واضح سرپا نگه می‌دارد تا حتی دست‌های شلوغ هم گیج نشوند."},"ICON-2036":{"nm":"تابلوی نقشه با سنجاق نشانه‌گذاری","de":"سنجاق‌ها را روی نقشه فرومی‌بری و یکی‌یکی جاهایی را که دلت می‌خواهد بروی، نشان می‌زنی. هر سنجاق، هیجانِ جایی‌ست که هنوز ندیده‌ای؛ سفر همان لحظه‌ای آغاز می‌شود که نقشه را می‌گشایی."},"ICON-2037":{"nm":"گیره‌ی پرچم صدازدن تاکسی","de":"هنگام صدا زدنِ تاکسی، گیره پرچم کوچک را راست نگه می‌دارد. نشانه‌ای که پرچم به‌جای بالا بردنِ دست فریاد می‌زند؛ حتی در خیابان هم صدازدن باید واضح باشد تا برسد."},"ICON-2038":{"nm":"دستگیره‌ی زنگ کنسیرژ","de":"دستگیره را فشار دهی، صدایی زلال به میز کنسیرژ می‌رسد. نشانه‌ای از مهمان‌نوازی که می‌گوید هر چه می‌خواهی بپرس؛ در شهری غریب، اطمینان‌بخش‌ترین یک صدازدن."},"ICON-2039":{"nm":"تخته‌گیره‌ی شماره‌ی رزرو","de":"برگه‌ی شماره‌ی رزرو را در تخته‌گیره محکم می‌کنی تا واضح دیده شود. تا جای وعده داده‌شده اشتباه گرفته نشود، این وظیفه‌شناسیِ کوچکی‌ست که یک خط عدد را مرتب نگه می‌دارد."},"ICON-2040":{"nm":"قاب نمایش بروشور تور","de":"بروشورهای تور را بچینی، دستِ مسافر خودبه‌خود می‌ایستد. در هر برگه‌ای که یکی‌یکی برداشته می‌شود، منظره‌ی راه‌هایی که هنوز طی نشده، آرام تا شده است."},"ICON-2041":{"nm":"پایه‌ی مهر نقشه‌ی راهنما","de":"برای نخستین قدم‌هایی که به ورودی گذاشته می‌شود، جعبه‌ی مهر روی نقشه را ثابت نگه می‌دارد. وقتی جوهر پخش نشود، راه هم گیج‌کننده نمی‌شود. جایی که خاموش وزنه را نگه می‌دارد تا راهنمایی کوچک سرپا بایستد."},"ICON-2042":{"nm":"برچسب نگه‌داری چتر","de":"در بعدازظهری که قطره‌های باران از لبه‌ی سقف چکه می‌کرد، به هر چتر شماره‌ای می‌آویزند. وقتی کسی پس از پایان باران بازمی‌گردد تا مال خودش را بردارد، برچسب خاطره‌ی خیس را واضح صدا می‌زند."},"ICON-2043":{"nm":"پایه‌ی زنگ فراخوان میز اطلاعات","de":"یک‌بار دینگ صدا کند، کسی از آن سو با روی باز می‌دود. زنگ کوچکی که بر گوشه‌ی میز آویخته، مهربان‌ترین مترجم است، حتی حرف‌هایی را که نتوانستی به زبان بیاوری منتقل می‌کند."},"ICON-2044":{"nm":"نازل دیسپنسر شامپو","de":"کف دست را باز کنی و به‌آرامی فشار دهی، کف با صدایی نرم بیرون می‌زند. همان یک بار تخلیه‌ای که رایحه را در سراسر حمام می‌پراکند. زنگ بیداری‌ای که ملایم‌ترین شکل، صبحی خواب‌آلود را بیدار می‌کند، درست از همین‌جا آغاز می‌شود."},"ICON-2045":{"nm":"سینی تخلیه‌ی جاصابونی","de":"سینی‌ای که آب جمع‌شده زیر صابون را آرام بیرون می‌ریزد. تا نرم نشود، تا له نشود. ملاحظه‌ای کوچک و مهربانه، برای نگه‌داشتنِ چیزی که هر روز اندکی فرسوده می‌شود، یک وجب بیشتر در کنارت."},"ICON-2046":{"nm":"قاشقک نمک حمام","de":"قاشقی از پودر برمی‌داری و در آب گرم حل می‌کنی، رنگ و رایحه به‌آرامی پخش می‌شوند. تا مچ دست را می‌چرخانی، وان به دریاچه‌ای کوچک بدل می‌شود و خستگیِ یک روز آرام در آن فرومی‌رود."},"ICON-2047":{"nm":"کیسه‌توری کف صابون","de":"تکه‌ای صابون را در توری حبس کنی و بمالی، کف نرمی کف دست را پر می‌کند. کیمیاگرِ خاموشِ گوشه‌ای از حمام، که خشونت را به نرمی بدل می‌کند."},"ICON-2048":{"nm":"کلاهک ضدعفونی مسواک","de":"آرزوی این‌که هرچه به دهان می‌رسد، همیشه پاک باشد. یک کلاهک کوچک که نوکِ موهای مسواک را به‌نرمی می‌پوشاند، حتی جاهای نادیده را هم مراقبت می‌کند. پاکیزگی از انباشتِ همین چیزهای کوچک ساخته می‌شود."},"ICON-2049":{"nm":"درِ ظرف گوش‌پاک‌کن","de":"ظرفی که چوب‌های سفید در آن مرتب خوابیده‌اند، و دری که گرد روی آن را می‌پوشاند. بازش می‌کنی تیک، می‌بندی‌اش تاک. نقطه‌ای مهربانه که با صدایی کوچک، نظمِ حمام را به پایان می‌رساند."},"ICON-2050":{"nm":"بطری قطره‌چکان روغن حمام","de":"کمی خم کنی‌اش، قطره‌قطره روغن معطر می‌چکد. درخشش و رایحه‌ی ملایمی که در وان پخش می‌شود. برای تجملی بودن ساده است، برای عادی بودن مهربانه‌ست؛ یک قطره‌ی تنها."},"ICON-2051":{"nm":"جداکننده‌ی سینی لوازم بهداشتی","de":"روی سینیِ خانه‌خانه‌شده، بطری‌های کوچک هر یک جای خود را می‌یابند. چیزهایی که پراکنده باشند شلوغ‌اند و کنار هم آراسته می‌شوند. یک جداکننده، نظمِ صبحی شلوغ را نگه می‌دارد."},"ICON-2052":{"nm":"پایه‌ی ساعت شنی سونا","de":"وعده‌ای مهربانه است که دست‌کم تا وقتی همه‌ی شن فرو می‌ریزد، پشتت را گرم کنی. وقتی ساعت شنیِ تکیه‌داده به پایه‌اش زمان را دانه‌دانه می‌شمارد، آدمی در بخار غلیظ، لحظه‌ای هیچ‌کس نیست و آرام می‌گیرد."},"ICON-2053":{"nm":"حوله‌ی گوش‌گوسفندی سونا","de":"انتهای حوله را لوله کنی و مانند دو گوش سرپا بایستانی، چهره‌ی درون آینه به‌آرامی رها می‌شود. در میان بخار داغ، آیینی کوچک از سونا که هرکس لحظه‌ای به کودکی بازمی‌گردد."},"ICON-2054":{"nm":"ملاقه‌ی آب سونا","de":"ملاقه را پر از آب کنی و روی سنگ‌های داغ بریزی، فِسسس بخار تا سقف بالا می‌رود. در همان لحظه، تمام بدن در مه گرم فرومی‌رود و خستگیِ کهنه به‌آرامی در قطره‌های عرق آزاد می‌شود."},"ICON-2055":{"nm":"میله‌ی دماسنج وان پاشویه","de":"میله را در آب فرو ببری، خط‌ها به‌آرامی سخن می‌گویند. نه چندان داغ نه سرد شده، دقیقاً همان دما. پیش از فرو بردنِ نوک انگشتان پا، انگشتی که نخست از حالِ آب می‌پرسد."},"ICON-2056":{"nm":"انبر سنگ داغ سونا","de":"نمی‌شود سنگی تازه داغ‌شده را با دست خالی گرفت. وقتی انبر محکم آن را می‌گیرد و بالا می‌برد، گرما به فاصله‌ای امن جابه‌جا می‌شود. سونا آرام می‌گوید: احتیاط هم خودش یک هنر است."},"ICON-2057":{"nm":"زیرانداز سونا","de":"یکی روی کف داغ پهن کنی، جایی که پشت به آن می‌خورد بسیار نرم‌تر می‌شود. زیراندازی که روزی خیس از عرق را بی‌کلام می‌پذیرد. آرامش، در نهایت از فاصله‌ای مناسب با کف می‌آید."},"ICON-2058":{"nm":"کیسه‌ی نمک وان پاشویه","de":"مشتی نمک درشت را در آب گرم حل کنی، خستگی از نوک انگشتان پا به‌آرامی ذوب می‌شود. وقتی بخار شور دور ساق پا می‌پیچد، روزی که تمام روز پیموده شده، سرانجام می‌ایستد."},"ICON-2059":{"nm":"بشقاب سنگی عطر سونا","de":"چند قطره عطر روی سنگ داغ‌شده بریزی، رایحه‌ی گرم‌شده به‌آرامی در سونا می‌پراکند. چشم‌ها را ببندی، اینجا جنگل است یا مزرعه‌ی گل؟ کوتاه‌ترین سفر، سفری از راه بینی."},"ICON-2060":{"nm":"روکش گرم‌نگه‌دار کیسه‌ی گرم","de":"پارچه‌ای که کیسه‌ی گرم‌شده را نرم در بر می‌گیرد تا گرما دیرتر بماند. درست مانند دلی که آن را محکم در آغوش می‌گیرد مبادا سرد شود، گرمایی که روی شکم گذاشته شده، تمام شب همراهت می‌ماند."},"ICON-2061":{"nm":"چوب‌های معطرساز آروماتراپی","de":"چوب‌های نازک رایحه را می‌مکند و به‌آرامی در اتاق رها می‌کنند. عطری کم‌رنگ که با هر دم به درون نفوذ می‌کند. راهی که در آن فضای زندگی، اندک‌اندک به رایحه‌ی صاحبش شبیه می‌شود."},"ICON-2062":{"nm":"دستگیره‌ی تنظیم زاویه‌ی تخت آفتاب","de":"دستگیره را به‌آرامی بچرخانی، پشتی به‌نرمی خم می‌شود. کمی به سوی آفتاب، کمی به سوی سایه. یافتنِ راحت‌ترین زاویه با لمس، حسابی‌ست کاملاً از آنِ خودت."},"ICON-2063":{"nm":"نوار ضدلغزش لبه‌ی استخر","de":"نواری ضدلغزش که دور تا دور لبه‌ی آب کشیده شده. تا پاهای کوچکی که پاشیدن‌کنان با شادی می‌دوند، امن بایستند، این خط پایانِ ایمنی‌ست که آرام و نادیده پهن شده است."},"ICON-2064":{"nm":"حلقه‌ی سوپاپ هوای شناور","de":"به سوپاپ کوچکی که هوا را حبس می‌کند، حلقه‌ای با دقت بسته شده. تا سوپاپ، اگر از شناور جدا شد، روی آب شناور نرود. هوشی که پیشاپیش از یک گمِ کوچک در ظهرِ تابستان جلوگیری می‌کند."},"ICON-2065":{"nm":"کلاهک ورودی پله‌ی استخر","de":"کلاهکی که انتهای پله‌ی رو به آب را نرم می‌پوشاند. تا کفِ پای برهنه نخراشد، نخستین قدمِ ورود را نرم می‌پذیرد. چون هر آغازی باید همیشه با احتیاط باشد."},"ICON-2066":{"nm":"حلقه‌ی بند کوسن تخت آفتاب","de":"حلقه‌ای که بند را در آن می‌بندی تا کوسن نلغزد. وعده‌ای کوچک که حتی وقتی باد می‌وزد جایش را نگه دارد. یک گره، سستیِ بعدازظهر را همان‌جا میخکوب می‌کند."},"ICON-2067":{"nm":"تخته‌ی جاگذاری نوشیدنی کنار استخر","de":"تخته‌ای که لیوان نوشیدنی را درست کنار لبه‌ی استخر جا می‌دهد. جایی که حتی با آب‌بازی پرشور هم بی‌تزلزل می‌ماند. گذاشتنِ خنکی در دسترس، ظهرِ تابستان را طولانی‌تر می‌کند."},"ICON-2068":{"nm":"گیره‌ی آویزان کردن مایو خیس","de":"مایوی خیس را برمی‌داری و آرام به دستِ نسیم می‌سپاری. تا زیر آفتاب خشک می‌شود، گیره خاموش نگهش می‌دارد. انتظاری آرام و مهربانه، برای بازی بعدی در آب."},"ICON-2069":{"nm":"وزنه‌ی پایه‌ی چتر آفتابگیر","de":"وزنه‌ای سنگین که زیر پایه‌ی چتر گذاشته می‌شود تا با باد تلوتلو نخورد. اینکه سایه مدت‌ها در یک جا بماند، همه به لطف همین وزن است. اطمینان اغلب در پایین‌ترین جا پنهان می‌شود."},"ICON-2070":{"nm":"تراشه‌ی شناور دماسنج استخر","de":"تراشه‌ی کوچکی که روی آب شناور است و آرام دما را گزارش می‌دهد. اگر خیلی سرد باشد سرخ می‌شود، اگر مناسب باشد نرم می‌ماند. فال‌بینی بامزه که با یک رنگ، حالِ آب را می‌خواند."},"ICON-2071":{"nm":"منگوله‌ی زیپ چادر","de":"منگوله‌ی کوچکی که به انتهای زیپ آویخته را بکشی، درِ چادر به‌آرامی باز می‌شود. دستگیره‌ای که حتی وقتی انگشتان کورمال‌کورمال می‌روند، بی‌درنگ در دست می‌آید. رفت‌وآمدهای شبِ عمیق را مهربانانه راهنمایی می‌کند."},"ICON-2072":{"nm":"سنجاق پروانه‌ای بند چادر","de":"سنجاقی که بند را به شکل پروانه گاز می‌گیرد و محکم نگه می‌دارد. پارچه‌ای که در باد می‌رقصید، سرانجام آرام می‌گیرد. شبِ کمپینگ را همین گره‌های کوچک و کارآمد، خاموش پاسداری می‌کنند."},"ICON-2073":{"nm":"سوپاپ هوای تشک گلمپینگ","de":"دهانت را روی آن بگذاری و فوت کنی، فوت کنی، تشک به‌آرامی باد می‌شود. وقتی پر شد و سوپاپ را محکم می‌بندی، کف نرم می‌شود و جایی برای دراز کشیدن زیر نور ستاره‌ها، سرانجام کامل می‌شود."},"ICON-2074":{"nm":"قلاب سقفی چادر","de":"قلابی که از سقف چادر آویخته، برای آویختنِ فانوس یا دستمال. هوشِ خانه‌داری‌ای که حتی فضای کوچک بالای سر را با صرفه‌جویی به کار می‌گیرد. گویی به‌جای آسمان، ستاره‌ای بر سقف آویخته‌ای."},"ICON-2075":{"nm":"بند نگه‌دارنده‌ی کیسه‌خواب لوله‌شده","de":"بندی که دور کیسه‌خوابِ لوله‌شده پیچیده و بسته می‌شود تا باز نشود. رختخوابی که هر صبح دوباره کوچک می‌شود. آماده شدن برای رفتن، یعنی تا کردنِ منظمِ گرمای دیشب."},"ICON-2076":{"nm":"تخته‌ی جاکفشی ورودی چادر","de":"تخته‌ای که در ورودی چادر گذاشته می‌شود تا کفش‌ها را مرتب نگه دارد. خاک بیرون، درون تمیز. با یک آستانه، درون و بیرون را مهربانانه از هم جدا می‌کند، ادبی کوچک از کمپینگ."},"ICON-2077":{"nm":"قلاب آویز فانوس گلمپینگ","de":"قلابی خمیده برای آویختنِ فانوس. همین‌جا آویزانش کنی، نور به‌شکل گرد در چادر می‌پراکند. جایی که یک نور را در تاریکی می‌آویزی، امشب اتاق نشیمنِ ما می‌شود."},"ICON-2078":{"nm":"گیره‌ی لوله‌ی پنجره‌ی تهویه‌ی چادر","de":"گیره‌ای که پنجره‌ی تهویه را لوله می‌کند و نگه می‌دارد. راهی برای نسیم اندکی باز بگذاری، هوای درون چادر بسیار تازه‌تر می‌شود. یک شکاف کوچک، آرام فضایی برای نفس کشیدن در تمام شب می‌سازد."},"ICON-2079":{"nm":"زیرانداز کف چادر","de":"زیراندازی که کف چادر پهن می‌شود تا خاک و رطوبت را دور نگه دارد. یک لایه که حتی روی چمن هم رختخوابی خشک می‌گستراند. تا در طبیعت بمانی اما خیس نشوی، آرام کنار تو کمک می‌کند."},"ICON-2080":{"nm":"حلقه‌ی نگه‌دارنده‌ی هالتر","de":"حلقه‌ای که در دو سر هالتر بسته می‌شود تا صفحه‌ها نلغزند. قفلِ کوچکی که به‌طور کامل به وزنِ کسی که بلند می‌کند اعتماد می‌کند. فقط وقتی ایمنی محکم پشتیبانی کند، حد و مرز یک پله ارتقا می‌یابد."},"ICON-2081":{"nm":"کلاهک دستگیره‌ی کتل‌بل","de":"در آخرین ستی که فلز کف دست را می‌خراشد، همین یک کلاهک کوچک درد را ناپدید می‌کند. اینکه نگه‌داشتن تا انتها از بلند کردنِ وزنه سخت‌تر است را، دست پیش از هر چیز در همان نقطه‌ی پایانی می‌فهمد."},"ICON-2082":{"nm":"گوه‌ی جاسازی صفحه‌ی وزنه","de":"اگر صفحه‌ی وزنه اندکی بلرزد، حالت بدن پیش از بلند کردن فرو می‌ریزد. گوه‌ای که نازک در شکاف جا می‌گیرد، مرکز را بی‌صدا نگه می‌دارد. استواری همیشه در جاهایی نادیده و آرام آغاز می‌شود."},"ICON-2083":{"nm":"گیره‌ی قفلِ هالتر","de":"نوک انگشتانی که قفل را می‌بندند نباید هیچ تردیدی داشته باشند. همان صدای کلیکِ کوچکِ قفل شدن، تمام حرکتِ بعدی را بر دوش می‌کشد. بدن پیش از هر چیز یاد می‌گیرد که اعتمادش را به یک گیره بسپارد."},"ICON-2084":{"nm":"تراشه‌ی رنگی وزن صفحه","de":"تراشه‌ای که برای هر وزن رنگی متفاوت دارد، دست پیش از خواندنِ عدد هم آن را می‌شناسد. قرمز سنگین است و آبی سبک، به یاد سپردنِ وزن با رنگ. بدن به‌طرز شگفتی، نیرو را از راه چشم می‌سنجد."},"ICON-2085":{"nm":"پایه‌ی کف کتل‌بل","de":"به لطف پایه‌ای که سطح تماس با کف را گسترده می‌کند، پارکت زمین گود نمی‌شود. رد ورزش باید فقط در عرق و ماهیچه بماند. دلی کوچک که نمی‌خواهد حتی زیر پا هم زخمی بگذارد، همین‌جا نهفته است."},"ICON-2086":{"nm":"نشانه‌ی مرکز هالتر","de":"نشانه‌ای که در میانه‌ی میله حک شده، نقطه‌ی مرجع تعادل چپ و راست است. دستی که درست مرکز را می‌گیرد، لرزش را نصف می‌کند. لحظه‌ای که بدانی مرکز کجاست، سرانجام می‌توانی ایمن بلند کنی."},"ICON-2087":{"nm":"قفسه‌ی نگه‌داری صفحه‌های وزنه","de":"صفحه‌ی استفاده‌شده به جای خود بازمی‌گردد. منظره‌ی صفحه‌هایی که به ترتیب وزن روی قفسه آویخته‌اند، ملاحظه‌ای آرام برای نفر بعدی‌ست. کسی باور دارد که فضایی مرتب، مطمئن‌ترین وسیله‌ی ایمنی‌ست."},"ICON-2088":{"nm":"لبه‌ی توقف‌دهنده‌ی غلتش صفحه‌ی وزنه","de":"حادثه‌ی صفحه‌ای که روی زمین می‌غلتد و پشت پا را له می‌کند، همیشه در یک لحظه‌ی غفلت رخ می‌دهد. لبه‌ی توقف، همان چشم‌به‌هم‌زدن را آرام سد می‌کند. اتفاق بزرگ از جای بزرگ نمی‌آید، از شکافی کوچک می‌غلتد."},"ICON-2089":{"nm":"کوسن پشتی نیمکت","de":"اگر کوسنی که پشت را نگه می‌دارد بیش از حد سفت باشد، حتی تنفس هم کم‌عمق می‌شود. آن مرز میان به‌اندازه‌ی سفتی و به‌اندازه‌ی نرمی، نقطه‌ی توازنی‌ست که فقط کسی که مدت‌ها نشسته با نوک انگشت می‌یابد."},"ICON-2090":{"nm":"پین تنظیم ارتفاع رک","de":"با یک پین که ارتفاع را تعیین می‌کند، میله دقیقاً با شانه‌ی هر کسی هم‌اندازه می‌شود. اینکه آدم‌هایی با قدهای متفاوت، همان وسیله را دوستانه با هم به اشتراک بگذارند؛ یک سوراخ تنظیمِ کوچک، آن برابریِ مهربانانه را می‌سازد."},"ICON-2091":{"nm":"روکش قرقره‌ی دستگاه","de":"درون روکشی که قرقره را در بر گرفته، کابل بی‌صدا دور و دوباره دور می‌چرخد. قطعه‌ای که اصطکاک را درون پنهان می‌کند و فقط نرمی را به دست می‌دهد. وسیله‌ی خوب هرگز زحمتی را که خودش کشیده، در نهایت آشکار نمی‌کند."},"ICON-2092":{"nm":"پایه‌ی ضدلغزش پای نیمکت","de":"پایه‌های ضدلغزشی که در انتهای چهار پا جا گرفته‌اند، نیمکت را محکم به زمین می‌چسبانند. فقط وقتی نلرزد می‌توانی با خیال راحت تمام قدرتت را در آن بریزی. ثبات، در نهایت، از اصطکاکی کوچک در نوک پا آغاز می‌شود."},"ICON-2093":{"nm":"قلاب نگه‌داری هالتر رک","de":"قلابی که میله روی آن آویخته می‌شود، باید همیشه در ارتفاعی در دسترسِ دست باشد. جایی که بازوی خسته، سرانجام میله را به‌آرامی فرو می‌گذارد؛ همان یک‌وجب موقعیت، تمرین امروز را ایمن به پایان می‌رساند."},"ICON-2094":{"nm":"دستگیره‌ی پین وزن دستگاه","de":"دستگیره‌ای که پین را برای انتخاب وزن فرومی‌بری، باید صاف باشد تا ناخن آسیب نبیند. حتی در همان حرکت کوچکِ لحظه‌ی تغییرِ وزن، پرداختی که نوک انگشتِ آدمی را در نظر گرفته، آرام پنهان است، همان را حس می‌کنی."},"ICON-2095":{"nm":"اهرم قفل زاویه‌ی نیمکت","de":"اگر اهرمِ قفل‌کننده‌ی زاویه‌ی پشتی شل باشد، حالت بدن آرام‌آرام فرو می‌ریزد. اطمینانِ همان لحظه‌ای که با صدای کلیک ثابت می‌شود. مسئول باشگاه هر صبح که در را باز می‌کند، پیش از هر چیز همین صدا را آرام بررسی می‌کند."},"ICON-2096":{"nm":"پایه‌ی میله‌ی ایمنی رک","de":"در بدترین لحظه که هالتر از دست رها می‌شود، پایه‌ی میله‌ی ایمنی همان وزن را به‌جای تو در آغوش می‌گیرد. با پایه‌ای نادیده که همیشه پایین منتظر است، آدمی سرانجام می‌تواند تا مرز خودش پیش برود."},"ICON-2097":{"nm":"کلاهک انتهای کابل دستگاه","de":"کلاهک کوچکی که انتهای کابل را جمع می‌کند، آخرین گره در برابر بازشدن است. بستنِ مرتبِ رشته‌ها تا پراکنده نشوند؛ شکوهِ پایان‌بندی همیشه در همان نقطه‌ی پایانیِ نادیده می‌ماند."},"ICON-2098":{"nm":"کیسه‌ی پودر گچ","de":"مشتی پودر سفید که به دست می‌مالی تا لغزش را از بین ببرد. حتی اگر مثل آرایش پشت صحنه دیده نشود، ثباتِ همه‌ی حرکاتِ امروز، درست از همین یک مشت آغاز می‌شود. آماده‌سازی همیشه از نوک انگشتان شروع می‌شود."},"ICON-2099":{"nm":"گیره‌ی تمرین قدرت مچ","de":"گیره‌ی کوچکی که بی‌صدا مشت کردن و باز کردن را تکرار می‌کند، قدرت کف دست را می‌سازد. قدرت مچ دیرتر از عضلات بزرگ رشد می‌کند، پس این تمرینی هم هست برای آرام فرو گذاشتنِ بی‌تابی."},"ICON-2100":{"nm":"بند بازکننده‌ی انگشتان","de":"بندی که میان انگشتان جا می‌گیرد و آرام آن‌ها را به بیرون باز می‌کند. دستی که فقط از عضلات مشت‌کننده استفاده می‌کرد، قدرتِ بازشدن را دوباره می‌یابد. دست می‌گوید: به‌اندازه‌ی محکم گرفتن، رها کردنِ آرام هم تمرین می‌خواهد."},"ICON-2101":{"nm":"درپوش پودر گچ","de":"اگر درِ ظرفِ پودر گچ کمی هم شُل باشد، تمام داخل کیف سفید می‌شود. همین یک درپوشِ کوچک که درست جفت می‌شود، از پیش جلوی این دردسر کوچک را می‌گیرد. موفقیت در نگه‌داشتن چیزها همیشه به همان درپوش بستگی دارد."},"ICON-2102":{"nm":"باند نگه‌دارنده‌ی زانو","de":"باندی که دورِ زانو می‌پیچد و آن را نگه می‌دارد، باید دقیقاً در فشار مناسب متوقف شود. اگر خیلی سفت باشد جریان خون می‌بندد و اگر شُل باشد فایده‌ای ندارد، پس دستی باتجربه آن مرز ظریف را از روی خاطره آرام می‌سنجد."},"ICON-2103":{"nm":"بند کِشیِ مقاومتی","de":"بندِ کِشی که کشیده و رها می‌شود، بدون هیچ وزنه‌ای عضلات خفته را بیدار می‌کند. مقاومت لزوماً سنگین بودن نیست. حتی در برابر یک کشش نرم هم، بدن همیشه با صداقت پاسخ می‌دهد."},"ICON-2104":{"nm":"کیسه‌ی وزنه‌ی مچ پا","de":"کیسه‌ی شنی که به مچ پا بسته می‌شود، هر قدم را با سنگینیِ دلچسبی به پایین می‌کشد. کمی وزن که اضافه شود، حتی یک پیاده‌روی ساده هم به تمرینی جدی بدل می‌شود. حکمتی کوچک است، افزودنِ اندکی تلاش به زندگیِ روزمره."},"ICON-2105":{"nm":"میله‌ی غلتکی تقویت مچ","de":"میله‌ای که وزنه‌ی آویخته به یک بند را با مچ دست آرام‌آرام بالا می‌کشند. مچ دست کوچک‌ترین و بیشتر از همه فراموش‌شده‌ترین مفصل است، و همین ابزار ساده آن نیرویِ فراموش‌شده را آرام از نو زنده می‌کند."},"ICON-2106":{"nm":"توپ لاستیکی تقویت گرفتار","de":"توپی لاستیکی که در دست فشرده و رها می‌شود، حتی پشتِ میز هم تمرین را بی‌صدا ادامه می‌دهد. قدرتی که در لحظه‌های پراکنده جمع می‌شود، بیش از قدرتی که یک‌جا خرج می‌شود دوام می‌آورد. پایداری همیشه از همین چیزهای کوچک می‌روید."},"ICON-2107":{"nm":"قفل کمربند ضربان‌سنج","de":"اگر قفلِ باندِ دور سینه کمی هم جابه‌جا شود، عددها می‌پرند. حتی گوش‌دادن به صدای قلبِ خود نیز پیش از هر چیز به بستنی محکم نیاز دارد. هر اندازه‌گیری، در نهایت، از یک تماسِ بی‌فاصله آغاز می‌شود."},"ICON-2108":{"nm":"گیره‌ی نبض‌سنج","de":"گیره‌ای که نوکِ انگشت را آرام گاز می‌گیرد و نبض را بی‌صدا می‌شمارد. آن را جا می‌زنی و نفست را آرام می‌کنی، و ریتم قلبت به‌روشنی روی صفحه‌ای کوچک بالا می‌آید. بدن همیشه بی‌هیچ دروغی حال واقعی‌اش را می‌گوید."},"ICON-2109":{"nm":"جعبه‌ی بند ضربان‌سنج مچی","de":"جعبه‌ای که ضربان‌سنج مچی را در خود جا می‌دهد، کوچک است اما اهل خانه‌اش را می‌شناسد. هرچه وسیله‌ای کوچک‌تر و راحت‌تر گم شود، بیشتر به خانه‌ای برای بازگشت نیاز دارد. نگه‌داشتنِ خوبِ چیزها هم گونه‌ای از مهربانی است."},"ICON-2110":{"nm":"پرچمِ سنجاقیِ ریتم دو","de":"پرچم کوچکی که نقطه‌ی هدفِ دونده را دقیق نشانه می‌گذارد. یک نقطه‌ی از پیش تعیین‌شده -«فقط تا همین‌جا»- پاهای سنگین را تا انتها می‌برد. خط پایانِ درونِ دل را همیشه با دستِ خودت می‌کاری."},"ICON-2111":{"nm":"کلاهکِ چراغِ ضربان","de":"چراغِ کوچکی که هماهنگ با ضربان قلب بی‌صدا چشمک می‌زند. اگر آرام به ریتمِ روشن و خاموش‌شدنش خیره شوی، دل دوباره از این فکر می‌لرزد که زنده‌بودن چیزی این‌قدر منظم بوده است."},"ICON-2112":{"nm":"بندِ مهره‌ایِ شمارش دور","de":"با مهره‌هایی که یکی‌یکی جلو می‌روند، تعداد تکرارها را می‌شماری. لازم نیست عدد را در ذهن نگه داری؛ انگشت‌ها به‌جای تو به یاد می‌آورند. وقتی شمارش را به دست بسپاری، ذهن می‌تواند تمام‌وکمال روی حرکت بماند."},"ICON-2113":{"nm":"پدِ گیره‌ای اکسیژن خون","de":"پدِ گیره‌ای که به نوکِ انگشت وصل می‌شود، آرام مقدار اکسیژنِ خون را می‌خواند. وقتی عمقِ نادیدنیِ نفس به شکل عدد بالا می‌آید، دوباره درمی‌یابی که مراقبتِ بدن در نهایت چیزی نیست جز نگاهِ دقیق."},"ICON-2114":{"nm":"بندِ رنگیِ محدوده‌ی ضربان","de":"بندی که شدتِ تمرین را با رنگ تقسیم می‌کند، در یک نگاه می‌گوید الان چقدر تلاش می‌کنی. آبی یعنی راحت، قرمز یعنی حد نهایی. رنگ خودش زبانی مهربان می‌شود، پیمانی ساکت و ساده."},"ICON-2115":{"nm":"کپسولِ ژله‌ایِ اندازه‌گیری","de":"کپسول ژله‌ایِ کوچکی که حالِ بدن را می‌سنجد، در یک دانه اطلاعاتِ یک روز را به‌آرامی نگه می‌دارد. هرچه در پوسته‌ی شفافش باشد، آرزوی کمی بیشتر شناختنِ خود هم همان‌جا جای گرفته است."},"ICON-2116":{"nm":"قلابِ آویزِ حوله‌ی عرق","de":"این عادتِ کوچک که آن را هرجایی رها نکنی و همیشه روی قلابِ خودش بیاویزی، کل فضا را مرتب نگه می‌دارد. مثل همین قلاب که از پیش جایی برای بازگشتِ حوله می‌سازد، نظم همیشه در همین جزئیاتِ کوچک می‌درخشد."},"ICON-2117":{"nm":"بندِ درِ بطریِ آب","de":"بندِ کوتاهی که به درِ بطری وصل است، از پیشامدِ غلتیدن و گم‌شدنِ در جلوگیری می‌کند. حکمتِ بستنِ چیزی که آسان گم می‌شود به بدن؛ همین یک بندِ کوچک دردسرِ یک روز را آرام کنار می‌گذارد."},"ICON-2118":{"nm":"پره‌ی بادبزنِ تهویه","de":"پره‌ی بادبزنی که با بازشدنِ کامل باد می‌سازد. مثل بادبزن‌های قدیمی که عرقِ روزهای گرم را خنک می‌کردند، ساده‌ترین ابزار خنک‌ترین آرامش را می‌بخشد. یک وزشِ نسیم همیشه از نوکِ انگشتان جوانه می‌زند."},"ICON-2119":{"nm":"کیسه‌ی حوله‌ی خنک‌کننده","de":"کیسه‌ی کوچکی که حوله‌ای را نگه می‌دارد که با خیس‌شدن سرد می‌شود. یک تکه پارچه که گرما را می‌گیرد، آنجا آرام خوابیده تا بعد روی گردنِ خسته بنشیند و به‌آرامی گرمای نیمروز را با خود ببرد."},"ICON-2120":{"nm":"بشقابکِ زیرآب","de":"بشقابکی که از پیش جایی برای افتادنِ قطره‌های آب آماده کرده است. به‌جای سرزنشِ چکه‌کردن، پیش از هر چیز جایی برای گرفتنش می‌سازد. مهربانیِ آشپزخانه همیشه همین‌طور بی‌صدا باقی می‌ماند."},"ICON-2121":{"nm":"پره‌ی جهت‌دهِ پنکه","de":"همان لحظه که بادِ رو‌به‌رو در امتداد یک پره‌ی کوچک کمی به کنار می‌رود، هوای خفه‌ی سالن تمرین بالاخره نفسی تازه می‌کند. تغییرِ جریان همیشه از همین زاویه‌های ناچیز آغاز می‌شود."},"ICON-2122":{"nm":"هدبند پیشانی","de":"اگر موی جلوی سر هنگام شستنِ صورت خیس شود، کل روز به‌هم می‌ریزد. این باند که موها را آرام از روی پیشانی بالا می‌برد، پنج دقیقه‌ی خشک به کسیِ روبه‌روی آینه می‌بخشد. تازه وقتی نباشد می‌فهمی چه ارزشی داشت."},"ICON-2123":{"nm":"پایه‌ی گیره‌ایِ لیوان آب","de":"وقتی لیوان روی لبه‌ی میز خطرناک می‌لرزد، این گیره آرام یک طرفش را نگه می‌دارد. روزی که بی‌ریختن گذشت، یک جرعه آب به تو یادآوری می‌کند که به‌خاطرِ لبه‌ای است که کسی به‌جای تو گرفته."},"ICON-2124":{"nm":"دستگیره‌ی قلابیِ پنجره‌ی هوا","de":"پنجره‌ی کاملاً بسته خفه‌کننده است و پنجره‌ی کاملاً باز سرد. این دستگیره‌ی قلابی همان شکافِ درست را در میانه به یاد می‌سپارد. تهویه در نهایت کاری‌ست از جنسِ دل - به‌اندازه باز نگه‌داشتن."},"ICON-2125":{"nm":"کلاهکِ گوشه‌ی بلوکِ چوب‌پنبه‌ای","de":"همیشه گوشه‌ی تیز است که با برخورد آسیب می‌رساند. برای همین تکه‌ای چوب‌پنبه می‌تراشند و روی هر گوشه می‌کشند. جایی که این‌گونه نرم پوشیده شده، دیگر زانوی هیچ‌کس را نمی‌آزارد."},"ICON-2126":{"nm":"دستگیره‌ی بندیِ بولستر","de":"جابه‌جاکردنِ بالشِ بلند کاری‌ست دردسرسازتر از تصور. یک بند که وصل شود، در یک دست به‌راحتی جا می‌گیرد. راهِ سبک برداشتنِ چیزی سنگین، به همان جایی بستگی دارد که دستگیره را می‌گذاری."},"ICON-2127":{"nm":"تسمه‌ی بستِ کمربند","de":"روزهایی هست که کمر را یک پله بیشتر تنگ می‌کنی، و روزهایی که یک پله شُل می‌کنی. صادق‌ترین چیزی که حالِ آن روزِ تو را می‌داند، همین بندِ کوچک است. فلزی که صداقتِ بدن را بی‌کلام ثبت می‌کند."},"ICON-2128":{"nm":"پایه‌ی بلوکِ چهارقسمتی","de":"بلوکی که به چهار قسمت بریده شده، کف را محکم نگه می‌دارد. نه بیش از حد بلند، نه بیش از حد پایین - درست به همان اندازه‌ی تعادل. نگه‌داشتن یعنی خود را پایین آوردن تا چیزی بالاتر بایستد، همین‌طور بی‌صدا نشان می‌دهد."},"ICON-2129":{"nm":"روکش بولسترِ تخم‌مرغی","de":"بالشِ گرد و تخم‌مرغی‌شکلی را در جامه‌ای کاملاً برازنده می‌پوشانی. اگر هم عرق کند، همین که در می‌آوری و می‌شویی کافیست. زندگیِ روزمره می‌داند هرچه چیزی بیشتر با پوست تماس دارد، بیشتر به لباسی برای عوض‌کردن نیاز دارد."},"ICON-2130":{"nm":"گوه‌ی تراز‌کننده‌ی بلوک","de":"اگر کف زمین اندکی هم کج باشد، هر چه با زحمت روی هم چیده‌ای می‌لرزد. یک گوه‌ی نازک که در آن شکاف بگذاری، دنیا دوباره افقی می‌شود. برای راست کردنِ چیزها هیچ چیزِ بزرگی لازم نیست."},"ICON-2131":{"nm":"گره‌ی مهره‌ای انتهای بند","de":"طوری گره‌ای محکم می‌زنی که انتهای بند باز و ژولیده نشود. بندی که انتهایش با دقت بسته شده، عمر بیشتری می‌کند. همین یک گرهِ کوچک نشان می‌دهد که پایان دادن دشوارتر از آغاز کردن است."},"ICON-2132":{"nm":"پدِ تاشوی محافظ زانو","de":"آن دردِ تیزی که هر بار زانو به کفِ سخت می‌خورد. یک پد که تا می‌خورد و باز می‌شود، آرام میان زانو و زمین جا می‌گیرد. مهربانی‌ای‌ست که به‌جای زانوی کسی، بار را نگه می‌دارد."},"ICON-2133":{"nm":"کفیِ ضدلغزشِ بلوک","de":"حتی محکم‌ترین بلوک هم اگر بلغزد بی‌فایده می‌شود. شیارهای ریزِ کنده‌شده روی کف، زمین را محکم چنگ می‌زنند. راز پایداری همیشه در همان زیرِ نادیدنی پنهان است."},"ICON-2134":{"nm":"گیره‌ی میله‌ی تراز","de":"میله‌ها را صاف ردیف می‌کنی و با گیره سرِجا نگه می‌داری. کسی که به مرتب‌کردنِ صف‌ها عادت دارد، آن را می‌داند: آن رضایتِ عجیب و کوچکی که از کنارِ هم گذاشتنِ چیزهای نامنظم می‌جوشد."},"ICON-2135":{"nm":"حلقه‌ی بندِ همسترینگ","de":"وقتی پشتِ ران چنان می‌کشد که فریادی از دهانت می‌پرد، این حلقه به‌جای دستت نوکِ پایی را می‌گیرد که دستت به آن نمی‌رسد. جایی که به تنهایی نمی‌شد رسید، یک رشته بند برای پا پلی می‌سازد."},"ICON-2136":{"nm":"پدِ بازکننده‌ی انگشتان پا","de":"انگشتانِ پایی که تمام روز در کفش محبوس بوده‌اند هم به کمی استراحت نیاز دارند. روی پدی که آن‌ها را از هم باز می‌کند، پا بعد از مدت‌ها کش‌وقوس می‌آید. عصری که آزادسازی را از دورترین نقطه آغاز می‌کند."},"ICON-2137":{"nm":"گونیای زاویه‌ی وضعیت بدن","de":"با چشم اصلاً نمی‌شود فهمید حالتِ بدن چند درجه کج شده. وقتی گونیا آرام زاویه را می‌گوید، بالاخره بدن راست می‌ایستد. خط‌کشی که آن انحرافِ نادیدنی را نشان می‌دهد."},"ICON-2138":{"nm":"گوه‌ی تراز کردنِ لگن","de":"بعدازظهری کسل‌کننده که لگن به یک طرف کج مانده و سفت شده. یک گوه زیرش می‌گذاری و به‌آرامی مرکزِ تعادل را بازمی‌یابی. این کار زور زدن برای صاف‌کردن نیست، بلکه کمک به یافتنِ دوباره‌ی جای درست است."},"ICON-2139":{"nm":"قفل بندِ بازکننده‌ی شانه","de":"بندی که شانه‌های جمع‌شده را آرام باز می‌کند. قفل را که ببندی، کمرِ خمیده به‌آرامی باز می‌شود. با شانه‌های کاملاً گشوده نفسی عمیق بکش، تازه آن‌وقت است که حالتِ تعظیمِ روی صحنه شکل می‌گیرد."},"ICON-2140":{"nm":"گوه‌ی نگه‌دارنده‌ی ستون فقرات","de":"به پشت که دراز بکشی، ستون فقرات خمِ طبیعیِ خود را می‌کشد. گوه‌ای که بی‌آنکه با آن خم بجنگد، آرام نگهش می‌دارد. راهِ استراحتِ خوب، از پذیرفتنِ همان خمی که بدن با آن زاده شده آغاز می‌شود."},"ICON-2141":{"nm":"گوه‌ی کشش روی پا","de":"کششِ روی پا همیشه یک‌جوری ناقص می‌ماند. با گذاشتنِ گوه‌ای مناسب، تا عمقی که هرگز به آن نمی‌رسیدی به خوشی کشیده می‌شوی. شیبِ کوچکی که کمک می‌کند کمی دورتر برسی."},"ICON-2142":{"nm":"پایه‌ی هم‌ترازی مچ دست","de":"وقتی مچی که جلوی صفحه‌کلید خم شده گز‌گز می‌کند، این پایه آرام زیرِ آن سُر می‌خورد. اولین چیزی که از دستِ کارکشته مراقبت می‌کند، همین چیزهای کوچک و فروتنِ زیرین‌اند."},"ICON-2143":{"nm":"بانداژِ محافظ مچ دست","de":"پیش از بلندکردنِ چیزی سنگین، یک دور دیگر باند دورِ مچ می‌پیچی. اطمینانی که با هر دور پیچیدن بیشتر می‌شود. عادتِ پیش از آسیب پیچیدن، راز آرامِ کسانی‌ست که سال‌ها تمرین می‌کنند."},"ICON-2144":{"nm":"کیف بازوییِ گوشی","de":"همیشه این دغدغه بود که هنگام دویدن گوشی را کجا بگذاری. این کیفِ بسته‌شده به بازو، همان دغدغه را می‌برد. با آهنگی که دوستش داری بسته به بازو بدو، و مسیر کوتاه‌تر احساس می‌شود."},"ICON-2145":{"nm":"کلاهکِ فنرِ فشارسنج دست","de":"کلاهکی که روی نوکِ فنرِ فشارسنج دست کشیده می‌شود تا کف دست را نخراشد. در تمامِ فشردن و رهاکردن، همین درپوشِ کوچک صلح میان دست و فلز را نگه می‌دارد. توجهی در جایی نادیدنی."},"ICON-2146":{"nm":"انگشتانه‌ی محافظ نوک انگشت دستکش","de":"انگشتان مادربزرگ که به خیاطی عادت داشتند، همیشه انگشتانه‌ای بر انگشت داشتند. همین انگشتانه که به نوک دستکش وصل شده، نوکِ انگشت را نگه می‌دارد. مهرِ مراقبت از دستانی که سال‌ها کار کرده‌اند، حتی از نسلی به نسل دیگر عجیب همانند مانده."},"ICON-2147":{"nm":"پدِ پینه‌ی گرفتار","de":"پینه‌هایی که در کف دست بسته‌اند، اثرِ انگشتِ باقی‌مانده از تلاش‌اند. پدی که رویش می‌گذاری، تکرارِ بعدی را ممکن می‌کند. با پوشاندنِ دوباره‌ی همان جای سفت‌شده، آدمی باز هم آویزان می‌ماند."},"ICON-2148":{"nm":"نوارِ ضدلغزشِ کف دست","de":"اگر کف دست پیوسته بلغزد، همان چیزی را که با زحمت گرفته‌ای از دست می‌دهی. با پیچیدنِ نوارِ زبر، دست و ابزار یک تن می‌شوند. قدرتِ ازدست‌ندادن، عجیب از اصطکاک می‌آید."},"ICON-2149":{"nm":"بندِ جذبِ عرق بازو","de":"پیش از آنکه عرقی که هنگامِ تمرین جاری شده به مچ برسد، این بندِ روی بازو نخست آن را می‌مکد. اینکه عرق کردن جای شرمی ندارد، پارچه‌ای کاملاً خیس بی‌کلام گواهی می‌دهد."},"ICON-2150":{"nm":"جالباسیِ خشک‌کن دستکش","de":"هر جا که بی‌فکر رهایشان کنی، صبحِ فردا دردسر می‌شود، اما اگر مرتب آویزانشان کنی، باد تمامِ شب خودش لطیف خشکشان می‌کند. بویِ تمیزِ دستکش‌های خوب‌خشک‌شده، فردا را تازه می‌گشاید."},"ICON-2151":{"nm":"دستگیره‌ی زیپِ لباس ورزشی","de":"با دستِ خیسِ خیس اصلاً نمی‌توان زیپِ ریز را گرفت. یک دستگیره که وصل شود، با یک کشش تمیز باز می‌شود. حلقه‌ای بی‌اهمیت، یک دقیقه‌ی سراسیمگی را کامل نجات می‌دهد."},"ICON-2152":{"nm":"وصله‌ی تهویه‌ی عرق","de":"روی داغ‌ترین نقطه‌ی بدن یک وصله‌ی تهویه می‌گذاری. گرمای محبوس‌شده به‌آرامی از میانِ وصله بیرون می‌خزد. باز کردنِ یک منفذِ کوچک درست در مرکزِ خفگی."},"ICON-2153":{"nm":"تکه‌ی کوسنیِ کفی کفش","de":"فقط قسمتِ فرسوده‌ی کفیِ کهنه را می‌بری و تکه‌ای نو جایش می‌گذاری. دستی که همه‌چیز را دور نمی‌ریزد، بلکه فقط جای دردناک را عوض می‌کند. یک تعمیرِ کوچک زیرِ پا، هر قدمِ روز را سبک‌تر می‌کند."},"ICON-2154":{"nm":"وصله‌ی اتوییِ شماره‌ی لباس ورزشی","de":"شماره‌ی پشت را با اتو محکم به لباس فشار می‌دهی و می‌کارَی. تا گرما فروکش کند، عدد محکم جای خود را روی پارچه می‌گیرد. مهرِ آغازی که آدم‌های هم‌شماره را یک تیم می‌سازد."},"ICON-2155":{"nm":"کلاهکِ تقویت نوکِ کفش","de":"سرنوشتِ کفشی که نوکش پیوسته می‌خورد را، کلاهکِ تقویت‌شده‌ی روی نوک آرام سد می‌کند. اولین جایی که فرسوده می‌شود، محکم‌ترینِ همه است. هرچه کفشی عمرِ بیشتری داشته باشد، از همان نوک محکم‌تر است."},"ICON-2156":{"nm":"گره‌ی بندِ کشیِ لباس ورزشی","de":"همان لحظه که بندِ کمرِ لباس ورزشی را می‌کشی و گره می‌زنی، لباسِ شُل به بدن می‌چسبد. همین گرهِ محکم و بازنشدنی، در طولِ حرکاتِ شدید هر چیز را سرِجا نگه می‌دارد."},"ICON-2157":{"nm":"بندِ ضدلغزشِ جوراب مچی","de":"آن دردسرِ جورابِ مچی که پیوسته توی کفش لوله می‌شد. یک نوار همان لغزش را می‌گیرد. جورابی که به‌خاطرِ کوچکیش نادیده گرفته می‌شد، بالاخره جای خودش را نگه می‌دارد."},"ICON-2158":{"nm":"پدِ عرق زیربغل لباس ورزشی","de":"پدی که از پیش روی جایی می‌گذارند که عرق بیشتر از همه سر می‌زند. حتی اگر کاملاً خیس شود، هیچ اثری روی ظاهرِ لباس نمی‌ماند. چیزهایی که بی‌صدا در جایی نادیدنی کار می‌کنند، صحنه را تمیز نگه می‌دارند."},"ICON-2159":{"nm":"حلقه‌ی کشیدنِ پاشنه‌ی کفش","de":"بعد از پوشیدنِ کفش، حلقه‌ی پاشنه را می‌کشی و پا یک‌راست تویش می‌رود. آن راحتیِ کوتاه که دیگر لازم نیست خم شوی. صبحِ شلوغ، همین یک حلقه به‌کارِ خیر می‌آید."},"ICON-2160":{"nm":"کلاهکِ سرِ ماساژور","de":"بسته به جایی که می‌کوبی، سر را عوض می‌کنی. هر عضله‌ی گره‌خورده شکلی مناسب دارد. عصری که به شانه‌ای که روز را تاب آورده، درست به اندازه‌ی درست تسلی می‌بخشد."},"ICON-2161":{"nm":"پایه‌ی شارژِ ماساژور","de":"حتی دستی که قرار است تمامِ روز بدن را باز کند، تنها بعد از شارژ بیدار می‌شود. تا چراغِ قرمز سبز شود، می‌شود کمی استراحت کرد. وقتی چشمک ایستاد، آرام نوبتِ نوازشِ دوباره‌ی شانه‌های سفت فرا می‌رسد."},"ICON-2162":{"nm":"دیالِ شدتِ ماساژور","de":"کمی، یک‌کم بیشتر، همین‌جا. با چرخاندنِ دیال، انگشتان آرام با بدنِ خود چانه می‌زنند. عهدِ امروز -سفت‌شدن فقط به همان اندازه‌ای که درد می‌کشد- درست میانِ خط‌کش‌های ریز نوشته شده."},"ICON-2163":{"nm":"حلقه‌ی نگه‌دارِ توپِ لرزان","de":"حتی توپی که خوب می‌غلتد هم به جایی برای مکث نیاز دارد. این نگه‌دارِ گرد، دلِ فرارکننده را آرام در آغوش می‌گیرد و تا نوبتِ بعدی سرِ جایش نگه می‌دارد. استراحت هم بخشی از تمرین است."},"ICON-2164":{"nm":"کلاهکِ دسته‌ی چوبِ طب‌فشاری","de":"با یک کلاهکِ کوچکِ نوک، درد از کفِ دست به‌آرامی محو می‌شود. میانِ سختی و پوست همیشه یک لایه‌ی نرم لازم است. دستِ مهربانی که پیش از هر چیز جایِ تماس را گرد و نرم می‌کند."},"ICON-2165":{"nm":"کیسه‌ی غلتکِ بادومی","de":"کیسه‌ای کوچک که غلتکی به شکل بادوم زمینی در خود جا داده. وقتی از گوشه‌ی کیف بیرون می‌غلتد، عزمِ دیروز برای مراقبت از بدن هم همراهش بیرون می‌آید. یک کیسه‌ی کوچک آن پیمان را به یاد می‌آورد."},"ICON-2166":{"nm":"پایه‌ی غلتکِ ماساژِ پا","de":"اگر جایی که پا را می‌سپاری بلرزد، آرامش هم می‌لرزد. این پایه که غلتک را استوار نگه می‌دارد، کف زمین را محکم می‌چسبد و جایی می‌سازد که دو پای خسته با خیال راحت تکیه دهند. اطمینان از همان بی‌لرزشی می‌آید."},"ICON-2167":{"nm":"درپوشِ مغزی غلتک","de":"درپوشِ کوچکی که مغزیِ خالی را می‌پوشاند. باید درون نادیدنی پُر باشد تا بیرون از هم نپاشد. آن جایی که در طولِ غلتیدن هیچ‌کس نمی‌بیند، این قطعه‌ی ساکت بی‌صدا نگهش می‌دارد."},"ICON-2168":{"nm":"درپوشِ سرِ چوبِ ماساژ","de":"کلاهکی که گرد روی سرِ چوب کشیده می‌شود. تا نفرسوده و نخراشد -نگه‌داشتنِ نوک، در نهایت، راهِ همراه‌داشتنِ آن برای مدتی طولانی است. دلی که اولین جایی را که ضربه می‌خورد، نرم‌ترین‌گونه می‌پوشاند."},"ICON-2169":{"nm":"قیچیِ نوارِ تیپینگ","de":"با یک کشش از یک دست، نوار تمیز بریده می‌شود. برای بستنِ گره و تمام‌کردن هم نکته‌ای کوچک هست، و این تیغه حسِ یک پایانِ منظم را می‌شناسد. یک پایانِ تمیز، ادامه را سبک‌تر می‌کند."},"ICON-2170":{"nm":"کلاهکِ چسبیِ انتهای نوار","de":"کلاهکی که آرام انتهای نوار را می‌فشارد تا باز نشود. آغاز کردن کارِ همه‌کس است، اما چسبیده‌ماندن تا پایان همیشه سخت است. این دستِ کوچک که آخرین ذره را نگه می‌دارد، بی‌صدا مسئولِ پایانِ امروز است."},"ICON-2171":{"nm":"آستین فشارنده‌ی مچ دست","de":"یک لایه دورِ مچِ خسته که بپیچی، درد یک ضرب دیرتر می‌رسد. مثل دستی که آرام دستت را می‌گیرد، فشار گاهی مهربان‌ترین حفاظت می‌شود. این تنگ‌کردن نیست، این نگه‌داشتن است."},"ICON-2172":{"nm":"قفل بندِ محافظ مچ پا","de":"همان تیک کوتاهِ بستنِ قفل، خیال را راحت می‌کند. مچ پا که محکم پیچیده شود، شجاعتی آرام سر می‌کشد که می‌شود یک قدمِ دیگر هم دورتر رفت. یک صدای کوچک، آغازی مطمئن می‌شود."},"ICON-2173":{"nm":"بستِ بندِ فشاریِ زانو","de":"هرچه بند را می‌کشی، زانو محکم‌تر می‌شود. نه چندان که باز شود، نه چندان که آزار دهد - جایی درست میانِ این دو هست. بست هرگز همان نقطه را فراموش نمی‌کند."},"ICON-2174":{"nm":"قیچیِ تیپینگ انگشت","de":"قیچیِ کوچکی که نوارِ پیچیده‌دورِ بندِ انگشت را دقیق می‌برد. نوکش گرد است تا پوست را نخراشد. هرچه ابزار برای مراقبت باشد، تیغه‌اش مهربان‌تر تیز می‌شود، همین قیچی آرام آن را نشان می‌دهد."},"ICON-2175":{"nm":"قرقره‌ی جمع‌کننده‌ی بندِ فشاری","de":"قابی که بندِ فشاریِ بازشده را مرتب دوباره جمع می‌کند. دستی که آنچه استفاده کرده با دقت لوله می‌کند، دفعه‌ی بعد هم گره نمی‌خورد. در هر لایه‌ی مرتب‌جمع‌شده، نظمِ امروز نشسته است."},"ICON-2176":{"nm":"بندِ محافظ ساق پا","de":"بندی که پدِ محافظِ جلوی ساق را می‌بندد. دلی که اول جایی را که ممکن است بخورد وارسی می‌کند، خودش نوعی آمادگی است. با پاهایی که محکم گره خورده وارد زمین شوی، ترسِ دلت نصف می‌شود."},"ICON-2177":{"nm":"گیره‌ی محافظ آرنج","de":"گیره‌ای کوچک که محکم می‌گیرد تا محافظ لیز نخورد. مثل برداشتن یک برگ کاغذ بی‌اهمیت به نظر می‌رسد، اما اگر باز شود همه‌چیز شُل می‌شود. یک بستنِ کوچک، اطمینانِ یک روز را محکم نگه می‌دارد."},"ICON-2178":{"nm":"دستگیره‌ی حلقه‌ی کششی","de":"حلقه را می‌گیری و بدن را کش می‌دهی، و نوکِ انگشتانت را می‌بینی که یک وجب بیشتر از دیروز رسیده‌اند. تنها عضله نیست که با کشیدن بلندتر می‌شود؛ دلِ سفت‌شده هم در همان لحظه کمی باز می‌شود."},"ICON-2179":{"nm":"فاصله‌انداز انگشتان پا","de":"فاصله‌ی میانِ انگشتانی که تمام روز در کفش محبوس بوده‌اند را که باز کنی، نسیمی به آن جای تنگ می‌آید. در این دنیا چیزهایی هستند که فقط پس از کمی فاصله راحت می‌شوند. حتی نوکِ پا هم به جایی برای نفس‌کشیدن نیاز دارد."},"ICON-2180":{"nm":"تخته‌ی گوه‌ایِ باز کردنِ ساق","de":"زیرِ ساق پا مثل گوه که جا بگیرد، پا آرام باز می‌شود. یک زاویه‌ی کج، وزنِ یک روز را بی‌صدا رها می‌کند. کمی تکیه‌داده دراز کشیدن، گاهی راحت‌ترین حالت است."},"ICON-2181":{"nm":"پایه‌ی آرام‌کننده‌ی گردن","de":"گردن را رویش می‌گذاری و کمی چشم می‌بندی. این پایه‌ی کوچک همیشه از همان جا آرام به شانه‌ها زمزمه می‌کند که می‌شود سر سنگین را برای لحظه‌ای زمین گذاشت. حتی برای تکیه‌دادن هم شجاعت لازم است."},"ICON-2182":{"nm":"کلاهکِ سرِ میله‌ی کششی","de":"کلاهکی که سرِ میله‌ی دراز را می‌پوشاند. اگر نوک نرم باشد، هرکجا که برسد خیال راحت است. گِرد کردنِ لبه‌ها پیش از رسیدن به هرکس -توجه همیشه همین‌طور بی‌صدا آغاز می‌شود."},"ICON-2183":{"nm":"تخته‌ی برجستگیِ کوسنِ طب‌فشاری","de":"بدن را روی برجستگی‌های ناهموار می‌گذاری، و روز از هر نقطه‌ی فشرده بیرون می‌ریزد. در مرزِ آن دردِ خوش، شانه‌هایی که تمامِ روز سفت مانده بودند، آرام مثل تسلیم‌شدن باز می‌شوند."},"ICON-2184":{"nm":"ساعت‌شنیِ نفسِ آرام","de":"پیمانی آرام برای کشیدنِ نفسی بلند، تا آخرین دانه‌ی شن که بریزد. رشته‌ی نازکِ شن آرام ریتمِ دم و بازدم را می‌شمارد. دلِ شلوغ هم در همان میانه لحظه‌ای فرو می‌نشیند."},"ICON-2185":{"nm":"پایه‌ی توپِ طب‌فشاریِ کفِ پا","de":"توپی را زیرِ مرکزِ کف پا می‌گذاری و آرام فشار می‌دهی. به پاهایی که تمام روز کل بدن را نگه داشته‌اند، این پایه‌ی کوچک آرام جایش را می‌دهد و می‌گوید نوبتِ تو است که نگه‌داشته شوی. حتی آنچه نگه می‌دارد، گاهی زمان استراحت دارد."},"ICON-2186":{"nm":"بندِ حلقه‌ای آرام‌کننده‌ی شانه","de":"حلقه‌بندی که به شانه می‌اندازی و می‌کشی. طنابی را به سمتِ جای سفت می‌کشی، و مفصلِ گره‌خورده یک‌پله‌یک‌پله شُل می‌شود. نشان می‌دهد که حتی آزاد شدن هم به چیزی برای گرفتنِ دست نیاز دارد."},"ICON-2187":{"nm":"دیسکِ طنابِ خط شنا","de":"دانه‌ی گردِ طنابِ خط‌بندی که آب را تقسیم می‌کند. مرزی مهربان که روی آب کشیده‌اند تا با شناگرِ کناری برخورد نکنی. جداکننده‌های کوچکی که مسیرِ هرکس را نگه می‌دارند، همه را تا انتها کنارِ هم پیش می‌برند."},"ICON-2188":{"nm":"قلابِ کششِ طنابِ خط","de":"قلابی که طنابِ خط را محکم می‌کشد و آویزان نگه می‌دارد. اگر شُل باشد با موج خم می‌شود، اگر خیلی سفت باشد پاره می‌شود. یافتنِ کششِ درست شبیه محکم‌نگه‌داشتنِ دل است - همیشه در همان میانه به‌دنبالش می‌گردی."},"ICON-2189":{"nm":"کلاهکِ رنگیِ خط شنا","de":"کلاهکِ کوچکی که هر خط را رنگی جدا می‌کند. نشانه‌ای که رنگ خورده تا حتی از دور هم مسیرِ خودت را یک نگاه بشناسی. با یک رنگ کسی را از گم‌شدن نجات‌دادن -راهنمایی از همین مهربانی‌های کوچک آغاز می‌شود."},"ICON-2190":{"nm":"تخته‌ی آویزِ طناب خط شنا","de":"تخته‌ای برای آویزانِ مرتبِ طناب‌های خط، وقتی استفاده نمی‌شوند. در دستی که طناب‌ها را برای شروعِ بعدی با ظرافت مرتب می‌کند، آرام آرزوی خوب تمام‌کردنِ امروز نشسته است."},"ICON-2191":{"nm":"دستگیره‌ی قرقره‌ی طناب خط شنا","de":"دستگیره را دور و دور می‌چرخانی و طنابِ درازِ بازشده را جمع می‌کنی. جمع‌کردنِ چیزی که پراکنده شده همیشه صبر می‌خواهد. یک دور، باز یک دور - پایان این‌طور بدون شتاب، آرام کامل می‌شود."},"ICON-2192":{"nm":"گیره‌ی گرهِ انتهای خط","de":"گیره‌ای که محکم گاز می‌گیرد تا گره‌ی انتهای طناب باز نشود. حتی یک بندِ ریز را هم رها نمی‌کند. باید دستی باشد که تا آخر مواظب است، تا طنابی دراز هم بی‌آنکه از هم بپاشد شکل خودش را زیبا نگه دارد."},"ICON-2193":{"nm":"دانه‌ی شناورِ طنابِ خط","de":"دانه‌ی شناورِ طنابِ خط که روی آب بالا و پایین می‌رود. برای غرق‌نشدن، درونِ خودش پُر از هوا شده. آب موج‌دار هر بار نشان می‌دهد که برخی سبکی‌ها از خالیِ پُرشده با تلاش می‌آید."},"ICON-2194":{"nm":"پرچمِ شماره‌ی خط شنا","de":"پرچمِ کوچکی که شماره‌ی خط را اعلام می‌کند. یک تکه پارچه که در باد می‌رقصد، به‌روشنی می‌گوید «اینجا جای توست». نشانه‌ای کوچک اما بی‌ابهام که بی‌آنکه گم شوی، یک‌راست به مسیرِ خودت می‌بردت."},"ICON-2195":{"nm":"قلابِ اتصالِ طناب خط","de":"قلابی که دو طنابِ خط را به هم وصل می‌کند. با یک قلاب که مسیرِ بریده را دوباره پیوند می‌زند، آبراه بالاخره کامل می‌شود. پیوند دادن در نهایت کارِ تکه‌ای کوچک فلز است که آرام میانِ جداها دست دراز می‌کند."},"ICON-2196":{"nm":"کفِ استارتینگ بلاک","de":"کفی که روی خط شروع است، تمامِ وزنِ اولین جهش را می‌گیرد. آن ۰.۱ ثانیه‌ی پرتاب‌شدن، محکمی که نوکِ پا رویش می‌کوبد آغازِ مسابقه را هل می‌دهد. هر پروازی از جایی محکم برای پا گذاشتن آغاز می‌شود."},"ICON-2197":{"nm":"میله‌ی گیرهِ شروع","de":"میله‌ای که درست پیش از سوت شروع، دست‌ها محکم می‌گیرند. باید دلِ لرزان را جایی گره زد، وگرنه شروع می‌لرزد. همین که جایی برای گرفتن هست، حرکتِ بعدی روشن‌تر و محکم‌تر می‌شود."},"ICON-2198":{"nm":"بندِ پرچمِ شنای پشت","de":"بندِ پرچمی که به شناگرِ روبه‌سقف می‌گوید دیوار نزدیک است. مهربانی‌ای که از پیش جایی نادیدنی را خبر می‌دهد. با یک نشانه که مراقبِ پشتِ توست، آخرین ضربه امن می‌شود."},"ICON-2199":{"nm":"پدِ دیوارِ برگشت","de":"پدِ نرمی که روی دیوارِ محلِ تغییرِ جهت گذاشته‌اند. تا حتی با برخوردِ سخت هم درد نگیرد، جای چرخش را نرم می‌پوشاند. در مسیرِ بازگشت، همیشه توجهی آرام از پیش پهن شده."},"ICON-2200":{"nm":"تخته‌ی لمسیِ خط پایان","de":"همان لحظه که نوکِ انگشت لمس می‌کند، همه‌چیز تمام می‌شود. پایانِ مسیری طولانی و نفس‌گیر، در نهایت به همین یک ضربه‌ی سبک ختم می‌شود. تخته آرام پاسخ می‌دهد که رسیدن چیزِ بزرگی نیست، فقط لمسِ دقیقِ همان نقطه است."},"ICON-2201":{"nm":"نوار سرسره‌ی سکوی شروع","de":"هرکسی که بالای سرازیری می‌ایستد، دست‌کم یک‌بار نفسش را حبس می‌کند. از آن ترس کوتاه که بگذری و سر بخوری، پاچ! خنده همراه با پاشیدن آب می‌ترکد. شروع همیشه یک گام آن‌طرف‌تر از ترسی کوچک آغاز می‌شود."},"ICON-2202":{"nm":"مخروط نشانه‌ی فاصله‌ی چرخش","de":"وقتی سر دوراهی مردد می‌مانی، این نقطه‌ی کوچک اول از همه با تو حرف می‌زند. اینجا برگرد، می‌گوید، راه را گم نکن. کسی این یک رنگ را می‌بیند و دوباره جهتش را پیدا می‌کند و به راه می‌افتد."},"ICON-2203":{"nm":"گوه‌ی زاویه‌ی بلوک شروع","de":"درست پیش از جهش، آن نیم‌ضربانی که بدن پایین‌ترین حالتش را می‌گیرد. یک تکیه‌گاه کوچک آنجاست که زاویه را نگه می‌دارد تا نوک پا نلغزد. هر لحظه‌ی اوج‌گرفتن از همین شیب زاده می‌شود."},"ICON-2204":{"nm":"کلاهک ضربه‌گیر گوشه‌ی دیوار","de":"تا بازی‌کردن و برخوردکردن درد نیاورد، گوشه تیزی‌اش را واگذار کرده و گرد شده است. این آرزو که کسی صدمه نبیند، بار به بار تراشیده شده و به دیوار چسبیده. مهربان‌ترین محافظت معمولاً همین‌قدر بی‌صدا است."},"ICON-2205":{"nm":"قلاب آویز حلقه‌ی نجات","de":"در حالت عادی فقط جایی‌ست که چیزی از آن آویزان است. اما لحظه‌ای که کسی در آب بیفتد، اینجا اولین جایی‌ست که دست به سویش دراز می‌شود. در این دنیا نوعی اطمینان هست که بهتر است هرگز به کارش نیاید."},"ICON-2206":{"nm":"میله‌ی قلاب نجات","de":"بازویی دراز که فاصله‌ی دست‌نیافتنی را در یک حرکت کوتاه می‌کند. وقتی دست کوتاهی می‌آورد، این قلاب به‌جای دست می‌نشیند. نجات، در نهایت، همان رساندن نوک انگشتانت به کسی‌ست که دور است."},"ICON-2207":{"nm":"دوش کنار استخر","de":"«قبل از رفتن توی آب، حتماً آب‌کشی کن.» درست مثل جمله‌ی همیشگی نجات‌غریق، رشته‌ای از آب روی سرت می‌ریزد. با یک هجوم سرد، غبار روز قل می‌خورد و می‌رود."},"ICON-2208":{"nm":"کاشی کف ضدلغزش","de":"بافت‌های ریز و برجسته‌ای که نمی‌گذارند پای برهنه بلغزد. از جایی که دیده نمی‌شود، آرام کف پا را نگه می‌دارد. محکم‌ترین ایمنی همیشه در جای بی‌جلوه پنهان است."},"ICON-2209":{"nm":"تابلوی عمق آب","de":"پیش از آنکه پا بگذاری، عدد اول از همه عمق را می‌گوید. جایی که اگر ندانسته وارد شوی می‌ترساندت، همین که بخوانی‌اش دل آرام می‌گیرد. کار این تابلو کمک به یک آماده‌شدن کوچک است."},"ICON-2210":{"nm":"طناب شناور خط ایمنی","de":"طناب‌های رنگارنگی که روی آب می‌رقصند و ناحیه‌ها را از هم جدا می‌کنند. شناورها دست در دست هم قول می‌دهند: تا اینجا امن است. تا مرزی هست، بالاخره می‌شود با خیال راحت هرچه دل می‌خواهد شنا کرد."},"ICON-2211":{"nm":"حوضچه‌ی ضدعفونی پا","de":"تشت کوچکی که پای برهنه لحظه‌ای پیش از ورود به آب در آن می‌ماند. آیینی کوتاه که پاکیزگی از نوک پا آغاز می‌شود، همان‌جا نهفته است. پاکیزگی همیشه از همین یک قدم دلسوزانه شروع می‌شود."},"ICON-2212":{"nm":"مخروط هشدار کف خیس","de":"یک مخروط زرد به‌آرامی قدم‌ها را کند می‌کند. «اینجا خیس است، مواظب باش.» ملاحظه‌ای که به‌جای کلمه با رنگ گفته می‌شود. این هشدار کوچک، روز کسی را که نزدیک بود بلغزد، آرام نگه می‌دارد."},"ICON-2213":{"nm":"جعبه‌ی کمک‌های اولیه‌ی دیواری","de":"جعبه‌ی سفید روی دیوار به‌ندرت باز می‌شود. اما همان لحظه‌ای که باز شود، آرامش کسی می‌شود. اضطراری همیشه در نزدیک‌ترین جا بی‌صدا در انتظار است."},"ICON-2214":{"nm":"توری جمع‌آور سطح آب","de":"برگ و غباری را که روی سطح آب شناور است آرام بالا می‌کشد. زلالی خودبه‌خود نمی‌آید، پس باید دست کسی هر روز یک‌بار آن را جمع کند. پشت آب آرام، توری‌ای پرتلاش هست."},"ICON-2215":{"nm":"شیلنگ روبات نظافت کف","de":"حتی شبی که همه خواب‌اند، آرام کف را لمس‌کنان می‌گردد. سخت‌کوش‌ترین کارگر در ساعت‌هایی که کسی نگاه نمی‌کند. زلالی صبح، مسیری‌ست که این شیلنگ تمام شب کشیده است."},"ICON-2216":{"nm":"قوطی دوز کلر","de":"حتی نگه‌داشتن زلالی آب هم اندازه‌ی درستی می‌خواهد. زیاده‌روی تلخش می‌کند، کم‌آوردن کدرش، و تعادل جایی میان این دوست. دستی نادیدنی هر روز آرام آن خط‌کش را تنظیم می‌کند."},"ICON-2217":{"nm":"بطری آزمایش کیفیت آب","de":"کمی آب در بطری کوچکی جمع می‌کند و حال امروز را می‌پرسد. به چشم همان‌طور به‌نظر می‌رسد، اما عددها دروغ نمی‌گویند. آرامش خاطر چیزی‌ست که هر روز یک‌بار این‌گونه تأیید می‌شود."},"ICON-2218":{"nm":"چنگک جمع‌آوری تخته‌های شناور","de":"چنگکی دراز که تخته‌ها و زواید شناور روی آب را یک‌جا جمع می‌کند. دستی که پراکنده‌ها را گرد هم می‌آورد، به‌نوعی شبیه دل است. حتی درهم‌ریختگی هم با یک جارو مرتب می‌شود."},"ICON-2219":{"nm":"توری درپوش چاهک فاضلاب","de":"توری ریزبافتی که راه خروج آب را نگهبانی می‌کند. آرام تشخیص می‌دهد چه چیزی را باید گذراند و چه چیزی را نگه داشت. حتی برای رهاکردن هم صافی لازم است، این توری کوچک بی‌کلام می‌گوید."},"ICON-2220":{"nm":"شناور دماسنج آب","de":"پیش‌آهنگی کوچک که روی آب می‌رقصد و دما را می‌خواند. سرد است یا مناسب، مهربانی‌ای که پیش از تماس بدن خبر می‌دهد. اولین آرامش ورود به آب همیشه از این شناور آغاز می‌شود."},"ICON-2221":{"nm":"میله‌ی قرقره‌ی روکش استخر","de":"دسته‌ای که روکشی پهن را می‌پیچد و به گوشه‌ای می‌سپارد. ابزاری که می‌داند کی باز شود و کی جمع، به‌نوعی مطمئن است. در زمان استراحت، انگار برای آب هم یک لحاف می‌کشند."},"ICON-2222":{"nm":"سبد اسکیمر استخر","de":"سبدی که زواید شناور روی سطح آب سرانجام در آن جمع می‌شوند. چون ظرفی هست که تفاله‌ها را در جایی نادیدنی می‌گیرد، روی آب همیشه شفاف است. پشت پاکیزگی، رنج انباشته می‌شود."},"ICON-2223":{"nm":"جالباسی خشک‌کن کلاه شنا","de":"کلاه شنای خیس را وارونه آویزان می‌کنند. تا قطره‌ها یکی‌یکی می‌چکند، کلاه آرام نفسش را تازه می‌کند. خشک‌شدن، در نهایت، اسم دیگری برای انتظار است."},"ICON-2224":{"nm":"حلقه‌ی بند شانه‌ی مایو","de":"حلقه‌ی کوچکی که بند را نگه می‌دارد تا از شانه نلغزد. از جایی نادیدنی، آرام ظاهر تو را مرتب نگه می‌دارد. آراستگی همیشه روی همین تکیه‌گاه‌های کوچک کامل می‌شود."},"ICON-2225":{"nm":"کیسه‌ی مرتب‌سازی کلاه شنا","de":"کیسه‌ای که کلاه‌های شنای خیس یکی‌یکی جای خود را در آن پیدا می‌کنند. خانه‌ای کوچک که چیزهای زودپراکنده را در یک آغوش جمع می‌کند. مرتب‌کردن، عادتی مهربانانه برای گم‌نکردن است."},"ICON-2226":{"nm":"پد سینه‌ی مایو","de":"یک پد که آرام درون لباس جا خوش کرده. از بیرون دیده نمی‌شود، اما شانه‌های کسی که آن را پوشیده به‌آرامی صاف می‌کند. بعضی اطمینان‌ها نه از بیرون که از درون بی‌صدا پر می‌شوند."},"ICON-2227":{"nm":"گیره‌ی برچسب اسم کلاه شنا","de":"گیره‌ی کوچکی که برچسب اسمی را به لبه‌ی کلاه شنا می‌چسباند. میان چیزهای شبیه‌به‌هم، واضح می‌گوید: «این مال من است.» یک نشانه کافی‌ست تا اشتباه‌گرفتن یک‌باره تمام شود."},"ICON-2228":{"nm":"حلقه‌ی زیپ مایو","de":"«می‌شه زیپ پشتم رو بکشی بالا؟» جایی که تنها به آن نمی‌رسیدی، این حلقه‌ی کوچک به‌جای دست بالا می‌کشد. کمکی مهربان برای همان یک بند آخر."},"ICON-2229":{"nm":"تخته‌ی ضدپیچش کلاه شنا","de":"کلاه شنایی را که عادت به پیچیدن کرده صاف می‌کنند و تکیه می‌دهند. تکیه‌گاهی که آرام کمک می‌کند چیز خمیده شکل خود را بازیابد. باید دستی باشد که صافش کند تا هر چیزی دوباره درست و راست شود."},"ICON-2230":{"nm":"بندکش کمر مایو","de":"بندکشی که کمر را درست‌اندازه در بر می‌گیرد تا سر نخورد. نه خیلی تنگ نه خیلی شل، دقیقاً به همان اندازه‌ی درست. راحتی همیشه جایی میان همین دو زندگی می‌کند."},"ICON-2231":{"nm":"گیره‌ی برگرداندن کلاه شنا","de":"گیره‌ای که کلاه شنای پشت‌ورو را می‌گیرد و در یک حرکت درستش می‌کند. حس‌ودست برگرداندن چیز واژگون تا حدی لذت‌بخش است. لذت کوچک مرتب‌کردن از همین چیزهای پیش‌پاافتاده می‌آید."},"ICON-2232":{"nm":"بند دسته‌ی تخته‌ی شنا","de":"بندی که دور دست می‌پیچد تا تخته‌ی شنا از دست نرود. حتی وقتی موج تو را می‌راند، داشتن جایی برای گرفتن، آرامشی بزرگ است. لرزش همان روزی که اولین بار شنا یاد گرفتی، هنوز روی این بند مانده."},"ICON-2233":{"nm":"بند سفت‌کننده‌ی بویه‌ی شنا","de":"بندی که بویه‌ی میان دو ران را محکم نگه می‌دارد. فقط وقتی شل نمی‌شود می‌توانی تمام حواست را به فرم بدهی. روی چیزی که خوب نگه داشته شده، تمرین آن روز کم‌کم عمیق‌تر می‌شود."},"ICON-2234":{"nm":"جالباسی دیواری فین شنا","de":"وقتی فین‌ها کنار هم روی دیوار آویزانند، درست شبیه گله‌ای اردک‌اند که کنار آب استراحت می‌کنند. پاهایی که شنا را تمام کرده‌اند آب را تکان می‌دهند و فردا را انتظار می‌کشند. حتی مکث هم جایی‌ست گرد و دوست‌داشتنی."},"ICON-2235":{"nm":"کلاهک گوشه‌ی تخته‌ی شنا","de":"کلاهک کوچکی که روی گوشه‌ی تخته‌ی شنا کشیده شده. تا برخورد درد نیاورد و فرسایش خرابش نکند، لبه را در بر می‌گیرد. راز کنار خود نگه‌داشتن چیزی برای مدت طولانی، در دلسوزی از همان گوشه‌هاست."},"ICON-2236":{"nm":"توری نگهداری فین شنا","de":"فین‌هایی شبیه پای پرده‌دار، داخل توری زیر آفتاب حمام می‌کنند. مثل اردک‌هایی که تازه از آب درآمده‌اند و پرهایشان را خشک می‌کنند، آرام داخل توری خشک می‌شوند. چرتی آسوده برای شنای بعدی."},"ICON-2237":{"nm":"برچسب مرتب‌سازی بویه‌ی شنا","de":"برچسب اسمی به هر بویه می‌چسبانند تا صاحبش روشن باشد. هرچه جایی بیشتر بین چند نفر تقسیم شود، وقتی «مال کیست» روشن باشد دل بیشتر آرام است. یک برچسب کوچک نظم برقرار می‌کند."},"ICON-2238":{"nm":"پایه‌ی زهکشی تخته‌ی شنا","de":"جایی که کج گذاشته شده تا آب جمع‌شده در تخته‌ی شنا آرام بچکد. باید آنچه را در خود گرفته‌ای خالی کنی تا سبک شوی، پایه بی‌کلام این را می‌گوید. اولین قدم خشک‌شدن، خوب‌تکیه‌دادن است."},"ICON-2239":{"nm":"بندکش تسمه‌ی فین شنا","de":"قطعه‌ی کوچکی که بند فین را درست‌اندازه‌ی پا سفت می‌کند. اگر شل باشد درمی‌آید، اگر سفت باشد درد می‌کند، همان یک درجه‌ی ظریف میان این دو. برای پیش‌رفتن سبک مثل اردکی پابرده، این یک ذره لازم است."},"ICON-2240":{"nm":"چیپ ریتم لگدزدن","de":"چیپ کوچکی که هر بار پا می‌زنی، ضرب را می‌گوید. یک، دو، سه—وقتی ریتم در بدن جا می‌گیرد، آب هم بی‌آنکه بفهمی به آواز تبدیل می‌شود. این چیپ آرام یاد می‌دهد که شنا هم ریتم دارد."},"ICON-2241":{"nm":"کیسه‌ی مایوی خیس","de":"توی کیف بیرون از استخر، همیشه من اول جایم را می‌گیرم. بقیه‌ی وسایل هرچه چپ‌چپ نگاه کنند، چه کنم، خیس باید جدا نگه داشته شود تا همه خشک بمانیم. اتاق قرنطینه‌ی رطوبت، همین است سمتی که مهربانانه به عهده گرفته‌ام."},"ICON-2242":{"nm":"تخته‌ی فشار آب‌گیری","de":"رطوبت خصلتی دارد که با فشار آرام فرار می‌کند. یک فشار محکم، دوباره یک فشار—تنها وقتی روی تخته وزن می‌گذاری تسلیم می‌شود. برای کسی که هیچ‌وقت جایی برای زور مچش نداشته، صحنه‌ای به این خوبی کم پیدا می‌شود."},"ICON-2243":{"nm":"تخته‌ی جداکننده‌ی کیف شنا","de":"اگر همه را در یک محفظه بریزی، خیس و خشک به هم می‌مالند. کاری که آرام میانشان می‌لغزد و خطی می‌کشد. اگر یک جداکننده صلح بیاورد، شاید آشتی چیزی به این سادگی باشد."},"ICON-2244":{"nm":"کیسه‌ی ضدآب کفش","de":"کفش‌های شن‌آلود را یکجا می‌بلعد بی‌آنکه حالتش عوض شود. هرچه داخلش بگذرد، بیرون خشک بماند—این ادبی‌ست که ضدآب‌بودن رعایت می‌کند. کیسه‌ی دهان‌بسته همه‌جا خوش‌آمد است."},"ICON-2245":{"nm":"درپوش زهکش کیف شنا","de":"درپوش را که بچرخانی، روزی که ته کیف جمع شده بود یک‌جا خالی می‌شود. جمع‌وجورکردن بعد از یک بازی خوش همیشه به همین یک سوراخ کوچک بستگی دارد. حتی بلدبودن چیزی را رهاکردن هم طراحی می‌خواهد."},"ICON-2246":{"nm":"پادری جاذب رطوبت","de":"آرام جلوی در می‌خوابد و رطوبت هر پایی را که وارد می‌شود می‌گیرد. حتی اگر کسی قدرش را نداند، کف چوبی می‌داند—امروز هم کسی نلغزید. در جای بی‌صدا، پاداشی بی‌صدا نهفته است."},"ICON-2247":{"nm":"نعلبکی نگهداری کلاه شنای خیس","de":"وقتی کلاه شنایی که کنار انداخته شده جایی برای رفتن ندارد، من نگهش می‌دارم. هرچند نعلبکی صدایم می‌کنند اما به‌جای غذا قطره‌های آب می‌گیرم، اگر کارم جادادن کسی باشد، حتی یک پایه هم می‌تواند سربلند باشد."},"ICON-2248":{"nm":"گیره‌ی خشک‌کردن حوله","de":"کار من محکم گازگرفتن یک حوله روی بند رخت است. هرچه باد اذیت کند رها نمی‌کنم، این لجاجت افتخار من است. تا زیر آفتاب خشک و نرم شود، دستی که یک‌بار گرفته هرگز اول رها نمی‌کند."},"ICON-2249":{"nm":"آویز کیف ضدآب","de":"همان لحظه که به قلاب آویزان می‌شود، کیف سرگردان بالاخره یک نشانی پیدا می‌کند. حتی اگر فقط آویزان باشد و یک وجب دیوار قرض کرده باشد، آیا چیزی به‌اندازه‌ی جایی که نگرانی گم‌شدن ندارد اطمینان‌بخش هست؟"},"ICON-2250":{"nm":"دستبند ورود سرسره","de":"شوری که آرام در انتظار نوبت مانده، همه‌اش در همین یک بند کوچک بسته شده. تازه وقتی به مچ بسته می‌شود صف سرسره شروع به موج‌زدن می‌کند، پس شاید ورود همان بستن یک قول به دور مچ باشد."},"ICON-2251":{"nm":"تکه‌ی مت سرسره‌ی آبی","de":"مردم بی‌آنکه بفهمند زیر پایشان شکافی هست، شاد می‌دوند. جایی که پهن شده تا کسی نلغزد، فقط وقتی همان یک تکه گم شود وجودش آشکار می‌شود. در این دنیا چیزهای زیادی هستند که فقط با جای خالی‌شان یادآوری می‌شوند."},"ICON-2252":{"nm":"بند ضدآب کلید کمد","de":"نگهبانی کلید کمد در برابر آب، شغل تمام‌عمر من است. دور مچ می‌پیچم و همراهش پاچ‌پاچ می‌کنم، اما فقط همان یک کلید را کاملاً خشک نگه می‌دارم. اگر مرا گم کنی حتی لباست را هم پیدا نمی‌کنی، پس همین‌قدرها مسئولی سنگین‌بار هستم."},"ICON-2253":{"nm":"تابلوی چراغ سیگنال شروع سرسره","de":"در آن لحظه‌ی کوتاه که قرمز به سبز تبدیل می‌شود، قلب همه‌ی بالای سرسره با هم می‌تپد. اختیار اجازه‌ی شروع—چه کسی فکرش را می‌کرد این تابلوی سیگنال کوچک بتواند این‌همه شور در خود جا دهد."},"ICON-2254":{"nm":"سگک جلیقه‌ی نجات رودخانه‌ی تنبل","de":"سگکی که بدن شناور روی رودخانه‌ی تنبل را محکم نگه می‌دارد. تازه بعد از صدای کلیک است که با خیال راحت خود را به جریان می‌سپاری. آرامش خاطر گاهی از همین قفل کوچک آغاز می‌شود."},"ICON-2255":{"nm":"پرچم راهنمای استخر موج","de":"از پیش به همه می‌گوید موج کی می‌رسد. بالارفتن پرچم یعنی هلهله، پایین‌آمدنش یعنی لحظه‌ای برای نفس‌تازه‌کردن. جالب اینکه چیزی که ضرب را کنار استخر خروشان نگه می‌دارد فقط یک تکه پارچه است."},"ICON-2256":{"nm":"گردنبند شماره‌ی سرسره","de":"اگر شماره‌ی صف را دور گردن آویزان کنی، اشتباهی پیش نمی‌آید. منظره‌ای که با یک برچسب شماره نوبت مشخص می‌شود—نظم، این‌طور به‌نظر می‌رسد، اغلب از یک گردنبند کوچک شروع می‌شود."},"ICON-2257":{"nm":"توکن شارژ دستبند آبی","de":"کمی روی دستبند لمسش کنی، شارژ تمام می‌شود. عصری که بی‌پول نقد و کارت در آب می‌گردی، این توکن کوچک نقش کل کیف‌پول را بازی می‌کند. هرچه مچ سبک‌تر باشد، دل هم سبک‌تر است."},"ICON-2258":{"nm":"کلاهک دسته‌ی توپ آبی","de":"دسته‌ی توپ آبی وقتی محکم گرفته شود بهترین حس را می‌دهد. یک کلاهک را گم کنی، نشانه‌گیری هم فراموش کن، همین‌طور در دستت می‌چرخد—سرنوشت یک نبرد آبی وسط تابستان به همین یک قطعه‌ی کوچک بستگی دارد."},"ICON-2259":{"nm":"قالب برج قلعه‌ی شنی","de":"شن خیس را محکم فشار می‌دهی، وارونه می‌کنی، و برجی کوچک بالا می‌آید. کسی بهتر از من دلی را که با دانستن فروریختن باز هم می‌سازد، نمی‌شناسد. برای معمار شن، قالب همان نقشه است."},"ICON-2260":{"nm":"دندانه‌ی شانه‌ی شن","de":"مثل شانه‌کردن روی شن بکشی، شیارهایی منظم می‌ماند. با اینکه می‌داند موج به‌زودی نقش را پاک می‌کند، دندانه‌ها باز هم پرتلاش خط می‌کشند. حتی ساختن با عشق چیزی که قرار است ناپدید شود، ظرافت خودش را دارد."},"ICON-2261":{"nm":"وزنه‌ی لنگر پایه‌ی چتر آفتابی","de":"بی‌صدا کنار پایه می‌ایستد تا چتر آفتابی با باد پرواز نکند. نگه‌داشتن سایه کار پارچه‌ی پرزرق‌وبرق نیست، کار همان وزنه‌ی سنگین و ثابت‌شده است. سنگینی نادیدنی همیشه مطمئن‌ترین است."},"ICON-2262":{"nm":"دسته‌ی الک شن","de":"شن را تکان‌داده که الک کنی، فقط صدف و گنجینه‌های کوچک در دستت می‌ماند. دسته را بگیر و تکان بده، نیمی از گنج‌یابی کنار دریا با همین یک الک تعیین می‌شود."},"ICON-2263":{"nm":"قالب شنی صدف‌شکل","de":"پرش کنی از شن خیس، بزن‌بزن، صدف‌هایی به‌اندازه‌ی کف دست روی ساحل ردیف می‌شکفند. شاید نتوانی صدف واقعی را بخوری، اما این شکل را هرکسی می‌تواند بسازد. جادویی ساده از تابستان."},"ICON-2264":{"nm":"پین تنظیم زاویه‌ی چتر آفتابی","de":"هر بار که خورشید جابه‌جا می‌شود، چتر آفتابی هم باید سرش را بچرخاند تا دنبالش کند. پین را بیرون بکشی و دوباره بزنی، سایه آرام جا عوض می‌کند. قلب هنر دوری‌کردن از نور در همین زاویه‌ی کوچک است."},"ICON-2265":{"nm":"کلاهک نوک تیغه‌ی بیل شن","de":"روی نوک تیز بیل بکشی، داخل کیف امن می‌شود. شجاعت کندن شن را لحظه‌ای کنار بگذار، با یک کلاهک به اسباب‌بازی‌ای رام تبدیل می‌شود. بلدبودن پنهان‌کردن تیزی هم نوعی ملاحظه است."},"ICON-2266":{"nm":"گیره‌ی گوشه‌ی مت ساحلی","de":"وقتی باد می‌خواهد گوشه‌ی مت را بلند کند، من محکم گازش می‌گیرم. نگه‌داشتن یک جا روی شن‌زار در نهایت به لجاجت هر چهار گوشه بستگی دارد. عصری بی‌تکان کار همین گیره‌های کوچک است."},"ICON-2267":{"nm":"قلاب لباس‌آویز سایه‌ی چتر","de":"بی‌خیال روی پایه‌ی چتر آویزانش کنی، لباس‌های خیس در سایه خشک می‌شوند. دور از آفتاب، رو به نسیم، یک بند رخت موقت که با یک قلاب برپا شده. حتی در ساحل هم حکمت خانه‌داری جریان دارد."},"ICON-2268":{"nm":"کیسه‌ی گردنی ضدآب گوشی","de":"گوشی را در آغوش می‌گیری و دور گردن می‌آویزی، حتی زیر آب هم شجاعت عکس‌گرفتن پیدا می‌شود. حفظ خواسته‌ی یک قاب بیشتر ثبت‌کردن، به‌شکل ضدآب. برای یک محافظ خاطرات، خیلی هم قابل اعتماد است."},"ICON-2269":{"nm":"کیسه‌ی ضدآب لباس خیس","de":"لباس‌های عوض‌شده‌ی خیس را بی‌غرغر یکجا در آغوش می‌گیرد. غرورش این است که حتی یک قطره آب به بقیه‌ی وسایل نرسد، پس دهانش را محکم می‌بندد و گوشه‌ای از کیف را نگهبانی می‌کند. پایان تمیز، از من شروع می‌شود."},"ICON-2270":{"nm":"بند روی‌پای صندل آبی","de":"آرام روی‌پا را در بر می‌گیرد تا صندل پابرهنه در نیاید. هرچند روی شن‌زار بدو بدو کنی، با یک بند خیالت راحت است. همراهی مطمئن قدم‌ها، بی‌سروصدا اما همیشه کنارت."},"ICON-2271":{"nm":"کیس گردنی ضدآب کارت","de":"بلیت و کارت را در آغوش می‌گیرد و دور گردن آویزان، همراه بازی آبی می‌شود. بدون نگرانی گم‌کردن هرچه دلت می‌خواهد پاچ‌پاچ کن، خودش را سپر کارت می‌کند. حالت یک محافظ قابل اعتماد."},"ICON-2272":{"nm":"کیسه‌ی پارچه‌ای ضدبخار عینک شنا","de":"داخل عینک شنایی که تار شده را یک‌بار با پارچه پاک کنی، دنیای زیر آب دوباره واضح می‌شود. یک کیسه‌ی پارچه‌ای کوچک همان کلیدی‌ست که دید تار را باز و روشن می‌کند."},"ICON-2273":{"nm":"برس تکاندن شن خیس","de":"حتی شن میان انگشتان پا را هم به‌آرامی می‌تکاند. دستی که آخرین بار جلوی در خانه، اثر یک روز پرشور در دریا را مرتب می‌کند. یک بار عبور برس، و شن یک روز بالاخره خداحافظی می‌کند."},"ICON-2274":{"nm":"کیسه‌ی زیپی ضدآب سکه","de":"چند سکه را محکم پشت زیپ حبس می‌کند. خیس شود یا نه، صدای جرینگ همان است، پس پول اضطراری برای بوفه تا آخر نگهبانی می‌شود. کیسه‌ای کوچک اما کاردان در خانه‌داری."},"ICON-2275":{"nm":"بند رول‌کردن حوله‌ی آب‌بازی","de":"حوله را رول کنی و با یک بند ببندی، درست به بند کوله آویزان می‌شود. هر دو دست آزاد، حوله روی شانه. راز سبک‌بارکردن آب‌بازی در همین یک بسته‌بندی کوچک پنهان است."},"ICON-2276":{"nm":"کلاهک جاکلیدی بند ضدآب","de":"دکمه‌ی پایانی بندی که کلید را در برابر آب نگه می‌دارد. فقط وقتی کلاهک کلیک می‌کند و بسته می‌شود، بالاخره با خیال راحت به استخر می‌پری. نقطه‌پایانی کوچک اما بی‌نقص که مسئولیت بستن قفل را به عهده دارد."},"ICON-2277":{"nm":"پلاگ دهانی اسنورکل","de":"به دندان بگیری، راه نفس باز می‌شود و منظره‌ی زیر دریا درست جلوی چشمت می‌آید. پلاگی کوچک که حتی زیر آب هم اجازه‌ی نفس‌کشیدن می‌دهد. چه کسی فکرش را می‌کرد قرض‌دادن یک نفس این‌قدر می‌تواند هیجان‌انگیز باشد."},"ICON-2278":{"nm":"پد ضدبخار ماسک","de":"وقتی داخل ماسک تار می‌شود، تماشای زیر آب هم کیفش را از دست می‌دهد. یک پد جلوی آن تاری را می‌گیرد، پس دید واضح کار همین یک لایه‌ی نادیدنی است."},"ICON-2279":{"nm":"کلیپ سفت‌کننده‌ی نوک فین","de":"نوک فین را درست‌اندازه‌ی پا سفت می‌کند تا بی‌هیچ شلی آب را پس بزنی. تا نیرویی که در یک لگد نهفته هدر نرود، کلیپ آرام روی نوک پا گرهی محکم می‌بندد."},"ICON-2280":{"nm":"روکش بند ماسک","de":"نرم دور بند ماسک را می‌پیچد تا موهایت را نکشد. ملاحظه‌ای یک‌لایه که آن لحظه‌ی سوزناک هر بار درآوردن ماسک را از بین می‌برد. چیزی که یک روکش کوچک از آن مراقبت می‌کند، عجیب اینکه همان مهربانی‌ست."},"ICON-2281":{"nm":"کلاهک سوپاپ تخلیه‌ی اسنورکل","de":"حتی در کار نگه‌داشتن نفس هم شکافی هست که آرام آب از آن نشت می‌کند. یک سوپاپ کوچک آن رشته‌ی آب را ملایم به بیرون هدایت می‌کند و جای نفس‌کشیدن را تا آخر نگهبانی می‌کند. دریا این توجه کوچک را با سپاس بیشتر از هر چیز به یاد می‌آورد."},"ICON-2282":{"nm":"قلاب نگهداری فین","de":"وقتی فین‌ها منظم روی یک قلاب کوبیده‌شده به دیوار آویزانند، آرامشی مرتب حتی در اتاق ابزار به‌هم‌ریخته می‌نشیند. گذاشتن هر چیز سرجایش، بی‌صداترین قول برای شیرجه‌ی بعدی است."},"ICON-2283":{"nm":"پد جیب بینی ماسک","de":"پدی که آرام بینی را فشار می‌دهد. به‌لطف این مهربانی کوچک که مانع هجوم آب می‌شود، صورت حتی در دریای سرد هم حالتش را از دست نمی‌دهد."},"ICON-2284":{"nm":"گارد بالای اسنورکل","de":"گاردی که نوک اسنورکل را گرد در بر گرفته، وقتی موج سرازیر می‌شود آرام آب را پس می‌راند. هرچه یک قطعه نادیدنی‌تر کار کند، عمیق‌تر ایمنی یک نفس را برپا نگه می‌دارد."},"ICON-2285":{"nm":"نوار ضدلغزش کف فین","de":"نواری باریک چسبیده به کف فین. یک خط اصطکاک که نوک پا برای نلغزیدن روی عرشه‌ی خیس به آن چنگ می‌زند. ایمنی همیشه بی‌صدا در همین بافت‌های کوچک آغاز می‌شود."},"ICON-2286":{"nm":"کلاهک سوپاپ کپسول اکسیژن","de":"کلاهی که سوپاپ کپسولی پر از هوا را می‌پوشاند. تا گرد نتواند بنشیند، تا راه نفس آلوده نشود. پوشاندنش نوعی مراقبت پیشاپیش است، حتی برای اولین نفس نفر بعدی."},"ICON-2287":{"nm":"کلاهک دهانی رگولاتور","de":"جایی که لب به آن می‌رسد باید همیشه پاکیزه‌ترین باشد. همین یک کلاهک روی دهانی، بی‌کلام دروازه‌ی نفس را از باد شور و شن نگه‌بانی می‌کند."},"ICON-2288":{"nm":"حلقه‌ی کشویی زیپ لباس غواصی","de":"حلقه‌ی کوتاهی وصل به زیپ لباس غواصی. ملاحظه‌ای که آویزان شده تا حتی دست بی‌حس از سرمای آب بتواند یک‌باره بکشدش بالا. حتی در بستن لباس هم فکر کسی نهفته است."},"ICON-2289":{"nm":"کلاهک محافظ گیج هوا","de":"کلاهک محافظی که شیشه‌ی دستگاهی را که هوای باقی‌مانده را نشان می‌دهد، در بر می‌گیرد. چون آن اعداد نباید هرگز تار شوند. هرچه یک قرص شماره‌ای بیشتر زندگی را بخواند، با دقت بیشتری تمیز و پوشیده می‌شود."},"ICON-2290":{"nm":"سگک کمربند وزنه","de":"آدم‌هایی که وزنه دور کمر می‌بندند تا به عمق فرو بروند. در همان لحظه‌ای که یک سگک باز و بسته می‌شود، انتخاب میان بالاآمدن و فرورفتن آرام در نوک انگشتان جمع می‌شود."},"ICON-2291":{"nm":"بند مچی چراغ غواصی","de":"در آب سیاه‌تاریک، یک بند دور مچ محکم چراغ را نگه می‌دارد. حتی اگر دست رها شود، نور همچنان دنبال می‌کند. برای همین است که گم‌نکردن یک نور کوچک وسط تاریکی، این‌قدر آرامش‌بخش است."},"ICON-2292":{"nm":"کلیپ مرتب‌سازی شیلنگ تنفس","de":"کلیپ کوچکی که شیلنگ‌های درهم را یک‌جا جمع می‌کند. اگر از پیش گره‌خوردن را جلو بگیری، حتی در لحظه‌ی اضطراری دست سرگردان نمی‌شود. مرتب‌کردن، مهربانی بی‌صدایی‌ست برای خود آینده."},"ICON-2293":{"nm":"تقویت نوک انگشت دستکش غواصی","de":"پارچه‌ی تقویتی که روی هر نوک انگشت لایه شده. جاهایی که طناب می‌کشند و روی صخره می‌گذارند اول از همه فرسوده می‌شوند، پس یک لایه‌ی اضافه از پیش برای آغوش‌گرفتن آن فرسایش گذاشته شده."},"ICON-2294":{"nm":"حلقه‌ی پایه‌ی کپسول اکسیژن","de":"یک حلقه‌ی پایه که کپسول سنگین را راست نگه می‌دارد. وزنی را که ممکن بود واژگون شود گرد در آغوش می‌گیرد و تعادل می‌بخشد. تکیه‌گاه‌بودن یعنی قرض‌دادن پهلوی خودت تا چیزی نیفتد."},"ICON-2295":{"nm":"کلاهک باله‌ی تخته‌موج‌سواری","de":"کلاهکی که نوک تیز باله‌ی زیر تخته را می‌پوشاند. تا راه‌رفتن روی شن آسیبی نرساند، لبه‌ی تیغه‌ای که موج را می‌شکافت لحظه‌ای به خواب می‌رود. در زمان استراحت، همه اجازه دارند کند شوند."},"ICON-2296":{"nm":"کلاهک محافظ نوک پارو","de":"کلاهکی محافظ که نوک تیغه‌ی پارو را نگهبانی می‌کند. مانع می‌شود خراشی از برخورد با صخره جریان آب را برهم بزند. اگر نوک را عزیز بداری، یک ضربه‌پارو‌زدن تو را دورتر می‌برد."},"ICON-2297":{"nm":"گریپ دسته‌ی پارو کایاک","de":"گریپی پیچیده در جایی که کف دست پارو را ملاقات می‌کند. جایی را که تاول می‌بست نرم می‌پوشاند تا دست‌ها حتی هنگام بالارفتن از رودخانه از پارو دلگیر نشوند."},"ICON-2298":{"nm":"قوطی نگهداری موم موج‌سواری","de":"قوطی حلبی کوچکی که یک تکه موم در آن نگهداری می‌شود. آن جادویی که پا را به تخته می‌چسباند، همیشه از همین جعبه‌ی به‌اندازه‌ی کف دست بیرون کشیده می‌شود. آماده‌شدن امروز از همین یک قوطی مرتب آغاز می‌شود."},"ICON-2299":{"nm":"حلقه‌ی سفت‌کننده‌ی بند مچ‌پای لیش","de":"حلقه‌ای که لیش وصل‌کننده‌ی مچ‌پا به تخته را سفت می‌کند. یک گره که قسم می‌خورد حتی وقتی موجی بزرگ تو را با خود ببرد، رهایت نمی‌کند. اتصال، قولی‌ست برای نگه‌داشتن تا خیلی دور نروی."},"ICON-2300":{"nm":"درپوش هوای برد پدل","de":"تخته‌ای که با پرشدن از هوا محکم می‌شود، و درپوشی که آن نفس را در خود حبس می‌کند. بازش کنی تخت و مسطح تا می‌شود، ببندیش روی آب می‌ایستد. یک درپوش کوچک، روزی را در خود دارد که باد می‌کند و فرو می‌نشیند."},"ICON-2301":{"nm":"بند کوسن صندلی کایاک","de":"بندی که کوسن را به صندلی می‌بندد. برای پشت و کمری که مدت‌ها نشسته پارو می‌زند، نرمی را در جای خود نگه می‌دارد تا لیز نخورد. حتی راحتی هم به گرهی محکم نیاز دارد."},"ICON-2302":{"nm":"ضربه‌گیر نوک تخته موج‌سواری","de":"ضربه‌گیری که دماغه‌ی تخته را در بر می‌گیرد. لایه‌ای است که به نوکی که بیشتر ضربه می‌خورد افزوده شده، تا خودش زودتر کند شود. گذاشتن نرمی در جایی که پیشاپیش می‌رود، عهدی است برای استفاده‌ی طولانی."},"ICON-2303":{"nm":"سگک بستن کیف ضدآب","de":"سگکی که دو سه بار تا می‌خورد و بسته می‌شود تا حتی یک قطره آب هم راه نیابد. نگه داشتن چیزهای عزیز در خشکی، همیشه به یک دست دیگر نیاز دارد. همان یک بار محکم بستن، آرامش خاطر می‌شود."},"ICON-2304":{"nm":"تکه‌ای از تور دروازه فوتسال","de":"تکه‌ای از توری که زمانی دروازه را لرزانده بود. رشته به رشته، هلهله‌ی لحظه‌ای را که توپ در آن جای گرفت به یاد می‌آورد. در هر گره یک گل نشسته، و در هر جای فرسوده، آن مسابقه هنوز زنده است."},"ICON-2305":{"nm":"نازل تلمبه توپ فوتبال","de":"نازل تلمبه‌ای که به توپ خالی از باد، جان دوباره می‌دهد. چرمی که افتاده و بی‌حال می‌غلتید، دوباره می‌جهد و می‌پرد. پر کردن، یعنی بازی متوقف‌شده را دوباره روی پا نشاندن."},"ICON-2306":{"nm":"پایه پرچم کرنر","de":"پایه‌ای که پرچم را در گوشه‌ی زمین راست نگه می‌دارد. نشانه‌ای کوچک از مرز است، اما با همان یک نقطه، خاکِ زمین بالاخره شکل یک استادیوم به خود می‌گیرد."},"ICON-2307":{"nm":"بند محافظ ساق پا","de":"بندی که محافظ ساق را به ساق پا می‌بندد. جایی را که بیشتر ضربه می‌خورد محکم نگه می‌دارد، تا در میان درگیری‌های خشن هم هر قدم بی‌باک بماند."},"ICON-2308":{"nm":"پین تعویض استاد کفش فوتبال","de":"پینی برای جایگزین کردن استاد فرسوده با یکی نو. دندان‌های کوچک نوک پا که چمن را چنگ می‌زنند. برای نلغزیدن، گاهی باید از زیر پا از نو ساخت."},"ICON-2309":{"nm":"درپوش سوپاپ توپ فوتبال","de":"درپوش کوچکی که منفذ نفس‌کشی توپ را می‌بندد. دهانه را کنترل می‌کند تا بادی که پر شده بیرون نزند. حفظ کشیدگی، به از دست ندادن آمادگی تا مسابقه‌ی بعد شبیه است."},"ICON-2310":{"nm":"مخروط خط‌کش زمین بازی","de":"مخروطی که روی زمین خط می‌کشد و راه را جدا می‌کند. تا اینجا تیم ما، از آنجا تیم حریف. یک مخروط کوچک، زمینی خالی و درهم‌ریخته را به زمین بازی‌ای با قاعده تبدیل می‌کند."},"ICON-2311":{"nm":"برس گردگیری کفش فوتسال","de":"برسی که خاک نشسته در شیارهای کفش فوتسال را می‌روبد. وقتی مسابقه تمام می‌شود، خاک یک روز هم روی کفش‌ها می‌نشیند. دست تکاننده، سلامی آرام است به پاهایی که خوب دویدند."},"ICON-2312":{"nm":"جالباسی دستکش دروازه‌بان","de":"جالباسی‌ای که دستکش دروازه‌بان را آویزان می‌کند تا خشک شود. جایی است که دست‌های خیس از عرق، به اندازه‌ی شوت‌هایی که مهار کرده‌اند، کمی استراحت می‌کنند. برای مسابقه‌ی بعد، خیسی خشک می‌شود و دلِ سفت‌شده آرام‌آرام باز می‌شود."},"ICON-2313":{"nm":"قلاب‌های تور حلقه بسکتبال","de":"قلاب‌های کوچکی که تور را به حلقه آویزان می‌کنند. به لطف همین‌ها، وقتی توپ رد می‌شود صدای خش‌خش نرمی بلند می‌شود. آن صدای صاف امتیاز، در واقع از همین قلاب‌ها آغاز می‌شود."},"ICON-2314":{"nm":"ابزار خالی‌کننده هوای توپ بسکتبال","de":"ابزاری که کمی هوای توپ خیلی سفت را خالی می‌کند. کشیدگی بیش از حد، جهش را وحشی می‌کند. کم کردن به اندازه‌ی درست. توپی با حس خوب، همیشه از همین تعادل مناسب زاده می‌شود."},"ICON-2315":{"nm":"پد سنسور تخته بسکتبال","de":"پد سنسوری که پشت تخته چسبانده شده. لحظه‌ی برخورد توپ را با اعداد، شفاف می‌خواند. حتی لحظه‌ای را که چشم از دست می‌دهد، این حس کوچک به یاد می‌آورد، پس داوری عادلانه‌تر می‌شود."},"ICON-2316":{"nm":"مخروط‌های مانع تمرین دریبل","de":"مخروط‌های مانعی که در مسیر تمرین دریبل ردیف شده‌اند. در میان آن‌ها، با پیچ و تاب فرار کردن، مهارت پا رشد می‌کند. سد راه شدن هم نوعی مهربانی است، آموزش راه بهتر فرار کردن."},"ICON-2317":{"nm":"برس سوپاپ توپ بسکتبال","de":"برس کوچکی که سوراخ سوپاپ توپ را تمیز می‌کند. اگر گرد و غبار آن را ببندد، سوزن داخل نمی‌رود، پس از همان دهانه‌ی نامرئی شروع به تمیز کردن می‌کند. پیش از پر کردن، همیشه باید خالی و پاک کرد."},"ICON-2318":{"nm":"رول نوار چسب انگشت","de":"رول نواری که دور انگشت پیچیده می‌شود. مفصلِ پیچ‌خورده را محکم نگه می‌دارد و شجاعت گرفتن دوباره‌ی توپ را می‌بخشد. بستن جای زخم، اعلامی کوچک است که متوقف نخواهی شد."},"ICON-2319":{"nm":"گیره شماره پشت پیراهن","de":"گیره‌ای که شماره‌ی پشت را به لباس می‌چسباند. به‌جای نامت، عددی زمین را طی می‌کند. در همان یک فشار محکم که نیفتد، به‌روشنی نوشته می‌شود امروز چه کسی بازی می‌کند."},"ICON-2320":{"nm":"حلقه هدف تمرین شوت","de":"حلقه‌ی هدفی که داخل حلقه‌ی اصلی جا می‌گیرد و نشانه را باریک می‌کند. جایی را که باید توپ وارد شود کوچک می‌کند، تا خطا کردن را تحمل‌پذیر سازد. اگر آن‌قدر به سمت دروازه‌ی باریک پرتاب کنی، نوک انگشتانت بی‌آنکه بفهمی دقت را یاد می‌گیرد."},"ICON-2321":{"nm":"پاک‌کن کف کفش بسکتبال","de":"پیش از قدم گذاشتن به زمین بازی، زانو خم می‌کنی و اول کف کفش را پاک می‌کنی. چون نمی‌خواهی حتی یک سُر خوردن روی چوب پارکت به‌جا بگذاری. با نوک پای تمیزشده اولین قدم را بردار، و امروزِ تو کمی محکم‌تر از دیروز است."},"ICON-2322":{"nm":"حلقه کشش تور والیبال","de":"کشیدگی را نمی‌توان دید. تنها در لحظه‌ای که حلقه بند را تا انتها می‌کشد و می‌ایستد، تور با یک وجب تنش، زمین را به دو نیم می‌کند. تعادلی که دستی نامرئی نگه می‌دارد، بازی را بیدار می‌کند."},"ICON-2323":{"nm":"گیره ثابت‌کننده آنتن","de":"آنتنی که پیوسته در باد می‌لرزید، با یک بار کلیپ صاف می‌ایستد. چیز کوچکی که لرزشی بزرگ را مهار می‌کند. دستی که پشت صحنه یک کابل را بی‌صدا محکم می‌کند نیز، درست با همین اندازه دلسوزی حرکت می‌کند."},"ICON-2324":{"nm":"جالباسی جلیقه لیبرو","de":"جلیقه‌ی رنگی‌متفاوت متخصص دفاع، آویزان بر دیوار منتظر مسابقه‌ی بعد است. نامی که پرزرق‌وبرق نیست اما تمام زمین را روی دوش می‌کشد: لیبرو. آنجاست چشمی که از پایین‌ترین جا، دورترین را می‌بیند."},"ICON-2325":{"nm":"کیسه محافظ زانو","de":"هرچه بیشتر روی زمین بغلتی، زانو بیشتر ضربه می‌خورد. این کیسه‌ی کوچک که محافظ‌ها را مرتب جا می‌دهد می‌داند: تنها کسی که اول یاد می‌گیرد چگونه خوب زمین بخورد، در پایان دورتر پرواز می‌کند."},"ICON-2326":{"nm":"گیج فشار توپ والیبال","de":"با یک ضربه‌ی نوک انگشت نمی‌شود فهمید. عقربه‌ی گیج به‌آرامی می‌لرزد و به یک خط اشاره می‌کند. سنجیدن نفس یک توپ، اولین دکمه‌ی مسابقه است. از فشاری صادقانه، مسیری صادقانه زاده می‌شود."},"ICON-2327":{"nm":"نوار خط دژبال","de":"دایره‌ای که با نوار روی خاک زمین بازی کشیده شده. داخل و بیرونش، جهانِ نیم‌روزه‌ی بازی گرگم‌به‌هوا را از هم جدا می‌کند. دستی که خط کشید می‌داند، قاعده همان آغاز بازی است."},"ICON-2328":{"nm":"پایه سوت داور","de":"وقتی صدای تیز سوت خاموش می‌شود، دوباره آرام سر جایش روی پایه می‌نشیند. نزدیک‌ترین جا برای شنیدن نفس داور. انصاف همیشه از همین کار کوچکِ سر جای خود ماندن آغاز می‌شود."},"ICON-2329":{"nm":"هدف دیواری تمرین پاس","de":"در سپیده‌دمی که کسی برای پاس گرفتن نیست، هزاران بار نوک انگشتانت را به سوی هدفِ روی دیوار می‌فرستی. دیوار مهربان‌ترین هم‌تیمی است. توپی که برمی‌گردد، تویِ خسته را دوباره برمی‌خیزاند."},"ICON-2330":{"nm":"میله سنجش ارتفاع تور","de":"اگر تور به‌اندازه‌ی یک انگشت هم پایین‌تر باشد، بازی از مسیرش خارج می‌شود. در لحظه‌ای که میله را بالا می‌بری، انصاف نه یک عدد که عادتی روزانه می‌شود. دقتی نامرئی است که زمین بازی را نگه می‌دارد."},"ICON-2331":{"nm":"پین زاویه بلوک استارت","de":"در حالت خمیده، زاویه‌ای که نوک پا به بلوک می‌رسد، همان یک درجه استارت را رقم می‌زند. با یک پین بلوک را ثابت می‌کنی و نفس را آرام می‌کنی. حالتِ آغاز، بی‌صدا تا خط پایان همراهت می‌آید."},"ICON-2332":{"nm":"پرچم شماره باند مسیر","de":"پرچم کوچکی که در هر باند کاشته شده، شماره‌اش را در باد می‌جنباند. همه در یک جهت می‌دوند، اما هر کس مسیر خودش را دارد. مسیر دو، هم‌سویی و تفاوت را با هم در آغوش می‌گیرد."},"ICON-2333":{"nm":"درپوش انتهای چوب امدادی","de":"برای لحظه‌ای که به دست آخرین دونده می‌رسد، درپوش انتهایی لبه‌ها را گرد می‌کند. در دوی امدادی، گران‌بهاترین چیز سرعت نیست، دستی است که به نفر بعد می‌سپاری."},"ICON-2334":{"nm":"جالباسی متر ثبت رکورد","de":"متری را که فاصله‌ها را ثبت کرده، روی دیوار آویزان می‌کنی تا گره نخورد. جایی که فاصله‌ی دیروز و امروز کنار هم آویزانند. رشد همیشه اول با اختلافی کوچک در اعداد از راه می‌رسد."},"ICON-2335":{"nm":"مخروط نشانگر پیچ مسیر","de":"مخروط کوچکی که در داخل پیچ گذاشته شده، نیت راه را بازگو می‌کند. نه خیلی به داخل نپیچ، نه خیلی به بیرون پخش شو. کسی که خوب می‌پیچد، در پایان جلوتر از همه است."},"ICON-2336":{"nm":"گیره روبان خط پایان","de":"روبانی را که اول به سینه‌ای خواهد رسید، گیره کشیده نگه می‌دارد و منتظر می‌ماند. رشته‌ای که برای پاره‌شدن وجود دارد. تمام روز باد را تحمل می‌کند، برای همان یک ثانیه‌ی کسی."},"ICON-2337":{"nm":"روکش تپانچه استارت","de":"تا لحظه‌ای که صدای بنگ شلیک نشده، دهانه‌ی تپانچه زیر روکش خفته است. ظرفی برای صدای آغاز. هرچه سکوت عمیق‌تر باشد، طنین اولین شلیک دورتر پخش می‌شود."},"ICON-2338":{"nm":"پین تنظیم ارتفاع مانع","de":"هر بار که ارتفاعِ پریدنی را یک پله بالا می‌بری، جای پین هم دنبالش تغییر می‌کند. ترس هم درست به همان اندازه رشد می‌کند. با این حال پاها هر بار جایی کمی بالاتر را می‌سنجند و پیش می‌دوند."},"ICON-2339":{"nm":"صفحه‌گردان شمارشگر دور","de":"وقتی گیج می‌شوی چند دور مانده، صفحه‌گردان را یک خانه می‌چرخانی. تیک کوچک عددِ کم‌شونده، دوباره نیرو به پاها می‌بخشد. دستی که فاصله‌ی باقی‌مانده را می‌شمارد، ریتم را نگه می‌دارد."},"ICON-2340":{"nm":"پایه نگهداری نیزه پرش","de":"نیزه‌ی بلند و لرزان جای مخصوص خودش را برای تکیه‌دادن می‌خواهد. چون ابزاری است که باید خم شود تا اوج بگیرد، با احتیاط بیشتری بر پا می‌شود. انعطافی که خوب نگهداری شده، بلندترین پرش را در خود دارد."},"ICON-2341":{"nm":"چنگک صاف‌کننده گودال شن","de":"ردپای ورزشکار قبلی را با چنگک آرام‌آرام هموار می‌کنی. گودال شن هر بار دوباره صاف می‌شود، انگار بار اول است. دستی که برای پرش کسی دیگر، رد پا را پاک می‌کند، همان‌جا بی‌صدا هست."},"ICON-2342":{"nm":"نوار نشانگر فاصله دورخیز","de":"یک قدم کم هم نمی‌شود، یک قدم زیاد هم نه. نوار نشانگر فاصله روی زمین، صادقانه جای زدن پا را می‌گوید. دورخیز خوب، طمعی بی‌پروا نیست، از محاسبه‌ای آرام بیرون می‌آید."},"ICON-2343":{"nm":"گریپ دیسک پرتابی","de":"اگر انگشت‌ها لیز بخورند، پیش از پرتاب، دیسک از قبل پرتاب شده است. بافت زبر گریپی که دیسک را در بر می‌گیرد، چرخش را کنترل می‌کند. زمان رها کردن، همیشه از حسِ گرفتن آغاز می‌شود."},"ICON-2344":{"nm":"حلقه نگهدارنده گلوله وزنه","de":"حلقه‌ی نگهدارنده، گلوله‌ی سنگین فلزی را آرام در آغوش می‌گیرد تا نغلتد. آشیانه‌ی کوچکی که آرامش پیش از پرتاب را حفظ می‌کند. هرچه نیرو انفجاری‌تر باشد، جای استراحتش باید محکم‌تر باشد."},"ICON-2345":{"nm":"کلاهک محافظ نوک نیزه","de":"کلاهکی که روی نوک تیز نیزه کشیده شده، سکوتی نرم را می‌پوشاند. وقتی ابزاری که قرار است دور پرواز کند، آرام دراز کشیده، خطر با ملاحظه رام می‌شود. امنیت حتی در انبار هم زندگی می‌کند."},"ICON-2346":{"nm":"گیره نگهدارنده میله پرش ارتفاع","de":"تا با کوچک‌ترین لمسی هم میله نیفتد، گیره با توازنی ظریف نگهش می‌دارد. جایگاهی که مسئول آن مرز لرزان بین رد شدن و نشدن است. انصاف در جزئیات کوچک جا خوش می‌کند."},"ICON-2347":{"nm":"قلاب لنگر گوشه تشک فرود","de":"اگر گوشه‌ی تشک فرود بلند شود، آسیب می‌رسد. لنگر هر چهار گوشه را محکم فشار می‌دهد. تا بدنی که بلندترین پرواز را داشته، ایمن‌ترین فرود را داشته باشد، بی‌آنکه دیده شود زیرش را نگه می‌دارد."},"ICON-2348":{"nm":"نوار مرز دایره پرتاب","de":"مرز جایگاه پرتاب با یک خط نوار کشیده می‌شود. اینکه پا روی آن خط بگذاری یا نه، رکوردی را زنده یا مرده می‌کند. جایی که آزادی و قاعده به هم می‌رسند، پیمانی است در قالب یک خط باریک."},"ICON-2349":{"nm":"پایه لاستیکی موازنه","de":"تا موازنه‌ی باریک نلرزد، پایه‌ی لاستیکی زمین را محکم گاز می‌گیرد. تعادل بی‌لرزشی که روی آن شکل می‌گیرد، در حقیقت از محکمیِ نادیدنی زیر آن ساخته شده."},"ICON-2350":{"nm":"باند دور دستگیره میله افقی","de":"تا کف دست نلغزد، باندی دور دستگیره‌ی میله افقی می‌پیچی. راز چرخشِ چرخنده نه در زرق‌وبرق که در دستی محکم بسته شده نهفته است. عرقی که روی تشک چکیده، این را می‌داند."},"ICON-2351":{"nm":"گیره ثابت‌کننده ارتفاع طناب حلقه","de":"اگر ارتفاع دو طناب فقط به‌اندازه‌ی عرض یک کف دست هم اختلاف داشته باشد، حرکت فرو می‌ریزد. گیره بی‌صدا آن توازن را نگه می‌دارد. تنها روی ارتفاعی دقیقاً هم‌تراز است که پرواز آزاد آغاز می‌شود."},"ICON-2352":{"nm":"روکش دستگیره اسب چرخشی","de":"روکشی که دستگیره را می‌پوشاند، از تاول زدن کف دست جلوگیری می‌کند. زیر آن حرکت چرخان و پیچان، دستی است که بارها زخم شده و بارها التیام یافته. محافظت، وعده‌ای مهربانانه برای تمرین بعدی است."},"ICON-2353":{"nm":"پین تنظیم فاصله میله‌های نابرابر","de":"فاصله‌ی میان دو میله را با پین دقیقاً تنظیم می‌کنی. آن فضای خالی که بدن در آن رفت‌وآمد می‌کند، خودش صحنه می‌شود. نوک انگشتان زودتر می‌فهمند که روی فاصله‌ای دقیق، جسورانه‌ترین پرش زاده می‌شود."},"ICON-2354":{"nm":"کلاهک فنر تخته پرش خرک","de":"لحظه‌ای که پا از تخته می‌کوبی، فنر بدن را به آسمان می‌راند. کلاهک، نیروی آن جهش را محکم در بر می‌گیرد. کوتاه‌ترین دورخیز، بلندترین پرواز در هوا را می‌سازد."},"ICON-2355":{"nm":"کیسه پودر منیزیم","de":"پودر سفیدی که به دست می‌مالی، طلسم کوچکی است که لغزندگی را پاک می‌کند. آیین کوتاه فرو بردن و بیرون کشیدن دست در کیسه، ترس را آرام می‌کند. حتی تنش هم در نهایت در نوک انگشتان مهار می‌شود."},"ICON-2356":{"nm":"باند دور مچ دست ژیمناستیک","de":"با پیچیدن باند دور مچ، رشته‌های دل هم با آن سفت می‌شود. مفصلی را که قرار است بلرزد، از پیش نگه می‌داری. یک مچ خوب بسته‌شده، آرام اجازه‌ی چرخشی جسورانه‌تر می‌دهد."},"ICON-2357":{"nm":"حلقه ایمنی تراپز","de":"درست پیش از پرتاب کردن بدن به هوا، حلقه‌ی ایمنی دستی نامرئی می‌شود. تنها وقتی ترس افتادن ناپدید شود، می‌توان دورترین پرواز را کرد. اعتماد، پرواز را کامل می‌کند."},"ICON-2358":{"nm":"درپوش قوطی نگهداری توپ تنیس","de":"زیر درپوشی که دهانه‌ی قوطی را بسته، توپ‌های تازه فشار خود را نگه‌داشته خفته‌اند. صدای کوچک پاپ باز شدن یک قوطی، هیجان مسابقه را بیدار می‌کند. مهر و موم، پیمانی است برای حفظ تازگی."},"ICON-2359":{"nm":"گیره کشش زه راکت","de":"گیره کشیدگیِ زه را محکم گاز می‌گیرد و تا آخر رها نمی‌کند. چون کشش یک رشته، برگشت توپ را تعیین می‌کند. حس دستِ نامرئی، از همین گیره‌ی کوچک آغاز می‌شود."},"ICON-2360":{"nm":"جاروی خط زمین تنیس","de":"وقتی مسابقه تمام می‌شود، آرام در امتداد خطوط سفید زمین جارو می‌کنی. با کنار زدن گرد و غبار، خط دوباره شفاف می‌شود. هموار کردن راه برای مسابقه‌ی بعد، آن مراقبت پایانی است که زمین را زنده نگه می‌دارد."},"ICON-2361":{"nm":"نوار محافظ سر راکت","de":"یک دور دور لبه‌ی راکت را که بپیچی، حتی برخورد خشن هم گرد و نرم پذیرفته می‌شود. می‌دانم که لبه اولین جایی است که فرسوده می‌شود. چون سهمِ من است که به‌جای تو فرسودگی را به عهده بگیرم، امروز هم در بیرونی‌ترین جا ایستاده‌ام."},"ICON-2362":{"nm":"چیپ دمای هوای سالن","de":"باد سرد سپیده‌دمی که با باز شدن در به داخل هجوم می‌آورد را، چیپی به اندازه‌ی کف دست پیش از هر انسانی می‌خواند. حس کردن آن پیش از سرد شدن نوک بینی—آرام‌ترین سلام برای گشودن روزی در سالن خالی."},"ICON-2363":{"nm":"صفحه پا خط پایه","de":"برای ورزشکاری که مردد است پا را کجا بگذارد، یک خط کشیده‌شده روی زمین کافی است. خطی که نباید از آن گذشت، خودش خط شروعِ دورترین پرش می‌شود؛ صفحه پا این را بی‌کلام می‌گوید."},"ICON-2364":{"nm":"جاسبدی توپ تنیس","de":"ده‌ها توپ را در یک لقمه در خود جای می‌دهد و حتی یکی هم نمی‌ریزد. جمع کردن آنچه روی زمین پراکنده شده و سپردنش به تمرین بعدی—دستی که بی‌صدا در گوشه‌ای مشغول است، امروز هم اینجا آویزان است."},"ICON-2365":{"nm":"درپوش انتهای دسته راکت","de":"لحظه‌ای که تیک آن را به انتهای دسته می‌زنی، راکت بالاخره در کف دستت جا می‌گیرد. یک درپوش کوچک، لغزیدن را از اطمینان خاطر جدا می‌کند. اگر انتها را محکم ببندی، اولین ضربه استوار می‌شود."},"ICON-2366":{"nm":"گیره حوله کنار زمین","de":"حتی وقتی باد شدید می‌وزد، حوله‌ای که با زحمت آب‌گیری شده پرواز نکند، در کنار زمین دهانش را محکم می‌بندد و می‌ایستد. حتی نگه داشتن استراحتی کوتاه برای گرفتن نفس، دست چابک کسی به آن رسیده است."},"ICON-2367":{"nm":"گیره صاف‌کننده پر شاتل‌کاک","de":"اگر فقط یک پر بی‌نظم شود، پرواز می‌لرزد. بال چروکیده را با احتیاط صاف کن، و شاتل دوباره برای پرواز مستقیم آماده می‌شود. رفتن به دور دست، همیشه از همین آراستگی کوچک آغاز می‌شود."},"ICON-2368":{"nm":"درپوش لوله شاتل‌کاک","de":"تا شاتل‌های ردیف‌شده داخل، نرم و بی‌جان نشوند، انتهای لوله را محکم می‌بندی. مدت‌هاست دیده‌ای که یک لمس رطوبت، پر را فرو می‌نشاند. مرتب نگه داشتن، خودش پیشاپیش بخشی از مسابقه است."},"ICON-2369":{"nm":"پایه غلتک توپ پینگ‌پنگ","de":"توپ کوچکی که آرام غلتیده بود، روی من لحظه‌ای نفس تازه می‌کند. آرام نگهش داشتن تا نغلتد و نیفتد—مهربانی‌ای به گردترین شکل، در کنار میز پینگ‌پنگ عرضه می‌شود."},"ICON-2370":{"nm":"غلتک لاستیکی راکت پینگ‌پنگ","de":"غلتک را آرام روی سطح لاستیکی بغلتان، گرد و غبار کهنه بلند می‌شود و چسبندگی دوباره جان می‌گیرد. چرخش باید زنده بماند تا توپ خم شود. حال امروز راکت، از همین یک بار مراقبت مهربانانه بیدار می‌شود."},"ICON-2371":{"nm":"چوب سنجش ارتفاع تور","de":"اگر تور فقط یک وجب بلندتر باشد، بافت بازی تغییر می‌کند. کسانی که هرگز به چشم اعتماد نمی‌کنند، مرا نزدش می‌آورند. به‌نظر می‌رسد انصاف تنها از ارتفاعی که دقیقاً با خط‌کش سنجیده شده، سرانجام می‌آید."},"ICON-2372":{"nm":"چیپ سنجش سرعت شاتل‌کاک","de":"سرعت شاتلی که هوا را می‌شکافد، آرام می‌سنجم. وقتی سرعتی که پیش‌تر نامرئی بود به عددی شفاف می‌نشیند، کلام بعدیِ مربی روشن‌تر می‌شود. کاری است برای تبدیل حدس به واقعیت."},"ICON-2373":{"nm":"کپسول نگهداری توپ پینگ‌پنگ","de":"توپی گرد را آرام در کپسول بخوابان، خراش و گرد و غبار همان‌جا دور می‌مانند. آرزوی سلامتش تا مسابقه‌ی بعد، همان دلی است که یک اتاقک کوچک کامل را وقفش می‌کند."},"ICON-2374":{"nm":"جالباسی زه راکت بدمینتون","de":"زه‌های شل‌شده را مرتب آویزان کن، تا دست بعدیِ در نوبت سردرگم نشود. مرتب کردن، در نهایت مانند یادداشتی مهربانانه است که از پیش برای فردایِ خودت نوشته‌ای. امروز فردا را آسان می‌کند."},"ICON-2375":{"nm":"نوار محافظ لبه راکت پینگ‌پنگ","de":"لبه‌ای که لاستیک آن به‌راحتی بلند می‌شود را، من آرام در یک خط در آغوش می‌گیرم. اگر لبه باز شود، حتی بافت توپ هم از مسیرش خارج می‌شود. نگهبانی از لبه، در نهایت نگهبانی از یک امتیاز می‌شود."},"ICON-2376":{"nm":"کیسه گرم‌کننده توپ اسکواش","de":"توپ سرد به‌سختی می‌جهد. پیش از مسابقه، کیسه‌ای که آن را مثل کف دست گرم می‌کند و در آغوش می‌گیرد. آن گرمای کوچکی که به دست منتقل می‌شود، نفس و ریتم یک راند را از پیش تعیین می‌کند."},"ICON-2377":{"nm":"گیره تور مش لاکراس","de":"وقتی گره‌ای از تور آرام شروع به شل شدن می‌کند، من بی‌کلام همان یک بخیه را گاز می‌گیرم و نگه می‌دارم. تور باید کشیده باشد تا توپ بماند. دستی که از جایی نامرئی تمام بازی را نگه داشته، همین‌جاست."},"ICON-2378":{"nm":"نوار محافظ نوک راکت اسکواش","de":"هرچه شدیدتر به سمت دیوار بچرخانی، راکت اول از نوکش می‌گرید. آن نوکِ گریان را آرام بپیچ، و یک فصل دیگر همراهت بازی می‌کند. کسی که بلد است نوک را دریغ کند، در نهایت راکت را طولانی در دست نگه می‌دارد."},"ICON-2379":{"nm":"روکش تیغه چوب هاکی","de":"روکش را روی تیغه‌ی تیز بکش، و بالاخره هم داخل کیف و هم نوک انگشتانت آرام می‌گیرد. آرام خواباندن چیزی خطرناک—نخستین ادب کهنه‌ای است که هنگام جمع کردن چوب رعایت می‌شود."},"ICON-2380":{"nm":"پارچه براق‌کننده توپ کریکت","de":"توپ قرمز را با پارچه بمالی، یک طرفش مثل آینه نور را در خود نگه می‌دارد. پرتاب‌کننده با حس نوک انگشتانش می‌داند که وقتی جلا زنده باشد، توپ خم می‌شود. حتی در پرداختِ دلسوزانه، راهبردی آرام نهفته است."},"ICON-2381":{"nm":"درپوش لوله نگهداری توپ لاکراس","de":"تا توپ‌های سفت هر جور دلشان خواست نغلتند، دهانه‌ی لوله را محکم می‌بندی. جمع کردن نرم چیزهایی که راحت پراکنده می‌شوند در یک جا—اصولِ اداره کردن همیشه همین‌قدر کوچک است."},"ICON-2382":{"nm":"قطعه هدف روی دیوار اسکواش","de":"هدف کوچکی که در دیوار کاشته شده، چشمان لرزان ورزشکار را به یک نقطه می‌کشاند. تنها نقطه‌ای که می‌گوید کجا را نشانه بگیری—حتی آن دیوار پهن هم پیش روی این قطعه، به هدفی روشن باریک می‌شود."},"ICON-2383":{"nm":"آستین گریپ چوب هاکی","de":"گریپی را که دستت به آن عادت کرده به چوبی نو و ناآشنا منتقل کن، و در همان لحظه ابزار یک‌باره از آنِ تو می‌شود. آستین کوچکی که آشنایی را همان‌طور می‌پوشاند—این خودش میان‌بر عادت کردن است."},"ICON-2384":{"nm":"جالباسی تور دروازه زمین","de":"تور را باید به دروازه آویزان کرد تا گل، بالاخره گل باشد. همیشه این تور بود که آن لحظه‌ی کوتاه پر شدن دروازه از توپ را تا آخر نگه می‌داشت. من همان‌جایم، جایی که شکل هلهله‌ی فوران‌شده را می‌گیرد."},"ICON-2385":{"nm":"روکش تیغه اسکیت","de":"با تیغه‌ی برهنه، حتی یک قدم بیرون از یخ هم نمی‌شود آسوده بود. وقتی یخ را ترک کردی، لطفاً مرا بپوش. آرام خواباندن تیزی هم، آیینی است که اهل یخ مدت‌ها پاسش داشته‌اند."},"ICON-2386":{"nm":"جالباسی بند اسکیت","de":"بندهای بلند چکمه‌ای که در آورده‌ای را، یکی‌یکی مرتب آویزان می‌کنی. بندی که باز شده تا گره نخورد، دفعه‌ی بعد روی یخ را روان می‌گشاید. پایان امروز، همان‌طور آماده‌سازی برای فردا می‌شود."},"ICON-2387":{"nm":"حوله تیغه اسکیت","de":"روی تیغه‌ای که تازه یخ را ترک کرده، قطره‌های ریز آب می‌نشینند. آن رطوبت را آرام پاک کنی، زنگ از کنارش می‌گذرد. جمع کردن بی‌صدای اثری که سرما به‌جا گذاشته، همان روز من است."},"ICON-2388":{"nm":"پد مچ چکمه اسکیت","de":"اگر مچ پا یک‌بار بلرزد، تمام سُر خوردن فرو می‌ریزد. پدی که محکم در برش می‌گیرد و جای پا را نگه می‌دارد. آن موازنه‌ی برازنده روی یخ، همیشه از جایی نامرئی اول آغاز می‌شود."},"ICON-2389":{"nm":"کیسه گارد تیغه اسکیت","de":"کیسه‌ی کوچکی در گوشه‌ی کیف هست تا گارد تیغه را با احتیاط داخلش بگذاری. عادت جا نگذاشتن آنچه لازم است، وسیله را مدت‌ها زنده نگه می‌دارد. کیفی مرتب، خودش اولین صحنه‌ی یک سُر خوردنِ خوب است."},"ICON-2390":{"nm":"گیره کفی چکمه اسکیت","de":"تا کفیِ داخل چکمه آرام لیز نخورد، زیر پا محکم نگهش می‌دارد. اگر جای پا کج شود، پرش هم کج می‌شود. دستی که پایین‌ترین جا را می‌گیرد، در نهایت به بلندترین پرش کمک می‌کند."},"ICON-2391":{"nm":"حلقه روکش تیغه اسکیت","de":"تا روکش سُر نخورد، با حلقه محکم می‌بندی و قفل می‌کنی. می‌دانم محافظتی شل، در نهایت اصلاً محافظت نیست. یک حلقه‌ی خوب بسته‌شده، آن تیغه را تا آخر نگه می‌دارد."},"ICON-2392":{"nm":"کلاهک محکم‌کننده بند اسکیت","de":"بند را محکم بکش و با کلاهک قفلش کن، از این پس دیگر باز نمی‌شود. بستن بی‌شکاف و استوار از همان نوک پا—محکم‌ترین گره‌ای است که پیش از اولین قدم روی یخ زده می‌شود."},"ICON-2393":{"nm":"پارچه خشک‌کن تیغه اسکیت","de":"از تیغه‌ای که تازه یک دور سُر خوردن را تمام کرده، رطوبتِ نشسته را آرام جمع می‌کنی. می‌دانم تیغه‌ای که خیس بماند، می‌گرید. تنها تیغه‌ای که نرم خشک شده، منحنی بعدی را روشن روی یخ می‌کشد."},"ICON-2394":{"nm":"کلاهک دستگیره چوب اسکی","de":"انتهای دستگیره‌ی چوب را نرم بپوشان، و کف دستِ گیرنده کمی راحت‌تر می‌شود. نیرویی که میدان برف را می‌شکافد، در نهایت از همان جای محکم گرفته‌شده می‌آید. یک کلاهک کوچک، یک سُرخوردن طولانی را تا آخر نگه می‌دارد."},"ICON-2395":{"nm":"پین بایندینگ اسنوبورد","de":"لحظه‌ای که پین کوچکی که برد را به پا وصل می‌کرد، بیرون بیفتد، کوهِ پیش رو می‌ایستد. قطعه‌ای که به‌سختی دیده می‌شود اما باید اول بررسی شود—همین اتصال محکم، خودِ آزادی روی برف می‌شود."},"ICON-2396":{"nm":"گیره محافظ نوک لبه اسکی","de":"تا لبه‌ی تیز داخل کیف را نخراشد، نوکش را آرام گاز می‌گیرد و نگه می‌دارد. آرام کردن تیزی—مراقبتی مهربانانه است که پس از یک نزول خوب از کوه ارائه می‌شود."},"ICON-2397":{"nm":"گارد نوک اسنوبورد","de":"نوک برد را کامل در بر بگیری، حتی برخورد روبه‌رو هم نرم پخش می‌شود. بی‌صدا نگهبانیِ جایی که اول برخورد می‌کند—شجاعت روبه‌رو شدن با سرازیری تند، درست از همین‌جا آغاز می‌شود."},"ICON-2398":{"nm":"روکش سگک چکمه اسکی","de":"تا سگک با برخورد به برف سرد آسیب نبیند، آرام رویش را می‌پوشانی. قفلی دیگر که قفل را نگه می‌دارد—همین روکش کوچک، فصل چکمه را کمی بیشتر طول می‌دهد."},"ICON-2399":{"nm":"حلقه بند ایمنی اسنوبورد","de":"تا برد حتی اگر از دستت رها شود دور نرود، من مچ پا و برد را با یک رشته پیوند می‌دهم. حتی اگر آن را از دست بدهی، هرگز واقعاً گمش نکنی—حلقه‌ی آرام اطمینانی که در انتهای رشته‌ای بلند آویزان است."},"ICON-2400":{"nm":"نوک خراش‌دهنده کف اسکی","de":"واکس کهنه‌ی سفت‌شده روی کف را، نرم و صاف پس می‌رانی. باید کهنه را کاملاً پاک کرد تا لغزش تازه زنده شود. کفی که با دلسوزی مرتب شده، میدان برف بعدی را بسیار سریع‌تر می‌گشاید."},"ICON-2401":{"nm":"بامپر نوک تخته اسنوبرد","de":"پیش از آنکه تخته، برف را بشکافد، نوکِ آن نخست به جهان می‌رسد. هر تلاقی‌ای را همیشه این تکه کوچکِ لاستیک نخست تحمل می‌کند. جایی در جلوترین نقطه که بی‌هیچ ادعایی ساییده می‌شود؛ سرازیریِ کسی بر این ایثارِ کُند و خاموش می‌لغزد."},"ICON-2402":{"nm":"حلقه سبدی چوب اسکی","de":"درست همان لحظه که چوب اسکی می‌خواهد در برفِ عمیق فرو رود، این لبه‌ی گرد به‌جای آن زمین را لمس می‌کند. حلقه‌ای که آرام، قدمی را که نزدیک بود بلغزد، نگه می‌دارد. دیده نمی‌شود، اما مثل دستی کنارت می‌ماند تا نلغزی."},"ICON-2403":{"nm":"درپوش برس واکس لبه‌ی تیغه","de":"وقتی مراقبت به پایان می‌رسد، پیش از آنکه گَرد خشک شود، به‌آرامی رویش را می‌پوشاند. کاری برای مهر و موم کردن نرمیِ امروز، بی‌آنکه یک تار مو هم آشفته شود. تا وقتی دوباره بازش می‌کنی، دلسوزیِ دیروز همان‌طور منتظرت باشد."},"ICON-2404":{"nm":"آویز گوش‌گیر زمستانی","de":"یادت هست؟ گوش‌گیری که با آمدن بهار، کنار کیف کمی از یاد می‌رفت. اما در شبی که خبر اولین برف می‌رسد، اولین چیزی است که صدایش می‌زنند. جایی مخصوص برای آویختن فصل هست، و این قلاب هرگز آن قول را فراموش نمی‌کند."},"ICON-2405":{"nm":"جعبه سنگ چاقوتیزکنی","de":"برای تیز کردن چاقو، باید نخست سنگ را خیس کرد—ترتیبی که مثل دستان مادربزرگ در جان آدم نشسته. حتی ابزاری که کندی را رام می‌کند، جایی برای استراحت لازم دارد؛ پس این خانه‌ی کوچک، سنگ را در آغوش می‌گیرد و منتظر مراقبتِ بعدی می‌ماند."},"ICON-2406":{"nm":"کیسه قالب واکس","de":"همان چیزی که سرازیریِ درخشان را می‌سازد، در دل خودش سخت و منجمد به خواب رفته است. سنگینیِ توپُر، در برگیرنده‌ی قالبی سفت‌شده. لغزش همیشه از همین وزنِ ساکت آزاد می‌شود و روی دشتِ برفی پخش می‌شود."},"ICON-2407":{"nm":"قلاب کیسه‌ی گرم‌کن دست","de":"در پیاده‌روی زمستانی، جایی که انگشت‌ها اول از همه در جیب دنبالش می‌گردند. خانه‌ای ثابت به آن گرمای کوچک می‌دهد که دست‌های یخ‌زده را ذوب می‌کند. هرچه روز سردتر، این قلاب کوچک مهربان‌تر می‌شود."},"ICON-2408":{"nm":"پایه سنگ سنباده لبه تیغه","de":"اگر بلرزد، تیغه کج می‌شود؛ پس نخست خودش را محکم ثابت می‌کند. پایه‌ای که ذره‌ای تکان نمی‌خورد، فقط برای آنکه مسئول دقتِ دیگری باشد. نوکِ راستِ چاقوی کسی، بر همین سکوتِ استوار می‌ایستد."},"ICON-2409":{"nm":"گیره گردن‌پیچ زمستانی","de":"در راه مدرسه با بادِ سرد، همان لحظه که گردن‌پیچ می‌خواهد بلغزد، تیک، به یقه می‌چسبد. حتی گرما هم باید جایش را حفظ کند تا واقعاً گرم باشد. یک صدای کوچک، گرمای صبح را نگه می‌دارد."},"ICON-2410":{"nm":"روکش اتوی واکس","de":"در حالی که سطحِ داغ‌کارکرده سرد می‌شود، یک تکه پارچه آرام از گرد و غبار محافظتش می‌کند. ابزاری که از ابزار دیگری مراقبت می‌کند، همان که سرازیری را آماده کرده بود. مراقبت این‌گونه، بی‌صدا ادامه می‌یابد."},"ICON-2411":{"nm":"درپوش قلم روغن لبه‌ی تیغه","de":"اگر یک‌بار باز بماند و خشک شود، دیگر نمی‌شود خط بعدی را کشید. پس بستنش همان باز کردنِ بعدی است—این درپوشِ کوچک، رطوبتِ نوکِ قلم را مهر و موم می‌کند و از پیش، ضربه‌قلمِ فردا را نوید می‌دهد."},"ICON-2412":{"nm":"سر منگوله تشویق","de":"صدها رشته‌ی ریشه از همین یک نقطه آغاز می‌شوند و هم‌زمان با ریتم پراکنده می‌شوند. شکوهِ تکان‌خوردن همیشه از جایی محکم بسته آغاز می‌گردد. زیر صحنه، اولین گره‌ای که موج را در جایگاه تماشاگران به راه می‌اندازد."},"ICON-2413":{"nm":"بند دستی چوب نوری","de":"بعد از دو ساعت هورا کشیدن، درست وقتی نزدیک است چوب نوری از دست بیفتد، این بند دوباره آن را به دستت برمی‌گرداند. آرزوی گم‌نکردنش حتی وقتی می‌افتد. آن نگرانیِ مهربان، حلقه‌ای بر مچ دست ساخته است."},"ICON-2414":{"nm":"گیره تاشوی کوسن سکو","de":"ده‌ها بار بلند شدن و نشستن، در میانِ هیجانِ تشویق. در این میان، این گیره‌ی کوچک، کوسن را با دقت تا می‌کند و جایت را نگه می‌دارد. حتی در جایگاهِ پرشور تماشاگران، دستی هست که جای کسی را مراقب است."},"ICON-2415":{"nm":"حلقه بندانا تشویق","de":"روزی که یک طرح در سراسر جایگاه پخش می‌شود، یک تکه پارچه، دل‌های ده‌ها هزار نفر را در یک رنگ می‌بندد. اولین نقطه‌ای که آن موج از آن آغاز می‌شود، همین حلقه‌ی کوچک است—جایی که تشویقِ تنها، به «ما» بدل می‌شود."},"ICON-2416":{"nm":"نیمه دستک تشویق","de":"اگر تنها بزنی صدایی کوچک است، اما وقتی در جایگاه جمع شود، موج می‌شود. نیمه‌ای که صادقانه‌ترین درک را از این حقیقت دارد که فقط با برخورد با دیگری طنین می‌اندازد. لحظه‌ای که کف‌زدنِ تو با من برخورد می‌کند، تشویق بزرگ‌تر می‌شود."},"ICON-2417":{"nm":"درپوش گوشه پلاکارد تشویق","de":"گوشه‌ی تیز را گِرد در بر می‌گیرد، تا کسی که کنارت نشسته آسیب نبیند. حتی در دلی که با شور تکان می‌خورد، ملاحظه‌ای برای دیگران جاسازی شده است. تشویق این‌گونه، در این گِردی، گرم‌تر می‌شود."},"ICON-2418":{"nm":"نگهدارنده میله روبان تشویق","de":"حتی در لحظه‌ای که تکان خوردن متوقف می‌شود، میله راست می‌ایستد و منتظر فریادِ بعدی می‌ماند. جایی برای اندکی سکون، تا بتواند دوباره تکان بخورد. میان یک فریاد و فریادِ دیگر، سکوتی کوتاه که روبان در آن نفسش را تازه می‌کند."},"ICON-2419":{"nm":"بادبزن مگافون تشویق","de":"تا فریاد یک‌نفر به انتهای صحنه برسد، شکل بادبزنی مسیر صدا را باریک می‌کند. دهانی که همیشه بیشتر از اندازه‌ی دل، به شیوه‌ی رساندن می‌اندیشد. شکلی که از اشتیاقِ رسیدن به دورترها ساخته شده."},"ICON-2420":{"nm":"جعبه سنجاق پشت نشان تشویق","de":"پیش از آنکه به سینه بچسبد و پس از آنکه جدا شود، استراحتِ نشان از همین‌جا آغاز و پایان می‌یابد. خانه‌ای کوچک که سنجاقِ تیزِ پشتی را با امنیت می‌خواباند. حتی نقطه‌ای که زمانی می‌درخشید، جایی برای دراز کشیدن و استراحت لازم دارد."},"ICON-2421":{"nm":"صفحه شماره تابلوی امتیاز","de":"در خود، دلسوزیِ روزگاری را دارد که هر گل با دست جابه‌جا می‌شد. پیش از عصر دیجیتال، نتیجه‌ی بازی خانه‌به‌خانه با نوک انگشتانِ انسان حک می‌شد. صفحه‌ای که حتی در یک عدد، هیجانِ کسی نهفته بود."},"ICON-2422":{"nm":"مهره آهنربایی تخته تاکتیک","de":"به دنبال نوک انگشتان مربی، دفاع و حمله جا عوض می‌کنند. هر تصویری در ذهن، پیش از بازی، نخست در جابه‌جاییِ همین نقطه‌های کوچک ترسیم می‌شود. نتیجه‌ی بازی، یک‌بار پیشاپیش روی تخته به نمایش درمی‌آید."},"ICON-2423":{"nm":"سایبان ضدخیرگی تابلوی امتیاز","de":"تا اعدادِ خیره‌کننده دیدِ بازیکن را تار نکند، سایبان نور را می‌بُرد. حتی روشنایی گاهی باید درست به‌اندازه سایه بیفتد تا نقشش را ایفا کند. در روشن‌ترین جا، سایه‌ای که خاموش‌ترین کار را می‌کند."},"ICON-2424":{"nm":"حلقه ورق‌زن امتیاز","de":"هر بار که یک برگ ورق می‌خورد، عدد تغییر می‌کند و فریادها به دنبالش بالا می‌روند. ردی از دورانِ آنالوگ، وقتی رکوردها با احساس دست تازه می‌شدند. روزگاری که با صدای ورق‌خوردنِ امتیاز، قلب هم ورق می‌خورد."},"ICON-2425":{"nm":"جعبه ماژیک خط‌کشی تاکتیک","de":"هر مسیری که روی تخته‌سفیدِ رختکن کشیده می‌شود، از همین قلم بیرون می‌آید. جعبه‌ای کوچک و محکم که طرحِ اولیه‌ی نبرد را در آغوش دارد. در سکوتِ پیش از نبرد، جایی که بیشترین حرف‌ها را در خود نگه داشته."},"ICON-2426":{"nm":"کلیک‌شمار امتیاز","de":"با هر فشار، یک خانه جلو می‌رود، با صدای تیکِ روشنی که شمارش را بالا می‌برد. اگر اعداد را به انگشت‌ها بسپاری، دل می‌تواند تمام و کمال رو به بازی باشد. ریتمی کوچک که بارِ شمردن را سبک می‌کند."},"ICON-2427":{"nm":"روکش سیم تابلوی امتیاز","de":"پشتِ نورِ درخشان، همیشه سیم‌هایی درهم و نامرتب هستند. کاری که آن آشفتگی را مرتب می‌پوشاند. تنها وقتی جای دیده‌نشده تمیز باشد، جای دیده‌شده سرانجام می‌درخشد."},"ICON-2428":{"nm":"برس پاک‌کن تخته تاکتیک","de":"وقتی یک دور تمام می‌شود، سطح را برای تصویرِ بعدی پاک می‌کند. استراتژیِ تازه همیشه فقط روی جایی خالی می‌تواند آغاز شود. برسِ پاک‌کننده، در واقع، اولین قلم‌موی تاکتیکِ بعدی است."},"ICON-2429":{"nm":"گیره پرچم نمایش امتیاز","de":"پرچمی را که می‌خواهد در باد پرواز کند، محکم می‌گیرد و رها نمی‌کند. تا پارچه‌ی در حال تکان‌خوردن، جایش را نگه دارد. حتی کارِ اعلام رکورد به جهان، نخست به دستی محکم برای نگه‌داشتن نیاز دارد."},"ICON-2430":{"nm":"گیره بند سوت داور","de":"با یک بارِ سوت، بازی می‌ایستد و دوباره جریان می‌یابد. گره‌ای کوچک که آن اقتدار را محکم به گردن می‌بندد. تا سوت به صدا درنیاید، مرتب نگه‌داشتنِ سکوت هم وظیفه‌ی همین گیره است."},"ICON-2431":{"nm":"قرقره متر اندازه‌گیری","de":"طولی را که باز کرده و اندازه گرفته، دوباره در خودش جمع می‌کند. اندازه‌گیری، در نهایت، تکرارِ باز کردن و جمع کردن است. دسته‌ای که بی‌هیچ گلایه‌ای به این رفت‌وبرگشتِ ساده کمک می‌کند، هر بار پشتِ دقت می‌چرخد."},"ICON-2432":{"nm":"جعبه تاشوی پرچم داوری","de":"پرچمی که قاطعانه داخل و خارج را از هم جدا می‌کرد، وقتی بازی تمام می‌شود، مرتب تا می‌شود و استراحت می‌کند. حتی آن سیگنالِ روشن، برای اتفاقِ بعدی کمی نفس تازه می‌کند. پشتِ قاطعیت هم، استراحتی آرام هست."},"ICON-2433":{"nm":"حلقه آویز کرنومتر","de":"زمانِ در جریان را، نه روی مچ، بلکه در یک نقطه آویزان می‌کند. پیش از اندازه‌گیری ساکن است، و همین که صدایش کنند، بی‌درنگ به راه می‌افتد—ایستگاهی برای زمان. خانه‌ی کوچکِ ثانیه‌ها، که نفسش را حبس کرده و منتظرِ علامتِ شروع است."},"ICON-2434":{"nm":"چرخ خط‌کش زمین بازی","de":"هرجا می‌چرخد، مسیری سفید و روشن باقی می‌ماند. مرزهای قوانین این‌گونه، دور به دور، بر زمین حک می‌شود. پیش از شروع بازی، چرخی که نخستین ردپا را روی زمینِ بازی برجا می‌گذارد."},"ICON-2435":{"nm":"جیب کارت داور","de":"در لحظه‌ی تصمیم، کارتی که از سینه بیرون کشیده می‌شود، اینجا خوابیده است. اتاق انتظارِ حکمی که تا نمایان‌شدن، تا آخر خاموش می‌ماند. جیبی که همیشه آماده منتظر است، به این امید که هرگز بیرون کشیده نشود."},"ICON-2436":{"nm":"پایه وزنه ترازو","de":"کارِ وزن کردن فقط روی کفی بدون لرزش صادقانه است. پایه‌ای که وزنه را نگه می‌دارد و در عین حال بدنِ خودش را صاف و مسطح تقدیم می‌کند. اولین قدمِ اندازه‌گیریِ دقیق همیشه از جایی آرام آغاز می‌شود."},"ICON-2437":{"nm":"کلیک‌زن سیگنال شروع","de":"با یک صدا، همه‌ی پاها هم‌زمان از زمین کنده می‌شوند. شروع بی‌نهایت کوتاه است، اما دستی که آن کوتاهی را می‌سازد، از هرکسی آرام‌تر است. دستی که لرزشِ خط شروع را با یک تیکِ واحد رها می‌کند."},"ICON-2438":{"nm":"پایه مخروط زمین بازی","de":"نامش ناآشناست اما کارش روشن است—مرکزِ زمینی شبیه صحنه را با وزن نگه می‌دارد. در مرکزی که همه می‌درخشند، همیشه یک پای دیده‌نشده بی‌صدا ایستادگی می‌کند."},"ICON-2439":{"nm":"سگک کمربند تنفس دیافراگمی","de":"صدای خوب نه از گلو، که از نفسِ عمیق می‌آید؛ این را کمر اول می‌داند. سگکی که می‌گذارد کف دست، برآمدن و فروافتادنِ شکم را حس کند. نقطه‌ی آغاز آواز همیشه زیر همین یک نفس نهفته است."},"ICON-2440":{"nm":"صفحه پَر تمرین تنفس","de":"وقتی پَر با نفس تو آرام تکان می‌خورد، نشانه‌ی یکنواختیِ نفس توست. به نفسِ دیده‌نشده به‌آرامی شکل می‌دهد و پایه‌ی آواز را آموزش می‌دهد. تمرینی که نفسِ پیش از اولین نُت را با چشم یاد می‌گیری."},"ICON-2441":{"nm":"ساعت شنی دم","de":"درونِ شیشه، شن مثل نفس فرو می‌ریزد. دم بکش، لحظه‌ای مکث کن، آرام بازدم کن—دانه‌ها ریتم را به‌جای تو می‌شمارند. مدتی به ریزشِ بی‌صدای شن نگاه کن، و بی‌آنکه بدانی، نفسِ آشفته‌ات مرتب می‌شود."},"ICON-2442":{"nm":"پایه تمرین شمع","de":"فتیله را روشن کن، و صدایت همراه با شعله‌ی لرزان می‌لرزد. کسی این پایه را با دقت تراشیده، تا آن لرزشِ کوچک را لحظه‌ای نگه دارد. به‌اندازه‌ی ضخامتِ موم سفت‌شده، اینجا شب‌هایی که تنها آواز خوانده‌ای، انباشته شده است."},"ICON-2443":{"nm":"بند کوسن فشار شکم","de":"به‌جای گذاشتن دست روی شکم، یک بند به‌آرامی آن نقطه را فشار می‌دهد. وقتی نفس بالا می‌آید محکم می‌کشد، وقتی خالی می‌شود آرام شل می‌شود. همراهی خاموش و کوچک در کنارت، که کمک می‌کند بدن ریتم را اول یاد بگیرد."},"ICON-2444":{"nm":"درپوش بادکنک تداوم نفس","de":"بادکنک را یک‌باره فوت نکن. بلند، آرام، تا انتها بیرونش بده. درحالی‌که درپوش را گاز می‌گیری و باد را بیرون می‌فرستی، هوا به عمیق‌ترین نقطه‌ی ریه می‌رسد. آواز، در نهایت، به‌اندازه‌ی طول نفسی که تحمل کرده‌ای، دور پرواز می‌کند."},"ICON-2445":{"nm":"دستگیره تنظیم نفس","de":"هرچه دل بیشتر بلرزد، دست بیشتر می‌خواهد چیزی را محکم بگیرد. این دستگیره را بگیر، شانه‌ها آرام پایین می‌افتند، و دم یک وجب بلندتر می‌شود. یادگیریِ گرفتن، همان یادگیریِ آرام کردنِ خود است؛ این را کف دست اول می‌داند."},"ICON-2446":{"nm":"حلقه باند لرزش شکم","de":"باند را به حلقه وصل کن، و لرزشی ملایم به مرکز شکم پخش می‌شود. نیرو بی‌صدا در همان نقطه‌ای جمع می‌شود که وقتی از ته دل می‌خندی می‌لرزد. مرکزِ استوار همیشه این‌گونه، آرام آرام، در جایی که کسی نمی‌بیند، رشد می‌کند."},"ICON-2447":{"nm":"صفحه شمارنده دم","de":"یک، دو، سه—هر بار که صفحه یک خانه می‌چرخد، عمقِ نفسِ کشیده‌شده حک می‌شود. یک خانه بیشتر شود، آواز هم یک عبارتِ بیشتر دوام می‌آورد. روی این صفحه‌ی کوچک، ظرفیتِ ریه‌ای که امروز پرورش داده‌ای، بی‌صدا ثبت می‌شود."},"ICON-2448":{"nm":"صفحه قاشقی تمرین زبان","de":"جایی که نوکِ زبان باید برسد، دقیق روی صفحه حک شده. چگونه بغلتانی، بزنی، و لحظه‌ای مکث کنی. پشتِ تلفظی که روان جاری می‌شود، بی‌شمار سحرهایی پنهان است که زبان این‌گونه مسیرش را از بر کرده."},"ICON-2449":{"nm":"گیره آینه شکل دهان","de":"گیره به‌آرامی شکلِ دهانی را که در آینه افتاده، نگه می‌دارد. «آ» گرد است، «ای» به دو طرف کشیده می‌شود. کلاسی آرام و فقط دونفره با آینه و خودم، درحالی‌که مستقیم به چهره‌ی خودم نگاه می‌کنم و شکلِ صدا را می‌سازم."},"ICON-2450":{"nm":"فُک چوب‌پنبه‌ای تلفظ","de":"فُکی کوچک که از چوب‌پنبه تراشیده شده، گوشه‌ی میز نشسته و به تلفظ گوش می‌دهد. در شب‌هایی که «ر» پیوسته می‌لغزد و دل می‌گیرد، چشمانِ گردِ فُک آرام می‌گوید: عیب ندارد، بیا یک‌بار دیگر امتحان کنیم."},"ICON-2451":{"nm":"سنجاق نشانه‌ی نفس متن ترانه","de":"کجای متنِ آهنگ باید نفس کشید، این سنجاق نخست می‌گوید. انتهای یک خط بزنش، و آن نقطه به علامتِ سکوتِ مهربانِ آهنگ بدل می‌شود. برای آنکه با دلِ باز بخوانی، حتی جمله هم به یک فاصله برای نفس تازه‌کردن نیاز دارد."},"ICON-2452":{"nm":"زیرچانه تمرین بیان کلمات","de":"فقط با کمی نگه‌داشتنِ چانه، تلفظی که می‌خواست پراکنده شود، جایش را می‌یابد. گفتارِ روشن فقط کار دهان نیست؛ چانه و گلو و نفس با هم آن را می‌سازند. همین تکیه‌گاهِ کوچک، بی‌صدا به آن تعادلِ دشوار کمک می‌کند."},"ICON-2453":{"nm":"پایه قالب دهان مصوت‌ها","de":"آ، اِ، ای، اُ، او—پایه‌ای که مسیرِ خروج این پنج مصوت از دهان را دقیقاً همان‌طور که هست برپا نگه می‌دارد. کنار آینه بگذارش، و هر روز اسکلتِ صدا را شکل بده. اسکلتِ هر آوازی، در نهایت، از همین پنج مصوت آغاز می‌شود."},"ICON-2454":{"nm":"کارت پیچیدگی زبان","de":"کارتی که خواندنش زبان را گره می‌زند و آخرش خنده را می‌ترکاند. اشتباه کردن واقعاً عیبی ندارد—اشتباه کردن خودِ تمرین است. هر بار که از این جمله‌ی شیطنت‌آمیز عبور می‌کنی، یک صدای دیگر روشن و واضح بیدار می‌شود."},"ICON-2455":{"nm":"دهانی گرم‌کردن لب","de":"گرم‌کردنی که با لرزاندنِ لب، دهانِ خشک را بیدار می‌کند. دهانی را گاز بگیر و باد را بلند بیرون بده، و لب‌های خواب‌آلود نرم و آزاد می‌شوند. کوچک‌ترین و مهربان‌ترین تمرینِ آماده‌سازی، برای گشودنِ نرمِ عبارتِ اول."},"ICON-2456":{"nm":"کش لاستیکی بخش متن آهنگ","de":"دور آن بخشی که پیوسته گیر می‌کنی، یک کش می‌بندی تا نشانش گذاشته باشی. هر بار آن نقطه را روی مچت می‌بینی، کوهی که امروز باید فتحش کنی به یاد می‌آید. هرچه گذر سخت‌تر باشد، بیشتر نگاهش می‌کنی، و بیشتر در دل نگهش می‌داری."},"ICON-2457":{"nm":"قلاب شال گردن‌گرم‌کن","de":"تا گلو در هوای سردِ سحرگاهانِ تغییرِ فصل خش‌دار نشود، شال را محکم به قلاب می‌آویزی. تنها از گلویی که گرم پیچیده شده، سرانجام صدایی صاف رها می‌شود. مراقبت از صدا همیشه از مراقبتِ گلو آغاز می‌شود."},"ICON-2458":{"nm":"نوک غلتک لرزش تارهای صوتی","de":"وقتی نوکِ غلتک آرام کنارِ گردن می‌چرخد، تارهای صوتیِ خوابیده در طول شب به‌آرامی بیدار می‌شوند. لرزشی سبک، تنشِ سفت را رها می‌کند، و نُتِ اولِ مردد، نرم‌تر می‌شود. دستی که پیش از خواندن، بدن را گرم می‌کند."},"ICON-2459":{"nm":"زیرلیوانی گرم‌کردن با زمزمه","de":"دهان بسته، آرام زمزمه‌کنان، لیوانِ گرمی که بخار می‌کند را با دو دست بگیر، و گلو هم گرم می‌شود. زمزمه‌ای آرام روی زیرلیوانی، گِرد گِرد پخش می‌شود. آواز این‌گونه، از یک جرعه گرمای ملایم آغاز می‌شود."},"ICON-2460":{"nm":"کپسول نگهداری آبنبات گلو","de":"برای روزهایی که گلو خشن و گرفته فرو می‌رود، آبنبات‌ها آرام درونِ کپسول جمع می‌شوند. درست پیش از رفتن روی صحنه یکی را در دهان بغلتان، و نعنایِ خنک گلویِ بسته را باز می‌کند. اندکی آرامش برای مواقع اضطراری، درون یک ظرفِ کوچکِ مخصوصِ خودت."},"ICON-2461":{"nm":"کیسه بخار گرم‌کننده گلو","de":"کیسه‌ای که با بخارِ گرم به‌خوبی خیس شده را دورِ گردن بپیچ، و نقاطی که از تمرینِ طولانی سفت شده بودند، نرم آب می‌شوند. با همان دلگرمیِ حوله‌ای تازه گرم‌شده، به تارهای صوتیِ خسته و فروافتاده، یک ضرب استراحت آرام پیشکش می‌کند."},"ICON-2462":{"nm":"ساعت شنی استراحت تارهای صوتی","de":"قولِ آرامی که امروز حرف نزنم، دانه‌های ریزِ شن بی‌صدا برایت می‌شمارند. کمی دهان بستن و صدا را نگه‌داشتن. آن زمانِ آرام، که بهترین مراقبت هم هست، اینجا آهسته جریان دارد."},"ICON-2463":{"nm":"دهانی گرم‌کردنِ تریل لب","de":"تریلِ لب که با لرزشِ سبکِ لب‌ها، از نُتی به نُت دیگر بالا و پایین می‌رود. دهانی را کمی گاز بگیر، و لرزشِ سرکشش یکدست‌تر می‌شود. ابزاری کوچک به‌اندازه‌ی کف دست، که اولین دکمه‌ی صداسازی را نرم می‌بندد."},"ICON-2464":{"nm":"درپوش اسپری رطوبت‌رسانِ گلو","de":"تا گلو روی صحنه‌ای خشک نخشکد، درپوش را فشار بده و مِهی نرم بپاش. یک نفسِ عمیق از هوای مرطوب‌شده بکش، و صدای خشکیده دوباره درخششِ صاف خود را باز می‌یابد."},"ICON-2465":{"nm":"توپ لرزشی گرم‌کردن صدا","de":"توپی را که روی کف دست ریز می‌لرزد، آرام نگه دار، و آن لرزش نرم از بازو تا گلو بالا می‌آید. دوستی گرد و مهربان برای گرم‌کردن، که اندام‌های صداساز را که از تنش سفت شده‌اند، آرام‌آرام تکان می‌دهد و بیدار می‌کند."},"ICON-2466":{"nm":"نشانگر نقطه فرمیشن","de":"یک نشانگر کوچک که درست روی زمینِ صحنه فرو رفته. اینجا جای توست، آن‌جا جای من. وقتی جمعی گرد هم می‌آیند تا یک تصویر واحد بسازند، این نشانگر بی‌صدا همه را سرِ جایشان نگه می‌دارد—قولی نادیدنی که هیچ‌کس پراکنده نشود."},"ICON-2467":{"nm":"تراشه نوک‌پیکانیِ مسیر حرکت","de":"تراشه‌ای به شکل نوکِ پیکان، جهتِ قدمِ بعدی را روشن نشان می‌دهد. کجا بچرخی، کجا بایستی—زمین پیش از تو می‌گوید تا راه گم نکنی. مسیر، نقشه‌ای است که نوکِ پا با گام‌های بی‌شمار از بر کرده."},"ICON-2468":{"nm":"سنجاق نقطه مرکزی فرمیشن","de":"تنها نقطه‌ای که وقتی جمعی گرد هم می‌آیند، بی‌صدا معیار می‌شود. دور همین سنجاق، دایره‌ای گرد کشیده می‌شود و فرمیشن باز می‌شود. حتی حرکاتِ پراکنده هم با همین یک نقطه‌ی مرکزی، ناگهان نظمِ خود را می‌یابند."},"ICON-2469":{"nm":"گوه نقطه تقاطع","de":"جایی که دو مسیر در یک نقطه به هم می‌رسند، گوه‌ای محکم فرو می‌شود. تا با هم برخورد نکنند، تا از هم جدا و ناهماهنگ نشوند. حتی در آن لحظه‌ی گذرا و نفس‌گیرِ رد شدن از کنار هم، کسی راهش را گم نکند."},"ICON-2470":{"nm":"پرچم جهت خروج","de":"وقتی طنینِ آخرین نُت محو می‌شود، آرام به سمتی که پرچم نشان می‌دهد بیرون می‌روی. خروج نباید به‌اندازه‌ی ورود هم آشفته باشد. حتی پایانِ صحنه، جهتی از پیش قول‌داده‌شده دارد."},"ICON-2471":{"nm":"گیره متر فاصله‌سنج","de":"نوکِ متر را با گیره محکم بگیر، و یک وجب، بعد یک وجبِ دیگر، دقیقاً بی‌خطا می‌شود. حتی فاصله‌ی میان آدم‌ها هم مثل اندازه‌گیری با خط‌کش، مرتب می‌شود. صحنه‌ای زیبا همیشه از همین نوک انگشتانِ دقیق زاده می‌شود."},"ICON-2472":{"nm":"حلقه بند مرجع صف‌آرایی","de":"بند را به حلقه ببند و در یک خط محکم بکش، و آن خطِ باریک معیارِ ایستادنِ همه در کنار هم می‌شود. آنچه صفِ منظم را این‌قدر مرتب نشان می‌دهد، به لطف همین یک خطِ راستِ نادیدنی است."},"ICON-2473":{"nm":"تراشه خط‌چین مسیر حرکت","de":"تراشه‌هایی که بی‌صدا روی زمین، مسیری با خط‌چین می‌کشند. اگر روی این ردهای کم‌رنگ راه بروی، حتی در تاریکی هم راه گم نمی‌کنی. تا نقطه به نقطه به هم وصل شوند، گام‌های پراکنده به یک جریانِ واحد می‌پیوندند."},"ICON-2474":{"nm":"پونز موقعیت روی زمین","de":"پونزی که روی زمین فرو رفته تا جایت را فراموش نکنی. حتی در تاریکیِ محض، نوکِ پا آن برجستگیِ کوچک را لمس می‌کند و بی‌شکست پیدایش می‌کند. تنها وقتی دقیقاً در همان یک نقطه می‌ایستی، نور سرانجام از بالای سرت می‌بارد."},"ICON-2475":{"nm":"باند تمرکز جداسازی گردن","de":"اگر چانه هم تکان بخورد، صدا هم می‌لرزد و از هم می‌پاشد. برای یادگرفتنِ اینکه فقط گردن حرکت کند و سر ثابت بماند، باند را می‌بندی. پشتِ حرکتی که این‌قدر آزاد به نظر می‌رسید، همین تمرینِ خاموشِ جداسازی نهفته است."},"ICON-2476":{"nm":"گیره کوسن ثابت‌کننده شانه","de":"تا شانه‌ها خودسرانه بالا نپرند، کوسن با گیره ثابت نگه داشته می‌شود. تا بدن دقیقاً تشخیص دهد کجا باید تکان بخورد و کجا ثابت بماند. خطِ کنترل‌شده همیشه از همین محکم‌نگاه‌داشتن‌های کوچک زاده می‌شود."},"ICON-2477":{"nm":"سگک کمربند حس‌گر دنده‌ها","de":"کمربند بی‌صدا رگه‌ی ظریفِ باز و بسته شدنِ دنده‌ها را می‌خواند. سگک را ببند، و حرکتِ نفس واضح تا نوک انگشتانت منتقل می‌شود. صداسازیِ عمیق و استوار، از همین حرکتِ نادیدنیِ استخوان‌ها سرچشمه می‌گیرد."},"ICON-2478":{"nm":"آونگ تکان دادن لگن","de":"آونگ آرام به چپ و راست می‌چرخد و ریتمی را که لگن می‌سازد، بی‌صدا نشان می‌دهد. وزنه‌ای کوچک به‌اندازه‌ی کف دست، بی‌کلام یاد می‌دهد که مرکزِ بدن چگونه وزنش را جابه‌جا می‌کند. اینکه حتی تکان‌خوردن هم رگه‌ای دارد."},"ICON-2479":{"nm":"حلقه چرخش مچ دست","de":"حلقه را به مچ دست بینداز و آرام به داخل و بیرون بچرخان، و مفصلی که تمام شب سفت بوده، نرم آزاد می‌شود. برای حرکتی که تا نوکِ انگشتان زنده برسد، اول باید مچ نرم شود. همین چرخشِ کوچک، بیانی بزرگ‌تر را می‌گشاید."},"ICON-2480":{"nm":"بند حلقه مقاومتی مچ پا","de":"حلقه را به مچ پا ببند و بند را بکش، و با هر قدمی که برمی‌داری، مقاومتی ملایم به نوک پا می‌چسبد. به همان اندازه که سنگین قدم برمی‌داری، در پاها بی‌صدا نیرو جمع می‌شود. پرشی سبک مثل پَر، همیشه بر همین تمرینِ سنگین می‌ایستد."},"ICON-2481":{"nm":"کیسه شن تمرکز مرکز بدن","de":"فقط پس از بستنش دور شکم است که سرانجام می‌فهمی مرکزِ بدنت کجا بوده. تا وزنه شانه‌ها را می‌کشد، مرکزِ لرزان به‌آرامی جایش را می‌یابد، و در جایی که بازش می‌کنی، فقط یک وضعیتِ راست‌ایستاده باقی می‌ماند."},"ICON-2482":{"nm":"درپوش میله تراز کردن ستون فقرات","de":"وقتی درپوشی کوچک به پشتی می‌رسد که تمام روز خمیده زندگی کرده، انگار کسی آرام شانه‌هایت را صاف می‌کند. می‌شود خمیده هم زندگی کرد، اما راست ایستادن، هنری مهربان است که باید دوباره آرام‌آرام یاد گرفت."},"ICON-2483":{"nm":"توپ طب فشاری آرام‌سازی عضله","de":"اگر نقطه‌ای گرفته را محکم فشار دهی، اول تیر می‌کشد و بعد آرام می‌شود. مثل گرمای پشتِ دستِ مادربزرگ که در کودکی پشتت را می‌مالید، آرام کردن یعنی مدتی بیشتر درد کشیدن در حالی‌که کنارت می‌مانی."},"ICON-2484":{"nm":"پیچ تنظیم زاویه آینه","de":"فقط به‌اندازه‌ی یک کف دست بچرخانی، آینه چهره‌ای کاملاً دیگر نشان می‌دهد. با یک چرخشِ پیچ، جهان کج می‌شود و دوباره راست می‌ایستد؛ پس انگار حتی روبه‌رو شدن با خود هم به نشانه‌گیریِ آرامی نیاز دارد."},"ICON-2485":{"nm":"پد پاک‌کن بخار آینه","de":"پیش از آینه‌ای که از بخارِ داغ تار شده، آدم برای لحظه‌ای چهره‌ی خودش را گم می‌کند. یک دستمالِ سریع، و چهره برمی‌گردد. به‌لطفِ همین دستی که تاری را می‌زداید، هر صبح دوباره خودم را می‌بینم."},"ICON-2486":{"nm":"لاستیک پایه سه‌پایه دوربین","de":"نوکِ پایه‌ی سه‌پایه، یک تکه لاستیک به‌اندازه‌ی ناخن، سرنوشتِ تصویر را رقم می‌زند. نیرویی که محکم زمین را گاز می‌گیرد، لرزش را آرام می‌کند؛ پس تصویری بی‌لرزش همیشه بی‌صدا از اصطکاکی نادیدنی آغاز می‌شود."},"ICON-2487":{"nm":"فیلم شطرنجیِ مرجع زاویه","de":"خطوطِ ریزِ شطرنجی روی فیلم، مثل چرخ‌های کمکی برای چشم هستند. هرچه ترکیب‌بندی به دست عادت می‌کند، خطوط آرام محو می‌شوند و فقط حس باقی می‌ماند. ردِّ یادگیری، هرچه پخته‌تر شود، نادیدنی‌تر می‌شود."},"ICON-2488":{"nm":"پدال شروع ضبط","de":"برای کسی که دو دستش پر از وسایل است، آخرین انگشتش همیشه نوکِ پا بوده. یک ضربه‌ی سبک، و ضبط آغاز می‌شود—پشتِ صحنه، خانه‌داری این‌گونه با مهارت، حتی تا نوکِ پا، نقشش را ایفا می‌کند."},"ICON-2489":{"nm":"گیره جهت‌دهیِ نور","de":"اینکه نور کجا بیفتد، در نوکِ انگشتانِ همین گیره‌ی به‌اندازه‌ی ناخن نهفته است. جابه‌جا کردنِ سایه به‌اندازه‌ی یک وجب و زنده‌کردنِ برجستگی، کاری است که کسی سرِ همان تفاوتِ کوچک، مدت‌ها با دقت مردد می‌ماند."},"ICON-2490":{"nm":"پرده مقایسه فیلم","de":"دیروز و امروز را کنار هم بگذار، و تازه آن‌وقت تغییر لب به سخن باز می‌کند. لحظه‌ای که پرده آرام پایین می‌آید، فاصله‌ی زمانی که میان آن دو طی شده، صادقانه روی صفحه آشکار می‌شود."},"ICON-2491":{"nm":"بند مچی ریموت","de":"یک بند دور مچ بپیچ، و دلی که از افتادنش نگران بود آرام می‌شود. وسیله‌ی ایمنیِ کوچک، برعکس، دست را آزادتر می‌کند—تناقضی مهربان که در آن، بسته‌بودن، دل را آسوده می‌کند."},"ICON-2492":{"nm":"درپوش لنز","de":"در حالی که دوربین استراحت می‌کند، لنز هم آرام چشمش را می‌بندد. در جهانی که یک ذره گرد و غبار روی صفحه زخم برجا می‌گذارد، آرام پوشاندنش همان آرزوی نگه‌داشتنِ طولانیِ آن است."},"ICON-2493":{"nm":"باند بالاکشیدن گوشه لب","de":"گوشه‌های لب را کمی بالا بکش، و حالتی که سفت بود آرام‌آرام باز می‌شود. لبخند هم در نهایت عضله است؛ اول قدرتِ ابزار را قرض می‌گیری، و یک روزِ صبح، خودت با نیروی خودت روشن می‌خندی."},"ICON-2494":{"nm":"غلتک ماساژ عضله گونه","de":"داخلِ گونه را آرام بغلتان و باز کن، و کلمات به‌مراتب روان‌تر جاری می‌شوند. آماده‌سازی‌ای آرام، پیش از خواندن، که چهره را نرم بیدار می‌کند. حالت هم وقتی گرم می‌شود، گرم‌تر می‌شود."},"ICON-2495":{"nm":"خط‌کش زاویه لبخند","de":"دوربین می‌داند که حتی لبخند هم زاویه‌ی درستِ خودش را دارد. با این خط‌کش این‌طرف و آن‌طرف اندازه می‌گیری و سرانجام می‌فهمی: زیباترین لبخند از صداقتی می‌شکفد که اصلاً قابل اندازه‌گیری نیست."},"ICON-2496":{"nm":"گیره حرکت ابرو","de":"اگر ابرو حتی یک میلی‌متر حرکت کند، کل رگه‌ی دل تغییر می‌کند. گیره‌ای که کوچک‌ترین جزءِ حالت را بی‌صدا نگه می‌دارد؛ بازیگری، کار نوک انگشتانی است که همین ظرافت را رام می‌کنند."},"ICON-2497":{"nm":"برچسب بالابرنده استخوان گونه","de":"استخوان گونه را کمی بالا بکش و بچسبان، و روی صورت جایی پدید می‌آید که نور در آن می‌ماند. حجمی که یک برچسبِ به‌اندازه‌ی ناخن می‌سازد—آرایشِ صحنه، این‌گونه رازهایی نادیدنی در خود پنهان دارد."},"ICON-2498":{"nm":"چشم‌بند پوششِ چشمک","de":"یک چشم را بپوشان، و دل تمام‌وکمال در چشمِ باقی‌مانده جمع می‌شود. تمرینِ چشمک، در نهایت، یادگیریِ پنهان‌کردنِ زیبای نیمی از صورت است. حالت‌هایی هستند که دقیقاً به همان اندازه که پوشیده می‌شوند، روشن‌تر می‌شوند."},"ICON-2499":{"nm":"گیره قالب شکل دهان","de":"گا، گیا، گئو... شکلِ دهان را با قالب هماهنگ کن، و تلفظِ مبهم روشن می‌شود. اینکه هر مصوت در واقع حالتی از صورت است را، آرام‌آرام پیش آینه در بدنت حک می‌کنی."},"ICON-2500":{"nm":"کیسه گرم‌کردن حالت چهره","de":"درست پیش از رفتن روی صحنه، کیسه‌ی گرمی که به‌آرامی صورت را گرم می‌کند. همان‌طور که دستِ سرد اجرا را سفت می‌کند، حالت هم همین‌طور است. حقیقتی کوچک از پشتِ صحنه: حتی لبخند هم به گرم‌شدنِ اولیه نیاز دارد."},"ICON-2501":{"nm":"نوار صاف‌کننده‌ی چین پیشانی","de":"وقتی نوار را دور پیشانی می‌بندی، چین‌های عمیقِ اخم آرام‌آرام باز می‌شوند. چیزی که چروک‌های حکاکی‌شده از نگرانی را برای مدتی به استراحت می‌برد. زیر پیشانیِ صاف‌شده، آدم کمی جوان‌تر به نظر می‌رسد."},"ICON-2502":{"nm":"انگشتانه‌ی ورق‌زدن فیلم‌نامه","de":"انگشتانه‌ی کوچکی که نوک انگشت برای ورق زدن صفحات به آن می‌شود. ریتم ورق زدن فیلم‌نامه‌ی ضخیم، صفحه به صفحه، بی‌آنکه بفهمی به ضرباهنگ داستان بدل می‌شود. حتی در خواندن هم عادتی مهربان در دستْ خانه می‌کند."},"ICON-2503":{"nm":"پرچمِ رنگ‌آمیزیِ احساسات","de":"شادی زرد است، اندوه آبی. وقتی رنگ را بر دل می‌نشانی و پرچم را برمی‌افرازی، احساسِ نادیدنی در باد به اهتزاز درمی‌آید و شکل می‌گیرد. حس‌ها را هم می‌شود این‌گونه با دست کشید."},"ICON-2504":{"nm":"گیره‌ی تأکیدِ دیالوگ","de":"«وزن را روی این کلمه بگذار»، گیره آرام این را می‌گوید. همان دیالوگ با یک تکیه‌ی صدا معنایش سراسر عوض می‌شود، پس این نشانه‌ای کوچک است که مرکز ثقل کلام را نگه می‌دارد."},"ICON-2505":{"nm":"بلوکِ کاما در خوانش","de":"بلوکی که گذاشته شده تا بگوید «همین‌جا یک ضربان مکث کن». کاما در میان دیالوگ توقف نیست، بلکه نفسی است که برای کلمات بعدی فرو می‌رود. کسی که خوب مکث می‌کند، در نهایت خوب هم سخن می‌گوید."},"ICON-2506":{"nm":"نوارِ گیره‌دارِ نشانِ نفس","de":"نوار در امتداد گیره بالا و پایین می‌رود و طول نفس را پیش چشم ترسیم می‌کند. تماشا و پیروی از ریتم دم و بازدم؛ آغاز هر آواز همیشه از مهار کردن نفس شروع می‌شود."},"ICON-2507":{"nm":"کیسه‌ی تاسِ احساسات","de":"تاسی که غلت‌زنان از کیسه بیرون می‌افتد، احساسِ امروز را تعیین می‌کند. اگر شادی آمد، شاد باش؛ اگر خشم آمد، خشمگین باش. تمرین بازیگری به بازیِ سپردنِ دل به تصادف بدل می‌شود."},"ICON-2508":{"nm":"پایه‌ی شیب‌دارِ نگهدارِ فیلم‌نامه","de":"فیلم‌نامه را روی پایه‌ی کج‌شده بگذار، دیگر لازم نیست سر خم کنی. این شیب کوچک که چشم را در سطح نگه می‌دارد، آرام از گردنی که با تمرینِ طولانی خشک شده مراقبت می‌کند."},"ICON-2509":{"nm":"پرده‌ی نجواگویی","de":"نشانه‌ای که می‌گوید از اینجا به بعد نجوا کن. صدایت را پشت پرده پایین بیاور و تماشاگران، برعکس، نفس در سینه حبس می‌کنند و گوش تیز می‌کنند. پارادوکس مهربانِ صحنه: هرچه آهسته‌تر بگویی، دورتر می‌رسد."},"ICON-2510":{"nm":"جعبه‌ی توکنِ تعویضِ نقش","de":"توکن را کمی برگردان و نقشی که بازی می‌کنی عوض می‌شود. امروز نقشِ اول، فردا دوستی که کنارت می‌ماند. در جزیره‌ای که همه با هم بزرگ می‌شوند، نوبت هرکس می‌رسد که وسط صحنه بایستد."},"ICON-2511":{"nm":"استیکرِ نقطه‌ی ثابتِ نگاه","de":"چشم را آرام روی نقطه‌ی کوچکی کنار دوربین می‌نشانی. لحظه‌ای که نگاهِ لرزان به یک‌جا می‌رسد، چشم‌ها در صفحه به‌روشنی جان می‌گیرند. نگاهِ ثابت، در نهایت، از بی‌حرکت ماندن آغاز می‌شود."},"ICON-2512":{"nm":"گونیای سنجشِ زاویه","de":"وقتی گوشه‌ای از صفحه به‌نوعی کج به نظر می‌رسد، گونیا را کمی نزدیک ببر و جواب پیدا می‌شود. کارِ راست کردنِ کج. پیش از آنکه به چشمانت اعتماد کنی، لحظه‌ای به خط‌کش اعتماد کن."},"ICON-2513":{"nm":"پایه‌ی هم‌سطح‌کننده‌ی لنز با چشم","de":"لنز را در ارتفاع چشمِ آدم تنظیم کن تا صفحه کمتر دروغ بگوید. نه از بالا، نه از پایین؛ فقط وقتی با همان چشم‌ها روبه‌رو می‌شوی، حالتِ واقعیِ بی‌آرایش ثبت می‌شود."},"ICON-2514":{"nm":"پرِ فلش‌نمای هدایتِ نگاه","de":"نگاه آرام‌آرام به سمتی که پَر اشاره می‌کند کشیده می‌شود. فلشی کوچک که نگاه بیننده را به‌نرمی می‌برد. یک نمای خوب همیشه با مهربانی نشان می‌دهد کجا را باید نگاه کرد."},"ICON-2515":{"nm":"تراشه‌ی کف‌فرشِ مسیرِ فیلم‌برداری","de":"نقطه‌ای از مسیری را که تا فرسودگی از حفظ شده‌ای زیر پا بگذاری، جای بعدی بی‌درنگ در دسترس می‌شود. قدم‌هایی که صحنه را می‌پیمایند، راهی نادیدنی‌اند که با پیوستنِ همین نشانه‌های کوچکِ چسبیده به کف ساخته شده."},"ICON-2516":{"nm":"نوارمتر فاصله‌ی دوربین","de":"فاصله‌ی میان سوژه و دوربین را با نوار اندازه می‌گیرند. در دنیایی که یک وجب دوری و نزدیکی را جدا می‌کند، نوارمتر نگهبانی خاموش می‌شود که مرزِ میان تاری و وضوح را پاس می‌دارد."},"ICON-2517":{"nm":"راهنمای کجیِ سر","de":"سر را تا چه اندازه باید کج کرد که مهربان‌ترین حالت به نظر برسد؟ با پیروی از راهنما، آرام‌آرام می‌فهمی—زاویه‌ی کجی، در نهایت، به همان اندازه‌ای شبیه است که دل باز می‌شود."},"ICON-2518":{"nm":"گیره‌ی آینه‌ی دستیِ چشم‌درچشمی","de":"آینه‌ی دستی را با گیره کنار دوربین بگذار، و همان‌طور که به چشمانِ خودت نگاه می‌کنی، با چشمانِ تو هم چشم در چشم می‌شوی. وسیله‌ای کوچک که پلی از نگاه میان «من در آینه» و «تو در صفحه» می‌سازد."},"ICON-2519":{"nm":"چراغِ نشانه‌ی فیلم‌برداری","de":"وقتی چراغ روشن می‌شود، یعنی هم‌اکنون فیلم‌برداری در جریان است. یک چراغ کوچک، تنشِ لحظه‌ی هیجان‌زده‌ی صحنه را یک‌جا جمع می‌کند. از لحظه‌ای که چراغ روشن است، نفسِ همه در یک ضرباهنگ منظم می‌شود."},"ICON-2520":{"nm":"دکمه‌ی زنگِ واکنش","de":"دکمه را فشار بده و صدای زنگی زلال و شفاف طنین می‌اندازد. مثل کف‌زدنی که بعد از یک صحنه‌ی خوب یک‌باره می‌ترکد، کلامی گرم از کسی که می‌گوید «آفرین»، درون همین زنگ کوچک نگه داشته شده است."},"ICON-2521":{"nm":"لوله‌ی قرعه‌کشیِ چابکی","de":"تکانش بده و چوب‌های داخلش تلق‌تلق صدا می‌کنند، اول از همه فضا را زنده می‌کنند. اینکه چه کسی صحنه را باز می‌کند با یک تکانِ مچ دست تعیین می‌شود—کسی که قرعه به نامش می‌افتد با خجالت می‌خندد، بقیه نفسی به‌راحتی می‌کشند. حتی تقسیمِ شانس هم قاعده‌ای مهربان دارد."},"ICON-2522":{"nm":"زنگوله‌ی افکت صدا","de":"مچ دست را کمی تکان بده و — جینگ — صدای تشویقی از جا می‌جهد. این زنگوله‌ی کوچک پیش از آنکه سکوت خجالت‌آور شود، خلأ را پُر می‌کند. در شمردنِ ضرباهنگِ خنده، همیشه این یکی یک قدم جلوتر است."},"ICON-2523":{"nm":"درِ جعبه‌ی سورپرایز","de":"تا باز نشود، هیچ‌کس نمی‌تواند حدس بزند درون چیست. این تنها وظیفه‌ی این در است. طوری که جیغ و خنده با هم در لحظه‌ی تکان خوردنِ در بترکند، هیجان را روی یک لولا آویزان کرده است."},"ICON-2524":{"nm":"بادبزنِ تاشوی واکنش","de":"صدای «چیک» بازشدنش خودش پاسخی می‌شود. لبه‌های بادبزن، تحسینی را که به کلام درنیامده باد می‌زند و می‌فرستد. میان حرکتِ باز و بسته شدن، شور و شوق رفت‌وآمد می‌کند و رشته‌ای از احساس همراه با نسیم تاب می‌خورد."},"ICON-2525":{"nm":"چرخِ روله‌تِ تنبیه","de":"هیچ‌کس از پیش نمی‌داند سوزن روی کدام خانه می‌ایستد. هرچه چرخ کندتر می‌شود، قلب برعکس تندتر می‌تپد—تیک، و در جایی که می‌ایستد، سرنوشتِ خنده‌دارِ امروز نوشته می‌شود. چند ثانیه‌ای که حتی لرزیدنش هم لذت‌بخش است."},"ICON-2526":{"nm":"تخته‌ی حبابِ گفتارِ شگفتی","de":"بالای سر بلندش کن و «وای» به شکل حروف بالا می‌آید. یک ورق کاغذ، دلی را که دهان نتوانسته دنبالش کند جلو می‌افتد و فریاد می‌زند. چون حتی واکنش هم به کمی کارگردانیِ صحنه نیاز دارد."},"ICON-2527":{"nm":"پرچمِ دستیِ توقف لحظه‌ای","de":"لحظه‌ای که پرچم بالا می‌رود، همه درست همان‌جا خشک می‌شوند. نشانه‌ای که حتی صدای نفس را در یک قابِ ثابت حبس می‌کند. وقتی دوباره پایین می‌آید، خنده‌ی منجمدشده یک‌جا سرریز می‌شود."},"ICON-2528":{"nm":"سطلِ گیره‌ی جواب‌های عجیب","de":"هرچه جواب عجیب‌تر باشد، محکم‌تر گیره می‌شود و آویزان می‌ماند. وقتی جواب‌های غلط ردیف‌شده روی بند رخت در باد تاب می‌خورند، به صحنه‌ای بدل می‌شود که خطاها بیش از جواب‌های درست دوست داشته می‌شوند. منظره‌ی روزی که اشتباه کردن هم اشکالی ندارد."},"ICON-2529":{"nm":"گوه‌ی پشتی‌ِ اصلاح‌کننده‌ی وضعیت بدن","de":"لحظه‌ای که به آن تکیه می‌دهی، ستون فقراتِ خمیده آرام‌آرام مسیر خودش را پیدا می‌کند. گوه‌ی کوچکی که بی‌کلام نگهت می‌دارد. وضعیت درست، آرام از پشت سر می‌گوید، تنها زمانی راحت می‌شود که کسی حامیت باشد."},"ICON-2530":{"nm":"بلوکِ نگهدارِ همتراز کردنِ لگن","de":"سفتیِ کوچکی که زیر پا می‌گذاری وقتی مرکز ثقل می‌لرزد. تعادل بدن، در نهایت، آرام‌آرام از کف زمین بالا می‌آید. بازیگرِ مکمل بی‌نامی که از جایی نادیدنی وضعیت بدن را نگه می‌دارد."},"ICON-2531":{"nm":"توپِ تعادلِ سفت‌کننده‌ی شکم","de":"آن را دور شکم ببند و آرام بفشار، مرکز پراکنده به یک نقطه جمع می‌شود. هرچه نفس را عمیق‌تر آرام کنی، توپ سفت‌تر می‌شود، و بدن، نفس‌به‌نفس، محوری را که فراموش کرده بود بازمی‌یابد."},"ICON-2532":{"nm":"خط‌کشِ بررسیِ انحنای ستون فقرات","de":"خط‌کش را در امتداد کمر بگذار، انحنای نادیدنی روی مقیاس آشکار می‌شود. صاف ایستادن یعنی پاک کردنِ انحنا نیست—یعنی خواندنِ همان خمیدگیِ کوچک هم با مهربانی."},"ICON-2533":{"nm":"حلقه‌ی کِشیِ بازکننده‌ی شانه","de":"آن را روی شانه بینداز و آرام بکش، سینه‌ی جمع‌شده کاملاً باز می‌شود. کِش همیشه نجوا می‌کند «به جای خودت برگرد»، و پشتی که یک روز تمام خمیده بود، با آن ندای نرم کم‌کم صاف می‌شود."},"ICON-2534":{"nm":"کیسه‌شنِ محرکِ عضلات مرکزی","de":"دور کمر ببندش و دانه‌های سنگینِ شن، مرکزِ خواب‌آلوده را بیدار می‌کنند. حتی حرکتی سبک هم جلوی این وزن در یک لحظه جدی می‌شود. اینکه هرچه تحمل کنی سفت‌تر می‌شوی را، دانه‌به‌دانه‌ی شن آرام یادآوری می‌کند."},"ICON-2535":{"nm":"تگِ کوسنِ نگهدارِ استخوان دنبالچه","de":"کوسنی که آرام زیر استخوان دنبالچه تکیه‌گاه می‌شود، و تگِ کوچکی آویزان از انتهایش. وسیله‌ای شبیه یادداشتی مهربان، نوشته و چسبانده‌شده برای روزی خسته از نشستنِ طولانی: «همین‌جا کمی می‌توانی تکیه کنی.»"},"ICON-2536":{"nm":"سه‌پایه‌ی زاویه‌ی نگهدارِ کمر","de":"با سه پایه ایستادگی می‌کند و زاویه‌ای را که کمر باید تکیه کند، آرام نگه می‌دارد. تکیه‌گاهی که آرام در وضعیتی رو به فروپاشی وارد می‌شود. برای نگه‌داشتنِ چیزی لرزان، شگفتا که سه نقطه کافی است."},"ICON-2537":{"nm":"گیره‌ی وضعیتِ عقب‌کشیدنِ چانه","de":"چانه را کمی عقب بکش و تکیه بده، خط گردنِ به‌هم‌ریخته جای خودش را پیدا می‌کند. غرغرِ گیره‌ای به اندازه‌ی یک انگشت، به‌نوعی مهربان است. این ابزار کوچک، راه راست نگه داشتنِ سر را یاد می‌دهد."},"ICON-2538":{"nm":"نردبانِ نواریِ گام‌های پا","de":"نواری که روی زمین پهن می‌شود، خانه‌هایی را که پا باید یک‌به‌یک روی آن‌ها بیفتد ترسیم می‌کند. اگر خانه‌به‌خانه صادقانه قدم بگذاری، بی‌آنکه بفهمی گام‌ها در بدن حک می‌شوند. راه، هرچه بیشتر پیموده شود، روشن‌تر می‌شود."},"ICON-2539":{"nm":"مخروط کوچکِ تغییرِ مسیر","de":"بگذارش سرِ پا، نشانه‌ی کوچکی که می‌گوید «همین‌جا بپیچ». به پایی که همیشه تنها مستقیم می‌دوید، یک پیچ هدیه می‌دهد. حتی در مسیرِ چرخیدن هم ریتمی خاصِ خودش پنهان است."},"ICON-2540":{"nm":"تخته‌ی لرزانِ ایستادن روی یک پا","de":"لحظه‌ای که روی یک پا می‌ایستی، تخته کمی کج می‌شود. آن چند ثانیه‌ای که با تمام توان برای غلبه بر لرزش تلاش می‌کنی، صادقانه‌ترین درسِ تعادل است. نوکِ انگشتانی که تلاش می‌کنند نیفتند، همه‌چیز را می‌گویند."},"ICON-2541":{"nm":"چراغ چشمک‌زنِ سرعتِ واکنش","de":"لحظه‌ای که سیگنال روشن می‌شود، دست و چشم برای اول‌بودن رقابت می‌کنند. نور چشمک‌زن مجالی برای تردید نمی‌دهد. دستِ چابک همیشه نیم‌ضرب زودتر از فکر حرکت می‌کند."},"ICON-2542":{"nm":"نشانگرِ زیگزاگیِ رد پا","de":"نقطه‌های کوچکی که مورب روی زمین چسبیده‌اند و پاها را به رقصیدنِ زیگزاگ می‌کشانند. سخت‌تر از خط راست، همیشه پیچ‌درپیچ بودن است. اگر دنبال نقاط سرگردان شوی، حرکت سریع پاها ماهرانه پخته می‌شود."},"ICON-2543":{"nm":"میله‌ی صافِ بندبازیِ تعادل","de":"پاهایت را روی میله‌ی باریک بگذار، دنیا مثل طنابی باریک تنگ می‌شود. مثل بندبازی که روی هوا راه می‌رود، تمرکز کل بدن را روی پهنای یک وجب می‌گذاری. تعادل، هرچه تنگ‌تر می‌شود، برعکس روشن‌تر می‌گردد."},"ICON-2544":{"nm":"دستبند توپِ جهشیِ چابکی","de":"به مچ دست ببندش و توپ کوچک با جهش برمی‌گردد. در لحظه‌ی پرتاب و گرفتن، سرعتِ واکنش در نوک انگشتان حک می‌شود. سرعت، در نهایت، از دست ندادنِ چیزی است که برمی‌گردد."},"ICON-2545":{"nm":"حلقه‌ی هولاهوپِ چالاک‌کننده‌ی پا","de":"به پا آویزانش کن و بچرخان، حلقه ساق پا را پیوسته تحریک می‌کند. لحظه‌ای که بایستی، می‌افتد، پس پا بی‌وقفه تکان می‌خورد. در میانِ حرکتی شبیه بازی، حرکتِ پا چالاک و سریع پخته می‌شود."},"ICON-2546":{"nm":"فرفره‌ی چوبیِ مرکز نوک پا","de":"فرفره‌ای که روی کف دست می‌چرخد، همان لحظه‌ای که مرکزش را از دست بدهد می‌ایستد. مثل روزهای کودکی که در حیاط فرفره می‌چرخاندی، تعادل چیزی است که تنها با چرخیدنِ بی‌پایان می‌تواند برپا بماند."},"ICON-2547":{"nm":"بندِ محافظِ سفت‌کننده‌ی مچ پا","de":"مچ پا را بپیچان و ببند، جای پای لرزان استوارتر می‌شود. هرچه جایی آسیب‌پذیرتر باشد، باید مهربان‌تر نگهش داشت. یک رشته بند به آسودگیِ یک قدم بدل می‌شود."},"ICON-2548":{"nm":"نوارِ پیچیِ گرم‌کننده‌ی زانو","de":"دورِ زانوی سرد بپیچانش، گرما میان بندها نفوذ می‌کند. مفصلِ سفت‌شده تنها با گرم شدن نرم می‌شود. پیش از حرکت، گرم‌ترین سلامِ صبحگاهی است که به بدنِ خودت می‌دهی."},"ICON-2549":{"nm":"توپِ فشاریِ شل‌کننده‌ی عضله","de":"نقطه‌ی گرفته را محکم فشار بده، دانه‌ها آرام گره را نوازش می‌کنند. تسلی عجیبی که هرچه بیشتر درد بگیرد، بیشتر باز می‌شود. حتی گرفتگی‌هایی که دست به آن‌ها نمی‌رسید را، این توپ کوچک به‌جای دست نوازش می‌کند."},"ICON-2550":{"nm":"چرخِ ترتیبِ گرم کردن بدن","de":"از هر خانه‌ای که چرخ بایستد، بدن را بیدار کن. گردن، شانه، مچ پا—ترتیب را به شانس بسپار و دل را سبک نگه دار. وقتی بازی در گرم کردنِ بدن رخنه می‌کند، بدنِ سفت‌شده اول از همه آرام لبخند می‌زند."},"ICON-2551":{"nm":"پکِ گرمِ گرم‌کننده‌ی مفصل","de":"پکِ داغ را روی مفصل بگذار، آرامشی مثل کرسیِ زمستانی پخش می‌شود. زمانی است که مفاصلِ سفت‌شده با خمار خواب‌آلود شل می‌شوند. تنها پس از گرم شدن، بدن آرام‌آرام برای حرکت آماده می‌شود."},"ICON-2552":{"nm":"حلقه‌ی دستگیره‌ی کششی","de":"حلقه را بگیر و بکش، عضلاتِ سفت به‌آرامی کشیده و بلند می‌شوند. میان دستِ مقاومت‌کننده و بدنِ باز شونده، گفتگویی کشیده رد و بدل می‌شود. هرچه بیشتر کش بیاید، حرکاتِ فردا سبک‌تر خواهد بود."},"ICON-2553":{"nm":"تخته‌ی برجستگی‌دارِ محرکِ کف پا","de":"پابرهنه روی برجستگی‌ها بایست، کفِ پاهای خواب‌رفته یکهو بیدار می‌شوند. مثل آن حسِ گزنده‌ی راه رفتنِ پابرهنه روی جاده‌ی سنگریزه، حسِ لمسِ زمین از نوک انگشتان بالا می‌آید."},"ICON-2554":{"nm":"پین آهنربایی یادداشتِ آسیب‌دیدگی","de":"می‌نویسی «زیاده‌روی نکن» و روی صفحه‌ی فلزی می‌چسبانی‌اش. خاطراتِ دردناک به‌راحتی فراموش می‌شوند، پس با آهنربا جلوی چشم آویزانش می‌کنی. مراقبت از بدن هم در نهایت از یک خطِ یادداشت آغاز می‌شود."},"ICON-2555":{"nm":"غلتکِ گره‌دارِ شل‌کننده‌ی فاسیا","de":"میله‌ی گره‌دار را آرام بغلتان، فاسیای چسبیده قسمت‌به‌قسمت باز می‌شود. لمسی که آرام گره‌ها را پس می‌راند. روزی که در خود پیچیده بود هم، اگر این‌گونه بند‌به‌بند باز شود، بسیار سبک‌تر می‌شود."},"ICON-2556":{"nm":"نوارِ کفیِ خط راه‌رفتن","de":"صاف روی زمین پهنش کن، برای پا خطی می‌سازد که باید دنبالش راه برود. حتی راه‌رفتنی درهم هم، وقتی روی این خط بیفتد، بی‌آنکه بفهمی صاف می‌شود. اگر مسیر را رسم کنی، پا دیگر سرگردان نمی‌شود."},"ICON-2557":{"nm":"میله‌ی افقیِ شانه","de":"عرضی روی شانه بگذارش، تعادلِ کج‌شده به یک‌سو آرام آشکار می‌شود. افقی بودن همیشه یعنی پایین آوردنِ یک سو و بالا بردنِ سوی دیگر. یک میله به‌تنهایی عادتِ کج را آرام نشان می‌دهد."},"ICON-2558":{"nm":"وزنه‌ی تعادلِ فرقِ سر","de":"برای اینکه وزنه‌ی روی فرقِ سر نیفتد، تمام بدن باید در یک خط راست بایستد. مثل تصویر قدیمیِ راه رفتن با کوزه‌ی آب روی سر، مرکز از بالاترین نقطه گرفته و پایین کشیده می‌شود."},"ICON-2559":{"nm":"تکیه‌گاهِ زاویه‌ی چانه","de":"چانه را آرام تکیه بده، سری که پیوسته خم می‌شد زاویه‌ی درستش را بازمی‌یابد. استراحتی کوتاه که به یک تکیه‌گاه تکیه دارد. خطِ راست تنها زمانی کامل می‌شود که کسی از پایین نگهش دارد."},"ICON-2560":{"nm":"میخِ فاصله‌ی گام","de":"میخی که در زمین کوبیده شده، از پیش فاصله‌ای را که پا باید بنشیند اندازه می‌گیرد. یک گام، نه پهن و نه تنگ—آن فاصله‌ی صادقانه. تعادلِ راه رفتن آرام از همین نشانه‌ی کوچک آغاز می‌شود."},"ICON-2561":{"nm":"گوه‌ی جهت‌نمای نوک پا","de":"نخستین قدمِ مردد، نوکِ پا اول از همه در تردید است که کدام سو برود. وقتی این گوه‌ی کوچک جهت را تعیین می‌کند، دل هم آرام به همان سو کج می‌شود. تعیینِ مسیر، تصمیمی بزرگ نیست، بلکه همان یک وجبی است که نوک پا نشانش می‌دهد."},"ICON-2562":{"nm":"کمربندِ صاف‌کننده‌ی کمر","de":"انگار همان صدایی که همیشه می‌گفت «کمرت را صاف کن، صاف کن»، درون این کمربند زنده مانده. روزِ خمیده را آرام صاف کن، وزنی که روی شانه‌هایت بود هم به‌طرز شگفتی کمی سبک‌تر می‌شود. یک وضعیتِ درست، حتی دل را هم برمی‌خیزاند."},"ICON-2563":{"nm":"کف‌پایه‌ی توزیعِ وزن","de":"هفت روی پای چپ، سه روی پای راست. اینکه وزن را کجا بیشتر بگذاری تعادل را تعیین می‌کند. کف‌پایه آرام می‌پرسد—الان به کدام سو بیشتر کج ایستاده‌ای؟ صاف ایستادن هم در واقع تنظیمی بی‌پایان است."},"ICON-2564":{"nm":"میله‌ی هدفِ ارتفاعِ نگاه","de":"چشم‌ها پیوسته به نوکِ پا می‌افتند. در آن لحظه‌ها، میله‌ای که دوردست برپاست، نگاه را آرام‌آرام بالا می‌کشد. تمرینِ دوردیدن، تمرینِ دورراه‌رفتن هم هست، پس لحظه‌ای که سر را بالا می‌گیری، حتی جایی که دست‌نیافتنی می‌نمود هم نزدیک می‌شود."},"ICON-2565":{"nm":"گیره‌ی کارتِ زاویه‌ی تعظیم","de":"پانزده درجه، سی درجه، چهل‌وپنج درجه. دل هم به همان عمقی که کمر خم می‌شود، خم می‌شود. زاویه‌ی نوشته‌شده روی کارت فقط یک عدد نیست، بلکه مقیاسی کوچک است که خلوصِ نسبت به طرف مقابل را می‌سنجد."},"ICON-2566":{"nm":"حلقه‌ی ادبِ دست‌درهم","de":"دو دست را مرتب کنار هم بگذار، دلِ بی‌قرار هم آرام در یک‌جا فرو می‌نشیند. این حلقه‌ی کوچک، نوکِ انگشتانِ سردرگم را مهربانانه می‌گیرد و اولین وضعیتِ سلام‌کردن را آرام برقرار می‌کند."},"ICON-2567":{"nm":"آهنربای فلشِ مسیر","de":"چیزی که پای گمشده اول از همه با نگاهِ سرگردان دنبالش می‌گردد، یک فلش است. جهتی که با آهنربا می‌چسبد، تردید را قطع می‌کند و قدم‌ها را آرام به سمتی که باید رفت می‌کشد. دلِ سرگردان هم بالاخره یک جهت پیدا می‌کند."},"ICON-2568":{"nm":"سنجاقِ نشانگرِ جهتِ خروج","de":"راهِ رفتن سخت‌تر از راهِ آمدن است. حتی در تاریکیِ خاموش هم این سنجاقی که به‌روشنی می‌درخشد، آرام آخرین مسیر را نشان می‌دهد. اینکه رفتنِ خوب هم بخشی از صحنه است، فقط در انتها فهمیده می‌شود."},"ICON-2569":{"nm":"نوارِ کارتِ ترتیبِ تعظیمِ رسمی","de":"زمانی بود که ترتیبِ کسی که اول تعظیم می‌کرد و کسی که بعد تعظیم می‌کرد روشن بود. با ترتیبِ نوشته‌شده روی نوار سر خم کن، ادب هم رگه‌ای پیدا می‌کند و نزاکت هم جریانی. این نگه‌داشتنِ ترتیبِ دل است."},"ICON-2570":{"nm":"تراشه‌ی آهنربایی هم‌ترازیِ گام","de":"اگر یک نفر از قدم بیفتد، کل صف می‌لرزد. مثل تراشه‌ای که با هم‌ترازیِ نوک پاها تیک می‌کند و می‌چسبد، ایستادن با هم یعنی آرام گامِ خودت را به کسی کنارت واگذار کنی. صدای پاهایی که در یک ضرباهنگ به زمین می‌خورند، مطمئن‌ترین چیز است."},"ICON-2571":{"nm":"نعلِ جایگاهِ تعظیمِ صحنه","de":"حتی یک تعظیمِ صحنه هم جایی برای ایستادن دارد. پاهایت را روی نشانه‌هایی بگذار که مثل نعل اسب دایره‌وار پهن شده‌اند، و اولین سلامی که از استرس پیوسته کج می‌شد، بالاخره شکل خودش را پیدا می‌کند. با شناختن جایگاه، لرزش هم کمی فرومی‌نشیند."},"ICON-2572":{"nm":"کارتِ حرکتِ دستِ سپاسگزاری","de":"قدردانی‌ای که کلمات نتوانستند کامل نگهش دارند، از نوکِ انگشتان جاری می‌شود. کشیدنِ یک قلب، گذاشتنِ دست روی سینه—هر حرکتِ نوشته‌شده روی کارت، ترجمه‌ای می‌شود از دل که به حرکت درآمده. صداقتی که می‌خواهد برسد، همیشه شکلی دارد."},"ICON-2573":{"nm":"میخِ کارتیِ فاصله‌ی صف","de":"حتی در صف ایستادن هم نزاکتی مهربان دارد. مثل میخی که دقیقاً یک وجب فاصله از نفرِ جلو نگه می‌دارد، انتظار از ملاحظه‌ای کوچک آغاز می‌شود—تلاش برای هُل ندادنِ یکدیگر. کمی دورتر ایستادن هم توجه‌کردن است."},"ICON-2574":{"nm":"حلقه‌ی ورق‌زنِ کارتِ متن","de":"وقتی جمله‌ی بعدی پیوسته لب می‌لرزاند، انگشت آرام یک برگ را ورق می‌زند. کاغذهای کوچکِ به حلقه بسته‌شده، آرام تپشِ قلب را فرومی‌نشانند و جای بعدی حرف‌زدن را آرام باز می‌کنند. هرچند بلرزی، جریان قطع نمی‌شود."},"ICON-2575":{"nm":"ساعت‌شنیِ ترتیبِ برنامه","de":"دانه‌های شنی را که آرام فرومی‌ریزند تماشا کن، ترتیبِ بعدی در دل آرام مرتب می‌شود. تا پیش از افتادنِ آخرین دانه، این ساعتِ کوچک بدونِ عجله یاد می‌دهد که چگونه زمان را با چشم بخوانی."},"ICON-2576":{"nm":"میله‌ی تمرینِ گرفتنِ میکروفون","de":"پیش از آنکه به دست عادت کند، یک میله‌ی خالی به سنگینیِ هزار من است. زاویه‌ی گرفتن، فاصله از دهان، فشاری که به مچ دست می‌دهی—تمرینی که بی‌شمار بار گرفته و رها شده، یک روز ناگهان به یک حرکتِ طبیعی شکوفا می‌شود."},"ICON-2577":{"nm":"میله‌ی زبانیِ شفاف‌کننده‌ی تلفظ","de":"گا، نا، دا، را. میله را در دهان نگه دار و آواها را بغلتان تا نوک زبان شفاف شود. کلمه‌ای که واضح و شفاف عبور می‌کند، مثل گلی است که آرام روی صدها ساعتِ لکنت‌دار و مبهم می‌شکفد."},"ICON-2578":{"nm":"پرچمِ دستیِ نشانه‌ی کیو","de":"شروع، توقف، یک ضربان مکث کن. یک پرچم بی‌کلام، تنفسِ صحنه را رهبری می‌کند. از جایی که دیده نمی‌شود از میان تماشاگران، دستی که آرام تکان می‌خورد، تمام ضرباهنگ‌ها را بی‌هیچ شکافی نگه می‌دارد."},"ICON-2579":{"nm":"زنگوله‌ی تغییرِ بخش","de":"دینگ، صدایی زلال طنین می‌اندازد و صحنه عوض می‌شود. مثل صدای زنگی که در بازارِ غروب پخش می‌شد، این طنینِ کوچک، دلِ مردد را به‌آرامی به بخش بعدی می‌برد. تغییر همیشه از یک صدا آغاز می‌شود."},"ICON-2580":{"nm":"آونگِ ضرباهنگِ نفسِ گفتار","de":"نفس بکش تو—یک، دو—و آرام بیرون بده. با آونگی که چپ و راست تاب می‌خورد نفس را منظم کن، و کلامی که شتاب‌زده سرریز می‌شد هم بی‌آنکه بفهمی ضرباهنگش را بازمی‌یابد. سرعتِ کلام، در نهایت، سرعتِ نفس بود."},"ICON-2581":{"nm":"تخته‌ی تاشوی متنِ برنامه","de":"در همان یک حرکتِ تاکردن و بازکردن، تمامِ ترتیبِ امروز دست‌نخورده نگه داشته شده. لحظه‌ای که تخته‌ی کهنه‌شده را باز می‌کنی، ذهنی که در سردرگمیِ اینکه اول چه چیزی را بیاورد بود، آرام صف می‌بندد. با یک بازکردن، روز مرتب می‌شود."},"ICON-2582":{"nm":"ساعت‌شنیِ ضرباهنگِ نفس","de":"دم سه، نگه‌داری چهار، بازدم شش. تا زمانی که شن جاری است، نفسِ من هم آرام همراهش جاری می‌شود. شمردنِ نفس‌ها یکی‌یکی، کهن‌ترین و مهربان‌ترین شیوه‌ی مراقبتِ آرام از خودِ شلوغی است."},"ICON-2583":{"nm":"منگوله‌ی کوسنِ مراقبه","de":"منگوله‌ی آویزان از لبه‌ی کوسن بی‌هیچ بادی آرام تاب می‌خورد. چهارزانو بنشین، و سکوتِ روحِ کهنی که روی ایوانی چوبی دلش را آرام می‌کرد، به‌آرامی به کنارت می‌آید، لحظه‌ای می‌ماند و می‌رود."},"ICON-2584":{"nm":"زنگوله‌ی دستیِ آرام‌کننده‌ی نفس","de":"وقتی یک نسیم عبور می‌کند، صدایی زلال آرام می‌نالد. این آویخته مثل بادزنگی زیر سایبان، قطره‌ای خنک و شفاف روی دلی که در سردرگمی می‌جوشید می‌چکاند. حتی صدا هم قدرت خنک‌کردن دارد."},"ICON-2585":{"nm":"بشقاب نگهدارِ دودِ عود","de":"دودِ باقی‌مانده از سوختنِ عود آرام روی بشقاب می‌نشیند. مثل عطری که صبح روزِ جشن بالای سفره برمی‌خاست، رشته‌ای از دود آرام‌آرام هوای آشفته را می‌نشاند و اتاق را از سکوت پر می‌کند."},"ICON-2586":{"nm":"وزنه‌ی نوسانیِ دم‌وبازدم","de":"نفسِ من روی یک وزنه سوار می‌شود که آرام بالا می‌رود و دوباره پایین می‌آید. وقتی دم می‌گیرم اوج می‌گیرد، وقتی بازدم می‌کنم فرو می‌نشیند—روزی که بدن راهِ نفس کشیدن را فراموش کرده، این ساعتِ کوچک دوباره از اول یادش می‌دهد."},"ICON-2587":{"nm":"چوبِ نواختنِ زنگِ مراقبه","de":"یک‌بار زنگ را آرام بنواز، طنین طولانی پخش می‌شود. مثل صدای بادزنگِ معبدِ کوهستانی، فقط با گوش‌دادنِ آرام تا زمانی که آن طنین کاملاً در هوا محو شود، گوشه‌ای از دل شفاف شسته می‌شود."},"ICON-2588":{"nm":"پرِ راهنمای مسیرِ نفس","de":"پر را آرام جلوی بینی نگه دار، مسیرِ نفسی که دیده نمی‌شد بالاخره هویدا می‌شود. تکانِ آرام یعنی خوب نفس می‌کشی؛ بی‌حرکتی یعنی زیاده از حد نگهش داشته‌ای. سبک‌ترین چیز گاهی صادق‌ترین راهنماست."},"ICON-2589":{"nm":"سنگریزه‌ی آرام‌کننده‌ی دل","de":"سنگریزه‌ی درونِ کف دست سرد و صاف است. مثل سنگی که مدت‌ها در کنارِ رودخانه غلتیده و همه‌ی لبه‌هایش را داده، اگر پیوسته با نوک انگشتان بازی‌اش دهی، تیزی‌های دلِ جوشان هم کم‌کم گرد و صاف می‌شود."},"ICON-2590":{"nm":"گیره‌ی دماسنجِ نفسِ بینی","de":"دمای نوکِ بینی آرام عمقِ نفس را می‌گوید. گیره خاموش هوایی را می‌خواند که سرد وارد و گرم خارج می‌شود، و نفسی را که معمولاً حتی حسش هم نمی‌کنی، پیش چشم به‌روشنی نشانت می‌دهد. نفس هم حالتی دارد."},"ICON-2591":{"nm":"تخته‌ی استیکرِ هوای احساس","de":"دلِ من امروز آفتابی است یا ابری؟ لحظه‌ای که استیکری کوچک را انتخاب می‌کنی و روی تخته می‌چسبانی، حالی که به‌کلام گفتنش سخت بود هم به نوعی هوا بدل می‌شود و شکلی روشن می‌گیرد. دل هم به پیش‌بینیِ هوا نیاز دارد."},"ICON-2592":{"nm":"مهرِ دستیِ رنگِ احساس","de":"شادی زرد است، اندوه آبی. رنگی انتخاب کن و محکم روی کاغذ بزن، رنگِ دل به شکل رَدی باقی می‌ماند. حتی احساسی که نام گذاشتن برایش سخت بود، رنگ اول از همه می‌آید و آرام می‌شناسدش."},"ICON-2593":{"nm":"تراشه‌ی گلبرگیِ دلِ امروز","de":"دلِ تمامِ امروز را آرام روی یک گلبرگ می‌گذاری. مثل شکوفه‌های ارغوانی که در روزِ بهاری پراکنده می‌شدند، تراشه‌ای سبک و لطیف، در انتهای روزی رو به غروب، آرام می‌پرسد که چطور گذشته."},"ICON-2594":{"nm":"آهنربای حبابِ گفتارِ تشویق","de":"حرفی که می‌خواهی بگویی پیوسته روی لب می‌ماند. لحظه‌ای که آهنربای حبابِ گفتار را می‌چسبانی، کلمه‌ای دلگرم‌کننده که نتوانستی به زبان بیاوری، آرام به روزِ خسته‌ی کسی می‌رسد. دل این‌گونه منتقل می‌شود."},"ICON-2595":{"nm":"مهرِ پاکتِ رازِ دل","de":"حرف‌هایی که نتوانستی بیرون بریزی را مرتب در پاکتی می‌گذاری و مهر می‌کنی. مثل روحِ کهنی که با نوکِ انگشت چسب می‌مالید و نامه را می‌بست، یک مهر، رازِ درون را امن نگه می‌دارد. آرام منتظر روزی که آن را بیرون بیاوری و باز کنی."},"ICON-2596":{"nm":"غنچه‌ی گلِ دماسنجِ احساس","de":"غنچه‌ی بسته، با لمسِ گرما، لایه‌به‌لایه محتاطانه باز می‌شود. شکفتنی که با بالارفتنِ دمای دل همراه است—اینکه امروز چقدر گرم شده‌ام را، این گل پیش از کلمات می‌داند. به دل هم بهار می‌رسد."},"ICON-2597":{"nm":"بندِ آینه‌ی دستیِ تحسینِ خود","de":"آینه را بالا بگیر و آرام با خودت که در آن منعکس شده چشم در چشم شو. آن صورتِ کوچکِ آویزان از بند، صورتِ تو را نشان نمی‌دهد، بلکه دیروزِ تو را نشان می‌دهد، کسی که سزاوارِ یک کلام است بابت خوب تاب‌آوردن. تسلی هرگز دور نبود."},"ICON-2598":{"nm":"ست مهرِ حالتِ چهره‌ی دل","de":"لبخندی روشن، اشکی لبریز، لب‌هایی از سرِ قهر برجسته. مهرهای حالتِ چهره را محکم بزن و روزنوشتِ دل را بنویس. روزی که برای نوشتن خیلی سنگین است، یک چهره‌ی کوچک به‌جای تو حالِ آن روز را آرام می‌گوید."},"ICON-2599":{"nm":"حلقه‌ی مرتب‌کننده‌ی کلافِ احساس","de":"هر قدر هم کلاف درهم‌پیچیده باشد، اگر رشته‌به‌رشته و آرام باز شود، در نهایت به یک نخ برمی‌گردد. احساساتِ درهم و خفه‌کننده را یکی‌یکی روی حلقه بیاویز، و دلی که هیچ نمی‌شد فهمیدش هم سررشته‌ای باریک پیدا می‌کند."},"ICON-2600":{"nm":"بندِ کیسه‌ی عطرِ خواب","de":"از کیسه‌ی عطرِ آویزان بالای بالش، عطرِ ملایمِ گیاهی آرام پخش می‌شود. مثل بویی که مادربزرگ عطر را عمیقِ کمد جا می‌داد، همان‌طور که بند را لمس می‌کنی، تنشی که تمام روز سیخ ایستاده بود، آرام به خواب می‌رود."},"ICON-2601":{"nm":"تخته‌ی چرخش خواب","de":"شبی که تا سپیده‌دم غلت زدی و به‌سختی خوابت برد. اگر وضعیت خوابیدنت را آرام بچرخانی، بی‌قراریِ دیروز بی‌صدا به طراوتِ امروزِ صبح بدل می‌شود. این تخته‌ی کوچک بی‌آنکه چیزی بگوید، یادآوری می‌کند که استراحت‌کردن هم تمرین می‌خواهد."},"ICON-2602":{"nm":"آویز مهتاب بالشی","de":"تکه‌ای از نوری که از شکاف پرده می‌تابد، بر بالای بالش آویخته می‌شود. رودی کم‌فروغ بر چهره‌ی خفته جاری می‌شود، و شب‌های ترسناکِ آن کارآموز از تاریکی، سرانجام نرم شد. این نخستین آرامش کوچکش بود."},"ICON-2603":{"nm":"تراشه‌ی غنچه‌ی حال‌روز","de":"حال‌وروزِ امروز مثل غنچه‌ای بسته است. کافی‌ست آرام روی تراشه فشار دهی تا کم‌کم باز شود؛ بدن پیش از هر چیز می‌داند که خوب خوابیده‌ای یا نه. حتی آن دودلیِ پیش از شکفتن هم به‌آرامی دوست‌داشتنی‌ست."},"ICON-2604":{"nm":"پوشش فتیله‌ی چراغ‌خواب","de":"«چراغ را خاموش نکن.» برای کوچک‌ترین که از تاریکی می‌ترسید، کسی به‌آرامی پوششی روی فتیله گذاشت. نه چندان روشن، نه چندان تاریک؛ قولی کوچک و مهربان که فقط تا به‌خواب‌رفتن کنارت می‌ماند."},"ICON-2605":{"nm":"سنجاق آفتابگردانِ بیداریِ صبح","de":"اگر کنار بالشت جا بدهی‌اش، مثل آفتابگردان به‌آرامی سر به‌سوی نخستین پرتو خورشید می‌چرخاند. حتی روزی که دلت نمی‌خواهد بیدار شوی، انگار می‌گوید که نور بی‌دلیل صدایت نمی‌زند، و صبح را به یک سو رهنمون می‌شود."},"ICON-2606":{"nm":"قلم‌موی گیاهیِ خواب","de":"کمی اسطوخودوس و بابونه به نوک قلم‌مو می‌زنی و یک‌بار روی بالش می‌کشی. تا رایحه در روبالشی نفوذ می‌کند، تنشِ یک روز کامل به‌آرامی از شانه‌ها فرو می‌ریزد. خوابِ خوب از همین عطرِ کوچک آغاز می‌شود."},"ICON-2607":{"nm":"گیره‌ی گوشه‌ی لحاف","de":"نزدیک سپیده‌دم، نوک پا دائم از زیر لحاف بیرون می‌زند. اگر گوشه‌ی لحاف را محکم با گیره ببندی، گرما تا صبح فرصت گریز پیدا نمی‌کند. این مراقبتِ کوچکی‌ست که به‌جای گفتنِ «شب‌بخیر» انجام می‌شود."},"ICON-2608":{"nm":"سبد سنگریزه‌های حال‌خوش","de":"هر روز یک اتفاق خوب، یک سنگریزه به‌اندازه‌ی کف دست. هرچه سنگ‌های جمع‌شده در سبد سنگین‌تر می‌شوند، دل هم بی‌صدا مطمئن‌تر می‌شود. جمع‌کردنِ لحظه‌های ساده در مشت؛ خوشبختی از همیشه همین‌طور شمرده شده است."},"ICON-2609":{"nm":"کوزه‌ی جمع‌آوریِ ستاره‌های عزم","de":"هر شب، عزمِ امروز را به‌شکل ستاره درمی‌آوری و آرام در کوزه می‌اندازی. وقتی لبریز شود، کوزه به آسمانی شب‌های کوچک بدل می‌شود. دهانه‌ی خالیِ آن می‌داند: پیمان‌ها تنها وقتی جمع شوند می‌درخشند."},"ICON-2610":{"nm":"آویز آب‌نبات پاداشِ کوچک","de":"در پایان روزی طاقت‌فرسا، آب‌نباتی که به خودت هدیه می‌دهی. لحظه‌ای که یکی از آویز برمی‌داری و در دهان می‌گذاری، حتی اگر کسی متوجه نشود، همه‌چیز رو‌به‌راه است. چون پاداشِ کوچک، صادقانه‌ترین تشویق است."},"ICON-2611":{"nm":"مهرِ «امروز انجامش دادم»","de":"کمی جوهر می‌زنی و محکم روی دفتر می‌کوبی: «امروز انجامش دادم.» روزی که خوب گذشت و روزی که فقط دوام آوردی، هر دو به یک اندازه یک خانه را پر می‌کنند. لازم نیست هر روز کامل باشد، فقط کافی‌ست دست از مهرزدن نکشی."},"ICON-2612":{"nm":"پایه‌ی نگه‌دارنده‌ی پرچمِ تشویق","de":"اگر محکم در زمین فرو رود، هرچه باد تندتر بوزد، پرچم پرشورتر به اهتزاز درمی‌آید. حتی چیزی که می‌لرزد به دستی نیازمند است که نگهش دارد. دلی که برای کسی هورا می‌کشد، این‌گونه از پایین تحمل می‌کند."},"ICON-2613":{"nm":"گلدان کاشتِ بذرِ هدف","de":"هدف چیزی نیست که با کلمات از بر شود، بلکه در خاک دفن می‌شود. تا دانه‌ای می‌کاری و آب می‌دهی و منتظر می‌مانی، بی‌تابی به‌آرامی به ریشه بدل می‌شود. تنها جوانه نیست که در این گلدان می‌روید."},"ICON-2614":{"nm":"تخته‌ی برچسبِ تشویقی","de":"برای هر کار خوب، یک برچسب. هرچه تخته رنگارنگ‌تر می‌شود، روزهایی که بی‌خیال از کنارشان گذشته بودیم، دوباره با رنگ زنده می‌شوند. در کودکی می‌دانستیم که تشویق هرچه بیشتر بچسبانی‌اش، روشن‌تر می‌شود."},"ICON-2615":{"nm":"حلقه‌ی گره‌زدن روبانِ عزم","de":"دستی که روبان را از حلقه رد می‌کند و گره می‌زند؛ محکم که باز نشود، اما نه آن‌قدر سفت. عزم درست مثل همین گره است؛ اگر خیلی سفت شود می‌گسلد، اگر شل بماند بی‌صدا وا می‌رود."},"ICON-2616":{"nm":"تراشه‌ی صدفِ دستاورد کوچک","de":"روی صدفی که از ساحل برداشته‌ای، یک دستاورد کوچک می‌نویسی. مثل تکه‌ای که موج‌ها بارها تراشیده و صیقل داده تا به اینجا رسیده، روز تو هم پس از غلتیدنی طولانی، براق می‌درخشد. هر آنچه در برابر زمان دوام آورده، سرانجام می‌درخشد."},"ICON-2617":{"nm":"قلاب آویزانِ مدال پاداش","de":"مدالی که به‌سختی به‌دست آمده را نه در کشو، بلکه در سطح چشم می‌آویزند. سنگینیِ آن روی قلاب، هر صبح شانه‌ها را صاف نگه می‌دارد. پاداش برای پنهان‌شدن نیست؛ برای این آویخته می‌شود که نگاهش کنی."},"ICON-2618":{"nm":"لیوانِ آب‌گیرِ چترِ باران فصلی","de":"باران فصلی از نوک چتر می‌چکد و پایین می‌غلتد. اگر لیوانی زیرش بگذاری، ورودی خانه خیس نمی‌ماند. نمی‌توان جلوی چیزی را که فرومی‌ریزد گرفت، اما می‌توان تعیین کرد کجا فرود بیاید."},"ICON-2619":{"nm":"کیسه‌ی سردکننده‌ی گرما","de":"پشت صحنه در گرمای تابستان، کیسه‌ی سردی که آرام روی گردن گذاشته می‌شود. حرارتِ برافروخته یک ضرب‌آهنگ فرو می‌نشیند. «یک نفس بکش.» دستی که پیش از گرما به‌فکر من است، دلگرم‌کننده است."},"ICON-2620":{"nm":"گیره‌ی ثابت‌کننده‌ی پره‌ی پنکه","de":"پره‌ای که با شتاب می‌چرخید هم با یک گیره به‌آرامی می‌ایستد. هرچه باد تندتر باشد، به چیزی نیاز دارد که محکم نگهش دارد. چیزهایی که تند می‌چرخند، سرانجام با دستی که نگهشان می‌دارد ایمن می‌شوند."},"ICON-2621":{"nm":"میله‌ی خشک‌کنِ کفشِ خیس","de":"کفشی که زیر باران خیس شده، طی یک شب حتی دل را هم نمناک می‌کند. اگر میله را داخلش بگذاری، صبح دوباره خشک و پوشیدنی می‌شود. چیز خیس را نباید دور انداخت، باید با ظرافت خشکش کرد."},"ICON-2622":{"nm":"تخته‌ی گِل‌گیرِ چکمه","de":"چکمه‌ای که پُر از گِل جاده‌ی مزرعه شده. فقط پس از آنکه روی تخته چند بار مالیده و تکانده شود، پا به داخل خانه می‌گذارد. جا گذاشتنِ لجن بیرون پشت در، آدابی کهن برای پاکیزه‌نگه‌داشتنِ خانه است."},"ICON-2623":{"nm":"کاشیِ خنکِ زیرپاییِ تابستان","de":"پای برهنه پیش از هر چیز می‌فهمد. اگر کف پا را روی کاشیِ پهن‌شده در تابستان بگذاری، حرارتِ نیمروز آرام در مشتی خنکا محو می‌شود. با همین یک خنکایِ کوچک، فصلِ بلند تحمل‌پذیر می‌شود."},"ICON-2624":{"nm":"نوار سدکننده‌ی آب باران آستانه","de":"فقط یک نوار روی آستانه بسته می‌شود، و باران دیگر نمی‌تواند به داخل سرازیر شود. خطی باریک که درون و بیرون را از هم جدا می‌کند. جایی که باید محافظت شود، به مرزی محکم و ساده بیشتر می‌آید تا دیواری بزرگ."},"ICON-2625":{"nm":"بشقاب نگه‌دارنده‌ی مارپیچِ ضدپشه","de":"در شبِ تابستان، وقتی مارپیچِ ضدپشه را روی بشقاب می‌گذاری، دودی تند اما آشنا برمی‌خیزد. مثل بخوری که دایره‌وار محو می‌شود، شب هم به‌آرامی عمیق‌تر می‌شود. این همان بویی‌ست از روزهایی که روی تخت چوبی دراز می‌کشیدیم و ستاره می‌شمردیم."},"ICON-2626":{"nm":"حلقه‌ی آستین‌بندِ خنک","de":"بازویی که زیر آفتاب می‌سوزد را با آستین‌بند می‌پوشانی. اگر با حلقه محکم به آستین لباس ببندی‌اش، کار نیمروز هم تحمل‌پذیر می‌شود. خنکا، همان توجه کوچکی‌ست که یک وجب از پوستِ در معرض را می‌پوشاند."},"ICON-2627":{"nm":"جارویِ دستیِ برگ‌روبی","de":"برگ‌های ریخته‌ی سرتاسر حیاط را با جاروی دستی جمع می‌کنی. یک فصل کامل زیر پا خش‌خش می‌کند. مرتب‌کردنِ چیزی، گاهی همان بدرقه‌کردنِ باشکوهِ چیزی است که باید برود."},"ICON-2628":{"nm":"میله‌ی نگه‌دارِ پنجره برای تهویه","de":"در اتاقی خفه، میله‌ای می‌گذاری تا پنجره کمی باز بماند. نسیم پاییزی بی‌صدا وارد می‌شود و هوای کهنه را با خود می‌برد. تهویه، همان روزنه‌ی کوچکی‌ست که آنچه درون راکد مانده را آرام با بیرون معاوضه می‌کند."},"ICON-2629":{"nm":"درپوش کیسه‌ی بلوط","de":"مثل سنجاب، کیسه را پُر از بلوط می‌کنی و دهانه‌اش را با درپوش می‌بندی، محکم که چیزی نغلتد بیرون. میلِ نگه‌داشتنِ آنچه جمع شده، غریزه‌ای کهن در موجودات کوچکی‌ست که زمستان را پشت سر می‌گذارند."},"ICON-2630":{"nm":"قالی‌کوب لحافِ پاییزی","de":"لحافی که تمام تابستان زیرش خوابیدی را در حیاط پهن می‌کنی و با قالی‌کوب محکم می‌کوبی. میان گردوغبار، بوی آفتاب پخش می‌شود. مچ دست پیش از هر چیز به یاد می‌آورد که باید فصل کهنه را تکاند تا بتوان فصل تازه را روی خود کشید."},"ICON-2631":{"nm":"نخِ سدِ باد شکاف پنجره","de":"باد سردی که از شکاف پنجره نفوذ می‌کند را با یک نخ محکم مسدود می‌کنی. رشته‌ای باریک، گرمای اتاق را تا آخرین لحظه نگه می‌دارد. آماده‌شدن برای زمستان می‌داند که سرمای بزرگ همیشه از یک شکاف کوچک آغاز می‌شود."},"ICON-2632":{"nm":"توری صافیِ برگ","de":"توری صافی که روی ناودان کشیده می‌شود؛ برگ‌ها را با ظرافت جدا می‌کند و تنها آب را عبور می‌دهد. لبه‌ی پاییزیِ بام می‌گوید که برای جاری‌شدنِ بدون انسداد، باید تعیین کرد چه چیزی عبور کند و چه چیزی نگه داشته شود."},"ICON-2633":{"nm":"گیره‌ی بستن دسته‌علفِ خشک","de":"دسته‌ی علفِ کاملاً خشک‌شده را با گیره محکم می‌بندی. دستی که چیزهای در حال پراکنده‌شدن را کنار هم گرد می‌آورد. حتی در جایی که سبزیِ تابستان کاملاً رخت بربسته، اگر گردآوری شود، کاربردش دست‌نخورده باقی می‌ماند."},"ICON-2634":{"nm":"آویزِ لرزانِ دماسنجِ بادِ پاییزی","de":"وقتی باد می‌وزد، آویز به‌آرامی می‌لرزد. از دامنه‌ی همان لرزش می‌شود سنجید که پاییزِ امروز چقدر عمیق شده است. دما عددی نیست؛ نخستین بار به‌صورت چیزی لرزان به دست می‌رسد."},"ICON-2635":{"nm":"جاگرم‌کن جیبِ کاپشن","de":"«دستت سرد شده، نه؟» جاگرم‌کنی که در جیبِ کاپشن گذاشته شده، انگشتانِ یخ‌زده را به‌آرامی گرم می‌کند. دلی که سرمای دیگری را زودتر از هرچیز حس می‌کند، همیشه بی‌صدا در دلِ جیب جا خوش کرده است."},"ICON-2636":{"nm":"لبه‌ی جمع‌کننده‌ی رطوبتِ پنجره","de":"لبه آرام اشک‌هایی را که پنجره‌ی زمستانی تمام شب ریخته، جمع می‌کند. رودخانه‌ای کوچک، ساخته‌ی اختلاف دمای درون و بیرون. پنجره‌ی سپیده‌دم هر روز نشان می‌دهد که هرچه اختلاف بیشتر باشد، جریان هم بیشتر است."},"ICON-2637":{"nm":"توری ایمنیِ شومینه","de":"جلوی شومینه‌ای که شعله‌ور می‌سوزد، توری ایمنی برپا می‌شود. گرما نزدیک، خطر درست به‌اندازه‌ی یک وجب دورتر. نگه‌داشتنِ آتش در کنارِ خود بدون آسیب‌دیدن، ابتدایی‌ترین فاصله در مراقبت از دیگری‌ست."},"ICON-2638":{"nm":"گیره‌ی نگه‌دارنده‌ی لحافِ زمستانی","de":"وقتی لحافِ کلفتِ زمستانی مدام سُر می‌خورد، گیره آن را فشرده و در جایش نگه می‌دارد. گرمای سنگین باید محکم نگه داشته شود تا واقعاً به‌کارش برسد. آسایشِ شب زمستانی این‌گونه با دقت پاسداری می‌شود."},"ICON-2639":{"nm":"کاردکِ یخ‌زدایی","de":"یخِ سفیدی که روی شیشه‌ی خودرو در سپیده‌دم نشسته را با کاردک تراشیده و پاک می‌کنی. دیدِ تارشده خط‌به‌خط باز می‌شود. نوکِ انگشتانِ صبح زمستانی می‌گوید که هرچه یخ‌زده هم سرانجام می‌شود تراشید و برداشت."},"ICON-2640":{"nm":"کاور عایق درِ بطریِ آب‌گرم","de":"روی بطریِ پُر از آب داغ، کاوری عایق کشیده می‌شود. تا تمام شب سرد نشود، لایه‌ای دیگر گرما را در بر می‌گیرد. راز نگه‌داشتنِ گرما برای مدتی طولانی، در نهایت همان در آغوش‌کشیدنِ صبورانه با چیزی‌ست."},"ICON-2641":{"nm":"میله‌ی فشارِ کاغذِ درزگیرِ در","de":"بادِ تیزی که از شکاف در نفوذ می‌کرد، لحظه‌ی برخورد با تو مکث می‌کند. میله‌ای که لبه‌ی کاغذِ درزگیر را محکم فشرده نگه می‌دارد. گرمای درونِ اتاق سرانجام از خانواده‌ی خود مراقبت می‌کند؛ زمستان با همین لجاجت کوچک گرم می‌گذرد."},"ICON-2642":{"nm":"بشقاب زیرِ گرم‌کنِ پا","de":"بشقاب گردی که زیر گرم‌کنِ پا پهن شده. تمام حرارت را تنها تحمل می‌کند، اما حتی یک لکه‌ی دوده روی زمین باقی نمی‌گذارد. وقتی نوکِ پای کسی خواب‌آلوده گرم می‌شود، سهمِ من از این روز بی‌صدا به پایان می‌رسد."},"ICON-2643":{"nm":"حلقه‌ی پارچه‌ی جاذبِ رطوبت","de":"تا پارچه‌ای که قطره‌های آب پنجره‌ی سپیده‌دم را پاک کرده جایی برای رفتن گم نکند، حلقه‌ای بر دیوار آویخته و منتظر می‌ماند. بیش از آنکه خیس شود، منتظرِ خشک‌شدنی دوباره برای فردا صبح ماندن، جوهرِ راستینِ جذب‌کردن است."},"ICON-2644":{"nm":"آویز خشک‌کنِ دستکش زمستانی","de":"دستکشی که پس از یک دور جنگ برفی، کنار شوفاژ انگشتانش را کاملاً باز می‌کند. منظره‌ی آویزان‌بودن از جالباسی و بخاری که آرام برمی‌خیزد. این آرام‌ترین رخت‌آویزیِ زمستان است که در پایان بعدازظهری با نوکِ بینیِ سرخ از راه می‌رسد."},"ICON-2645":{"nm":"پرِ یدکیِ گردگیر","de":"وقتی پرها فرسوده می‌شوند، با پرِ تازه تعویض می‌شوند. لحظه‌ای که نوکِ گردگیر دوباره کرکی و نرم می‌شود. این پرِ کوچکِ یدکی، آرام روی کف دست به تو می‌گوید که ابزارِ نظافت هم فصل تغییر خودش را دارد."},"ICON-2646":{"nm":"دسته‌ی چلانَنده‌ی دستمالِ نظافت","de":"دسته‌ای که برای صرفه‌جویی در نیرویِ مچ دست نصب شده. یک پیچش کافی‌ست تا دستمال خودش آب را بیرون بریزد. خداحافظ روزهایی که جلوی تخته‌ی رخت‌شویی زحمت می‌کشیدیم. در خانه‌داری، یک مشت ترفند همان مهربانی‌ست."},"ICON-2647":{"nm":"سرِ یدکیِ برسِ زمین‌شو","de":"وقتی برسِ زمین‌شو فرسوده می‌شود، فقط سرش را تعویض می‌کنند. دسته همان است، وزنِ آشنا در دست هم همان. در چیزهایی که مدت‌ها استفاده می‌شوند، مهربانیِ کوچک و محکمی زندگی می‌کند که نمی‌خواهد کلِ آن دور انداخته شود."},"ICON-2648":{"nm":"مغزیِ یدکیِ غلتکِ پرزگیر","de":"پس از کندنِ آخرین ورقِ غلتک، دلت به‌طرزی عجیب خالی می‌شود. آن‌وقت است که مغزیِ تازه‌ای جا می‌گذاری. این قولِ سرسختانه و مهربانِ یدکی‌ست که حتی یک پرزِ چسبیده به ژاکت را هم تا آخر رها نمی‌کند."},"ICON-2649":{"nm":"کاردکِ گردگیریِ گوشه","de":"حتی در گوشه‌ای که جارو به آن نمی‌رسد، گردوغبار بی‌صدا لانه می‌کند. نوکِ باریکی که با دقت گوشه را پاک می‌کند. دلی که حتی نادیدنی‌ها را هم می‌رساند، همان غرورِ راستینِ خانه‌داری‌ست."},"ICON-2650":{"nm":"شانه‌ی تمیزکننده‌ی جارو","de":"حتی جاروی جارو‌کننده هم به دستی نیازمند است که به آن استراحت بدهد. اگر موهای درهم‌گره‌خورده میان تارها را با این شانه شانه کنی، جارو پس از دورِ کاری، سرانجام برای جارویِ بعدی آماده می‌شود."},"ICON-2651":{"nm":"پدِ واکسِ رگه‌ی چوبِ کف","de":"اگر در امتدادِ رگه‌های چوب یک لایه واکس بکشی، چوب به‌آرامی جلاییِ فراموش‌شده‌اش را به یاد می‌آورد. بعدازظهری که کف پا میان لغزیدن و نلغزیدن است، و خانه با براقی، خوشحال لبخند می‌زند."},"ICON-2652":{"nm":"جاروبِ گردگیریِ شکافِ در","de":"من دنبال گردوغباری هستم که در شکافِ در زندگی می‌کند. هر بار در باز و بسته می‌شود، آنچه آرام روی هم انباشته می‌شود را با بدنِ نازکم جمع می‌کنم. هرچه شکاف باریک‌تر و عمیق‌تر باشد، نوبتِ من بی‌شک زودتر می‌رسد."},"ICON-2653":{"nm":"کلاهکِ توریِ زیرپاییِ ورودی","de":"تا گردوغباری که زیرپاییِ ورودی بلعیده دوباره به بیرون درز نکند، کلاهکی توری به‌عنوان آخرین دروازه‌بان می‌ایستد. گردوغباری که کفشِ خاکی از دنیای بیرون آورده، همین‌جا و نه فراتر، اجازه‌ی ورود می‌یابد."},"ICON-2654":{"nm":"برسِ رسوب‌زدای شیرآب","de":"رسوبی که آرام روی گردنِ شیرآب نشسته را برسِ کوچک با چرخش می‌تراشد و می‌زداید. هرجا دست‌ها هر روز بیشتر لمسش می‌کنند، باید بیشتر بدرخشد. این همان آدابِ حمامیست که این برسِ کوچک پاسداری می‌کند."},"ICON-2655":{"nm":"کلاهکِ توریِ موگیرِ چاهک","de":"مویی را که به‌سمتِ چاهکِ فاضلاب می‌رفت، آرام می‌گیرم. جلوگیری از فاجعه‌ی کوچکِ گرفتگی، تنها با یک کلاهک. روزِ این قهرمانِ کوچکِ گرد و محکم، همیشه بی‌صدا زیر پا جاری‌ست."},"ICON-2656":{"nm":"کاردکِ درزگیریِ کاشی","de":"بندکشیِ سیاه‌شده میانِ کاشی‌های سفید، آن سال‌های کهنه را با نوکِ ابزار به‌آرامی می‌تراشی. وقتی شکاف‌های باریک تمیز شوند، تمامِ حمام مثل چیزی نو، سبک نفس تازه می‌کند."},"ICON-2657":{"nm":"سنجاق تمیزکنِ دوشِ حمام","de":"اگر سوراخِ مسدودِ دوش را با نوکِ سنجاق باز کنی، آبی که مدت‌ها فقط چکه می‌کرد، دوباره خنک سرازیر می‌شود. صدای دلپذیرِ آبِ صبح، وقتی یک انسدادِ کوچک باز می‌شود."},"ICON-2658":{"nm":"لیوانِ نگه‌داریِ برسِ توالت","de":"برسِ توالت هم تنها وقتی در جایی خشک استراحت کند، واقعاً بهداشتی می‌شود. مرتب در لیوانِ کوچکی که رطوبت را می‌گیرد جا می‌گیرد و منتظرِ نوبتِ بعدی می‌ماند. کرامتِ یک ابزار نه در کاربرد، که در نگهداریِ آن نمایان می‌شود."},"ICON-2659":{"nm":"اسفنجِ پاک‌کنِ کپک","de":"کپکِ سیاهی که در گوشه‌ی کاشی پخش شده، آن مهمانِ سمج را اسفنج مؤدبانه به رفتن دعوت می‌کند. پس از یک‌بار پاک‌شدن، حمام دوباره با سفیدیِ اصلیِ خود روشن می‌شود."},"ICON-2660":{"nm":"تیغه‌ی پاک‌کنِ بخارِ آینه","de":"جلوی آینه‌ای که پس از دوش کدر شده، تیغه یک خط می‌کشد و چهره‌ی واضحِ من بازمی‌گردد. لحظه‌ای که دوباره با حالتِ امروزم روبه‌رو می‌شوم، همانی که مدتی پشتِ بخار پنهان مانده بود."},"ICON-2661":{"nm":"آویزِ دمپاییِ حمام","de":"اگر دمپاییِ خیس را وارونه آویزان کنی، آب می‌چکد و درونش نرم خشک می‌شود، تا پای نفرِ بعدی سرد نباشد. توجهِ این آویزِ کوچک همیشه یک قدم جلوتر، به استقبال می‌آید."},"ICON-2662":{"nm":"جعبه‌ی برسِ ناخن","de":"برسِ کوچکی که کثیفیِ زیرِ ناخن را می‌روبد، خانه‌ی خودش را دارد. راحت درونِ جعبه جا می‌گیرد، بدون رطوبت خشک می‌شود، و منتظرِ روشویی بعدی می‌ماند. پاکیزگی همیشه به‌آرامی از مرتب‌کردن آغاز می‌شود."},"ICON-2663":{"nm":"درِ لیوانِ ضدعفونیِ مسواک","de":"مسواکی که روزی دو بار با دهان روبه‌رو می‌شود هم به پناهگاهی کوچک نیاز دارد. لحظه‌ای که درِ لیوانِ ضدعفونی بسته می‌شود، یک قلمرو از پاکیزگی در برابرِ رطوبتِ سرگردانِ حمام آرام محافظت می‌شود."},"ICON-2664":{"nm":"کپسولِ سفریِ گوش‌پاک‌کن","de":"تا گوش‌پاک‌کن‌های داخلِ چمدان نشکنند یا پخش نشوند، کپسولی گرم آن‌ها را در آغوش می‌گیرد. هرچه چیزی کوچک‌تر باشد، باید زودتر برایش آماده شد، تا در جاده‌ای ناآشنا غافلگیر نشوی."},"ICON-2665":{"nm":"تختهٔ کوچکِ بررسیِ بخارِ نفس","de":"روی کف دست‌ات «هو» فوت می‌کنی و آرام به تخته‌ی کوچک نزدیکش می‌کنی؛ نفس‌ات لمسش می‌کند و کدر و شیری می‌شود. این تخته‌ی کوچک، بی‌آنکه چیزی بگوید، دوست‌داشتنی‌ترین گواهِ زنده‌بودنِ من در روزی سرد را ثبت می‌کند."},"ICON-2666":{"nm":"خانه‌ی نگه‌داریِ گوش‌پاک‌کنِ چوبی","de":"وقتی گوش‌پاک‌کن همراهِ کیف بیرون می‌رود، نوکش به‌راحتی کند می‌شود. برای همین خانه‌ای کوچک برایش فراهم شده. درونِ آن، جایی که نوکش حتی هنگام حمل هم آسیب نمی‌بیند، ابزارِ ظریف با آرامش به خواب می‌رود."},"ICON-2667":{"nm":"گیره‌ی تاکردنِ دستمالِ جیبی","de":"گیره به‌آرامی دستمالی را که چهار گوشه‌اش مرتب تا شده گاز می‌گیرد و از به‌هم‌ریختنش در کیف جلوگیری می‌کند. یک تکه دستمالِ منظم تاشده، هر زمان بیرون بیاید، وقاری آرام هدیه می‌دهد."},"ICON-2668":{"nm":"جعبه‌ی چسب‌زخم","de":"روزی که زانویت زخم می‌شود، جعبه را باز می‌کنی و انواعِ چسب‌زخم صف‌کشیده منتظرت هستند. مهربانی‌ای که بلد است حتی برای زخمِ کوچک هم شلوغش کند. جعبه‌ی کمک‌های اولیه همیشه باید در دسترسِ دست باشد."},"ICON-2669":{"nm":"پاک‌کنِ اثرِ انگشتِ کف‌دستی","de":"اگر اثرِ انگشتِ روی شیشه را پاک کنی، ردِ دستِ مردد ناپدید می‌شود. جادویی کوچک به‌اندازه‌ی کفِ دست، که در آن دنیای پشتِ پنجره، تارشده در هر نقطه‌ی لمس‌شده، دوباره شفاف می‌شود."},"ICON-2670":{"nm":"جداکننده‌ی بازیافتِ زباله","de":"کاغذ این سو، قوطی آن سو. یک جداکننده، سرنوشتی را که نزدیک بود درهم بیامیزد، از هم جدا می‌کند. بازیافت در نهایت همان دلِ تقسیم‌کردنِ صبورانه است، و این خانه‌ی محکم، نخستین خط را واضح می‌کشد."},"ICON-2671":{"nm":"بیلچه‌ی جداکنِ برچسب","de":"حتی برچسبی که سرسختانه چسبیده، جلوی من به‌آرامی تسلیم می‌شود. اگر لبه‌ی تیغِ صافش را کمی زیرِ گوشه فرو کنی، بدونِ هیچ ردی، خداحافظیِ دلپذیری رخ می‌دهد."},"ICON-2672":{"nm":"دندانه‌ی بُرشِ نوارِ ماسکینگ","de":"برای استفاده از نوار ماسکینگ لازم نیست دنبال قیچی بگردی. کافی‌ست روی دندانه بگذاری و بکشی تا دقیقاً در امتدادِ رگه‌اش پاره شود. رفیقِ کوچک و چابکی که نوکِ انگشتانِ دفترچه‌آرا بیشترین علاقه را به آن دارد."},"ICON-2673":{"nm":"قابِ فلزیِ چسبانِ گوشه","de":"قطعه‌ی فلزیِ کوچکی که گوشه‌ی برآمده را از درون محکم می‌گیرد. در جایی نادیدنی، بی‌صدا زاویه را حفظ می‌کند. پشتِ چیزهایی که ظاهرشان راست و صاف است، معمولاً چنین تکیه‌گاهِ پنهانی وجود دارد."},"ICON-2674":{"nm":"لوله‌ی محافظِ ورقه‌های استیکر","de":"تا برگه‌های استیکرِ ارزشمند چروک یا نمناک نشوند، در کنارِ فیلمِ محافظ درون لوله به خواب می‌روند. کنارِ لذتِ گردآوری، همیشه تلاشی همراه است که می‌خواهد آن را با ظرافت نگه دارد."},"ICON-2675":{"nm":"برسِ تمیزکنِ مهرِ جوهری","de":"برس در امتدادِ شیارهای مهری که غرقِ جوهر شده، آرام می‌کشد و رنگِ کهنه را می‌زداید. دستی کوچک و پرتلاش که از پیش تمیز می‌کند تا نقشِ بعدی واضح چاپ شود."},"ICON-2676":{"nm":"بالِ نگه‌دارنده‌ی برگه‌های شفاف","de":"تا برگه‌های شفافِ زونکن نلغزند، بال‌ها هر دو طرف را محکم می‌گیرند. به‌لطفِ اینکه هر برگه در جای خودش می‌ماند، نوکِ انگشتی که ورق می‌زند هرگز به‌هم نمی‌ریزد."},"ICON-2677":{"nm":"بیلچه‌ی نگه‌داریِ تکه‌های تزئینی","de":"تکه‌های ریزِ تزئینیِ پراکنده را با بیلچه‌ای کوچک یک‌ضرب جمع می‌کنی. وقتی زحمتِ برداشتنِ یکی‌یکی با انگشت از میان می‌رود، وقتِ ساختنِ صبورانه‌ی چیزی به‌مراتب لذت‌بخش‌تر می‌شود."},"ICON-2678":{"nm":"بندِ محکم‌کنِ منگوله‌ی نشانگرِ کتاب","de":"تا منگوله‌ی انتهای نشانگرِ کتاب شل نشود، بند محکم آن را می‌بندد. حتی راهنمایی که تو را به صفحه‌ی نیمه‌خوانده بازمی‌گرداند، تنها وقتی ظاهرش منظم باشد، خیالت را راحت می‌کند."},"ICON-2679":{"nm":"گیره‌ی درِ قلمِ تزئینی","de":"گیره‌ای که در قلمِ تزئینی را محکم می‌گیرد تا نوکش خشک نشود. از دردسرِ سفت‌شدنِ قلمی که فراموش شده باز بماند جلوگیری می‌کند، پس رنگ همیشه مثل بارِ اول، مرطوب جاری می‌شود."},"ICON-2680":{"nm":"نوکِ یدکیِ پیچ‌گوشتی","de":"دسته‌ی پیچ‌گوشتی همان می‌ماند، فقط نوکِ سرش تعویض می‌شود؛ چهارسو یا تخت، بی‌درنگ. هوشی که با یک ابزار از پسِ کارهای مختلف برمی‌آید، محکم در همین نوکِ کوچک جای گرفته است."},"ICON-2681":{"nm":"پیچِ کاغذسنباده‌ی گوشه‌گیر","de":"اگر سطحِ زبر را دور دست بپیچی، کفِ دست خودش به ابزار بدل می‌شود. با هر بار سایش در امتدادِ رگه، گوشه‌ی خشن گِرد می‌شود، و صافیِ نهایی را همیشه نوکِ انگشتانِ انسان تشخیص می‌دهد."},"ICON-2682":{"nm":"قیفِ دسته‌بندیِ پیچ","de":"پیچ‌های پراکنده از گلوگاهِ باریک عبور می‌کنند و غلتان در یک نقطه گرد می‌آیند. صدای چیزهای کوچکی که روی میز می‌غلتیدند و حالا جای خود را می‌یابند، حتی دلِ آشفته را هم منظم می‌کند."},"ICON-2683":{"nm":"قلابِ انتهای متر","de":"قلابِ نوکِ متر، دستِ دومِ کسی‌ست که تنها کار می‌کند. اگر آن را به لبه‌ای بند کنی، متر دیگر نمی‌لرزد، و به‌اندازه‌ی طولی که اندازه‌گیری شده، دست و دل هم صادق‌تر می‌شوند."},"ICON-2684":{"nm":"روکشِ دسته‌ی آچار","de":"لایه‌ای که روی دسته‌ی سردِ فلزی کشیده می‌شود. لحظه‌ای که دست می‌گیری‌اش، به‌جای سردی، گرمایی نرم لمس می‌شود. ابزار وقتی ابتدا به فکرِ دستی‌ست که آن را می‌گیرد، مدتی طولانی‌تر کنارت می‌ماند."},"ICON-2685":{"nm":"کلاهکِ محافظِ نوکِ درفش","de":"روی هر نوکِ تیز، کلاهکی کوچک کشیده می‌شود. آسودگیِ دستی که در کشو می‌گردد بی‌آنکه فرو رود؛ هرچه چیزی تیزتر باشد، اگر با دقت پوشانده شود، کسی آسیب نمی‌بیند."},"ICON-2686":{"nm":"تیغه‌ی روکش‌کنِ سیمِ برق","de":"تنها روکشِ نازک را می‌کَنَد، بی‌آنکه سیمِ درونی آسیب ببیند. لحظه‌ای که یک لایه آرام باز می‌شود و رشته‌ی مسی می‌درخشد، تیغه‌ی خوب دقیقاً می‌داند کجا باید متوقف شود."},"ICON-2687":{"nm":"پاک‌کنِ پنجره‌ی حبابِ تراز","de":"تنها وقتی یک حباب درست وسط بایستد، واقعاً تراز است. تمیزکردنِ پنجره‌ی کوچک شبیهِ همان آماده‌سازیِ آرامی‌ست که پیش از کشیدنِ خط، نفس را یکنواخت می‌کند."},"ICON-2688":{"nm":"غلافِ محافظِ انگشتِ میخ‌کوبی","de":"غلافِ کوچکی که انگشتِ نگه‌دارِ میخ را کاملاً می‌پوشاند. می‌گوید بدونِ ترس بکوب، حتی اگر چکش کج بخورد اشکالی ندارد؛ محکم آماده است تا به‌جایِ انگشت ضربه را بپذیرد."},"ICON-2689":{"nm":"زیرانداز ضدلغزشِ کاسه‌ی غذا","de":"لایه‌ای از لاستیک که کاسه‌ی غذا را از سُرخوردن روی زمین نگه می‌دارد. بی‌آنکه کاسه هنگامِ خوردنِ پرشور فرار کند، آرامشِ یک وعده از جایی آغاز می‌شود که تکان نمی‌خورد."},"ICON-2690":{"nm":"آویزِ پیمانه‌ی غذای دام","de":"پیمانه‌ای که غذا با آن ریخته می‌شود، روی دیوار آویزان می‌شود تا سبک خشک شود. نظمی کوچک که در هر وعده از همان نقطه به استقبالِ دست می‌آید؛ داشتنِ دهانی که باید مراقبش باشی، همین‌قدر مهربان است."},"ICON-2691":{"nm":"بشقابِ سرریزِ کاسه‌ی آب","de":"جرعه‌ای را که از لبه‌ی کاسه‌ی آب پاشیده و سرریز شده، آرام دریافت می‌کند. به‌لطفِ بشقابِ پهنی که از پیش در آغوش می‌گیرد تا زمین خیس نشود، زیر پا همیشه خشک و آسوده می‌ماند."},"ICON-2692":{"nm":"انبرِ توزیعِ تنقلات","de":"انبری که دقیقاً یک تکه تنقلات را برمی‌دارد و می‌دهد. حتی روبه‌روی دهانِ کوچکی که با فشردنِ پوزه منتظر است، در بخشیدن، نوکِ انگشتانی مهربان و بی‌آشفتگی وجود دارد."},"ICON-2693":{"nm":"گیره‌ی پیچ‌کنِ دهانه‌ی کیسه‌ی غذا","de":"گیره‌ی کوچکی که دهانه‌ی کیسه‌ی بازشده‌ی غذا را می‌پیچاند و می‌گیرد. با یک بستنِ ساده، رطوبت مسدود می‌شود، و مشتی از تازگیِ ترد برای فردا صبح دست‌نخورده محفوظ می‌ماند."},"ICON-2694":{"nm":"درپوشِ نوکِ آب‌خوریِ دام","de":"درپوشی که دقیقاً با نوکِ آب‌خوری جفت می‌شود. قطره‌ی چکه‌کننده می‌ایستد و اطرافش خشک می‌شود. آنچه خوب مسدود شده نشت نمی‌کند و مدتی طولانی، زلال باقی می‌ماند."},"ICON-2695":{"nm":"لیوانِ مدرّج اندازه‌گیریِ غذا","de":"دقیقاً یک لیوان بر اساسِ خط‌کش برمی‌داری، نه زیاد و نه کم. در دستی که وعده‌ی امروز را عادلانه می‌سنجد، روزِ عضوِ کوچکِ خانواده به‌اندازه‌ی درست جای می‌گیرد."},"ICON-2696":{"nm":"لبه‌ی زیراندازِ غذایِ ریخته‌شده","de":"لبه‌ای که مانع می‌شود غذای ریخته از حاشیه‌ی زیرانداز بیرون بزند. یک لبه‌ی کمی برجسته، خرده‌های در حالِ پراکنده‌شدن را محکم گرد می‌آورد."},"ICON-2697":{"nm":"حلقه‌ی جداکنِ کاسه‌های تودرتو","de":"حلقه‌ی کوچکی که دو کاسه‌ی روی هم را آرام از هم جدا می‌کند. دستی که با گیرافتادگیِ محکم دست‌وپنجه نرم می‌کرد، سبک می‌شود. اگر خوب دقت کنی، جداکردنِ درست هم نوعی مراقبتِ مهربانانه‌ست."},"ICON-2698":{"nm":"قیفِ جمع‌آوریِ توپِ حیاط","de":"قیفی که توپ‌های غلتیده در حیاط را در یک‌جا گرد می‌آورد. در غروبی پس از یک دورِ بازیِ پرشور، دستی که چیزهای پراکنده در اینجا و آنجا را جمع می‌کند، خودبه‌خود به یاد می‌آید."},"ICON-2699":{"nm":"کلاهکِ میخِ حصار","de":"روی هر میخِ حصار، کلاهکی گِرد کشیده می‌شود. تا نوکِ آن زیرِ باد و باران ترک نخورد، دلی که حتی کوچک‌ترین چیز را می‌پوشاند و مراقبتش می‌کند، سراسرِ حیاط را فرا گرفته است."},"ICON-2700":{"nm":"قلابِ تاکردنِ تونلِ بازی","de":"قلابی که تونلِ بازیِ حسابی بازی‌شده را مرتب تا می‌کند و آویزان می‌کند. اگر روزی خاک‌آلود را خوب جمع کرده و آویزان کنی، بازیِ خوب‌مرتب‌شده بی‌تردید فردا را وعده می‌دهد."},"ICON-2701":{"nm":"کوسن دستگیره طناب کششی","de":"کوسنی که نرم و لطیف دور دستگیره‌ی طناب کششی را می‌پیچد. هر چقدر هم محکم بکشی، کف دستت هرگز زخم نمی‌شود. اینکه هرچه بیشتر بگیری دستت راحت‌تر می‌ماند، مدیون مهربانی کوچک کسی است."},"ICON-2702":{"nm":"قلاب پارچه‌ی سایه‌بان حیاط","de":"قلابی که پارچه‌ی سایه‌بان کشیده‌شده در حیاط را محکم نگه می‌دارد. حتی خنکای نیمروز هم باید نگه‌داشته شود تا بماند. زیر سایه‌ای که قلاب کشیده نگهش داشته، بعدازظهری کِش‌آمده به آرامی استراحت می‌کند."},"ICON-2703":{"nm":"روکش تیغه‌ی بیل خاک‌کنی","de":"روکشی که به آرامی روی تیغه‌ی بیل خاک‌کنی کشیده می‌شود. اگر بگذاری بعد از یک روز کار سخت استراحت کند، کند نمی‌شود و آماده می‌ماند تا دوباره خاکِ بهار بعدی را ملاقات کند."},"ICON-2704":{"nm":"سطح شیب‌دار غلتاندن توپ","de":"یک سطح شیب‌دار که توپ روی آن غلت‌غلتان پایین می‌آید. توپ با شادی در طول شیب ملایم می‌دود. یک شیب کوچک، شادیِ تمام یک روز را می‌سازد."},"ICON-2705":{"nm":"حلقه‌ی چفت درِ نرده","de":"حلقه‌ی چفتی که درِ نرده را قفل می‌کند. با صدای کوچکِ «تیک»ِ بسته‌شدنش، دل آرام می‌گیرد. یک درِ محکم بسته، یک حیاط کوچک را به دنیایی کامل برای خودش تبدیل می‌کند."},"ICON-2706":{"nm":"بند زنگوله‌ی بازی","de":"اگر بند زنگوله‌دار را آرام تکان دهی، صدایی زلال پخش می‌شود. جلینگ، جلینگ—اتاقی که تا کنون ساکت بود بیدار می‌شود، و با یک زنگِ کوچک، تمام دل گوش‌به‌زنگ می‌شود."},"ICON-2707":{"nm":"زیرگلدانی آب‌گیر","de":"بشقابی که آرام آبی را که از زیر گلدان نشت می‌کند، می‌گیرد. سرریز آب را نگه می‌دارد تا لبه‌ی پنجره خیس نشود. حتی محبت هم وقتی سرریز شود، به جایی برای نگه‌داشتن نیاز دارد."},"ICON-2708":{"nm":"بیل کوچک نشاءکاری","de":"بیلچه‌ای کوچک برای جابه‌جا کردن نهال‌های لطیف به خاک و جای‌دادن نرم آن‌ها. زیر نوک انگشتانی که هر جوانه را با احتیاط جا می‌اندازند، حتی در باغچه‌ای به اندازه‌ی کف دست، بهاری سبز سر بلند می‌کند."},"ICON-2709":{"nm":"سنجاق نشانه‌گذاری جوی باغچه","de":"سنجاقی نشانه‌دار که روی آن می‌نویسی در هر جو چه کاشته‌ای و در خاک فرو می‌بری. روی خاکی که هنوز جوانه‌ای نزده، یک برچسب کوچک آرام به یاد می‌سپارد چه چیزی قرار است برویَد."},"ICON-2710":{"nm":"توری نوکِ آبپاش","de":"توری ظریفی که روی نوکِ آبپاش نصب می‌شود. آبی که زمانی یک‌جا و یک‌ریز می‌ریخت، حالا مثل نم‌نمِ باران به رشته‌های بسیار پخش می‌شود. تنها جریان نرم آب است که برگ‌های لطیف را آسیب نمی‌زند."},"ICON-2711":{"nm":"گیره‌ی محکم‌کننده‌ی تکیه‌گاه","de":"گیره‌ای که ساقه‌ی لرزان را آرام به تکیه‌گاهش می‌بندد. تکیه‌ای قرضی و موقت تا وقتی که چیز هنوز لطیف بتواند صاف بایستد—رشد کردن به چنین تکیه‌گاهی نیاز دارد."},"ICON-2712":{"nm":"گیره‌ی درزبندی پاکت بذر","de":"گیره‌ای که پاکت بذر باقی‌مانده را محکم می‌بندد. اگر درست ببندیش، حتی یک دانه هم بیرون نمی‌رود. وعده‌ای کوچک برای بهار آینده، در همین یک بار بستن نهفته است."},"ICON-2713":{"nm":"پیمانه‌ی اندازه‌گیری خاک و کود","de":"پیمانه‌ای کوچک برای برداشتن مقدار درست خاک و کود. نه زیاد، نه کم—یک قاشقِ دقیق. تنها روی مقدار درست‌اندازه‌گیری‌شده است که خاک سرانجام کار خودش را انجام می‌دهد."},"ICON-2714":{"nm":"قلاب آویز گلدان","de":"قلاب آویزی که گلدان را سبکبال در هوا معلق می‌کند. سبزی‌ای که بالا برده شده، یک وجب به آفتاب و نسیم نزدیک‌تر می‌شود. باغچه‌ای کوچک کنار پنجره به آرامی معلق می‌ماند."},"ICON-2715":{"nm":"توری محافظ جوانه","de":"توری محافظی که آرام روی جوانه‌های تازه‌سر‌زده را می‌پوشاند. تا وقتی برگ‌های هنوز لطیف بتوانند سرمای اول و آفتاب سوزان را تاب بیاورند، لطیف‌ترین چیز اول از همه مراقبت می‌شود."},"ICON-2716":{"nm":"جاشانه‌ی نظافت","de":"جایی که موهای ریخته را با تق‌تق از شانه می‌تکانی و مرتب آویزانش می‌کنی. شانه‌ی نرم و خالی‌شده منتظر لمس بعدی می‌ماند. مرتب بودن همیشه از عادت کوچکِ مراقبت از ابزار شروع می‌شود."},"ICON-2717":{"nm":"حلقه‌ی ضدلغزش تشت شست‌وشوی پا","de":"حلقه‌ای که تشت شست‌وشوی پا را نگه می‌دارد تا نلغزد. زیر پاهای کوچکی که آب‌بازی می‌کنند تشت تکان نمی‌خورد، پس نه دستِ شست‌وشو‌دهنده و نه دلِ شسته‌شده هیچ‌کدام نمی‌لرزند."},"ICON-2718":{"nm":"قلاب دیواری بند قدم‌زدن","de":"قلابی برای آویزان‌کردن بندِ قدم‌زدن کنار در ورودی. از جای خودش کنار در، آمادگی برای بیرون‌رفتن همیشه منتظر می‌ماند. لحظه‌ای که بند پایین می‌آید، قدمی هیجان‌زده هم همراهش راه می‌افتد."},"ICON-2719":{"nm":"کلاهک محافظ ناخن‌گیری","de":"کلاهک محافظی که هنگام کوتاه‌کردن ناخن، بافت لطیف را حفظ می‌کند. تنها با مرزی امن که می‌گوید «دقیقاً تا همین‌جا»، دستِ در برگرفته‌ی قیچی هم می‌تواند بی‌لرزش و آرام بماند."},"ICON-2720":{"nm":"نوار دماسنج آب حمام","de":"نواری که روی آب حمام شناور می‌شود و دمای آن را می‌گوید. دلی که زمانی با فرو بردن پشت دست، گرمای مناسب را می‌سنجید، حالا شناور آنجاست، به روشنی در یک نوار رنگی ترجمه شده."},"ICON-2721":{"nm":"غلتک چسبی موگیر","de":"یک تار موی سفید روی لباس مشکی، درست پیش از رفتن روی صحنه از همیشه بزرگ‌تر به نظر می‌رسد. با صدای غلت‌غلت، خرده‌های یک روز کامل یکی‌یکی روی کاغذ چسبناک می‌نشینند. مرتب بودن این‌گونه، ورق به ورق، به اندازه‌ی همان چیزی که کنده می‌شود کامل می‌شود."},"ICON-2722":{"nm":"انبرک کیسه‌ی زباله‌ی قدم‌زدن","de":"انتهای مسیرِ قدم‌زدن، لحظه‌ای مهربان برای خم‌شدن هست. کیسه را در نوک انبرک نگه‌داری کن تا دست‌ها پاک بماند و دل سبک. در قدم‌زدن با هم، ادب کوچکِ مراقبت از پشتِ سر هم هست—و این انبرک این را زودتر از هر چیز می‌داند."},"ICON-2723":{"nm":"لبه‌ی پادری در ورودی","de":"لبه‌ی پادریِ جلوی در، اولین خوش‌آمدگویی است که پا با آن روبه‌رو می‌شود. اگر انگشتان خیس اینجا یک لحظه بایستند، کف داخل خشک می‌ماند. پایین‌ترین جای دنیا، بی‌کلام همه‌ی واردشوندگان را پاک می‌کند و خوش‌آمد می‌گوید."},"ICON-2724":{"nm":"بند گره‌ای زنگوله‌ی آرایش","de":"حتی بستنِ یک زنگوله هم ترتیب خودش را دارد. بند را دو بار بپیچان و یک بار از آن بگذران، صدایی زلال با هر قدم غلت‌غلت‌کنان همراه می‌شود. آراستگی، در نهایت، دلی است که این لمسِ پایانیِ کوچک را هرگز فراموش نمی‌کند."},"ICON-2725":{"nm":"کیسه‌ی آب‌گیر چتر تاشو","de":"در سرسرایی که باران تازه بند آمده، از نوکِ چتر تاشده قطره‌ها نقطه‌نقطه روی زمین پخش می‌شوند. یک کیسه آرام آن‌ها را می‌گیرد و زیر پای کسی دیگر لیز نمی‌خورد. مهربانی معمولاً این‌طور، بی‌صدا، کنارت می‌ماند."},"ICON-2726":{"nm":"گیره‌ی بندِ کیف","de":"کیفی که به صندلی آویزان شده، پیوسته آرام‌آرام سُر می‌خورد و پایین می‌افتد. یک بار با گیره‌ی بند محکمش کن، دو دست بی‌نگرانیِ افتادنش سبک می‌شوند. آسودگیِ بیرون‌رفتن از جایی شروع می‌شود که بتوانی بار را برای لحظه‌ای فراموش کنی."},"ICON-2727":{"nm":"کیسه‌ی پارچه‌ای گرم‌کن دست","de":"در کوچه‌ای که باد سرد می‌وزد، یک کیسه‌ی پارچه‌ای در جیب، به آرامی گرما را به کف دست منتقل می‌کند. لایه‌ای نرم که چیز داغ را می‌پیچد و به‌اندازه گرمش می‌کند. مهربانیِ زمستان همیشه از میان یک تکه پارچه می‌رسد."},"ICON-2728":{"nm":"پایه‌ی آینه‌ی تاشو","de":"باز که می‌کنی، آینه‌ای کوچک زاویه‌ی خودش را کج می‌گیرد. بی‌آنکه با دست نگهش داری، پایه به‌جای تو می‌ایستد تا بتوانی خودت را ببینی. حتی در آن فرصت کوتاهِ مرتب‌کردن ظاهر، یک همراهِ کوچکِ قابل‌اعتماد کنارت هست."},"ICON-2729":{"nm":"درپوش دستمال‌مرطوب سفری","de":"اولین برگ دستمال‌مرطوب همیشه در حال خشک‌شدن بود. درپوش را با یک تیک ببند و رطوبت تا آخرین برگ می‌ماند. حفظ‌کردن چیزی تا آخرین استفاده—راز خانه‌داری پایدار در چنین چیزهای کوچکی پنهان است."},"ICON-2730":{"nm":"جداکننده‌ی سکه‌ی کیف‌پول","de":"وقتی سکه‌ها میان اسکناس‌ها پخش می‌شوند، صف صندوق همیشه شلوغ می‌شود. یک جداکننده چیزهای گرد را در یک طرف جمع می‌کند و دیگر انگشت‌ها سردرگم نمی‌مانند. مرتب‌سازی یعنی به هر چیز جا و نامی دادن."},"ICON-2731":{"nm":"کیس تاشوی ماسک سفری","de":"تا زده که می‌شود، ماسک حتی داخل کیف هم چروک نمی‌خورد. کیسی که یک برگ برداشته‌شده را تمیز در خودش نگه می‌دارد. یک عادت مهربان از نگه‌داری منظم برای دفعه‌ی بعد، همین‌جا جمع شده."},"ICON-2732":{"nm":"روکش دندانه‌ی شانه‌ی سفری","de":"دندانه‌های شانه در کیف اغلب چیزهای دیگر را می‌خراشیدند. روکش دندانه را بپوشان و هم شانه ایمن می‌ماند هم چیزهای همراهش سالم. هرکس که مراقب وسایلش بوده می‌داند یک لایه‌ی محافظِ کوچک، هر دو طرف را نگه می‌دارد."},"ICON-2733":{"nm":"گیره‌ی تقسیم‌کننده‌ی کشو","de":"هر بار که کشو باز می‌شد، وسایل به‌هم‌ریخته مثل یک آه بیرون می‌ریختند. با یک گیره کشو را به بخش‌هایی تقسیم کن، چیزهای کوچک بالاخره ناحیه‌ی خودشان را پیدا می‌کنند. کشوی مرتب، بی‌صدا حال‌وهوای هر صبح را تغییر می‌دهد."},"ICON-2734":{"nm":"پایه‌ی نمایش سکه","de":"یک سکه‌ی قدیمی را سرپا نگه‌دار، خودش به‌تنهایی نمایشگاهی کوچک می‌شود. پایه آن را مایل نگه می‌دارد تا نقش رویش را واضح نشان دهد. بالا بردنِ زمانی که دست‌خورده و ساییده شده تا سطح چشم—لذت مجموعه‌داری همین‌جا عمیق می‌شود."},"ICON-2735":{"nm":"حلقه‌ی جمع‌کن سیم هندزفری","de":"صبح‌هایی بوده که نیمی‌شان صرف بازکردن گره سیم هندزفری شده. آن را دور حلقه‌ی جمع‌کن مرتب بپیچان تا دفعه‌ی بعد که بیرونش می‌آوری صاف و روان باشد. یک مرتب‌سازی کوچک، هدیه‌ای آرام است که به «خودِ فردا» می‌دهی."},"ICON-2736":{"nm":"قلاب دیواری سیم شارژر","de":"سیم شارژری که روی زمین رها بود، پیوسته زیر پا می‌رفت. یک قلاب روی دیوار بچسبان و آن را آویزان کن، میز به‌مراتب بازتر می‌شود. مهار کردن بی‌نظمی چیز بزرگی نیست—فقط جایی کوچک به اندازه‌ی یک میخ است."},"ICON-2737":{"nm":"جاریموت ایستاده","de":"کنترلی که همیشه در شکاف مبل گم می‌شد، بالاخره خانه‌ای دارد که به آن برگردد. سرپا در جا‌ریموت بگذارش، دیگر نه دنبالش می‌گردی نه رویش می‌نشینی. داشتن جای مخصوص خود، حتی برای یک وسیله هم آسایشی کوچک است."},"ICON-2738":{"nm":"گیره‌ی آویز دسته‌ی عینک","de":"عینکِ برداشته‌شده همیشه آرام‌آرام به گوشه‌ای سُر می‌خورد. دسته‌اش را آرام روی گیره آویزان کن، عدسی‌ها دیگر به زمین نمی‌خورند. آرزوی بی‌خط‌وخش رساندنِ آن به فردا، در همین آویز کوچک نهفته است."},"ICON-2739":{"nm":"گیره‌ی دسته‌بندی دسته‌کلید","de":"هرچه دسته‌کلید سنگین‌تر شود، تشخیص اینکه کدام کلید برای کدام در است مبهم‌تر می‌شود. آن‌ها را با گیره‌ی دسته‌بندی ببند، تا فقط با نوک انگشت جفتِ خودش را بشناسی. راهنمایی بی‌صدا که هر روز، به درهایی که باز و بسته می‌شوند، آرام نظم می‌دهد."},"ICON-2740":{"nm":"گیره‌ی نگهدارنده‌ی یادداشت","de":"یادداشت‌های نوشته‌شده روی میز اغلب می‌افتادند و رو می‌شدند. وقتی گیره کاغذ را سرپا نگه می‌دارد، حروف مستقیم به چشمانت خیره می‌شوند. راهی برای اینکه خطی که نباید فراموش شود، همیشه در دیدرس زندگی کند."},"ICON-2741":{"nm":"پایه‌ی سرپا نگهدارنده‌ی نوک قلم","de":"چند بار برای برداشتن قلمی که غلتیده و افتاده کمر خم کرده‌ای؟ نوکش را در پایه فرو کن و بایستان، فاصله تا خط بعدی یک وجب کوتاه‌تر می‌شود. ایستگاهی کوچک که همیشه کنار کسی که می‌نویسد بیدار می‌ماند."},"ICON-2742":{"nm":"پایه‌ی برگردان ساعت شنی","de":"ساعت شنی وقتی تمام جاری شد، فقط با برگرداندنِ کسی دوباره زنده می‌شود. پایه آن لحظه‌ی آخرین دانه را می‌گیرد و به‌نرمی آن را واژگون می‌کند. لمسی که زمان را به آغاز برمی‌گرداند، همین‌جا روی تکه‌ای چوب کوچک آرام می‌گیرد."},"ICON-2743":{"nm":"سیب‌زمینی کبابی با کره","de":"کره آرام‌آرام روی سیب‌زمینیِ باپوست‌کبابی‌شده آب می‌شود. وقتی رگه‌ی طلایی همراه بخار نفوذ می‌کند، گوشتِ پفکی درونش با آرامش خوشمزگی را در خود می‌گیرد. همان لحظه‌ای که یک سبزیِ ریشه‌ای خاک‌بو، گرم‌ترین حالت خودش می‌شود."},"ICON-2744":{"nm":"بلال کبابی با کره","de":"دانه‌های زرد ردیف‌شده روی گریل تق‌تق صدا می‌کنند. یک تکه کره روی آن‌ها سُر می‌خورد و بویی شیرین ناگهان بالا می‌آید. شیرینیِ یک مزرعه‌ی تابستانی درست در یک لقمه جا می‌گیرد."},"ICON-2745":{"nm":"وافل","de":"در هر خانه‌ی کوچکِ شبکه‌ای، شربت آرام منتظر جمع‌شدن می‌ماند. بیرون ترد، درون پفکی—یک گاز که بزنی، بخار گرم بیرون می‌زند. خانه‌های چهارگوش‌اش مثل ظرفی‌اند که خوشبختیِ کوچک را سهم‌سهم تقسیم می‌کند."},"ICON-2746":{"nm":"پنکیک","de":"بوی خمیری را که روی ماهیتابه طلایی پف می‌کرد به یاد دارم. روی نان‌های گردِ لایه‌لایه چیده‌شده، کره آرام فرو می‌ریزد و ذوب می‌شود. بشقابی نرم که فقط در صبحی بی‌عجله، آرام اجازه‌ی حضور می‌گیرد."},"ICON-2747":{"nm":"شکلات","de":"یک تکه در دهان بگذاری، آرام‌آرام با گرمای بدن باز می‌شود. شیرینی‌ای که در انتهای تلخی پخش می‌شود، تنشِ دل را آرام رها می‌کند. در روزی خسته‌کننده، تکه‌ای قهوه‌ای از تسلی که از جیب بیرون می‌آید."},"ICON-2748":{"nm":"کیک توت‌فرنگی","de":"توت‌فرنگی‌های سرخ روی خامه‌ی سفید نشسته‌اند و بهار را زودتر از همه خبر می‌دهند. وقتی چنگال برشِ نرم را می‌شکافد، رایحه‌ای ترش آرام شکوفا می‌شود. در روزی که چیزی برای جشن‌گرفتن هست، ستاره‌ی مهربانِ وسط میز."},"ICON-2749":{"nm":"چیزکیک","de":"یک برش سنگین روی زبان به‌غلظت فرو می‌ریزد. طعم شورِ پایانی دستِ شیرینی را می‌گیرد و پیوسته یک لقمه‌ی دیگر می‌طلبد. دسری که دوستدارانِ غلظتِ فشرده، آرام‌آرام و باحوصله می‌خورندش."},"ICON-2750":{"nm":"کوکی موز","de":"رایحه‌ی موزِ له‌شده در فر زرد و رسیده می‌شود. یک گاز بزن و شیرینی نرمی در دهان پخش می‌شود. لحظه‌ی گرمِ تبدیل یک میوه‌ی کاملاً رسیده به کوکی، دوباره."},"ICON-2751":{"nm":"کوکی شکلاتی","de":"دانه‌های شکلات در خمیر، حین پخت، غلیظ و نرم باز می‌شوند. وقتی هنوز گرم است بشکنیش، قهوه‌ای پررنگ به نوک انگشتانت می‌مالد. با یک لیوان شیر، تکه‌ای که بعدازظهر را کمی مهربان‌تر می‌کند."},"ICON-2752":{"nm":"کوکی دانه‌های کاکائو","de":"خرده‌های ریز کاکائو میان خمیر تق‌تق زیر دندان می‌شکنند. تلخیِ عمیق و بی‌شیرینی، ذائقه‌ی بزرگسال را آرام تسکین می‌دهد. کوکی‌ای کمی جدی که رایحه‌ی خام و اصیل پیش از فرآوری را همچنان در خود دارد."},"ICON-2753":{"nm":"تست پنیری","de":"روی نانِ طلایی‌کباب‌شده پنیر مثل نخ کشیده می‌شود و بلند می‌آویزد. تردیِ بیرون و خوشمزگیِ درون در یک لقمه روی هم می‌افتند. ساده‌ترین و مهربان‌ترین غذایی که یک صبحِ دیرهنگام را سیر و پرانرژی می‌کند."},"ICON-2754":{"nm":"ساندویچ","de":"میان دو تکه نان، دلسوزیِ یک روز کامل لایه‌لایه جا می‌گیرد. یک گاز بزن و طعم‌های روی‌هم‌چیده‌شده همه با هم سلام می‌دهند. میزی کوچک روی کف دست، آماده که به هر کجا با خودت ببریش."},"ICON-2755":{"nm":"تست فرانسوی","de":"نانی که کاملاً در تخم‌مرغ خیس شده روی ماهیتابه زرد می‌شود. لبه‌هایی که همراه رایحه‌ی کره پف کرده‌اند، اول از همه ترد می‌شوند. یک خط شربت که رویش بریزی، حتی نانِ ساده هم به تجملِ یک روز تعطیل تبدیل می‌شود."},"ICON-2756":{"nm":"رامیون قارچ","de":"رایحه‌ی عمیق قارچ همراه بخار روی آبگوشتِ درحال‌جوشیدن بالا می‌آید. یک تکه کلاهکِ جویدنی که بیرون بکشی، شیرینیِ خاک‌بو در دهان پخش می‌شود. کاسه‌ای کمی خاص که پیش از رشته، با رایحه شکمت را سیر می‌کند."},"ICON-2757":{"nm":"رامیون سرخ‌شده","de":"روی رشته‌های بی‌آبگوشتِ تفت‌داده‌شده، ادویه‌ی تند مثل جلایی می‌پیچد. با چاپ‌استیک بالا بیاوریش، از میان بخار رایحه‌ی خوشمزه‌ی دودی پخش می‌شود. وقتی دلت یک وعده‌ی سریع و غلیظ بخواهد، مطمئن‌ترین دوست."},"ICON-2758":{"nm":"رامیون پنیری","de":"یک برش پنیر روی رشته‌های داغ بگذار، آرام فرو می‌ریزد و ذوب می‌شود. آبگوشتِ تند با خوشمزگیِ نرم روبه‌رو می‌شود و لبه‌ها گرد می‌شوند. کاسه‌ای که دقیقاً برای شبی که می‌خواهی تیزیِ طعم را کمی آرام کنی مناسب است."},"ICON-2759":{"nm":"رامیون کاری","de":"رایحه‌ی غلیظ کاری دور رشته‌ها می‌پیچد و بخار زرد بالا می‌فرستد. یک هورت که بکشی، تندیِ گرم از درون گرمت می‌کند. رشته‌هایی با تنوعی دلپذیر که به آبگوشتِ آشنا رایحه‌ای کمی نا‌آشنا اضافه می‌کند."},"ICON-2760":{"nm":"رامیون دریایی","de":"روی آبگوشتی پر از بوی دریا، میگو و صدف چاق‌وچله بالا می‌آیند. خوشمزگیِ عمیق و درعین‌حال تازه، میان رشته‌ها نفوذ می‌کند. جادویی کوچک که بی‌آنکه راه دوری بروی، بوی ساحل را در یک کاسه می‌آورد."},"ICON-2761":{"nm":"گیم‌باپ تربچه‌ی ترشی","de":"تربچه‌ی زرد ترشی وسط می‌نشیند و برنج دورش گرد حلقه می‌زند، و یک برگ جلبک همه را با مهربانی در یک رول می‌بندد. در سپیده‌دم روز پیک‌نیک، صادقانه‌ترین وعده‌ای که روی تخته‌ی برش زاده می‌شود."},"ICON-2762":{"nm":"گیم‌باپ تن‌ماهی","de":"لحظه‌ای که یک قاشق تن‌ماهیِ مخلوط‌شده با مایونز میان برنج نفوذ می‌کند، حتی زیر نور نیمه‌شبِ فروشگاه بیست‌وچهارساعته هم یک وعده به‌اندازه‌ی کافی گرم می‌شود. تسلی‌ای که دست‌های شلوغ بیشتر از هرچیز به سراغش می‌روند."},"ICON-2763":{"nm":"سالاد میوه","de":"رنگ‌های جمع‌شده‌ی فصل، برای اولین بار در یک کاسه به هم می‌رسند. اینکه سرخ و سبز و زرد بی‌دعوا کنار هم چطور جور می‌شوند را، میوه فقط بعد از برش‌خوردن و کنار هم نشستن نشانمان می‌دهد."},"ICON-2764":{"nm":"سالاد مرغ","de":"سینه‌مرغِ به‌سادگی کباب‌شده روی سبزیجات برگ‌سبز مرتب چیده می‌شود. روی میزِ کسی که برای صحنه‌ی فردا آماده می‌شود، همیشه بشقابی به همین آراستگی هست."},"ICON-2765":{"nm":"سالاد گوجه و خیار","de":"گوجه‌ی رسیده و خیار ترد را با طعمی تند و تازه مخلوط می‌کنند. در نیمروزی پر از صدای زنجره، یک چاپ‌استیک که به دهان بگذاری، تابستان یک ضرب خنک درونش سرد می‌شود."},"ICON-2766":{"nm":"سالاد کاهو","de":"برگی که تازه از باغچه چیده شده را زیر آب سرد بشوی، نوک انگشتانت خنک بیدار می‌شوند. لحظه‌ای که معمولی‌ترین سبزی، سبزترین و تازه‌ترین جای روی میز را از آن خود می‌کند."},"ICON-2767":{"nm":"سالاد ذرت","de":"هر بار که دانه‌ای شیرین تق می‌ترکد، مزرعه‌ای در میانه‌ی تابستان پر از آفتاب جلوی چشمانت گسترده می‌شود. حتی درون کاسه‌ی سالاد هم، ذرتِ زرد آفتاب خودش را هرگز فراموش نمی‌کند."},"ICON-2768":{"nm":"کلم‌سالاد (کول‌اسلا)","de":"وقتی کلم رنده‌شده سسِ ترش‌وشیرین را به خود می‌گیرد، تردی‌اش کمی نرم‌تر می‌شود. فضیلتِ پیش‌غذا این است که کنار هر غذای اصلی که باشد، بی‌رقابت با نور، سهم خودش را تمام و کمال انجام می‌دهد."},"ICON-2769":{"nm":"سالاد میگو با لیموترش","de":"کمی لیموترش که بچکانی، شیرینیِ میگو یک پله واضح‌تر بیدار می‌شود. یک قطره‌ی ترش که به کل بشقاب جان می‌بخشد—لمسی نهایی، کوچک اما تعیین‌کننده."},"ICON-2770":{"nm":"همبرگ استیک","de":"خمیرِ گوشتِ کلفت‌شکل‌گرفته روی صفحه‌ی داغ آرام طلایی می‌پزد. آبِ گوشتی که لحظه‌ی برخورد نوک چاقو بیرون می‌زند—وعده‌ای که میان غذای خانگی و غذای غربی، طولانی‌ترین عمر عشق را داشته."},"ICON-2771":{"nm":"پیتزا","de":"همان یک لقمه‌ای که پنیرش بلند کشیده می‌شود، دست‌به‌دست میان جمعی که دورهم نشسته‌اند رد می‌شود. وقتی یک قرصِ گرد را با هم به تکه تقسیم می‌کنند، دورهمی سرانجام دورهمیِ واقعی می‌شود."},"ICON-2772":{"nm":"پاستا خامه قارچ","de":"رایحه‌ی عمیقِ خاکیِ قارچ و نرمیِ خامه، رشته‌به‌رشته‌ی پاستا را در آغوش می‌گیرند. در غروبی با صدای آرام باران، رایحه‌ی غلیظ آرام‌آرام تا کف بشقاب پخش می‌شود."},"ICON-2773":{"nm":"پاستا میگو","de":"میگوی چاق‌وچله را کمی در روغن زیتون تفت می‌دهند و با رشته‌ها یکی می‌کنند. وقتی شوریِ دریا با سادگیِ رشته روبه‌رو می‌شود، غروبی بی‌حادثه کمی خاص می‌شود."},"ICON-2774":{"nm":"پاستا روغن‌سیر","de":"سیر، روغن و رشته—فقط همین سه چیز. طعمی هست که هرچه بیشتر کم کنی واضح‌تر می‌شود، و آلیو اولیو این را بی‌هیچ زیاده‌ای، آرام ثابت می‌کند."},"ICON-2775":{"nm":"پاستا صدف","de":"آبی که صدف با بازکردن دهانش رها می‌کند، عمیق به هر رشته نفوذ می‌کند. رایحه‌ی یک جرعه شراب سفید روی بشقاب، مثل یک روز بهاری، مدتی طولانی از بین نمی‌رود."},"ICON-2776":{"nm":"پاستا خامه","de":"وقتی خامه‌ی غلیظ آرام رشته‌ها را در آغوش می‌گیرد، از همان لقمه‌ی اول گوشه‌ای از دل گرم می‌شود. تسلی‌ای که نرمی می‌دهد، در روزی بادخیز عمیق‌تر می‌شود."},"ICON-2777":{"nm":"پاستا گوجه","de":"سسِ گوجه‌ی طولانی‌جوشیده، سرخ روی رشته‌ها پخش می‌شود. وقتی شیرینی و ترشی آرام تغلیظ می‌شوند و بالاخره تعادل می‌یابند، ساده‌ترین بشقاب مطمئن‌ترین می‌شود."},"ICON-2778":{"nm":"امورایس","de":"تخم‌مرغِ نرم مثل پتویی آرام روی برنجِ گرم را می‌پوشاند. حتی یک اسم که با کچاپ رویش بنویسی، میزِ آن روز به نامه‌ای کوچک از طرف کسی تبدیل می‌شود."},"ICON-2779":{"nm":"ماهی سالمون کبابی","de":"جلوی آتش آرام کبابش می‌کنند تا پوستش ترد شود. یک رشته بخار که همراه شکافتنِ گوشتِ صورتی‌رنگ در امتداد رگه‌هایش بالا می‌رود—صبر همیشه صادقانه از سالمون پاداش می‌گیرد."},"ICON-2780":{"nm":"بروسکتا","de":"روی نان ترد برشته، گوجه‌ی خردشده و ریحان انبوه چیده می‌شود. سبکیِ برداشتنش با انگشت و یک گاز زدن، اولین سلامِ یک دورهمی را با گرمی باز می‌کند."},"ICON-2781":{"nm":"اسموتی انبه","de":"انبه‌ی رسیده را نرم می‌گیرند و با یخ خنک مخلوط می‌کنند. وقتی قطره‌ها روی لیوان زرد جمع می‌شوند، یک بعدازظهرِ کِسل تابستانی تا نوک نی بالا می‌آید."},"ICON-2782":{"nm":"لیموناد","de":"لیموی تازه‌فشرده، شکر و آب سرد را می‌ریزند و با تکان‌دادن لیوان مخلوط می‌کنند. وقتی ترشیِ زرد خنک از گلو پایین می‌رود، حتی گرمای بی‌رحم هم برای لحظه‌ای تسلیم می‌شود."},"ICON-2783":{"nm":"شیر توت‌فرنگی","de":"توت‌فرنگیِ له‌شده را در شیر حل کن، ابری صورتی آرام‌آرام در لیوان می‌نشیند. هیجانِ نوک‌انگشتیِ بازکردن در یخچال در کودکی، کاملاً در یک لیوان جای می‌گیرد."},"ICON-2784":{"nm":"شیر موز","de":"نوشیدنی‌ای که فقط با شکل گردِ کوزه‌مانندش، خاطره‌ی یک دوران کامل است. خاطره‌ی زردِ فرو‌کردن نی روی نیمکتِ حمام عمومی، با هر جرعه به‌مهربانی زنده می‌شود."},"ICON-2785":{"nm":"شیر بلوبری","de":"دانه‌های بنفش را تق‌تق له کن و بریز داخل، شیر سفید به آبی آسمانیِ کمرنگی رنگ می‌گیرد. همان یک مشت میوه‌ی کوچک، یک لیوان کامل را به رنگی تازه تبدیل می‌کند."},"ICON-2786":{"nm":"آب‌میوه","de":"چند میوه را با هم بگیر، طعمی می‌شود که با نام هیچ‌کدام به‌تنهایی صدایش نمی‌زنند. همسرایی کوچک از شیرینی‌ها، که با آمیختن با هم پرتر و غنی‌تر می‌شوند."},"ICON-2787":{"nm":"کاکائو","de":"کنار پنجره‌ای برفی، ماگ گرم را آرام با دو دست در آغوش می‌گیری. لیوانِ قهوه‌ای که بخارش تاب می‌خورد و بالا می‌رود، از نوک انگشت تا دل، آرام گرمت می‌کند."},"ICON-2788":{"nm":"قهوه","de":"همیشه همین یک لیوان است که چراغ اتاق تمرینِ سپیده‌دم را روشن می‌کند. وقتی رایحه‌ی تلخش آرام خواب‌آلودگی را کنار می‌زند، صحنه‌ی روزی دیگر همین‌طور آرام آغاز می‌شود."},"ICON-2789":{"nm":"سوشی سالمون","de":"برنج را در دست فشار می‌دهی و آن رگه‌ی ظریف میان سفتی و نرمی را می‌سنجی. لحظه‌ای که یک برشِ نازکِ سالمون آرام رویش می‌خوابد، یک لقمه به کمال یک دلسوزیِ کوچک تبدیل می‌شود."},"ICON-2790":{"nm":"فرنی کدو حلوایی","de":"کدوی زرد را کاملاً می‌جوشانند و نرم له می‌کنند. با هر قاشقی که در دهان می‌گذاری، آفتابِ پاییز گرم در دهان باز می‌شود. فرنی‌ای که اول از همه، وقتی مریضی، به یادت می‌آید."},"ICON-2791":{"nm":"کاری ماهی","de":"گوشتِ ماهی که کمی در ادویه پخته شده، درون کاری نرم خرد می‌شود. بافتِ دریا را به کاسه‌ای آشنا اضافه کن، غروبی معمولی یک وجب دورتر به سفر می‌رود."},"ICON-2792":{"nm":"میگوی سرخ‌شده","de":"همان لحظه‌ی کوتاهِ گرفتن دُم، پوشاندن با خمیر و انداختن در روغن جوشان، جایی است که برد و باخت رقم می‌خورد. میگوی پوشیده در لباسِ طلایی، پیش از آنکه تردی‌اش سرد شود، درخشان‌ترین حالتش را نشان می‌دهد."},"ICON-2793":{"nm":"کالاماری سرخ‌شده","de":"حلقه‌های گرد در روغن داغ چاق و پف‌دار بالا می‌آیند. آن لقمه‌ای که تردی جویدنی‌بودن را در بر گرفته، زیر نور زردِ کنار خیابانِ دست‌فروشی بهترین جفتش را پیدا می‌کند."},"ICON-2794":{"nm":"مرغ کبابی","de":"ادویه بزن و جلوی آتش آرام کباب کن، پوستش با جلایی می‌درخشد. غذایی که طعمش با یک تنظیم ساده‌ی آتش عوض می‌شود—ساده‌ترین، و به همین دلیل، صادقانه‌ترین."},"ICON-2795":{"nm":"خوراک تفتی گوشت خوک و کیمچی","de":"کیمچیِ خوب‌رسیده و گوشتِ خوک را با هم تفت بده، ترشی به شیرینی می‌رسد. غذایی که خودش خواستارِ یک کاسه برنج سفید می‌شود—مطمئن‌ترین جفت روی میز کره‌ای."},"ICON-2796":{"nm":"خوراک تفتی گوشت خوک","de":"روی آتش تند سریع تفت بده تا بیرونش کاملاً برشته شود. وقتی رایحه‌ی خوشمزه‌ی روغن آشپزخانه را پر می‌کند، منوی امشب دیگر بی‌هیچ پرسشی مشخص شده است."},"ICON-2797":{"nm":"خوراک تفتی گوشت گاو و قارچ","de":"قارچِ خوش‌رایحه و گوشت گاو را با هم تفت بده، طعمِ هرکدام عمیق‌تر می‌شود. وعده‌ای آراسته از پاییز که خاک و مزرعه آرام روی یک بشقاب دست هم را می‌گیرند."},"ICON-2798":{"nm":"داک‌گالبی پنیری","de":"پنیر را سخاوتمندانه روی داک‌گالبیِ تند ذوب کن و بلند بکش. وقتی جمعی دور صفحه‌ی داغ می‌نشینند، حتی تندیِ سوزاننده هم به خنده تبدیل می‌شود."},"ICON-2799":{"nm":"خوراک کیمچی","de":"هرچه کیمچی کهنه‌تر باشد، آبگوشتی عمیق‌تر و غلیظ‌تر می‌دهد. روبه‌روی هم بنشین جلوی دیزیِ قل‌قل‌کننده، و کلمه‌ی «خانواده» دوباره گرم می‌شود."},"ICON-2800":{"nm":"خوراک دوئنجانگ (خمیر سویا)","de":"دوئنجانگِ خوشبو را حل کن، توفو و کدوسبز اضافه کن و آرام و باحوصله بجوشان. صدایی که تا آخرین لحظه در دیزی قل می‌زند، مطمئن‌ترین نشانه‌ی این است که به خانه برگشته‌ای."},"ICON-2801":{"nm":"سوپ گوشت گاو و تربچه","de":"نیم‌روزی که آرام، پیش شعله‌ای کم‌سو نشستی و صبر کردی تا تربچه شفاف شود. وقتی یک قاشق از آبگوشت زلال به لب می‌رسد، سفره‌ی بی‌آرایش آن روزها در ذهن زنده می‌شود. ساده‌ترین چیزها همیشه بیشتر از همه در خاطر می‌مانند."},"ICON-2802":{"nm":"سوپ صدف","de":"لحظه‌ای که صدف‌ها دهان می‌گشایند، بهار در دل دیگ عمیق‌تر می‌شود. مشتی رایحه‌ی دریا که همراه بخار بالا می‌رود، آشپزخانه‌ی سپیده‌دم روستایی ساحلی را در ذهن ترسیم می‌کند. در هر شکاف بازشده، تکه‌ای از دریای شور نشسته است."},"ICON-2803":{"nm":"سیب‌زمینی شیرین کاراملی","de":"در راه بازگشت از مدرسه، تکه‌های زرد که در لیوان کاغذی مثل گرم‌کن دست گرفته می‌شدند. با گاز زدن پوسته‌ی طلایی، بخار ناگهان بالا می‌زند. پوسته‌ی شیرین کاراملی و درون داغش، طعم زمستانی که از همه مهربان‌تر بود."},"ICON-2804":{"nm":"بادمجان سرخ‌شده","de":"لحظه‌ای که رنگ بنفش با روغن آشنا می‌شود و آرام‌آرام نرم می‌گردد. سبزی‌ای که به له‌شدنش خرده می‌گرفتند، در واقع بهتر از هر چیز دیگر ادویه را در خود جای می‌دهد. با یک گاز، لطافتِ دستِ آشپز پیش از هر چیز به تو می‌رسد."},"ICON-2805":{"nm":"سیب‌زمینی خورشتی با سس سویا","de":"عصری که بوی شیرین در تمام آشپزخانه پخش می‌شد، همان‌طور که سس سویا غلیظ می‌گشت. دستی که یک دانه‌ی قهوه‌ای براق را در جای ناهارخوری می‌گذاشت. توجهی که در هیچ دستور پخت نوشته نشده، در هر دانه‌ی کوچک نشسته است."},"ICON-2806":{"nm":"برگ پرلا ترشی‌شده","de":"کار خواباندن تمام رایحه‌ی تابستان در نمک، تا به سفره‌ی زمستان برسد. یک برگ را جدا کن و روی برنج بگذار، فصل گذشته دوباره در دهانت شکوفا می‌شود. میان برگ‌های چیده‌شده لایه‌به‌لایه، آفتاب همان سال به خواب رفته است."},"ICON-2807":{"nm":"کیمچی تازه کلم چینی","de":"دستی که تاب انتظار برای کیم‌جانگ را نداشت، همان روز آن را با نوازش می‌آمیزد. طراوتی که فقط در همان لحظه‌ای که ادویه تازه به برگ‌های ترد نفوذ می‌کند، قابل چشیدن است. تازگیِ پیش از تخمیر، تجملی است مخصوص همین امروز."},"ICON-2808":{"nm":"قارچ سرخ‌شده","de":"چیزهایی که پس از باران، در سایه‌ی جنگل بی‌صدا سر برآوردند. در حین سرخ‌شدن با روغن کنجد پرلا، بوی خاک به عطر خوش تبدیل می‌شود. هرچه چیزی در تاریکی آرام‌تر رشد کرده باشد، عطرش عمیق‌تر و پررنگ‌تر است."},"ICON-2809":{"nm":"اسفناج مزه‌دار","de":"سبزی برگی که با آب‌پز شدن به یک مشت کوچک فرو می‌کاهد، با نوک انگشت‌ها نوازش‌وار مزه‌دار می‌شود. همان حجم فروتنانه، فضیلت سبزیجات بهاری است. یک بشقاب سبز، یک وجب آفتاب بهاری بیشتر به سفره می‌آورد."},"ICON-2810":{"nm":"جلبک دریایی مزه‌دار","de":"رشته‌های لغزنده که تازه از دریا بیرون کشیده شده‌اند، با سس ترش و تند درهم می‌آمیزند. طعمی شور که با هر جویدن می‌ترکد. بشقابی که بافت موج‌دار دریا را مستقیم به کاسه منتقل کرده است."},"ICON-2811":{"nm":"کدو سبز سرخ‌شده","de":"سبزیجاتی هستند که هرچه پیرتر می‌شوند، شیرینی‌شان بیشتر می‌شود. نازک برشش بزن و با میگوی نمک‌سود سرخ کن، حتی کدوی بی‌رنگ‌ورو هم آرام‌آرام شیرینی خود را آشکار می‌کند. زردی‌ای که تا آخر در دهان به‌نرمی باز می‌شود."},"ICON-2812":{"nm":"برنج سرخ‌شده با کیمچی","de":"وقتی کیمچی کهنه عمیق می‌شود، در یک تابه با برنج سرد دیدار می‌کند. کاسه‌ای که از پیوند باقی‌مانده با باقی‌مانده، سیرکننده‌ترین می‌شود. زیر نور کم‌سوی اتاق مجردی در نیمه‌شب، مهربان‌ترین نجات."},"ICON-2813":{"nm":"خورش کاری مرغ","de":"وقتی آبگوشت زرد روی برنج سفید را می‌پوشاند، سفره روشن می‌شود. روزگاری که ادویه‌جات غریبه بودند، اولین طعمی از دنیای بیرون که با آن انس گرفتیم. ظهر یکشنبه‌ای که گوشت مرغ نرم و پرپشت از هم باز می‌شد."},"ICON-2814":{"nm":"برنج سرخ‌شده","de":"خرده‌ریزهای باقی‌مانده در گوشه‌ی یخچال، در یک تابه با صمیمیت کنار هم می‌نشینند. سخاوتی که هر چیزی را با آغوش باز می‌پذیرد. جمع کردن پراکنده‌ها در یک‌جا، همان آغاز خانه‌داری است."},"ICON-2815":{"nm":"بولگوگی روی برنج","de":"گوشتی که در سس شیرین خوابانده شده، آرام روی برنج بخارگرفته می‌لغزد. وقتی ستاره‌ی سفره‌ی مهمانی به یک کاسه‌ی روزمره فرو می‌نشیند، آن ویژگی خاص، مهربان‌تر می‌شود."},"ICON-2816":{"nm":"بی‌بیم‌باپ","de":"روی برنج پرپشت، نمکی‌های پنج‌رنگ به دایره‌ای گرد می‌نشینند. در نوک انگشتانی که رنگ‌ها را هماهنگ می‌چینند، ذوق زیبایی‌شناسی کهن جاری است. طعم هماهنگی، فقط وقتی همه با هم مخلوط شوند کامل می‌شود."},"ICON-2817":{"nm":"برنج سرخ‌شده با میگو","de":"میگوهای گوشتی میان دانه‌های برنج به رنگ صورتی می‌درخشند. با سرخ‌کردن یک مشت از دریا، حتی وعده‌ای معمولی ادای سفره‌ی جشن را درمی‌آورد. شیرینی‌ای که در لحظه‌ی ترکیدن زیر دندان پخش می‌شود، خوشایند است."},"ICON-2818":{"nm":"گوشت خوک تند روی برنج","de":"گوشت خوکی که کاملاً در ادویه‌ی تند فرو رفته، با برنج بخارگرفته دیدار می‌کند. کاسه‌ای که در وقت ناهار اول از همه ته می‌کشید. تسلی یک وعده که روزی پرمشغله را نوازش می‌کند و آرام می‌سازد."},"ICON-2819":{"nm":"برنج تن‌ماهی و مایونز","de":"یک قوطی کنسرو، یک خط مایونز و یک کاسه برنج گرم. مواد اندک‌اند اما تسلی فراوان است. طعم آن شب، که پنهانی روی نیمکت کلاس بعد از درس‌خوانی شبانه مخلوط می‌شد."},"ICON-2820":{"nm":"برنج کاری","de":"رنگ طلاییِ غلیظ تمام بشقاب را پر می‌کند. توجهی که تا نرم‌شدن کامل سیب‌زمینی و هویج، مدت‌ها هم‌زده شده است. صمیمیت آن غروب که تمام خانواده به یک دیگ چشم دوخته بودند، در ذهن زنده می‌شود."},"ICON-2821":{"nm":"بی‌بیم‌باپ جلبک دریایی","de":"رشته‌های خوش‌بوی دریا با گوچوجانگ آمیخته و به‌آرامی مخلوط می‌شوند. وقتی بافت لغزنده و ترش دانه‌های برنج را در بر می‌گیرد، دریایی که یک زن غواص با نفس‌حبس‌کرده بیرون کشیده، در یک کاسه گسترده می‌شود."},"ICON-2822":{"nm":"ماهی خال‌مخالی کبابی","de":"پشت نقره‌ای روی گریل به رنگ طلایی می‌پزد. دستی که استخوان را جدا می‌کرد و گوشت را روی برنج می‌گذاشت. در یک تکه ماهی پشت‌آبی، عشقی بی‌صدا نشسته که این‌گونه غذا داد و بزرگ کرد."},"ICON-2823":{"nm":"پنکیک سیب‌زمینی","de":"چیزی که در روزهای بارانی، در آشپزخانه‌ی کوهستانی گانگوون رنده و سرخ می‌شد. لبه‌های چسبنده و کناره‌های ترد در یک قرص کنار هم زندگی می‌کنند. خمیری که بیشتر از هر چیز با صدای باران روی پنجره جور در می‌آید."},"ICON-2824":{"nm":"پنکیک کیمچی","de":"لحظه‌ای که کیمچی ترش به تابه‌ی روغنی می‌رسد، تمام خانه از صدای جلزوولز پر می‌شود. دایره‌ی طلایی‌ای که خودبه‌خود یک کاسه ماکولی می‌طلبد. غذایی همیشگی که با صدای باران زیر ایوان همراه می‌شود."},"ICON-2825":{"nm":"پنکیک پیازچه","de":"پیازچه‌ها را مرتب می‌خوابانی، خمیر را می‌ریزی و آرام سرخ می‌کنی. قرصی که میان تردی و نرمی در نوسان است. درست مثل همان منظره‌ی صمیمی روز بازار که بخار از روی بساط بلند می‌شد."},"ICON-2826":{"nm":"پنکیک کدو سبز","de":"کدوی نازک‌برش‌خورده را با خمیر می‌پوشانی و طلایی سرخ می‌کنی. دایره‌ی سبزکم‌رنگی که گوشه‌ای از سفره‌ی مراسم یادبود را منظم نگه می‌داشت. تشریفاتی پرزحمت که فقط با دست زیاد به‌کار بردن کامل می‌شود."},"ICON-2827":{"nm":"ماهی مرکب سرخ‌شده تند","de":"پاهایی پوشیده از سس قرمز، با درخششی براق می‌درخشند. حتی وقتی از تندی، دانه‌های عرق روی پیشانی می‌نشیند، چوب‌غذاخوری متوقف نمی‌شود. بشقابی که عرق و لذت در آن درهم تنیده‌اند."},"ICON-2828":{"nm":"توک‌بوکی","de":"توک و اومک عمیق در آبگوشت قرمز غلیظ‌شده‌ی گوچوجانگ فرو می‌روند. تمام بعدازظهر مغازه‌ی خوراکی که با سکه‌های جمع‌شده دونفره خورده می‌شد، در آن جای گرفته است. طعمی از خاطره که فقط با شنیدن نامش آب دهان راه می‌افتد."},"ICON-2829":{"nm":"سوپ اومک","de":"دکه‌ی خیابانی که اومک در آبگوشتش تاب می‌خورد و بخار شیشه را کدر می‌کند. یک سیخ را بگیر، کمی آبگوشت در لیوان کاغذی بریز و جرعه‌جرعه بنوش، شب سرد زمستانی گرم‌تر می‌شود."},"ICON-2830":{"nm":"توفو و کیمچی","de":"کنار توفوی نرم، کیمچی سرخ‌شده‌ی تند می‌نشیند. سرد و گرم، ملایم و تند، در یک بشقاب هماهنگ می‌شوند. همراهی‌ای که مدت‌ها شب‌های بزرگ‌سالان را پاس داشته است."},"ICON-2831":{"nm":"سوسیس و سبزیجات سرخ‌شده","de":"سوسیس قرمز و سبزیجات با رنگ کچاپ در تابه جلزوولز می‌کنند و درهم می‌آمیزند. خانه‌ای که وقتی درِ ظرف ناهار روز مسابقات ورزشی باز می‌شد، اول از همه خالی می‌شد. رنگ آن روز، هرچقدر زمان بگذرد، همیشه روشن می‌ماند."},"ICON-2832":{"nm":"لاته سیب‌زمینی شیرین","de":"سیب‌زمینی شیرین له‌شده‌ی نرم، در شیر گرم به‌آرامی حل می‌شود. شیرینی بومی‌ای که با خط کره‌ای روی منوی نوشیدنی‌ها نوشته شده. در روزی که نوک انگشتانت سرد است، آن را با دو دست بگیر تا گرمایش آرام‌آرام در فنجان پخش شود."},"ICON-2833":{"nm":"مایونز","de":"سسی که هنوز به آشپزخانه‌ی جزیره‌ی درخشان نرسیده است. به‌زودی به‌صورت آیکونی به رنگ کرم طراحی خواهد شد. (در حال آماده‌سازی)"}};